window.IDW_ITEMS_TR=window.IDW_ITEMS_TR||{};window.IDW_ITEMS_TR["cs-CZ"]={"ICON-0001":{"nm":"Stopa","de":"Jedna hlínově zbarvená stopa na parketách. Někdo se tu dlouho procházel sem a tam, než nakonec udělal ještě jeden krok vpřed. Stopa nezaznamenává čas strávený váháním, ale ten jediný okamžik, kdy se člověk rozhodl odejít."},"ICON-0002":{"nm":"Lucerna","de":"Když plamen dosáhne knotu, tma tiše ustupuje píď po pídi. Do malého tepla, jež hřeje konečky prstů, prý dávní lidé vpisovali svá přání a nechávali je plout. Lucernu nerozsvěcujeme, abychom svítili, ale abychom byli nablízku."},"ICON-0003":{"nm":"Stuha","de":"Jediným uzlem se srdce krásně zabalí. Ruka, která dárek posílá, jej uváže tak, aby šel snadno rozvázat, ruka, jež jej přijímá, si ho chce rozvazovat pomalu. Stuha nesvazuje krabici, ale to rozechvění těsně před podáním dárku."},"ICON-0004":{"nm":"Poštovní schránka","de":"Stojí na rohu uličky s dokořán otevřenými rudými ústy. I v době, kdy jsou ručně psané dopisy vzácností, tahle malá schránka až do konce čeká na něčí zprávu. Laskavá nádoba, která nejjasněji zazáří ve chvíli, kdy se úplně vyprázdní."},"ICON-0005":{"nm":"Minimapa vlastního ostrova","de":"Poskládaná se vejde do kapsy, rozložená ukáže list papíru, na kterém vedle sebe leží moře i hřebeny hor. Pro toho, kdo sem přichází poprvé, je každý roh ještě neotevřeným příslibem. Ve chvíli rozevření se i malý ostrov stává rozlehlým světem."},"ICON-0006":{"nm":"Mikrofon","de":"Půl doby těsně před prvním tónem, kdy si člověk urovnává dech. Když víš, že pohledy z hlediště čekají na tvé jediné slovo, konečky prstů se rozechvějí. Mikrofon nezesiluje zvuk – donese to rozechvění až do konce."},"ICON-0007":{"nm":"Hodiny","de":"Vteřinová ručička neodpočívá, ale nikdo tě nikam nehoní. Kolik nocí zbývá do debutu, kolik minut do vystoupení — na ciferníku plyne čekání i vzrušení stejnou rychlostí. Pohled na čas je způsob, jak si utišit srdce."},"ICON-0008":{"nm":"Zápisník","de":"Věc s nejvíce prázdnými řádky ze všech. Ukládají se sem taneční kroky, svítání odhodlání i slova, která se nikdy neodeslala. Ve chvíli, kdy ho otevřeš, k tobě dnešnímu tiše promluví ten včerejší."},"ICON-0009":{"nm":"Razítko","de":"Nasákne rudou tuší a jediným pevným stiskem se do papíru zřetelně vyryje slib. Stopa těžší než písmo, jasnější než slovo. Na konci každé listiny lidé místo jména svěřovali své srdce právě tomuto malému razítku."},"ICON-0010":{"nm":"Podstavec","de":"Sklání se, jak jen může, aby udržel něco jiného. Místo, které mlčky drží na nejnižším místě, aby se to, co leží nahoře, nezakolísalo. Nezáří, a přesto v něm sídlí laskavost, jež nedovolí, aby se cokoli zhroutilo."},"ICON-0011":{"nm":"Poštovní známka","de":"Malý obrázek, který se olízl v rohu a pevně přilepil. Nejpoctivější cena, jakou lze dát srdci posílanému do dálky. Jeden čtvercový kousek krajiny drží dopis za ruku až za moře."},"ICON-0012":{"nm":"Vlaječkový špendlík","de":"Zapíchni ji do mapy a stane se z ní věta: „Dostal jsem se až sem.“ Není to dobytí, ale záznam, a povzbuzení pro toho, kdo přijde příště. Značka, která beze slov postrčí vpřed – při pohledu na tuhle vlaječku ještě jeden krok."},"ICON-0013":{"nm":"Větvička","de":"Větvička, která se jednou ohnula, zapomene, jak se láme. V každém místě, kde se sklonila před větrem, se pevně zapustí suk, a starý les ve vánku šeptá, že pravá pevnost pochází ze stop vydrženého utrpení."},"ICON-0014":{"nm":"Knoflík","de":"Znovu a znovu se rozepíná a zapíná a přitom stahuje límec k tělu. Jeden malý kroužek tiše zadrží jak ranní chlad, tak náhlý pocit studu. Teprve když s cvaknutím upadne, zjistíš, jak velké bylo jeho místo."},"ICON-0015":{"nm":"Obálka","de":"Teprve ve chvíli, kdy se zalepí ústí, se z ní stane tajemství. Co je uvnitř, ví jen ten, komu je určena. Jedna vrstva papíru položená mezi srdcem a světem – nejtenčí a nejlaskavější dveře ze všech."},"ICON-0016":{"nm":"Krabice","de":"Její čtyři rohy jsou rovné, a tak dokáže velkoryse pojmout cokoli. V době stěhování vzpomínky, o svátcích dárky, jindy zase všelijaké drobnosti. Pod zavřeným víkem je vždy plno něčího „později“."},"ICON-0017":{"nm":"Klika","de":"Mezi dveřmi a člověkem je to ona, kdo první nabídne ruku. Teprve jedním zatáhnutím se konečně propojí vnitřek s vnějškem. Každé rozhodnutí vejít nebo odejít nejprve na okamžik sevře tuto studenou ruku."},"ICON-0018":{"nm":"Lžíce","de":"Svými prohnutými ústy tiše nabírá teplou polévku. Nástroj, který si pamatuje teplo té první lžičky, jež matka nejdřív ofoukla a podala. U stolu je to ruka, která se úst dotýká nejčastěji – ta nejlaskavější ze všech."},"ICON-0019":{"nm":"Bačkory","de":"Ve chvíli, kdy překročíš práh, si nohy jako první oddechnou. Zvuk večera, kdy odložíš klapající den a jdeš dál tiše šoupavými kroky. Pár úhledně postavený u vchodu ti řekne: „Teď jsi doma.“"},"ICON-0020":{"nm":"Klíč","de":"Dřív než se naučí zamykat, naučí se otvírat. Malý kus kovu, který se zahřívá v dlani, až jednoho dne tiše zůstane stát před neznámými novými dveřmi. Věc, jež si nejdéle uchovává teplo toho, kdo odešel."},"ICON-0021":{"nm":"Číše","de":"Prázdná je upravená, naplněná je nade vše teplá. V čirém zvuku, když se dvě zvednuté číše cinkavě střetnou, se ukrývá nevyřčený slib. Nádoba zrozená k tomu, aby zářila spíš ve dvou než o samotě."},"ICON-0022":{"nm":"Talíř","de":"Do kulatého okraje se vejde celá denní dávka péče. Vyprazdňovat, utírat a znovu naplňovat po celý život — je to kus domácnosti, který září nejčastěji, a přitom je nejčastěji zapomínán. Jeviště stolu se prostírá vždy právě na něm."},"ICON-0023":{"nm":"Světlo","de":"Jediným vypínačem se změní výraz celého pokoje. Když svítí jasně, je to všední den, když tlumeně, je to útěcha. Bod světla ponechaný svítit až do konce kvůli tomu, kdo přijde pozdě, se stává nejteplejším přivítáním na světě."},"ICON-0024":{"nm":"Čajová lžička","de":"Jedno pomalé otočení nad hladinou čaje a lístky s vodou do sebe vzájemně vsáknou. Pohyb ruky, jenž nikam nespěchá, drobné čekání, než se rozprostře vůně. Jedna stříbrná ručička láskyplně zpomaluje tempo odpoledne."},"ICON-0025":{"nm":"Záložka","de":"Slib tiše vložený na místo, kde četba přestala. Mezi stránkami spí odhodlání: „Zastavil jsem se tu, ale určitě se vrátím.“ I když se příběh zavře, srdce je zřetelně vyznačeno na tom jediném řádku."},"ICON-0026":{"nm":"Polštářek","de":"Beze slova přijímá záda a kolena, které potřebují o něco se opřít. Hluboko se propadne a pak se pomalu znovu nadme, jak do sebe vstřebává únavu celého dne. Věc, jež nejvelkoryseji dovoluje ten nejlínější postoj."},"ICON-0027":{"nm":"Rámeček","de":"Hranatý okraj svazuje jednu scénu s věčností. Alespoň ten okamžik, který se do něj vešel, čas nevybledí, ať uplyne, kolik chce. Laskavá volba, méně o tom, co pojmout, více o tom, co se rozhodneme zachovat."},"ICON-0028":{"nm":"Mapa","de":"V každém přehybu je vepsána stopa toho, jak se cesta ztratila a znovu se našla. Když ji rozložíš, můžeš konečky prstů projít i místa, kam jsi nikdy nešel. Každé dobrodružství začíná tou malou odvahou rozevřít jediný list."},"ICON-0029":{"nm":"Pohlednice","de":"Polovina zadní strany je fotografie, polovina prázdné místo. Ten, kdo odjel daleko, posílá pár slov „mám se dobře“ spolu s krajinou onoho místa. Nejupřímnější list papíru, kde zpráva o sobě není trapná ani bez obálky."},"ICON-0030":{"nm":"Identifikační karta","de":"Ve chvíli, kdy si ji pověsíš na krk, konečně vstoupíš do vnitřního světa. Mé jméno napsané na malé kartě tiše potvrzuje: „Tady, tohle je tvé místo.“ Není to oprávnění k průchodu, ale doklad, že někam patříš."},"ICON-0031":{"nm":"Písmeno B","de":"Písmeno, které bývá nejčastěji vyvoláváno uprostřed slova. Zvuk vznikne teprve tehdy, když se rty na okamžik sevřou a pak se s prasknutím rozevřou. Není ani začátkem, ani koncem, ale spolehlivým druhým místem, které udržuje rytmus."},"ICON-0032":{"nm":"Vizitka","de":"Podává se oběma rukama, přijímá se s pohledem do očí. Na jediném listu papíru je tiše stlačen celý den i hrdost jednoho člověka. Do úzkého prostoru mezi jménem a titulem se jemně usadí ten den první dojem."},"ICON-0033":{"nm":"Obal knihy","de":"Na samém vnějšku příběhu jako první čelí dešti a větru. Aby ochránil písmena uvnitř, opotřebovává se nejdřív po rozích. To krátké rozechvění těsně před otevřením vždy začíná právě na tomto jediném listu."},"ICON-0034":{"nm":"Učebnice","de":"Podtržení a zvýrazňovačem je hustě zapsán zápas jednoho člověka. Jako nová kniha působí zdrceně, ale po dočtení se stane nejspolehlivějším přítelem. Stopy toho, jak se neznámé stalo známým, jsou úhledně přeloženy na každé stránce."},"ICON-0035":{"nm":"Taneční propustka","de":"Tenhle jeden lístek doširoka otevírá dveře do zkušebny. Místnost plná zrcadel, dupot nohou, prvních osm dob, které se právě učíš. Že je v pořádku, když tanec ještě není hladký, tiše šeptá malý kousek papíru a jemně postrčí rozechvělá záda vpřed."},"ICON-0036":{"nm":"Pořadač","de":"Volné listy, které se dosud toulaly samy, se úhledně sešijí na jednu páteř a konečně získají pořadí. Jakmile vznikne pořadí, stane se z toho příběh, a čím je pořadač tlustší, tím laskavěji dokazuje, že to někdo prožil krok za krokem, vrstvu po vrstvě."},"ICON-0037":{"nm":"Testový list","de":"Konečky prstů se na okamžik zachvějí nad prázdným řádkem. Strašnější než špatná odpověď je čelit přímo tomu, co nevíš. Když je oprava hotová, na každém chybném místě tiše zůstane prostor, ve kterém příště něco vyroste."},"ICON-0038":{"nm":"Písmeno A","de":"První hláska, která vzejde jedině tehdy, když se ústa doširoka otevřou. Často stojí v čele řady, na samém začátku jména. Vždycky, když se něco začíná, začíná se tímhle písmenem – proto je pokaždé o trochu odvážnější."},"ICON-0039":{"nm":"Písmeno D","de":"Svými měkce vyklenutými zády jemně podpírá slovo. Jeho oblá strana se úhledně zavěsí na konec něčího jména. Není okázalé, ale bez něj by bylo prázdno – tichý společník uprostřed abecedy."},"ICON-0040":{"nm":"Cvičný list","de":"Jediný papír na světě, na kterém je chyba v pořádku. Dovolí ti znovu a znovu, desítkykrát, opakovat stejný pohyb, stejnou větu. S každým zmačkaným a vyhozeným listem se někdo určitě o kousek zlepšoval."},"ICON-0041":{"nm":"Notový list","de":"Ve dvě ráno tě probudí jediné pobrukování. Tužka se na notové osnově zarazí proto, že melodie je rychlejší než ruka. V každé stopě smazané a znovu zapsané pomalu roste ještě bezejmenná píseň."},"ICON-0042":{"nm":"Přístupová karta","de":"Ve chvíli, kdy si ji pověsíš na krk, se obyčejná chodba promění v jiný svět. Kabely se plazí tmou jako hadi a za jevištěm začíná neslyšné odpočítávání. Právo vstoupit sem za tebe promluví tenhle jediný lístek."},"ICON-0043":{"nm":"Kontaktní tisk","de":"V každém malém políčku je zastavený jiný výraz. Smích, ohlédnutí, zavřené oči. Když prstem přejíždíš snímek za snímkem, do konečků prstů se vrací rozechvění toho dne, kdy jsi mačkal spoušť. I samotný výběr jednoho snímku je už záznamem."},"ICON-0044":{"nm":"Denní harmonogram","de":"Zítra v kolik, kde a co. Jediný list papíru předem načrtne trasu na celý den. Mezi políčky nahuštěnými po minutách někdo krok za krokem podle zapsaného pořadí kráčí blíž ke svému snu."},"ICON-0045":{"nm":"Visačka","de":"Za cenovkou tiše visí čas toho, kdo věc vyrobil. Malý papírek, který se stane skutečně mým teprve tím krátkým gestem odtržení. Na místě přestřižení zůstává vůně novoty a hrst rozechvění."},"ICON-0046":{"nm":"Portfolio","de":"Otočíš obálku a naráz se rozevře celá ušlá cesta. Vedle stránky, na kterou jsi hrdý, stydlivě stojí i tvůj nemotorný první pokus. Když se poprvé představuješ někomu jinému, upřímnější sebeprezentaci než tuhle nenajdeš."},"ICON-0047":{"nm":"Diář","de":"Zapíšeš dnešek, načrtneš příští týden a občas jedno políčko začerníš. I když se nikdy nic nestane přesně podle plánu, ruka, jež vyplňuje políčka, se nezastaví. Něco jako malý obřad, při kterém si předem jednou prožiješ budoucnost."},"ICON-0048":{"nm":"Playlist","de":"Mezi pomalými skladbami a rychlým rytmem seřadíš písně do jedné linie podle počasí svého srdce toho dne. Když si pomyslíš, že přesně v tomhle pořadí plyne něčí celý den, i ticho mezi skladbami zjihne."},"ICON-0049":{"nm":"Studentský průkaz","de":"Jméno, fotka a pár čísel. Jediný doklad dosvědčující dobu, kdy ses proplétal mezi třídou a zkušebnou. V kartě, opotřebené po rozích od nesčetných cest do kapsy a z kapsy, je vryt neopakovatelný, svěží každodenní den."},"ICON-0050":{"nm":"Náramek","de":"Pamatuješ si tu chvíli, kdy sis na zápěstí uvázal barvu toho dne? Společně vykřičené heslo, koncertní noc, kdy jste zmokli spolu. Že ho nerozvazuješ, i když šňůrka chátrá a barva bledne, je proto, že chceš, aby to léto dál žilo na tvém zápěstí."},"ICON-0051":{"nm":"Páska na rukáv","de":"Ve chvíli, kdy si ji obtočíš kolem paže, se nenápadně přidá tíha zvaná zodpovědnost. Znamení toho, kdo stojí v čele řady a odchází ze svého místa jako poslední. Jeden kus látky dokáže někoho nechat vyrůst o kousek výš."},"ICON-0052":{"nm":"Prsten","de":"Jedna linie, kulatě spojená, bez jediného přerušení. Protože se v ní dotýká začátek s koncem, lidé v ní vidí tvar věčnosti. Když se dvě ruce tiše spojí, dřív než slova zůstane jako tvar slib."},"ICON-0053":{"nm":"Vyznamenání","de":"Do malého kovového kousku připnutého na hrudi jsou vryty vydržené dny. Nezáří kov samotný, ale nespočet nocí zkoušení, jež se za ním skrývá. Dřív než pýcha se v člověku vzedme, nevím proč, vděčnost."},"ICON-0054":{"nm":"Zástěra","de":"Uvážeš tkanice na krku a obě ruce jsou volné. Signál, že jsi připraven se do něčeho ponořit celý – ať už je to mouka nebo barvy. Čím víc skvrn postupně přibývá, tím sytější je i péče vložená do toho dne."},"ICON-0055":{"nm":"Klapky na uši","de":"Když pevně obejmou uši, vnější zvuky o krok ustoupí. Na cestě do školy, kde fouká ostrý vítr, je to malý úkryt, do jehož měkkého vnitřku se dá nenápadně schovat. Teplo zimy někdy začíná právě takhle – od konečků uší."},"ICON-0056":{"nm":"Kostým","de":"Než se zvedne opona, visí na ramínku a zadržuje dech. V každém jednotlivém švu je složena choreografie. Ve chvíli, kdy se ruka provlékne rukávem, se z člověka stává role a jeviště se stává druhou kůží tohoto oděvu."},"ICON-0057":{"nm":"Koruna","de":"Ve chvíli, kdy si ji nasadíš na hlavu, se skloněná záda sama od sebe narovnají. Zlatý lesk šeptá dřív o odpovědnosti než o moci. Chladná tíha, jež se dotýká čela, ti to prozradí sama: čím zářivější místo, tím je těžší."},"ICON-0058":{"nm":"Plášť","de":"Obtoč si ho kolem ramen a za zády se rozevlaje vítr. Ten pocit, kdy tě při každém běhu jeden pruh látky následuje jako stín. Není to tolik znamení hrdiny, jako spíš dětské srdce, které si prostě chtělo připadat úžasné."},"ICON-0059":{"nm":"Maska","de":"Když si zakryješ tvář, staneš se paradoxně upřímnějším. Jako za starých dvorních představení, kdy se za maskou dalo do sytosti smát i plakat. Za skrytým výrazem hlasitěji uniká pravý hlas, který jindy jen polykáš."},"ICON-0060":{"nm":"Rtěnka","de":"Odšroubuješ víčko, jedním tahem nakreslíš čáru a na rtech se usadí malé odhodlání. Poslední kontrola před zrcadlem, rudá linka natažená přes váhání. V tom krátkém okamžiku, kdy se nanáší barva, se strach tiše odsune stranou."},"ICON-0061":{"nm":"Sako","de":"Když ramenní linie sedí přesně, člověk trochu ztvrdne. Vyhrneš rukávy a je to chuť do práce, postavíš límec a je to chuť vyrazit ven. Jediný oblek tiše určuje postoj celého dne."},"ICON-0062":{"nm":"Taekwondový pás","de":"Pokaždé, když se barva posune o stupeň výš, mění se i množství potu nashromážděného pod ní. Ráno v dojangu, kdy se utahoval uzel a klanělo se. Konečky prstů, jež váží pás, se znovu soustředí rozptýlená mysl."},"ICON-0063":{"nm":"Brýle","de":"Nasadíš si je na oči a svět zaostří o jeden tón. Za kulatým štítem, který zadrží vítr i prach, i ta obyčejná cesta, kterou vždycky chodíš, jaksi zazáří jako startovní čára."},"ICON-0064":{"nm":"Rukavice","de":"Navlečeš si ji na ruku a vzejde odvaha pevně cokoli sevřít. Prsty, jež se dosud krčily ze strachu, že něco upustí, se konečně doširoka rozevřou. Chráněná je sice ruka, ale to, co je vlastně chráněno, je výzva, jež má teprve přijít."},"ICON-0065":{"nm":"Rouška","de":"Zakryješ ústa a oči promluví o to víc. Na rušné ulici, mírně zakrytý, si užíváš malou svobodu anonymity. A proto se úsměv, jenž zůstane po sundání, rozlévá o to jasněji."},"ICON-0066":{"nm":"Kšiltovka","de":"Mírně stáhneš kšilt a slunce i pohledy uhnou o kus stranou. Pod tou malou střechou posazenou na hlavě smíš dnes aspoň chodit s uvolněným výrazem. Nejlehčí proměna vždycky začíná právě tady."},"ICON-0067":{"nm":"Košile","de":"Zašustí to – z právě vyžehleného límce voní ráno. Zatímco zapínáš knoflíky popořadě odshora, i pomačkaná mysl se krok za krokem upravuje. Jeden bílý list otevírá první větu dne."},"ICON-0068":{"nm":"Šátek","de":"Jedním otočením kolem krku se uzavře průchod větru. Zatímco cíp látky lehce povlává na rameni, chlad už se dovnitř nedostane. Jeden pruh látky položený někde mezi stylem a teplem."},"ICON-0069":{"nm":"Zimní rukavice","de":"Když jsou konečky prstů pevně obemknuté, ani zima už není strašná. Malý zimní luxus, kdy ruce, které sis ohříval dechem, potichu zteplají. Jedna sundaná a podaná rukavice dokáže ohřát i ruku někoho jiného."},"ICON-0070":{"nm":"Identifikační známka","de":"Dvě tenké destičky se tiše dívají jedna na druhou. Tři slabiky jména a pár čísel – to je to, co někoho udrží v paměti až do konce. Studený kov, a přece se nějak podobá tomu nejteplejšímu slibu."},"ICON-0071":{"nm":"Úchytný kroužek","de":"Provlékneš prst a obava z upuštění se pomalu rozplyne. Malé ujištění, díky němuž unese i jedna ruka a bezpečně s ním zamává. Když natahuješ paži co nejdál, abys zachytil jednu fotku, tiše podepře tvou dlaň."},"ICON-0072":{"nm":"Květinový věnec","de":"Nasadíš si ho na hlavu a s tebou přijde náruč jara. Květiny natrhané na louce a spletené do kruhu se jemně ovinou kolem čela. Nad jasným úsměvem na fotografii dlouho přetrvává slabá vůně trávy."},"ICON-0073":{"nm":"Maska na spaní","de":"Zakryješ oči a světlo i hluk naráz ustoupí do dálky. Protože nevidíš, slyšíš jen svůj vlastní dech. Na chvíli vypneš svět a vstoupíš do vnitřního ticha, a za zády se tiše zavřou malé dveře."},"ICON-0074":{"nm":"Šála","de":"Jednou kolem, podruhé kolem – s každým otočením kolem krku zima trochu zmírní. Někde mezi vlněnými nitěmi je možná vpleteno srdce toho, kdo ji upletl. Zabořená až po špičku nosu, a svět je hned o poznání útulnější."},"ICON-0075":{"nm":"Půlmaska","de":"Zakrytá jen polovina tváře, a začíná noc plesu. Odhalené rty se usmívají, skryté oči chovají tajemství. Ta úzká mezera mezi tím, že poznáš a nepoznáš, kdo se za maskou skrývá, rozechvívá půlnoční vzduch."},"ICON-0076":{"nm":"Baret","de":"Nasadíš ho nakřivo a do obyčejného dne se nenápadně vkrade nádech elegance. Jeden kulatý, plochý kus látky tiše obleče tvá ramena do napodobeniny umělce. Radost přináší i ta chvilka před zrcadlem, kdy vybíráš správný úhel."},"ICON-0077":{"nm":"Choker","de":"Obtočíš ho těsně kolem krku a pohledy se přirozeně stáhnou vzhůru. Jediný tenký proužek dokáže změnit náladu úplně celou. Malý, ale zřetelný – jako spona, jež naplní sebevědomí na celý dnešní den."},"ICON-0078":{"nm":"Parka","de":"Vytáhneš zip až úplně nahoru a i sněhová vánice o krok ustoupí. Zasuneš ruce hluboko do tlusté podšívky a všechen ruch světa se ztiší. Malý domek, který zůstává teplý až do konce, i uprostřed drsného větru."},"ICON-0079":{"nm":"Kalhoty","de":"Provlékneš nohy, zapneš pas a teprve pak jsi konečně připraven vyrazit ven. S každým krokem se látka jemně pohybuje po svém vlákně. Den začíná někde uprostřed mezi pohodlím a upraveností."},"ICON-0080":{"nm":"Piercing","de":"I přidání jediného malého bodu vyžaduje trochu odvahy. Jeden zářivý kousek kovu udělá na obyčejném uchu zřetelnou tečku. Docela malé, ale jasné světlo, jež odráží dnešní já, které se opravdu změnilo."},"ICON-0081":{"nm":"Zvuková křivka","de":"Pro zvukového inženýra se píseň neslyší – vidí se. Z hřebenů stoupajících a klesajících na obrazovce vyčte, kde se toho dne chvěl dech. Hlas, který dřív nebylo vidět, leží jako pohoří a rozprostírá terén celé skladby."},"ICON-0082":{"nm":"Ladička","de":"Těsně před vystoupením postupně pohladíš všech šest strun a usadíš rozladěné tóny zpátky na místo. I odchylka pouhých 0,5 stupně a hlediště to postřehne jako duch. Naladit vše tak přesně, že si toho nikdo nevšimne – to je laskavost věnovaná jevišti."},"ICON-0083":{"nm":"Popruh","de":"Jedním omotáním kolem zápěstí se rozpustí obava z upuštění. Na jevišti je nejděsivější věcí ztratit něco z ruky, a tak si díky jedinému malému poutku konečně oddechneš."},"ICON-0084":{"nm":"Činel","de":"V okamžiku jediného úderu se na poslední větu skladby vtiskne zřetelná tečka. Zlatý kotouč umí znít nejkratší dobu a přitom zanechat nejdelší dozvuk. Konec se má takhle jasně uzavřít."},"ICON-0085":{"nm":"Kytara","de":"Prsty sklouznou po šesti strunách a úzký pokoj se rázem promění v celé jeviště. Něčí první melodie i sebemluva z nespavého svítání – to všechno poprvé nadechlo uvnitř tohoto oblého dřevěného těla."},"ICON-0086":{"nm":"Zvukový obláček","de":"Na jedné straně oblohy se noty stlačily jako vata a vznášejí se. Prý, jakmile jimi jednou přejede vítr, místo kapek deště se snese melodie – a děti z ostrova jim vybíhají naproti bez deštníku."},"ICON-0087":{"nm":"Krok","de":"Pohyb po jevišti je aritmetika řešená špičkami nohou. Tady jeden krok, tam půl doby — chyba nevadí, jen pomalu. Políčka, stovkrát prošlapaná a vryta do těla, se spojí a teprve tak vznikne mapa jedné skladby."},"ICON-0088":{"nm":"Zesilovač","de":"Krabice, jež mění šepot v jásot. A přece se ruka pokaždé na okamžik zastaví, než posune hlasitost o stupeň výš. Tahle krabice ví, že k poslední řadě hlediště nedolehne hlasitější zvuk, ale ten přesnější."},"ICON-0089":{"nm":"Notové chmýří","de":"Kulaté hlavičky not se shluknou do chomáče vaty a je to měkké jako polštář. Prý, když si na něj tiše lehneš a podložíš hlavu, vyplyne sotva slyšitelná ukolébavka – jedna z nejlaskavějších pověstí na ostrově."},"ICON-0090":{"nm":"Kazeta","de":"Stiskneš tlačítko převíjení a se skřípěním se páska pomalu vrací k první písni toho léta. V malé krabičce, do níž je celá jedna éra navinutá, beze zbytku spí čas, kterého se už nikdy nedotkneš."},"ICON-0091":{"nm":"Ladicí vidlice","de":"Lehce udeříš do dvouzubého kovu a ve vzduchu se zrodí jeden referenční tón. Podle tohoto drobného chvění tiše sklánějí hlavu všechny nástroje. Začátek čehokoli přichází právě z takhle křehkého chvění."},"ICON-0092":{"nm":"Zvukový čip","de":"Kousek zvuku je jemně uvězněný v čipu velkém sotva jako nehet. Neúmyslně nahraný povzdech, smích někoho, o kom sis myslel, že je dávno pryč — uvnitř téhle drobnosti to pořád žije a dýchá, teplé jako dřív."},"ICON-0093":{"nm":"LP deska","de":"Jehla udělá svůj první krok podél drážky a jako první se ozve tichý praskavý dech. Někdo má rád i ten drobný šum tak moc, že se tohoto černého kotouče až do konce nedokáže vzdát."},"ICON-0094":{"nm":"Kapsička","de":"To, čeho si nejvíc ceníš, si vždycky necháváš nejblíž u srdce. Jeden látkový váček velký jako dlaň se jednou stane ohřívačem rukou, jindy talismanem a jindy zase schránkou pro tajemství."},"ICON-0095":{"nm":"Náplast","de":"V nocích, kdy se zkoušení protáhne dlouho, se na každou patu nalepí jedno malé vyznamenání. Náplast nalepená proto, aby spolkla slovo „bolí to“ — je to tichý slib, o kterém nikdo neví, že bude tančit i zítra, ať se děje cokoli."},"ICON-0096":{"nm":"Polštář","de":"Místo, kam nakonec odložíš celé jedno denní jeviště, je právě tenhle měkký čtverec. Tiše na něj složíš hlavu a potlesk, který ti ještě zněl v uších, se pomalu vytrácí, a i na ostrov konečně padá noc."},"ICON-0097":{"nm":"Zvonek","de":"Cink – jedním krátkým zazvoněním někdo otevře dveře a vstoupí. Signál, že přišel host, i pozdrav, že se den otevřel. Jeden malý kousek kovu celý den vyzvání jen a jen radostné přivítání."},"ICON-0098":{"nm":"Pouzdro","de":"Čím vzácnější věc, tím pevnější domeček si pro ni postavíš zvlášť. Ruce, jež ho otevírají a zavírají, jsou pokaždé opatrnější proto, že to, co je uvnitř, není jen obyčejná věc, ale srdce, které nechceš za nic na světě ztratit."},"ICON-0099":{"nm":"Kartáč","de":"Přejedeš každým jednotlivým vláknem po směru a prach přilepený v koutě se nenápadně stáhne. Díky doteku, který se nezdráhá dosáhnout i na neviditelná místa, vítá pokoj každý den nové ráno."},"ICON-0100":{"nm":"Skica","de":"Linky před dokončením se nesnaží schovávat své váhání. V každé stopě smazané a znovu nakreslené beze lži zůstává to, čím chtěly být. Čím nemotornější začátek, tím upřímnější."},"ICON-0101":{"nm":"Panenka","de":"Existují bytosti, které utěšují, jen když je držíš v náručí, beze slova. Bavlněný přítel, který se s tebou třásl na polštáři v noci, kdy se ti za scénou třásly ruce – takového si každý nosí někde v srdci."},"ICON-0102":{"nm":"Zvon","de":"Horský chrámový zvon zazvoní jednou a přejde celé údolí. Je to srdce kovu, které touží dosáhnout dál a ještě dál, a proto zní tak dlouze – a ten zvuk se pak pomalu usazuje v hrudi toho, kdo naslouchá."},"ICON-0103":{"nm":"Deštník","de":"Když se o něj podělíte, jedno rameno vždy zmokne. Pod mírně nakloněným deštníkem je promoklé rameno tím nejjasnějším důkazem laskavosti. Krátká cesta pod jednou střechou zůstává v srdci dlouho."},"ICON-0104":{"nm":"Podložka","de":"Rozlož ji na holou podlahu a to místo se hned stane cvičebnou. Místo, které tě beze slova zachytí, když se koulíš a padáš – na ní si nespočet pohybů poprvé zvyklo na tělo."},"ICON-0105":{"nm":"Rolnička","de":"Jemně s ní zatřeseš a z ruky se vyvalí čistý, cinkavý zvuk. Malá kulatá radost, kterou si kdysi děti přivazovaly k lemům pestrobarevných kabátků a s ní pobíhaly po dvoře, se znovu probouzí na tvé dlani."},"ICON-0106":{"nm":"Hračka had","de":"Jeho protáhlý, visící tvar zákeřně lidi vyleká. Nejdřív strach, útěk, a nakonec smích – i takový žertík je jednou z podob vzájemné laskavosti."},"ICON-0107":{"nm":"Hračka","de":"Každý má i v dospělosti jednu krabici, kterou se nedokáže odhodit. Uvnitř je smích těch nejzářivějších časů stále pevně natažený jako nedotočené pero."},"ICON-0108":{"nm":"Jídelní stolek","de":"Rozlož sklopené nožičky a hned kdekoli vznikne místo pro rodinu. Zvuk lžic narážejících o sebe, když všichni sednou kolem – ten prostý souzvuk zní ze všech dnešních melodií nejvřeleji."},"ICON-0109":{"nm":"Mýdlo","de":"Postupně se v ruce zmenšuje a tiše přitom někoho očišťuje. Opotřebovávat se, aby umylo druhého – teprve dlouho poté, co bubliny všechny zmizí, se ukáže to tiché srdce."},"ICON-0110":{"nm":"Hřeben","de":"Stejně jako rozplétá zacuchané vlasy pramínek po pramínku, i rozcuchaný den se postupně urovná. Jediný krátký dotek před zrcadlem tiše napraví, kromě vlasů, i držení srdce."},"ICON-0111":{"nm":"Ptačí klec","de":"Existuje pták, který zpívá a neodletí, i když jsou dvířka dokořán otevřená. Srdce, které zůstává ne proto, že je uvězněné, ale protože chce zůstat – ten jemný rozdíl tahle klec pozná dřív než kdokoli jiný."},"ICON-0112":{"nm":"Ohřívač rukou","de":"Ve frontě před zimní halou malé teplo v kapse tiše rozehřívá ztuhlé prsty. Laskavost velikosti dlaně, kterou někdo předem zahřál a protřepal, s myšlenkou na tebe, jak se chvěješ zimou."},"ICON-0113":{"nm":"Kapesník","de":"Jediný kus látky, který bez reptání přijme slzy i pot. Drobná výšivka v rohu tam něžně zůstává, jako poslední pozdrav toho, kdo odešel dřív, se vzkazem: nezapomeň."},"ICON-0114":{"nm":"Sprej","de":"Jedno stisknutí a struktura vzduchu se v okamžiku promění. Mlha stoupající nad jevištěm i kytka za ranním oknem – v těchto jemných kapičkách se na chvíli stanou jiným světem a zazáří."},"ICON-0115":{"nm":"Vonný proužek","de":"Vybírat vůni se podivně podobá vybírání vzpomínky. Slabý pramínek vůně přenesený na hrot útlého papírku tiše přivede k nosu roční období, o kterém sis myslel, že jsi ho zapomněl."},"ICON-0116":{"nm":"Stůl","de":"V každém opotřebeném slojí dřeva je tiše vyryt počet společně snědených jídel. Hlučné večery i osamělé pozdní noci – tenhle čtverec vše přijal beze slova a zářil čím dál víc."},"ICON-0117":{"nm":"Klubko nití","de":"Jemně zatáhneš za jeden konec a rozmotá se hladce, jediný steh a zase se spojí. Spravovat přetržené vždy tiše začíná právě takhle – od jediného tenkého vlákna nitě."},"ICON-0118":{"nm":"Pláštěnka","de":"I v lijáku právě tenhle jeden kus konečně vyžene ven. Jen ten, kdo zná radost z čvachtání deštěm, nepoužije déšť jako výmluvu, aby zůstal doma."},"ICON-0119":{"nm":"Váček","de":"Sevři vstup do kroužku a to, co je uvnitř, je konečně v bezpečí. V jednom malém, ohmataném pytlíčku se spolu houpou mince, vzpomínka na nějaký den i slova, která nikdy nezazněla."},"ICON-0120":{"nm":"Knihovna","de":"Pomalu přejeď prstem po hřbetech srovnaných knih a pod konečky prstů ucítíš uplynulá roční období. Proč se nedokážeš zbavit dočtené knihy? Protože tam pořád žije to tehdejší ty."},"ICON-0121":{"nm":"Věž z knih","de":"Přečtené knihy si lehnou na bok, nepřečtené se skládají navrch. I když slib, že je jednou všechny přečteš, se u stropu trošku kymácí, tohle houpání máš rád, a tak dnes přidáváš ještě jeden svazek."},"ICON-0122":{"nm":"Běhací kolo","de":"I když se zdá, že ať běžíš sebevíc, zůstáváš na místě, malé nožky si nejdřív osvojují rytmus špiček. Nezastavené včerejšky se hromadí a jednoho dne zazáří jasně na skutečné cestě."},"ICON-0123":{"nm":"Potah","de":"Aby na to nesedal prach, aby to nevybledlo na slunci – i v zakrývání je péče konečků prstů. Čím vzácnější věc, tím laskavěji je chráněna na místech, která nikdo nevidí."},"ICON-0124":{"nm":"Vlna","de":"Jedno vlákno, které se kdysi kutálelo a odvíjelo z klína babičky. Vypadá zamotaně, ale najdeš-li konec a jemně zatáhneš, vždycky tě poslušně následuje. Tak se zimní noci prodlužovaly, oko po oku."},"ICON-0125":{"nm":"Kosmetická taštička","de":"Balzám na rty, gumička do vlasů, úhledně složený dopis – vypadá to maličko, ale je v tom uloženo srdce celého dne. Se zvukem zavíraného zipu se všechny ty vzácné drobnosti naráz ocitnou v bezpečí."},"ICON-0126":{"nm":"Opěrka rukou","de":"Odpoledne usnuté nad knihou, večer strávený přecházením při telefonátu. Na místě, které se čím déle sedí, tím víc otiskuje, se potichu nahromadil každý oddech, který si loket pamatuje, do výšky jedné dlaně."},"ICON-0127":{"nm":"Balíček","de":"Dokud ho neotevřeš, nepatří ještě nikomu. Zapečetěný sáček je plný nerozbaleného očekávání, až se konečky prstů, které svírají jeho roh, lehce zachvějí. To je vzrušení z otevírání."},"ICON-0128":{"nm":"Balicí papír","de":"Srdce, které dorazí o krok dřív než samotný dárek. Zatímco přehýbáš rohy do roviny a svazuješ stuhou, usměvavá tvář toho, kdo dárek dostane, se ti předem rozzáří v dlaních."},"ICON-0129":{"nm":"Gamepad","de":"Tlačítka, která si palce zapamatují dřív než hlava. Prohrál jsi, ale ještě jedno kolo – a to jedno kolo nakonec vezme celou noc. Váha, která přesně sedí do ruky, tiše zvedá dnešní noční dobrodružství."},"ICON-0130":{"nm":"Semafor","de":"Červená znamená na chvíli zastavit, zelená, že teď už můžeš jet. Jediný prostý slib a nespočet cest plyne, aniž by se zamotaly. Že i čekání má svůj pořádek, ti laskavě prozradí blikající světlo."},"ICON-0131":{"nm":"Šipka","de":"Nejlaskavější tvar pro toho, kdo ztratil cestu. Když je zoufale nejasné, kam jít, jeden směr, který někdo dřív vyznačil, znovu pevně postaví zastavené kroky na nohy."},"ICON-0132":{"nm":"Souřadnice","de":"Stačí dvě čísla a lze přesně ukázat kamkoli na světě. Místo, kde jste se domluvili sejít, písečná pláž, kde je zakopaný poklad. Aby slib neztratil cestu, jedna malá tečka ho pevně drží až do konce."},"ICON-0133":{"nm":"Dlaždice","de":"Sama je to jen jeden hranatý kousek. Ve chvíli, kdy si lehnou bok po boku, rameno na rameni, stanou se podlahou a stěnou. Malé věci se spojí a vytvoří místo, kam někdo může klidně vkročit."},"ICON-0134":{"nm":"Přesýpací hodiny","de":"Když se horní komora vyprázdní, dolní se pomalu naplňuje. Při pohledu na tiše stékající písek věříme, že čas plyne. Otoč je a vše je zase na začátku – to je laskavá malá lež písku."},"ICON-0135":{"nm":"Míč","de":"Hodíš ho a vrátí se, kopneš do něj a odkutálí se. Být kulatý a nikdy nevědět, kam se odrazí, je jeho největší kouzlo. Uprostřed hřiště smích vždycky začínal kulatě právě od tohohle malého tělesa."},"ICON-0136":{"nm":"Vypínač","de":"Cvak – jedním stiskem se rozsvítí, jedním zhasne. Ten drobný zvuk při vstupu do tmavého pokoje jasnou čárou rozděluje rozházený začátek a konec dne."},"ICON-0137":{"nm":"Otazník","de":"Neznat odpověď není nic, za co by ses měl stydět. Je to naopak radostný důkaz, že zvědavost je stále živá. Když tenhle malý háček ťuká na tvou mysl, učení konečně dělá první krok."},"ICON-0138":{"nm":"Zápalka","de":"Jedna tyčinka, která škrtne o vlastní tělo, aby předala oheň. Krátce hoří a tiše zhasne, ale v té chvilce se rozsvítí svíčka a zahřeje kamna. Malý dar sebe sama se stává prvním knoflíkem tepla."},"ICON-0139":{"nm":"Stolička","de":"Vystoupíš na ni jen jednou nohou a ruka dosáhne i na polici, na kterou předtím nedosáhla. Práce, která na chvíli prodlouží něčí výšku. Tady je laskavé místo, které se sehne nízko, aby nás jemně pozvedlo výš."},"ICON-0140":{"nm":"Náramkové hodinky","de":"To první, co sis navlékl na zápěstí v den, kdy ses rozhodl začít cvičit. Malý kouč, který počítá tep srdce a kroky, ti poklepáním sdělí, že dnes jsi ušel o kousek víc než včera."},"ICON-0141":{"nm":"Budík","de":"Nejsvědomitější přítel, kterého ráno co ráno nikdo nemá rád. Díky tomu, že za tebe pokaždé bojuje s pokušením pěti minut navíc pod peřinou, žádný slib ani sen nepřijde pozdě. Ten nevlídně znějící zvuk je ve skutečnosti povzbuzení."},"ICON-0142":{"nm":"Jádro","de":"Ta nejvnitřnější část, která zůstane, když se sloupne všechno z povrchu. Jablečné semínko, upřímné srdce – ať je to cokoli, uprostřed toho vždy leží to nejpevnější. Jeden bod, který zůstane i po všem tom otřásání."},"ICON-0143":{"nm":"Pero","de":"Šmouha, která se otiskla na hraně ruky, než inkoust zaschl. Ať se píše dobře, nebo ne, první tah před bílým papírem vždycky vyžaduje trochu odvahy. Je to most, po kterém myšlenka přechází ke konečkům prstů."},"ICON-0144":{"nm":"Štětec","de":"Když nasákne tuší a přejíždí po hanji, zůstane na papíře celé i to nejmenší zaváhání. Chceš-li psát rychle a chamtivě, hned tě to prozradí. Štětec jako první pozná poctivost, která přebývá v konečcích prstů."},"ICON-0145":{"nm":"Bublina s řečí","de":"Místo, které se kulaté vznese nad hlavou dřív, než slova stihnou vyjít z úst. Uloží se v ní ta jedna věta, kterou chceš říct. Když je prázdná, právě si vybírá, čím se naplní."},"ICON-0146":{"nm":"Zaškrtávací pole","de":"Nakresli do prázdného čtverečku dvě čárky a srdci se hned uleví. Malá medaile, kterou si sám udělíš za dokončený úkol. Na konci dne, při pohledu na vyplněná políčka, se ujišťujeme, že jsme dnešek zase prožili dobře."},"ICON-0147":{"nm":"Tablet","de":"Kudy se dotkneš prstem, tam se rozlévá obrázek a plynou písmena. Polož si ho tiše na klín a rozsvítí se celý jeden svět. Je lehký, ale možnosti, které v sobě nese, rozhodně tenké nejsou."},"ICON-0148":{"nm":"Dálkový ovladač","de":"Má vrozený talent schovávat se ve škvírách gauče. Moc přepínat kanály vždycky patří tomu, kdo ho drží v ruce. Nejmenší a nejmilejší rodinná hádka se odehrává právě na téhle jedné dlani."},"ICON-0149":{"nm":"Vyvažovací závaží","de":"Váha, která se snížila až úplně na dno, aby udržela to, co se kymácí. Ať se nahoře děje cokoli, pokud je dole těžko, nakonec to nespadne. Rovnováha se vždy drží na místech, která nejsou vidět."},"ICON-0150":{"nm":"Puzzle","de":"Noc, kdy jsi šátral i pod gaučem po posledním chybějícím dílku. Ten tichý pocit slasti, když přesně zapadne na místo. Když roztroušené věci najdou svá místa, obrázek je konečně dokončen."},"ICON-0151":{"nm":"Pravítko","de":"Měřit délku je zároveň i způsob, jak dodržet slib. Aby byla jedna píď stejná pro každého, ryska za ryskou poctivě stojí v řadě. Jedna rovná čára dokáže narovnat i pokřivené srdce."},"ICON-0152":{"nm":"Plátno","de":"Prázdná bílá plocha, na které nic není, je nejděsivější a zároveň nejvzrušivější. Dokud na ni nepoložíš první tečku, může se stát čímkoli. Prázdnota není konec, ale jiné jméno pro začátek."},"ICON-0153":{"nm":"Kostka","de":"Nejeden člověk kvůli srovnání všech šesti stran probděl celou noc. Neúnavná zarputilost konečků prstů, které točí znovu a znovu. Ve chvíli, kdy promíchané barvy najdou svá místa, se malý vesmír úhledně srovná."},"ICON-0154":{"nm":"Přenosná herní konzole","de":"Malá obrazovka, nad kterou se o prázdninách skláněli bratranci a sestřenice hlava na hlavě. Svět dobrodružství, který se pohodlně vejde do dlaně. Stačí jediná fráze melodie při zapnutí a celé to léto se vrátí naráz."},"ICON-0155":{"nm":"Grip","de":"Ten pocit, jak se pevně sevřeným úchopem přilne k ruce, tiše dodává sebedůvěru. Aby to neklouzalo, aby to nevyklouzlo. V nejdůležitější chvíli je to spojnice, která pevně sváže ruku a nástroj v jeden celek."},"ICON-0156":{"nm":"Plnicí pero","de":"Zatímco píšeš s doplněným inkoustem, i písmo se trochu víc urovná. Uklidňuješ srdce zvukem škrábajícího hrotu, tiše se podobá péči, s jakou jsi kdysi pomalu začínal první řádek ručně psaného dopisu."},"ICON-0157":{"nm":"Paleta barev","de":"Modrá vedle červené, zelená nad žlutou. Na téhle malé destičce, kde barvy leží úhledně bok po boku, obrázek konečně získává výraz. Každé dobrodružství míchání a vrstvení tu dělá svůj první krok."},"ICON-0158":{"nm":"Sada","de":"Každý kousek zvlášť je obyčejný, ale poskládané vedle sebe tvoří jeden příběh. Ta jistota, když nic nechybí a všechno je na svém místě. Ve shromažďování roztroušených věcí na jedno místo dřímá malá radost z dokonání."},"ICON-0159":{"nm":"Badmintonový míček","de":"Jemný svist větru, který vydávají peříčka, když vzlétne po zásahu raketou. Zdá se příliš lehký, než aby doletěl daleko, ale odpálen s rozhodností letí rovnou až na konec kurtu. I lehkost je svého druhu síla."},"ICON-0160":{"nm":"Anténa","de":"Tiše stojí obrácená k obloze a snaží se zachytit neviditelný signál. Trpělivost, která nakonec přitáhne i vzdálený hlas. Ve dnech, kdy se špatně chytá, stačí lehce naklonit úhel a zase se to vyjasní."},"ICON-0161":{"nm":"Stetoskop","de":"Kulatý konec, chladně přiložený na hruď, a dech, který se na chvíli zastaví. Nastavíš ucho jedinému malému bušení a k tvým konečkům prstů se přenese ten nejstarší rytmus toho, že jsi naživu. Nástroj, u kterého je naslouchání na prvním místě."},"ICON-0162":{"nm":"Šachový pěšec","de":"Malá figurka, která kráčela pomalu, jen o jedno políčko. Přesto se ve chvíli, kdy dosáhne posledního řádku, může stát čímkoli. Nad jediným tahem, který svým neohrabaným krokem obrátí celou partii, tiše bdí starobylá šachovnice."},"ICON-0163":{"nm":"Ovladač","de":"Pamatuješ na noci, kdy jsi dvěma palci proplouval vesmírem? Ohmataný úchop, který jsi v prohře odhodil a pak trapně sebral zpátky. Nejdelší a nejvřelejší rozhovor, který jsi beze slova sdílel s někým za obrazovkou."},"ICON-0164":{"nm":"Herní konzole","de":"Zapneš napájení a krátký zaváděcí tón zazní jako pozdrav. Hranatá krabička, kterou jsi celé prázdniny zapínal a vypínal pod peřinou; první dětské dobrodružství vždy začínalo právě ve světle téhle obrazovky."},"ICON-0165":{"nm":"Časová osa","de":"Levý konec je začátek, pravý konec den, který ještě nepřišel. Přetáhneš-li mezi ně jedinou tečku kamkoli, znovu se rozevře chvíle, o které sis myslel, že jsi ji zapomněl. Místo, kde čas leží položený v jedné rovné linii."},"ICON-0166":{"nm":"Hranol","de":"Kdo by řekl, že zdánlivě čiré světlo v sobě celou dobu skrývalo sedm barev. Tajemství, které se rozvine v duhu ve chvíli, kdy projde kouskem skla. Čím upravenější věc, tím víc barev se v ní ukrývá."},"ICON-0167":{"nm":"Golfové týčko","de":"Malý podstavec, na který se opatrně položí míček. Čím dál chceš něco poslat, tím pevnější oporu to nejdřív potřebuje. Tenhle drobný kolík v trávě podpírá úplně první krok."},"ICON-0168":{"nm":"Pletací jehlice","de":"Jedno oko, pak další. Když jedno upustíš, musíš vše rozpárat a vrátit se na začátek. Šála, která se celou zimu pomalu prodlužovala na klíně – místo, kde se trpělivost konečků prstů propletla do tepla."},"ICON-0169":{"nm":"Melodická linka","de":"Jeden tón, který ti unikl z rtů coby pobrukování dřív, než na něj přišel text. V té ještě rozmazané melodii, na kterou se ještě nepřilepila slova, se skrývá nejupřímnější první tvář písně."},"ICON-0170":{"nm":"Radar","de":"Vysílá signál do temnoty, kterou nevidí, a tiše čeká na jednu vracející se tečku. Trpělivost kulatého zeleného světla, které věří, že tam něco je, i když nic vidět není."},"ICON-0171":{"nm":"Rytmický pad","de":"Ťuk, ťuk, jen lehce poklepeš a světlo se zvukem naráz vyskočí nahoru. Místo, kde si ruce zapamatují rytmus dřív než hlava. Nejmenší a nejlaskavější jeviště, rozprostřené na dlani."},"ICON-0172":{"nm":"Barva","de":"Staří malíři získávali barvu drcením kamene a hlíny. Indigo z trávy, červeň z hlíny. I v téhle jediné kapce, vytlačené dnes na konečky prstů, dál proudí odvěká péče, s jakou se příroda pečlivě přenášela do nádoby."},"ICON-0173":{"nm":"Čára","de":"To, co se zrodí teprve ve chvíli, kdy se rozhodneš spojit bod s bodem. Krátká nebo dlouhá, křivá nebo rovná, je to nejprostší stopa, kterou zanechá touha vydat se někam. Začátek každého obrázku."},"ICON-0174":{"nm":"Uzávěrka","de":"Cvak – ta jediná krátká tma navždy uchová jeden okamžik. I výraz, který by ti málem unikl v mrknutí oka, tenhle malý nůž zachytí, uřízne kousek světla a ztuhne v něm vzpomínka."},"ICON-0175":{"nm":"Bezpečnostní lano","de":"Lano, které se pevně přiváže o krok dřív než ten, kdo šplhá do výšky. Místo tebe drží srdce sevřené strachem z pádu, neviditelně střeží tvůj bok, šňůra jednoho slibu. Vždycky je za tvými zády."},"ICON-0176":{"nm":"Visací zámek","de":"Těžký litinový zámek, kterým se kdysi zamykala komora. Nešlo o uvěznění, ale o přání nechat vzácné věci klidně a bezpečně uložené. I v ruce, která zamykala, byla péče – opora starého domova."},"ICON-0177":{"nm":"Váha","de":"Když jedna strana ztěžkne, druhá sama zlehkne. V té chvíli váhání, co a kolik na ni položit, se člověk učí spravedlnosti. Dvě ramena, která houpáním učí rovnováze."},"ICON-0178":{"nm":"Rozdělovač","de":"I to, co je pevně spojené, se nakonec podle sloje rozštěpí. Malý nástroj, který rozdělí cokoli na dvě části a nahlédne dovnitř. Zvídavé konečky prstů, které touží znovu rozebrat to, co bylo spojeno, a podívat se dovnitř."},"ICON-0179":{"nm":"Počítadlo","de":"Jedna, dva, tři. Malý přítel, který za tvé prsty tiše počítá čísla. Srdce sevřené obavou, že něco přehlédneš, promění cvakáním v klid – laskavý společník počítání."},"ICON-0180":{"nm":"Kurzor","de":"Malá šipka, která někde na obrazovce bliká a čeká na další příkaz. Ani během váhání neopustí své místo, špička světla, která tiše pokyvuje: pojďme teď začít."},"ICON-0181":{"nm":"Chyt","de":"Ten jeden bod, kterého se naposledy chytíš, těsně předtím, než síla z konečků prstů úplně vyprchá. Že existují chvíle, kdy vydržíš jen díky odhodlání nepustit se, ti tiše prozradí malý výstupek na stěně."},"ICON-0182":{"nm":"Oblázek","de":"Kámen, který se dlouho koulel v potoce a vzdal se všech svých hran. Zaoblit se je jiné jméno pro čas, který byl obroušen. Sevři ho tiše v dlani a nahmatáš v něm trpělivost tekoucí řeky."},"ICON-0183":{"nm":"Erb","de":"Staré rody kdysi vyryly na jediný pruh vlajky zvíře a hvězdu, aby se dala poznat. Obrázek, který předával srdce dřív než slova. Starobylé znamení, které pečlivě stlačuje hrdost jednoho člověka do jediného malého políčka."},"ICON-0184":{"nm":"Štít","de":"Postavit se do cesty bylo vždy kvůli tomu, kdo stojí za zády. Přijímat na sebe letící šípy místo někoho, aby zůstal obyčejný den v bezpečí – těžká, a přesto laskavá zeď."},"ICON-0185":{"nm":"Znovuzrození","de":"Existuje srdce, které zhasne a znovu se rozsvítí. Teprve poté, co jednou padneš, se konečně naučíš, jak zase vstát. Druhý nádech, který se tiše naplňuje přesně v místě, o kterém sis myslel, že je koncem."},"ICON-0186":{"nm":"Luk","de":"Ruka, která chce poslat něco daleko, nejdřív napne tětivu až úplně dozadu. Že pustit znamená nejdřív přivinout co nejblíž k sobě, ti tiše, beze slova, prozradí napjatě prohnuté tělo luku."},"ICON-0187":{"nm":"Srdíčko","de":"Slova \"mám tě rád\" se stále zmenšují do drobného tvaru. Tenhle tvar, kradmo nakreslený na konci lightsticku nebo mezi dvěma dotýkajícími se prsty. Nejobyčejnější a nejupřímnější zkratka srdce."},"ICON-0188":{"nm":"Mrak","de":"Pomalu pluje ve směru větru a pokaždé se promění v jinou tvář. Jednou zajíc, jednou vata – nic si nedrží dlouho a všechno nechává plynout dál, nejlehčí srdce oblohy."},"ICON-0189":{"nm":"Bludiště","de":"Místo, kde se učíš, jak se otočit před slepou zdí. I když bloudíš, tvé kroky každou chvíli o kousek rostou blíž k východu. Musíš se jednou ztratit, aby se ti otevřel smysl pro cestu."},"ICON-0190":{"nm":"Zub","de":"Existoval zvyk házet vypadlý zub na střechu. Malé přání, aby nový zub vyrostl rovně. Dětský něžný slib, že musíš jednou v životě něco ztratit, abys dorostl něčeho pevnějšího."},"ICON-0191":{"nm":"Planeta","de":"Kulaté těleso, které nikdy neopustilo svou dráhu kolem hvězdy. Vypadá osaměle, ale jeho gravitace vždy nutí něco kroužit po jeho boku. Tiše držet své místo se samo o sobě stává celým světem."},"ICON-0192":{"nm":"Hvězda","de":"V noci, kdy lidé ztratili cestu, vzhlíželi k nejjasnějšímu bodu. Světlo, k němuž se nedá dosáhnout, přesto jasně ukazuje směr. Slib, který sílí právě proto, že je tak vzdálený."},"ICON-0193":{"nm":"Silueta","de":"Postavíš se zády ke světlu a z člověka zůstane jen obrys. Jediná černá postava, jíž bylo vymazáno jméno i výraz. Prázdnota, která právě proto, že je prázdná, nechá představivost obsáhnout ještě víc."},"ICON-0194":{"nm":"Ucho","de":"Chceš-li dobře zpívat, musíš nejdřív dobře naslouchat. Rytmus i srdce, obojí nakonec začíná nasloucháním. Malé kulaté dveře, otevřené, kam všechny zvuky světa dorazí jako první a zůstanou."},"ICON-0195":{"nm":"Spadané listí","de":"Jsou listy, které nejkrásněji zazáří právě ve chvíli, kdy padají. Lehkost, s jakou dohořívají do červena svou letní zeleň a tiše se pokládají k zemi. Podzim ukazuje, že i konec může být tak krásný."},"ICON-0196":{"nm":"Měsíc","de":"Byly noci, kdy se pod kulatým světlem svátku úplňku spínaly ruce a přály si přání. Tvář, která se nikdy neopakuje, jak dorůstá a couvá. Lucerna, která se mění, a přesto vždy osvětluje to samé místo."},"ICON-0197":{"nm":"Srdce","de":"I na jevišti je nakonec nejupřímnější právě tenhle tep. Nezastaví se, i když se chvěje, a bije silněji, když srdce přetéká. Malý rudý buben, který místo tebe rozechvěle vyjadřuje povzbuzení, jež slova nedokázala vyslovit."},"ICON-0198":{"nm":"Stín","de":"Společník, který se nikdy neodloučí, dokud existuje světlo. Ztmavne, čím jasněji svítí, a vybledne, čím je šero hlubší – další já, které mě sledovalo nejdéle. Jeden člověk, který stojí po boku i v osamělé dny."},"ICON-0199":{"nm":"Ocásek","de":"Radostí se sám od sebe zavlní, strachem se potají stočí. Poctivý konec, který nikdy úplně neskryje srdce, i když jsou ústa pevně sevřená. Vnitřní pocit, který tělo prozradí jako první."},"ICON-0200":{"nm":"Stužka na ohonek","de":"Malá šňůrka, kterou se na konci uváže mašle, jako závěr. Srdce, které ještě jednou pevně utáhlo uzel, aby se nerozvázala. Laskavé zavěšení, které shromáždí a utiší věci náchylné se rozprchnout."},"ICON-0201":{"nm":"Zornice","de":"Slova si můžeš vybírat, ale pohled v očích neschováš. Místo, kde prozrazené srdce uniká jako první, uvnitř toho černého kolečka. I když polkneš slova „líbíš se mi“, tvé zorničky už se chvějí tvým směrem."},"ICON-0202":{"nm":"Podkova","de":"Kus železa, který čím víc se obrušoval na špičce z běhu po dlouhých cestách, tím byl pevnější. Když se pověsí obráceně nade dveře, prý se v ní hromadí štěstí, které přichází i odchází. Tiše podpírá něčí bezpečný návrat domů."},"ICON-0203":{"nm":"Erbovní kámen","de":"I když déšť a vítr obrousí písmena do mlhava, stačí je nahmatat prsty a vyrytá kresba znovu živě ožije. Váha jednoho srdce, které nechtělo být zapomenuto. Kámen tak dlouho v sobě chová jediné jméno."},"ICON-0204":{"nm":"Plovací blána","de":"Jedinou tenkou blankou spojující prsty se učí odstrkovat vodu. Malé veslo, které příroda potají vtiskla do ruky nešikovnému plavci. Něžný návrh, který tě – byť pomalu – nakonec přece dovede na druhý břeh."},"ICON-0205":{"nm":"Třpytky","de":"Všichni si stěžují, že jakmile ulpí na rukou, drží se dní, a přesto po těchto zrníčkách světla sáhnou jako po prvních, když je slavnostní den. Nasyp hrst hvězdného prachu a i obyčejný papír se zatřpytí a dnešek se stane výjimečným."},"ICON-0206":{"nm":"Dráp","de":"Lesní zvěř škrábe drápem do hlíny a zanechává svou stopu. Ne hrozbu, ale otisk – tichý podpis, že tudy prošla. Ostrý hrot se pro někoho může stát i něžným ukazatelem cesty."},"ICON-0207":{"nm":"Blesk","de":"Ve chvíli, kdy obloha na okamžik rozevře linie své dlaně, dorazí světlo dřív než hrom. Jako by ti říkalo, ať se jednou nadechneš, než k tobě dolehne ten mohutný zvuk. Strach a úžas se vždy rodí společně z téhož záblesku."},"ICON-0208":{"nm":"Amulet","de":"Jeden řádek přání pevně vtištěný tuší do červeného papíru. Věřilo se, že pod polštářem odvede zlé sny stranou. Srdce, které se modlí za něčí bezpečí, dokáže být takhle vřelé i v jediném tenkém listu papíru."},"ICON-0209":{"nm":"Křídlo štětce","de":"Existují okamžiky, kdy se hrot štětce promění v křídlo. Ta lehkost, s jakou klouže po papíru při tahu jediné čáry. Že psaní je vlastně jistý druh létání, to stará ruka rozetírající tuš tušila jen matně."},"ICON-0210":{"nm":"Kost","de":"To, co zůstane, teprve když se všechno maso rozpadne. Bílá kostra, která vydržela do posledka, protože byla nejpevnější. Jediný tichý důkaz, který si i přes to, že čas si vezme vše ostatní, pamatuje aspoň tvar."},"ICON-0211":{"nm":"Nos","de":"Vůně je nejrychlejší zkratka k paměti. Pach oleje ve sváteční kuchyni, studený vzduch rána po prvním sněhu – špička nosu to postřehne první a srdce se přidá o krok pozadu."},"ICON-0212":{"nm":"Toust","de":"Nejrychlejší jídlo, po kterém ráno sáhneš, když spěcháš. Kousneš do dozlatova opečeného povrchu a v křupnutí se rozpadne dávka odvahy na celý den. Věci, které nemusejí být okázalé, ale zahřejí, dokážou člověka znovu postavit na nohy."},"ICON-0213":{"nm":"Sušenka","de":"Kdo čekal před troubou nejdéle, ten dostane první sousto. Teplo čerstvě upečeného okraje, chvilková sladkost. Ty, které se pekly s myšlenkou na někoho, jsou podivně o to sladší."},"ICON-0214":{"nm":"Svačinka","de":"Odpoledne, kdy se zkouška protahuje, sáček vytažený z hloubi tašky. Rozděl ho napůl a sytost se podivuhodně zdvojnásobí. Hrst něhy, která naplní srdce dřív než hlad."},"ICON-0215":{"nm":"Kapsle","de":"Dokud ji neotočíš a neotevřeš, nikdo neví, co je uvnitř. V kulaté skořápce je vždy stejné rozechvění srdce. Nejpoctivější vzrušení na světě, ve kterém se prodává a kupuje malá náhoda."},"ICON-0216":{"nm":"Klika","de":"Místo, kterého se jako první dotknou nesčetné ruce otevírající a zavírající dveře. První pozdrav domova, který začíná chladem a v dlani se zahřívá. Čím víc se na ní usazují dotyky, tím víc se ta místnost pomalu stává něčím domovem."},"ICON-0217":{"nm":"Procházka","de":"I chůze bez cíle má svůj důvod. Čas, kdy se zamotané myšlenky rozplétají do kroků, vlákno po vláknu. Vrátíš se z kolečka a odpověď zůstává stejná, přesto je srdce o poznání lehčí."},"ICON-0218":{"nm":"Skútr","de":"Dvě kola prořezávající úzké uličky. Není rychlý, zato vítr přijímá celým tělem naplno. Bývají dny, kdy si prostě chceš dnes osvěživě zajet, i kdyby to nebylo daleko."},"ICON-0219":{"nm":"Bezpečnostní tyč","de":"Než nastoupíš, jedna příčná tyč se pevně sklopí před hruď. Spolehlivý slib, že s tebou vydrží až do konce toho strašidelného úseku. Beze slov a chladně ti dává najevo, že se za ni klidně drž pevně."},"ICON-0220":{"nm":"Schody","de":"Stoupáš po jednom schodu a než se naděješ, výhled je docela jiný. Chodidla se jako první naučí, že žádnou výšku nedosáhneš jedním skokem. Samo stoupání a sestupování bylo pro někoho denní dávkou kroků."},"ICON-0221":{"nm":"Terárium","de":"Není to uvěznění lesa ve skle, ale pečlivé pěstování celého světa. Vesmír velký jako dlaň, kde se šíří mech a perlí se kapky vody. Čím déle se do něj díváš, tím pomaleji se srdce barví do zelena."},"ICON-0222":{"nm":"Pódium","de":"Vystoupíš na místo o píď výš a výhled, který se otevře, je jiný. Místo, kde se strach a hrdost setkávají ve stejné výšce. Podle toho, kdo na něm stojí, se ten jediný stupínek pokaždé mění v jiné jeviště."},"ICON-0223":{"nm":"Letadlo","de":"Ve chvíli, kdy se pod nohama rozprostřou mraky, se ti konečně zasteskne po místě, které jsi opustil. Není to vzdalování se, ale rozšiřování světa. I sen odchovaný na malém ostrově takhle přeletí oblohu."},"ICON-0224":{"nm":"Skateboard","de":"Věc, na kterou lze pořádně vyjet teprve tehdy, když se nejdřív naučíš padat. Pokaždé, když si odřeš koleno, se do těla o kousek víc vryje rovnováha. Poctivá čtyři kolečka, která ujedou o to dál, oč lépe umíš spadnout."},"ICON-0225":{"nm":"Pas","de":"Otevřeš desky a je plný prázdných stránek. Každé razítko, které je má zaplnit, se stane důkazem prožitého života. Malá knížka, která v sobě nenese ani tak to, kam všude jsi už byl, jako spíš možnost dostat se kamkoli."},"ICON-0226":{"nm":"Plánek","de":"Nemá přesné vzdálenosti ani měřítko, ale je to cesta nakreslená rukou, a proto se na ní nedá vůbec zabloudit. Papír, na kterém se vřele proplétají uličky a jména obchodů. Vedení plné srdce je vždy vřelejší než cesta samotná."},"ICON-0227":{"nm":"Plán pohybu","de":"Papír, na kterém je každý krok na jevišti nakreslen jako čára. Kde se zastavit, kde se otočit, to šipky slibují předem. I tanec, který působí volně, ve skutečnosti začíná právě na tomhle jediném listu."},"ICON-0228":{"nm":"Rozpis sedadel","de":"V neznámém prostoru je první věc, kterou tápavě hledáš, tvé vlastní místo. Ono jediné políčko, ke kterému se konečně dostaneš díky řadě a číslu. Jediný list papíru pěkně, jedno po druhém, usadí tisíce rozechvění přesně na jejich místo."},"ICON-0229":{"nm":"Uliční průvodní kartička","de":"Návod, který někdo vlastní rukou napsal pro toho, kdo by mohl zabloudit v bludišti uliček. Laskavé písmo, které říká, na kolikátém rohu zahnout. Vlídnost čtvrti, úhledně vepsaná do jediné malé kartičky."},"ICON-0230":{"nm":"Bezpečnostní karta","de":"Teprve když si tuhle kartu pověsíš na krk, otevřou se dveře do vnitřního světa. Malé oprávnění, které dovoluje vstup, a tichý důkaz, že sem patříš. Její váhu zná jen ten, kdo ví, kolik času stálo ji získat."},"ICON-0231":{"nm":"Denní náramek","de":"Jednou si ho připneš na zápěstí a jsi členem toho dne, dokud ho nesundáš. Jediný papírový pásek odděluje vnitřek od venku a stává se znamením, že jsi strávil stejný den společně s ostatními. I po odstřižení tam stopa ještě dlouho zůstává."},"ICON-0232":{"nm":"Hostovská jmenovka","de":"Díky jedné malé jmenovce přilepené na hrudi se neznámé místo stává tvým místem. Když se slovo „vítej“ předá na jediném listu papíru, i ten, kdo přišel poprvé, se konečně stává hostem."},"ICON-0233":{"nm":"Tubus na plakát","de":"Pevný válec, který uchrání srolovaný plakát bez jediného zalomení. Protože čím vzácnější obrázek, tím rovněji musí být poslán. Zevnitř není nic vidět, přesto vyráží na cestu s něčí péčí v sobě."},"ICON-0234":{"nm":"Obal na materiály","de":"První list, který obepíná tlustý svazek podkladů. Tvář, které se ruka dotkne dřív než obsahu. Když je obálka upravená, i to smýšlení uvnitř působí upraveně – vlídný začátek malé formality."},"ICON-0235":{"nm":"Vzpomínková pohlednice","de":"Na kousek vzdálené scenérie napíšeš pár slov na pozdrav a odešleš je. Než dorazí, i odeslaná náklonnost trochu zestárne a stane se o to milejší. Pomalé teplo psaného dopisu, které zpráva na obrazovce nikdy nedožene."},"ICON-0236":{"nm":"Dárková visačka","de":"Malý lístek papíru přivázaný k dárku. Balení je hotové už jen díky třem slovům „pro tebe“. Nejkratší dopis na světě, který nezapisuje, co dáváš, ale na koho jsi myslel."},"ICON-0237":{"nm":"Role balicích nálepek","de":"Pokaždé, když odtrhneš kousek k použití, výsledek vypadá o to úhledněji. Malý uzlík, který pěkně přidrží konec, jenž se chystá povolit. Poslední tah pečlivě zabaleného dárku vždy pochází z téhle stočené pásky."},"ICON-0238":{"nm":"Průhledný obal na dopis","de":"Průhledná vrstva, která obalí ručně psaný dopis, aby jej čas nevybledl. Písmo zůstává vidět, ale otisky rukou už se ho nedotknou. Neviditelná blána tiše střeží něčí opatrované srdce."},"ICON-0239":{"nm":"Barevná vosková pečeť","de":"Poslední tečka, která uzavírá obálku – čím sytější barva, tím méně srdce z ní uniká. Slib, že se jí do rozlepení nedotkla žádná ruka. I tajemství potřebuje takhle hezký uzel."},"ICON-0240":{"nm":"Knížka vzkazových visaček","de":"Malá knížka svazující krátké vzkazy dohromady. Každá stránka je jedno slovo připravené pro někoho. Když takhle poskládáš slova, která jsi nestihl vyslovit, jednou z nich vyroste odvaha je opravdu doručit."},"ICON-0241":{"nm":"Skládací cedule","de":"Rozložená říká „tudy“, složená „na dnes je konec“. Celý den stojí s nohama rozkročenýma u ústí uličky pro toho, kdo by mohl zabloudit. Večer, kdy se skládá, je pro mě tou nejněžnější chvílí odpočinku."},"ICON-0242":{"nm":"Poštovní páska","de":"Ovineš-li kolem sebe hromadu pohlednic, roztroušené pozdravy se konečně stanou jedním svazkem srdce. Jediná lehká páska úhledně sváže slova mířící do daleka a tiše vyprovodí záda, která se vydávají na cestu."},"ICON-0243":{"nm":"Svazek děkovných lístečků","de":"Protože slovo „děkuji“ pořád sklouzává z jazyka, napíšeš ho na lísteček velký jako dlaň a tiše ho svážeš. Čím tlustší je svazek, tím víc bok po boku roste i tíha srdce, které někomu dlužíš."},"ICON-0244":{"nm":"Vzorový list pokřiků","de":"Jeden vzorový list s nápisem „takhle to skandujte“. Pokřik, na který se ještě nenavěsil hlas, chová v sobě jen tiché rozechvění, jako prázdná notová osnova čekající na první takt."},"ICON-0245":{"nm":"Lísteček žádosti o předtáčení","de":"Vzkaz s prosbou o rezervaci předtáčení vždy zůstává v kolonce páté hodiny ranní. Ten malý papírek si tiše zapisuje, jako by všemu rozuměl, srdce, které si zkracuje spánek, aby si zajistilo místo."},"ICON-0246":{"nm":"Lístek pořadí na fanpodpis","de":"Jediný list, který určuje, v jakém pořadí předáš svůj pozdrav. Stát ve frontě neznamená čekat na svou řadu – je to chvilkové vypůjčení pořadí, protože svou náklonnost prostě nejde vyjádřit číslem."},"ICON-0247":{"nm":"Náramek s pořadovým číslem","de":"Jediné číslo rozhoduje, v jakém pořadí se dnes zařadíš do fronty. Ať už jsi vpředu, nebo vzadu, lidé nosící tenhle malý lehký pásek na zápěstí jsou nakonec spřízněné duše, které se sešly, aby viděly totéž jeviště."},"ICON-0248":{"nm":"Tabulka na třídění fotokaret","de":"Ačkoli je to stejná tvář, tvrdíš, že jsou všechny jiné, a zapisuješ je políčko po políčku zvlášť. Čím plnější tabulka, tím uspořádanější srdce, a to jedno prázdné políčko rozbuší hruď touhou, kterou dnes chceš zaplnit."},"ICON-0249":{"nm":"Kontrolní seznam alba","de":"Verze, fotokarty, dokonce i to, zda je zapečetěné – seznam náklonnosti zapsaný v číslech. S předstihem si maluješ pýchu dne, kdy bude vše zaškrtnuto, a i dnes pěkně zakroužkuješ další řádek."},"ICON-0250":{"nm":"Návod na pokřiky","de":"Tvar rukou, takt výkřiku, dokonce i místa, kde se popadne dech. Aby se i nováček rychle vmísil do jednoho hlasu, malý lísteček se stává laskavým průvodcem, který putuje z ruky do ruky."},"ICON-0251":{"nm":"Soukromý poznámkový blok","de":"Sem si zapisuješ jen ty věty, které nikomu neukážeš. Že nejupřímnější je stránka, kterou jsi nikdy neotevřel, to tenhle blok tiše střeží se zavřenými deskami."},"ICON-0252":{"nm":"List výročních razítek","de":"Přitiskneš a další den se stává výjimečným. Jediným malým razítkem ťuknutým na obyčejné datum si „dnešek“ potají zapíše jméno na seznam dní hodných vzpomínání."},"ICON-0253":{"nm":"Obal na psací desky","de":"Ať fouká vítr, ať bije déšť, sepnutý papír uchrání až do konce. Já, kdo jsem si vzal na sebe roli brnění desky, jsem spolehlivý osobní strážce popsaných písmen."},"ICON-0254":{"nm":"Rejstříkový štítek","de":"Aby ses neztratil v tlustém svazku podkladů, vystrčí malý jazýček a ohlásí „tady“. Jeden barevný štítek na první pohled ovládne stovku stránek."},"ICON-0255":{"nm":"Kategorizační štítek","de":"Tohle do téhle přihrádky, tamto do tamté. Mým úkolem je uklidit zmatek světa úhledně, řádek po řádku. Ve chvíli, kdy se přilepí štítek, si zpřeházené věci konečně najdou své místo."},"ICON-0256":{"nm":"Mini schvalovací deska","de":"Ve chvíli, kdy razítko ťukne dolů, se nějak cítíš jako opravdový dospělý. Malá velikostí, ale s čiperskou autoritou – jedno schvalovací razítko a nahromaděná práce se svižně uzavře."},"ICON-0257":{"nm":"Průhledné pouzdro na dokumenty","de":"Uvnitř je jasně vidět, není co skrývat. Chová v sobě důležitý papír a vlastním průhledným tělem ho obepíná, aby se nenamočil deštěm ani nezmačkal, a odnese ho až na místo setkání."},"ICON-0258":{"nm":"Docházková páska","de":"Přišel jsi, a další políčko se zaplní. Když se každodenní stopy hromadí v řadě podél pásky, neviditelná svědomitost se konečně stane vzorem viditelným na první pohled."},"ICON-0259":{"nm":"Sešit chyb","de":"Zapisovat si, co jsi udělal špatně, není hromadění hanby. Aby ses na stejném místě nepotkl podruhé, přepisuješ včerejší chybu do dnešního rádce."},"ICON-0260":{"nm":"Razítková deska rozvrhu","de":"Ťukneš razítkem do prázdného rozvrhu a zrodí se „slib“. Kouzlo dne rozhodnutého jediným švihem zápěstí – to kouzlo je vlastně jen jiné jméno pro pilnost toho, kdo si věci připravuje s předstihem."},"ICON-0261":{"nm":"Štítek na hřbet knihy","de":"Jmenovka knih stojících hřbetem otočeným k regálu. Krátká písmena vepsaná do úzkého hřbetu jediným pokynem přivolají tu jedinou knihu, kterou jsi hledal mezi stovkami dalších."},"ICON-0262":{"nm":"Ochranný list na fotografie","de":"Holé ruce zakázány. Jako by říkala, ať nezanecháš ani jediný otisk prstu, jemně se pokládá na vzácný snímek. Milující srdce takhle díky opatrné péči vydrží dlouho, předlouho."},"ICON-0263":{"nm":"List filmového rejstříku","de":"Přidáš-li číslo ke každému pásku filmu, roztroušené okamžiky znovu naleznou svůj pořádek v příběhu. Malý průvodce, který pečuje o vzpomínky zapsané světlem, aby se nepomíchaly."},"ICON-0264":{"nm":"Kapsa na fotografie","de":"Průhledný domov, kde se čtvercové kousky štěstí ukládají jeden po druhém jako v svatyni. Bez obav o pomačkané rohy tu ta nejmilejší tvář úhledně září po všechna čtyři roční období."},"ICON-0265":{"nm":"Mini obálka na fotky","de":"Než teplo čerstvě vyvolané fotografie vůbec vychladne, malá obálka ji rozevřenýma náručemi přijme. Jeden snímek, který vstoupí ústím velkým jako dlaň, se dřív, než se naděješ, stává pokladem v něčí tašce."},"ICON-0266":{"nm":"Lentikulární obal","de":"Mým úkolem je bez jediného škrábnutí uchránit vrtošivou fotografii, jejíž výraz se mění, když ji nakloníš. Ochránit každou jinou tvář z každého úhlu – k tomu musím být i já sám náramně pilný."},"ICON-0267":{"nm":"Štítek na třídění záběrů","de":"Který ze čtyř záběrů je nejlepší, to za tebe ukáže štítek. Tenhle drobný úkol, rozdělit vydařené a vtipné vedle sebe, je tajemstvím, jak si vzpomínku vychutnat dvakrát."},"ICON-0268":{"nm":"Páska na fotopásek","de":"Úhledně ováže úzkou, dlouhou vzpomínku o čtyřech políčkách. Pevně obejme do jednoho svazku smích onoho dne, který se chystal rozprchnout, a bezpečně ho donese až do hloubi tašky."},"ICON-0269":{"nm":"Rohová nálepka na fotky","de":"Když lepíš fotografii do alba, malá ruka, která jemně přidrží její čtyři rohy. Aby neodpadla, aniž bys ji celou zamazal lepidlem – jemnost takhle začíná právě od rohů."},"ICON-0270":{"nm":"Tabulka úprav tisku","de":"O trošku tepleji, o kousek méně jasně. Jediná tabulka, na které pomrkáváš čísly, dokud nevyjde barva podle tvého gusta, tiše promění obyčejný snímek v umělecké dílo."},"ICON-0271":{"nm":"Klip na účtenky","de":"Úhledně sevře pomačkané účtenky a nepustí je. Svými malými ústy si zručně hlídá denní útratu, takže měsíční vyúčtování je pak o poznání lehčí."},"ICON-0272":{"nm":"Potvrzenka rezervace","de":"Při jediném řádku „rezervace potvrzena“ se srdci pomalu uleví. Jediný list papíru se stává důkazem slibu a pěkně, kousek po kousku, uchovává rozechvění až do vytouženého dne."},"ICON-0273":{"nm":"Potvrzenka o vrácení","de":"Malý, ale hrdý důkaz, že jsi vrátil vypůjčenou věc zpátky na místo. Ve chvíli, kdy tenhle papír držíš v ruce, se lehce smaže jeden dluh, který ležel v koutku srdce."},"ICON-0274":{"nm":"Pouzdro na úschovní lístek","de":"Abys neztratil lístek na vyzvednutí svěřené věci, budu ho místo tebe pevně držet já. Vždyť osud jednoho malého papírku dokáže rozhodnout o konci něčího dne."},"ICON-0275":{"nm":"Ocásek půjčovního štítku","de":"Malá visačka, která se pohupuje na každé vypůjčené věci. Sleduj tenhle ocásek a hned se ukáže, kdo si co odnesl, takže i záhada ztracené věci se rychle vyřeší."},"ICON-0276":{"nm":"Kontrolní list přejímky","de":"Očima projedeš každou položku a hlídáš, jestli něco nechybí. Když se zaškrtávací políčka jedno za druhým zaplní, neviditelná pečlivost si konečně vyslouží jméno důvěra."},"ICON-0277":{"nm":"Obálka na vyúčtování","de":"Zapíšeš-li na obálku peníze, které přišly a odešly, rozházená čísla se klidně srovnají do řady. Konec vyúčtování vždycky uzavře tečkou právě tenhle malý poznámkový lísteček."},"ICON-0278":{"nm":"Přepravní štítek","de":"Vyráží na cestu s vepsaným tím, kam míří a ke komu dorazí, přímo na vlastním těle. Ve chvíli, kdy se tenhle štítek nalepí, se z krabice stává cestovatel s cílem a s rozechvěním vyráží na cestu."},"ICON-0279":{"nm":"Páska potvrzení převzetí","de":"Slovo „v pořádku doručeno“ sváže do jediné pásky a pošle ho zpátky. Úleva toho, kdo přijal, a klid toho, kdo poslal, se na téhle malé šňůrce tiše chytí za ruce."},"ICON-0280":{"nm":"Kroužek na kartičky se slovíčky","de":"Slova, která by se ztratila, kdyby se rozsypala na volné listy, jediný malý kroužek proplete a pevně udrží pohromadě. Listuješ jimi znovu a znovu, a než se naděješ, cizí slova se stanou přáteli, kterým si zvykl jazyk."},"ICON-0281":{"nm":"Páska poznámek k výslovnosti","de":"Na místo, kde ti jazyk pořád sklouzává, pověsíš malý štítek. I neznámý zvuk, který se ztrácel v ústech, díky téhle poznámce dřív, než se naděješ, najde svou správnou výslovnost. První stránka krocení neohrabaného zvuku, kousek po kousku."},"ICON-0282":{"nm":"Krabička na překladové lístečky","de":"Malé mosty, které přemosťují slovo a slovo, leží v ní úhledně poskládané, jeden do každé přihrádky. Napíšeš pracně vybranou větu a nenápadně ji podáš, a i srdce, které se nedokázalo domluvit, se přiblíží díky jedinému lístečku mezi nimi."},"ICON-0283":{"nm":"Výstřižek s citátem","de":"Věta, která se přesně dotkne srdce, vydrží jen tehdy, když ji přepíšeš rukou. Nalep si řádek vystřižený z rohu knihy před stůl, a ta písmena tiše podepřou dnešek, který se propadal."},"ICON-0284":{"nm":"Poznámkové záložky","de":"Barevné praporky zastrčené do tlusté knihy, abys v ní neztratil cestu. Že se dá zabloudit dál jen tehdy, znáš-li místo návratu, o tom ti tiše šeptají výstupky vykukující z tabů mezi stránkami."},"ICON-0285":{"nm":"Kontrolní čip zapamatování","de":"Jediná značka ťuknutá vedle toho, co sis zapamatoval. Malá kotva, která zadrží věci, jež na chvíli zabloudí do hlavy a chystají se zas zmizet, takže v každém začerněném políčku tiše dřímá včerejší vynaložené úsilí."},"ICON-0286":{"nm":"Balíček obálek s kvízem","de":"Dokud obálku neroztrhneš, nikdo netuší, co z ní vypadne. Těch pár vteřin, kdy si prsty pohráváš se zapečetěným místem – balíček rozechvění, ve kterém je úhledně složená jediná otázka a spolu s ní zapečetěné i tlukot srdce."},"ICON-0287":{"nm":"Sešit s gramatickými záložkami","de":"Pravidla se neučí hlavou, ale vpisují se do ruky. Od barevné záložky nejčastěji otevírané stránky až po sešit, který se měkce a pomalu opotřebovává – ty omšelé rohy se stávají letokruhy času, který jsi vydržel."},"ICON-0288":{"nm":"Tabulka na procvičování mluvení","de":"Jediná tabulka pro toho, komu je otevřít ústa tou nejtěžší věcí na světě. Sjíždíš prstem políčko za políčkem dolů, a i první slova, která se chvěla v hrdle, dřív, než se naděješ, najdou svůj hlas. Vždyť i odvaha má svůj pořadník."},"ICON-0289":{"nm":"Barevný náčrt","de":"Barvy před dokončením leží drsně rozprostřené a popadají dech. Ne odpověď, ale stále ještě možnost – na tomhle nedokonalém listu se rozvlňuje víc zítřků než na čemkoli jiném."},"ICON-0290":{"nm":"Kousek moodboardu","de":"Slepíš-li na jedno místo dohromady jednotlivě roztroušené dojmy, atmosféra, která ti dosud nešla uchopit, matně odhalí svůj obrys. Nějaký pocit, který ještě nemá jméno, na něj kousky, opřené o sebe, tiše ukazují."},"ICON-0291":{"nm":"Vzorník vzorků","de":"Mřížoví ubrouskového uzlu a splet okenní mříže jsou úhledně srovnané ve svazku, stránku po stránce. Tam, kde se stejný vzor opakuje až do konce, nesídlí lenost, ale slib – pevné srdce, které si drží jednu linii."},"ICON-0292":{"nm":"Vzorník kostýmních látek","de":"Ačkoli je to stejné světlo, na každém kousku látky se jinak usadí lesk i stín. Než vybereš scénický kostým, noc strávenou váháním, kdy jsi ho desetkrát přejel prsty, tenhle jediný vzorek beze zbytku uchová."},"ICON-0293":{"nm":"List zakázaných úprav loga","de":"Papír, který jako první zřetelně vypíše to, co se nesmí dělat. V obrysu přeškrtnutém červeným křížkem se svoboda naopak vyjasní, takže na místě, kde jsi čekal slepou uličku, se otevře nová cesta."},"ICON-0294":{"nm":"Barevný referenční čip","de":"Vzorový kousek vyrobený zvlášť, protože barvu prostě nejde slovy popsat. Zachytí na malou dlaň onen okamžik, kdy západ slunce hořel nejruději, aby ho mohl příště přesně předat dál se slovy „tohle je přesně ta barva“."},"ICON-0295":{"nm":"Karta rozvržení náčrtu","de":"První kresba, lehce načrtnutá, co kam umístit. Rozhodnout o umístění znamená vlastně rozhodnout se v srdci, takže mezi neohrabaně rozházenými linkami se pomalu otevírají oči rovnováhy celku."},"ICON-0296":{"nm":"Nástěnka poznámek k materiálu","de":"Dřevo, hlína, kámen – jména hmatatelných věcí jsou na ní hustě popsaná. Tajemství, které zná jen ten, kdo začíná tím, že rukou nejdřív přečte strukturu – z čeho stavíš, z poloviny už rozhoduje, čím se to stane."},"ICON-0297":{"nm":"Průsvitka na obkreslování","de":"Položíš tenký papír na podkresbu a tiše obkresluješ linky. Zatímco si na chvíli půjčuješ cizí cestu, ruka se ji učí, a mezi kopírovanými čarami se nenápadně, dřív než se naděješ, klube vlastní čára."},"ICON-0298":{"nm":"Páska pro vstupní trasu","de":"Lidé vcházejí v řadě podél pásky nalepené dlouze po podlaze. Jediná linka, která tiše vede, aby se rozjásané kroky nezamotaly – neviditelná něžná ruka, jež podepírá rozechvění, aby se nezhroutilo."},"ICON-0299":{"nm":"Cedule s pokyny na akci","de":"Cedule stojící místo slov „tudy prosím“. Malá laskavost postavená na každé křižovatce, aby nikdo nezabloudil, tiše provádí neznámý den nováčka za ruku."},"ICON-0300":{"nm":"Štítek s číslem stánku","de":"Jediné číslo přidělené každému stánku jasně určuje majitele toho místa. Malé číslo, ale je slibem, že „tohle je tvoje místo“, takže i na neznámé akci máš kam se vracet."},"ICON-0301":{"nm":"Formulář souhlasu štábu","de":"Jeden řádek podpisu zanechaný tam, kde se srdce shodla, že budou pracovat společně. Je to jen tenký list papíru, ale nese váhu rozhodnutí důvěřovat jeden druhému, a právě tady začíná každá pomocná ruka na akci."},"ICON-0302":{"nm":"Svazek zkušebních poukazů","de":"Baculatý svazek zkušebních poukazů, svázaný tak akorát do dlaně. Čím víc se rozdává, tím míň se zmenšuje a tím víc cizích „poprvé“ přibývá — svazek dobré vůle, který čím víc se ho dotýkáš, tím víc hřeje."},"ICON-0303":{"nm":"Značka fronty","de":"Odsud čekejte, šeptá tiše podlaha. Když se srdce, která dodržují pořadí, sejdou dohromady, i dlouhá fronta se stane vlastní scenérií, a jedna malá značka mění netrpělivost v klid."},"ICON-0304":{"nm":"Visačka osobního vyzvednutí","de":"Malá visačka, která se lehce zachytí v místě, kde si přebíráš to, co sis předem objednal. Ve chvíli, kdy ji sevřeš v ruce, sklouzne z ramen ta jemná úleva — uzel, ve kterém dlouho čekající srdce konečně dostane tvar."},"ICON-0305":{"nm":"Lístek na záhadnou krabičku","de":"Radost z výběru jednoho, aniž bys věděl, co je uvnitř. Zatřeseš a srdce se rozbuší dřív než ozvěna cinkotu zevnitř, a ta chvilka těsně před otevřením se stává tou nejnabubřelejší nadějí celého dne."},"ICON-0306":{"nm":"Samolepka dokončené výměny","de":"Malé kulaté razítko oznamující, že výměna proběhla hladce. Je to hladká tečka zanechaná mezi rukama, které dávaly a přijímaly, a jakmile se přilepí, obchod se konečně teple zaokrouhlí."},"ICON-0307":{"nm":"Pečetící páska záznamu","de":"Vzácná krabička je jednou omotána páskou a tiše zapečetěna. Je to prosba, aby ji nikdo neotvíral bezmyšlenkovitě, a zároveň nejtišší projev úcty k tomu, co je uvnitř — vše se vejde do jediného pruhu pásky."},"ICON-0308":{"nm":"Kapsle s tajným vzkazem","de":"Slovo, které jsi chtěl vyslovit, je jemně uzamčeno uvnitř malé tuby. Zavřeš ji pevně, jako bys pohřbíval pocit, který jsi nedokázal odeslat, a malý trezor v dlani hlídá čas až do dne, kdy ji znovu otevřeš."},"ICON-0309":{"nm":"Malá výstřižková kartička","de":"Vystřižený a přilepený kousek v sobě jemně nese náladu toho dne. Lehčí než deník a osobitější než fotografie — list papíru velký jako dlaň pevně drží den, který by jinak snadno proklouzl mezi prsty."},"ICON-0310":{"nm":"Záznamový list první návštěvy","de":"Chvění dne, kdy jsi poprvé vkročil na tento ostrov, zůstává zachyceno v jednom krátkém řádku. Těsně předtím, než se cizost proměnila v důvěrnost, papír místo tebe uchovává tu nejčistší první chvíli a opatruje ji dlouho."},"ICON-0311":{"nm":"Třídicí tabulka vzpomínek","de":"Tabulka, do níž se vzpomínky pečlivě zapisují podle druhu a odvětví. Když všechny vzpomínky nahážeš do jedné zásuvky, i ten nejmilejší den se pod nimi ztratí — čím vzácnější věc, tím laskavěji si zaslouží vlastní místo."},"ICON-0312":{"nm":"Bublinový vzkazový čip","de":"Slova, která jsi chtěl říct, se nafoukla kulatě jako balónek a vznášejí se na papíře. I věta, kterou jsi nedokázal vyslovit nahlas, uvnitř kulatého okraje potichu sebere odvahu — malá teplá skulinka, kudy srdce může uniknout ven."},"ICON-0313":{"nm":"Stojánek na datum","de":"Malý stojánek, který postaví dnešní datum zpříma, aby ti hledělo do očí. Vybereš jeden jediný den z těch, co plynou v řadě, a posadíš ho doprostřed — a i obyčejné datum tak získá teplo hodné oslavy."},"ICON-0314":{"nm":"Sběratelské číslo","de":"Jedinečné číslo přidělené každé věci, kterou si vážíš. Sbírat znamená slíbit, že tuhle jedinou věc budeš na světě nazývat tou jedinou svého druhu — a proto na malé visačce zřetelně vyryté číslo nese váhu srdce."},"ICON-0315":{"nm":"Archivní obal","de":"Tenký vnitřní obal, do kterého po jednom zasouváš věci, jež si chceš schovat na dlouho. Uložit něco jen o vrstvu dál od světla a času — milovat něco totiž nakonec znamená umět to dobře opatrovat."},"ICON-0316":{"nm":"Poutko na toploader","de":"Tenoučké poutko, které umožní zavěsit toploader kolem krku. Je to způsob fanouškovství — procházet dnem s oblíbencem u srdce — a na této tenké šňůrce je uvázán celý den něžného doprovodu."},"ICON-0317":{"nm":"Špendlík na stojánek fotokartičky","de":"Stačí jeden malý špendlík a fotokartička se na stole postaví zpříma. Naplocho je to jen list papíru, ale vzpřímeně se z ní stává tvář, se kterou se setkáváš pohledem — tiše tak vytváří místo, kde se oči mohou dlouho zdržet."},"ICON-0318":{"nm":"Holografická fólie na fotokartičky","de":"Jediná tenká fólie, ze které při každém úhlu stéká duha. Vrstva, jež zachytí kousek světla, oblékne obyčejnou kartičku do hvězdného svitu — malé kouzlo, kdy se s každým máchnutím zápěstí probudí jiný záblesk výrazu."},"ICON-0319":{"nm":"Ochranný obal na fotokartičku","de":"Stačí zmáčknout roh a zdá se, že se s ním přehne i to vzácné srdce. Průhledné brnění, které pevně objímá jeden drahocenný list — taková opatrnost jde vždycky ruku v ruce s opravdovým vážením si něčeho."},"ICON-0320":{"nm":"Zásobník na řazení fotokartiček","de":"Mělký zásobník, do kterého se v řadách ukládají desítky fotokartiček ke spánku, jedna vedle druhé. Rozházené jsou jen hromádkou, ale srovnané do řad se stávají sbírkou, a s každým uspořádáním se do nich vrývá pořadí náklonnosti."},"ICON-0321":{"nm":"Obálka na výměnu fotokartiček","de":"Když vkládáš fotokartičku do obálky, abys ji předal dál, prsty se na okamžik zaváhají. Není to loučení, ale prosba, ať se stane něčím oblíbencem. Ve chvíli, kdy zalepíš chlopeň, tiše změní majitele jedno malé pouto."},"ICON-0322":{"nm":"Zdobicí fix na fotokartičky","de":"Prázdné místo nevyplňuje písmo, ale cit. Kudy pero prošlo, tam vyklíčí malá srdíčka a hvězdičky, a obyčejný list papíru se probouzí jako jedinečné povzbuzení. Zdobení je jen jiné jméno pro vyznání."},"ICON-0323":{"nm":"Kroužek se sponkou na fotokartičky","de":"Cvak, ozve se, jak se sponka zaklapne. Tím jedním malým zámkem se kartičky, co se málem rozprchly, spojí do jedné řady. I když se celý den třesou v tašce, ani jeden roh se nepoškodí. Pevnost dokáže být takhle tichá."},"ICON-0324":{"nm":"Pouzdro na přenášení fotokartiček","de":"Do ruky, která zip otevírá a zavírá, se nenápadně vryl zvyk. Ať přijde náhlá přeháňka nebo tlačenice davu, jen vnitřek zůstává suchý. Mít to, co si nejvíc vážíš, na nejhlubším místě — to je něžná práce zvaná přenášení."},"ICON-0325":{"nm":"Šňůrka na náramek z fan meetingu","de":"Jedna fanynka si dlouho pamatovala, jak vřelé měl personál ruce, když jí vázal šňůrku na zápěstí. Jediný uzel je znamením, že dnes patříš sem. Dvakrát omotaná, aby nepovolila, tahle šňůrka drží na místě celodenní rozechvění."},"ICON-0326":{"nm":"Vstupní náramek","de":"Přesně v okamžiku, kdy projdeš vchodem, se konečně jasně rozdělí uvnitř a venku. Nošený celý den brzy přiroste ke kůži a v čase, kdy ho sundáváš, po něm zůstane jemná stopa — jako důkaz místa, kde jsi setrval."},"ICON-0327":{"nm":"Žeton talk showové sekce","de":"Jakmile se otevře talk sekce, žeton se s cinkáním rozkutálí. Kdo promluví první, jaká otázka se vylosuje — ta malá náhoda dokáže obrátit celou atmosféru vzhůru nohama. Vrtoch jednoho žetonu je milejší než jakýkoli sepsaný scénář."},"ICON-0328":{"nm":"Pořadový lístek na autogramiádu","de":"Do ruky sevřeš očíslovaný lístek a postavíš se do fronty. Číslo 142. Zatímco počítáš 141 lidí před sebou, srdce už počítá svou vlastní řadu. Čekání je dlouhé, ale díky jednomu lístku se i ten čas stává součástí toho rozechvění."},"ICON-0329":{"nm":"Rukavice na hi-touch","de":"Ve zlomku okamžiku, kdy se dlaně dotknou, rukavice místo tebe zachytí to prchavé teplo. Ruka hřátá celý den kvůli půlvteřinovému doteku. Teprve tehdy člověk pozná, že ani látka to zachvění nedokáže úplně zadržet."},"ICON-0330":{"nm":"Odznak na památeční fotografii","de":"Cvak, jedním zvukem se dnešek beze zbytku zakonzervuje. V rámečku přidrženém odznakem se i nešikovně vypadající úsměv jednou stane tou nejpostrádanější scénou. Zaznamenávat je ta nejněžnější chamtivost — chtít udržet okamžik."},"ICON-0331":{"nm":"Stužka na sedadlo","de":"Malá stužka pověšená na opěradle se pohupuje, i když nefouká vítr. Znamení, které tam někdo uvázal, stopa, že tu byl člověk. I na prázdném sedadle po skončení představení se zdá, že jen ona stužka si ještě pamatuje rytmus."},"ICON-0332":{"nm":"Kontrolní štítek na dárky","de":"Na každý jednotlivý dárek se lepí štítek. Jestli byl odeslán, jestli byl zkontrolován, jestli nic nechybí. I přijímání cizího citu potřebuje svou domácí péči, a tahle malá samolepka spojuje pečlivost s pečlivostí beze mezery."},"ICON-0333":{"nm":"Pamětní lístek","de":"List papíru popsaný proto, aby zůstal na dlouho k prohlížení. Počasí toho dne, číslo sedadla, dokonce i název poslední skladby. Vzpomínka bledne, ale jen tenhle lístek ne. I uchovávání vzpomínek si žádá svůj malý formulář."},"ICON-0334":{"nm":"Poutko na fanouškovský ručník","de":"Provlečeš poutko koncem ručníku a už nesklouzne z ramen. Mezi utíráním potu, roztočením nad hlavou a znovu přehozením kolem krku. Jedno malé spojení udrží gesta povzbuzování bez přerušení."},"ICON-0335":{"nm":"Sponka na transparent","de":"Sponky pevně svírají oba konce transparentu. Aby se písmena ani při zvednutých pažích nesložila ani nezavlnila. Tady, mimo pohled, stojí ten nejtišší vedlejší hrdina, který drží zprávu rovně."},"ICON-0336":{"nm":"Ztlumující pouzdro","de":"Zip klouže pomalu a bez zvuku. Ticho navržené tak, aby na místě, kde je slíbený klid, neunikl ani jediný hluk. Ohleduplnost někdy znamená udělat se neslyšným, tiše říká tohle pouzdro."},"ICON-0337":{"nm":"Rytmický žeton na tleskání","de":"Pokaždé, když se dlaně srazí, čip počítá takt. Ťap, ťap, ťap — roztroušené tleskání se v jistém okamžiku sloučí do jednoho rytmu. Kouzlu, kdy se tisíce potlesků promění v jeden nádech, tiše pomáhá malý čip."},"ICON-0338":{"nm":"Složka s fanouškovskými pokyny","de":"Rozevřeš ji a fanouškovský postup je vypsaný krok za krokem. Jakou barvu zvednout na kterém verši, kdy přidat pokřik. I nováček se s touhle jedinou složkou hned stane součástí rodiny. Malý průvodce, jak sdílet slib."},"ICON-0339":{"nm":"Šňůrka na vějíř","de":"Přivážeš šňůrku na rukojeť vějíře a on ti nespadne, i kdyby ti vyklouzl z ruky. V horký den, když se po mávání obě ruce uvolní k jásání, houpe se na zápěstí. Jedna šňůrka najednou ochladí horko i vzrušení."},"ICON-0340":{"nm":"Kousek třpytivé fólie","de":"Zachytí-li světlo, každý kousek ho rozláme do jiného úhlu. Položíš ho na dlaň a zatřpytí se malá duha, s každým zatřesením barvy ožívají. Třpyt je možná jen umění rozdělit si světlo na drobné kousky."},"ICON-0341":{"nm":"Malá tyč na transparent","de":"Vytáhneš malou tyč a látka se napne ve větru. Zvedneš ji vysoko oběma rukama a písmena dosáhnou až za hlediště, sklopíš ji a vejde se do kapsy tašky. Velikost srdce se neměří délkou tyče."},"ICON-0342":{"nm":"Balíček fanouškovských samolepek","de":"Na každé samolepce je vyraženo povzbudivé heslo. Do diáře, na telefon, na roh notebooku — kamkoli je nalepíš, každodennost se zabarví povzbuzením. Takhle zamilované srdce zanechává stopy úplně všude."},"ICON-0343":{"nm":"Ochranný obal na album","de":"Ruka, která balí album do obalu, je opatrná. Aby se rohy neodřely, aby nevybledly na slunci. Hudbu slyší uši, ale tenhle jeden list si pamatují ruce. Je to brnění srdce, které chce mít to, co miluje, dlouho po boku."},"ICON-0344":{"nm":"Kroužkové pouzdro na disky","de":"Vložíš disky do obalů a svážeš kroužkem, a stane se z nich jedna deskotéka. Šustivý zvuk při každém otočení stránky je příjemný. Sesbírat roztroušenou hudbu úhledně do dlaně — to je tichá radost sběratele."},"ICON-0345":{"nm":"Přihrádkový organizér na merch","de":"Jedna přepážka a merch, který se málem promíchal, najde svoje místo. Tady fotokartičky, tam klíčenky, vedle nich lightsticky. Uspořádat znamená postavit věcem domov. V okamžiku, kdy se rozdělí přihrádky, se zmatek promění v řád."},"ICON-0346":{"nm":"Zapečeťovací šňůrka na náhodný balíček","de":"Svážeš ústí náhodného balíčku šňůrkou a nikdo osud ještě není rozhodnutý. Dokud ho nerozvážeš, každý je hlavní postavou vlastní naděje. Chvění prstů, které rozvazují pečeť, je tou pravou radostí, kterou tahle šňůrka celou dobu opatruje."},"ICON-0347":{"nm":"Krabice na řazení bonusů","de":"Bonusy se v krabici řadí podle druhu. Pohlednice s pohlednicemi, záložky se záložkami. Podívej se, jak se přihrádky s přibývajícím množstvím plní víc a víc, a najednou uvidíš na jeden pohled všechen čas, který jsi sbíral. Třídit znamená sepisovat seznam vzpomínek."},"ICON-0348":{"nm":"Štítek na rozlišení verzí","de":"Existují věci, které vypadají stejně, a přece stejné nejsou. Jeden štítek odliší verzi A od verze B, první vydání od dotisku. Díky malému znaku zmizí zmatek a do světa sběratelství přibude jedna jasná jmenovka."},"ICON-0349":{"nm":"Poznámka k prvotýdenním prodejům","de":"První týden po vydání, a jedno jediné číslo rozhoupe srdce. Zaškrtávací značky úhledně zapsané na poznámkovém papíře. Sesbírej záznamy pár dní a stane se z nich malá vysvědčení podpory. Pečlivý zvyk, jak přeložit zamilované srdce do čísel."},"ICON-0350":{"nm":"Zajišťovací krytka na plakát","de":"Nasadíš krytku na konec smotaného plakátu a on zůstane klidně rozvinutý. Aby se nezmačkal, zatímco přemýšlíš, jestli ho pověsit na zeď, nebo dát do rámu. Malá zátka, která tvou nejoblíbenější scénu udržuje dokonale rovnou."},"ICON-0351":{"nm":"Stojánek na fotografii","de":"Fotografie stojí na stojánku mírně nakloněná. V rohu stolu, přesně v úhlu úrovně očí. Vynález, díky kterému se s ní setkáš pohledem pokaždé, když projdeš kolem. Nejjednodušší způsob, jak přizvat oblíbenou tvář do každodenního výhledu."},"ICON-0352":{"nm":"Role zkušební pásky","de":"Na podlahu se lepí páska, aby označila místo, kde máš stát. Jedno políčko, druhé políčko, přesně tady. Po desítkách šlápnutí na stejnou stopu se choreografie vryje do těla. Pod okázalým jevištěm leží právě tyhle poctivé stopy pásky."},"ICON-0353":{"nm":"Kolíček pro pohyb po jevišti","de":"Jeden kolíček zapíchnutý do podlahy jeviště napoví další krok. I ve tmě špička nohy najde to místo jako první. Přesná cesta, kterou nevidíš, neviditelná mapa nakreslená nespočtem zkoušek."},"ICON-0354":{"nm":"Ušní chránič štábu","de":"Nasadíš si ušní chránič a řev hlediště o vrstvu ztlumí, zatímco hlas předávající pokyny zůstane zřetelný. Uši štábu v zákulisí vždycky poslouchají dva světy najednou. Malý nástroj, jak vylovit signál uprostřed hluku."},"ICON-0355":{"nm":"Jmenovka na ramínko v šatně","de":"Na každém ramínku visí jmenovka. Kostým jedna, kostým dva, kostým na přídavek. Podíváš se na tenhle seznam pořadí převlékání a den na jevišti se ti dopředu vykreslí podle sledu oblečení. Tichý řád, který krotí shon."},"ICON-0356":{"nm":"Kontrolní visačka na rekvizity","de":"Než se vystoupí na jeviště, na každou rekvizitu se připne visačka. Nic nechybí, všechno je v pořádku. Hlediště o tom netuší, ale právě tahle drobná kontrola brání nehodám. Za zdánlivě dokonalým jevištěm vždycky stojí pečlivá ruka."},"ICON-0357":{"nm":"Žeton s pokynem k nástupu","de":"Žeton s pokynem putuje z ruky do ruky. Teď, jdi. Okamžik, kdy se předá načasování bez jediného slova. Ve tmě vedle jeviště tenhle malý signál drží všechny pohromadě, aby nikdo nezmeškal takt."},"ICON-0358":{"nm":"Nášivka do zákulisí","de":"Existují dveře, kterými smí projít jen ten, kdo nosí tuhle nášivku. Zákulisí, kam ovace doléhá přes zeď. Jeden malý kousek látky odděluje oslnivé předjeviště od uspěchaného zázemí. Znamení lidí, kteří jeviště nesou na svých bedrech."},"ICON-0359":{"nm":"Clona na promptér","de":"Clona zabraňuje, aby světlo promptéru unikalo do hlediště. Vidí ho jen ten na jevišti, diváci netuší nic. Zdvořilý strážce jevištního tajemství, který potichu skrývá pomoc, jež nesmí být odhalena."},"ICON-0360":{"nm":"Přehoz na zrcadlo v šatně","de":"V šatně po skončení představení je zrcadlo zahaleno látkou. Sklo, které celý den odráželo nespočet výrazů, si na chvíli zavře oči. To, s čím se holá tvář bez líčení naposledy setkává, není zrcadlo, ale tichá tma."},"ICON-0361":{"nm":"Vstupní náramek na předtočení","de":"Malá páska, která se jednou zapnutá nerozepne, dokud se nepřestřihne. Kvůli jediné podmínce vstoupit do hlediště předtočení někdo nasedl do prvního vlaku za tmy před svítáním. Váha na zápěstí se stává celodenní dávkou rozechvění."},"ICON-0362":{"nm":"Štítek pohotovosti k natáčení","de":"Těsně předtím, než se rozsvítí červené světlo, je mým úkolem svázat dech všech do jedné řady. V tichu, které čeká na pokyn, vydržím potichu až do poslední chvíle. Ve chvíli, kdy mě sundají, se konečně zvedne opona živého vysílání."},"ICON-0363":{"nm":"Značka pozice kamery","de":"Jedna malá značka vyražená na podlaze zručně určuje trasy šesti kamer. Kde má být záběr zachycen nejjasněji, to režisér ví ještě dřív, než začne zkouška. Ruka, která si mimo obraz předem kreslí, co bude uvnitř obrazu."},"ICON-0364":{"nm":"Visačka na zvukovou zkoušku","de":"Poklepeš mikrofonem směrem k prázdnému hledišti. Pokud dozvuk trvá dlouho, přidá se na strop ještě jedna vrstva zvukové izolace. Péče, s jakou se doladí struktura zvuku, aniž by o tom diváci věděli, potichu začíná právě u téhle malé visačky."},"ICON-0365":{"nm":"Sešit razítek z akcí","de":"Pokaždé, když projdeš akcí, sesbíráš do jednoho políčka další razítko. V každé rozmazané stopě inkoustu je otištěno i počasí a rozechvění toho dne. Zcela zaplněná stránka se stává mapou stop, kterou nikdo jiný nedokáže napodobit — jen mou vlastní."},"ICON-0366":{"nm":"Šňůrka na návštěvnickou propustku do televize","de":"Bez téhle šňůrky se brána v hale neotevře. Zavěšena kolem krku, zatímco krok za krokem procházíš chodbou, se svět, který jsi až doteď vídal jen na obrazovce, pomalu přibližuje na dosah ruky."},"ICON-0367":{"nm":"Balení návleků do studia","de":"Podlaha studia je vždycky studená a kluzká. Zuješ boty, obuješ tenké návleky a kroky potichu zmizí. Kamera přece zaznamenává tanec, ne dupání, takže smazat zvuk je vlastně také zdvořilost vůči jevišti."},"ICON-0368":{"nm":"Jmenovka na svačinu v šatně","de":"Mezi zkouškou a živým vysíláním přichází hlad nejupřímněji ze všeho. Na každé svačině v koutě šatny je malá jmenovka s tím, čí je. Tahle vlídnost, že si na to někdo vzpomněl, dokáže provést člověka celým tím dlouhým dnem až do konce."},"ICON-0369":{"nm":"Páska s poznámkou z monitoringu","de":"Přehráváš záznam a zapisuješ si. Tady pohled, tam o půl taktu později. Nahustěné písmo je tajný dopis zítřejšímu já. Páska přilepená na konci je tichým slibem být o kousek lepší než včera."},"ICON-0370":{"nm":"Pozvánka na showcase","de":"Jeden list papíru se pro někoho může stát celoročním čekáním. Krátká věta zvoucí na showcase se zrodila jako nejmenší pozvánka na světě, v sobě nesoucí i chvění prstů, které otevírají obálku."},"ICON-0371":{"nm":"Šňůrka na visačku pro tisk","de":"Zavěšena kolem krku novináře proplouvá samým středem cvakání závěrek. Kroky spěchající najít ten nejlepší úhel — právě jejich rychlost se stává průchodem, kterým se žár jeviště přenáší do vnějšího světa."},"ICON-0372":{"nm":"Pořadník závěrečného pozdravu","de":"Aby se nikdo nesplet ani ve chvíli, kdy se na jeviště vyvalí bouřlivý potlesk, kdo je první a kdo další je zapsáno v jedné řadě. Řazení posledního pozdravu se skládá s toutéž pečlivostí jako první nástup."},"ICON-0373":{"nm":"Podlahová značka u fotostěny","de":"Před fotostěnou je na podlaze předem vyznačené místo pro špičky nohou. Stačí uhnout o jediný krok a logo v pozadí se oříznou. Tajemství té nejzářivěji zachycené pozice je tiše vyznačeno přímo pod nohama."},"ICON-0374":{"nm":"Náramek na premiéru","de":"Malá páska nasazená na zápěstí těsně předtím, než v kině zhasnou světla. Jakmile se zvedne opona, všichni se ve stejné tmě poprvé v životě setkají se stejnou scénou. Malé znamení, že jsi byl u toho prvního okamžiku."},"ICON-0375":{"nm":"Pamětní úlomek opony","de":"V den posledního představení se po posledním pozdravu opona pomalu snesla dolů. Kousek vystřižený z toho pruhu a zasazený do rámečku. V látce ještě vlažně přetrvává žár reflektorů a chvění potlesku, ještě nevychladlé."},"ICON-0376":{"nm":"Razítko prvního odhalení","de":"Razítko vyryté pro tu jedinou chvíli, kdy se poprvé ukážeš světu. Druhé první odhalení neexistuje, a tak i krátký okamžik, kdy schne inkoust, je čas, který se už nikdy nevrátí."},"ICON-0377":{"nm":"Kartička s momentem z jeviště","de":"Nejzářivější záběr z jednoho vystoupení, vystřižený a vsazený do kartičky. Hudba i světla se zastavily, ale ve chvíli, kdy ji sevřeš v ruce, ten den se ovace znovu vzedmou v uších. Malé kouzlo, kdy zamrzlá scéna ožívá."},"ICON-0378":{"nm":"Poznámka k závěrečné póze","de":"Poznámka zachycující úhel prstů a pohledu, který se musí zastavit přesně v okamžiku, kdy dozní poslední tón. Jen ten, kdo ví, že jeden jediný závěrečný záběr dokáže ovlivnit i celé následující dny, uchovává tenhle malý nákres pečlivě složený."},"ICON-0379":{"nm":"Špendlík města z turné","de":"Na mapě je do každého navštíveného města zapíchnutý jeden špendlík. Mořský vánek Pusanu i poledne v Kwangdžu jsou zaseknuté na hrotech těchhle drobných hřebíčků. Tiše spojíš body a uvidíš linku dlouhé cesty napříč celým jedním ročním obdobím."},"ICON-0380":{"nm":"Sponka na sekci sedadel","de":"Rozděluje desetitisíce sedadel na sekce a ukazuje cestu. Aby ses nezatoulal, aby ses do nikoho nenarazil. Kdo mě následuje, každý dojde na svoje místo. Řád je koneckonců malá laskavost pro všechny."},"ICON-0381":{"nm":"Visačka vstupní brány","de":"Před branou prochází jeden po druhém kontrolou v pořadí. Poslední brána, která vpouští dovnitř ruku svírající lístek i srdce bušící vzrušením. Ve chvíli, kdy mnou projdeš, dlouhé čekání skončí a dnešní jeviště se rozjede."},"ICON-0382":{"nm":"Kapsle na uchování náramku","de":"I když barva vybledne, ovace toho dne zůstávají zapečetěné beze změny. Nedokážeš vyhodit pásku ze zápěstí, a tak ji úhledně srolovanou uložíš do malé kapsle. Protože chceš, aby i vzácná vzpomínka měla svůj kousek místa, kam si může lehnout."},"ICON-0383":{"nm":"Tyč pro výměnu na místě","de":"Mezi fanouškem a jevištěm putuje z ruky do ruky něco. Může to být dopis, může to být malý dárek. Já razím cestu, aby ten cit doputoval v bezpečí — nejrušnější most na celém místě konání."},"ICON-0384":{"nm":"Pečeť s datem představení","de":"Datum toho dne je otištěné uvnitř kulaté pečeti a navždy se zastaví. Kalendář se listuje dál, ale jen tenhle malý kruh zůstává v tom jednom dni. Když je den, na který lidé nechtějí zapomenout, vždycky si něco zapečetí."},"ICON-0385":{"nm":"Nášivka na cestovní tašku z turné","de":"Taška, která jela na turné s sebou, získává za každé město o jednu nášivku víc. Názvy míst všité na látce se, aniž bys to čekal, promění v životopis. Dokonce i odřené a rozedřené rohy zůstávají jako důkaz, že jste spolu prošli všude."},"ICON-0386":{"nm":"Šňůra na cedulku s lístky","de":"Cedulka pohupující se na konci vstupní fronty, a jedna šňůrka pevně svázaná na jejím konci. Uprostřed scenérie rukou zvedajících lístky vysoko do dlouhé řady tiše označuji čelo průvodu, kde stojí v řadě rozechvění."},"ICON-0387":{"nm":"Kousek stužky z přídavku","de":"V noci, kdy hlasy volající po přídavku zněly nejhlasitěji, odpadl jeden kousek stužky zdobící jeviště. Jako píseň zazpívaná déle, protože bylo líto skončit, i v tomhle kousku je zauzlená neochota odejít."},"ICON-0388":{"nm":"Lahvička se vzkazem","de":"Jedno slovo úhledně složené uvnitř skleněné lahvičky. Jako malá loďka vypuštěná v naději, že jednou někoho dostihne, i já v sobě nesu srdce a pomalu unáším časem. Až do dne, kdy mě otevřou, slib uvnitř tiše spí."},"ICON-0389":{"nm":"Malá visačka s vyznáním","de":"Slova, která jsi nedokázal vyslovit nahlas, napíšeš na malou visačku a nenápadně ji tam vsuneš. Písmo se chvělo, ale upřímnost byla jasná. Někdy dokáže ten nejmenší papír pojmout tu největší odvahu."},"ICON-0390":{"nm":"Schránka na anonymní vzkazy povzbuzení","de":"I bez podpisu se cit dostane k cíli. S každým vzkazem, který vklouzne do schránky, přibývá jedna anonymní dávka něčí podpory. Sbírka bezejmenné vlídnosti, kde nevíš, kdo psal, ale teplo je nezaměnitelně jasné."},"ICON-0391":{"nm":"Papír na skládání přání","de":"Čtvercový papír se pod tvými prsty stává jeřábem, stává se hvězdou. S každým přeložením se o vrstvu víc poskládá i přání. Ve pečlivě složeném tvaru dřímá upřímnost, která vydrží déle než slova."},"ICON-0392":{"nm":"Pečetní vosk na stužku","de":"Kápneš vosk, přitiskneš razítko, a dopis je konečně zapečetěný. Přesně podle starého způsobu, jak pevně upevnit srdce. Na chladnoucím rudém vosku se tiše uzamkne jedno tajemství."},"ICON-0393":{"nm":"Výplňový papír na dárky","de":"Ze strachu, aby se dárek neponičil, ho měkce obalí kolem dokola. Do každého pomačkaného záhybu prosakuje prosba, ať se nic nerozbije. Vrstva opatrného citu na neviditelném místě, kterou příjemce pravděpodobně přejde bez povšimnutí."},"ICON-0394":{"nm":"Barevná šňůrka na dopis","de":"I šňůrka svazující dopis má svou barvu. Žlutá znamená povzbuzení, modrá stesk. Pocit, který se slovy nedá plně vyjádřit, si vybereš podle odstínu a zavážeš do uzlu. Ještě než ho rozvážeš, teplota srdce dorazí k prstům jako první."},"ICON-0395":{"nm":"Zakrývací páska na vzkaz","de":"Jedna páska, která schovává rukopis až do poslední chvíle před předáním. Chrání vyznání úzkostné z toho, že bude odhaleno, až do samého konce. Upřímnost, která se odhalí lehkým nadzvednutím — váhu toho chvění znám ze všech nejblíž."},"ICON-0396":{"nm":"Žeton s heslem povzbuzení","de":"V noci, kdy se lightsticky vlní jako moře, je uvnitř čipu vyryta jediná věta, kterou má zaznít jedním hlasem. Slovo slibu, které sjednocuje roztroušená srdce do jedné řady. Když ji zpívají všichni společně, ta věta září nejjasněji."},"ICON-0397":{"nm":"Ošoupaná klíčenka ze zkušebny","de":"Klíčenka, která stovkrát otevřela a zavřela dveře zkušebny. Barva je oloupaná a kroužek uvolněný, ale zůstal v ní jako patina pot z těch nejnešikovnějších let. Být ošoupaný znamená zůstat na místě tak dlouho."},"ICON-0398":{"nm":"Kousek jevištní líčicí tužky","de":"Jevištní líčení se dokoná teprve pod reflektory. Kousek té sytě zbarvené hmoty. Ve stopě nanesené pevně tak, aby nerozmazal ani pot, zůstala beze zbytku vsáklá péče o to, přenést výraz až k nejvzdálenějším sedadlům."},"ICON-0399":{"nm":"Pouzdro na ušní koncovky","de":"Malé ušní koncovky, díky nimž jsi na jevišti slyšel svůj vlastní hlas. Když skončí vystoupení, uložíš je úhledně do pouzdra. Čím blíž něco přenášelo hudbu k tobě, tím pečlivěji ho chceš opatrovat."},"ICON-0400":{"nm":"Jmenovka na osobní skříňku","de":"Na konci chodby ubytovny visí na každé skříňce jmenovka. Drobné písmo prozrazující, čí místo to je, mění neznámý prostor v domov. Získat vlastní přihrádku je něžné svolení, že tady smíš zůstat."},"ICON-0401":{"nm":"Kapesní lahvička na péči o hlas","de":"Mezi zkouškami pomalu upiješ doušek vlažné vody. Hrdlo je nástroj, který si zpěvák jen vypůjčuje, a tak tahle malá lahvička, naplněná dřív, než voda vychladne, předem střeží zítřejší první tón. Pečující srdce je vždycky takhle tiché."},"ICON-0402":{"nm":"Připomínkový špendlík na rozvrh","de":"Na dni nahuštěném minutu po minutě ukazuje jeden špendlík na další políčko. Mezi těmi hustými řádky je nejvítanější právě to prázdné políčko. Chvilka, kdy smíš pohlédnout z okna, se tam skrývá, maličká."},"ICON-0403":{"nm":"Sponka na deku do zákulisí","de":"Odpoledne, kdy jsi opřená o židli s hotovým líčením na chvíli usnula, ti někdo jemně přehodil přes ramena deku. Tahle sponka, která ji zakousla, aby nesklouzla, tiše svírá teplo toho dotyku až do chvíle, kdy vyjdeš na jeviště."},"ICON-0404":{"nm":"Malý vzorek parfému","de":"Lehce ho poklepeš na vnitřní stranu zápěstí a vůně rozkvete jen na dosah dlaně. Nevadí, že se nešíří daleko. Je to stopa, kterou pozná jen ten, kdo se přiblíží - o to tajemnější, a proto o to víc moje."},"ICON-0405":{"nm":"Prací visačka na tréninkové oblečení","de":"Ať vypereš sebevíc, pach potu vsáklý hluboko do látky se nikdy úplně nevytratí. Skládáš tréninkové oblečení, které usychalo měkké na slunci, a myslíš si - ta neodstranitelná stopa je vlastně ta nejupřímnější."},"ICON-0406":{"nm":"Gelová fólie do reflektoru","de":"Vsuneš jeden tenký barevný list a bílé světlo se rozlije do barvy západu slunce, přidáš ještě jeden a usadí se úsvit. Za oponou zatajil dech ten, jehož ruka obléká i světlo do šatů a rozhoduje, do jakého ročního období jeviště zabarví."},"ICON-0407":{"nm":"Krytka na objektiv","de":"I když je kamera vypnutá, někdo otevře tuhle malou krytku a očistí objektiv. Kvůli další scéně, která ještě nebyla natočena. Nad časem, který se nedostane na obrazovku, nejrušnější ruka předem nastavuje ostření."},"ICON-0408":{"nm":"Odrazová deska na jeviště","de":"I když sama nesvítí, existuje deska, která přijaté světlo vrací do zastíněné tváře. Střed jeviště je tak jasný proto, že na kraji tiše drží úhel a odráží světlo něčí paže."},"ICON-0409":{"nm":"Pouzdro s barevným filtrem","de":"Vsuneš do průhledného pouzdra modré světlo a celé hlediště se promění v moře, vyměníš je za červené a na tom místě se rozhoří západ slunce. Kouzlo, kdy se stejné jeviště jednou barvou promění v jiné roční období, začíná v téhle tenké jediné vrstvě."},"ICON-0410":{"nm":"Číslovaný špendlík na světla","de":"Každé z mnoha světel má svoje malé číslo. Které se rozsvítí a které usne, tím je předem utkán průběh dnešního večerního představení podle pořadí těchto čísel. Za oslnivou oponou vždycky leží rozevřený pečlivý seznam."},"ICON-0411":{"nm":"Svítící značkovací páska","de":"Na zatemněné podlaze jeviště tiše svítí fosforeskující páska místo, kde se má zastavit noha. Z hlediště není vidět, ale špičky nohou účinkujícího po tomhle mdlém světle tápají, aby našly svou pozici. I ve tmě existuje laskavý průvodce."},"ICON-0412":{"nm":"Clona proti stínu","de":"Deska, která zadržuje pronikající světlo, aby stín dopadl ostře. Zacházet s tmou je nakonec totéž jako zacházet se světlem, a tak se to, co se má ukázat, rozhoduje nejdřív tím, co se má tiše skrýt."},"ICON-0413":{"nm":"Čip na měření osvětlení","de":"Malý čip, který měří jas prostoru, čte čísla na dlani. Příliš jasno i příliš tma totiž bolí oči. Tenhle čip tiše hlídá tu neviditelnou správnou míru, kde se člověk cítí nejpohodlněji."},"ICON-0414":{"nm":"Clona bodového světla","de":"Clona přidaná, aby bodové světlo neuniklo, kam nemá. Soustředit světlo jen na jednoho člověka je něžná pozornost. V okamžiku, kdy vkročíš do toho kulatého světla, se svět na chvíli dívá jen na jedinou osobu."},"ICON-0415":{"nm":"Sada koncovek do sluchátek","de":"Pár koncovek, které přesně sedí do uší. Stačí malý rozdíl ve velikosti a zvuk uniká, a v okamžiku, kdy uniká, ztratíš takt. Píseň bez jediného zakolísání na jevišti někdy začíná právě v tomhle malém páru gumy."},"ICON-0416":{"nm":"Suchý zip na kabely","de":"Suchý zip, který spoutá zamotané dráty do jednoho úhledného pramene. Čím méně to kdo vidí za jevištěm, tím víc vynikne pořádek. Úhlednost jednoho svazku kabelů tiše podpírá zvuk, který vpředu plyne bez zakolísání."},"ICON-0417":{"nm":"Štítek na kontrolu linek","de":"Jmenovky popsané rukou, přilepené na desítkách kabelů, které říkají, který nástroj je který. Teprve když si každé to křivé písmenko udrží svoje místo, tóny, které hrály každý zvlášť, se konečně sleji do jedné písně."},"ICON-0418":{"nm":"Tichá podložka","de":"Jeden list tiché podložky, který beze slova pohltí kroky i chvění. Klade se tam, kde je klid opravdu potřeba. Nejčistší zvuk se někdy zrodí právě na téhle tiché podlaze, odkud neunikne jediný šum."},"ICON-0419":{"nm":"Žeton pro zvukovou zkoušku","de":"Žeton, který se v dlani zahřívá, zatímco se před představením ladí zvuk. Pokaždé, když je dokontrolovaný jeden mikrofon, jedna reprobedna, přesune se do jiné ruky. Dokonalost hlavního vystoupení se formuje krok za krokem právě v téhle tiché zkoušce."},"ICON-0420":{"nm":"Krytka na mikrofon","de":"Protože je to místo, kterého se dotklo tolik hlasů, čistíš tuhle krytku obepínající špičku mikrofonu obzvlášť pečlivě. Je to nádoba, která pojme píseň, takže je pro zpěváka skoro jako další ruka. Zatímco ji čistíš, předem si v duchu kreslíš zítřejší první verš."},"ICON-0421":{"nm":"Sponka pop filtru","de":"Tenká vrstva síťky natažená mezi rty a mikrofonem. Díky malé sponce, která tu blánu drží, se drsně unikající dech brzy vyhladí do kulatého, měkkého hlasu."},"ICON-0422":{"nm":"Štítek na zvukový rack","de":"Malý štítek zavěšený, aby ses neztratila mezi policemi nakupené techniky v tmavém zákulisí. Zdroj oslnivého zvuku, který plní hlediště, je vždycky takhle úhledně srovnaný právě v takových šerých místech."},"ICON-0423":{"nm":"Kolík mřížky reproduktoru","de":"Kolík, který pevně drží mřížku reproduktoru. Okno, kudy vychází zvuk, jako první čelí prachu, a tak tenká vrstva síťoviny chrání tón. Všechno, co se dotkne ucha, má na sobě navrstvenou neviditelnou ochranu."},"ICON-0424":{"nm":"Nálepky na taneční kroky","de":"Nálepky pro rozestavení, nalepené bod po bodu na podlaze. Tajemství skupinového tance, který do sebe zapadá jako čepel, se ve skutečnosti skrývá pod chodidly. Na nespočtu smluvených značek, kde desítky lidí šlapou na stejný bod, rozprchnou se a zas se sejdou."},"ICON-0425":{"nm":"Kotouč na trénink otáček","de":"Cvičný kotouč, který se točí dokola na místě. Aby přemohla závrať, naučí se nejdřív upřít pohled na jeden bod. Ať se točí sebe rychleji, ten jeden bod nikdy nepustí - je to rovnováha, kterou si tělo pomalu vrývá do paměti."},"ICON-0426":{"nm":"Role tejpu na koleno","de":"Role pásky, která pevně omotá koleno. Klouby, které tisíckrát skočily a dopadly, mlčí až do konce, ale tahle jedna vrstva to mlčení tiše podepírá. Za tělem, jež vydrží až do posledního, vždycky stojí něčí péče."},"ICON-0427":{"nm":"Deska na zarovnání špiček","de":"Deska, která úhledně nastaví úhel špiček nohou. Říká se přece, že tanec se dovršuje spíš ve špičkách nohou než v konečcích prstů. Desítky špiček natažených stejným směrem se spojí a vytvoří kouzlo, kdy víc lidí vypadá jako jeden."},"ICON-0428":{"nm":"Protiskluzová podložka do zkušebny","de":"Protiskluzová podložka položená na podlahu zkušebny. Aby ses mohla vydovádět naplno, musíš být nejdřív v bezpečí. Teprve na podlaze, kde se dá kutálet bez obav z pádu, se konečně rozkvetou ty nejodvážnější, nejnebojácnější pohyby."},"ICON-0429":{"nm":"Karta s rozpisem pohybu","de":"Karta, na které je choreografie rozkreslená na drobné kousky, dobu po době. Ať je pohyb sebetěžší, rozděl ho políčko po políčku a najednou zjistíš, že ho zvládáš. Hladký tok na jevišti, plynoucí jako voda, je utkaný právě z těchto po kouscích zapamatovaných obrázků."},"ICON-0430":{"nm":"Kolík na záclonu přes zrcadlo","de":"Kolík, který drží záclonu, jež na chvíli zakryje zrcadlo ve zkušebně. Je potřeba i čas, kdy tančíš jen podle citu v těle, bez odrazu. Ve chvíli, kdy je zrcadlo zakryté, hudba konečně pronikne až pod kůži - to se prostě ví."},"ICON-0431":{"nm":"Korálek na počítání taktu","de":"Cvak, cvak - při každém taktu posuneš prstem jeden korálek a počítáš dál. Hmatatelně, jako podle starého způsobu počítání. Takt, kostra hudby, se teprve tehdy pevně usadí v těle, když se ho naučíš přes něco, čeho se dá dotknout."},"ICON-0432":{"nm":"Kontrolní páska na rozcvičku","de":"Kontrolní páska, která ukazuje, jestli je tělo pořádně rozehřáté. Před skutečným tréninkem vždycky nejdřív přijde klidná příprava. Než litovat po zranění, uvázat si jeden pásek a pomalu probudit tělo nakonec dovolí tančit déle."},"ICON-0433":{"nm":"Číslovaná sponka na kostým","de":"Sponka, která na každý z mnoha kostýmů zakousne číslo, aby se nepopletly. Během zadýchaného převlékání by i jediný zaměněný kostým znamenal potíž, a tak má každý oděv zřetelně napsané svoje pořadí. I shon je půvabný, když ho podpírá řád."},"ICON-0434":{"nm":"Jehelníček z krejčovny","de":"Jehelníček odložený v koutě krejčovny. Zdržuje se tu ruka, která beze slova spravovala roztržené švy a utržené knoflíky. Za dokonale padnoucím oděvem na jevišti se skrývá péče stehů, které jeviště nikdy neviděly."},"ICON-0435":{"nm":"Kroužek se zbytky látky","de":"Kroužek, na který je navlečeno pár kousků náhradní látky. Pro případ, že by se poškodil originální kostým, se předem odkládá stejná tkanina. Tahle drobná příprava, uchovaná v naději, že se nic nestane, zachrání jevištní kostým právě ve chvíli, kdy se stane něco velkého."},"ICON-0436":{"nm":"Balíček náhradních knoflíků","de":"Balíček knoflíků, které lze v nouzi rovnou přišít. Když se těsně před představením utrhne jeden knoflík, celá šatna se na okamžik rozvíří. Malá, ale nesmírně spolehlivá lékárnička, která tu krátkou závratnou krizi jedním rázem utiší."},"ICON-0437":{"nm":"Držák na jevištní opasek","de":"Držák, který pevně svírá pásek jevištního kostýmu. Aby se oděv nerozjel, ať skáčeš a otáčíš se sebedivočeji. Svoboda, kterou si na jevišti naplno užíváš, pramení nakonec z toho, že je pevně stažené to, co nikdo nevidí."},"ICON-0438":{"nm":"Peříčkový oprašovač","de":"Protože pod reflektory vynikne i to nejmenší chmýří, přejíždíš peříčkovým oprašovačem jemně přes kostým. Těsně předtím, než vkročíš na jeviště, patří to poslední něžné pohlazení oblečení vždycky tomuhle měkkému pírku."},"ICON-0439":{"nm":"Visačka na pantofle do zákulisí","de":"Jmenovka na každém pantofli v zákulisí. V malém štítku, na kterém stojí, čí to je, se tiše skrývá ujištění, že patříme do stejného týmu. Ta místnost, kde si zuješ boty a natáhneš nohy, se stává nejútulnějším domovem za jevištěm."},"ICON-0440":{"nm":"Deska se sponkami na styling","de":"Deska se sponkami, která přidržuje pramínky, zatímco se upravují vlasy. Pramínek po pramínku, prsty svěřují vlasy, které se chtějí rozlétnout, na chvíli téhle sponce. Upravenost je nakonec vytvořená ze sumy takových drobných zastavení."},"ICON-0441":{"nm":"Pouzdro na zavírací špendlíky","de":"Za svítání, kdy praskl šev, otevřeš víčko pouzdra a uvnitř leží úhledně malé chladné stříbro. Ruka, která z neviditelného nitra drží kostým nejpevněji - zavírací špendlík vždycky tiše pracuje za jevištěm."},"ICON-0442":{"nm":"Utěrka na čištění objektivu","de":"Fouknout jednou dechem a otřít v kroužcích - a zamlžený svět se vyjasní. Máš ráda ten krátký okamžik, a tak objektiv čistíš stále dokola. Malý útržek jarního slunce, který místo někoho jiného vyjasní jeho pohled na svět."},"ICON-0443":{"nm":"Gumové nožičky na stativ","de":"Nasadíš gumu na tři špičky a parketová podlaha už dál nevřeští. Zatímco malé body pohlcují chvění, obraz na plátně se jako lží ztiší. Stabilita vždycky tiše začíná u nohou."},"ICON-0444":{"nm":"Pláštěnka na kameru","de":"I když po ní stékají kapky deště, objektiv zůstává suchý a zachycuje svět dál. V zamračené odpoledne venkovního natáčení se přes kameru jemně přehodí průhledný plášť do deště. Protože to, na čem záleží, se má nejdřív zabalit, než zvlhne."},"ICON-0445":{"nm":"Značkovací páska pro natáčení","de":"Postav se sem, otoč se támhle - barevné krátké značky beze slova zřetelně ukazují cestu. I když je po představení bez lítosti odlepíš, zvyklé chodidlo si to místo pamatuje ještě dlouho potom."},"ICON-0446":{"nm":"Sponka na oddělení stránek","de":"Malá sponka, která jedním kousnutím sevře stránky, co se chtějí rozletět. Cvak - jedním svěžím zvukem se včerejšek a dnešek úhledně svážou. Uklízet znamená ten něžný zlozvyk, kdy tiše přidržíš to, co bylo skoro ztracené."},"ICON-0447":{"nm":"Deska pro vyvážení bílé","de":"Nastavíš bílou desku před obraz a barvy si tiše najdou svoje místo. Žlutý západ slunce, modrý úsvit, bez lži. Jedna deska, která zná pravou bílou, přiměje ostatní barvy mluvit poctivě."},"ICON-0448":{"nm":"Plechovka na paměťové karty","de":"V malé plechovce spí klidně čipy plné vzpomínek. Otevřeš víčko - cvak - a scény z minulé sezóny se vysypou do dlaně. Vzpomínka takhle zůstává láskyplně uložená v jedné pevné plechovce."},"ICON-0449":{"nm":"Sluneční clona na monitor","de":"Obepneš monitor černou clonou a odlesky rázem ustanou. I u okna zalitého sluncem obraz neztrácí svou barvu. Abys dobře viděla, musíš nejdřív zastínit rušivé světlo - to ti clona tiše připomíná."},"ICON-0450":{"nm":"Zvukotěsný kolík na plac","de":"Malý kolík vklíněný do škvíry dveří tiše odřízne hluk zvenčí. Kroky z chodby ani smích ze sousední místnosti sem už nedosáhnou. Protože chceš-li zachytit čistý zvuk, musíš nejdřív vystavět ticho."},"ICON-0451":{"nm":"Balíček líčicích houbiček","de":"Svazek měkkých, nadýchaných houbiček srovnaných pěkně na sobě. Poklepeš špičkami prstů trochu pudru a tvář se rozzáří o odstín. Za každým zářivým úsměvem na jevišti se skrývají právě tyhle jemné dotyky."},"ICON-0452":{"nm":"Pouzdro na sponky do vlasů","de":"Úhledný domov pro drobné sponky, které se tak snadno ztrácejí. Otevřeš víčko a stříbrné řady se seřadí, aby tě přivítaly. Rozprášené jsou neviditelné, ale pohromadě dodávají jistotu - i ty nejmenší věci potřebují svůj vlastní domov."},"ICON-0453":{"nm":"Sterilizační box na štětce","de":"Štětce, které celý den nasávaly barvu, si uvnitř boxu dopřejí sprchu UV světla. Zatímco neviditelné světlo smývá to staré, zítřejší štětinky budou čerstvé jako nové. I čistota je jedna z vrstev píle."},"ICON-0454":{"nm":"Síťka na pudrové labutěnky","de":"Kulaťoučké labutěnky si v síťovém pytlíku tiše popadají dech. Když sítí prochází vzduch, jejich nadýchanost vydrží déle. V dobře vysušené labutěnce už předem dřímá záře zítřejšího rána."},"ICON-0455":{"nm":"Uzávěr lakového spreje","de":"Fss - jedno stříknutí a ani vítr už neroztřepí ani pramínek. Malý uzávěr, který přes noc podrží pečlivě vystylovaný účes. Nad pevně upraveným vlasem se pak rozprsknou jasná světla."},"ICON-0456":{"nm":"Krytka na štětec na rty","de":"Malé víčko, které jemně obepíná tenkou špičku štětinky. I když se v tašce houpe sem a tam, štětec zůstává rovný a čistý. Péče o jeden drobný štětec dokoná jeden tah barvy na rtech."},"ICON-0457":{"nm":"Zrcátko s pořadovým číslem","de":"Vedle čísla, které oznamuje tvoje pořadí, se tiše krčí malé zrcátko. Těsně předtím, než vejdeš na jeviště, je to místo, kde naposledy urovnáš rozcuchanou ofinu. I tréma trochu zlehčí, když se do ní jednou zahledíš."},"ICON-0458":{"nm":"Potítko na zápěstí","de":"Měkký pásek, který jedním pohybem zápěstí setře pot z čela. Čím prudší choreografie, tím častěji po něm sáhne ruka. Malá útěcha na zápěstí, která je nablízku v každé zadýchané chvíli."},"ICON-0459":{"nm":"Štítek na tašku s rekvizitami","de":"I když v šatně stojí v řadě deset stejných tašek, nic se nespletě. Jmenovka na každé z nich jasně řekne, komu patří. Napsat si 'moje' je drobné, ale něžné gesto."},"ICON-0460":{"nm":"Rezervační kolík na zkušebnu","de":"Kdo dnes bude používat tuhle zkušebnu? Malý kolík zapíchnutý do nástěnky u dveří beze slova rozděluje čas. Srdce, která čekají na svou řadu, se tiše řadí za tímhle jediným kolíkem."},"ICON-0461":{"nm":"Ochranný kroužek na nástěnné hodiny","de":"Průhledný kryt se jemně snese na nástěnné hodiny a zadrží prach. Tikající ručičky se nikdy nerozmažou a čas plyne dál čistě. Nad tím, na čem záleží, je vždycky potřeba neviditelná vrstva ochrany."},"ICON-0462":{"nm":"Ochranná podložka na podlahu","de":"Tenká podložka přilepená pod nohu židle chrání dřevěnou podlahu, než se poraní. Táhneš ji a nic se nedrápe, přesuneš ji a nezůstane jediná stopa. Neviditelná péče o podlahu - to je tajemství, díky němuž vydrží dlouho."},"ICON-0463":{"nm":"Značka zákazu nápojů","de":"Odlož si tady na chvíli pití, prosí laskavě malý čip. Notový zápis i technika by měly potíže, kdyby zvlhly. I slovo 'zákaz' se takhle podané promění v teplou ohleduplnost."},"ICON-0464":{"nm":"Štítek na tlačítko větrání","de":"Když chceš vyměnit dusný vzduch, stiskni tady - ukazuje cestu malý štítek vedle tlačítka. Volnější dech, jak se ukáže, tiše začne právě u takové drobné značky."},"ICON-0465":{"nm":"Gumová podložka pod reproduktor","de":"Gumová podložka pod reproduktorem tiše pohltí tupé chvění. Basy se už nešíří po podlaze, a tak zvuk zní o poznání čistěji. Dobrá rezonance se konečně vyjasní až na pevném podkladu."},"ICON-0466":{"nm":"Magnetka s číslem skříňky","de":"Malá magnetka s číslem, která přilne na dvířka skříňky. Ve které přihrádce dnes budou spát moje věci? I když se místo každý den mění, stačí jedna magnetka a hned mám svou přihrádku. Sounáležitost přichází právě z tak lehoučké značky."},"ICON-0467":{"nm":"Stěrka na zrcadlo","de":"Jeden tah přes zrcadlo a orosení zmizí do čista. Chvíle, kdy se rozmazaná tvář znovu jasně vynoří. Abych se opravdu viděla, musím nejdřív tiše setřít to, co pohled kalí."},"ICON-0468":{"nm":"Nárazník na dveře","de":"Měkký tlumič vklíněný do škvíry prudce zavírajících se dveří. Zmírní jak ránu bouchnutí, tak přiskřípnutý prst. Malé bezpečí, které mezi tvrdé nárazy nenápadně vsune vrstvu jemnosti."},"ICON-0469":{"nm":"Kryt na kabely","de":"Nad kabely, které křižují podlahu, pevný kryt spolehlivě přemostí cestu. Noha se nezachytí, dráty se nesešlápnou. Tichá vytrvalost jednoho bloku, který chrání cestu, aniž by ji zatarasil."},"ICON-0470":{"nm":"Výstražný kužel: kluzká podlaha","de":"Na mokré podlaze stojí samotný žlutý kužel a tiše varuje. Šlapej opatrně, pomalu. Za jasným jevištěm stojí právě takový malý strážce, který beze slova hlídá každý krok."},"ICON-0471":{"nm":"Nouzová svítící tyčinka","de":"Jeden paprsek se rozsvítí na chodbě zasažené výpadkem proudu. Aby ses ani ve tmě neztratila, vloží se ti do ruky nouzová záře. Na světě jistě existují věci, které nejjasněji svítí právě v nejtemnější chvíli."},"ICON-0472":{"nm":"Ochranná krytka na zábradlí","de":"Kulatá krytka nasazená na konec schodišťového zábradlí měkce obejme ostrý roh. I neopatrně přejetá ruka se nezraní. Tiše zakrýt to, co je ostré, je taky jistý druh ohleduplnosti k někomu druhému."},"ICON-0473":{"nm":"Ochranný polštář na hranu jeviště","de":"Kolem hrany jeviště je omotaný nadýchaný polštář. Aby se ani špička nohy při prudké choreografii neporanila. Za každým zářivým pohybem tančí spolu i neviditelná ochrana."},"ICON-0474":{"nm":"Kotouč pro značení podlahy","de":"Kulatý kotouč položený na podlaze tiše říká: 'stůj tady'. Ti, co stojí ve frontě, i ti, co hledají svoje místo, se u tohohle jediného bodu zastaví. Řád roste z malé značky."},"ICON-0475":{"nm":"Poutko na baterku","de":"Omotáš si jednou kolem zápěstí šňůrku zavěšenou na konci baterky a i ve tmě neztratíš světlo z dohledu. Obě ruce mají volnost bez obavy z upuštění - malé, ale spolehlivé jedno kolečko poutka."},"ICON-0476":{"nm":"Zábranné lano","de":"Sem už prosím nechoď dál, žádá jemně jedna jediná šňůra, která vytyčí čáru. Laskavá hranice, jež tiše odděluje nebezpečné od bezpečného. I zadržet někoho je jeden ze způsobů, jak ho ochránit."},"ICON-0477":{"nm":"Kolík bezpečnostní kontroly","de":"Na každém prohlédnutém místě zanechá malý kolík svoje 'zkontrolováno'. Jeden bod, jako otisk mysli, která nic nevynechala a všechno obešla. Bezpečí není nic velkolepého - je to prostě součet takhle bod po bodu zanechaných stop."},"ICON-0478":{"nm":"Mini klapka","de":"Při svěžím zvuku, cvak, který přeruší první dobu, se dech všech na place v jediném okamžiku sladí. Ať je sebemenší, startovní čára každé scény je vždycky přesně tahle jedna doba. Právě tady se otevírá vzrušující začátek natáčení."},"ICON-0479":{"nm":"Krytka na stolní mikrofon","de":"Přes mikrofon na stole se jemně nasadí měkká krytka. I když se dech prudce vyrve ven, dorazí čistě, bez šumu. Nejvřeleji hlas obepíná právě tahle malá, měkká vrstva."},"ICON-0480":{"nm":"Kus akustického panelu","de":"Kus zvukotěsného panelu zasazený do zdi tiše sbírá ozvěny. Zvuk se už neodráží a nerozptyluje, a tak se píseň hromadí o poznání čistěji. Dobrá rezonance vzniká z pečlivého tříbení ticha."},"ICON-0481":{"nm":"Háček na sluchátka","de":"Pověsit sem sluchátka je malý slib. Rozmotat kabel a urovnat ho, aby si je další člověk mohl rovnou vzít a jít. Jeden háček vnáší tichý řád do rušné kabiny."},"ICON-0482":{"nm":"Kontrolka nahrávání","de":"V okamžiku, kdy se rozsvítí červené světlo, se v kabině zastaví každý dech. Signál, který zastaví i kroky za dveřmi. Zachytit zvuk začíná právě udržením tohohle hlubokého ticha."},"ICON-0483":{"nm":"Krabička na trsátka","de":"Trsátka srovnaná podle barvy do přihrádek. Tloušťka a váha utvářejí zvyk konečků prstů. Ta přesnost, s jakou těsně před jevištěm sáhneš rovnou pro to pravé, aniž by ses dívala, tady vyrůstá."},"ICON-0484":{"nm":"Popisovač kabelů","de":"Abys se neztratila ani na podlaze plné desítek zamotaných pramenů, musíš popsat oba konce jménem. Jen ten, kdo si zapsal, odkud kabel přichází a kam vede, netápe rukou ani ve tmě."},"ICON-0485":{"nm":"Otočný knoflík mixpultu","de":"Otočíš ho o šířku prstu a barva hlasu se změní. Zvýšíš a zdrsní se, snížíš a ztratí se v hloubce - hledáš prstem ten jediný bod mezi nimi. Nejjemnější dotek utváří tu největší změnu."},"ICON-0486":{"nm":"Zajišťovací podložka stojanu","de":"Jeviště nedrží zářivé reflektory, ale tenhle malý kroužek. Pevně svírá chvění na místě a tiše vydrží na svém postu, aniž by ho kdo zahlédl."},"ICON-0487":{"nm":"Štítek na demontáž scény","de":"I opatrné ukládání zpátky všeho, co bylo postaveno, má svůj jasný postup. Jeden list papíru popisující, kde uvolnit a kam přesunout. Ruce, které bourají, jsou stejně jisté jako ruce, které stavěly."},"ICON-0488":{"nm":"Sáček na ztracené věci","de":"Každá zapomenutá věc v sobě nese vlastní příběh. Uložit ji do malého sáčku a čekat na jméno majitele je něžnost, která si na chvíli vezme na starost i srdce toho, kdo ji ztratil."},"ICON-0489":{"nm":"Značka úklidové trasy","de":"Sleduj šipky nakreslené na podlaze a vyčistíš úplně všechno bez mezery. I koště potřebuje cestu, aby se netočilo naprázdno. Nejzářivější místo leží na konci nejlépe vyznačených kroků."},"ICON-0490":{"nm":"Naváděcí tyč pro odchod","de":"Když poslední potlesk utichne, tahle tyč otevře cestu ven. Ruka, která pomalu propouští ještě rozjařená srdce, aniž by je poranila. I doprovázet konec v sobě nese vřelou pozornost."},"ICON-0491":{"nm":"Klubko zbytků pásky","de":"Smotáš zbylé útržky do kuličky a znovu se jim najde využití. Tak jako se konec, který málem skončil v koši, změní v pevnou kuličku, i šetrné srdce roste z drobných konečků prstů."},"ICON-0492":{"nm":"Číslo na sedadlo","de":"Aby se nikdo neztratil, musí mít každá židle v hledišti svoje číslo. Malá čepička, která přiděluje místo, promění chvění nováčka v klidnou úlevu."},"ICON-0493":{"nm":"Kolík na třídění odpadu","de":"Malý kolík, který rozděluje a zasouvá papír od plastu. Smíchané je to prostě odpad, roztříděné se z toho znovu stává surovina. Třídění je něžný čin, který věcem vrací druhý život."},"ICON-0494":{"nm":"Visačka na vrácení techniky","de":"Co je vypůjčené, se musí vždycky vrátit na svoje místo. S každým konečkem prstu, který vrací věc opatřenou visačkou, se vrství o kousek víc důvěry. Kdo dobře vrací, ten si příště zase vypůjčí s lehkým srdcem."},"ICON-0495":{"nm":"Klíč pro odhlášení ze zákulisí","de":"Sundáš ze sebe dnešní líčení i kostým a nakonec vrátíš tenhle klíč. Vrátit na odchodu to, co jsi dostala při příchodu. Začátek i konec dne se tak vejdou do stejné ruky."},"ICON-0496":{"nm":"Pouzdro na cushion houbičku","de":"Nadýchaná labutěnka ztrácí svou strukturu, když se na ni tlačí. Proto se něžně uloží k odpočinku do jednoho kulatého domečku. Chceš-li dlouho zachovat její jemnost, musíš s ní nejdřív jemně zacházet."},"ICON-0497":{"nm":"Vzorek očních stínů","de":"Jeden bod barvy položený na víčko změní celý výraz. Barva dřímající v malém čipu se probudí až pod světly reflektorů a dodá pohledu upřenému k jevišti hloubku."},"ICON-0498":{"nm":"Krytka na štětec na tvářenku","de":"Když se poškodí špička štětiny, zhroutí se s ní i sytost barvy. Nasadit malou čepičku a chránit tak její strukturu je tichý zvyk člověka, který chce mít dobré nástroje po ruce co nejdéle."},"ICON-0499":{"nm":"Tenká paletka na rty","de":"Objemná paletka zabírá v tašce celé místo. Ruka, která ví, že stačí jeden tence seříznutý proužek. Je to okamžik, kdy se ubírání stává samotným aktem dobrého balení."},"ICON-0500":{"nm":"Chránič řas","de":"Aby se řasy vyladěné jedna po druhé nerozmazaly, malý chránič jemně střeží jejich křivku. Co bylo s péčí nadzvednuto, musí být s péčí i chráněno - to napovídá čas strávený před zrcadlem."},"ICON-0501":{"nm":"Pouzdro na vatové tyčinky","de":"Malý domeček, aby se bílé vatové tyčinky nerozsypaly na všechny strany. Dotek, který je vždy po ruce pro poslední úpravu. Drobná příprava zaplňuje mezery velkého pódia."},"ICON-0502":{"nm":"Náhradní gumičky do kulmy na řasy","de":"Když guma ztvrdne, kulma při natáčení řas bolestivě štípe. Mít po ruce náhradní gumičky pramení z jemnocitu, který myslí i na tu nejmenší bolístku."},"ICON-0503":{"nm":"Štětec na korektor","de":"Tenký hrot štětce jemně stírá stíny. Přináší jas na místa, kam světlo dosud nedosáhlo. Ruka, která spíše přidává světlo, než by kryla nedostatky, dokončí líčení mnohem půvabněji."},"ICON-0504":{"nm":"Sítko na pudr","de":"Jemný pudr provlečený sítkem ulehne hladce, beze shluků. Ta trocha námahy navíc, prosít ho ještě jednou. Píle se nakonec pozná právě na konečku prstu, který udělá krok navíc."},"ICON-0505":{"nm":"Natáčecí spona na ofinu","de":"Spona, která ofinu srolovanou dokulata na chvíli přidrží. Zatímco čekáte, tvar se klidně usadí. Upravenost rozkvétá tam, kde se člověk umí nespěchat a počkat."},"ICON-0506":{"nm":"Lžička na vosk na vlasy","de":"Vosk se touto malou lžičkou nabere dřív, než se dotkne rukou. Zdrženlivost brát si jen přesně tolik, kolik je třeba. Ruka, která umí použít bez nadbytku, vytváří ten nejpřirozenější účes."},"ICON-0507":{"nm":"Podložka pod kulmu","de":"Rozpálenou kulmu nelze jen tak odložit kamkoli. Jedna podložka chrání stůl i ruce zároveň. Místo, které pracuje s teplem, vždy potřebuje bezpečný kout na odpočinek."},"ICON-0508":{"nm":"Vzorek vlasového oleje","de":"Jediná kapka stačí na dostatečný lesk, proto je úhledně uložena v malé vzorkové lahvičce a zastrčena do koutku tašky. Malá lahvička, na rozdíl od velké, se nakonec dostane do ruky mnohem častěji."},"ICON-0509":{"nm":"Hřebínek na čištění kartáče","de":"Vlasy zamotané ve štětinách hřebínek pomalu vyčeše ven. Péče o nástroje je tichý rituál po skončené práci. Dobře upravený kartáč krásně utváří zítřejší účes."},"ICON-0510":{"nm":"Cívka na gumičky do vlasů","de":"Stačí je namotat na cívku a všechny jsou na první pohled přehledné. Tento úhledně stočený balíček je něžná chvilka klidu darovaná uspěchanému ránu, kdy se gumičky rozkutálely na všechny strany."},"ICON-0511":{"nm":"Balení rukavic na barvení","de":"Tenké rukavice, které chrání ruku nanášející barvu, aby se nezabarvila. Touha přivítat další úkol čistýma rukama i po skončené práci. Ochrana je jen jiné jméno pro takovou připravenost."},"ICON-0512":{"nm":"Pouzdro na síťku na vlasy","de":"Malý sáček, do kterého se úhledně složí síťka, jež drží účes na místě. Čím méně objemu věc má, tím snáz se ztratí, a proto je vděk za pečlivou ruku, jež jí najde vlastní domov."},"ICON-0513":{"nm":"Fixační pero na odstávající vlásky","de":"Pero, které ťuknutím uhladí odstávající vlásky zpět na místo. Úplně poslední dotek po skončeném velkém stylingu. Dokončení je vždy prací s hlazením toho nejmenšího místečka."},"ICON-0514":{"nm":"Testovací uzávěr na parfém","de":"Při výběru vůně se nedrží přímo pod nosem. Nanese se na malý uzávěr a nechá rozplynout ve vzduchu, teprve tak se odhalí její skutečná struktura. I vůně je upřímná až v okamžiku, kdy ji ucítíme o krok dál."},"ICON-0515":{"nm":"Kuličková lahvička na parfém","de":"Kulatá kulička se kutálí a kreslí vůni na zápěstí. Na rozdíl od starých lahviček, kde se vůně jen ťukala, se tu jedna linka roztéká jako po hedvábí. Vůně zanechává jiný příběh podle toho, jakým způsobem se dotkne."},"ICON-0516":{"nm":"Uzávěr na tělový mlhový sprej","de":"Malý uzávěr, který uvězní vůni rozpínající se jako mlha. Zavírat a chránit to, co se rozptýlí, jen když se otevře. Trocha šetrnosti způsobí, že vůně zůstane po boku déle."},"ICON-0517":{"nm":"Přívěsek na krém na ruce","de":"Připevníte kroužek k malému krému na ruce a on jde s vámi všude. Společník houpající se venku na tašce se stává něžným pozdravem vyprahlým konečkům prstů."},"ICON-0518":{"nm":"Háček na žínku","de":"Když se napění bublinky, musí se pořádně usušit. Síťovaná koule zavěšená na háčku v koutě koupelny setřepává kapky vody a svěže čeká na příští ráno."},"ICON-0519":{"nm":"Pouzdro na masážní míček","de":"Malý sáček, do kterého se uloží tvrdý míček uvolňující ztuhlá ramena. Krátký odpočinek za jevištěm, chvíle tichého hlazení strnulého těla. Péče vždy začíná u sebe sama."},"ICON-0520":{"nm":"Dóza na chladivé náplasti","de":"Dóza, ve které jsou uskladněné náplasti, jež po nalepení příjemně zchladí. V noci po rozpáleném vystoupení v ní dřímá malá útěcha, pomalu utišující rozehřáté tělo i srdce."},"ICON-0521":{"nm":"Pero s olejem na nehty","de":"Stisknout, potřít, zalesknout se. Vyprahlým konečkům prstů stačí jediná kapka. Netřeba žádné okázalé kúry; jemný lesk, který se rozlévá ze špičky malého pera, se půvabně rozprostírá po nehtech. Péče začíná právě takovou jednou malou kapkou."},"ICON-0522":{"nm":"Sponka na voňavý sáček","de":"Malý uzlík, jenž přiváže vůni k papíru. Kdykoli otevřete zásuvku, jemná hrst vůně vás pozdraví dřív než vlastní ruka. Něha, která zůstává nablízku, i když ji nevidíte — jedna sponka tiše v sobě ukrývá útěchu na celý den."},"ICON-0523":{"nm":"Paletka na nehtové tipy","de":"Malé pódium, na němž se předem rozprostřou barvy pro všech deset prstů. Který odstín se dnes bude hodit? Na paletce se odehrává tichý konkurz. Ta chvilka výběru je nějak vzrušující a den konečků prstů tu právě začíná."},"ICON-0524":{"nm":"Krytka na odhrnovač kůžičky","de":"I v odhrnování je něha. Jeden zadřený proužek kůžičky se zaobleným hrotem jemně, nikam nespěchá. Uspěchaná ruka vždy něco přehlédne, a tak je úprava blíž mysli, jež se dívá pomalu a pozorně."},"ICON-0525":{"nm":"Mini pilníček-leštička","de":"Drsná strana a jemná strana, dvě tváře v jedné ruce. Jemné obroušení hrbolatých míst do hladka je maličkost, ale dokonalost vždy přichází právě z takových drobných doteků. Poslední slovo nakonec patří jemnosti."},"ICON-0526":{"nm":"Arch nálepek na nehty","de":"Hvězdička, kytička, srdíčko — stačí vybrat ten pravý motiv pro dnešní náladu a přiklepnout ho. Na archu, kde v řadách odpočívají obrázky velké jako nehet, se jedna nálepka třpytí jako něžný podpis zanechaný na konečku prstu."},"ICON-0527":{"nm":"Krycí štítek na UV lampu","de":"Tenká clona, která na chvíli uvězní světlo. Zatímco gel tuhne, oči odpočívají a tvrdnou tiše jen konečky prstů. I čekání potřebuje kousek stínu — v nespěchaném čase se dnešní konečky prstů dokonávají."},"ICON-0528":{"nm":"Dóza na nehtové ozdůbky","de":"Třpytivé kousky dřímou přihrádka po přihrádce. Kamínky, perličky, hvězdný prach — víčko se otevírá se vzrušením, jaké přináší odemčení neoznačené šperkovnice. Které světlo dnes položit na nehty? Právě tenhle okamžik výběru se třpytí nejvíc."},"ICON-0529":{"nm":"Pečující rukavice na ruce","de":"Krátká dovolená, kterou si ruce dopřejí, zatímco spíte. Uvnitř rukavic suchá pokožka přes noc pomalu ozdravuje vlhkostí. Péče se nakonec vždy odehrává tam, kde ji nevidíme, a ráno o té něze jako první ví konečky prstů."},"ICON-0530":{"nm":"Pumpička s odlakovačem","de":"Jedno stisknutí, přesně tolik, kolik je třeba. Chladivá vůně se vsákne do vatičky a dočista setře včerejšek z nehtů. I vyprazdňování má svůj rytmus — jedno stisknutí pumpičky tiše uvolní místo pro nový lak."},"ICON-0531":{"nm":"Pinzeta na kamínky","de":"Chcete-li uchopit klenot jemnější než konček prstu, potřebujete ještě jemnější ruku. Hrot pinzety přemístí jeden bod bez chvění — jemnost je stejně tak zásluhou nástroje jako srdce. Jedno malé světýlko nachází své místo."},"ICON-0532":{"nm":"Přihrádka na náušnice","de":"Aby se osamělá náušnice nikdy víc neztratila v zásuvce. Zasunete-li každý pár na své místo, výběr v uspěchaném ránu se stane o poznání lehčím. Uklízení je malá laskavost věnovaná budoucí sobě."},"ICON-0533":{"nm":"Sada na měření velikosti prstenu","de":"Malý svazek kroužků, který obvod prstu promění v číslo. Postupné zkoušení jednotlivých velikostí se podobá pomalému poznávání toho, co člověku sedí přesně. Jako ta úleva, když něco padne úplně dokonale."},"ICON-0534":{"nm":"Kolík na hodinkový řemínek","de":"Když se řemínek povolí, právě tenhle malý kolík znovu připoutá čas k zápěstí. Že nejhlouběji skrytá součástka vydrží nejdéle — to dlouho nošené hodinky mlčky vědí."},"ICON-0535":{"nm":"Přihrádka proti zamotání náhrdelníků","de":"Přihrádky rozdělené tak, aby se tenké řetízky nemohly zamotat jeden do druhého. Ráno bez zamotání začíná u malých přepážek rozdělených ještě večer předem. Volnost je nakonec mysl uspořádaná dřív, než se jí dotkne ruka."},"ICON-0536":{"nm":"Zapínání na zadní stranu brože","de":"Čím okázalejší přední strana, tím tišší je ta zadní. Malá spona, jež pevně podpírá brož připnutou na látce — za každým viditelným leskem vždy stojí bezejmenná ruka, která to drží. Místo o to spolehlivější, oč méně je vidět."},"ICON-0537":{"nm":"Pouzdro na sluneční brýle","de":"Měkká látka jemně obepíná čočky, jež chránily před letním sluncem. Malý sáček, který uchrání jeden pár před nárazy v tašce. Něha, s níž si člověk něčeho váží, přichází vždy v podobě takové měkké vrstvy."},"ICON-0538":{"nm":"Děrovač do opasku","de":"Pro pas zúžený o jednu dírku i pro roční období rozšířené o jednu dírku. Stačí prorazit ještě jednu dírku a opasek zase sedí. Vždy se mění jen já, a tiše se mi přizpůsobovat je práce tohoto malého nástroje."},"ICON-0539":{"nm":"Klip na šátek","de":"Klip, který sklouzávající šátek zachytí v jednom bodě a přidrží. Půvab, jenž se ve větru neustále rozpínal, se konečně usadí na místě. I elegance se občas opře o tuhle malou sponku a upraví den, který se málem rozcuchal."},"ICON-0540":{"nm":"Sada přívěsků na tašku","de":"Sada malých kroužků k zavěšení na bok tašky přišla pohromadě. Touha nosit s sebou to, co má člověk rád — zavěsit dnešní náladu na jeden přívěsek je malý rituál, který znáte jen vy, a nějak je z něj radost."},"ICON-0541":{"nm":"Odstraňovač žmolků","de":"Když se svetr přes noc jako by zestárl žmolky, stačí po něm jemně přejet touto dózou a znovu se obleče do tváře novoty. Lehké bzučení, které odnáší opotřebení, je nějak uklidňující. Milovaný kus oblečení tak znovu ožívá."},"ICON-0542":{"nm":"Vonná kartička do skříně","de":"Zasuňte ji hluboko do skříně a tiše po několik dní naplní dny vůní. Dopis psaný vůní místo písmen, stránka čitelná, i když se nerozevře. Každé ráno, kdy vytáhnete kus oblečení, se nejdřív rozšíří něha zapsaná včera."},"ICON-0543":{"nm":"Špendlík proti statické elektřině","de":"Zimní ráno, kdy se lem sukně lepí na nohy, jeden špendlík jemně tu přilnavost rozpustí. Malý klid, jenž utiší i neviditelné tření — když zmizí jedna drobná mrzutost, den plyne o poznání hladčeji."},"ICON-0544":{"nm":"Cestovní kartáč na oděvy","de":"Těsně před vyjitím ze dveří usedl na rameno pruh prachu. Rozevřete složený kartáč, jeden tah, a první dojem je znovu upravený. Dokončení se vždy odehrává u dveří a úhlednost je završena právě tím jedním tahem."},"ICON-0545":{"nm":"Štítek na prací síťku","de":"Věci, které se nesmí míchat, uvězní síťka, a štítek tiše popíše jejich jméno. I prádlo má své místo a k místu patří drobná značka. Řád snadno rozházeného dne roste z právě takového malého jmenovky."},"ICON-0546":{"nm":"Pero na odstraňování skvrn","de":"I stopu, kterou po košili zanechala jediná kapka kávy, klepnutí za klepnutím tiše zažene pryč. Pero, které chybu nezakrývá, ale jemně stírá. Každý potřebuje jednu šanci začít den znovu čistě."},"ICON-0547":{"nm":"Hadřík na leštění bot","de":"Jeden tah hadříkem a kůže si znovu získá svůj lesk. Čím déle jsou boty nošeny, tím hlouběji se usadí lesk. Lesk je odměnou za čas ušlý společně — boty tiše vrývají ty roky na nárt."},"ICON-0548":{"nm":"Krytka na tkaničky","de":"Malá čepička nasazená na konec rozvázané tkaničky. Aby se pohled neodklonil až do cíle, konec je pevně zapečetěn. Jedna dobře zavázaná tkanička pošle krok o kus dál — drobná péče se stává odvahou doběhnout až do konce."},"ICON-0549":{"nm":"Jmenovka na ramínko","de":"Mezi podobnými ramínky tiše prozradí jedna malá destička, „tohle je moje místo“. Tichý průvodce, který zmírňuje zmatek uspěchaného rána — méně hledání znamená i lehčí start dne."},"ICON-0550":{"nm":"Pouzdro na pinzetu na kontaktní čočky","de":"Někdy je potřeba hrot přesnější než konček prstu. Pinzeta, jež bez chvění zvedne malou čočku, čeká uvnitř pouzdra na svou chvíli. Přesnost vždy tiše leží připravená, spí, dokud není zavolána, a pak se okamžitě probudí."},"ICON-0551":{"nm":"Mini balení kosmetických tampónků","de":"Malý balíček obsahující přesně tolik, kolik stačí na jedno použití. Zmenší objem v tašce, aniž by ubral na jemnosti. I brát si méně je jistý druh laskavosti — na uvolněné místo pak vstoupí lehčí den."},"ICON-0552":{"nm":"Pouzdro na matující ubrousky","de":"Lesk rozlitý na nose v poledne jemně přitiskne a setře jeden tenký lístek. Papírky spí v úhledných řadách uvnitř pouzdra — v tu chvíli, kdy vytáhnete jeden lístek, se každý na okamžik zastaví a láskyplně se podívá na sebe v zrcadle."},"ICON-0553":{"nm":"Skládací zrcátko s hřebenem","de":"Složené je dlaní, rozevřené je zrcátkem a hřebenem. Malý všeuměl v koutku tašky, jenž zvládne rychlou úpravu za pochodu. Upravenost není nic okázalého, je blíž mysli, která se dokáže kdekoli rozevřít pro jeden rychlý dotek."},"ICON-0554":{"nm":"Krytka na cestovní holítko","de":"Bezpečně uspí ostrou čepel v cestovní tašce. Díky téhle tupě vyhlížející, ale pevné krytce se ani prsty tápající v uspěchaném ránu nepořežou. Starostlivost je vždy zakrytí nebezpečí o krok dopředu."},"ICON-0555":{"nm":"Poutko na balzám na rty","de":"Malý štít houpající se na popruhu tašky. Bez obav, že se bude povalovat v kapse a rozbije se, zůstávají vyprahlé rty vždy na dosah ruky. Mít něco po ruce znamená nakonec srdce, které dá potřebné na nejbližší vzdálenost."},"ICON-0556":{"nm":"Držák na dezinfekční gel","de":"Stisknete jednou rukou a vypadne hrst čistoty. Zavěste ho u dveří, na stůl, kamkoli, a zvyk čistých rukou se o to přiblíží. Dobrý zvyk není nic okázalého, začíná na dosah ruky."},"ICON-0557":{"nm":"Tenké pouzdro na kapesníčky","de":"Štíhlé tělo, v němž se skrývá hrst kapesníčků. Aniž by kapsa vypadala vypouklá, je vždy tiše připraveno na náhlou rýmu nebo slzy. List, který se dá potají podat někomu jinému — čím štíhlejší je připravenost, tím je půvabnější."},"ICON-0558":{"nm":"Mini lahvička ústní vody","de":"V den, kdy je po ostré ramen polévce třeba se s někým setkat, se tahle malá lahvička nenápadně postará o osvěžení. Doušek svěžesti se občas stane velkou dávkou sebedůvěry a nesmělý pozdrav udělá mnohem lehčí."},"ICON-0559":{"nm":"Třpytivý pudr v tabletě","de":"Nanesete konečkem prstu na tvář a rozprostře se jako hvězdný prach rozptýlený pod světly. To, že obyčejná tvář v okamžiku zazáří, je kouzlo právě téhle jedné malé tabletky. Světlo takhle přichází vždy — na prášku uloženém na konečku prstu."},"ICON-0560":{"nm":"Tlumicí nálepka na glitter","de":"Na místo, kde je třpyt až příliš okázalý, tahle nálepka jemně přitlumí světlo. I odejmutí jedné vrstvy okázalosti je součástí líčení — jemnost, jež zůstane na uvolněném místě, se občas stane úplně novým smyslem."},"ICON-0561":{"nm":"Pero na sbírání kamínků","de":"Malý kamínek zachycený pod chodidlem při procházce. Pero, které se schválně skloní, aby ho zvedlo. Srdce, jež konečkem prstu tiše sebere to, co mohlo být jen minuto — něha vždy začíná zastavením se."},"ICON-0562":{"nm":"Úložná destička na umělé řasy","de":"Malá destička, na niž se úhledně, řasa po řase, pokládají umělé řasy. I po sundání zůstane jejich půvabná křivka nezměněná. Tichá, upravená útěcha uskladnění, jež říká, že i to, co bylo na chvíli odloženo, si pamatuje své místo."},"ICON-0563":{"nm":"Krytka na řezačku pásky na víčka","de":"Dvě čepele se sevřou a jedním tahem přeruší uzel. Čím čistší je řez, tím úhlednější je další uzel. Z konečku prstu, který dobře váže a dobře odstřihává, se i nový začátek rozvine mnohem lehčeji."},"ICON-0564":{"nm":"Konturovací páska na linii obličeje","de":"Jeden pruh podél linie čelisti, nalepený opatrně, se zadrženým dechem. Kontura neznamená kreslit linku, která tam nebyla, ale zdůraznit místo, jež bylo krásné už předtím. Je to dotek, který něžně sleduje strukturu, jež tam byla odjakživa."},"ICON-0565":{"nm":"Pudr odrážející světlo","de":"Pudr, který do sebe naplno vsákne světlo a půvabně ho vrátí zpět. Sám nezáří, přesto se rozjasní tím, že přijaté světlo rozptýlí na drobné jiskřičky. Jako když se předává vypůjčená něha dál někomu jinému — třpyt roste tím víc, čím víc se sdílí."},"ICON-0566":{"nm":"Vějíř na fixaci líčení","de":"Vánek vějíře, jenž pracně vytvořený make-up drží pohromadě až do konce dne. Aby se nezhroutil, aby nezateklo, tiše ho chladí a nechá zatuhnout. Aby pečlivě upravená tvář zůstala výrazná, dokud nespadne opona na jevišti."},"ICON-0567":{"nm":"Korektorová paletka barevných odstínů","de":"Drobné kousky, jež po jedné přihrádce utiší a napraví posunutý odstín. I barva, jež sama plavala kdesi mimo, konečně zazáří, když vedle ní stojí barva, která ji doplňuje. Teprve když se barva chytí barvy za ruku, vznikne jedno čisté plátno."},"ICON-0568":{"nm":"Balení nákrčníků","de":"Ovinete-li ho kolem krku, chladný vzduch svítáníjících zkušeben se citelně zmírní. Hřeje jako dotek babičky, jež kdysi ovinovala vnoučeti krk. Chlad vždy přichází nejdřív na nejtenčí místa, a proto se první obejme šíje."},"ICON-0569":{"nm":"Sáček na zahřívací masku na oči","de":"Malý sáček, do kterého se ukládá zahřátá maska na oči. V okamžiku otevření chlopně se po víčkách zvolna rozlije ospalé teplo. Něžný rituál před spánkem, jenž na chvíli zapečetí unavený den a pak jej zase uvolní."},"ICON-0570":{"nm":"Cestovní zvlhčovací filtr","de":"Malá filtrační membrána, jež vysušené místnosti vrací vláhu. Zevnitř, kde ji nikdo nevidí, tiše cedí to, co kalí. Vlhkost naplňující místnost je jasnost, kterou udržel něčí nenápadný trud."},"ICON-0571":{"nm":"Dávkovač vitamínů","de":"Dóza, jež rozdělí denní dávku tablet do jednotlivých přihrádek. Poctivě je brát znamená slib, že zítra znovu stanete na jevišti. V každé malé přihrádce je úhledně uspořádána péče, kterou k sobě člověk chová."},"ICON-0572":{"nm":"Pouzdro na špunty do uší","de":"Domeček pro špunty, jež na chvíli ztiší zvuky světa. I ticho potřebuje péči, a proto uléhají úhledně uvnitř pouzdra. Pořádně prospaná noc je to, co příští den probudí čistý hlas — odpočinek to dobře ví."},"ICON-0573":{"nm":"Klip na chladicí ručník","de":"Klip, který pevně přichytí na rameno vychlazený ručník, aby nesklouzl. V parném dni jeden pramínek chladu na šíji pomůže vydržet dlouhé odpoledne. I malý chlad, když ho přidržíte, vydrží déle."},"ICON-0574":{"nm":"Sáček na protahovací míček","de":"Sáček, do kterého se uloží míček, jenž uvolnil tělo. Naplno ho roztáhnout a zase sbalit do malého tvaru připomíná nádech a výdech. Mezi rozevřením a shrnutím se tělo i mysl pomalu stávají pevnějšími."},"ICON-0575":{"nm":"Kompresní obinadlo","de":"Páska, jež kolo za kolem obepíná vyvrtnutý kotník. Není to stažení, je to tiché podepření. Čím víc je místo přetížené, tím víc potřebuje ruku, jež u něj mlčky vytrvá — obinadlo to šeptá, zatímco se omotává."},"ICON-0576":{"nm":"Visačka pro záznam kondice","de":"Visačka, na niž se jednou větou zapíše dnešní kondice a pověsí se. Poctivě přiznat, co je dobré a co ne, je malá odvaha. Místo předstírání, že je vše v pořádku, napište dnešní sebe — a někdo si tu jednu větu přečte a tiše se o vás postará."},"ICON-0577":{"nm":"Vonná kapsle do bot","de":"Vonná kapsle vhozená dovnitř boty. Malá, jemná útěcha darovaná nohám, jež celý den obcházely jeviště. Nejlepší vůně tam, kde bylo nejvíc práce — něha dosahuje až po samé špičky prstů, nic nevynechá."},"ICON-0578":{"nm":"Velikostní tabulka vložek do bot","de":"Tabulka, jež i na obyčejné vložce jasně vyznačí velikost chodidla. Jedny přesně padnoucí vložky odlehčí kroky na jevišti. Zohlednit rozdílný krok každého z nás — dobrá velikost je nakonec srdce, jež se hluboko dívá na toho druhého."},"ICON-0579":{"nm":"Přívěsek s lžící na boty","de":"Přívěsek s lžící na boty zmenšenou do velikosti dlaně. Malá pozornost, jež zjemní ten krátký okamžik obouvání. Nohy vydávající se na cestu s sebou vždy tiše nesou i něčí něžnou pomocnou ruku."},"ICON-0580":{"nm":"Prachový obal na kabelku","de":"Látka, jež jemně přikryje oblíbenou kabelku před prachem. I když se nepoužívá, uspí ji láskyplně a chrání její strukturu. Věci, na nichž srdci záleží, i když se jich ruka nedotýká často, v sobě nosí právě takovou tichou péči."},"ICON-0581":{"nm":"Kolíček na nastavení popruhu","de":"Kolíček, jenž povolený popruh přizpůsobí těsně na tělo. Příliš volný a rameno mu podklouzne, příliš utažený a dech se ztěžkne. V malém dílku nastavení, kdy je vše přesně tak akorát, konečně najde pohodlí jak scénický kostým, tak srdce."},"ICON-0582":{"nm":"Mazací pero na zip","de":"Jeden tah po zaseknutém zipu a znovu klouže hladce. Jak osvěžující je ten zvuk, když se zaseknuté náhle uvolní. To, co znovu rozproudí zastavené místo, je jediný pramínek hladkosti."},"ICON-0583":{"nm":"Hrot na čištění tenisek","de":"Hrot štětinek, jenž bod po bodu očistí tenisky pokryté prachem. Mimo jeviště pečlivě smaže neviditelné stopy tréninku. Při pohledu na znovu zbělelou špičku boty se zdá, že zítra se dá běžet zas s novým srdcem."},"ICON-0584":{"nm":"Uzávěr na nepromokavý sprej","de":"Uzávěr nepromokavosti, jenž nechá kapky deště stočit do kuliček a skanout dolů. Nanést předem jednu vrstvu, aby nic nezmoklo, je něha, jež hledí daleko dopředu. Protože se ví, že přijdou deštivé dny, obtáhne se dnešek, jasný a suchý, jedním tenkým filmem."},"ICON-0585":{"nm":"Ochranná látka na kůži","de":"Látka jemně přehozená přes kůži, aby zabránila záhybům. Chrání strukturu jako stará ruka, jež kdysi zabalovala paraván do papíru hanji. Čím déle chcete něco mít po boku, tím pomaleji na to jít — vypěstovaný vztah je jen jiné jméno pro čas věnovaný péči."},"ICON-0586":{"nm":"Jmenovací pás na kufr","de":"Jmenovací pás, díky němuž na první pohled poznáte svůj kufr mezi nespočtem jiných. Mezi zavazadly kroužícími po pásu zvedne ruku jediné písmeno. Ať odjedete jakkoli daleko, jedno jméno je jistota, že se zase shledáte."},"ICON-0587":{"nm":"Klip na kompresní sáček","de":"Klip, jenž nabobtnalá zavazadla přitiskne naplocho a zajistí. Nejde ani tak o vyprázdnění, jako spíš o pečlivé složení. Z konečku prstu, jenž úhledně zeštíhluje domácnost, se zmenšuje i chtivost — pevně stlačené zavazadlo to tiše prozrazuje."},"ICON-0588":{"nm":"Cestovní prací ubrousek","de":"Prací ubrousek, jenž jediným kusem promění umyvadlo v pračku. Připomíná moudrost poutníka, jenž si daleko od domova prádlo pral ručně. Cestovat s lehkým zavazadlem, a přesto si vzít s sebou úhlednost — dávný postoj poutníka na cestě."},"ICON-0589":{"nm":"Povlak na cestovní polštářek","de":"Čistý povlak, čerstvě navlečený na polštářek, jenž podpíral krk. Místo, o něž se opíráme, musí být vždy čisté, aby mysl našla klid. Ponechat místo měkké a prázdné, aby se o ně mohl někdo pohodlně opřít — pohostinnost tam právě začíná."},"ICON-0590":{"nm":"Popruh cestovní váhy","de":"Popruh, jenž zvedne kufr do vzduchu a odhadne jeho váhu. Než vyrazíte, předem si v ruce zvážíte tíhu zavazadla. Mezi tím, co vzít, a tím, co nechat, je to chvíle, kdy se tiše zváží i tíha srdce."},"ICON-0591":{"nm":"Pár pouzder na boty","de":"Pár pouzder, do nichž se vedle sebe uloží dvě boty, levá i pravá. To, co se snadno ztratí zvlášť, je v páru jisté a spolehlivé. Věci, jež vždy chodí spolu, mají v sobě sílu tiše na sebe dohlížet."},"ICON-0592":{"nm":"Přídavný háček na tašku","de":"V den, kdy nestačí jedna ruka, malý háček, na nějž lze na chvíli zavěsit tašku. Volná přihrádka pro dny, kdy je zavazadel víc, než dokážete unést. Pouhé vědomí, že je kam na chvíli něco zavěsit, citelně odlehčí ramenům."},"ICON-0593":{"nm":"Čip s cestovním programem","de":"Trasa dne přehledně vyryta na jeden čip. Kde se sejít a kam pak dál — vodicí linka nakreslená předem pro kroky, jež snadno zabloudí. Cesta, po níž se jde společně, se sotva ztratí, když je rozepsána přihrádka po přihrádce."},"ICON-0594":{"nm":"Krytka univerzálního adaptéru","de":"Krytka, jež se přesně zapasuje i do zásuvky neznámé země. Ač se liší tvarem, nakonec se propojí v jedno. Spojovat věci, jež přišly z různých míst — soulad tiše začíná právě jednou malou proměnou."},"ICON-0595":{"nm":"Obal na dopravní kartu","de":"Průhledný list, jenž chrání kartu při každém přiložení k turniketu. Denní cesta do práce a zpět, i vyrudlé stopy dotyků, jemně obalí. I obyčejná cesta se stane vzpomínkou, když si jí vážíme — dokazuje to právě tahle tenká vrstva."},"ICON-0596":{"nm":"Klip na jízdenku","de":"Klip, jenž úhledně přidrží jízdenku, která se rychle pomačká. Ztratíte-li jízdenku na cestě, zachvěje se i srdce. Čím menší papírek, tím pevněji ho držet — jistota cesty pramení právě z toho jednoho místa."},"ICON-0597":{"nm":"Poznámkový čip na přestup","de":"Malý čip, na nějž je jednou větou zapsáno, kde přestoupit. Na každé matoucí křižovatce otevře cestu do jasna jediné slovo napsané předem. Poznámka je něžné pošeptání budoucí sobě, jež by mohla zabloudit."},"ICON-0598":{"nm":"Průchodová visačka","de":"Visačka, jež tiše rozpozná průchod branou. I cesta, jež se zdála zablokovaná, se plavně otevře, máte-li své oprávnění. Projít otevřeně znamená lehce vykročit do dalšího úseku bez zaváhání."},"ICON-0599":{"nm":"Pouzdro na účtenky z taxi","de":"Na každém malém papírku je zřetelně vytištěna stopa cesty, kterou jste ten den ušli. Sesbírejte účtenky, jež se povalovaly na všechny strany, a úhledně je zastrčte pohromadě, a i den, jenž se zdál nicotný, se lístek po lístku nahromadí v pořádnou cestu."},"ICON-0600":{"nm":"Reflexní páska na kolo","de":"Páska, jež na tmavé cestě zachytí procházející světlo a tiše se zatřpytí. Ač sama nezáří, rozjasní se cizím světlem. Být viditelný je něžná prosba noční cesty: vrať se prosím bezpečně domů."},"ICON-0601":{"nm":"Chránič koleček na kufr","de":"Že hrany kufru zůstanou po tisících otáčkách na letištním pásu netknuté, za to vděčíš tomuhle malému návleku na kolečkách. Místo, které se jako první dotkne té nejdrsnější cesty – tiché opatrování bývá vždycky schované tam, kde si ho nikdo nevšimne."},"ICON-0602":{"nm":"Potah na opěrku hlavy","de":"Na dlouhé cestě autobusem si přetáhneš potah přes opěrku a opřeš hlavu o okno. Vůně předchozího cestujícího ani včerejší únava sem už nedosáhnou. Čisté místo k odpočinku hlavy je na neznámé cestě překvapivě velkou útěchou."},"ICON-0603":{"nm":"Značka místa na parkovišti","de":"„Které patro, které místo to bylo?“ Kdo se kdy dlouho toulal prázdným parkovištěm, ví, jak spolehlivý je tenhle špendlík. Jedna jediná značka zapíchnutá místo blednoucí paměti dopředu určuje cestu zpátky."},"ICON-0604":{"nm":"Šňůrka na klíč od pokoje","de":"Jak to, že klíč od pokoje tak snadno zmizí? Navlékni ho na šňůrku a omotej kolem zápěstí a na pokoj, který tě dnes večer čeká, už nezapomeneš. I v cizím městě ti na zápěstí visí ta malá jistota, že máš svoje vlastní místo."},"ICON-0605":{"nm":"Cedulka na dveře","de":"Když začne zkouška, pověsíš na dveře cedulku. Nerušit – teď je čas jen a jen pro soustředění. Tu hlubokou ztišenost za oponou tiše střeží právě takové drobné signály."},"ICON-0606":{"nm":"Toaletní taštička","de":"Kartáček, čisticí pěna, ručníček velký jako dlaň. Ať se vydáš kamkoli, stačí sbalit jen tuhle taštičku a konec i začátek dne budou vždycky upravené stejnou důvěrně známou rukou. Hrstka drobných věcí, díky které se i cizí lůžko rázem promění ve svoje."},"ICON-0607":{"nm":"Klip na náhradní ručník","de":"Vedle umyvadla ležel náhradní ručník pořád vlhký, protože neměl kam. S klipem konečně najde svoje místo. Dát něčemu prostor, kde může uschnout – laskavost mívá zpravidla přesně tuhle velikost."},"ICON-0608":{"nm":"Pouzdro na prodlužku","de":"Pokaždé, když jsi otevřel tašku, byly nabíječky zamotané do jednoho uzlu. Stočíš celou prodlužku a zastrčíš dovnitř – a věci se hned srovnají. Rozmotaný kabel znamená, že se ještě před cestou trochu rozmotá i kousek srdce."},"ICON-0609":{"nm":"Štítek s číslem lůžka","de":"Číselný štítek na každé palandě ve společné ubytovně. Jediný lístek, který ti řekne, které místo je tvoje, promění i cizí neznámý pokoj do večera v domov. Začátky bývají vždycky takhle malé."},"ICON-0610":{"nm":"Mini šňůra na prádlo","de":"Zavěsíš oba konce mezi okenní rámy a je z toho šňůra na prádlo. V slunečný den se pár ručně vypraných ponožek ve větru vesele pohupuje do sucha. I daleko od domova takhle na šňůře uschne kus všedního dne."},"ICON-0611":{"nm":"Jmenovka na pantofle","de":"Když se u dveří nahromadí spousta pantoflí, nepoznáš, čí jsou. Stačí připnout malou jmenovku a i bota pozná svého pána. Když spolu žije víc lidí namačkaných pohromadě, právě takové laskavé značky jsou k nezaplacení."},"ICON-0612":{"nm":"Pouzdro na snídaňový kupón","de":"Pouzdro, do kterého zasuneš snídaňový lístek. V hladovém ránu ti tenhle jediný papírek slibuje mísu horké polévky, ze které stoupá pára. Den na cestách se vždycky pomalu otevírá jedním teplým jídlem."},"ICON-0613":{"nm":"Reflexní páska na kotník","de":"Omotáš ji kolem kotníku a ve tmě odráží světlo zpátky. Na noční procházce mlčky mává přijíždějícímu autu zdálky – „tady někdo je.“ Bezpečí se takhle skromně třpytí."},"ICON-0614":{"nm":"Víčko na vlhčené ubrousky","de":"Víčko, které přesně sedí na otvor balení vlhčených ubrousků. Každý ubrousek se vytáhne hladce a zbytek nevysychá. Zdá se to jako maličkost, ale věci, po kterých sáhneš každý den, mívají vždycky svůj dobrý důvod."},"ICON-0615":{"nm":"Poutko na piknikovou deku","de":"Deku srolujete do kolečka a svážete poutkem. Břeh řeky, stín třešňových květů – ve chvíli, kdy ji rozprostřete, se to místo stane naším. Poutko, které s sebou nosí celé území velké jako dlaň."},"ICON-0616":{"nm":"Pouzdro na náplasti proti komárům","de":"Nezbytná věc letních večerů – pouzdro na náplasti proti komárům. Do jedné jediné přihrádky se vejde starostlivost připravená ještě dřív, než začne svědění. Zadní řady venkovního pódia bývají vždycky jistější díky právě takovým drobným opatřením."},"ICON-0617":{"nm":"Karabina na láhev na procházku","de":"Karabina, kterou při vycházce připneš láhev k tašce. Mít vodu na dosah, až přijde žízeň, znamená, že dojdeš o kus dál. Drobné spojení, díky kterému chodec nikdy nezastaví."},"ICON-0618":{"nm":"Skládací nákupní košík","de":"Rozložíš a je to nákupní košík, složíš a vejde se do dlaně. Ideální na svazek zeleniny, ke kterému sis stačil na trhu přičichnout. Moudrost domácnosti odjakživa směřuje k menšímu objemu, k lehčímu nošení."},"ICON-0619":{"nm":"Klip proti větru","de":"Ve větrný den pevně sevře třepotající se cíp stanu. Jediný klip přitiskne na místo to, co se pořád zmítalo. Venku bývá nejspolehlivější, překvapivě, věc velká jako prst."},"ICON-0620":{"nm":"Sluneční clona na okno","de":"Špendlík, který zapíchneš do okna a šikmo zastíníš sluneční paprsky. Když je poledne příliš ostré, tiše nad tebou rozprostře hrst stínu. Zmírnit oslnění bývá pro někoho tím nejlaskavějším dotekem."},"ICON-0621":{"nm":"Krytka na nouzovou píšťalku","de":"Krytka, která zakrývá ústí nouzové píšťalky. Nepustí dovnitř prach, aby ve chvíli, kdy to bude skutečně potřeba, zazněla na jeden nádech. Některé věci přinášejí klid jen tím, že jsou nablízku, i když doufáš, že je nikdy nepoužiješ."},"ICON-0622":{"nm":"Krytka na hrot deštníku","de":"Malá krytka, kterou nasadíš na hrot deštníku. Když se ostrý konec otupí, neublíží ani člověku vedle tebe, ani tvé vlastní tašce. Slušnost v deštivý den tiše začíná právě tím, že se ostrý hrot obalí do kulata a měkka."},"ICON-0623":{"nm":"Pouzdro na pláštěnku","de":"Pouzdro, do kterého srolovaná pláštěnka zapadne a schová se. Tiše čeká v koutě tašky, dokud se nespustí další liják. Připravenost je nakonec jen kousek srdce, který si dopředu sbalí věc, kterou možná nikdy nepoužije."},"ICON-0624":{"nm":"Nepromokavé návleky na boty","de":"Natáhneš je přes boty a déšť už dovnitř neprosákne. I na cestě do školy v lijáku zůstanou ponožky sušinké. Den, kdy nezmokneš až do prstů u nohou, ti náladu změní víc, než by se zdálo."},"ICON-0625":{"nm":"Protiskluzová podložka na sníh","de":"Nalepíš ji na podrážku a namrzlá cesta hned tolik neděsí. Tu zimu, kdy jsi drobnými krůčky přebíhal zasněžené uličky, tě tahle podložka tiše držela na nohou. Spolehlivost skrytá pod opatrnými kroky."},"ICON-0626":{"nm":"Chladicí kruh na krk","de":"Obtočíš ho kolem krku a tiše se rozlije chladivý proud. Letní moudrost, díky které si i v největším vedru nosíš na šíji pramínek svěžesti. I snášet horko se rok od roku učíme trochu obratněji."},"ICON-0627":{"nm":"Stojánek na ruční ventilátor","de":"Stojánek, na který postavíš ruční ventilátor. Když máš obě ruce volné, můžeš listovat knihou i psát, místo abys mával. Malý závan větru dokáže dlouhé letní odpoledne u stolu udělat tak akorát snesitelným."},"ICON-0628":{"nm":"Pouzdro na ohřívač rukou","de":"Pouzdro, ve kterém nosíš ohřívač rukou. Když si prokřehlé prsty strčíš do kapsy, aby se zahřály, malé teplo už tam čeká. Zimní vycházky se dají vydržet právě s touhle hrstkou tepla."},"ICON-0629":{"nm":"Pouzdro na chrániče uší","de":"Pouzdro, ve kterém uchováváš chrániče uší. Místo, kam je pečlivě uložíš, dokud nepřijde další zima. Věci, kterých se ani se změnou ročního období nedokážeš zbavit, v sobě nesou tichou víru v zimu, se kterou se ještě setkáme."},"ICON-0630":{"nm":"Čip na měření UV záření","de":"Přiložíš ho jemně ke světlu a čip ti barvou prozradí dnešní sílu UV záření. Konečně zviditelní intenzitu slunečního svitu, kterou jsi předtím nemohl vidět. Je to, jako by sis na zápěstí připjal malé oko, které umí číst oblohu."},"ICON-0631":{"nm":"Razítková karta uliček","de":"Karta, kterou zaplňuješ razítky sesbíranými od obchodů podél uličky. S každým vyraženým políčkem se v srdci jasněji vykresluje mapa čtvrti. Vzpomínky nasbírané po vlastních nohou takhle zůstávají jako otisky razítek."},"ICON-0632":{"nm":"Nástěnka s cestovními špendlíky","de":"Malá nástěnka, do které zapíchneš špendlík za každé místo, kde jsi byl. S přibývajícími tečkami se rozšiřuje i obvod tvého světa. Každý špendlík je stopou, která tiše šeptá: „já jsem tady byl.“"},"ICON-0633":{"nm":"Šňůrka s kompasem","de":"Ať bloudíš sebedéle, sever jediný zůstává vždycky na svém místě. Malý kompas zavěšený na hrudi, když nemáš tušení, kudy dál, nejdřív tiše uklidní rozechvěné srdce."},"ICON-0634":{"nm":"Kroužek s poznámkami k trase","de":"Lístečky popsané při hledání cesty navlečené na kroužku. „Za červenou poštovní schránkou doleva.“ Něčí neobratné písmo tiše provádí neznámou uličkou. Cesta zanechaná na papíře jen tak nevybledne."},"ICON-0635":{"nm":"Sešit nálepek s památkami","de":"Sešit, který zaplňuješ jednou nálepkou koupenou v každém cíli cesty. Věže, mosty, staré hradby se hromadí strana po straně. Sbírat navštívená místa se podobá tomu, jako bys prsty znovu ohmatával čas, kterým jsi prošel."},"ICON-0636":{"nm":"Přestupní čip do metra","de":"Čip, který pevně svíráš v ruce na přestupní stanici, kde se linky rozdělují. Ten krátký okamžik rozhodování, kam přesednout, dokáže někdy obrátit směr celého dne. Jedinou malou volbou ukáže město jinou tvář."},"ICON-0637":{"nm":"Karta objevování čtvrti","de":"„Dnes až k pekařství v této čtvrti.“ Vytáhneš jednu kartu a je určen dnešní cíl objevování. I ta uzoučká, důvěrně známá ulička, kterou chodíš pořád, se s úkolem stane novou cestou. Karta, která připomíná, že dobrodružství není daleko."},"ICON-0638":{"nm":"Pouzdro na vizitky z obchodů","de":"Pouzdro, do kterého zastrkáváš vizitky získané v oblíbených obchodech. To místo, kde bylo tak dobré jídlo, ten majitel s přívětivým pozdravem – hromadí se přihrádka po přihrádce. Sblížit se s jedním městem začíná právě u takových drobných papírků."},"ICON-0639":{"nm":"Deska odznaků za dokončenou trasu","de":"Deska, na které za dokončení celé procházkové trasy získáš odznak. Odměna za doputování do cíle zůstane v ruce jako kulatý kousek kovu. Ta hrdost, kterou zná jen ten, kdo prošel celou cestu, se tu zřetelně otiskne."},"ICON-0640":{"nm":"Zámek na tašku s klíčenkou","de":"Malý zámek s klíčenkou, kterým zajistíš zip na tašce. Pečlivě střeží to nejcennější, a přitom si vesele cinká na okraji tašky. Docela vynalézavý společník cestovatele, ve kterém splynula bezpečnost s ozdobou."},"ICON-0641":{"nm":"Lokátor proti ztrátě","de":"Krčí se v té nejhlubší tmě tašky a přesně ve chvíli, kdy to všichni vzdali, slabě zablikne. „Tady jsem.“ Zvuk toho, jak se věc, o které sis myslel, že je navždy ztracená, vrací zpátky pod prsty. Malý, a přece stojí při svém majiteli až do konce."},"ICON-0642":{"nm":"Zajišťovací kroužek na zip","de":"Cvak – jednou zapnutý, obyčejná ruka ho neotevře. Stejnou tvrdohlavostí zastaví uspěchaný nehet i pokradmu se plížící prst. Bezpečnost svou tíhou tiše říká, že být tu a tam trochu neposedná, je v pořádku."},"ICON-0643":{"nm":"Poutko s bezpečnostním zvonkem","de":"Neviditelný strážce, který hlídá, aby zboží na pultu nevyšlo bez placení ven. Když ho mine poctivá ruka, zůstane až do konce zticha. Zvonek, který nezazvoní, je ten nejpokojnější zvonek ze všech."},"ICON-0644":{"nm":"Krycí štítek na kontaktní údaje","de":"Tiše se přeloží přes jméno a číslo napsané na balíku. Kdo tu bydlí, kam to jede, to musí vědět jen adresát. Umět dobře zakrýt je taky druh laskavosti, tiše si stojí za svým místem."},"ICON-0645":{"nm":"Páska na obal pasu","de":"Neznámé letiště, desítky stejných obalů krouží před svítáním po pásu. Uprostřed nich máváš barvou, kterou znáš jen ty – „tudy.“ Malý kabátek, který obléká doklad vydávající se na dalekou cestu. Ať se obal sebevíc obnosí, cesta zůstává jasná."},"ICON-0646":{"nm":"Rozdělovací peněženka na hotovost","de":"Bankovky vlevo, mince vpravo, rezerva v přihrádce, o které nikdo neví. Je to první místo, kam sáhne ruka čerstvě z tržnice. I rozházený den si tu uvnitř najde svoje místo, úhledně a s cinkotem."},"ICON-0647":{"nm":"Bezpečnostní pečetní nálepka","de":"Jednou odlepená, zanechá stopu. Malé, poctivé svědomí, které nedokáže do konce skrýt, že „tu někdo otevřel.“ Pod každou krabicí, která dorazí zapečetěná a v pořádku, leží nezlomné mlčení tohoto přítele."},"ICON-0648":{"nm":"Čip s nouzovým kontaktem","de":"Kapsa zatoulaného dítěte, vnitřek tašky na notebook, konec vodítka pro psa. I ve chvíli, kdy nejde promluvit, za tebe zřetelně vykřičí číslo. V jediném malém čipu je uschované celé „prosím, doveďte mě domů.“"},"ICON-0649":{"nm":"Krytka dálkové spouště na selfie tyč","de":"Skupinové fotky, kde kvůli krátkým pažím vždycky někdo vypadl ze záběru. Teď stačí jedno cvaknutí tlačítka na konci a celá rodina se vejde do jednoho záběru. V té chvíli, kdy se všichni smějí, potichu zmáčknu spoušť a skočím doprostřed."},"ICON-0650":{"nm":"Šňůrka na pouzdro na objektiv","de":"Šňůrka, která pevně přitiskne náhradní objektivy, aby se v tašce netloukly. Jeden kousek skla je zároveň jedna krajina, a tak tou vahou nikdy nezacházíš lehkovážně. V každém uzlu je zavázaná opatrnost fotografa."},"ICON-0651":{"nm":"Kroužek na pouzdro s filtry","de":"Jeden tenký list dokáže stejnou oblohu proměnit v jiné světlo. Místo, kde tahle drobná kouzla úhledně přebývají v kulatém hnízdě. Pokaždé, když otevřeš pouzdro, se ti na okamžik zachvějí prsty – jaký západ slunce dnes zachytím?"},"ICON-0652":{"nm":"Pouzdro na stativ","de":"Složený se vejde na dlaň, rozložený stojí na třech nohou bez sebemenšího chvění. Něžně sroluješ přítele, který místo tvých rozechvělých rukou udrží scénu v klidu. Čím těžší vybavení, tím měkčí látka mu náleží."},"ICON-0653":{"nm":"Podložka na řemínek fotoaparátu","de":"Po celodenní chůzi přijde chvíle, kdy fotoaparát tíží rameno. Právě tehdy tiše převezme kus té váhy jedna jediná podložka. Malá, měkoučká útěcha položená na rameno, které jde daleko za jedním dobrým záběrem."},"ICON-0654":{"nm":"Karta na třídění pamětových karet","de":"Noc, kdy si nejsi jistý, na které kartě spí které vzpomínky ze stovek fotek. Barevné značky ukazují cestu. Jarní výlet modře, první vystoupení žlutě. Malý, laskavý knihovník, který i vzpomínkám vyhradí vlastní poličku."},"ICON-0655":{"nm":"Navíječ nabíjecího kabelu","de":"Než kabely v tašce stihnou předvést představení uzlů, úhledně je stočíš do kolečka a uložíš ke spánku. Když urovnáš jeden kabel, jako by se zároveň rozvázal i pramínek v srdci. Na tu stočenou podobu je milý pohled."},"ICON-0656":{"nm":"Štítek zálohy fotek","de":"„Tyhle fotky – zálohoval jsem je?“ Drobná poznámka, která dopředu odpoví na ten neklid, co se pozdě v noci znenadání vkrádá. Čím vzácnější chvíle, tím víc musí žít na dvou místech nebo více, píše si štítek zřetelně pro sebe."},"ICON-0657":{"nm":"Rámeček na kompozici","de":"Podíváš se na svět skrz hranatý rámeček a hned je jasné, co zachytit a co nechat stranou. Dobrá fotka nevzniká přidáváním, ale dobrým ubíráním – to tě jako první naučí právě prázdný rámeček."},"ICON-0658":{"nm":"Přívěsek s peněženkou na drobné","de":"Pohupuje se na okraji tašky a v sobě chová pár mincí. Malá pokladnice, která se otevře jako první před automatem nebo stánkem s dýmajícími rybími koláčky. Ten cinkot je zvukovým efektem drobného štěstí."},"ICON-0659":{"nm":"Jehla na účtenky","de":"Lístky papíru, které jsi málem zahodil, se jeden po druhém navlékají. Co jsi dnes snědl a co koupil – účtenka je upřímnější deník než kterýkoli sešit s výdaji. Za měsíc se z nich nasbírá slušně tlustý záznam o životě."},"ICON-0660":{"nm":"Jmenovka na tržní košík","de":"Visí na zápěstí vyraženém na trh a společně obchází stánky. Kostka tofu, svazek jarní cibulky, i ta laskavost přidaná navíc zdarma. Všechnu tu váhu přijímá bez reptání. Přítel, kterého víc těší plnit než vyprazdňovat."},"ICON-0661":{"nm":"Deska na suvenýrové magnetky","de":"Vybereš jeden v každém cíli cesty, přilepíš na lednici a z kuchyně se stane malá mapa světa. Navštívená města visí vedle sebe a šeptají: „pojďme zase.“ I obyčejný plech má sílu udržet vzpomínky."},"ICON-0662":{"nm":"Sešit razítek z regionů","de":"Jedno razítko na stránku a projité uličky znovu ožívají v inkoustu. Červené otisky nasbírané při putování celou zemí jsou mapou tvých šlépějí. Čím míň prázdných políček zbývá, tím tišeji láká další cesta."},"ICON-0663":{"nm":"Cívka balicí šňůry","de":"Dlouhá, předlouhá trpělivost, která se odvíjí donekonečna, jen aby svázala jednu jedinou dárkovou krabici. Úhledný uzel dopřeje jen rukám, které vědí, kdy přestřihnout. Stočená tiše čeká, až přijde její další řada."},"ICON-0664":{"nm":"Výplňový polštářek na dárky","de":"Objímá křehké srdce do měkkého náručí. I v rozhoupané rozvážce vydrží pevně a měkce – „v pořádku, já tě podržím.“ Dopředu tak střeží i ten jasný úsměv toho, kdo krabici otevře."},"ICON-0665":{"nm":"Nálepka na zakrytí cenovky","de":"Milá bílá lež, která tiše přikryje cenu darovaného předmětu. „Nemusíš vědět kolik, stačí přijmout to srdce,“ říká a jemně se posadí přes cenovku. Není to skrývání, ale to, jak nechat to srdce zazářit ještě víc."},"ICON-0666":{"nm":"Přívěsek s mini nákupním vozíkem","de":"Opravdový vozík netlačíš, ale tenhle malý přítel houpající se na špičce prstu v sobě nese celé to vzrušení z výpravy do obchodu. Malý, a přece to chvění „co dneska koupím?“ váží stejně jako to skutečné."},"ICON-0667":{"nm":"Svítící klip na botu","de":"Zablikne na špičce tenisky vyražené na noční procházku a vyšle projíždějícímu autu signál „tady někdo je.“ První světýlko, které tě přivítá v temné uličce. Bezpečí vždycky tiše začíná od špiček prstů u nohou."},"ICON-0668":{"nm":"Nástavec na malou baterku","de":"Nasadíš ho na hlavu baterky a světlo se rozlije dál a jemněji. Malý kouzelník, který na temný strop stanu namaluje hvězdné shluky. V nocích, kdy je tma trochu strašidelná, lepšího přítele nenajdeš."},"ICON-0669":{"nm":"Tlačítko „jsem doma“","de":"Zmáčkneš a vzkaz „dorazil/a jsem v pořádku“ odletí k daleké rodině. Místo zvuku otevíraných dveří pozdě v noci přinese zprávu jedno malé tlačítko. Někdo usíná právě s čekáním na tenhle signál."},"ICON-0670":{"nm":"Role reflexních nálepek","de":"Uřízneš čtvereček, nalepíš na tašku, na kolo, na deštník a noční cesta je hned o něco méně nebezpečná. Ospalec, který se rozzáří zplna, jen co potká světlo reflektorů. Stočená čeká, až přijde další tma."},"ICON-0671":{"nm":"Karta pro nouzové taxi","de":"Zastrčená v přihrádce peněženky a i prázdná zastávka pozdě v noci je hned míň skličující. Číslo, jeden řádek adresy zapsané jako slib – „odvezu tě domů.“ Kdo by řekl, že slovo „nouzový“ dokáže znít tak spolehlivě."},"ICON-0672":{"nm":"Páska s mapou noční cesty","de":"Ovineš si ji kolem zápěstí a jdeš ulicemi s řídkým osvětlením. Která ulička je jasná, kde je tma – potichu ti prozradí zkratku, kterou zná jen noc. Páska, která se přiváže po tvém boku, abys ve tmě nikdy neztratil směr."},"ICON-0673":{"nm":"Pouzdro na bezpečnostní alarm","de":"Zatáhneš v ohrožení a vykřikne tak hlasitě, že se leká celá ulička. Za normálních dnů se poslušně schovává v pouzdru a šetří hlas pro tu jedinou chvíli. Ten největší křik v té nejmenší tašce."},"ICON-0674":{"nm":"Klíčenka se světlem na dveře","de":"Sbohem nocím, kdy jsi tápal po klíčové dírce na temném konci chodby. Visí u dveří a kulatou záři vítá ruku vracející se domů. „Dobrá práce, jsi doma,“ pozdraví klíčenka jako první."},"ICON-0675":{"nm":"Vzkaz na návrat do ubytování","de":"„Vezmi si deštník, zhasni, než odejdeš.“ Krátká připomínka na lednici hlídá prázdný pokoj. Malý lístek pro toho, kdo se má vrátit. Laskavost obsažená v jednom kusu papíru tiše doprovodí až ke dveřím."},"ICON-0676":{"nm":"Hřeben na urovnání kabelů","de":"Zamotané dráty jemně pročesává a urovnává, jako by česal vlasy. Džungle kabelů za stolem se po pár tazích promění v úpravný pořádek. Není to jen vlasy, co se dokáže zamotat, tiše připomíná hřeben."},"ICON-0677":{"nm":"Přihrádka na tužky","de":"Tužky sem, zvýrazňovače tam, nůžky do posledního oddílu. V jedné nádobce rozdělí malou vesnici a každému peru určí místo. Jakmile jsou tu přihrádky, ruka už netápe. Začátek drobného pořádku na stole."},"ICON-0678":{"nm":"Klip na poznámky k monitoru","de":"Visí na boku monitoru a „dnešní úkoly“ strká přímo do výše očí. Malá nástěnka viděná zpříma, na kterou se nedá zapomenout. Jediný klip tiše zadrží mysl, která se pořád snaží všechno odkládat."},"ICON-0679":{"nm":"Třídicí zásuvková miska","de":"Sponky a gumičky, napínáčky a gumy. Malým kmenům v zásuvce dá každému vlastní pokojík. Když ruka sáhne do rozdělených přihrádek, čas hledání se zkrátí a kousek srdce se odlehčí."},"ICON-0680":{"nm":"Tuba na štětec na prach","de":"I jediné smítko prachu na objektivu se na fotce promění v obrovskou skvrnu. Proto štětec v tubě čeká vždycky bezvadně připravený. Pilná ruka, která hlídá čistotu, jíž si nikdo nevšimne."},"ICON-0681":{"nm":"Rohová podložka na stůl","de":"Dlaň měkkosti prostřená v jednom rohu stolu. Pero se nesklouzne dolů a místo studeného skla podpírá zápěstí teplá struktura. Laskavý povrch, který jako první nabídne svoje místo, aby se rukopis dlouhé noci nezachvěl."},"ICON-0682":{"nm":"Držák na kabel myši","de":"Když se zamotá šňůra, někde se zamotá i srdce. Dotek, který dopředu zachytí bloudící pramínek a uloží ho úhledně. Sotva viditelný, přesto tiše urovnává vzhled stolu – drobná, pilná úprava."},"ICON-0683":{"nm":"Stojan na nabíjecí dok","de":"Zvedneš ležící zařízení do šikmého postoje a obrazovka se konečně setká s tvým pohledem. I čekání během nabíjení se tím stane úhledným časem. Podepřít znamená dopřát správné držení těla i tomu, co si právě odpočine."},"ICON-0684":{"nm":"Štítek na malý koš","de":"I ten nejmenší koš dostane svoje jméno. Jediný řádek „sem hoď“ přivolá na rozházený stůl tichý pořádek. Štítek je nakonec drobným pozdravem, kterým věci sdělíš: tady je tvoje místo k použití."},"ICON-0685":{"nm":"Špendlík na nástěnku","de":"Přitiskne list papíru pevně na nástěnku. Svěřit stěně na chvíli myšlenku, na kterou nechceš zapomenout. Dnešní předsevzetí zavěšené na hrotu špendlíku se lehce chvěje ve větru a pokaždé, když jdeš kolem, tě zastaví."},"ICON-0686":{"nm":"Rámečkový čip na štítky","de":"Jediný hranatý rámeček promění obyčejné písmo v jasnou, jedinou větu. Čip, který snadno rozptýleným poznámkám obtočí úhlednou důstojnost. Není to uzavírání, ale objetí důležitých slov, aby se neztratila."},"ICON-0687":{"nm":"Průhledná úchytka na zásuvku","de":"Na průhlednou zásuvku připevníš úchytku a i když vidíš, co je uvnitř, neotevřeš ji jen tak lehkovážně. Dlaň vzdálenosti – viditelná, a přece nedotčená. I průhlednost potřebuje slušnost, šeptá tiše zásuvka."},"ICON-0688":{"nm":"Uzavírací klip na víčko","de":"Necháš-li ji otevřenou, vůně i barva se potichu vytratí. S jedním malým klipem, který pevně sevře víčko, zůstane včerejší barva netknutá až do zítřka. Uzamknout znamená ve skutečnosti chránit to, na čem ti záleží."},"ICON-0689":{"nm":"Držák na vysoušecí prostředek","de":"Malý strážce, který nenávidí vlhkost a mlčky drží svou hlídku. Že mít nablízku suchý vzduch je první podmínkou dlouhodobého uchování, ti tiše prozradí právě tenhle úpravný držák. Tak se udržuje sucho."},"ICON-0690":{"nm":"Jmenovka na úložný košík","de":"Na každém košíku malá jmenovka. Když je jednou určeno, v kterém oddílu co bydlí, čas strávený hledáním se rovnou promění v čas odpočinku. Uklízení je laskavým vzkazem, který dopředu předáš svému budoucímu já."},"ICON-0691":{"nm":"Mini přepážka na stůl","de":"Malá přepážka, která na stole vmžiku postaví útulnou místnůstku. S touto jedinou deskou vznikne tichý kout mírně odvrácený od světa. Útulné místo jen pro tebe, kam se může usadit soustředění."},"ICON-0692":{"nm":"Stojánek na úložné sáčky","de":"Stojánek, který jemně podepře záda sáčků, co pořád padaly na bok. Stačí, že stojí úhledně v řadě, a vybrat ten pravý je hned mnohem snazší. Postavit věci rovně znamená myslet dopředu na ruku, která přijde příště."},"ICON-0693":{"nm":"Čip na označení prázdného místa","de":"Čip, který úmyslně označí prázdné místo. I ponechat prostor k zaplnění je svým způsobem plán. Prázdné políčko není lenost, ale hrst mezery zdvořile ponechané volné pro něco, co brzy přijde."},"ICON-0694":{"nm":"Krytka na zubní kartáček","de":"Ke kartáčku, který se dotýká úst, si člověk dovolí být důkladnější. Malá čepička, která zabrání i jedinému smítku prachu. Postarat se o čistotu, kterou nikdo nevidí, je tou drobnou péčí, jež otevírá každé svěží ráno."},"ICON-0695":{"nm":"Síťka pod mýdlo","de":"Síťka, která mýdlo jemně nadzvedne, aby se ve vodě nerozmočilo. Zásadu, že když necháš vodu odtéct, mýdlo vydrží déle, tiše dokazuje den co den z toho nejnižšího, nejmenšího místa v koupelně."},"ICON-0696":{"nm":"Klip na šamponovou pumpičku","de":"Jemně přidrží hlavičku pumpičky, aby jedno stisknutí vydalo přesně tolik, kolik je třeba. Zvyk šetrně zacházet je základem hospodárnosti, která vydrží dlouho. Jediný malý klip laskavě hlídá plýtvání."},"ICON-0697":{"nm":"Závěsná krytka na holicí strojek","de":"Ostrým věcem se hodí vlastní domeček. Zastrčíš holicí strojek do krytky a pověsíš, a s ním odteče pryč i vlhkost, i nebezpečí. Umět opatrně zacházet s ostrostí je zároveň umění, jak si vážit sám sebe."},"ICON-0698":{"nm":"Kruh na sprchový ručník","de":"Dlouze protažený ručník vytvoří kruh a doveze tě až tam na záda, kam sám nedosáhneš. Podél jediné čáry, po které klouže pěna, se koupelnou vřele rozlévá laskavé teplo toho, kdo si i sám umyje záda."},"ICON-0699":{"nm":"Sítko do odtoku","de":"Jedna malá síťka, která nechá vodu odtéct a zbytky zadrží. Tiše, na místě, které nikdo nevidí, brání ucpání. Že věci pracující na tom nejnižším místě udržují chod celého domu, ti beze slov připomíná odtok."},"ICON-0700":{"nm":"Přísavný háček na desku","de":"Vytvoří na zdi nové místo, aniž bys musel zatlouct jediný hřebík. Pevně přitiskneš, odlepíš a nezůstane po něm ani stopa. Umění chvíli pobýt a odejít, aniž bys zanechal otisk – přísavka tuhle lehkou zdvořilost dobře zná."},"ICON-0701":{"nm":"Visačka na koupelnové pantofle","de":"Pár úhledně srovnaný před prahem. Péče domova, kde se zouvá obuv, se pečlivě táhne až ke dveřím koupelny. Malé přivítání, které zahřeje studené špičky prstů, tiše vyznačuje visačka."},"ICON-0702":{"nm":"Mini kelímek na vyplachování","de":"Malý kulatý kelímek, který pojme doušek na čištění zubů. V krátké chvíli vyplachování tiše přebírá začátek i konec dne. Není okázalý, ale je po tvém boku každý den – prostota je ta nejtrvalejší podoba domácí péče."},"ICON-0703":{"nm":"Návlek na oprašovač","de":"Návlek nasazený na peří oprašovače, který sbírá prach, jako by ho hladil. Jako pták, který si při odpočinku pečlivě složí křídla, i nástroj, jenž zná své místo k odpočinku, zůstává po tvém boku dlouho."},"ICON-0704":{"nm":"Náhradní role na chloupky","de":"Odloupneš jednu vrstvu a pod ní se objeví čerstvý, hebký povrch. Lepkavé vnitřní listy, které sbírají chmýří a vlásky. V kulaté náhradní roli, jež se po spotřebování znovu doplní, je svinutá ctnost pilného opakování."},"ICON-0705":{"nm":"Svorka na hadr","de":"Svorka, která pevně sevře hadr místo tvé ruky. Udržuje mezi studenou podlahou a prsty odstup na dlaň. Jedna rukojeť, jež na sebe bere špinavou práci, dělá dřinu s úklidem o poznání lehčí."},"ICON-0706":{"nm":"Krytka na kartáček do štěrbin","de":"Malý čepeček, který chrání jemný hrot tenkého kartáčku určeného k pronikání do úzkých škvír. Srdce, jež pečuje i o kouty, kam ruce nedosáhnou. Ten, kdo čistí neviditelná místa, o kousek rozšiřuje náruč domova."},"ICON-0707":{"nm":"Štítek na rozprašovač","de":"Malá visačka jemně přilepená na rameni rozprašovače. Ať je uvnitř čistá voda nebo saponát, jasně to sdělí jediným řádkem. Štítek, který předem odstraňuje zmatek, je dávným zvykem šikovné hospodyně."},"ICON-0708":{"nm":"Páska na doplnění toaletního papíru","de":"Páska, která na prázdné místo nasadí novou roli a pevně ji sváže. Nejjednodušší dotek, jenž znovu spojí to, co bylo přerušeno. Něčí srdce, které doplňuje dřív, než dojde, je kulatě obtočeno kolem této malé smyčky."},"ICON-0709":{"nm":"Háček na úklidové rukavice","de":"Háček, na který se pověsí mokré rukavice hned po skončení práce s vodou, aby uschly. Pracovitým rukám dopřává chvíli odpočinku. Zatímco vlhkost pomalu mizí, je to krátká přestávka, kdy si vydechnou před dalším úkolem."},"ICON-0710":{"nm":"Kolíček na zavěšení koštěte","de":"Zavěsíš-li koště obráceně, štětiny se neohnou a zůstanou rovné. Postoj, který zpříma čeká na další dvorek. Malé, ale spolehlivé místo, jež pomáhá koštěti udržet si tvar i po skončené práci."},"ICON-0711":{"nm":"Klip na pytel na odpadky","de":"Pevně sevře hrdlo pytle a bez jediného úniku ho utěsní. Jedním pohybem, jenž pečlivě stáhne konec, se úklid stane o poznání čistším. Dokončení věci, to nakonec vždy začíná dobrým uzavřením."},"ICON-0712":{"nm":"Nádoba na kolíčky na prádlo","de":"Nádoba, v níž společně žijí kolíčky na prádlo, jež se snadno ztrácejí, když jsou rozházené. Dává drobným věcem společný domov, kde mohou zůstat. Shromáždíš-li ty malé vojáčky svých prstů na jedno místo, najdeš je, kdykoli je potřeba, na první pohled."},"ICON-0713":{"nm":"Kroužek na párování ponožek","de":"Osamělá ponožka vždy někam potichu zmizí. Svážeš-li páry kroužkem ještě před praním, ani po měkkém usušení se ty dvě nerozdělí. Třídění je malý slib, jenž předem brání ztrátě."},"ICON-0714":{"nm":"Sáček na prací kouli","de":"Kutálí se dokolečka uvnitř pračky a poklepáváním probouzí nečistoty vsáklé do oblečení. Rytmus, jímž kulaté tělo hladí prádlo. Uprostřed dravého proudu vody nese v sáčku odedávný pud prádla – poklepávání."},"ICON-0715":{"nm":"Odměrka na vlněný prací prostředek","de":"Jemné oblečení potřebuje jen jemné množství. Odměrka, která přesně na jedno víčko odměří vlněný prací prostředek. V jedné malé rysce se skrývá opatrný dotek při zacházení s vlnou. I ubírání přebytku je projev péče."},"ICON-0716":{"nm":"Záplata na ochranu látky","de":"Malá záplata, jemně přiložená na protřené místo. Srdce prstů, které se o opotřebené místo stará, místo aby ho lehkovážně zahodilo. V každé zašité stopě zůstává jemně otisknutý vzor let strávených s tím kusem oblečení."},"ICON-0717":{"nm":"Kolík na zajištění sušáku","de":"Kolík, jenž tiše přidržuje sušák, aby prádlo neodlétlo ve větru. I ve dnech, kdy se prádlo na slunci vzdouvá, pomáhá mu udržet si místo uprostřed toho kolébání. Úloha jednoho malého, ale spolehlivého závaží."},"ICON-0718":{"nm":"Visačka na síťku na spodní prádlo","de":"Jemné spodní prádlo se pere zvlášť, uvnitř síťky. Síť, jež měkké věci pevně obejme a ochrání před dravým proudem vody. Jeden malý sáček s visačkou připomíná, že opatrné chránění křehkého je také domácí péčí."},"ICON-0719":{"nm":"Háček na odměrku pracího prášku","de":"Pověs odměrku na prací prášek úhledně na zeď. Bez zbytečného trápení, kdy upadne do bubnu a namočí ti ruku. Úpravný zvyk mít stále stejný nástroj na stejném místě je pevně uložen v tomto malém háčku."},"ICON-0720":{"nm":"Zarážka na šňůru na prádlo","de":"Pevně sevře konec šňůry na prádlo, takže i naložená těžkým prádlem se nerozváže. Poslední uzel, jenž vydrží až do konce a nedovolí napjaté šňůře prověsit se. Na tomhle záleží pevné dokončení."},"ICON-0721":{"nm":"Štítek na povlak na polštář","de":"Místo, kterého se noc co noc jako první dotkne tvář, s cedulkou velikosti nehtu všité dovnitř. Kdo kdy přečte drobounké písmo s teplotou praní? Přesto je to ten nejbližší návod ze všech, jenž bdí u spícího obličeje."},"ICON-0722":{"nm":"Svorka na deku","de":"V noci s otevřeným oknem deka neuteče, ani když dovnitř zavane vítr. Protože svorka se zavřenou pusou pevně svírá roh. Mlčenlivá ruka, jež místo spícího drží pevně okraj."},"ICON-0723":{"nm":"Clona na noční lampičku","de":"„Když světlo dosáhne k očím, spánek se vzdálí.“ Díky jedné cloně, kterou kdosi potichu postavil, ustoupí světlo zpět a jen matně zvlhčí nohy postele. Malá přepážka, jež zapůjčí kousek tmy."},"ICON-0724":{"nm":"Kapsa do mezery u postele","de":"Vzpomeň si na tu mezeru mezi matrací a stěnou, kam ruka nikdy nedosáhla. I dálkový ovladač, co spadl, i brýle se teď scházejí právě tady. Kapsa, kterou postel potichu rozevře, aby zachytila věci, o něž jsi málem přišel."},"ICON-0725":{"nm":"Miska na uložení brýlí","de":"Sundáš-li čočky, svět se rozmazaně rozlije do měkka a tu krátkou bezbrannost zachytí mělká miska. Ráno, i bez tápání prsty, brýle vždy čekají na stejném místě."},"ICON-0726":{"nm":"Podstavec na budík","de":"Šest ráno, na pevném podstavci se ozve nejnenáviděnější zvuk. Beze stopy chvění drží hodiny a nakonec tím otevírá něčí den. Mlčky nese na svých bedrech tvrdošíjný slib probuzení."},"ICON-0727":{"nm":"Držák nabíjecího kabelu u postele","de":"Nabíjecí kabel, jenž dřív sklouzával přes čelo postele, už nepadá na zem. Protože malý držák tiše svírá konec šňůry. Na dosah ruky – dotek, který uspořádal noční trasu."},"ICON-0728":{"nm":"Páska na sbalené pyžamo","de":"Páska, která jednou obtočí úhledně složené pyžamo a sváže je. I měkkost, jež se snadno pomačká, potřebuje upravenost. Pro zítřejší noční sebe si dnešní já úhledně smotá pyžamo – malá příprava."},"ICON-0729":{"nm":"Držák na voňavou kartičku","de":"Postavíš-li vonící kartičku šikmo, jako bys otáčel stránkou, otáčíš nosem roční období. Od levandule po citrus – stává se z toho voňavý deník toho dne."},"ICON-0730":{"nm":"Podložka do misky na klíče","de":"Kout u vchodu, kde dřív klíče cinkavě padaly. Miska vyložená měkkou podložkou pohltí ten ostrý zvuk. Malá podložka tiše přijme první pohyb toho, kdo se právě vrátil domů."},"ICON-0731":{"nm":"Kryt na odkapávání deštníku","de":"Z konce deštníku, který jsi přinesl dovnitř, kape déšť. Jeden kryt ty kapky úhledně zachytí, takže někdo tím dopředu domyslel a zabránil malé louži, jež by se jinak potichu rozlila po podlaze."},"ICON-0732":{"nm":"Háček na roušku","de":"Čip velikosti nehtu přilepený na zeď vedle dveří. Jako poslední rituál před odchodem se sem zavěsí rouška. Malé zapamatovávací zařízení, které u dveří udrží tvou pozornost, aby ses nezapomněl vybavit."},"ICON-0733":{"nm":"Kryt na čepel nože na balíky","de":"Ochranný kryt nasazený na čepel, jež rozřezává krabice s balíky. Tiše zakrývá riziko pořezání skryté za vzrušením z rozbalování. Nenápadná ohleduplnost, jež bezpečně otevírá konec čekání."},"ICON-0734":{"nm":"Podstavec na kartáč na boty","de":"Místo, kam se odloží ještě vlhký kartáč na boty po vykartáčování. I když v sobě drží vlhkost, podklad zůstává suchý. I nástroj, jenž tvoří čistotu, potřebuje místo k odpočinku, připomíná malý podstavec."},"ICON-0735":{"nm":"Nástěnka na vzkazy pro návštěvy","de":"„Na chvíli jsem se stavil/a.“ Krátký řádek zanechaný na nástěnce u vchodu. Malé náměstíčko, kde se lidé, kteří se minuli, sdílejí napříč časem. Na jednom políčku papíru se překrývají pozdrav, prosba a jedno srdíčko."},"ICON-0736":{"nm":"Role těsnění pod dveře","de":"Průvan, jenž prosakoval škvírou pod dveřmi širokou jako prst. Srolovaná zábrana tiše zatarasí tu cestu. Zadrží v pokoji o vrstvu víc tepla, které dosud neviditelně unikalo."},"ICON-0737":{"nm":"Přívěsek na dveřní zarážku","de":"Malý přívěsek, jenž podepře patu dokořán otevřených dveří, aby se znovu nezavřely. Svou vahou pevně drží místo kvůli vanoucímu vzduchu i procházejícím krokům. Vlídná tvrdohlavost, jež udržuje otevřenost."},"ICON-0738":{"nm":"Kryt vypínače u vchodu","de":"Vypínač u vchodu, po němž jsi pozdě v noci tápavě hledal/a. Světélkující kryt tiše ohlásí své místo ve tmě. Malý průvodce, jenž se rozzáří dřív, než se rozsvítí světlo, aby ruka nebloudila."},"ICON-0739":{"nm":"Podložka pod hrnek","de":"Ve chvíli, kdy hrnek postavený na stůl začal klouzat, jedna podložka tiše zachytí jeho patu. Podtácek, jenž klidně hájí své místo a nezanechá jedinou skvrnu, ani když se na něm srazí kapky vody."},"ICON-0740":{"nm":"Klip s vůní do auta","de":"Malý voňavý klip zavěšený v autě. Nesen prouděním z ventilace, jemný vánek pomalu naplní úzký prostor. Vlídná útěcha na sedadle řidiče, jež voní i nudu čekání na červenou."},"ICON-0741":{"nm":"Návlek na bezpečnostní pás","de":"Měkký návlek nasazený na pás, který vede přes rameno. Drsnost, jež se dotýkala šíje, se pomalu vytratí. I popruh určený pro bezpečnost může mít v sobě něhu, praví tento kousek látky velikosti dlaně."},"ICON-0742":{"nm":"Clona na parkovací číslo","de":"Cedulka, jež tiše zakryje číslo označující tvé místo v podzemní garáži, než vyfotíš. Každý má informace, které by raději nezanechal. Jedna vrstva opatrně vymazaná z běžné scény každodennosti."},"ICON-0743":{"nm":"Krytka na zvonek jízdního kola","de":"Cililink. Jasný pozdrav, který kolo pronese na rohu uličky. Krytka nasazená na zvonek uchrání ten zvuk i v dešti. Při jednom malém zacinkání se lidé s úsměvem uhnou o krok stranou."},"ICON-0744":{"nm":"Kroužek na řídítka","de":"Kroužek, jenž měkce obalí pocit řídítek v dlani. I po dlouhém svírání za jízdy ruce neztuhnou. Čím delší cesta, tím víc pohodlí místa úchopu zkracuje tu vzdálenost."},"ICON-0745":{"nm":"Nálepka se jménem na helmu","de":"Nálepka se jménem přilepená dovnitř helmy. Mezi stejně vyhlížejícími přilbami tiše volá: „tohle je moje.“ Nejosobnější značka ze všech, vyrytá na tvrdosti, jež chrání hlavu."},"ICON-0746":{"nm":"Odrazka na kolo","de":"Krytka, jež svou práci začíná teprve, když zapadne slunce. Zachytí procházející světlo a jasně odrazí kolo. Ve tmě posílá světlem malý signál: „tady někdo je.“"},"ICON-0747":{"nm":"Pouzdro na klíče od auta","de":"Klíč od auta, jenž se dřív v kapse odíral o ostatní klíče. Měkké pouzdro pevně obalí jeho povrch. V něm je uloženo přání, aby věc, kterou svíráš každý den, vydržela dlouho bez škrábanců."},"ICON-0748":{"nm":"Přísavná polička","de":"Přísavná polička, jež se lehce přichytí ke zdi bez jediného zatlučeného hřebíku. I na stěně, na níž nechceš zanechat stopu, vznikne jedno úložné políčko. Dovednost zavěsit domácí péči do místnosti, kterou máš jen na chvíli vypůjčenou, aniž by po ní zůstala stopa."},"ICON-0749":{"nm":"Háčková deska bez vrtání","de":"Že se dá něco zavěsit, aniž by se do zdi vrtalo. Háčková deska bez vrtání si potichu vezme na starost lehčí náklad. Přání nepoškodit vypůjčený prostor je půvabně uloženo v jednom malém háčku."},"ICON-0750":{"nm":"Magnetická organizační lišta","de":"Zvuk, jak se kov cvakavě přichytí na místo. Přitáhneš-li magnetem malé nástroje rozházené na všechny strany, chaotický pracovní stůl se srovná do úhledné řady a s ním přijde i malá radost."},"ICON-0751":{"nm":"Úložná tyč do mezery","de":"Vzpomeň si na tu úzkou, zapomenutou škvíru mezi lednicí a stěnou. Tenká tyč tu mezeru naplní užitečností. Skromný nápad, jenž z prostoru pokládaného za neužitečný vytěží úložný prostor."},"ICON-0752":{"nm":"Lepicí podložka","de":"Lepicí podložka, která jednou přilepená bezpečně unese i těžkou věc. Odloupneš ji a překvapivě nezůstane po ní jediná stopa. Tichá, tvrdošíjná síla, jež snáší váhu z místa, které není vidět."},"ICON-0753":{"nm":"Háček přes dveře","de":"Háček, jenž stačí jen lehce zavěsit přes horní hranu dveří. Tašky i ručníky visí přesně na dosah ruky. Věšák vzniklý bez jediného hřebíku přidává stísněnému pokoji o kousek volnosti navíc."},"ICON-0754":{"nm":"Nástěnný klip na kabely","de":"Klip, jenž sesbírá kabely visící po zdi do jedné úhledné linky. Zamotaný chumel za stolem se narovná do čisté trasy. Neviditelné uklizení dokáže odlehčit dokonce i vzduch v místnosti."},"ICON-0755":{"nm":"Podložka pod stojací lampu","de":"Podložka, kterou jemně podložíš pod patu stolní lampy. Nezanechá škrábance na stole a utiší i sebejemnější chvění. I stavění světla začíná pevnou podlahou, jež se netřese."},"ICON-0756":{"nm":"Protiskluzová lepicí deska","de":"Rohožka, jež dosud potichu klouzala pod nohama, se konečně zastaví na svém místě, protože lepicí deska pevně sevře podlahu. Nenápadná bezpečnostní síť, jež tiše odstraní chvíli, kdy jsi málem upadl/a, ještě dřív, než nastane."},"ICON-0757":{"nm":"Krytka na přesný šroubovák","de":"„Tenhle jeden malý šroubek se prostě nepovolí.“ Krytka nasazená na hrot přesného šroubováku chrání čepel. Nejjemnější nástroj prstů, jenž otevírá svět velikosti dlaně uvnitř stroje."},"ICON-0758":{"nm":"Kroužek na imbusové klíče","de":"Kroužek, jenž na jednu smyčku navlékne několik imbusových klíčů. Kov seřazený podle velikosti se rozevře jako vějíř s tichým šustotem. Uspořádaný rytmus ruky, jež jedním pohybem vybere přesně ten jeden, který potřebuje."},"ICON-0759":{"nm":"Přívěsek s mini metrem","de":"Přívěsek připevněný k mini metru, jenž se ti vejde přímo do dlaně. Visí na kroužku na klíče a doprovází tě kamkoli. Malý přítel, jenž na místě změří a zodpoví jakoukoli délku, co tě náhle zaujme."},"ICON-0760":{"nm":"Krabička na třídění šroubků","de":"Třídicí krabička, kde si každý z rozmanitých šroubků najde svou vlastní přihrádku. I drobné součástky, jež se dřív v hromadě přehazovaly, tak získají řád. Ruka, jež se nejdřív naučí uklízet, teprve pak opravovat."},"ICON-0761":{"nm":"Krytka na trysku lepidla","de":"Zavřená netuhnu, otevřená vysychám – žiji přesně mezi tím. S každou kapkou, jež ukápne, se někde právě znovu spojuje něco, co se rozbilo. Jedno malé víčko tiše střeží hranici mezi klidem a tokem."},"ICON-0762":{"nm":"Přívěsek s vodováhou","de":"Poctivost velikosti dlaně, jež se pohupuje na konci svazku klíčů. Vždy je to právě tahle malá bublinka, kdo jako první postřehne nakřivo pověšenou poličku. V kapse nosím kamaráda, jenž mi potichu prozradí, že se svět trochu naklonil."},"ICON-0763":{"nm":"Krytka na hrot pinzety","de":"Čím je věc ostřejší, tím víc potřebuje šat, jenž ji zkrotí. Jemně zakryješ-li hroty, neublíží si ani ruka, ani součástky. První slušnost při zacházení s ostrým je tiše přikrýt jeho hrot – tuto něhu na sebe bere malá krytka."},"ICON-0764":{"nm":"Malá řezací podložka","de":"Podložka, jejíž jizvy se samy zacelí i po tisících přejetích čepelí. Na místo pořezané je znovu položena další práce a znovu se zacelí. Mlčenlivý den podlahy, jež dává sama sebe, aby jiné věci mohly být čistě rozřezány."},"ICON-0765":{"nm":"Sáček na náhradní dílky","de":"Sáček, jenž pevně stiskne své hrdlo, aby jeden šroubek, jedna pružinka navždy nezmizely. Drobnosti, jež zbyly po opravě, tu tiše čekají na svou příští chvíli. Ztrátě vždy zabrání právě takové skromné přihrádky."},"ICON-0766":{"nm":"Klip na sáček se sušenkami","de":"Udržet křupavost otevřeného sáčku znamená nakonec jediné rozhodné stisknutí. Malý slib, že nedá vlhkosti šanci. Zvyk pevně sevřít konec zachraňuje zítřejší svačinu."},"ICON-0767":{"nm":"Kelímek na porci želé","de":"Chceš-li jeden sáček rozdělit mezi víc lidí, musíš ho nejdřív spravedlivě rozdělit. Srdce, jež do každého malého kelímku nabere stejný podíl. Věřím, že sdílení začíná přesně stejným množstvím, aby nikomu nebylo líto."},"ICON-0768":{"nm":"Kousek fólie od čokolády","de":"Stříbro, jež obalovalo sladkost, se pod prsty snadno pomačká. Vyhladíš ho a na okamžik se zaleskne; složíš ho a stane se vzpomínkou. Kousek světla, jenž je nejkrásnější teprve poté, co je vše snědeno – ještě jednou se na něj podívej, než ho zahodíš."},"ICON-0769":{"nm":"Páska se štítkem na svačinu","de":"Co je uvnitř, jak dlouho to vydrží dobré – místo mlčenlivého sáčku to řeknu za něj já. V okamžiku, kdy se nalepí jeden proužek, získá i svačina jméno a slib. Třídění je vlastně ten nejněžnější způsob, jak si pamatovat."},"ICON-0770":{"nm":"Krabička na třídění bonbonů","de":"Kyselé a sladké se nedávají do stejné přihrádky. Práce, jež je předem rozdělí, aby ruka nezaváhala. Když se malé krabičky srovnají do řady, radost z výběru se potichu zdvojnásobí."},"ICON-0771":{"nm":"Ochranný papír na sušenky","de":"Tenký papír vložený mezi sušenky, aby se cestou neotloukly. Čím křehčí věc, tím jemnější doprovod potřebuje. Měkkost někdy chrání líp než tvrdost."},"ICON-0772":{"nm":"Motouz na krabici s koblihami","de":"Jeden uzel svázaný do křížku přebírá odpovědnost za bezpečnou cestu dortu v krabici. Stává se úchytem, pečetí i znamením rozechvělého očekávání. Chvíle, kdy se ten motouz rozváže, je právě něčí narozeniny."},"ICON-0773":{"nm":"Klips na sáček na pečivo","de":"Jednou mě zkroutíš, přeložíš a nasadíš, a měkkost pečiva zůstane zapečetěná až do zítřejšího rána. Malá, umíněná tvrdohlavost bránící přístupu vzduchu. Chránit něco měkkého po dlouhou dobu bývá vždy úkolem něčeho pevného."},"ICON-0774":{"nm":"Visačka na výměnu svačin","de":"Tvůj podíl mně, můj podíl tobě. Pamatuješ na to rozechvění, když jste si vypisovali jména na malé visačky a vyměňovali svačiny? Na papírku připnutém k srdci, jež se dělí, je vždy pečlivě vypsané jméno kamaráda."},"ICON-0775":{"nm":"Zátka na brčko","de":"Když se na chvíli zastavíš mezi doušky, zavřeš mě. Aby se nic nerozlilo, aby to nevychladlo, aby to tiše čekalo na místě. Úkolem malé zátky je střežit otvor pro chvíli, kdy se rty vrátí zpět."},"ICON-0776":{"nm":"Jmenovka na termohrnek","de":"Malý kroužek, jenž mezi řadou stojících termohrnků prozradí: „tenhle je můj.“ Jedna barva a zmatek se tiše rozplyne. Jeden jediný kroužek stačí, aby označení „to je moje“ bylo zcela jasné."},"ICON-0777":{"nm":"Návlek na kelímek","de":"Jedna vrstva vlnité lepenky, jež se nenápadně vsune mezi horký kelímek a dlaň. Ohleduplnost vložená tak, abys se nespálil/a ani neuklouzl/a. Střežit ten prostor mezi znamená dovršit klidný, bezstarostný doušek."},"ICON-0778":{"nm":"Štítek na formu na led","de":"Jsou lidé, kteří si ke každé dávce ledu zapisují datum výroby. S vírou, že i chlad má svůj pořádek. Jeden malý štítek nechává čas v mrazáku plynout poctivě, jeden po druhém."},"ICON-0779":{"nm":"Kleštičky na sáček s čajem","de":"Sleduješ čas louhování a v pravou chvíli sáček vytáhneš. Šikovný cit pro to, kdy zastavit, dřív než čaj zesílí příliš. Hloubku čaje neurčuje ani tak délka louhování, jako spíš okamžik, kdy ho vyndáš."},"ICON-0780":{"nm":"Stojánek na kávový filtr","de":"Mlčky stojí a drží filtr, aby horká voda mohla pomalu prokapávat. Dobře ví, že spěch dělá vůni mělkou. I podepírat trpělivost vyžaduje neochvějný postoj."},"ICON-0781":{"nm":"Popruh na láhev","de":"Popruh, jenž zavěsí láhev na zápěstí nebo rameno, aby s tebou šla dál. Způsob společnosti, díky němuž je pořád nablízku, aniž bys ji musel/a schválně balit. Aby ses na ni nezapomněl/a, někdy je lehké přivázání tím nejněžnějším způsobem."},"ICON-0782":{"nm":"Víčko na otevřenou plechovku","de":"Zakryje otvor rozečtené plechovky a zabrání prachu i úniku bublinek. Malý klobouček, jenž na sebe bere odpovědnost za svěžest až do dalšího doušku. I v tom, že se tiše přikryje něco na chvíli otevřeného, je kus péče."},"ICON-0783":{"nm":"Pouzdro na kupón na nápoje","de":"Desátý šálek zdarma – aby ten slib nezmizel, chová v sobě razítkovou kartičku. Aby se dny plněné políčko po políčku nepomačkaly. V tomto pouzdru se hromadí pilné kroky stálého hosta."},"ICON-0784":{"nm":"Pásek na krabičku na jídlo","de":"Pásek, jenž jednou obtočí krabičku na jídlo, aby se víčko neotevřelo. Malé ujištění, že se šťáva neprolije v tašce. O bezpečnou cestu až do oběda se stará právě tohle jedno pevné otočení."},"ICON-0785":{"nm":"Sada kelímků na přílohy","de":"Dá-li se každé příloze její vlastní místo, chutě se navzájem nesmísí. Kimchi jako kimchi, zelenina jako zelenina, každé zvlášť a zřetelně. Přihrádky, jež tvoří tyto malé kelímky, jsou řádem svačinové krabičky i něhou nad rukou, jež vařila."},"ICON-0786":{"nm":"Pouzdro na hůlky","de":"Malý domov, jenž čistě chová a nosí s sebou hůlky, které sdílely všechna tři jídla dne. Tichý společník, jenž si drží upravenost i uvnitř školní tašky. Právě to srdce, jež si je bere s sebou, nakonec vytváří spořádané jídlo."},"ICON-0787":{"nm":"Štítek na lahvičku s omáčkou","de":"Sójová omáčka, nebo ocet? Dodá jasno lahvičce, s níž jsi dřív míval/a zmatek. V okamžiku, kdy se nalepí jeden řádek, zaváhání prstů zmizí. Tempo rušné kuchyně tiše vytvářejí právě tyhle drobné značky."},"ICON-0788":{"nm":"List na rolování kimbapu","de":"Tenký list mořské řasy, jenž stočí rýži a náplň v jedno tělo. Musí pevně obemknout, aby se při krájení nerozpadlo. Rozechvění výletního rána se vyvalí kulaté právě z této jediné vrstvy."},"ICON-0789":{"nm":"Kelímek na párátka a špejle","de":"Postavíš-li špejle a párátka na jedno místo, ruka v pravou chvíli netápe. Dopřát domov i špičatým věcem. Uklízení je nakonec drobná laskavost pro příští ruku, jež po nich sáhne."},"ICON-0790":{"nm":"Návlek na chladicí vložku","de":"Aby chlad vydržel byť jen o chvíli déle, obalí se chladicí vložka ještě jednou vrstvou. Zároveň brání i tomu, aby se taška zvlhčila kondenzací. O to, aby chlad vydržel až do konce, se vždy stará právě tahle tlustší vrstva."},"ICON-0791":{"nm":"Přepážka do krabičky na jídlo","de":"Malá zídka postavená, aby si rýže a přílohy navzájem nezasahovaly do místa. Klid jedné přihrádky, kam se šťáva nepřelije. Krabička na jídlo rozdělená po přihrádkách v sobě beze zbytku uchovává pečlivé srdce toho, kdo ji připravil."},"ICON-0792":{"nm":"Kartička s pořadím chodů","de":"Nejdřív polévka, nebo rýže? Kartička, jež jemně napovídá dnešní pořadí chodů. Vlídný návod, že jíst v pořadí chutná víc. Tiše ti prozradí, že i jídlo má, podobně jako příběh, svůj tok."},"ICON-0793":{"nm":"Nálepka na odměrku","de":"Malá nálepka vedle rysky přesně ukáže: „až sem.“ Značka, jež jedním rázem srovná množství, s nímž jsi vždycky váhal/a. Přesnost pramení právě z jedné takové malé vodicí čárky."},"ICON-0794":{"nm":"Silikonová úchytka na pokličku","de":"Malá úchytka, jež ti dovolí zvednout horkou pokličku, aniž by sis spálil/a prsty. Tiše ti půjčí odvahu otevřít hrnec, z něhož stoupá pára. Bezpečí vždy pramení z toho, že si předem připravíš místo k úchopu."},"ICON-0795":{"nm":"Mini věšák na kolíček","de":"Malý kolíček, jenž dá místo utěrce i sáčku, věcem, které dřív neměly kam se zavěsit. Neuklizený kousek zdi promění v upravený výjev. Jeden zvyk zavěšovat věci dělá kuchyni o poznání lehčí."},"ICON-0796":{"nm":"Krytka na olejový štětec","de":"Zakryješ-li hrot štětce na olej, prach i ztuhnutí se mu vyhnou. Klobouček, jenž tu jemnost uchová až do příštího vaření. Malá péče o nástroj nakonec dlouho zachovává chuť."},"ICON-0797":{"nm":"Slánka s lžičkou","de":"Malá lžička žijící zabodnutá přímo v solničce. Pokaždé pečlivě nabere přesnost jednoho špetky. Cit pro dochucení je právě tolik srdce, kolik si ho tahle malá lžička pamatuje."},"ICON-0798":{"nm":"Magnetická deska s časovačem","de":"Přilepená na dveřích lednice odpočítává 3 minuty na nudle a měří 30 sekund cvičení. S jedním magnetem zůstává čas, jenž by jinak uplynul, na chvíli před očima. Pilný kroužek, jenž na chvíli přišpendlí k zdi to, co jinak plyne."},"ICON-0799":{"nm":"Návlek na rukojeť hrnce","de":"Vrstva, jež se omotá kolem, abys rozžhavenou rukojeť nechytil/a holou rukou. Malý štít, jenž stojí mezi žárem a dlaní. Bezpečné přenesení vždy začíná právě tímto měkkým obalením."},"ICON-0800":{"nm":"Protiskluzová podložka pod prkénko","de":"Když mě položíš na podlahu, prkénko už se dál neklouže. Kousek gumy, jenž zespodu drží pevně pokaždé, když se krájení zakolísá. Stabilita je práce pevného sevření na místě, které není vidět."},"ICON-0801":{"nm":"Klip na kuchyňskou rukavici","de":"Místo, kde si na chvíli odpočine ruka, jež se bez ustání pohybovala před plamenem. Připni třepotající se rukavici ke zdi a začne krátký oddech až do dalšího jídla. Uklízení je nakonec jen jiné jméno pro něhu."},"ICON-0802":{"nm":"Držák na míchátka do kávy","de":"Vedle pultu místo, kde se tenké tyčinky opírají rameny o sebe, úhledně narovnané. Připravené nakreslit kolečko v něčím ranním šálku, seřazené v řadách jako sbor těsně před tím, než se hlasy spojí."},"ICON-0803":{"nm":"Páska na sadu podtácků","de":"Páska, jež jemně tlumí to tiché ťuknutí sklenice o stůl. Svaž kulaté podtácky dohromady a příprava na přivítání hostů je hotová. Pohostinnost vždy začíná právě na takových nenápadných místech."},"ICON-0804":{"nm":"Štítek na sirup","de":"Jediné jméno na lahvi. Sladké, husté – to jedno krátké slovo dokáže uklidnit uspěchané ráno a udělat je o něco přehlednějším. Štítek je papír, na který se předem zapisuje malý slib."},"ICON-0805":{"nm":"Kelímek na dezertní špejličky","de":"Kelímek, ve kterém spolu žijí špičaté tyčinky určené k propíchnutí kousku ovoce. Než je zabodnou jako praporky na dezertní talíř, čekají zde tiše na svou chvíli. I sladkost má svůj pořádek."},"ICON-0806":{"nm":"Návlek na míchátko","de":"Papírový kabátek, který pevně obejme hrst míchacích tyčinek. Vsákne vlhkost, kterou studený nápoj vypustí, a udrží konečky prstů držící sklenici v suchu. Neviditelná péče vždy přichází z okraje."},"ICON-0807":{"nm":"Visačka na nosič kelímků","de":"Ve chvíli, kdy nestačí dvě ruce, ponese kelímky za tebe malé držadlo. Pevně svírá zabalené teplo, aby nevykápla ani kapka, a doprovodí to teplo až k rohu něčí ulice."},"ICON-0808":{"nm":"Obal na pager z kavárny","de":"Kabátek, který tiše obepíná čekání, než se ozve vibrace. Střeží zářící pořadové číslo v koutě kavárny a v sobě chová i to chvění, že už brzy zazní tvé číslo."},"ICON-0809":{"nm":"Kroužek na razítkové kupóny","de":"Papír, na kterém deset vyplněných políček přinese jeden šálek zdarma. S každým dalším razítkem trochu povyroste i jméno „stálý zákazník“. Skromná radost navlečená na malém kroužku."},"ICON-0810":{"nm":"Vzorkový sáček kávových zrn","de":"Sáček, který v sobě nese hrst zrn a jako první nabídne vůni. Kyselost a sladkost, jež se otřou o nos, tím prvním dojmem rozhodnou o osudu šálku. Vůně dorazí vždy rychleji než jakékoli vysvětlení."},"ICON-0811":{"nm":"Magnetka na štítky do lednice","de":"Malá magnetická jmenovka, která ťukne o dvířka lednice. Zapiš si, co a kdy přibylo, a i skoro zapomenutá příloha si znovu najde své místo v řadě. Domácnost je práce s přidržováním unikající paměti."},"ICON-0812":{"nm":"Kolíček s datem uskladnění","de":"Útržek, který zřetelně vyryje den, kdy bylo něco zabaleno. Malý svědek, jenž ti i po pár dnech tiše potvrdí, že tohle je ještě v pořádku. Čerstvost chrání konečky prstů, které si pamatují datum."},"ICON-0813":{"nm":"Páska na dávkovací dózy","de":"Páska, jež obepne pas rozdělené dózy kolem dokola. Pevně přitiskne kymácející se víčko a udrží malý pořádek uvnitř lednice. Svazovat něco dohromady se podobá uklízení v srdci."},"ICON-0814":{"nm":"Barevné klipy na sáčky","de":"Barevné klipy, které pevně skousnou hrdlo sáčku. Červená znamená pálivé, žlutá sladké – ruka to pozná už podle barvy. Kuchyňský semafor takhle beze slova ukazuje cestu."},"ICON-0815":{"nm":"Jmenovka na mraženou potravinu","de":"Jmenovka jemně položená na něco zamraženého. Utěší sáček pokrytý jinovatkou, aby nezapomněl, čím kdysi byl. Malé pozdravné psaníčko poslané ingrediencím, jež upadly do zimního spánku."},"ICON-0816":{"nm":"Síťka na skladování zeleniny","de":"Řídká síťka, jež velkoryse obejme zeleninu ještě s hlínou. Babiččina kuchyně dávno věděla, že jen ta, které se dopřeje prostor k dýchání, vydrží déle. Provětrání je něžný okraj darovaný zelenině."},"ICON-0817":{"nm":"Třídicí uzávěr na víčka","de":"Třídicí uzávěr, jenž po jednom spáruje víčka podle velikosti. Najít ztracený pár je něžnější práce, než by se zdálo. Když se sejde vhodná dvojice, i kuchyně se hned zdá uspořádanější."},"ICON-0818":{"nm":"Štítek na krabičku vajec","de":"Značka úhledně přiřazená ke každému z deseti malých hnízd. Domácí moudrost, jež radí spotřebovat nejdřív ta starší vejce. I v jediné ranní míchanici je ukrytá péče o pořadí."},"ICON-0819":{"nm":"Nálepka na zbytky jídla","de":"Napiš „tohle je moje!“, nalep to a i lednice na chvíli pozná klid. Roztomilé vyhlášení války, kterým se předem určí majitel nočního jídla. Rodina se i dnes točí na těchto drobných dohodách."},"ICON-0820":{"nm":"Podložka na příbor","de":"Malý kousek, jenž jemně nadzvedne lžíci a hůlky, aby se nedotýkaly přímo stolu. Tahle drobná úhlednost potichu pozvedne úroveň jídla. Stolování se takhle nenápadně učí slušnosti."},"ICON-0821":{"nm":"Kroužek na ubrousky","de":"Kroužek, jenž tiše zasune a přidrží ubrousek, který by se jinak rozlétl ve větru. Sesbírá bílý papír čekající na svou chvíli k rozevření a úhledně vtiskne stolu malý řád."},"ICON-0822":{"nm":"Rožek na prostírání","de":"Kousek, jenž jemně přitiskne a uklidní nadzvednutý roh prostírání. Stůl každý den učí, že teprve když je jeden konec pevně držen, celek konečně leží rovně. I roh nese svůj díl odpovědnosti."},"ICON-0823":{"nm":"Malý tácek na koření","de":"Malý tácek, jenž vedle sebe podává misku sójové omáčky a špetku soli. Široká náruč stolu, který dá místo i té nejmenší příloze. Korejská kuchyně sílí právě v srdci, jež nezapomíná na drobnosti."},"ICON-0824":{"nm":"Číslo na stůl","de":"To číslo, které v rušné restauraci zavolají: „Host u čísla tolik a tolik!“ Přiřadí čekání pořadí a všem tak zachová spravedlnost. V jednom kolečku se skrývá malý slib a teplý talíř, jenž brzy dorazí."},"ICON-0825":{"nm":"Páska na označení sklenice","de":"Páska omotaná kolem sklenice s vodou, aby nenápadně prozradila, čí je. Malý praporek, jenž mezi podobnými sklenicemi vyznačí tvé místo. Za společným stolem taková ohleduplnost předchází zbytečným záměnám."},"ICON-0826":{"nm":"Kolíček na talíře k nabírání","de":"Kolíček, jenž barvou roztřídí talířky, ze kterých si nabíráš. Laskavě vede hranici mezi tvým a mým a radost ze sdíleného jídla tím udělá čistší. Vřelost se sdílí, ale hygiena se přitom pečlivě hlídá."},"ICON-0827":{"nm":"Zástěna na jídelní lístek","de":"Čas rozvažování, skrytý za rozevřeným jídelním lístkem. I to krátké váhání nad tím, co si dát, je ve skutečnosti součástí jídla. Co si dnes dát – tu chvíli chvění tiše zastíní."},"ICON-0828":{"nm":"Stojánek na jmenovku","de":"Malý stojánek, jenž vzpřímeně drží jmenovku. Ať na svatbě, či na hostině, jasně oznámí, že tady je tvé místo. Pohostinnost se naplní teprve v tu chvíli, kdy je vysloveno jméno."},"ICON-0829":{"nm":"Návlek na muffin","de":"Papírový kabátek, jenž pevně obejme baculatý pas čerstvě upečeného muffinu. Podpírá teplé tělo, aby nevyklouzlo z ruky, a chrání teplo až do samotného okamžiku prvního kousnutí. I dezert potřebuje kabátek."},"ICON-0830":{"nm":"Uzávěr na zdobicí sáček","de":"Zátka, jež pevně sevře hrot sáčku na vytlačování krému. Během pauzy pečlivě uzavře ústí, aby neuniklo jediná kapka. Malý kvítek na dortu vykvete právě z této zdrženlivosti."},"ICON-0831":{"nm":"Kroužek na vykrajovátka","de":"Kulatá sada formiček, jež vykrajují těsto do tvaru hvězd a medvídků. Stejná mouka se skrze konečky prstů probouzí do desítek podob. Ať pečeš cokoli, těsta se vždy jako první dotkne péče."},"ICON-0832":{"nm":"Přívěsek na škrabku na těsto","de":"Plochá ruka, jež šetrně sesbírá těsto a čistě je rozdělí. Ta píle, s níž ošetří i hrst přilepenou na míse, rozhoduje o objemu bochníku. Pečení je práce šetrné ruky."},"ICON-0833":{"nm":"Deska na odměrky","de":"Deska, jež úhledně a bez zakolísání ukládá odměrky – jednu malou lžičku, půl velké. Jedna přesná lžíce narovná rovnováhu chuti. Za slovy „ruka to umí“ se ve skutečnosti skrývá pečlivé odměřování."},"ICON-0834":{"nm":"Háček na chňapku","de":"Háček, na který se pověsí rukavice, jež stála na stráži před horkou troubou. Tlustá dlaň, jež bránila popáleninám, zůstává na dosah i v době odpočinku. Bezpečí vždy začíná tím, co má své pevné místo."},"ICON-0835":{"nm":"Klip na chladicí mřížku","de":"Kleštičky, jež úhledně přidrží mřížku, na které chladne čerstvě upečené pečivo. Udrží ho na místě, dokud unikne pára, a spolu s ním čekají, až se dovrší křupavost. I chladnutí potřebuje trochu trpělivosti."},"ICON-0836":{"nm":"Zápich na dort","de":"Zápich, jenž na dort jemně zabodne pět slov „Všechno nejlepší k narozeninám“. Těsně předtím, než zhasnou svíčky, tento malý praporek rozzáří něčí den nejjasněji. Oslava se ukáže nejlépe, když je vztyčená vysoko."},"ICON-0837":{"nm":"Dávkovač moučkového cukru","de":"Dávkovač, jenž v sobě chová poslední lehké posypání. Usadí se jako bílý sníh na čerstvě upečeném dezertu a promění obyčejný kousek v malý dárek. Poslední dotek přichází vždy z té nejlehčí ruky."},"ICON-0838":{"nm":"Etiketa na trojúhelníkový kimbap","de":"Sloupni obal v pořadí 1, 2, 3 a mořská řasa na trojúhelníku znovu ožije křupavá. Jeden řádek, díky němuž na první pohled poznáš spolehlivého přítele z nočního obchodu za rohu. Hladové noci po pozdním doučování tu zůstávají přilepené."},"ICON-0839":{"nm":"Přidržovač víčka na instantní nudle","de":"Podpěra, jež po tři minuty čekání tiše přidržuje víčko, aby se neodklopilo. Nahrazuje místo hůlek, které se dřív pokládaly navrch, aby neunikla pára. Ta krátká chvíle, kdy se nudle vaří, je nejvíce vzrušující okamžik nočního jídla."},"ICON-0840":{"nm":"Krytka na špejli","de":"Malá krytka, jež pevně sevře konec špejle. Chrání ji, aby se do ní dobře kousalo a na ruce nezůstala ani kapka omáčky. Radost ze svačiny před obchodem s pouličním jídlem se vždy dovršuje právě takovými drobnostmi."},"ICON-0841":{"nm":"Držadlo na igelitovou tašku","de":"Zavěsíš ho na prsty a igelit tiše zaskřípe. Váha nákupu se nakloní na jednu stranu a cesta domů zanechá na dlani červenou stopu. V tom lehkém zvuku se houpe těžká tíha jedné domácnosti pro celý den."},"ICON-0842":{"nm":"Klip na složenou účtenku","de":"Přelož dlouhou rozvinutou účtenku napůl, cvakni klipem, a dnešní útrata se stane úhledným svazkem. Zatímco se papír provoněný inkoustem hromadí vrstvu po vrstvě, i drobné vzpomínky na domácnost se řadí do pořádku."},"ICON-0843":{"nm":"Visačka na mikrovlnku","de":"Než se ozve pípnutí, visačka tiše odpočítává čas ohřevu. Malá cedulka s minutami, sekundami a názvem toho, co se má ohřát. I srdce, jež čeká, až na něj přijde řada zahřát se, má takové rysky."},"ICON-0844":{"nm":"Role slevových nálepek","de":"Pokaždé, když odlepíš další políčko, zašimrá konečky prstů lepkavé zapraskání. Když se v řadě rozvinou červené číslice, něčí nákupní košík se o něco odlehčí. Kotouček malé laskavosti, stočený a čekající."},"ICON-0845":{"nm":"Kroužek na omáčkový sáček","de":"Něco nakyslého tiše vytryskne u koutku úst a obyčejný den se trochu osladí. Když se sáček zavěšený na kulatém kroužku houpe při každém kroku, jedna drobná sladkost mě celý den provází v kapse."},"ICON-0846":{"nm":"Košík z večerky","de":"Uchopíš ho a plast se lehce prohne. Osvětlený obchod pozdě v noci, hloubka tak akorát na pár trojúhelníkových kimbapů a jeden nápoj. Vlídná nádoba přesně na jedno jídlo, u které nejsi osamělý ani sám."},"ICON-0847":{"nm":"Páska na krabičku makronek","de":"Jediná páska jemně obejme krabičku, aby se pestrobarevné makronky nerozsypaly. Kdo už dostal dárek, ví konečky prstů, že to chvění těsně před rozvázáním stuhy je vlastně nejsladší ze všeho."},"ICON-0848":{"nm":"Klip na síťku na ovoce","de":"Sevřeš hrdlo síťky a jemně stiskneš – a vůně jablek se tiše prodere pletivem. Jedna malá ruka, jež je drží, aby se nevykutálela ven. Tichá, laskavá výzva sníst je brzy, než změknou."},"ICON-0849":{"nm":"Látka na víčko sklenice s džemem","de":"Připomíná letní kuchyň mé babičky, jak přikrývala víčka sklenic kulatým kouskem látky a svazovala je gumičkou. V jednom kostkovaném hadříku se spolu zapečetí sladký čas zrání džemu a vložená péče. Takhle se ruční um uchovává, přikrytý."},"ICON-0850":{"nm":"Stužka na sáček se sušenkami","de":"Vlož čerstvě upečené sušenky do celofánu a stočením stužky je zavaž – vůně másla pronikne až ke konečkům stuhy. Ruka, jež podává něco vlastnoručně vyrobeného, se vždy trochu chvěje. Uzel, jenž s sebou sváže i kus srdce."},"ICON-0851":{"nm":"Přepážková vložka na čokoládu","de":"Políčko po políčku určuje místo, aby se čokolády navzájem nedotýkaly. Aby se nerozpustily, aby se nerozdrolily. To, co malá přepážka chrání až do konce, je nakonec celistvé srdce jednoho kousku, jenž má být komusi podán."},"ICON-0852":{"nm":"Dárková etiketa na čaj","de":"Na štítku obtočeném kolem sáčku čaje jméno úhledně napsané rukou. Malý papírek předem prozradí, že po zalití spolu s párou stoupá i vůně bylin. Šálek, u kterého se ruce zahřejí ještě dřív, než se stihne napít."},"ICON-0853":{"nm":"Náhrdelník s lahvičkou bonbónů","de":"Náhrdelník vytvořený omotáním šňůrky kolem hrdla lahvičky plné barevných bonbónů. Při každém kroku se uvnitř kutálí zvuk jako malé kuličky. Hrdý poklad dětství, se sladkostí zavěšenou kolem krku."},"ICON-0854":{"nm":"Přívěsek na dárkovou lžičku","de":"Jediný malý přívěsek na konci držadla stačí a obyčejná lžička se nečekaně stane dárkem. Při každém nabrání zacinká lehký, čistý zvonek. Drobná ozdoba, jež darovanému srdci přidá trochu půvabu."},"ICON-0855":{"nm":"Poděkovací visačka k svačině","de":"Touha vrátit alespoň trochu z toho, co jsme dostali. List poděkovací visačky jemně přivázaný k sáčku se svačinou. Místo nedořečeného „děkuji“ tiše přechází malý pozdrav z ruky do ruky."},"ICON-0856":{"nm":"Kroužek se vzorky maskovací pásky","de":"Vzorky odstřižené a nalepené po pídích se řadí v malém pásu. Zatímco konečky prstů pomalu vybírají, jaká barva se hodí, den se zbarví do všech odstínů už jen z pouhé myšlenky na zdobení. Řádka vzorků, u které je radost i to váhání."},"ICON-0857":{"nm":"Krytka na pinzetu na nálepky","de":"Nasadíš krytku na špičku pinzety a i nálepka velká jako nehet zůstane nedotčená. Přesná ruka, jež jemně zvedne rohy, na které prsty nikdy nedosáhnou. S věcmi, které máme rádi, vždy zacházíme obezřetně."},"ICON-0858":{"nm":"Rohová nálepka do diáře","de":"Nalep nálepky do čtyř rohů diáře a třepotající se stránky se jako kouzlem uklidní. Pocit lehkého přitisknutí papíru, malý obřad, jenž pěkně zapečetí dnešní den. Zápis nabývá pevnosti právě od rohů."},"ICON-0859":{"nm":"Naváděcí destička na děrovačku","de":"Destička, jež předem naznačí, kde udělat díru. Zarovnej ji tiše podle tečkované čáry a nedojde k žádné odchylce. Srdce, jež se bez spěchu ještě jednou přesvědčí, přesnost vždy přichází tiše z toho jednoho okamžiku klidu navíc."},"ICON-0860":{"nm":"Tácek na papírové odstřižky","de":"Papírové drobky zbylé po stříhání se šustivě snášejí do tácku. Krátký příbytek pro malé útržky, aby se stůl nezanesl nepořádkem. Konec tvoření se takhle bez hluku uklidí."},"ICON-0861":{"nm":"Barevný razítkovací polštářek","de":"Lehce stiskneš polštářek a zvedneš – na konečcích prstů se vlhce rozlije barva. Červená, žlutá, modrá – malá duha, jež ulpí na jediném razítku. Měkké políčko, kam se ťuk ťuk vysazuje barva na bílý papír."},"ICON-0862":{"nm":"Role dekorativní pásky","de":"Vzor, jenž se s tichým šustěním odvíjí, pokračuje bez konce. Odlep jeden díl, přilep ho a na dřív fádním místě rozkvetou květiny. Kotouček malé magie, stočený a čekající, jenž krásní s každým pohybem ruky."},"ICON-0863":{"nm":"Krytka na tematické razítko","de":"Malá čepička, jež pevně obalí hlavu razítka, aby inkoust nezaschl. Tiše hlídá, aby příští otisk zůstal ostrý. Barva dobře uchovaná rozkvete stejně živě i na dalším listu papíru."},"ICON-0864":{"nm":"Odstřižky z dekorativní děrovačky","de":"Malé kousky, jež děrovačka s cvaknutím upustí. Konfety z barevného papíru vystřižené do hvězd, srdíček a lístků se v jemné hromádce sesbírají na dlani. Malé drahokamy, příliš krásné na vyhození, takže je nakonec někam zase nalepíš."},"ICON-0865":{"nm":"Kroužek se štítky na cívky","de":"Malý štítek se jménem barevné nitě napsaným na každé cívce. Laskavá značka, jež ukáže své místo dřív, než se zamotá. Zapletená nit i zapletené srdce se s jedinou jmenovkou rozmotávají mnohem snáz."},"ICON-0866":{"nm":"Obal na jehelníček","de":"Měkký obal na plstěnou knížku, do níž jsou nahusto zapíchané jehly. Otevřeš ji a šicí potřeby úhledně leží v řadě a vítají mě. Malý svazek, jenž láskyplně uspává ostré věci, aby se konečky prstů neporanily."},"ICON-0867":{"nm":"Kroužek se vzorky látek","de":"Hrubá či hebká – pomalý čas, kdy konečky prstů jeden po druhém ohmatávají vzor tkaniny a vybírají. Mezi kousky látek úhledně srovnanými podle barvy tkanina, než se stane oděvem, nejprve tiše čeká, až se jí někdo dotkne."},"ICON-0868":{"nm":"Vyšívací kruh","de":"Vlož látku do kulatého kruhu a utáhni – napne se jako blána bubnu. Malý signál, že je vše připraveno k vyšívání steh po stehu. Kruh pevně nedrží látku, ale soustředěné srdce."},"ICON-0869":{"nm":"Kapsle na třídění knoflíků","de":"Knoflíky, jež se dřív povalovaly a kutálely, se teď spořádaně usadí podle barvy v každé přihrádce kapsle. Domácí moudrost rozdělovat je po malých dávkách, aby se žádný neztratil. I sbírání roztroušených věcí vyžaduje takovou péči."},"ICON-0870":{"nm":"Držák na krejčovskou křídu","de":"Držák, jenž pohodlně uchopí křídu, kterou se kreslí čáry na látku. Pevně podepře něco, co se snadno láme. První čára musí být rovná, aby byl rovný i oděv – klidná první myšlenka, než se vezmou do ruky nůžky."},"ICON-0871":{"nm":"Sklenička na špendlíky","de":"Uvnitř průhledné sklenice o sebe cinkají a chrastí špendlíky. Nastav ji proti slunci a na hrotu každé jehly se zaleskne malé světýlko. Úhledná nádoba, jež na jedno místo sesbírá a jemně uspí věci, které by roztroušené byly nebezpečné."},"ICON-0872":{"nm":"Role záplatovací pásky","de":"Kouzelný pruh, jenž se po přežehlení na potrhaném místě tiše přilepí. Bez jediného stehu se ošuntělý oděv potichu zahojí. Srdce, jež raději spravovalo a nosilo dál, než aby vyhazovalo, je stočené vrstvu po vrstvě v kulaté roli."},"ICON-0873":{"nm":"Šablonový papír na nášivky","de":"List šablonového papíru s předem nakresleným tvarem nášivky. Tečkovaná čára laskavě vede cestu, kudy povedou nůžky. Nejdřív nakreslit obrys toho, co chceš vytvořit – vzrušení vždy začíná od té slabé podkresby."},"ICON-0874":{"nm":"Uzávěr na kelímek na vodu","de":"Nasaď ho na hrdlo kelímku a ať se barevná voda houpe jak chce, nevyteče ani kapka. Zakryje i tu starost, že by se kalná voda z vypláchnutého štětce rozlila po stole. Tichá zátka, jež mlčky střeží místo, kde se maluje."},"ICON-0875":{"nm":"Ochranná páska na pastelku","de":"Omotej pásku kolem pastelky, ze které se práší barevný prach, a prsty se zašpiní méně. Papír, jenž jemně obaluje jemnou barvu, aby se nedrolila. Čím měkčí je, tím jemněji ji musíš držet, aby jemně vybarvila i papír."},"ICON-0876":{"nm":"Nástavec na pastelku","de":"Nasaď nástavec na ohryzaný konec pastelky a jeden krátký kousek zase povyroste. Srdce, jež něco nezahodí jen proto, že se to zkrátilo. Z konečků prstů, jež ji používají až do konce, se barva kresby dovrší sytější až do posledního políčka."},"ICON-0877":{"nm":"Háček na kelímek na štětce","de":"Zavěs kelímek na oplachování na háček a kapky vody stékající ze štětce tiše skanou dolů. Než se nanese další barva, krátké a čisté ticho oplachování štětce. I v tom zvuku očišťování plyne tichý rytmus."},"ICON-0878":{"nm":"Krytka na paletový nůž","de":"Malá krytka, jež pevně zakryje čepel nože, kterým se rozetírá a seškrabuje barva. Tiše chrání ostrý hrot, aby neztupl. Struktura silně nanesené barvy se rodí právě z pečlivě opatrovaného ostří."},"ICON-0879":{"nm":"Klip na plátno","de":"Pevná svorka, jež silou napne plátno na rám a pevně je přidrží. Skousne ho pevně a malovací plocha se napne jako buben. Jen s neochvějným podkladem může tah štětce nad ním volně a svobodně běžet."},"ICON-0880":{"nm":"Popruh na kreslicí desku","de":"Přehodíš popruh přes rameno a deska tě následuje za zády. Posadíš se kdekoli a to místo se stane tvým vlastním ateliérem. Malý ateliér nošený na zádech, jenž se lehce vydává hledat scenérii, kterou by chtěl nakreslit."},"ICON-0881":{"nm":"Tuba akrylové barvy","de":"Přidej jednu kapku vody navíc a je z toho svítání, o kapku míň a je půlnoc. Stejná modrá pokaždé na konečcích prstů otevře jinou oblohu. Ve chvíli, kdy vytlačíš barvu z tuby, se dnešní barva srdce rozlévá po papíře."},"ICON-0882":{"nm":"Ukázkový list přechodu barev","de":"Že se soumrak nezčervená naráz, to věděl tento papír jako první. Malé schůdky přecházející od světlého k tmavému. Oko po nich pomalu kráčí a tiše sleduje čas, v němž barva dozrává."},"ICON-0883":{"nm":"Krytka na háček na háčkování","de":"Náprstku podobný malý štítek, který si nasadíš dřív, než se ti nit zaryje do prstu. Ví to ruka, jež už dlouho háčkuje. Jen když zůstane nezraněná, dokáže bezpečně dovést práci až k poslední oku."},"ICON-0884":{"nm":"Kroužkový značkovač na pletení","de":"Jediná značka, a hned je znovu jasné, kam ses dostal. Uklidnění z toho, že nemusíš stejné oko počítat dvakrát. I srdce teprve tehdy nebloudí, když si jemně vyznačí místo, kterým prošlo."},"ICON-0885":{"nm":"Přívěsek na počítání řad","de":"Tichý důkaz dokončené řady se hromadí políčko po políčku. I práce, jež se zdála nekonečná, když se počítá jedna po druhé, je najednou za polovinou. Malý počet udrží dnešní srdce vytrvalé až do konce."},"ICON-0886":{"nm":"Kolíček na uspořádání konečků nitě","de":"Necháš-li rozvázaný konec nitě jen tak, nikdy nevíš, kde se zamotá další uzel. Ruka, jež předem uklidí místo, které nikdo neuvidí. Něha se zpravidla hýbe právě takhle nejdřív, na místech, jež nejsou vidět."},"ICON-0887":{"nm":"Šňůra na nácvik uzlů","de":"Jednoduchý uzel, mašlový uzel, prstenový uzel. Stejnou šňůru vážeš a zase rozvazuješ, dokud si to ruka nezapamatuje. Když se nešikovné konečky prstů jedné noci znenadání stanou hbitými, ta jediná šňůra to pozná jako první."},"ICON-0888":{"nm":"Páska se štítkem na přízi","de":"Malý pruh, na který se ke každému klubku zapíše jeho tloušťka a barva. Je to zvyk zrozený z nocí strávených marným hledáním stejné příze, když už došla. Zápis je něžný vzkaz budoucímu já."},"ICON-0889":{"nm":"Vzorník na měření napětí pleteniny","de":"Kolik ok se vejde do 10 centimetrů – to malé číslo určuje velikost celého oděvu. Že kousek velký jako dlaň drží v rukou míru celku, je, když si ho zvedneš, docela závažná věc."},"ICON-0890":{"nm":"Značkovač na knoflíkové dírky","de":"Než se přišije knoflík, nejdřív se tečkou vyznačí, kde se má udělat dírka. Díky té brzy zmizející značce nebude náprsenka nakřivo. Píle zpravidla nakonec tiše zůstává na místě, jež není vidět."},"ICON-0891":{"nm":"Kroužek s malým střapcem","de":"Jako střapec na konci norigae, i malý kroužek vytváří chvění. Na tom, co visí a tiše se vlní, vždy spočine lidský pohled. Vlákno, jež tiše ožívá pokaždé, když jím projde vítr."},"ICON-0892":{"nm":"Mini lahvička barvy","de":"S barvou se správně nezachází tak, že se šetří, ale tak, že se používá přesně. Barva, u níž stačí jedna kapka, odhadovaná rukou položenou vedle malé lahvičky. Zdrženlivost pramení z toho, že se jednou odloží chtivost."},"ICON-0893":{"nm":"Malá brusná tyčinka","de":"Začíná se na hrubé straně a postupně se přechází k jemné. Nikde neexistuje povrch, který by zhladl na jeden zátah. Z konečků prstů, jež snižují zrnitost krok po kroku, dřív drsné místo pomalu měkne."},"ICON-0894":{"nm":"Stojánek na svorky na modely","de":"Držíš-li slepený díl v ruce, zůstanou na něm otisky prstů. Sevři ho jemně do svorky a ruce se osvobodí, sušení pak samo v tichosti doběhne do konce. I čekání se odlehčí, když ho někdo za tebe podepře."},"ICON-0895":{"nm":"Podložka na lepení","de":"Když na stůl kápne kapka lepidla, stopa zůstane dlouho. Zvyk položit si nejdřív jednu podložku. Polovina práce možná začíná právě z toho přání neušpinit místo."},"ICON-0896":{"nm":"Přihrádky na třídění dílků","de":"Smíchá-li se pár desítek stejně tvarovaných dílků, sestavení se rychle promění v labyrint. Dotek, jenž je rozdělí do jednotlivých přihrádek, předem zkrátí čas, který bys jinak strávil bloudit. Uklízení je laskavost darovaná budoucímu já."},"ICON-0897":{"nm":"Kolíček s pořadím sestavení","de":"Malý kolíček s poznámkou, který díl nasadit jako první. Dodrž pořadí a nic se snadno nerozpadne. Model, stejně jako jakýkoli den budovaný krok za krokem, sílí právě na tomto tichém slibu."},"ICON-0898":{"nm":"Mini háček na štětce","de":"Položíš-li použitý štětec naplocho, štětiny se stlačí a ohnou. Místo, kam ho zavěsit vzhůru nohama, aby z něj odkapala vlhkost. Kdo si dlouho drží nástroje nablízku, je po skončení práce spíš ještě zaměstnanější a pečlivější."},"ICON-0899":{"nm":"Nádoba na plastové odstřižky","de":"Nádoba, do níž se tiše sbírají zbytky odříznuté z rámečku. Vypadají zahozeně, přesto se jednou vrátí jako malý detail. Nádoba mlčky ví a čeká, že i to, co zbylo, má svou chvíli."},"ICON-0900":{"nm":"Krytka na dokončovací sprej","de":"Poslední vrstva, nastříkaná zblízka, jen steče dolů. Z odstupu na dlaň, lehce, lehce. Nanášení lesku je možná i cvičením v tom, jednou odložit chtivost srdce."},"ICON-0901":{"nm":"Pouzdro na tuhy do mikrotužky","de":"Tenká tuha do mikrotužky se v kapse tak snadno zlomí. Uložená úhledně v malé tubě nepřijde nazmar ani jediná tyčinka. Uklízet znamená nakonec tiše pečovat předem o zítřejší já."},"ICON-0902":{"nm":"Návlek na gumu","de":"Malý papírový kabátek navlečený na gumu. Čím víc černá od doteků rukou, tím víc stop oprav se na ní nahromadilo. Mazat znamená také něžné svolení začít znovu od začátku."},"ICON-0903":{"nm":"Pouzdro na hroty per","de":"Hroty per praskají, když vyschnou, a ohýbají se při nárazu. Jedna malá tuba, do níž je uložíte zvlášť, dlouho chrání strukturu vašeho písma. S nástrojem, s nímž zacházíte jemně, se nakonec jemně klouže jako odměna."},"ICON-0904":{"nm":"Vzorek inkoustu do plnicího pera","de":"Inkousty, které zkoušíte kapku po kapce. Barva, o níž jste si mysleli, že je tyrkysová, se na papíře promění v hluboké moře. Barvu je vždy třeba poznat osobně - odstín, který si představíme v mysli, se tak často mine s realitou."},"ICON-0905":{"nm":"Plechovka na knižní záložky","de":"Malá vlaječka jemně vsunutá do místa, kde jste přestali číst. Když knihu příště otevřete, včerejší já vám kyne a čeká. I místo, kde jste se zastavili, se stává slibem - něžným dílem té drobné značky."},"ICON-0906":{"nm":"Balíček praporkových záložek","de":"Odlepíte jeden lístek, přilepíte ho a příběh se odtamtud znovu rozbíhá. Když se malé praporky seřadí podél okraje knihy, roztroušené myšlenky se úhledně spojí do jediné mapy."},"ICON-0907":{"nm":"Magnet na sbírání sponek","de":"Malý magnet, který jedním tahem posbírá roztroušené sponky. Čím menší věc, tím snáz se ztratí, a tak jedna sbírající síla tiše zachrání neuklizený stůl. I v přitahování je jistá něha."},"ICON-0908":{"nm":"Sada krytek na tužky","de":"Malé čepičky, které obepínají hroty tužek a chrání vnitřek tašky. Cokoli ostrého nakonec vždy do něčeho píchne, a tak potřebuje ruku, jež ho tiše zakryje. Aby zůstalo ostré, ale nikoho neporanilo."},"ICON-0909":{"nm":"Samolepka se jmenovkou na stůl","de":"Ve chvíli, kdy napíšete své jméno a nalepíte ho na stůl, se to místo konečně stane něčím vlastním. Když i prostor velký jako dlaň dostane majitele, změní se úplně i způsob, jak v něm usedáte se srdcem."},"ICON-0910":{"nm":"Krytka na rukojeť švihadla","de":"Krytka nasazená dřív, než se konce rukojeti odřou a rozštípnou. Rytmus lana protočeného tisíckrát si dlaň zapamatuje dřív než hlava. Takt vrytý do těla se jen tak lehce nezapomíná."},"ICON-0911":{"nm":"Jógový popruh s kruhem","de":"Uchopíte kruh a pomalu otevíráte tělo. Čím víc se popruh napíná, tím víc se ztuhlá ramena po vrstvách uvolňují. Protahovat neznamená násilně táhnout, ale spíš trpělivě čekat, dokud se tělo samo neotevře."},"ICON-0912":{"nm":"Pouzdro na pingpongový míček","de":"Bílý míček, tak lehký, že se odkutálí daleko, a při šlápnutí se hned promáčkne. Jedno malé pouzdro chrání ten nejkřehčí míček až do dalšího zápasu. Pevnost často pramení z toho, že je něco měkce zabaleno."},"ICON-0913":{"nm":"Omotávka na badmintonovou raketu","de":"Jednou úhlednou vrstvou omotáte rukojeť kloužící potem. Na dobře omotané rukojeti se raketa stává součástí ruky. Tajemství hrát citem, ne silou, se skrývá v této tenké jediné vrstvě."},"ICON-0914":{"nm":"Malý žeton na skóre","de":"Jeden bod, pak další. Přesouváním malých žetonů se skóre postupně hromadí. Když je počet vidět, zápas se vyjasní a odvaha dohnat ztrátu jediného bodu se tiše probouzí."},"ICON-0915":{"nm":"Klip na směrování bot","de":"Úhledně postavené špičky bot vždy hledí stejným směrem. Malé pootočení rukou, když si je zouváte. Jedno drobné uspořádání dělá zítřejší ranní kroky o poznání lehčími."},"ICON-0916":{"nm":"Šňůrka na píšťalku","de":"Pověsíte si píšťalku na krk a získáte právo říct stůj. Pohled na celé hřiště, které se zastaví na jediné krátké zapískání. Srdce, jež důvěřují tomu drobnému zvuku, se spojují a stávají se slibem."},"ICON-0917":{"nm":"Pouzdro na jehly do pumpičky","de":"I splasklý míč se znovu napne díky jediné tenké jehle. Ta jehla, pečlivě uložená v malé tubě, dokáže svou ztrátou proměnit celou pumpičku v nepoužitelnou věc. Chvíle, kdy na té nejmenší věci záleží nejvíc."},"ICON-0918":{"nm":"Mini kužel na značení","de":"Odsud až tam - malý kužel vykresluje hranici, kterou předtím nebylo vidět. I bez čáry se lidé přirozeně seřadí podle té značky. Řád tiše vyrůstá právě z takových drobných signálů."},"ICON-0919":{"nm":"Váček na žetony","de":"Váček, který na jednom místě shromáždí cinkající žetony. Stáhnete-li ústí, nic se nerozsype. Sáček beze slov ukazuje, že i malé, bezvýznamné věci musí mít místo, kam patří, než mohou konečně splnit svůj úkol."},"ICON-0920":{"nm":"Podložka na míchání karet","de":"Na klouzavém stole se karty v ruce špatně drží. Jediná podložka udělá míchání i sbírání karet o poznání hladší. I v dobré hře je skryta ta něžná příprava - nejdřív vybrat správný povrch."},"ICON-0921":{"nm":"Chránič rohů herního plánu","de":"Když skončí večer u deskové hry, někdo mlčky ošetří nejdřív čtyři rohy herního plánu. Ví totiž, že prohloubený záhyb pokřiví příští partii. V prstech, jež uhlazují okraje, je ukryté přání zítra si zase spolu zahrát."},"ICON-0922":{"nm":"Víčko na kelímek na kostky","de":"Ten krátký okamžik, kdy všichni společně třesou, hází a zadrží dech. Je to malý strop, který nedovolí kostkám vyskočit ven. Pod víčkem si dnešní štěstí na chvíli popadne dech, než se s cinknutím vykutálí ven."},"ICON-0923":{"nm":"Rovnací deska na kostičky","de":"Čím víc je někdo pohlcen hrou, tím víc se mu křiví řada. Tiché posunutí nakloněných kostiček zpátky do rovné linie. Rovnání je ruka, jež něžně přijímá něčí rozjařenou netrpělivost."},"ICON-0924":{"nm":"Plechovka na herní žetony","de":"Čím víc se plechovka žetonů plní, tím víc se i hra rozohňuje. Když se kulaté žetony srazí s cinknutím v dlani, ten zvuk se stane radostí ještě dřív než výhra nebo prohra."},"ICON-0925":{"nm":"Prsten na značení tahu","de":"Malý prsten, který oznámí, že teď jsi na řadě ty. V tu jedinou chvíli, kdy ho posunete o políčko dál, se všechny oči tiše obrátí ke mně. Kroužek, jenž se pomalu otáčí mezi čekáním a očekáváním."},"ICON-0926":{"nm":"Podstavec na hrací figurku","de":"Čím snáz figurka padá, tím pevnější musí mít oporu pod nohama. Jeden podstavec udrží místo i na mírně kolísajícím hracím plánu. Aby velké nahoře mohlo hrdě stát, musí malé dole vydržet."},"ICON-0927":{"nm":"Sponka na návod ke hře","de":"Otevřený návod k pravidlům se vždy potutelně sám převrací. Než vítr stránky odnese, tato sponka jemně přidrží jednu stránku na místě. Pravidla musí zůstat přidržena, aby hra vydržela až do konce."},"ICON-0928":{"nm":"Šňůrka na pouzdro na trsátko","de":"Kytarové trsátko vždy vyklouzne z prstů právě v nejvzrušenější chvíli. Jedna šňůrka, zavěšená na pouzdru, zabrání tomu drobnému útěku. Jen ten, kdo zažil noc, kdy hudba náhle utichla, ví tuto šňůrku ocenit."},"ICON-0929":{"nm":"Pouzdro na plátky nástroje","de":"Plátek ztratí svůj hlas v okamžiku, kdy vyschne. Uvnitř vlhké tuby čeká tenký kousek třtiny na další vystoupení. Místo, kde nejdřív uspíte dech, než ho zase vdechnete zpátky."},"ICON-0930":{"nm":"Navíječ strun","de":"Když struna povolí, tón se také potichu prohne. Pomalé otáčení kličkou, jímž se navrací napětí - péče vždy vychází ze zápěstí. Úpravný zvuk začíná právě u takových drobných úkonů pořádku."},"ICON-0931":{"nm":"Hadřík na čištění nástroje","de":"Když skončí hra, i na nástroji zůstane slabý pot. Jeden tah měkkým hadříkem vrátí lesk a dnešní tóny se spolu s ním tiše usadí. Pečující srdce se vždy projeví v dokončení."},"ICON-0932":{"nm":"Kryt na ladicí kolíčky","de":"Ponechané holé, ladicí kolíčky nenápadně zrezaví. Jeden malý kryt zpomalí o krok roční období kovu. Ten, kdo se stará nejdřív o nenápadné koutky, hraje nejdéle."},"ICON-0933":{"nm":"Klipová lampička na notový pult","de":"V zákulisí za tmy nastane chvíle, kdy jasné musí být jen noty. Malá lampička, připnutá k pultu, tiše sesílá světlo dolů. Hrst záře, jež osvětluje cestu pod nohama, aby se noty neztratily."},"ICON-0934":{"nm":"Tlumicí nástavec na cvičení","de":"Ranní nácvik se vždy tiše přetahuje se sousedovým spánkem. Nasadíte-li tuto krytku, hlasitý zvuk se scvrkne na šepot. Existuje i hudba, jež roste, zatímco chrání něčí sladký spánek."},"ICON-0935":{"nm":"Samolepky na bicí pad","de":"Malé značky nalepené na bicím padu. Kde udeřit pro jaký zvuk - oči se cestu naučí dřív než ruce zapamatují. Takt se takto pomalu vrývá do těla."},"ICON-0936":{"nm":"Čip na zápis melodie","de":"Melodie, kterou si prozpěvujete, bez zachycení rychle zmizí. Pár taktů narychlo poznamenaných na čip někdy dorostou v celou píseň. Inspirace se vždy vrací k ruce, jež pilně zapisuje."},"ICON-0937":{"nm":"Gumička na obal knihy","de":"Je nepříjemné, když se rozečtená kniha v tašce sama od sebe rozevře. Jediná gumička jemně sváže stránky a ty se hned zkrotí. Slib úhledně poskládat věci pro příští stránku."},"ICON-0938":{"nm":"Prstýnek na přidržení stránek","de":"Den, kdy chcete jednou rukou držet otevřenou knihu a druhou usrkávat teplou kávu. Kroužek nasazený na prst za vás přidrží stránky. Drobná úleva začíná právě u takových malých vynálezů."},"ICON-0939":{"nm":"Čip s časovačem na čtení","de":"Sednete si \"jen na jednu kapitolu\" a noc se nějak nepozorovaně prohloubí. Stisknete čip, nastavíte čas, a i čtení tak dostane svou zastávku na oddech. Čím milejší věc, tím víc potřebuje tu něžnou odvahu vědět, kdy přestat."},"ICON-0940":{"nm":"Ochranná krytka na rohy knihy","de":"Čím milejší kniha, tím dřív se jí potutelně opotřebí rohy. Nasadíte jednu krytku a rohy obalu zůstanou pěkně kulaté a chráněné. Malé brnění, jež si nasadíte, abyste si dlouho, předlouho podrželi to, na čem vám záleží."},"ICON-0941":{"nm":"Papírová páska na poznámky ke čtení","de":"Bývají chvíle, kdy jediná věta rázem stiskne srdce. Dojem přepsaný na pásku zůstane na té stránce jako záložka. Vřelá teplota podtržení, kterou zná jen ten, kdo knihu opravdu četl."},"ICON-0942":{"nm":"Visačka na vrácení knihy","de":"Datum vrácení vždy přijde o den dřív, než čekáte. Když vás datum napsané na visačce tiše postrčí do zad, i vypůjčená kniha získá zdvořilost rozloučení. Kvůli rukám dalšího čtenáře knihovna takhle čeká."},"ICON-0943":{"nm":"Klipová lampička na knihu","de":"Noc, kdy bdíte a čtete sami vedle spící rodiny. Stačí jedno malé světýlko připnuté na okraj stránky. Nemusíte zahnat úplně celou tmu - na jednu stránku stačí jen tento kousek tichého času."},"ICON-0944":{"nm":"Vonná kartička s vůní knih","de":"Staré knihy voní směsí slunce a papíru. Tato kartička, o níž se říká, že tu vůni uchovává v jediném plátku, po otevření na okamžik znovu probudí uličku antikvariátu na špičce nosu. Paměť si vkládá záložky i do vůně."},"ICON-0945":{"nm":"Špendlík na značení přečtené stránky","de":"Kam až jsem to vlastně dočetl - malý špendlík, který smaže tu bezradnou otázku. Zapíchnete ho do poslední věty a zítřejší já se už neztratí. Něžná značka, jež si za vás pamatuje místo, kde jste se zastavili."},"ICON-0946":{"nm":"Přívěsek na řemínek telefonu","de":"Jediný přívěsek zavěšený na řemínku telefonu udělá z člověka trochu jiného člověka. Oblíbená barva, oblíbený tvar. Drobný vkus sevřený v dlani jemně pohne náladou toho dne."},"ICON-0947":{"nm":"Ochranná krytka objektivu","de":"Osud cestovatelských fotografií závisí na jediném skle objektivu. Chvíle, kdy sejmete ochrannou krytku, je zároveň pohotovostí srdce stisknout spoušť. Malý rituál, který otevře oči jako první, ještě než zachytíte scénu."},"ICON-0948":{"nm":"Zátka do nabíjecího konektoru","de":"Prach v tašce si to vždy namíří nejdřív na nabíjecí otvor. Zacpete-li ten malý vstup jedinou zátkou, konektor zůstane dlouho čistý. Je v tom pečlivost, jež se postará i o skulinu, kterou není vidět."},"ICON-0949":{"nm":"Vysunovací kroužek na telefon","de":"Postavíte telefon šikmo, jen abyste si pohodlně pustili video. Vyklopíte kroužek na zadní straně a ruka i obrazovka si najednou volněji vydechnou. Jedna malá vyvýšená opora dokáže protáhnout klidnou večerní chvíli."},"ICON-0950":{"nm":"Čisticí náplast na displej","de":"Obrazovka plná otisků prstů jaksi rozmlží i mysl. Jedním setřením náplastí se svět zase vyjasní. Čistota bývá občas jen krátkou záležitostí jediného prstu."},"ICON-0951":{"nm":"Pouzdro na jehličku na SIM kartu","de":"Jehlička na SIM kartu je skřítek, který zmizí vždycky přesně ve chvíli, kdy ho nejvíc potřebujete. Uložíte-li ji do jedné přihrádky pouzdra, už nikdy nebudete prohledávat celý dům kvůli sponce do vlasů. Drobný pořádek tiše zachrání naléhavou chvíli."},"ICON-0952":{"nm":"Samolepka na bezdrátovou nabíjecí podložku","de":"Noc, kdy se telefon sám od sebe dobije, zatímco jen tiše leží na podložce. Přilepená samolepka jemně vyznačí místo, kam si má telefon lehnout. Neviditelný proud beze slova doplní denní dávku energie."},"ICON-0953":{"nm":"Zaslepovací samolepka na oznámení","de":"Notifikace, které nechcete vidět, je klidnější mysli zakrýt. Jediná samolepka utiší drobné světýlko za svítání. Někdy je i nedívání se něžným způsobem, jak se chránit sám před sebou."},"ICON-0954":{"nm":"Ochranný kroužek na objektiv","de":"V okamžiku, kdy se objektiv fotoaparátu dotkne podlahy, srdce se leknutím propadne. Jeden nasazený kroužek nenápadně odvrátí ten malý pád. Lem, jenž jako první chrání oko, které zachycuje vzpomínky."},"ICON-0955":{"nm":"Jmenovka na kabel","de":"Konečně rozeznat ten svůj mezi změtí zapletených kabelů. Jediná visačka konečně dá nabíjecímu kabelu vlastní jméno. Malá vlaječka, jež ukazuje cestu mezi zmatenými šňůrami."},"ICON-0956":{"nm":"Pouzdro na nabíječky","de":"Nabíječky v cestovní tašce se vždy mezi sebou zapletou a hádají. Uspořádané úhledně v jedné přihrádce pouzdra se konečně usmíří. Umění balení spočívá v tom něžně svolat roztroušené věci na jedno místo."},"ICON-0957":{"nm":"Štítek na prodlužovací kabel","de":"Otvory v prodlužovačce vypadají všechny stejně a pokaždé se v nich ztratíte. Přilepíte štítek, určíte, čí místo je čí, a rušné ráno hned ubíhá plynuleji. Malá jmenovka umenšuje drobné každodenní půtky."},"ICON-0958":{"nm":"Naviják na kabel","de":"Rozmotaný k použití a zase namotaný zpět - úhledný den jedné šňůry. Namotáte ho vrstvu po vrstvě na jednu cívku a zamotání čistě zmizí. Ruka, jež po použití vrátí věc na její místo, dělá zítřek lehčím."},"ICON-0959":{"nm":"Krytka na magnetický konektor","de":"Magnetický konektor k sobě nepozorovaně přitahuje drobné kovové piliny. Zakryjete-li ho krytkou, lepkavý prach se už nechytí. Zařízení, jehož se dotkne ještě jedna pečující ruka, žije po vašem boku déle."},"ICON-0960":{"nm":"Gumička na powerbanku","de":"Necháte-li powerbanku a kabel zvlášť, jeden z nich vždy zmizí. Svážete-li je gumičkou, konečně se stanou párem. Malý uzlík, který těsně před odchodem z domu jemně sváže, ať cestují spolu."},"ICON-0961":{"nm":"Prachová krytka na zásuvku","de":"Prázdný otvor zásuvky si prach po pár dnech tiše zabydlí jako vlastní domov. Když tuto malou krytku postavíte místo sebe na stráž, nabíječka, jež se tam příště zasune, se nadechne prvním čistým dechem. Vrátný, který pečlivě střeží prázdný čas."},"ICON-0962":{"nm":"Barevný kroužek na kabel","de":"Noc strávená tápáním po svém kabelu ve změti šňůr - kdo to řekl, obarvěme je? Modrá je tvoje, žlutá je moje. Jediným malým kroužkem se od té chvíle už nikdy nespleteme. Stopa vřelého slibu, jež zůstala v koutě zkušebny."},"ICON-0963":{"nm":"Třídicí čip na adaptéry","de":"Kulaté kolíky a ploché kolíky, 110 a 220. Čip, který si tiše zapamatoval tvář zásuvek, jež se v každé zemi liší. V koutku kufru na první cestu přes moře na jeviště bývala vždycky zastrčená právě tato drobná třídicí karta."},"ICON-0964":{"nm":"Podložka na třídění špuntů do sluchátek","de":"Prý má každý ušní kanálek jinou hloubku i šířku. Rozložit vedle sebe tři velikosti - velkou, střední, malou - a vybrat jediný pár, který přesně sedne do ucha. Něžný postup, při němž se nejdřív sladí tělo, teprve pak sluch."},"ICON-0965":{"nm":"Silikonový lem na pouzdro","de":"Jevištnímu kostýmu věnujeme pozornost až po každý steh, ale rohy pouzdra vždy narážejí do světa holé. Když tento tenký silikonový pásek jemně obepne okraj, i po ránu, kdy pouzdro vyklouzlo z ruky za svítání, obrazovka vítá jitro nezraněná."},"ICON-0966":{"nm":"Samolepka proti hluku","de":"Bývají dny, kdy chcete na chvíli vypnout zvuky světa. Tato malá samolepka na sluchátku je značka, jež rozsvítí ticho. Amulet, který jásot z hlediště i hluk metra odnese na dálku, jen dokud neskončí jedna píseň."},"ICON-0967":{"nm":"Sada háčků na sluchátka","de":"Při tanci vždy jedno sluchátko uteče jako první. Zavěsíte-li tyto háčky, jež něžně objímají ušní boltec, hudba samotná zůstane v uších až do konce i uprostřed prudké choreografie. Drobný objev, který si lidé ve zkušebně předávali mezi sebou."},"ICON-0968":{"nm":"Krytka na úklidový kartáč","de":"Malá čepička nasazená, aby se prach na konečcích štětin znovu nerozprášil. Že i úklidový nástroj potřebuje úklid, věděla už dávno ruka, jež po zametání stavěla koště obráceně vzhůru nohama."},"ICON-0969":{"nm":"Podložka pod nabíjecí stanici","de":"Nabíjecí stanice na stole pořád klouzala, protože neměla nohy. Jakmile tuto tenkou podložku podloženou pod ni nahradí chybějící nohy, zařízení klidně zůstane na svém místě a přes noc si tiše doplní sílu."},"ICON-0970":{"nm":"Značka na rozlišení leva a prava","de":"Vlevo L, vpravo R. Přidán je ještě jeden bod navíc, aby ho bylo poznat i poslepu potmě. Přání ani jednou nesplést levou a pravou nohu na jevišti je nezpochybnitelně vtištěno do této drobné značky."},"ICON-0971":{"nm":"Krytka na audio rozdvojku","de":"Ten konektor, jímž se jeden proud zvuku dělil mezi víc lidí, je třeba během odpočinku zaslepit. Aby prach nepronikl do obvodu. Drobná, opatrná ruka, jež si přeje, aby píseň, kterou jste poslouchali společně, i příště tekla čistě."},"ICON-0972":{"nm":"Naviják na kabel sluchátek","de":"Jako starý pohyb ruky navíjející přízi, i kabel sluchátek se tady, namotaný do kolečka, stane úhledným. Chvíle, kdy se hudba, jež se dosud zamotaná válela v tašce, konečně uspořádá. Zítřejší rozmotávání bude o poznání lehčí."},"ICON-0973":{"nm":"Šňůrka na krytku objektivu","de":"Pokaždé, když jste otevřeli objektiv, krytka vždy ztratila, kam se poděla. Přivážete-li ji šňůrkou k fotoaparátu, už nikdy zbytečně netápete v kapse. Že věc, kterou nechcete ztratit, stačí přivázat nablízko, se ruka naučila jako první."},"ICON-0974":{"nm":"Přívěsek do patice pro blesk","de":"Do prázdné patice pro blesk na vršku fotoaparátu potajmu vsunete drobnou ozdůbku. Ten jediný přívěsek bez jakékoli funkce nějak promění těžkou, strohou výbavu v milovanou, jako by byla vaše vlastní. Umění přilnout k nástroji."},"ICON-0975":{"nm":"Přezka na nastavení popruhu","de":"Pokaždé, když se popruh tašky zaryje do ramene, o kousek povolíte nebo utáhnete tuto přezku. Jeden pohyb prstů, jímž zvolíte délku podle svého těla. I nošení nákladu je nakonec péče o sebe sama, tiše říká přezka."},"ICON-0976":{"nm":"Pouzdro na sadu filtrů","de":"Malý domeček, v němž jsou vrstva po vrstvě uloženy skleněné kousky, jež dělí světlo. Zákal a jasno, soumrak a noc. Jako zásuvka, kam se předem vybere a uloží počasí, fotograf tuto krabičku vždy otevře jako první, než vyrazí na cestu."},"ICON-0977":{"nm":"Prachová krytka na ofukovací balonek","de":"Gumový balonek, jenž profukem odhání prach, je na prach stejně slabý právě u svého vlastního ústí. Během odpočinku ho zakryjete touto krytkou. V tom, že nástroj, jenž utírá druhé, si nejdřív tiše zakryje vlastní ústa, je jaksi cosi něžného."},"ICON-0978":{"nm":"Krytka na tlačítko spouště","de":"To, že se spoušť v tašce sama zmáčkne a vyfotí sto snímků prázdné oblohy, zažil skoro každý aspoň jednou. Tato malá krytka na tlačítku té zbytečné práci zabrání. Drobný zámek, jenž má zachytit jen ty chvíle, které si opravdu chcete uchovat."},"ICON-0979":{"nm":"Samolepky na třídění baterií","de":"Vždy je to trápení, když se v jedné kapse smíchá vybité s plným. Barevná samolepka na každé baterii ten zmatek tiše roztřídí. Červená je prázdná, zelená je spolehlivá. Beze slova svítící semafor ponechaný na place natáčení."},"ICON-0980":{"nm":"Přepážka do fotobrašny","de":"Rozdělíte tašku na přihrádky, aby se objektiv, tělo a náhradní baterie navzájem nesrážely. Vytvoření několika malých pokojíčků uvnitř jednoho nákladu. Každé místo má svého majitele, a tak nic neztratí své místo, i když se zatřese."},"ICON-0981":{"nm":"Fotografické rukavice s výstelkou","de":"Zimní venkovní natáčení, kdy jedině konečky prstů, mačkající spoušť, nesmí zmrznout. Tlustá výstelka v dlani, rukavice, jež ponechají cit na konečcích prstů. Něžný kompromis terénu, jenž se snaží v jedné ruce svírat zároveň teplo i preciznost."},"ICON-0982":{"nm":"Pouzdro na hroty do tabletového pera","de":"Že se i hrot pera opotřebovává jako tuha tužky, ví každý, kdo dlouho drží tablet. Tato malá tuba, v níž se koulí náhradní hroty pohromadě, je jako nouzová zásoba na konečcích prstů, jež předem doplňuje linky, které nesmí přetrhnout."},"ICON-0983":{"nm":"Podnos na klávesy klávesnice","de":"V den, kdy jste jednu po druhé vytáhli klávesy, umyli je a znovu nasadili, se tento podnos stal malým přílivovým dnem. Pohled na souhlásky a samohlásky, jak leží políčko po políčku a schnou. Existuje i péče, kterou uvidíte, teprve když něco rozeberete."},"ICON-0984":{"nm":"Sada nožiček na myš","de":"Tajemství, díky němuž myš klouže po stole jako po hladině, se skrývá v těchto drobných nožičkách přilepených na spodku. Balíček, který vyměníte, jakmile se opotřebují. Dřina věcí, jež z neviditelného místa mlčky nesou tu hladkost."},"ICON-0985":{"nm":"Gumový stojánek pod notebook","de":"Podobá se notýsku, ale ve skutečnosti je to gumová podložka, jež podpírá notebook. Nadzvednete obrazovku lehce do výšky očí a narovnáte přitom shrbený krk. Ohleduplnost, jež napřimuje postoj toho, kdo dlouho píše a dlouho se dívá."},"ICON-0986":{"nm":"Posuvný kryt na webkameru","de":"Prstem odsunete a zakryjete objektiv, znovu odsunete a otevřete. Přání být viděn jen tehdy, když sami chcete. V tomto jediném malém posuvníku přebývá velký klid jménem soukromí. Zvuk zavření je nějak podivně uklidňující."},"ICON-0987":{"nm":"Štítky na třídění USB disků","de":"Pět podobných černých tyčinek a vůbec žádný způsob, jak poznat, co je na které uloženo. Přilepíte malý štítek, dáte jim jméno, a teprve pak se stanou vaší vlastní rodinou. Aby se dalo snadno najít, potřebuje věc jméno, kterým ji zavoláte."},"ICON-0988":{"nm":"Rohové úchyty na podložku na stůl","de":"Když se rohy podložky na stůl pořád svinují nahoru, křiví se i rukopis. Tyto drobné díly, jež jemně přitisknou všechny čtyři rohy, střeží plochý klid na stole. Jen když je povrch tichý, mohou být klidné i konečky prstů."},"ICON-0989":{"nm":"Klip na stojánek USB rozbočovače","de":"Svorka, jež šikmo postaví na okraj stolu rozbočovač, do něhož se sbíhá víc kabelů. Pohled na to, jak se nepořádné šňůry sbírají a uklízí do jediného bodu. I tady žije ten cit pro svázání rozcuchaného do jednoho pramene."},"ICON-0990":{"nm":"Zátka na sprej na čištění displeje","de":"Malá zátka, jež uzavírá ústí spreje stírajícího otisky prstů z displeje. Vždy pevně zavřená, aby kapalina neunikla ani nevyschla. Aby bylo vidět jasně, je třeba nejdřív šetřit prostředky na čištění - prostý řád domácí péče."},"ICON-0991":{"nm":"Pouzdro na paměťové karty","de":"Několik dní záznamů z vystoupení tiše spí na kartě velké sotva jako nehet. Ztratíte ji a celý ten den zmizí naráz, a tak ji pečlivě shromažďujete v malé peněžence. Domov, jenž v sobě uchovává tu nejmenší a přitom největší vzpomínku."},"ICON-0992":{"nm":"Štítky na externí disky","de":"Pět černých externích disků spí v šuplíku se stejnou tváří. Přilepit štítek a pojmenovat je \"to léto\", \"nevydané klipy\". Práce, jíž se do rozmazané vzpomínky vloží jasný rejstřík."},"ICON-0993":{"nm":"Kontrolní čip na zálohu","de":"Jestli je záloha hotová, nebo ne - z toho tenoučkého rozdílu se srdce svírá. Tento malý čip, tiše vsunutý na místo, kde jste skončili, vám řekne \"až sem je to v bezpečí\". Klid v duši přichází z toho, že po sobě zanecháte značku."},"ICON-0994":{"nm":"Token na cloudové poznámky","de":"Token, jenž vyšle jednořádkovou poznámku vzhůru do úložiště plovoucího kdesi na nebi. Malá magie, při níž vás ten text vyjde přivítat, ať zapnete zařízení kdekoli. Noční obloha, na niž jste kdysi vypouštěli draka a psali přání, jako by teď jemně sestoupila na dlaň."},"ICON-0995":{"nm":"Sada ochranných krytek na USB","de":"Ponechaný s odhaleným konektorem, jak se povaluje v tašce, se kontakt nevyhnutelně poškodí. Nasadíte na každý konec malou čepičku a uložíte je jako jednu sadu. Akt, jímž jemně uspíte čas, kdy se nepoužívají - nejtišší příprava na příští připojení."},"ICON-0996":{"nm":"Gumička na pouzdro s daty","de":"Gumička, jež pevně obepne a sváže zařízení s cennými daty. Jedním otočením ji pevně utáhnete, aby se v roztřesené tašce o nic nenaráželo. Ruka, jež kdysi pečlivě zavazovala uzel na ranci, žije stejně dál i v digitálním světě."},"ICON-0997":{"nm":"Štítek na třídění souborů","de":"Když se stovky souborů nahromadí beze jména, samo hledání se stane bloudění. V okamžiku, kdy nalepíte barevné štítky a otevřete jednotlivé větve, se mezi neuspořádanou hromadou objeví cesta. Uklízet nakonec znamená razit cestu."},"ICON-0998":{"nm":"Kartička s nápovědou k heslu","de":"Napsat heslo celé je nebezpečné, nenapsat ho vůbec znamená zapomenout. A tak si necháte jen nenápadný klíč, jemuž rozumíte jen vy sami. Třeba \"to město prvního koncertu\". Chytrý a něžný způsob zapamatování, jenž nezapisuje odpověď, ale cestu k ní."},"ICON-0999":{"nm":"Samolepka s datem uskladnění","de":"Nepoznamenáte-li den, kdy jste to uložili, uskladnění se brzy promění v zapomnění. Datumová samolepka na každé krabici jasně vyryje \"od kdy\". Duch staré spižírny, kde se zapisoval den, kdy se namíchala kvašená sójová pasta, pokračuje dál na tomto malém papírku."},"ICON-1000":{"nm":"Krytka na mini kruhové světlo","de":"Krytka, jež zakrývá otvor pro světlo malé lampičky vydávající kulatou záři. Na chvíli uspíte světlo, aby se čočka v tašce nepoškrábala. I uchovávat tmu pěkně netknutou, než se rozsvítí, je jedním ze způsobů, jak si vážit jasu."},"ICON-1001":{"nm":"Utahovací šroub držáku","de":"Ještě jednou otočit. Uvolněná mezera zmizí a pod dlaní se usadí tíživé uklidnění. Za pódiem, které se nechvěje, se vždy skrývá jedno pevné otočení něčího zápěstí. To, co drží malý šroubek, je neviditelná pevnost."},"ICON-1002":{"nm":"Značka „Vysíláme“","de":"Ve chvíli, kdy se rozsvítí červené světlo, se kroky na chodbě potichu promění v chůzi po špičkách. Před slovy „Vysíláme“ všichni zadrží dech. I ticho za dveřmi je srdce obrácené k někomu druhému – to tichounce oznamuje tenhle malý čip."},"ICON-1003":{"nm":"Poznámkový bloček na chat","de":"Zachytit konečky prstů povzbuzení, které by jinak zmizelo na obrazovce. Čas, kdy každé slovo, jež by uteklo pryč, zůstává úhledně a jasně na papíře. Zaznamenávat znamená uchovávat něhu toho, kdo chce dojít k druhému, byť i pozdě."},"ICON-1004":{"nm":"Tlumicí kryt klávesnice","de":"Ve dvě hodiny ráno zvuk klapajících kláves zmizí, jako by to byla lež. Tenká fólie, aby nerušila dech klidně spícího spolubydlícího. Ten nejtišší ohled vždy začíná v tichém koutě."},"ICON-1005":{"nm":"Klip na rameno mikrofonu","de":"Mezi rty a mikrofonem přesně ta vzdálenost, při níž se píseň nezachvěje. Tenhle drobný klip drží ten slib pevně. Za pódiem vždy stojí napřed ruka, jež tak pevně vše podpírá."},"ICON-1006":{"nm":"Svorka na plátno pozadí","de":"I když fouká vítr, pozadí se ani nehne. Protože jedna malá čelist pevně sevřená v rohu drží celou scénu na místě. Za neochvějným výhledem stojí vždy někdo neviditelný, kdo zatíná zuby."},"ICON-1007":{"nm":"Štítek na stream desk","de":"Na desítkách tlačítek díky malým jmenovkám ruka nikdy nezabloudí. Jeden řádek štítku předem vymaže jednu chybu živého vysílání. Klid pramení z písmen napsaných dřív, než přijde chvění."},"ICON-1008":{"nm":"Tlačítko časové značky","de":"Stiskneš ho a do plynoucího času se zapíchne malá vlaječka. Otisknout pečeť na „teď“, které se už nikdy nevrátí. Když se po dlouhé době ohlédneš, ta značka se stane dveřmi do vzpomínek."},"ICON-1009":{"nm":"Klíčenka se čtečkou čipů","de":"Přiložíš ji a pípne – informace se probudí. Malý společník visící na svazku klíčů, cinkající v kapse. Obyčejný den takhle bezpečně plyne dál díky drobným zvukovým signálům."},"ICON-1010":{"nm":"Štítek na chytrou zásuvku","de":"Když má každá zásuvka své jméno, už nikdy nebloudíš, který kabel je který. Srdce, jež dá jméno i neviditelné elektřině. Pořádek je jen jiná tvář, kterou si na chvíli obléká něha."},"ICON-1011":{"nm":"Stojánek se senzorem teploty a vlhkosti","de":"Strážce velký jako dlaň, jenž beze slova hlídá teplotu a vlhkost v pokoji. Pohodlí neotvírá ústa, ale tenhle stojánek tiše pečuje o tvůj stav v každém okamžiku. Přesně takhle se v tichosti chrání pohoda."},"ICON-1012":{"nm":"Krytka dveřního senzoru","de":"Malé oko, které nepromešká ten okamžik, kdy se dveře jemně pootevřou. Beze slova předává zprávu, že se někdo vrátil domů. Prázdný dům vždy hlídají právě takové mlčenlivé věci."},"ICON-1013":{"nm":"Držák na dálkové ovladače","de":"Dálkové ovladače, jež se povalovaly tu i tam, konečně najdou svá vlastní místa. Malé místečko, které tiše podrží to, co bylo skoro ztraceno – ruka, jež předem vyrývá slib, že se ještě setkají."},"ICON-1014":{"nm":"Token spánkové aplikace","de":"Každou noc, kdy se ti spí dobře, se navrší jedna kulatá odměna. I spánek se prý hromadí kousek po kousku jako trénink, něžně ti to říká aplikace. Ta nejmenší cena na světě, podaná tobě, jenž ses dobře vyspal."},"ICON-1015":{"nm":"Podstavec na časovou kostku","de":"Zatímco tři minuty pravidelně ubíhají, kostka počítá svůj čas beze zachvění. Jedno místečko velké jako dlaň, jež ji tiše podpírá zezdola. I čekání potřebuje podlahu, na kterou se dá s klidem v srdci stoupnout."},"ICON-1016":{"nm":"Kryt kontrolky upozornění","de":"Aby nebylo příliš jasné, jemně zahalí světlo do jedné vrstvy. Ať je upozornění sebenaléhavější, oči ať zůstanou klidné. Ohleduplnost je srdce, které tiše zvažuje i sílu světla."},"ICON-1017":{"nm":"Karta na výměnu baterie","de":"Když se objeví tahle karta, znamená to, že je čas vyměnit malé srdce uvnitř přístroje. Vlídné upozornění, aby ses o to postaral dřív, než se zastaví. Tajemství dlouhého společenství vždy spočívá v pozornosti o krok napřed."},"ICON-1018":{"nm":"Sada čepiček na joystick","de":"Drobné čepičky nasazené tak, aby palec neuklouzl. Cit v konečcích prstů se stane o to zřetelnějším. Tahle jedna malá čepička dokáže rozhodnout výhru či prohru zápasu odehraného zpocenýma rukama."},"ICON-1019":{"nm":"Kryt doku konzole","de":"Jemně přikrývá místo, kde konzole odpočívá, před prachem. Protože i krátce spící přístroj potřebuje jednu přikrývku. Starostlivé srdce se ve skutečnosti nejzřetelněji projeví právě tehdy, když se věc nepoužívá."},"ICON-1020":{"nm":"Pouzdro na přenosnou konzoli","de":"Na cestách vždy jen sem dovnitř. Váček, jenž měkce obepíná přenosnou konzoli. Aby zůstala v pohodě, i když v tašce naráží ze všech stran – vzácné věci je dobré zabalit ještě jednou navíc."},"ICON-1021":{"nm":"Kroužek nálepek na tlačítka","de":"Stačí položit na fádní tlačítko jeden malý obrázek a v tu chvíli se stane úplně tvým. Zanechat vlastní stopu na naprosto stejném přístroji. Osobitost vždycky tiše rozkvétá právě na takových nepatrných místech."},"ICON-1022":{"nm":"Pouzdro na herní kazetu","de":"Jedna hra, do níž ses celou noc nořil, klidně spí uvnitř tohohle malého pouzdra. Znovu otevřeš víčko a ta noc se probudí, celá netknutá. Vzpomínky se překvapivě často vejdou do krabičky ne větší než dlaň."},"ICON-1023":{"nm":"Podstavec s chladicím ventilátorem","de":"Zatímco vánek chladí žár, místo, jež mírně naklání a podpírá přístroj. Vytváří chvíli, aby si rozpálené tělo mohlo oddechnout. Chceš-li doběhnout daleko, musíš také umět na okamžik zastavit a vychladnout."},"ICON-1024":{"nm":"Kolík poutka na zápěstí","de":"Omotáš ho kolem zápěstí a zapneš kolík, a ovladač se od tebe neodpojí ani při sebedivočejším pohybu. Tenhle popruh, jenž vypadá jako přítěž, je ve skutečnosti tou jistotou, díky níž se můžeš s klidným srdcem řádit dál."},"ICON-1025":{"nm":"Čepička na analogovou páčku","de":"Na rukojeť ohlazenou dlouhým používáním obléct nový kabátek. Cit, na který si zvykla ruka, nech beze změny, jen povrch ať je jako nový. Chvíle, kdy důvěrná známost a nové vzrušení leží vedle sebe v jedné ruce."},"ICON-1026":{"nm":"Štítek uložené pozice","de":"Do každé pozice pro uložení hry úhledně zapíšeš, čí je to dobrodružství. Jeden řádek štítku mlčky střeží cestu uplynulých pár dní. Vzácné vzpomínky je dobré opatřit jménem vyrytým na místo, aby je nikdo nepřepsal."},"ICON-1027":{"nm":"Pouzdro na diktafon","de":"Přístroj, jenž v sobě uchovává zvuk, je vzácnější právě kvůli tomu, co v sobě nese. Nosíš ho pečlivě uloženého v měkkém váčku, který ho chrání před nárazy. Uvnitř možná spí něčí hlas, a proto o to opatrněji."},"ICON-1028":{"nm":"Protivětrná krytka mikrofonu","de":"Odežene zvuk větru a ponechá jen hlas. Chlupatá čepička, kterou při venkovním nahrávání jemně nasadíš na mikrofon. Drobné síto, jež z rozháraného hluku vybere jen ryzí upřímnost."},"ICON-1029":{"nm":"Štítek na hlasovou poznámku","de":"Tohle je text, co mě napadl, tohle melodie, co jsem si pobrukoval. Na každou hlasovou poznámku nalepíš barevnou jmenovku. Roztroušené střípky inspirace konečně najdou svá místa a seřadí se do řady."},"ICON-1030":{"nm":"Čip se samplovacím tlačítkem","de":"Stiskneš ho a vyskočí ven kousek dřív uloženého zvuku. Kapka deště, potlesk, něčí smích – útržky světa se probouzejí na konci prstu. Hudba je vlídný sbor právě takových drobných čipů."},"ICON-1031":{"nm":"Obálka na sbírání zvuků","de":"Zvuky, které náhodou zaslechneš cestou, jemně uložíš do téhle obálky. Vlnění větru, i ticho ranní uličky. Materiál, z něhož jednou vznikne píseň, se takhle skromně schraňuje odjakživa."},"ICON-1032":{"nm":"Nožky mini stativu","de":"Tři nožky rozevřou na stole malé pódium. Místo chvějící se ruky stojí pevně a drží scénu na místě. Ostrý jediný záběr se rodí teprve z těch tří nohou, jež mlčky stojí bez hnutí."},"ICON-1033":{"nm":"Visačka na nahrávku","de":"Ke stovkám nahraných souborů připojíš jednu po druhé krátkou jmenovku. Aby bylo na první pohled jasné, který je ta první sloka, co poprvé vyklouzla v který den. Malý ukazatel, jenž ti pomůže znovu najít roztroušené hlasy."},"ICON-1034":{"nm":"Nálepková páska s vlnovkou","de":"Vlnitá páska, odlitá přímo podle tvaru zvuku. Omotáš ji kolem sešitu nebo pouzdra a je to, jako by hudba byla vidět přímo před očima. Vlídný klam, jenž mění slyšené v to, co lze vidět."},"ICON-1035":{"nm":"Háček na sluchátka","de":"Když skončí zkouška, tiše připraví místo k odpočinku pro unavená sluchátka. Jeden malý hák zapíchnutý do rohu stolu. Uklizený stůl je místo, kam si předem zavěsíš zítřejší chuť do práce."},"ICON-1036":{"nm":"Stužka na dárkovou krabičku","de":"Poslední otočka omotaná kolem pasu dárkové krabičky. Právě touhle jednou stužkou se srdce konečně dovrší. Upřímnost se často předá dřív rukou, jež hladí povrch, než tím, co je uvnitř."},"ICON-1037":{"nm":"Krytka na konec stuhy","de":"Jemně obalí a zakončí konec stuhy, aby se nerozplétal. Jeden detail, kterého si stěží kdo všimne, tiše mění první dojem z dárku. Když je zakončení jemné, i srdce dorazí jemně."},"ICON-1038":{"nm":"Pečetní vosk","de":"Jednu horkou kapku upustíš a zapečetíš obálku. Jako u starého dopisu, jeden tíživý slib, že se nemá otevírat lehkovážně. Obřadnost v sobě občas takhle nese vřelou váhu."},"ICON-1039":{"nm":"Stojánek na děkovnou kartičku","de":"Podpírá zpříma kartičku se slovy díků, aby se nepomačkala. Aby srdce dorazilo vzpřímeně. Vděčnost zůstává v srdci déle, když je upravená i její podoba."},"ICON-1040":{"nm":"Výplňový papír ve tvaru hvězdiček","de":"Papír vystřižený do tvaru hvězdiček měkce vyplní mezery v krabici. Vata srdce, jež si přeje, ať se nic neublíží, i když to zatřese. I v temnotě uvnitř balíčku tak vlastně pluje jedna malá hvězda."},"ICON-1041":{"nm":"Jmenovka k dárku","de":"Před políčkem „komu“ se pero na dlouhou chvíli zastaví. Tvář, jež se vybaví, zatímco píšeš jméno, období strávené společně. Ve chvíli, kdy se přiváže, se tenhle drobný papírek stane tajemstvím, které nikdo nepřečte, dokud se nerozváže."},"ICON-1042":{"nm":"Razítko s blahopřáním","de":"Stiskneš ho a vytiskne se jasné kulaté blahopřání. Zatímco čekáš tu chvilku, než inkoust zaschne, nejvřelejší je srdce, jež přemýšlí, komu ho podat. Jestli má nějakou vadu, tak snad jen tu, že se ti chce razítkovat ještě jednou."},"ICON-1043":{"nm":"Cívka s dárkovou šňůrkou","de":"Pečlivě navinutá, pak se vesele odvíjí u něčích rozechvělých konečků prstů. V té krátké chvíli navíjení a odvíjení se srdce svázané k niti konečně stává darem."},"ICON-1044":{"nm":"Uzlový přívěsek (ne kytička)","de":"Není to napodobenina květiny, ale tvar, kdy jedna jediná nit znovu a znovu obejme sama sebe a rozkvete sama od sebe. Trpělivost konečků prstů, jež celou noc vybíraly uzly, zůstala jako tenhle jeden malý poupátko."},"ICON-1045":{"nm":"Váček se šťastnými mincemi","de":"Srdce, jež nenápadně vloží pár mincí do kapsy toho, kdo se vydává na dlouhou cestu. Není to o váze, ale o naplnění něhou. Cinkání při každém kroku nahrazuje pozdrav „šťastnou cestu“."},"ICON-1046":{"nm":"Přívěsek s tobolkou přání","de":"Uvnitř kulaté skořápky klidně spí jedno složené přání. To, že se splní, když ho otevřeš, je lež, ale že to přání zůstane navždy živé, když ho podržíš neotevřené – to je pravda."},"ICON-1047":{"nm":"Ochranná uzlová šňůrka","de":"Šňůrka pevně upletená z pěti barevných nití, jež obrací zlou energii za tvá záda. Jako ruka babičky, jenž v dětství svázala uzel kolem zápěstí – v každém svázaném místě je jemně vetkaná něčí modlitba."},"ICON-1048":{"nm":"Pouzdro na papírového jeřába","de":"Malý domeček, jenž chrání jen jednoho jediného papírového jeřábka z tisíce, které je třeba složit, aby se staly přáním. Protože i kdyby se pomačkalo jen jedno křídlo, rozplynula by se i veškerá oddanost vložená do té noci."},"ICON-1049":{"nm":"Váček na třpytivé kamínky","de":"Drobné jiskřičky, jež upadly z pódiového kostýmu – místo, kam smeteš to, co se ti nechce vyhodit. I třpyt, jenž se jednou přilepil a týden tě pak sledoval, tady spočine poslušně, jako by ležel na dlani."},"ICON-1050":{"nm":"Razítko dobrého znamení","de":"Malá kartička, kterou nenápadně přidáš, když vybíráš dobrý den. Ne u prahu věštírny, ale na vlastním stole tiše otiskneš kousek milého pověrčivého přání, aby se dnes stalo jen to dobré."},"ICON-1051":{"nm":"Karta s náramkem přání","de":"Na jednom listu papíru vytištěném do tvaru náramku je uloženo něčí tiché přání. I když si ho nemůžeš připnout na zápěstí, schovej ho hluboko do peněženky a to srdce zůstane přivázané po tvém boku, kráčeje s tebou napořád."},"ICON-1052":{"nm":"Slánka před dveře","de":"Hrubou sůl nasypanou do malé sklenice tiše postavíš před dveře. Starý zvyk, jenž zlou energii odežene a vpustí jen milé hosty. Každé slané zrnko je malý strážce, který hlídá náš domov."},"ICON-1053":{"nm":"Krycí štítek na šťastné číslo","de":"Těsně před seškrábáním je na chvíli každý výherce. Tenhle štítek, jenž jemně zakrývá šťastné číslo, střeží tu poslední vteřinu, kdy naděje nabírá na síle nejvíc. I když se ti při škrábání chvějí prsty, dělá, že si ničeho nevšiml, a zavře oči."},"ICON-1054":{"nm":"Krytka na uchování narozeninové svíčky","de":"Pečlivé srdce, jež i jednou zapálenou svíčku uchová v pořádku až do příštích narozenin. Jestli se loňské přání ještě nesplnilo, letos ho prostě navážeš tam, kde jsi přestal, a přeješ si dál – jeden vlídný způsob počítání."},"ICON-1055":{"nm":"Odpočítávací prsten na výročí","de":"Drzá věcička, jež ti navlékne D-den na prst. Pokaždé, když se počet zbývajících dní posune o jedno políčko, i srdce se o to samé přiblíží. Prý se sám od sebe rozzáří v den, kdy dojde k nule – tak si to aspoň umanul."},"ICON-1056":{"nm":"Gumička na párty čepičku","de":"Tenká šňůrka, jež pevně přidrží kornoutovou čepičku na hlavě. Sám oslavenec si sice brzy postěžuje, že ho škrtí, a sundá si ji, ale na fotce ji má nasazenou navždy, v tom jednom záběru. K té úloze to úplně stačí."},"ICON-1057":{"nm":"Malý špejlík na dortík","de":"Drobná značka zapíchnutá do dortíku velkého sotva jako dva články prstu. I nad sladkostí, jež zmizí na jedno sousto, se oslava vzpřímeně napřímí. Ať je jakkoli malý, narozeniny jsou narozeniny a dnešní hvězdou jsi ty."},"ICON-1058":{"nm":"Nálepka s párty petardou","de":"I bez prásknutí vypadá nejokázaleji ze všech – papírová petarda. Ve chvíli, kdy se přilepí na obálku, se obyčejná zásilka promění v dopis z oslavy. Mnozí ji nechávají na místě, škoda ji odloupnout."},"ICON-1059":{"nm":"Kolíček na fotografie","de":"Ze strachu, že mi na šňůře uvázané vzpomínky vyklouznou, mám pusu vždycky pevně zaťatou. Dokud jednu fotografii svírám, ani vítr proudící škvírou v okně ty dny nedokáže shodit."},"ICON-1060":{"nm":"Nášivka balónku s datem","de":"Nášivka ve tvaru balónku s číslem. Nalep ji na oblečení a celé okolí se dozví, jaký je dnes zvláštní den. Odlepíš ji a zůstane po ní stopa – a i ta rozmazaná stopa se stane další vzpomínkou."},"ICON-1061":{"nm":"Značka na výměnu dárků","de":"Šibalská značka, jež jemně poplete, čí ruka dárek přijala a čí ho podala. Pravidlo, malé a laskavé, u stolu s výměnou dárků – pamatuj si spíš, co si mezi sebou vyměnili, než kdo to dal."},"ICON-1062":{"nm":"Číslo na slavnostní stůl","de":"Malé číslo postavené u každého slavnostního stolu. Určit předem, kdo kde sedí, aby si nikdo nepřipadal rozpačitě – v tom je vlídná moudrost lidí, kteří uspořádali už mnoho oslav."},"ICON-1063":{"nm":"Dárková taška na kliku","de":"Způsob, jak předat srdce, aniž bys zazvonil. Pověsíš ji nenápadně na kliku a zmizíš, jako bys utíkal – a překvapený výraz toho, kdo ji najde, se vrací dárci jako ten největší dar."},"ICON-1064":{"nm":"Štítek tajné zásilky","de":"Na povrchu není napsáno vůbec nic. Skrýt odesílatele až do konce je malá hrdost téhle nálepky. Čím déle příjemce s úsměvem kroutí hlavou v úžasu, tím dokonaleji je splněna ta tajná úloha."},"ICON-1065":{"nm":"Vzkazový čip na dveře","de":"Malý lísteček, jejž necháš místo toho, když ti nesejde odvaha zaklepat. Krátký řádek jako „jen jsem se stavil“ vydrží déle než zvuk zvonku. Protože křivé, klikaté písmo má svou vlastní tvář."},"ICON-1066":{"nm":"Bezpečnostní krytka na řezák","de":"Když ostří balíkového nože nedbale míří na prst, nenápadně se postaví do cesty malý hrdina. Bezpečně chrání konečky prstů, uspěchané vzrušením z nové věci, až do posledního řezu."},"ICON-1067":{"nm":"Kousek bublinkové fólie","de":"Narodil jsem se k tomu, abych byl mačkán. S tím tichým lupnutím se ze dne nějak samo od sebe uvolní napětí. Někdy se stává, že mě milují déle než tu věc, kterou jsem sám obaloval."},"ICON-1068":{"nm":"Špendlík s časem doručení","de":"Špendlík, jenž přesně vyznačí, v kolik hodin to dorazí. I nejasné čekání se snáze snáší, jakmile má jednu jedinou souřadnici. Kolikrát do té doby vykoukneš ke dveřím, je čistě na tobě."},"ICON-1069":{"nm":"Klíčenka k výdejnímu boxu","de":"Malý společník pro toho, kdo pořád zapomíná kód od zásilkovny. Visí na svazku klíčů, klinká sem a tam, a jeho tichým uměním je vyloudit v tu rozhodující chvíli povzdech „aha, jasně“."},"ICON-1070":{"nm":"Cedulka na košík u dveří","de":"Jmenovka na košíku v koutě předsíně. Je na ní napsán němý slib: „nech to tady“. I když je prázdný, místo, jež čeká na něčí srdce, nikdy není osamělé."},"ICON-1071":{"nm":"Nálepka na zakrytí adresy","de":"Na krabici, kterou vyhazuješ, necháš jméno, ale adresu jen tak setřeš. To, že je v pořádku, aby všichni znali, sahá jen ke jménu – kde bydlíš, ať zůstane jen tvé tajemství. Ve chvíli, kdy odlepíš a nalepíš tuhle jednu vrstvičku, se zrodí drobný klid."},"ICON-1072":{"nm":"Štítek na dózu se svačinkami","de":"Štítek, jenž na první pohled prozradí, co je uvnitř dózy. Jenže háček je v tom, že když na něj napíšeš „svačinky“, nějak se ti uleví, i když víčko vůbec neotevřeš. Za tvou chuť k jídlu si štítek zodpovědnost nebere."},"ICON-1073":{"nm":"Malý přívěsek na řetízek","de":"Drobné zrnko, jež pod oblečením tiše sdílí tvou tělesnou teplotu. Vždy se dotýká místa, které nikdo nevidí, a právě proto je o to dražší. Nejbližší přítel, jenž kráčí spolu s tebou na hrudi."},"ICON-1074":{"nm":"Razítková podložka na tlapky","de":"Přitiskneš k tlapce a zůstane řada drobných otisků. Deník dnešní procházky, úhledně zapsaný na papíře – kdo kudy šel. První, inkoustem potřísněný krok je vždy ten nejzřetelnější."},"ICON-1075":{"nm":"Krytka kartáče na srst","de":"Malá krytka, jež si spolehlivě poradí se srstí zamotanou v kartáči. V období línání, kdy se za jedno kartáčování nashromáždí celá hrst, by se bez téhle krytky celý dům proměnil v načechranou sněhovou pláň. Pilná uklízečka, po níž není ani stopa."},"ICON-1076":{"nm":"Pouzdro na sáčky na procházku","de":"Malý domeček, jenž úhledně nosí sáčky potřebné na procházku. Jen ten, kdo se předem připraví, si prý chodí volně a s klidem – to tohle pouzdro každý den mlčky dokazuje. Ten jeden sáček, bez kterého bys byl v úzkých, kdybys na něj zapomněl."},"ICON-1077":{"nm":"Zakrývací jmenovka","de":"Jmenovka, jež nenápadně skryje skutečné jméno a ponechá jen přezdívku. Na světě existuje i taková něha, kterou si člověk nepřeje ukázat úplně každému. To zvláštní oslovení, jež znají jen zasvěcení, se tu jemně skrývá."},"ICON-1078":{"nm":"Podložka pod misku na vodu","de":"Ležím pod miskou na vodu a jsem stále vlhká. Zachycuji za ni kapky, jež stříkají na všechny strany, a chráním podlahu, aby zůstala suchá. Nikdo mě nechválí, ale ani já si nestěžuji."},"ICON-1079":{"nm":"Nit na spravování hraček","de":"Panenka s roztrženým švem se nevyhazuje, ale znovu sešívá. S každým místem, jež steh po stehu zaceluješ, znovu zesílí čas strávený s tou malou bytůstkou. Spravování je nakonec jen tiché odkládání rozloučení."},"ICON-1080":{"nm":"Náhrdelník se vzpomínkovou fotkou","de":"Srdce, jež nosí kolem krku snímek s nejzářivějším úsměvem. Ten den na fotce se místo ustrnutí v čase pohupuje s každým tvým krokem a doprovází tě až do dneška. Ten krásný okamžik se nikdy nezastaví."},"ICON-1081":{"nm":"Barevný čip nálady","de":"Kdyby i srdce mělo barvu, jakou barvu by mělo to tvé dnes? Ve chvíli, kdy vybereš jeden čip a položíš ho na stůl, se tiše rozlije pocit, jejž se slovy nedalo úplně vyjádřit. Barva soumraku i svítání jsou obě dobré – je to malé zrcátko, které tiše odráží toho tebe z toho dne."},"ICON-1082":{"nm":"Kulička se záznamem dne","de":"Když se den nachýlí, dnešek se v kuličce kulatě sroluje. To, co se ti povedlo, i to, co ti nešlo, se pečlivě uloží a kutálí se dál. Položíš si ji na dlaň a včerejší ty jsi trochu zahřátý – poplácá tě po zádech, že jsi i dnes žil dobře."},"ICON-1083":{"nm":"Sklenice s pochvalnými lístky","de":"Milá slova se rozptylují až příliš snadno, a tak je skládáš po jednom do téhle sklenice. Když se pochvaly nahromadí jako vůně, otevřeš víčko v noc, kdy je srdci prázdno. Znovu vytáhneš a přečteš útržek něhy, kterou ti kdysi někdo podal, a to dávné teplo znovu ožije."},"ICON-1084":{"nm":"Smírčí stuha","de":"Zamotané srdce se podobá uzlu – i jeho rozplétání vyžaduje pečlivost. Když dva lidé uchopí oba konce šňůrky a pomalu je táhnou, vznikne, aniž byste se nadáli, krásná mašle. Usmíření neznamená přetnout, ale znovu svázat – to ti tiše sděluje tahle šňůrka."},"ICON-1085":{"nm":"Žeton vděčnosti","de":"V den, kdy ti slovo „děkuji“ nechce přejít přes rty, podáš místo něj nenápadně žeton. Ruka, jež ho přijme, přečte celé tvé srdce z té drobné váhy. Upřímnost, jež dorazí dřív než slova – náklonnost se předává v jednom kulatém zrnku."},"ICON-1086":{"nm":"Značka přestávky","de":"I zkušebna, jež běžela celý den, potřebuje jeden takt na nadechnutí. Zavěsíš tuhle značku na dveře a čas se na chvíli zpomalí. Že píseň potřebuje k dýchání pomlku, to dobře ví každý, kdo prožil zadýchaný den."},"ICON-1087":{"nm":"Zásuvka na tajné pocity","de":"Existují dny, kdy nemůžeš vyložit úplně vše, co máš v srdci. V takové dny tiše uložíš smutek i rozechvění do jedné malé zásuvky v mysli a zavřeš ji. Teď je v pořádku je tam nechat – jednou přijde den, kdy ji pomalu otevřeš a všechno si roztřídíš."},"ICON-1088":{"nm":"Role nálepek s úsměvem","de":"Odtrhneš jedno políčko a na konečku prstu ti zůstane otisk úsměvu. Drobná veselost, kterou jemně nalepíš do rohu sešitu nebo na kamarádovu skříňku. Když na papíře vyjde malé sluníčko, den toho, kdo ho najde, se o kousek rozjasní."},"ICON-1089":{"nm":"Přívěsek se zvonečkem pozdravu","de":"Touha dotknout se tebe, jenž jsi daleko, se sroluje do jednoho zvonku. Zatřeseš jím a čistý zvuk za tebe předá pozdrav. Ve dnech, kdy ses neodvážil zeptat, jak se máš – tenhle drobný zvuk se svezl na větru a dorazí k tobě jako první."},"ICON-1090":{"nm":"Špendlík na obal proti jarnímu dešti","de":"V dny, kdy prší jarní déšť, se právě to, co si nejvíc vážíš, promáčí nejsnáz. Sepneš obal tímhle špendlíkem a kapky deště sklouznou stranou. Srdce, jež v náručí chrání jednu vzácnou knihu – jeden malý špendlík zastoupí tu něhu za tebe."},"ICON-1091":{"nm":"Letní chladicí náplast","de":"Jedno lupnutí na hřbet ruky vyčerpané letním vedrem. Chladivý pocit se rozlévá jako máta a pot z tebe trochu opadne. Tu svěžest ležení na dřevěné verandě a ovívání vějířem věrně napodobí list papíru velký sotva jako dlaň."},"ICON-1092":{"nm":"Kousek podzimní kostkované látky","de":"Kousek kostkované látky, jenž se podobá podzimnímu poli. Je to stopa po tom, jak někdo pečlivě zalátal opotřebené místo. Srdce, jež raději spravuje, než by vyhodilo – drobné kousky látky se spojí a znovu vřele oživí to, co bylo obnošené."},"ICON-1093":{"nm":"Klip na zimní rukavice","de":"Zimní rukavice nějak pořád utíkají, jedna po druhé. Spojíš obě tímhle klipem a prokřehlé ruce nikdy nezabloudí. Přání nic neztratit se usadilo v drobném kousku kovu a drží obě rukavice pěkně vedle sebe."},"ICON-1094":{"nm":"Voděodolná jmenovka do deštivé sezóny","de":"V období dešťů se v dešti rozpije i jmenovka. Tahle voděodolně upravená cedulka ochrání písmo i v lijáku. Řádek, jenž zůstane zřetelný i po dešti – aby se do konce nezapomnělo, čí to vlastně je."},"ICON-1095":{"nm":"Sklenice na uchování prvního sněhu","de":"První sníh mizí ve chvíli, kdy se dotkne ruky, a tak jsi do sklenice uložil aspoň to rozechvění. V tom skle uvězněný není sníh, ale srdce, jež se ten den rozbušilo. Zatřeseš a celá jedna zima se znovu rozvíří a odnese tě zpátky do toho rána."},"ICON-1096":{"nm":"Sváteční stuha na obálku","de":"Jedna červená stuha omotaná kolem sváteční obálky. Všichni vědí, že náklonnost v podávající ruce váží víc než to, co je uvnitř. Srdce, jež zabaluje spolu s přáním zdraví i požehnání dohromady, je pěkně svázané právě v téhle tenoučké stuze."},"ICON-1097":{"nm":"Páska na piknikové nádobí","de":"Rozprostřeš deku, rozbalíš svačinu a vítr pořád nadzvedává víčka. Sepneš nádobí pevně touhle páskou a piknik se nerozhází. Srdce, jež chce ochránit připravené jídlo až do konce, se schová v jedné drobné pásce."},"ICON-1098":{"nm":"Vzorková karta sezónní vůně","de":"Abys poznal roční období, aniž bys ji musel otevřít, je vůně toho ročního období uložena v jedné kartičce. Na jaře květiny, na podzim vůně suchého listí. Ve chvíli, kdy se dotkne špičky nosu, se vybaví celé to období vcelku – „tohle je dubnový vzduch“."},"ICON-1099":{"nm":"Podložka s klipem na cenovky","de":"Věčný problém stánku, kde cenovky pořád odlétaly, utišila jediná tahle deska s klipem. Pevně přidrží čísla a napřímeně je nastaví před zákazníka. První pozdrav obchodu začíná jedním poctivým řádkem, jenž se nikdy nepokřiví."},"ICON-1100":{"nm":"Obracecí cedule „Otevřeno“","de":"Obrátíš tuhle desku a pověsíš ji na dveře, a obchod se konečně probudí. Z „připravujeme“ na „vítejte“. Malý signál, jenž oznamuje začátek dne – místo, kterého se majitelova ruka dotkne jako první každé ráno."},"ICON-1101":{"nm":"Razítková podložka na věrnostní kartičku","de":"Když se všech deset políček zaplní, jako by se mělo přihodit něco dobrého. Každé razítko je krokem stálého zákazníka, láskou, která se hromadí. V každém otisku vtisknutém do podložky, dokud inkoust nezaschne, žije a dýchá malý slib návratu."},"ICON-1102":{"nm":"Krytka na ucho papírové tašky","de":"Ucho papírové tašky je vždy slabé proti váze nákupu. Nasadíte-li tuto krytku, provázek na pokraji přetržení znovu zesílí. Touha bezpečně donést obsah domů — malá součástka, která tuto cestu podepírá až do konce."},"ICON-1103":{"nm":"Miska na drobné u pokladny","de":"Tato miska tiše zbavuje váhavosti chvíle, kdy si drobné podáváme z ruky do ruky. Zvuk mincí, jak cinkají na své místo. Dávání i přijímání je díky této kulaté ohleduplnosti o poznání vřelejší."},"ICON-1104":{"nm":"Žeton na sbírání bodů","de":"Dnešní kroky se pěkně jeden po druhém ukládají do jediného žetonu. Podivná matematika, při níž se srdce zlehčuje tím víc, čím víc se toho nashromáždí. Radost z pomalého doplňování připomíná potěšení sledovat, jak se prázdný džbán, aniž bychom se nadáli, naplní až po okraj."},"ICON-1105":{"nm":"Číslovací špendlík na regál","de":"Do každého regálu je s láskou zapíchnuto malé číslo. Tichý průvodce, který napovídá, kde co najdete. Srdce, jež předem vyznačí místo, abyste nebloudili — i v takovém pořádku dřímá vřelost."},"ICON-1106":{"nm":"Kelímek na ochutnávkové špejle","de":"Malý kelímek, který nabízí sousto k ochutnání napíchnuté na špejli. I váhavý zákazník se u tohoto jediného kousku nesměle otevře. Pohostinnost slov „ochutnejte jeden“ visí na hrotu špejle a přidrží kroky toho, kdo přišel poprvé."},"ICON-1107":{"nm":"Držák rezervačního seznamu","de":"Jména dnešních hostů stojí v tomto držáku úhledně v řadě. Něžný slib, že i čekání má svůj pořádek. Postavit jediný list rovně vzhůru se stává první pečlivou přípravou, jak s péčí přivítat něčí den."},"ICON-1108":{"nm":"Kolíček na fotografickou šňůru","de":"Na zeď se natáhne šňůra a fotografie se na ni jedna po druhé připnou kolíčky. Usměvavé okamžiky visí bok po boku a schnou jako prádlo. Zavěsíte-li vzpomínky tam, kam dopadá slunce, při každém průchodu znovu zavlaje ten den plný smíchu."},"ICON-1109":{"nm":"Malý koberec do rohu","de":"Malý koberec položený u kraje pokoje. Místo, které jako první rozprostírá teplo na studenou podlahu. Ta píď, které se holé chodidlo dotkne jako první — tady se konečně s úlevou a příjemnou ospalostí usadí špičky nohou toho, kdo se vrátil domů."},"ICON-1110":{"nm":"Plátno na jmenovku dveří","de":"Kus látky, který jemně zakrývá jmenovku na dveřích. Na chvíli skrýt jméno je také svého druhu domácí půvab. Cíp, který půvabně splývá přes hranici mezi vnitřkem a vnějškem — dnes na něm měkce visí přání v klidu si odpočinout."},"ICON-1111":{"nm":"Klip na kabel osvětlení","de":"Tento klip úhledně přidrží prověšenou šňůru osvětlení. Ruka, jež narovná cestu, aby se světlo nerozptýlilo. Když se za soumraku uhladí jedna neposedná šňůra, uklidní se jak světlo v pokoji, tak i srdce."},"ICON-1112":{"nm":"Magnetická krytka na plakát","de":"Malá magnetická krytka na připevnění plakátu na zeď. Papír drží na svém místě, aniž by vznikla jediná dírka po napínáčku. Ruka, která zachází s tím, co si cení, je vždy jemná — a právě tady je uloženo přání nic nepoškodit."},"ICON-1113":{"nm":"Třásňová šňůra na závěs","de":"Střapcová šňůra, jež přiváže cíp záclony na jednu stranu. Otevírá půvabnou cestu, kudy může vstoupit ranní slunce. Jediné zatažení za třásněmi zdobenou šňůru a do pokoje se rázem vplíží a zůstane jasný nový den."},"ICON-1114":{"nm":"Štítek na podstavec svíčky","de":"Malý štítek nalepený na podstavec vonné svíčky. Úhledně na něm stojí, jaká vůně hoří a kdy byla poprvé zapálena. Dát jméno vůni, kterou máme rádi — právě tato úpravnost činí vzduch v pokoji ještě něžnějším."},"ICON-1115":{"nm":"Gumové nožičky pod dekorační poličku","de":"Čtyři gumové nožičky, které podpírají poličku, aby se nekymácela. Z neviditelného místa mlčky snášejí veškerou tíhu. Malé a nízké, snadno přehlédnutelné, ale právě to, co drží pevně úplně dole, nakonec vydrží nejdéle."},"ICON-1116":{"nm":"Přívěsek se směrovou šipkou","de":"Pro toho, kdo váhá, kterým směrem se vydat, tiše ukazuje cestu jediná šipka. Něžné gesto, které říká: neztrať svou cestu. Díky srdci, které někdo dopředu postavil na každé rozcestí, i dnes jdeme dál, aniž bychom zabloudili."},"ICON-1117":{"nm":"Klíčenka pozvání na ostrov","de":"Klíčenka, kterou do ruky vloží ten, kdo vás zve na ostrov. Přijmete-li ji, jste od nynějška také jedním z rodiny zdejších. Pohostinnost, jež vítá cizího hosta do vřelého nitra, je pevně uložena v malém slibu visícím na konci šňůrky."},"ICON-1118":{"nm":"Teploměrný žeton vztahu","de":"Jediný žeton lišácky prozradí teplotu mezi dvěma lidmi. Ať je to ještě ostýchavá modř, nebo se už proměnila v teplou karmínovou. Rychlost, jakou náklonnost sílí, se těžko měří, ale dlaň to teplo vycítí jako první."},"ICON-1119":{"nm":"Krabička vzorků vkusu","de":"Když ještě nevíte, co má někdo rád, sesbíráte drobné vzorky do jedné krabičky a podáte mu ji. V radosti z vybírání pomalu roste vlastní vkus. Co se nakonec stane tím pravým — krabička je plná vzrušující možnosti."},"ICON-1120":{"nm":"Rezervační špendlík na hlídání","de":"Slib postarat se o někoho je zřetelně zapíchnut do tohoto jediného špendlíku. Napíšete-li jméno a čas, srdce neztratí cestu. Ono vřelé vzájemné vypomáhání, kdy jsme se střídali v hlídání dětí jeden druhého, tu žije a dýchá dodnes."},"ICON-1121":{"nm":"Kapsle na záznam růstu","de":"Tak jako se na veřejích dveří vrství čárka po čárce naměřená výška, tato kapsle tiše zapečeťuje včerejší tebe. Až daleko v budoucnu otevřeš víčko, poznáš to. Jak daleko dokázaly ty kdysi drobné krůčky dojít."},"ICON-1122":{"nm":"Stužka na vzpomínku prvního setkání","de":"Chvění prvního sevření rukou je jemně přivázáno do jediné stužky. Uzel tu není proto, aby byl rozvázán, ale aby teplo toho dne dál žilo na zápěstí."},"ICON-1123":{"nm":"Štítek do Mého pokoje","de":"„Tady je moje místo.“ V okamžiku, kdy se na roh stolu nalepí jediný malý štítek, kdysi cizí pokoj se konečně nadechne a stane se Mým pokojem. Jmenovka je první místo, kam se usadí srdce."},"ICON-1124":{"nm":"Sklenice na kuličky blízkosti","de":"Zatřeseš a kuličky se kutálejí — kutálí se i zvuk toho, jak se dva lidé přibližují o kousek blíž. Až se nádobka naplní po okraj, stačí zavolat jméno a smích už bude čekat, aby tě přivítal jako první."},"ICON-1125":{"nm":"Pečeť přípravy na debut","de":"Poslední list, který zavírá obálku. Až sem to byla příprava, obrátíš stránku a je to jeviště. Když ji prstem pevně přitiskne, praktikant se nadechne a uklidní dech. Konečně, je to tady, začátek."},"ICON-1126":{"nm":"Voda","de":"Nejobyčejnější, a proto nejvzácnější. Ve zkušebně za svítání, kde jsou zhasnutá světla, pozvedne jediný doušek toho, kdo klesl k zemi, zpátky na nohy. Něha bez vlastního tvaru, jež se vlije do jakékoli nádoby."},"ICON-1127":{"nm":"Čistá voda","de":"Průzračnost, v níž jasně prosvítají i oblázky na dně. Horský pramen se svou čistotou nikdy nechlubí. Srdce, které nemá co skrývat, je vždy takové — vidět až na samé dno."},"ICON-1128":{"nm":"Mořská voda","de":"V okamžiku, kdy se dotkne jazyka, se přivalí vzdálené vlny. V jediném slaném doušku je rozpuštěn celý obzor, rackové i přístav, který jsme opustili. Moře v paměti navždy zůstává slané."},"ICON-1129":{"nm":"Led","de":"Na dlani se pomalu zmenšuje, mizí přesně tak, jak ho sevřete. Ať vypadá jakkoli tvrdě, ví, že se nakonec vrátí zpět k vodě. Led je řeka, jež si na chvíli zadržela dech."},"ICON-1130":{"nm":"Sněhová koule","de":"Pevně stlačená hrouda letí bíle a protíná uličku. Rozpustilý smích a tváře zrůžovělé zimou. Nejbělejší hračka, kterou zima potají vloží dětem do rukou."},"ICON-1131":{"nm":"Hlína","de":"Chová v sobě semínko, pije dešťovou vodu a beze slova přijímá procházející stopy. Černá kůže, jež obejme úplně všechno. U prvního místa všeho, co roste, leží právě tahle hrst."},"ICON-1132":{"nm":"Úrodná hlína","de":"Zaboříte-li prsty dovnitř, měkce vás obejme černá mastnota. Právě tady bylo tajemství, proč babiččina zahrádka byla každý rok tak zelená. Dobře odležená hlína šeptá vůní hnoje o bohaté úrodě."},"ICON-1133":{"nm":"Jíl","de":"Ve chvíli, kdy nasákne vlhkostí, poslušně přijme jakýkoli tvar. Pod dotekem rukou se stává ptákem, stává se miskou — něžné tělo. Zatímco se kruh točí, hrst hlíny se konečně poprvé pustí do snění."},"ICON-1134":{"nm":"Písek","de":"Drobná zrnka, jež se vám mezi prsty tiše vytrácejí. Čím pevněji je sevřete, tím rychleji protečou — čím dál víc připomínají čas. V jedné hrsti pláže spí nespočet včerejšků."},"ICON-1135":{"nm":"Oblázky","de":"Kameny obroušené do kulata na břehu potoka. Jsou stopou toho, jak je voda dlouho a trpělivě hladila, dokud neztratily ostré hrany. Čím dál se oblázek dokutálel, tím jemněji se vám vloží do dlaně."},"ICON-1136":{"nm":"Kámen","de":"Hrouda ležící bezstarostně u cesty. Někdo do ní bezmyšlenkovitě kopne a jde dál, někdo ji tiše zvedne a postaví z ní věž. Stejný kámen se podle srdce toho, kdo ho drží, stává buď břemenem, nebo přáním."},"ICON-1137":{"nm":"Dlažební kámen","de":"Široký plochý kámen, jenž protíná nádvoří starého paláce. Stovky let obuvi po něm šlapaly, až se uprostřed prohloubil. Každý, kdo na něj vkročí, jedním krokem přidá ještě jednu vrstvu času."},"ICON-1138":{"nm":"Vápenec","de":"Mušle z dob, kdy tu bývalo moře, se vrstva po vrstvě ztvrdly v bílý kámen. V peci se rozpustí na vápno a natře zdi do čista bíla. Ať vypadá jakkoli klidně, je to kámen, jenž v sobě chová celou jednu éru."},"ICON-1139":{"nm":"Uhlí","de":"Starý les, jenž upadl do černého spánku. Kapradiny ze stovek milionů let staré doby, pevně sražené hluboko v podzemí. Zapálíte-li ho, dávno pohřbené sluneční světlo se s plamenem znovu probudí."},"ICON-1140":{"nm":"Dřevěné uhlí","de":"Oheň v sobě uchová, ale kouř mlčky pohltí. Dřevo zčernalé v peci na uhelném milíři beze slova rozkvete do ruda na roštu ohniště. Čím tišší věc, tím déle hřeje."},"ICON-1141":{"nm":"Větvička","de":"Větev, jež se raději mlčky ohýbala, než by se zlomila, zná umění poddat se. V každém místě, kde vydržela drsný vítr, se vytvořil suk, a opravdová pevnost je nakonec vždy jen stopou toho, jak dobře se dokázala ohnout."},"ICON-1142":{"nm":"Kmen","de":"V přeříznutých letokruzích leží kulatě naskládáno sto jar a zim. Léta, jež strom prožil, tu leží celá vyrovnaná a tiše čekají, až na ně přijde řada stát se sloupem domu."},"ICON-1143":{"nm":"Řezivo","de":"Při každém tahu hoblíku se odhalí další vonná vrstva letokruhu. Zatímco se drsné dřevo mění v hladké, na podlaze se hromadí piliny jako žlutý sníh. Ruka, jež jej opracovává, probouzí jeho užitečnost."},"ICON-1144":{"nm":"Prkno","de":"Pokládá podlahu, sbíjí lavici, obepíná plot. Když se rovně naříznutá prkna sejdou jedno po druhém, konečně vznikne místo, kde mohou žít lidé. Obyčejné věci se nakupí a stanou se domovem."},"ICON-1145":{"nm":"Bambus","de":"Uvnitř dutý, přesto vzpřímený proti větru. Jeho odhodlání, s nímž se u každého kolénka přeruší a znovu vyraší, si přáli napodobit staří učenci. Právě tady stojí věc, jež je díky své prázdnotě ještě vzpřímenější."},"ICON-1146":{"nm":"Korek","de":"Stisknete-li ho a pustíte, znovu se nadme do původní tloušťky. Při pohledu na tuto lehkou, a přesto neochvějnou strukturu pochopíte, že měkkost rozhodně neznamená slabost. Od zátek na lahve až po nástěnky tiše všechno podpírá."},"ICON-1147":{"nm":"Tráva","de":"I pošlapaná se s dalším deštěm znovu postaví. Zelená vytrvalost, jež bez jediného jména celá pokrývá pole. Nepodceňujte její malost — první, co ohlašuje jaro, je vždy právě toto nízké místo."},"ICON-1148":{"nm":"Sláma","de":"To, co po sklizni zůstane na poli žlutě ležet. Spletená se stane střechou, rozprostřená teplým lůžkem. Srdce, jež i po odevzdání všech zrn nakonec pokrývá lidi až do posledního kousku."},"ICON-1149":{"nm":"Rákos","de":"Jakmile ji ovane vítr, šustí, šustí a celý břeh řeky rozezpívá. Stébla, jež uvnitř dutá pláčou tím dál. Rákos se ani trochu nestydí za to, že jeho kolébání je zároveň jeho písní."},"ICON-1150":{"nm":"Bavlna","de":"Když puklina vyzrálé tobolky s cvaknutím pukne, rozkvete malý mráček. Tento lehký, měkký chmýří se stane přízí a stane se šatem, jenž v mrazivé zimní noci tiše zahřeje něčí ramena."},"ICON-1151":{"nm":"Ovčí vlna","de":"Přiložíte-li ji na ruku, zůstane na ní tuk a tiše přetrvá teplo. Kabát, jenž si ovce navlékla na vlastní tělo, aby vydržela chladné hory. Ostříhané teplo se nyní přesouvá do lidské zimy."},"ICON-1152":{"nm":"Nit","de":"Ať je jakkoli tenká, sotva viditelná, vždy je to právě ona, kdo znovu spojí dva rozpadlé cípy. Sama je slabá jako jedno vlákno, ale spletená se stává celým kusem látky. Při spojování na tloušťce vůbec nezáleží."},"ICON-1153":{"nm":"Látka","de":"Útek a osnova se nesčetněkrát zkříží a utvoří jeden celý pás. Je výsledkem toho, že vlákna, jež by se sama rozpletla, se pevně chytila jedno druhého. Že čím hustší tkanina, tím teplejší — platí přesně stejně i mezi lidmi."},"ICON-1154":{"nm":"Kůže","de":"Čím víc se používá, tím víc se do ní vsakují stopy dotyků a postupně se podobá svému majiteli. Zatímco se počáteční tuhost dřuje, barva sytí a struktura měkne. Ten lesk vrytý časem nedokáže napodobit nic jiného."},"ICON-1155":{"nm":"Pírko","de":"Lehké natolik, že na dlani necítíte žádnou váhu. Jediné vlákno, v němž zůstala uchována vzpomínka na let oblohou. Nezapomeňte prosím, že nejlehčí věc vystoupala nejvýše."},"ICON-1156":{"nm":"Mušle","de":"Náhle se vybaví babiččina slova, ať si ji přiložíte k uchu. V jejím duhovém vnitřku je vyryto celé moře, jež jsme opustili, takže i z prázdné mušle je slyšet vlnobití dávno minulého času."},"ICON-1157":{"nm":"Korál","de":"Ztvrdlý jako kámen, přesto kdysi jistě byl dýchajícím společenstvím. V pomalém moři tráví stovky let rozvětvováním svých ramen. Nejpevnější větev vyroste jen po tom nejdelším čekání."},"ICON-1158":{"nm":"Perla","de":"Neschopna snést dráždění jediného zrnka písku, ústřice je tiše zahalila do světla. Obejmeš-li bolest a zaobléš ji, takhle nádherně se rozzáří — malá útěcha, kterou nabízí moře."},"ICON-1159":{"nm":"Mořská řasa","de":"Zelená stuha, jež se kluzce rozprostírá po skalách odhalených odlivem. Sevřete-li ji v ruce, udeří vás ostrá vůně moře. Bez kořenů, jen s tělem svěřeným proudu, moře tiše pěstuje svou zahradu."},"ICON-1160":{"nm":"Sušené řasy nori","de":"Přiblížíte-li jeden černý list krátce k ohni, zezelená a rozšíří se lákavá vůně. To ráno, kdy jsme jej omotávali kolem čerstvě uvařené rýže. Ať je jakkoli tenoučký, s lehkostí obejme štěstí celého jídla."},"ICON-1161":{"nm":"Sůl","de":"Jsem bílý krystal, který moře zanechalo na slunci. Jedna špetka prohloubí fádní polévku, ale sklouzne-li ruka, přebije všechny chutě. Jen prsty, jež znají tu pravou míru, mě dokážou skutečně ovládnout."},"ICON-1162":{"nm":"Střep skla","de":"Teprve na místě, kde se rozbilo, dokáže konečně ohnout světlo v duhu. Dovednost, o níž nevědělo, dokud bylo celé. I rozbitá věc si prý ponechává svůj podíl slunečního svitu, na který má nárok — tiše to prozrazuje střep ležící u okna."},"ICON-1163":{"nm":"Sklo","de":"Být průhledný neznamená jen to, že nemáte co skrývat. Znamená to, že jste kvůli propuštění světla beze zbytku vymazali vlastní podobu. I v tom, jak neviditelně tam prostě setrvává, je při dotyku ruky cítit chladná úhlednost."},"ICON-1164":{"nm":"Skleněná láhev","de":"Musí být uvnitř prázdná, aby mohla něco pojmout. Ať je to džem, hrst polních květin nebo přeložený dopis, jméno se jí mění podle toho, co do ní vstoupí. Nádoba, jež se nebojí prázdnoty, je ta nejštědřejší."},"ICON-1165":{"nm":"Prázdná láhev","de":"Mám ráda ticho, jež přichází po vypitém posledním doušku. Někdo mě odhodí, někdo mě vypláchne a postaví na parapet, aby mě naplnil slunečním svitem. Nalézt znovu využití na místě, kde vše skončilo — to je druhý život vyprázdněných věcí."},"ICON-1166":{"nm":"Papír","de":"Ležím rozprostřený doběla, připravený zapsat cokoli. Vždy jsem to já, kdo se dívá nejdéle do srdce toho, kdo váhá nad první řádkou. Trpělivost čistého listu je o píď hlubší než sám inkoust."},"ICON-1167":{"nm":"Starý papír","de":"To, co zežloutlo, není stárnutí, ale vytrvalost. V každém záhybu se vsáklo teplo rukou, které jej rozevíraly a četly. Starý papír, aby nebyl zapomenut, zapisuje svou vlastní barvou čas, jenž uplynul."},"ICON-1168":{"nm":"Inkoust","de":"Začíná jako jediná kapka, stává se větou, a jakmile zaschne, zůstává jako slib. Rozmáznutý je právě takový, jaký je — stopa toho dne. Protože mým úkolem je učinit věci nezvratnými, lidé mě tisknou o něco pečlivěji."},"ICON-1169":{"nm":"Železná ruda","de":"Kámen, jenž spal rudým spánkem hluboko v zemi. Teprve po průchodu ohněm konečně vydá železo, jež v sobě skrývá. Tvrdost není tvrdá od počátku — je to jméno, které dostane, až projde žárem."},"ICON-1170":{"nm":"Železný ingot","de":"Teprve poté, co ruda přestála oheň, vychladla v jedinou hroudu. Tento chladný, těžký tvar se stává mostem, mečem i motykou. Protože jeho účel zatím není určen, může se stát čímkoli."},"ICON-1171":{"nm":"Měděná ruda","de":"Vyšla ze země oděná do zelené patiny barvy nezralého jablka. Roztavíte-li mě, rozezní se zvon, postaví se socha, potečou dráty. I ve spánku v temné podzemní zemi jsem vždy čekala, až na mě přijde řada stát se něčím."},"ICON-1172":{"nm":"Měděný ingot","de":"Necháte-li ho dlouho u sebe, sám si vlastníma rukama ušije modrý šat. Někdo tuto barvu nazve vadou, jiný ji hladí jako vzor let. Kov, jenž se nestydí za svou proměňující se barvu, je milován nejdéle."},"ICON-1173":{"nm":"Zlatá ruda","de":"Zrnko nalezené opakovaným proplachováním říčního písku. Není vzácné proto, že by bylo vzácné jako takové — je vzácné, protože se nemění. Staří lidé je vkládali do rukou jako památku se slovy, ať se podobáme srdci, jež nerezaví."},"ICON-1174":{"nm":"Zlatý ingot","de":"Leží jako jediná hrouda, aniž by pobledl nebo zrezl. Vyslechl nejvíc z lidské chamtivosti, a přesto sám po ničem netouží. Jen těžké mlčení, věrné jedinému úkolu — zářit."},"ICON-1175":{"nm":"Kovový šrot","de":"Nedosloužil — čeká na svůj další úkol. Ohnuté hřebíky a promáčklé plechovky se sejdou dohromady a znovu potkají žhavý oheň. Slovo „odhozený“ pro mě znamená jen: chvíli si odpočívám."},"ICON-1176":{"nm":"Šroub","de":"Sám nesvedu nic. Teprve když se zatočím a stáhnu dvě desky pevně k sobě, konečně splním svůj úkol. Dovednost malého tělíčka přidržet velkou věc — i v té svírající síle je vloženo úsilí."},"ICON-1177":{"nm":"Hřebík","de":"Jednou zatlučen, jen tak neustoupím. S každým úderem kladiva se neprohlubuje rána, ale slib. Jde-li o pevné spojení, ochotně nastavuji svou hlavičku."},"ICON-1178":{"nm":"Ozubené kolo","de":"Zatlačím zub souseda a otáčíme se spolu. Nesnažím se hnát sám kupředu, ale umím se přizpůsobit tempu vedle sebe. Jako hodiny, jejichž čas plyne jen tehdy, když se zuby zaberou do sebe, věřím, že souznění je samo o sobě pohybem."},"ICON-1179":{"nm":"Pružina","de":"Čím víc je stlačena, tím víc v sobě shromažďuje sílu vrátit se zpět. Ohnout se neznamená vzdát se, ale připravit se znovu se narovnat. Malá spirála, jež odrazí přesně tolik, kolik nárazu pohltila — tam, kde je pružnost sama pevností."},"ICON-1180":{"nm":"Elektrický vodič","de":"Navenek skromný plášť, uvnitř cesta, jež plyne bez ustání. Z neviditelných míst přenáší světlo i zvuk. Jako ruka, jež mlčky propojuje věci v zákulisí, je to cesta o to důvěryhodnější, oč méně je vidět."},"ICON-1181":{"nm":"Baterie","de":"Do svého malého těla postupně ukládá jasné světlo celého půldne. Až se vyčerpá, prostě ji zase naplní, říká, a prázdnotu nikdy nepovažuje za konec. Chová v sobě malý večer, jenž rozjasní něčí dlouhou noc."},"ICON-1182":{"nm":"Žárovka","de":"Jediné tenoučké vlákno se rozžhaví do ruda a odsune tmu stranou. Nespaluje své tělo, aby pokoj hřálo, ale aby jej rozjasnilo. Nejžhavější je v okamžiku, kdy se rozsvítí, a proto i nejjasnější — malé slunce jediného okamžiku."},"ICON-1183":{"nm":"Čočka","de":"Shromažďuje rozptýlené světlo a jasně je soustředí do jediného bodu. Tiše přivolá jak vzdálenou hvězdu, tak drobné písmenko na dlani. Aby pomohla vidění, sama skrývá svou vlastní podobu — čirý, kulatý dohazovač."},"ICON-1184":{"nm":"Guma","de":"Ať ji stisknete nebo natáhnete, nakonec se vždy vrátí na své místo. I ti, kdo ji hanili za měkkost, si mě v deštivý den obují. Práce, při níž se drsný náraz vstřebá měkce — i v této poddajnosti žije vytrvalost."},"ICON-1185":{"nm":"Plastový úlomek","de":"Malý úlomek, jenž se odlomil od hlavního tělesa. Málem skončil v odpadu, ale sejde-li se jich víc, znovu se stanou něčím novým. Není lehký proto, že je malý — je částí něčeho, co dokáže díky své lehkosti dojít daleko."},"ICON-1186":{"nm":"Lano","de":"Teprve spletením mnoha pramenů vznikne jediný provaz. Samo se snadno rozplete, ale spletené dokáže táhnout loď i vázat náklad. Starý uzel spolupráce, drsný na dlani, o to houževnatější, oč víc byl společně zkroucen."},"ICON-1187":{"nm":"Plachtovina","de":"Nenávidí vítr, naopak jej přijímá plnou hrudí. Jen když se napne a nadme, pošle loď daleko, takže i protivítr se pro mě stává silou. Umění postupovat vpřed tím, že se nebrání drsnému, ale objímá jej — tomu jsem se naučila na moři."},"ICON-1188":{"nm":"Úlomek kotvy","de":"Je jen jeden roh kotvy, ale svou váhu si pamatuje celou. Časy, kdy se zachytávala hlubokého dna a zastavovala loď. I teď, odlomená, je to těžký úlomek, jenž zná váhu setrvání."},"ICON-1189":{"nm":"Lodní hřebík","de":"Hřebík, jenž bod po bodu přidržoval palubu kymácející se na vlnách. I zrezlý do ruda solí neopustil své místo až do konce. I v pevném držení něčeho plovoucího je zapotřebí vytrvalosti."},"ICON-1190":{"nm":"Nepromokavá plachta","de":"O práci bránit dešti nedělá zbytečné řeči. Mlčky přijímá vše, co se snáší shora, a chrání to, co je pod ní, v suchu. Není okázalá, přesto je to spolehlivá jediná vrstva, jež zakryje něčí náklad před promočením."},"ICON-1191":{"nm":"Barvivo","de":"Teprve když tiše prosákne do bavlněné látky, stane se barvou. Ať indigová, nebo mořenová, staré matky barvily konečky prstů, když do látky vtiskávaly barvu. I v usazování a vsakování je hloubka, jež jen stěží vybledne."},"ICON-1192":{"nm":"Vonný olej","de":"Stačí jediná kapka a celým pokojem se náhle rozprostře široké pole. Host, jenž dorazí jako první, ačkoli je neviditelný. Krajina, jež se jako první dotkne špičky nosu a nenápadně zatahá za lem spících vzpomínek."},"ICON-1193":{"nm":"Vosk","de":"Zahřeje-li se, teče, vychladne-li, ztuhne a udrží svůj tvar. Putuje mezi měkkostí a pevností a tiše obtiskne cokoli. Něžný materiál, jenž uzavírá, zapečeťuje a leští, měnící svůj výraz podle teploty."},"ICON-1194":{"nm":"Svíčka","de":"Pomalu roztává vlastní tělo, aby rozjasnila jeden díl tmy. Až celá dohoří, zůstane jen zkrácená výška, ale čas, kdy hřála něčí noc, nezmizí. Rovný knot, jenž zná umění zářit, i když se sám zmenšuje."},"ICON-1195":{"nm":"Kompost","de":"Hnijící věci se sejdou dohromady a stanou se tou nejúrodnější hlínou. Odhozené slupky a suché spadané listí se tak stávají pokrmem pro jarní klíčky. Na místě, o němž jsme si mysleli, že skončilo, si další život tiše nabírá první dech."},"ICON-1196":{"nm":"Rýže","de":"Než se jedno zrnko ocitne v dlani, ruka se ho dotkne osmdesát osm krát. Od sázení sazenic až po mlácení cepem, celý farmářův rok je celý uložen v tomto drobném zrnku. Miska páry stoupající z rýže je vlastně něčí čtvero ročních období."},"ICON-1197":{"nm":"Hnědá rýže","de":"Se sotva odloupnutou slupkou si zachovala svou původní barvu. To, že chutná čím dál oříškověji, čím déle ji žvýkáte, je chuť poctivosti, jež nikam nespěchala. Pevná umíněnost zrna, jež odmítlo hladké omletí a ponechalo si drsnou strukturu."},"ICON-1198":{"nm":"Pšenice","de":"Pamatuje si zlaté pole, jež se ve větru jednohlasně sklánělo. Stává se chlebem, nudlemi i těstem na halušky a hřeje stoly po celém světě. Obilí, jež právě proto, že je tak obyčejné, proniklo o to hlouběji do lidského žití."},"ICON-1199":{"nm":"Mouka","de":"Teprve poté, co se stane jemným bílým práškem, se konečně připraví stát se čímkoli. Potká-li vodu, nabobtná, potká-li oheň, upeče se. Protože nemá pevný tvar, je to poddajný základ, jenž získá podobu podle toho, jak jej ruce hnětou."},"ICON-1200":{"nm":"Těsto","de":"Mouka a voda se pod dlaní spojí v jednu hroudu. Čím víc se hněte, tím je pružnější, čím déle čeká, tím víc kyprě nabobtná. Uspěcháš-li to, ztuhne — čas kynutí prostě nejde uspíšit, říká stará pekárna."},"ICON-1201":{"nm":"Strouhanka","de":"Otřeseš z prstů bílý prach a než se naděješ, bílé jsou i rukávy. V trojobalu je křupavá, navršená připomíná první sníh. Je to nejlehčí stopa, kterou po sobě zanechá upečený bochník chleba, ale i v maličkosti dokáže vyrůst užitečnost."},"ICON-1202":{"nm":"Těstoviny","de":"Ve chvíli, kdy rozevřeš hrst jako vějíř do vroucí vody, do kuchyně jako by dolehlo vzdálené sluneční světlo. Dlouhé nudle jsou prací zápěstí a al dente je srdce, které umí čekat, i když je ještě mírně nedovařené. Podívej se na ten lesk, jak se stáčí kolem vidličky."},"ICON-1203":{"nm":"Instantní nudle","de":"Za svítání, kdy je už smyt veškerý jevištní make-up, se potajmu otevře jeden sáček. Tři minuty, než změknou nudle, jsou nejsoukromější chvílí celého dne. S foukáním do horkého sousta chladne i napětí a za zamlženými brýlemi dnešek tiše končí."},"ICON-1204":{"nm":"Rýžový koláč","de":"Teprve když rýže vydrží bití v hmoždíři, stane se z ní tteok. Jako prostý koláč, jako indžolmi, jako songpchjon – totéž zrno získá stovku jmen podle ruky, která je hnětla. Na sváteční tabuli promlouvá dřív náklonnost než ústa – jídlo, které chutná nejlépe, když se dělí."},"ICON-1205":{"nm":"Rýžové koláčky do polévky","de":"Když nakrájíš válcovitý koláč našikmo, plátky jsou kulaté jako drobné mince. Plavou v bílém vývaru – jsou to rýžové koláčky, nebo kulatá přání? Sníst k snídani na Nový rok celou misku znamená přidat si rok k věku – tak něžně tahle země počítá čas."},"ICON-1206":{"nm":"Brambora","de":"Oklepeš hlínu a objeví se kulatá tvář. Hlíza, která mlčky sílila i ve větru na svazích Kangwonu – dušená je nadýchaná, smažená voňavá. I ve dnech s prázdnou kapsou poctivě naplnila žaludky celé rodiny."},"ICON-1207":{"nm":"Batát","de":"Když se na rohu uličky objevil sud s pečenými batáty, byl to začátek zimy. Odloupneš alobal a žlutá pára nejdřív zahřeje prsty – ta sladkost je odměnou kořene za vydrženou zimu. Teplo, které se dobře fouká, půlí a dělí."},"ICON-1208":{"nm":"Mrkev","de":"Jediný oranžový klín, který se rovně zavrtává do hlíny. Člověk by řekl, že ji mají rádi jen zajíci, ale osmažená probudí skrytou sladkost a v polévce přidá i barvu. Staří lidé, kteří tvrdili, že prospívá očím, měli většinou pravdu."},"ICON-1209":{"nm":"Ředkev","de":"Stačí jeden bílý, těžký kořen a zimní stůl je zajištěný. Mrazivě svěží jako tongčchimi, osvěžující jako polévka s ředkví, křupavá jako kkakdugi. Nic nepřijde nazmar – i zelené natě se suší pod okapem a uchovávají jako siräigi. Šetrná zelenina."},"ICON-1210":{"nm":"Cibule","de":"Loupeš slupku a po tváři skane slza. I štiplavé, pálivé maso zesládne jako lží, jakmile se setká s rozpáleným olejem. Jméno zapsané téměř v první řádce každého korejského jídla – tichý hrdina, který mlčky pokládá základ vůně."},"ICON-1211":{"nm":"Jarní cibule","de":"Nasypeš najemno nakrájenou bílou spodní část a zelené listy na vývar, a teprve tehdy se zdá miska konečně hotová. Zbylý kořínek zapíchneš do sklenice s vodou a znovu vesele vyroste – malá okenní zahrádka pro hospodyňky."},"ICON-1212":{"nm":"Česnek","de":"Šest stroužků se kulatě sejde v jednu hlavu. Ten pálivý kořen, který prý proměnil medvěda v ženu. Rozťukáš ho hřbetem nože a vůně se rázem probudí do plamene – bez hrsti česneku nemá smysl ani kimči, ani žádný guláš."},"ICON-1213":{"nm":"Zázvor","de":"Malý hrbolatý kořen jako propletený uzel. Stačí jediný plátek a utiší rybí pach, prochladlé tělo zahřeje zevnitř. Vřelý šálek s medem, který jsi pil v nocích, kdy tě soužila rýma, začínal právě touto štiplavou ostrostí."},"ICON-1214":{"nm":"Pekingské zelí","de":"Naložíš do soli hutné, nabité listy, a teprve tehdy se otevře první kapitola kimči. To, co se na sklonku podzimu hromadilo na každém dvoře jako hory. Když se celá rodina sesedla, aby naložila jednu hlávku, byl to slib, že společně přečkají dlouhou zimu."},"ICON-1215":{"nm":"Zelí","de":"Loupeš list po listu z kulatě stočených vrstev a zdá se to bez konce, takže se srdce nakonec samo zklidní. Spařené je jemné, osmažené sladké. Zelenina, která pod neohrabaným zevnějškem skrývá nečekanou něhu."},"ICON-1216":{"nm":"Hlávkový salát","de":"Do prohnutého listu položíš kousek masa, přidáš lžičku ssamdžangu a nacpeš si plná ústa. U kulatě sedícího kruhu, kde se jí zabalené sousto, každý tiše odloží formality – není to nic jiného než zelená pohostinnost."},"ICON-1217":{"nm":"Listový salát","de":"List, který v koutě zahrádky vyraší jako první. Otrháš ho a on zas doroste, celé léto tak plní stůl. Ta svěží zelená vůně, opláchnutá studenou vodou a zabalovaná rukama, je pro někoho chutí celého domova."},"ICON-1218":{"nm":"Špenát","de":"Ta zelená z kresleného seriálu, po jejímž vyprázdnění konzervy vytryskla síla. Spařený se scvrkne do jediné hrstky, ale vůně a síla zůstávají netknuté. Dobrý promnutý rukama do salátku i rozpuštěný v hrsti do misového vývaru – zelenina, kterou rozhodně nelze podceňovat jen proto, že je běžná."},"ICON-1219":{"nm":"Kapradí","de":"Utrhneš křehké výhonky, které nabídla jarní hora, uvaříš je a znovu usušíš. Teprve po té dlouhé námaze se dostanou na obětní stůl i do bibimbapu. Kolik práce si vyžádá, tolik péče se do ní vrství – vzácná bylina, kterou hora vypěstovala za jednu sezónu."},"ICON-1220":{"nm":"Horské byliny","de":"Zdánlivě bezejmenný, přitom každý s vlastní vůní – dar jara. Babiččiny ruce na horské stezce na první pohled poznají, který list je k jídlu. V jednom koši bylin přijde s vůní celá jedna sezóna."},"ICON-1221":{"nm":"Pelyněk","de":"Bylina, hořce a přitom voňavě, která jako první prorazí zmrzlou zem. Zaděláš ji do koláčků a jarní světlo vstoupí přímo do úst. V prvním měsíci roku se z ní vařila polévka, o níž se věřilo, že zažene celoroční neštěstí – jaro odjakživa přicházelo s touto vůní."},"ICON-1222":{"nm":"Perilový list","de":"Vůně, která jediným listem sytě prostoupí celá ústa. Podávaný k propečenému bůčku nebo naskládaný a naložený v sójové omáčce – miska rýže zmizí bleskurychle. Tahle svébytná vůně je milá jen u stolu této země."},"ICON-1223":{"nm":"Zelená paprika","de":"Zelený plod, dutý uvnitř, který se křupavě láme. Jemná hořkost probudí otupělou chuť a osmažená na oleji nabude ještě jasnější barvu. Stačí ji nadrobno nakrájet a rozprášit a jakékoli jídlo hned zesvěží."},"ICON-1224":{"nm":"Paprika","de":"Červená, žlutá, oranžová – barvy jako semafor plní celý košík. Kousneš do syrové a stéká z ní sladká šťáva, samotná barva rozjasní stůl. Rčení, že hezky vypadající zelenina i chutná lépe, tady sedí přesně."},"ICON-1225":{"nm":"Rajče","de":"Kulatá červeň, o níž se odjakživa vede spor, je-li ovoce nebo zelenina. Dlouho vařená prohloubí chuť, syrová je nekonečně svěží. Je to plod, který nejpoctivěji shromáždil letní slunce, a jedno kousnutí rozprskne celé poledne."},"ICON-1226":{"nm":"Okurka","de":"Zeleň, která nejosvěživěji zchladí letní vedro. Rozplave se ve studené polévce a ústa zchladnou, naložená jako sobagi ožije křupavostí. V parných dnech se hodí i tence nakrájená na oči – zelenina svěží zvenčí i zevnitř."},"ICON-1227":{"nm":"Dýně","de":"Visí kulatě na konci úponku a do pozdního podzimu si pomalu plní sladkost. Dlouze vařená se stane žlutou kaší, co konejší žaludek, osmažená se promění ve zlatavý plaček. Zavěšená pod okapem slouží celou zimu jako spolehlivá spíž."},"ICON-1228":{"nm":"Cuketa","de":"Světle zelená, která na letní zahrádce den ode dne mohutní. Nakrájená na kostičky do misového guláše, zlatavá jako plaček – tak jemná, že je vlídná i k dětským ústům. Tím vzácnější, čím je běžnější – stálý host na letním stole."},"ICON-1229":{"nm":"Lilek","de":"Podlouhlý plod se zářivým fialovým leskem. Nasákne-li olejem, zjemní donekonečna, propařený má vlákna hebká jako hedvábí. Ač vypadá nenápadně, hodí se ke všemu – vlídný vedlejší herec na stole."},"ICON-1230":{"nm":"Kukuřice","de":"Žlutá zrnka srovnaná úhledně v řadách. Letní svačina, kterou jsi vařenou v hrnci fouknutím do horkého kousku odhryzoval, a zároveň radostné znamení, že pole dozrálo. V chomáčku hebkých vousů je nabito sladkostí."},"ICON-1231":{"nm":"Sójové boby","de":"Malá tvrdá zrnka přes noc nasáknou vodou a zakulatí se. Jemně semletá se stanou sójovým mlékem, dlouze zkvašená pastou jang – bílkoviny na stole této země většinou začínaly právě zde. Zaseješ jedno zrnko do hlíny a vrátí se jako celá rostlina."},"ICON-1232":{"nm":"Tofu","de":"Když sójové boby nasáknou vodou, semelou se a ztuhnou, vznikne bílý kvádr s rovnými hranami. Jemné a nenáročné, v žádné polévce netrvá na vlastní barvě. I pod lžící se měkce rozpadá – jídlo, jehož ctností je právě prostota."},"ICON-1233":{"nm":"Adzuki fazole","de":"Uvaříš dozelena drobná červená zrnka a vylouhuje se z nich sytá, temně rudá sladkost. V nejdelší noci roku se teplou miskou kaše z adzuki fazolí zaháněla zima i zlí duchové zároveň – ten cit v ní žije dodnes. Ta červeň mezi vrstvami dušeného koláče byla vlastně samotná péče."},"ICON-1234":{"nm":"Fazolová pasta (adzuki)","de":"Jemná náplň, vzniklá tím, že se uvařené fazole rozmačkají a znovu a znovu zredukují. Lžíce mezi housky, uvnitř koláčku, na vrcholu ledové tříště – jedna nit sladkosti zahřeje i dávné vzpomínky. Ten dlouhý čas cezení a zavařování se přímo promění ve sladkost."},"ICON-1235":{"nm":"Houba","de":"Po dešti tiše vystrčí hlavu ze tmavého stínu lesa. Umění hlíny, která si vypěstuje vlastní vůni bez jediné hrstky slunce. Stačí přidat hrst do polévky a bez masa se vyloupne hluboká chuť umami – tajemství, které les schovává."},"ICON-1236":{"nm":"Houba shiitake","de":"Hnědý deštníček s dokořán rozevřeným kloboukem. Usušená na slunci nabude vůně několikanásobně silnější, takže jediná sušená houba lehce zajistí celý hrnec vývaru. Pevný pilíř vegetariánského stolu a dlouholetý oblíbenec těch, kdo znají hlubokou chuť."},"ICON-1237":{"nm":"Houba matsutake","de":"Hluboko v podzimním borovém lese zvedá hlavu jen nesměle, jen vedle borovic. Nedá se pěstovat, musí se najít vlastníma nohama, a proto je ta vůně o to vzácnější. Stačí ji lehce opéct a namočit jen do soli, a do úst vstoupí kus lesa."},"ICON-1238":{"nm":"Hlíva královská","de":"Roztrháš tlustou nožičku podél vláken a v ruce ucítíš žvýkavost. Roste spolehlivě po celý rok, a proto nikdy nechybí na stole. Grilovaná i osmažená – v jejím vydatném těle je plno nenáročné sytosti."},"ICON-1239":{"nm":"Jahoda","de":"Na konci fóliovníku, který přečkal zimu, zraje do červena jako první. Jedno kousnutí je sladkokyselé, přesně jako první pozdrav raného jara. Položíš jednu kulatou bobuli na dort a obyčejný dnešek se hned promění ve výročí."},"ICON-1240":{"nm":"Borůvka","de":"Praskne s tichým lup a v ústech se jasně rozlije kyselost. Sbíráš jednu fialovou kuličku po druhé a než se naděješ, kelímek je prázdný; rozsypeš je po bílém mléku a rozprostře se rovnou malá noční obloha."},"ICON-1241":{"nm":"Jablko","de":"Kousneš do něj a s křupnutím se rozláme podzim. Ta červeň, kterou ti babička ze sadu otřela utěrkou a podala, je barva, jaká vzniká jen dlouhým objímáním sluníčka. Čím je tvrdší, tím lépe umí zůstat sladké až do konce."},"ICON-1242":{"nm":"Hruška","de":"Když loupeš slupku, prsty zchladnou jako první. V přední řadě sváteční tabule na Čchusok, ve chvíli, kdy se ústa naplní studenou sladkou šťávou, si vedle tebe tiše přisedne kousek podzimního nočního vánku."},"ICON-1243":{"nm":"Broskev","de":"Na místě každého opadlého broskvového květu vyroste chlupaté, sametové léto. Lehce ji stiskneš a vůně se rozšíří jako první; v okamžiku kousnutí následuje do úst celá sezóna."},"ICON-1244":{"nm":"Hrozny","de":"Fialová zrníčka visí v jednom hroznu, opřená ramenem o rameno. Praskne a nejdřív přijde kyselost, sladkost o půl taktu později – jako úhledný sbor, který zpívá na sklonku léta."},"ICON-1245":{"nm":"Zelené hrozny","de":"Světle zelená barva nechává sluneční světlo procházet skrz naskrz a v každém zrnku se rozsvítí lucerna. Bez pecek, čistě osvěžující – sladkost bez jediného zbytečného tónu, jako právě vytažená první fráze písně."},"ICON-1246":{"nm":"Citron","de":"Škrábneš nehtem do žluté kůry a vůně náhle probudí špičku nosu. I když se ti při jedné kapce koutky úst samy stáhnou, na konci té kyselosti je podivným způsobem koutek, kde se celý den rozjasní."},"ICON-1247":{"nm":"Limetka","de":"Menší a temněji zelený plod než citron, který nejprve pozdraví ostrou, pichlavou vůní. Stačí jeden plátek a i vlažná voda se v okamžiku probudí – malá, ale houževnatá hrst svěžesti."},"ICON-1248":{"nm":"Pomeranč","de":"Ve chvíli, kdy ho loupeš, ulpí na prstech vůně slunce. Vkládáš dílek po dílku do úst a puk, puk, praskají malé balonky sladké šťávy – to kulaté oblé nakonec zaoblí i náladu."},"ICON-1249":{"nm":"Mandarinka","de":"Pamatuješ tu chuť, jak jsi je loupal s nohama zabořenýma pod teplou zimní peřinou? Vůně, která se šířila od nehtů, obarvila celý pokoj do žluta. Jeden pytlík stačí jako záminka, aby se sešla celá rodina."},"ICON-1250":{"nm":"Banán","de":"Byly dny, kdy jsem si hlad za svítání v koutě zkušebny zahnal jediným žlutým kouskem, co se vykutálel z tašky. Měkký, sladký a sytý – nejvlídnější nouzové řešení."},"ICON-1251":{"nm":"Ananas","de":"Než se ukáže žlutá dužina, musíš projít vrstvou ostnaté kůry. Jeden kousek v ústech a sladkokyselost štípne do jazyka, kolem rtů se zatím nenápadně vznáší vůně jižního moře."},"ICON-1252":{"nm":"Mango","de":"Rukama rozdělíš zralou dužinu a lepkavá sladká vůně smočí prsty. Když se sytě žlutá v ústech měkce rozpustí a zmizí, mihne se sladký sen jako krátký letní odpolední spánek."},"ICON-1253":{"nm":"Kokos","de":"Zatřeseš tvrdou skořápkou a uvnitř se ozve šplouchnutí vody. Rozbiješ ji – bílá dužina a osvěžující šťáva – malá nádoba, v níž se celé vzdálené moře houpe uzavřené vevnitř."},"ICON-1254":{"nm":"Dračí ovoce","de":"Zvenčí vypadá jako růžové šupiny a člověk se nejdřív zarazí, ale rozkrojíš ho a uvnitř je bílá dužina posetá drobounkými semínky. Chuť skromná, zevnějšek okázalý – potutelný komediant, uvnitř přesný opak toho, jak vypadá zvenčí."},"ICON-1255":{"nm":"Kiwi","de":"Rozkrojíš napůl chlupatě hnědý plod a objeví se zelený drahokam. Vezmeš lžičku z řezu poseté černými semínky jako hvězdami, a jedno kyselé sousto tě zatřese ze spánku."},"ICON-1256":{"nm":"Kuřecí maso","de":"Položíš ho na vymaštěnou pánev a nejdřív se propeče zlatavé prskání. Jemné a šťavnaté, snadno si sedne k jakémukoli stolu – stálý host nenáročného jídla."},"ICON-1257":{"nm":"Vepřové maso","de":"Na grilu syčí a praská, tuk odstřikuje a maso zlátne. V noci firemní večeře, kdy jsi cpal plná ústa zabalená v listu salátu s tečkou ssamdžangu, voňavá plnost zahřála celý stůl."},"ICON-1258":{"nm":"Hovězí maso","de":"Do každého červeného vlákna je jemně vetkaný tuk a leskne se. Položíš ho na rozpálenou kamennou desku a místnost nejdřív naplní vůně; v okamžiku, kdy vezmeš kousek do úst, se tiše rozváže denní únava."},"ICON-1259":{"nm":"Slanina","de":"Na ranní pánvi křupavě tančí tuk. Stačí ta slaná vůně a i zaspalá rodina, mnoucí si oči, se sejde v kuchyni – jídlo, které jako první zavolá vůně."},"ICON-1260":{"nm":"Párek","de":"Naříznuté místo se doširoka rozevře a šťáva vystříkne. Ten červený tvar chobotničky, který zodpovídal za jeden oddíl svačinového boxu, byl malý luxus, který si užívaly dětské obědy."},"ICON-1261":{"nm":"Pepperoni","de":"Kulatý pikantní plátek se na horkém sýru stahuje od okrajů dovnitř. Když se v jamce nasbírá kapka tuku, to je vrchol celé pizzy – malý, ale s kulatou, sytou přítomností."},"ICON-1262":{"nm":"Karbanátek","de":"Vytvaruješ ho silně, položíš na grilu a od okrajů začne hnědnout. Vložíš zeleninu mezi propečenou přitisknutou placku a dokonalá sytost, co se vejde do jedné ruky, je hotová."},"ICON-1263":{"nm":"Vejce","de":"Rozklepneš ho a žloutek vyklouzne jako kulaté sluníčko. Dobré je zamíchané do čerstvě uvařené rýže, dobré jako žlutý pruh uvnitř kimbapu – nejobyčejnější, a tedy nejvlídnější bílkovina."},"ICON-1264":{"nm":"Mléko","de":"Studená láhev položená za svítání přede dveřmi – den se často otevíral tím chladem na dlani. Zahřáté stoupá pára, vychlazené je voňavé – bílá barva, která je vždy nablízku."},"ICON-1265":{"nm":"Sýr","de":"Žlutý plátek se pomalu rozplyne na teplém pecivu. Srdce čekající na tu chvíli, kdy se táhne v dlouhých nitích – čím víc se rozpouští, tím hlubší a sytější je jeho vůně."},"ICON-1266":{"nm":"Sýr čedar","de":"Sytá oranžová barva na první pohled slibuje slanou chuť. Tence nakrájený v toastu se rozšíří umami chuť po celých ústech – čím výraznější barva, tím výraznější chuť."},"ICON-1267":{"nm":"Máslo","de":"Upustíš kousek na rozpálenou pánev a měkce se rozpustí, stoupá voňavá pára. Namažeš na chleba, zamícháš do rýže – žlutá magie, která zjemní vše, čeho se dotkne."},"ICON-1268":{"nm":"Šlehačka","de":"Čím déle šleháš, tím víc se řídká bílá barva vzdouvá v pevný oblak. Ve chvíli, kdy dáš lžíci na dort, se obyčejné odpoledne rozjasní jako malé narozeniny."},"ICON-1269":{"nm":"Jogurt","de":"Ponoříš lžíci a hladce se zvedne kyselá bílá hmota. Přidáš kousek ovoce a ráno je lehčí, jeden kelímek a žaludek se klidně urovná – chuť jemného začátku."},"ICON-1270":{"nm":"Makrela","de":"Položíš ji na rošt a tuk odstřikuje, kuchyň naplní kouř, napůl rybí a napůl voňavý. Ruka, která vybírala kůstky a kladla maso na rýži – nejhlubší péče usazená v obyčejném jídle."},"ICON-1271":{"nm":"Losos","de":"Růžová vlákna leží narovnaná vrstva na vrstvě. Studený se v ústech měkce rozpouští, grilovaný prosakuje tukem a voní – pevná chuť, která doplavala proti proudu vzdáleného moře."},"ICON-1272":{"nm":"Tuňák","de":"Otevřeš víčko konzervy a náhle stoupne slaná vůně. Byly noci v pronajatém pokojíku, kdy jsi ho míchal do rýže a balil do řasy, časy, kdy se jedna konzerva stala vydatným jídlem."},"ICON-1273":{"nm":"Treska","de":"Čiré maso je tak jemné, že se z něj hned při vaření vylouhuje osvěžující vývar. Bílá ryba, která přečkala ostrý vítr zimního přístavu – jedna horká miska polévky a i prokřehlé ruce se pomalu rozehřejí."},"ICON-1274":{"nm":"Kreveta","de":"Stočí kulatě záda a při vaření se šedá barva zbarví do růžova. Pružné praskání a voňavá chuť – loupeš je jednu po druhé, a než se naděješ, talíř je prázdný."},"ICON-1275":{"nm":"Krab","de":"Vyloupat bílé maso z tvrdé skořápky je chvíle drobné trpělivosti. Kousek, který si na konci té námahy vložíš do úst, je sladký – podzimní moře vstoupí do úst vcelku."},"ICON-1276":{"nm":"Kalmar","de":"Na grilu se kulatě stáhne a vysílá voňavý kouř. Žvýkavý kousek, namočený do pikantní omáčky – vložíš ho do úst a přijde s ním slané moře."},"ICON-1277":{"nm":"Mušle","de":"V čirém vývaru otevírají ústa a tiše vydávají svou vůni. Se zvukem probublávání se šíří vůně moře, a jedno srknutí prohřeje a uvolní prochladlý žaludek."},"ICON-1278":{"nm":"Rybí koláč","de":"Ponoříš ho i s párátkem do horkého vývaru a stoupá obláček páry. Před stánkem v mrazivý den ruce, které si nabraly vývar do papírového kelímku a foukaly na něj – malá útěcha, kterou nabízí ulička."},"ICON-1279":{"nm":"Kimči","de":"V hliněné nádobě pomalu zraje a pěstuje si kyselou, hlubokou vůni. Stačí ho rukou natrhat na kousky a položit na čerstvě uvařenou rýži; chuť, která se liší dům od domu, je přímo historií toho domu."},"ICON-1280":{"nm":"Nakládaná ředkev","de":"Žlutý plátek s křupnutím vesele praskne v ústech. Věrný společník po boku rolky kimbapu nebo talíře pouličního jídla – sladkokyselost svěže vypláchne umaštěná ústa."},"ICON-1281":{"nm":"Kyselé okurky","de":"Okurka na chvíli zatají dech v soli, pak otevře oči v octu. Aby nepropásla okamžik, kdy se vrátí křupavost, sklenice neopouští slunné okno. Čas, který ji pomalu marinuje, s sebou přináší chuť."},"ICON-1282":{"nm":"Gočudžang","de":"Červeň, která v hliněné nádobě vydržela celý rok. Za pálivostí se tiše skrývá sladkost sóji, takže jedna rozpuštěná lžíce udělá z guláše konečně tvář naší rodiny. Hloubka, kterou dvorní nádoby na jang vypěstovaly sluncem."},"ICON-1283":{"nm":"Doenjang","de":"Bochník medžu objal plíseň a přečkal s ní celou zimu. Voňavá hloubka je nejistá chůze po laně mezi vyzrálostí a přezrálostí – babička tu hranici poznala jediným čichnutím k prstům. Chuť, která se prohlubuje přesně tak dlouho, jak dlouho čekáš."},"ICON-1284":{"nm":"Sójová omáčka","de":"Čím tmavší jsou boby, tím hlubší je jejich nitro. Jedna kapka oživí zeleninový salát a dodá lesk dušenému jídlu, takže všechny barvy kuchyně nakonec začínají právě z této teplé hnědi. Umami za hranicí slanosti."},"ICON-1285":{"nm":"Černá fazolová pasta","de":"I stejná černá má jinou strukturu. Sladkoslaný dozvuk, ještě jednou osmažený s karamelem – zamícháš ji do nudlí a ten černý lesk otřese chutí a probudí ji. První knoflík, kterým začíná chuť čínského ohně."},"ICON-1286":{"nm":"Kari koření","de":"Žlutý prášek, v němž se v jedné lžíci svorně snoubí několik koření. Rozpustíš ho ve vodě a bublavě se rozvaří, prohřeje celý dům – stává se předzvěstí nejsytější misky deštivého večera."},"ICON-1287":{"nm":"Pepř","de":"Vůně přežije jen tehdy, když se mele celý, namletý předem se tiše vytratí. Poslední otočka mlýnku přichází vždy těsně před vypnutím plamene – malá tečka, kterou vařící ruka šetrně pokládá na konec."},"ICON-1288":{"nm":"Chilli prášek","de":"Papriky sušené na podzimním slunci teprve dokonají svou červeň. Podle toho, zda se rozemelou najemno nebo nahrubo, se láme povaha kimči – kuchařský cit nakonec pramení právě z volby zrnitosti tohoto prášku."},"ICON-1289":{"nm":"Sůl","de":"Dochutit znamená přibližovat se po ždibcích ke straně nedosolení. Slanost, jednou přidaná, se nedá vzít zpět, a tak zkušená ruka vždy nakonec dá o trochu méně a ochutná. To, co si nechá stranou, je její rezerva."},"ICON-1290":{"nm":"Cukr","de":"Konejší hořkost a zaobluje hrany kyselosti. Sladkost však nesmí prozradit svou přítomnost, a tak čím lepší je koření, tím tišeji cukr na konci zmizí ze stopy. Sladkost, která se umí schovat."},"ICON-1291":{"nm":"Med","de":"Sklenice, kterou včely nasbíraly tisíckrát létajíc na květinovou louku a zpět. Ztuhne-li, oživíš ho vodní lázní; rozpustíš-li ho v čaji, jemně obejme hrdlo. Zlatá lžička, v níž se svařila celá jedna sezóna."},"ICON-1292":{"nm":"Kuchyňský olej","de":"Otočíš ho jednou kolem rozpálené pánve a suroviny zapomenou přilnout. Naliješ-li příliš brzy, připálí se, příliš pozdě, přilepí se, takže právě ten okamžik, kdy se začne zvedat kouř, je zlatým pravidlem smažení. Čas se měří sluchem."},"ICON-1293":{"nm":"Olivový olej","de":"V zelené barvě prvního lisování žije zároveň trávová vůně a jemná pálivost. Přežije nejlépe, pokud se přidá na konec spíš než na oheň, takže nechat ho nevařené je jeho nejpoctivější použití."},"ICON-1294":{"nm":"Sezamový olej","de":"Kápneš na konec jedinou kapku a zeleninový salát teprve tehdy ohlásí, že je hotový. Jeho vůně snadno unikne nad ohněm, a proto je vždy tichou tečkou, přidanou až po skončení veškeré přípravy."},"ICON-1295":{"nm":"Vanilkový lusk","de":"Rozřízneš lusk a vyškrábeš černá semínka, a dezert si oblékne šaty z vůně. Nevyhodit ani vyluhovaný lusk, ale zahrabat ho do cukru – stará šetrnost, kterou zdědili cukráři."},"ICON-1296":{"nm":"Kakaové boby","de":"Bílá dužina a hořká semínka uvnitř plodu. Teprve po kvašení a sušení na slunci se přeloží do sladkosti, jakou známe. Než se stane čokoládou, má svou první, nejdivočejší tvář."},"ICON-1297":{"nm":"Čokoláda","de":"Vrtošivá povaha, která se roztéká už jen z tepla dlaně. Musí ztuhnout kolem 28 stupňů, aby ožil ten křupavý lom a lesk, takže za sladkostí se překvapivě skrývá vybíravé pravidlo teploty."},"ICON-1298":{"nm":"Kávová zrna","de":"Než se semele, jedno zrnko je blízké tvrdému mlčení. Jakmile se však setká s horkou vodou, nabobtná a vychrlí vůni – první signál, který budí ráno, vždy začíná právě v tomto malém zrnku."},"ICON-1299":{"nm":"Čajové lístky","de":"Zůstanou-li v horké vodě příliš dlouho, jsou svíravé, příliš krátce, jsou fádní. Tiše počítat čas, za který se lístky pomalu rozvinou – louhovat čaj znamená měřit čekání konečky prstů."},"ICON-1300":{"nm":"Máta","de":"Rozmačkáš ji a prosákne hořkost, a tak je to křehký list, se kterým je vždy třeba zacházet jemně. Lehkým poklepáním probudíš uspalou vůni, a když ji v horký den necháš plavat ve sklenici, celé léto se ztiší o tón chladněji."},"ICON-1301":{"nm":"Bylinky","de":"Přidáte-li je i se stonkem, vůně zesílí; použijete-li jen listy, zůstane čistá. Sušené zesílí, čerstvé jsou svěží — a šíře vůně, kterou v sobě nese jeden svazek, rozšiřuje i tvář kuchyně."},"ICON-1302":{"nm":"Kaštan","de":"V trnité slupce se skrývá lesklá dužina. Naříznete-li ji a upečete, s tichým prasknutím se pootevře a rozvoní se sladce — jako by se dalo v ruce sevřít teplo sáčku pečených kaštanů z uličky ve studeném větru."},"ICON-1303":{"nm":"Burský oříšek","de":"Ořechová vůně se dovrší až na plameni při pražení. Malé zrníčko, které loupete jedno po druhém, až zapomenete na čas — a sednete-li si s ním v kruhu na verandě, spolu s ním se loupou i tiché historky."},"ICON-1304":{"nm":"Mandle","de":"Lehce spařená a zbavená slupky zbělá a zjemní ještě víc. Rozdrcená a umletá připomíná mléko, celá upečená křupe — a šíře proměn, které jedno zrnko v sobě nese, naplno rozšiřuje představivost cukráře."},"ICON-1305":{"nm":"Sezamová semínka","de":"Jemně jimi na mírném ohni potřásáte, až v jednu chvíli začnou tiše poskakovat. Chvíle těsně předtím, než ten zvuk ustane, je ta nejvoňavější — pražení sezamu se tak nakonec stává věcí, kterou posloucháte ušima."},"ICON-1306":{"nm":"Cukrová třtina","de":"Rozkousáte-li jeden článek, spolu s travnatou vůní z něj prosákne sladká šťáva. Stéblo, které musí být znovu a znovu zahušťováno, než se stane sladkostí, kterou známe — počátek cukru je nečekaně tak zelený a vysoký."},"ICON-1307":{"nm":"Surový cukr","de":"Hrubá sladkost, která si díky menšímu rafinování ponechala vlastní barvu. Zůstává v ní jemně ukrytá hloubka podobná vůni hlíny, a tak si ji ruce, jež mají rády upřímnost před jemným vyleštěním, schválně vyhledávají."},"ICON-1308":{"nm":"Kakaové boby","de":"Semínko čerstvě vyjmuté z lusku je hořké a trpké. Vůně rozkvete, až tiše vydrží několik dní kvašení — sladkost je tak malou odměnou, kterou tento bob dostává na konci své dlouhé trpělivosti."},"ICON-1309":{"nm":"Drcené kakaové boby","de":"V kouscích jemně nadrcených pražených bobů není ani zrnko cukru. Vložíte-li si je do úst, nejdřív přijde hořkost a teprve pak opožděně ořechová vůně — tak se setkáte s kakaem před sladkostí, v jeho nejupřímnější podobě."},"ICON-1310":{"nm":"Zelená kávová zrna","de":"Zelené zrnko, které v sobě ještě nese syrovou vůni trávy. Takhle vůně jen tiše spí, a dokud nepřijme křest ohněm, zůstává klidně možností, jež sama neví, čím se stane."},"ICON-1311":{"nm":"Pražená kávová zrna","de":"Na hnědém povrchu, z něhož lehce vystoupil olej, se nashromáždila plná vůně. Musí se semlít, než vychladnou, aby ta vůně zůstala celistvá — osud jednoho šálku se tak potichu rozhoduje během několika dní po pražení."},"ICON-1312":{"nm":"Vanilkový lusk","de":"Jediný pramínek vůně prostoupí celý hrnec mléka. I použitý lusk stačí zapíchnout do sklenice s cukrem a za pár dní provoní úplně všechen cukr — je to přepych, na němž není jediná zbytečná část."},"ICON-1313":{"nm":"Pepř","de":"Vůně jednoho zrnka celého pepře začne slábnout hned ve chvíli, kdy je namleté. Proto se nechává celé na stole a drtí se vždy jen podle potřeby — čerstvost totiž vzchází ze srdce, které nic neodkládá."},"ICON-1314":{"nm":"Bílý pepř","de":"Zrnko zbavené slupky, díky čemuž je hladší, je spíš jemné než ostré. Zrodilo se z ohleduplnosti nezanechat v bílé omáčce jedinou černou tečku — je to jemnost místa, které zůstává neviditelné."},"ICON-1315":{"nm":"Skořice","de":"Louhujete-li jeden kousek, do čaje se pomalu rozlévá teplá pálivost. Vůně vydrží déle, když se přidá vcelku a ne mletá — hloubka zimního nápoje tak pramení z vytrvalosti této sušené kůry."},"ICON-1316":{"nm":"Hřebíček","de":"V jednom poupěti tvaru malého hřebíčku je vůně nahuštěná do posledního místečka. Přidáte-li jich příliš mnoho, pohltí celý pokrm — a tak zdrženlivost jediného kousku tiše střeží rovnováhu chuti."},"ICON-1317":{"nm":"Muškátový oříšek","de":"Semínko se nechává celé a jen se z něj podle potřeby trochu strouhá. Má povahu vůně, která se po umletí předem rychle rozptýlí, a tak poslední pohyb, jediné rychlé strouhnutí, dodá mléku ještě hlubší vůni."},"ICON-1318":{"nm":"Kardamom","de":"Prasknete-li zelený lusk, zevnitř se vyvalí svěží, chladivá vůně. Stačí do čaje rozdrtit jedno dvě zrnka a obyčejný šálek náhle získá vůni vzdálené země."},"ICON-1319":{"nm":"Šafrán","de":"Rudá vlákna, sotva tři z jednoho jediného květu. Rozpustíte-li je v teplé vodě, pomalu se rozlévá žluté světlo — vzácnost je tak i váhou času, který ruce strávily jejich sbíráním, jedno po druhém."},"ICON-1320":{"nm":"Kurkuma","de":"Rozemelete-li kořen z hlíny, obarví do žluta i konečky prstů. Má povahu, kdy se vůně probouzí jen lehkým osmažením na oleji — zlatavá barva kari je tak barvou, kterou tento drobný kořen vzkvetl nad ohněm."},"ICON-1321":{"nm":"Bobkový list","de":"List, o němž se říká, že spočíval na čele vítěze. Pustíte-li jeden do vroucí vody, mezi parou se na chvíli vynoří jásot starého stadionu. I ve dnech, kdy jste nezvítězili, se nadechnutí jeho vůně stane zeleným utěšením, jež tiše obejme dnešní vás."},"ICON-1322":{"nm":"Kokosové mléko","de":"Bílá šťáva, která vyteče teprve po rozbití tvrdé skořápky. V koutě tržiště v horké zemi stačí zapíchnout brčko a jedním douškem se poledenní žízeň úplně rozplyne. Chladná, sladká vůně, jež se rozlévá po celých ústech, s sebou přináší stín tropů."},"ICON-1323":{"nm":"Kokosový olej","de":"Ztuhlý je bílý jako první sníh, zahřátý v dlani se jeho vůně tiše rozlévá. V kulaté dóze je celá uchovaná laskavá domácí moudrost ostrovní babičky, která ho podávala se slovy, že jedna dóza stačí od hlavy až k patě."},"ICON-1324":{"nm":"Sušený banán","de":"Po několika dnech na slunci zežloutlá dužina zhoustne a zpruží. Ukusujete-li po kousíčcích, šetrně, v ústech se nenápadně znovu probudí lepkavá sladká vůně deštivé sklizňové sezóny. Sladkost, jež zrála pomalu, v sobě tak nese celé roční období."},"ICON-1325":{"nm":"Sušené mango","de":"Měkká dužina se na slunci zahustila a znovu se zrodila jako jantarové želé. V jednom kousku jsou zastoupeny hned tři chutě — kyselá, sladká i tažná — a když ho pomalu válíte v ústech, celý sáček prodlouží odpoledne."},"ICON-1326":{"nm":"Sušený ananas","de":"Na rozdíl od trnitého zevnějšku je dužina nesmírně žlutá a jasná. Usušená na slunci nabírá na kyselosti a stačí jedno kousnutí, aby se koutky úst samy zvedly. Svěží dozvuk, který zůstává po jednom kousku, přetrvává dlouho."},"ICON-1327":{"nm":"Košík tropického ovoce","de":"Čerstvě natrhané barvy se v jednom košíku prolínají. Oranžová manga, žlutá banánu, zlatavá ananasu — dřív než ruka stihne po čemkoli sáhnout, dovalí se nosem léto. Náruč, z níž se na první pohled rozjasní srdce."},"ICON-1328":{"nm":"Svazek mořských řas","de":"Mořské vlasy sesbírané ze skal obnažených odlivem. V jejich slaném pobřežním pachu je zapletený i zvuk vln, a namočíte-li je tiše do studené vody, nahořklá mořská vůně se pomalu dovalí až do kuchyně. Hrst jich na stole rozprostře malé bahnité pobřeží."},"ICON-1329":{"nm":"Sušené mořské plody","de":"Hrst pevně vysušeného moře. Roztrháte-li ho rukou po vláknech, spolu se slaností se uvolní i slaný vítr starého přístavu. Starý přítel u srdečného stolu, po němž se samo vybaví číše makkolli."},"ICON-1330":{"nm":"Sušená oliheň","de":"Deset chapadel rovně rozprostřených a usušených na slunci. Lehce opečená na ohni, až stoupne ořechová vůně, se rve podél vláken. Díky té tažné, žvýkavé chuti stoupá důstojnost pozdního nočního talíře o stupeň výš."},"ICON-1331":{"nm":"Nasolená ryba","de":"Zahrabaná v hrubé soli se ryba učí, jak snášet čas. Jeden kousek hluboce slané dužiny stačí, aby se miska rýže v okamžiku vyprázdnila — je to laskavé tajemství, které babička od moře předávala z ruky do ruky."},"ICON-1332":{"nm":"Solené krevety","de":"Drobné krevety pomalu zrají v soli a znovu se rodí jako hloubka chuti umami. Ve chvíli, kdy se lžíce vloží do zelí při kimčovém podzimu, se slaná vůně rozleje po celém dvorku. Tahle jedna lžíce rozhoduje o chuti celoročního kimči."},"ICON-1333":{"nm":"Sušená sardelka","de":"Tělíčko velké jako prst na sobě nese hloubku celého hrnce vývaru. Dětská kuchyně, kde se při vytrhávání hlaviček a vnitřností tiše povídalo — malá, a přesto vděčná ryba, jež pevně stála uprostřed domácnosti."},"ICON-1334":{"nm":"Kombu","de":"Dlouhá černá stuha vyrostlá na dně moře. Vložit ji do studené vody a jemně vylovit těsně před varem — to je slib, který si ruce vařící vývar předávaly z generace na generaci. Hluboká chuť umami nikdy, nikdy nespěchá."},"ICON-1335":{"nm":"Hidžiki","de":"Hrbolatá textura v ústech tiše popraskává. Mořská řasa, jež na jaře barvila příbřežní skály do zelena — jemně promíchaná se zálivkou rozprostře v koutě stolu malé, svěží moře. Je to chuť, kterou se žvýká jaro."},"ICON-1336":{"nm":"Perlorodka","de":"Kulaté světlo, vytvarované dlouhým chováním mezi dvěma pevnými polovinami skořápky. Než se nepohodlí jednoho zrnka písku proměnilo v klenot, moře ani jednou nespěchalo. Položíte-li ji na dlaň, spolu s ní na ni dosedne i váha té dlouhé trpělivosti."},"ICON-1337":{"nm":"Korálová ozdoba","de":"Mořská větev, kterou vlny po staletí opracovávaly. Dotkne-li se jí sluneční světlo, rozlije se do růžova a oranžova, takže i pouhé postavení na poličku obarví celý pokoj do teplého ostrova. Milá je i drsná struktura, jíž se dotýkají konečky prstů."},"ICON-1338":{"nm":"Perleťový knoflík","de":"Na místě, kde kdysi bydlela lastura, byl kulatě vystřižen třpytivý vnitřek. Přišitý na límec — pokaždé, když ho zapínáte, se u konečků prstů zablýskne malá duha. Poslední laskavý dar, který moře zanechalo, dávajíc vše a odcházejíc."},"ICON-1339":{"nm":"Skleněná kulička","de":"Zakoulíte-li ji v dlani, spolu s ní se kutálí i světlo uvězněné uvnitř. Časy, kdy se dřepělo v uličce a hrálo se o kuličky, aniž by si kdo všiml zapadajícího slunce — kapsa dítěte, jež vyhrálo o jednu víc, byla nezvykle těžká a plná pýchy."},"ICON-1340":{"nm":"Jalovcová řezba","de":"Z každého vyřezaného vlákna prosakuje jemná vůně. Lidé odedávna toto dřevo pálili, aby si urovnali rozháraná srdce. Podržíte-li tiše jeden kousek, od konečků prstů se pomalu naplňuje klid."},"ICON-1341":{"nm":"Vonná tyčinka","de":"Tenký proužek pomalu doutná a razí si cestu vzhůru. Sledujete-li očima křivku, kterou kreslí kouř, i srdce, jež celý den spěchalo, nenápadně zpomalí krok a tiše se zastaví na místě."},"ICON-1342":{"nm":"Barvířský květ","de":"Rozpustíte-li barvu skrytou v okvětních lístcích ve vroucím kotli, čirá látka se pomalu obarví do té barvy. Je to jen chvilkové vypůjčení si světla, jež příroda předem nanesla — barvení bylo odjakživa laskavým pozdravem posílaným květině."},"ICON-1343":{"nm":"Indigová barva","de":"Hluboká, tajuplná modř, získaná opakovaným kvašením indigové rostliny. Pokaždé, když se látka namočí a vytáhne, pomalu přechází barvou z nebeské modři k mořské. Je to barva čekání, jež rozkvete teprve tehdy, když se odloží netrpělivost."},"ICON-1344":{"nm":"Karmínová barva","de":"Vylouhujete-li kořen mořeny, v kotli se probudí západ slunce, jenž dosud dřímal v hlíně. Byla to nejslavnostnější a nejjasnější barva ve vesnici, ta, která na svatební den krásně barvila lem sukně nevěsty."},"ICON-1345":{"nm":"Zlatá nit","de":"Zlato tenčí než vlas se vytahuje a s péčí spřádá vlákno po vláknu. Všude, kde je jím vyšito, uchovává světlo, takže i v temné místnosti se zhasnutou lampou se právě ten vzor sám tiše rozzáří."},"ICON-1346":{"nm":"Hedvábí","de":"Vlákno, jež vyplivl bourec morušový, se musí znovu a znovu tkát, než se z něj stane jediný pruh látky. Dotek, který po hřbetu ruky klouže jako jarní voda — jemně tkaná látka, kterou dávní lidé pomalu pěstovali, chovajíce v sobě celé jedno roční období."},"ICON-1347":{"nm":"Perlový knoflík","de":"Vybráno bylo jen vnitřní světlo perly a kulatě opracováno. Pokaždé, když se jím zapíná límec čogori, konečky prstů se na okamžik stanou elegantními. Malé, a přece úhledné zrnko, jež nenápadně pozvedá důstojnost oděvu."},"ICON-1348":{"nm":"Útržek mořské mapy","de":"Za roztrženým okrajem se náhle přerušuje neznámá pobřežní linie. Prý jen ten, kdo shromáždí zbylé kusy, dosáhne pokladu — ale možná už samotná cesta bloudění za větrem, hledání, byla tím pokladem."},"ICON-1349":{"nm":"Stará námořní mapa","de":"Mořskou vodou rozmazaná trasa a vybledlá kresba kompasu. Sledujete-li konečkem prstu čáru, kterou nějaký námořník nakreslil v tmavé noci jen podle hvězd, na starém papíře se pomalu znovu vynoří ostrov, jenž dávno zmizel."},"ICON-1350":{"nm":"Vzkaz v láhvi","de":"Uvnitř skleněné láhve, kterou vlny vyplavily na břeh, list papíru stočený do ruličky. Pozdrav, o němž nikdo neví, kdo ho a kdy poslal na cestu, konečně dosáhl něčí ruky. Má-li jen srdce, i moře se dokáže stát takhle pomalým poštovním doručovatelem."},"ICON-1351":{"nm":"Vyplavená bedna","de":"Dobrodružství trvá až do chvíle, kdy se otevře víko, ztuhlé nabobtnáním ve slané vodě. Ať už uvnitř čeká poklad, nebo jen prázdný písek, do bedny, jež doplula zdaleka, vždy spolu s ní připlul i příběh nějaké neznámé tváře."},"ICON-1352":{"nm":"Malý klíč","de":"Starý kousek kovu, jenž se přesně vejde do dlaně. Ačkoli je dávno zapomenuto, jaké dveře otevírá, u konečků prstů zůstává těžknout laskavá tíha, díky níž si člověk nejdřív vybaví, jak něco odemknout, než jak to zamknout."},"ICON-1353":{"nm":"Stříbrná mince","de":"Kulaté stříbro, jehož vzor otěrem rukou vybledl. Jedna mince, jež byla kdysi něčím jízdným na loď i únavným nocležným — pohladíte-li její chladem vystydlý povrch, u konečků prstů se matně znovu probudí teplo dávného obchodu."},"ICON-1354":{"nm":"Zlatá mince","de":"Položíte-li ji na dlaň, nejdřív srdcem otřese její tíživá váha. Jedna mince, jež ve slunci žlutě září, slibuje, jako by vlastnictví z vás udělalo boháče — ale nejjasněji ze všeho ve skutečnosti září ono rozechvění těsně předtím, než ji sevřete v ruce."},"ICON-1355":{"nm":"Kapitánská pečeť","de":"Kapitánův slib, pevně vtisknutý do červeného vosku. Jediným otiskem se vydal rozkaz a určila se drsná plavební trasa. Autorita byla nakonec jen jedním malým, pevným razítkem, jemuž se všichni na téže lodi společně rozhodli věřit."},"ICON-1356":{"nm":"Ruční mikrofon","de":"Ve chvíli, kdy ho sevřete, dlaň zaplní podivně sebejistá váha. Ať už při rozechvělém prvním pozdravu, nebo ve chvíli, kdy nakonec vykřiknete vysoký tón — tahle jedna malá tyčka tvému hlasu jemně přidá křídla."},"ICON-1357":{"nm":"Bezdrátový mikrofon","de":"Když zmizel kabel, celé jeviště se rázem rozšířilo. I když doběhnete až na konec hlediště, hlas se ani jednou nepřeruší — jako by vás někdo tiše postrčil do zad se slovy, ať běháte a zpíváte podle libosti."},"ICON-1358":{"nm":"Stojanový mikrofon","de":"Pevně stojí u nohou a tiše čeká na zpěváka. Uvolní-li se obě ruce, píseň se místo konečků prstů rozlévá celým tělem. Tahle tyčka tiše říká, že i v setrvání na jednom místě až do konce je jasně obsažen svůj vlastní půvab."},"ICON-1359":{"nm":"Pop filtr","de":"Jedna vrstva látky, kulatě zahrazující prostor před mikrofonem. Prudké nádechy jemně odfiltruje a propustí jen čistý hlas. Umožnit, aby bylo dobře slyšet, znamená tiše chránit z místa, které až do konce zůstává neviditelné."},"ICON-1360":{"nm":"In-ear monitor","de":"Vklouzne přesně do ucha a za řevem desetitisíců diváků se zřetelně znovu ozve vlastní píseň. Na jevišti zaplaveném světlem i zvukem je to nejmenší a nejskrytější společník, jenž nedovolí ztratit rytmus."},"ICON-1361":{"nm":"Sluchátka","de":"Ve chvíli, kdy přikryjí uši, se svět o kus zmenší a zůstane jen hlasitá píseň. Jedna kulatá místnost, do níž nikdo nemůže vstoupit. A přesto, uvnitř sluchátek nasazených o samotě, člověk podivně není sám."},"ICON-1362":{"nm":"Noty","de":"Když se černé tečky tiše usadí na linkách, mlčící papír v sobě pojme zvuk. Písmo, které se spíš poslouchá, než čte. Ve chvíli, kdy se otevře, píseň, jež stála na místě, znovu dýchá."},"ICON-1363":{"nm":"Zpěvácké noty","de":"Na každém místě k nadechnutí je zakroužkováno malé kolečko. Zde se nadechni, tam ho zase tiše vypusť. Jedna laskavá mapa, jež otevírá cestu tak, aby se hlas nezranil."},"ICON-1364":{"nm":"Klavírní noty","de":"Stránka, na níž se deset prstů zároveň ptá na cestu. Levá ruka se drží kořenů, pravá kreslí melodii. Dvě ruce, jež vyprávěly každá jiný příběh, se v posledním taktu nakonec spojí v jedno."},"ICON-1365":{"nm":"Akordová tabulka pro kytaru","de":"První cizí jazyk, jemuž se prsty učí, jeho vůbec první slovo, je zapsané právě tady. Teprve když se šest teček spojí do kroužků, rozezní se jeden tón. Každou nocí, kdy se tiskne a znovu tiskne, na konečcích prstů roste mozol."},"ICON-1366":{"nm":"Metronom","de":"Ťuk, ťuk — vedle vás vyklepává neochvějný krok. Když srdce spěchá napřed, zezadu vás pomalu, pomaličku pozdrží. Vždyť rytmus je nakonec jen slib, že půjdeme spolu."},"ICON-1367":{"nm":"Ladička","de":"Když se ručička sesune přesně doprostřed, tón teprve najde své místo. Ten jediný bod, jenž není ani vysoký, ani nízký. Tak tohle je tedy naladění — už se netřást, jen tiše se zastavit."},"ICON-1368":{"nm":"Kartička klavírních kláves","de":"Každým obrácením listu vkráčí klávesa přímo do dlaně. Od C až po H, malý vesmír sedmi políček. I v noci, kdy chybí skutečný klavír, tady píseň tiše roste."},"ICON-1369":{"nm":"Kytarové trsátko","de":"Malý, pevný kousek, sevřený mezi palcem a ukazovákem. Upustíte-li ho, navždy zmizí pod židlí, ale ve chvíli, kdy ho sevřete v ruce, se najednou rozezní všech šest strun."},"ICON-1370":{"nm":"Bubenické paličky","de":"Když se dvě paličky srazí ve vzduchu, na tom místě padne signál. Jedna, dvě, tři, čtyři. Roztroušená srdce všech se podle těchto čtyř dob začnou tlouct stejným tempem."},"ICON-1371":{"nm":"Tamburína","de":"Jednou úderem se čistý zvuk rozprskne na všechny strany, jako by se rozbily paprsky slunce. Ať vypadá sebelehčeji, je to takt, po němž ruka sáhne jako první, když nálada začíná chladnout. Nikdo ji nemůže přehlížet jen proto, že je malá."},"ICON-1372":{"nm":"Taneční tenisky","de":"Pro nohu, jež se po podlaze otáčí jako by klouzala, se tření stává zbraní. Do opotřebené podrážky se vrývá otočka za otočkou. Nejparádnější pohyb vždy začíná od jednoho pevného páru."},"ICON-1373":{"nm":"Chrániče kolen","de":"Jen ten, kdo si nesčetněkrát klekl a znovu vstal, zná vděčnost za tuhle jedinou tenkou vrstvu látky. To, co dělá podlahu už méně děsivou — odvaha bývá občas takhle omotaná kolem kolen."},"ICON-1374":{"nm":"Chránič zápěstí","de":"Zavine-li se předem místo, kde se zápěstí ohýbá, i přehnaný pohyb se stane o něco shovívavějším. Zápěstí je mlčenlivé a trpí samo, dokud ho nerozbolí. To dlouhé mlčení za něj místo toho zadrží jedna vrstva."},"ICON-1375":{"nm":"Chránič kotníku","de":"Na konci vysokého skoku je dopad, a na konci toho dopadu je kotník. Nejnižší místo, jež na sebe přijímá váhu celého těla. Tahle malá páska tiše střeží zítřejší trénink."},"ICON-1376":{"nm":"Posilovací guma","de":"Čím víc ji natáhnete, tím víc se vzpírá a snaží se vrátit na místo. Zatímco snášíte ten odpor, tělo se nepozorovaně, kousek po kousku, prodlužuje. Protažení je nakonec jen stopou, kterou zanechal čas strávený vytrvalostí."},"ICON-1377":{"nm":"Jóga podložka","de":"Ve chvíli, kdy se rozprostře, na podlaze vznikne kousek země patřící jen mně samotné. Malé území k lehnutí, ležení a urovnání dechu. Začátek i konec dne se tiše sbírají na téhle jediné podložce."},"ICON-1378":{"nm":"Pěnový válec","de":"Zatlačíte-li pevně na ztuhlé místo, zprvu to bolí, ale hned poté přijde úleva. Uvolnit to, co ztuhlo, s sebou vždy nese trochu bolesti. Vždyť tělo i mysl se musí jednou stisknout, aby se mohly uvolnit."},"ICON-1379":{"nm":"Činka","de":"Zvednout stejnou váhu a zvednout ji znovu. Přesně o jedno zvednutí víc než včera, to je vše. V opakování, na němž není nic okázalého, paže mlčky sílí. Jeden kus kovu, jenž je jen a jen upřímný."},"ICON-1380":{"nm":"Kettlebell","de":"Jedna rukojeť roztočí celé tělo najednou. Když se kulatá váha otáčí a kreslí kruh, na zkoušku je vystavena rovnováha toho, kdo ji drží. Aby člověk zůstal nezakolísaný, musí nejprve poznat svůj vlastní střed."},"ICON-1381":{"nm":"Švihadlo","de":"Přeskočíte lano, jež vám svižně proletí pod nohama, a přeskočíte ho znovu. Stejně jako ta hra, kdy se s kamarády počítalo na dvorku, čím víc se hromadí čísla, tím víc dochází dech a tím víc přibývá smíchu."},"ICON-1382":{"nm":"Běžecké boty","de":"Pár, jehož skutečnou hodnotu poznáte, teprve když vykročíte na cestu. Rozřízne-li se ranní vzduch při běhu stejnou cestou znovu, roh, jenž byl včera daleko, je dnes hned za rohem. Vzdálenost si pamatují nohy."},"ICON-1383":{"nm":"Sportovní ručník","de":"Když otřete pot z čela, zůstane na něm vsáknutý jeden řádek dnešní snahy. Vypere se a stopa zmizí, ale to, co bylo vyliato, se přece jen kdesi pečlivě ukládá vrstva po vrstvě. Nejupřímnější povzbuzení vždy schne po vašem boku."},"ICON-1384":{"nm":"Láhev na vodu","de":"Vyprázdní se, naplní se, vyschne, dá se doušek. Ta prostá cesta tam a zpět tiše nese celý den. Stejně jako se u studny zvedala a klesala okovaná vědra, i den se znovu rozbíhá od aktu naplnění."},"ICON-1385":{"nm":"Proteinový koktejl","de":"Dobře protřepán a jedním douškem spolykán — sval, jenž se dnes rozdrtil, se zítra znovu naplní. Chuť sice není nijak honosná, ale tělo ví, že tohle je jazyk zotavení. Růst se vždy pije potichu."},"ICON-1386":{"nm":"Energetická tyčinka","de":"Jedna tyčinka, zploštělá v kapse. Nouzová zásoba, jež zaplní prázdný čas mezi jídly. Není na ní nic velkolepého, a přece tohle malé sousto pomůže vydržet ještě jeden pohyb navíc odpoledne."},"ICON-1387":{"nm":"Bonbón na hrdlo","de":"Zatočíte-li ho v ústech, chladivá máta jemně pohladí zdrsnělé hrdlo. Den, kdy se hodně mluvilo, noc, kdy se hodně zpívalo — jeden malý bonbónek utiší tu drsnou cestu. I sladkost má jasně své využití."},"ICON-1388":{"nm":"Čaj pro hlas","de":"Teplá pára hřeje hrdlo a jedním douškem se napětí v ramenou tiše rozpustí. Starý předpis, jako zázvorový čaj, který vařívala babička. Laskavý pozdrav, jenž se hlasu podává předtím, než se začne zpívat."},"ICON-1389":{"nm":"Medová voda","de":"Do vlažné vody se pomalu rozpouští jedna lžíce medu. Ten samý šálek, který dospělí obvykle namíchali, kdykoli bylo hrdlo drsné a suché. Není to ani lék, ani nápoj, jen sladkost, jež tiše hladí tělo zevnitř."},"ICON-1390":{"nm":"Nádržka zvlhčovače","de":"Nádoba, jež do pokoje vypouští jemnou mlhu. V zimní noci, kdy suchý vzduch škrábe na hrdle, neviditelně rozdává vlhkost. Starat se o někoho zpravidla plyne přesně takhle, beze zvuku."},"ICON-1391":{"nm":"Kupon na odpočinek","de":"Jeden list papíru, na němž stojí, že je dovoleno si odpočinout. Ve chvíli, kdy ho vezmete do ruky, se břemeno na srdci o kousek odlehčí. Že i zastavení se je forma cviku — tenhle malý lístek za vás dává svolení."},"ICON-1392":{"nm":"Rozvrh tréninku","de":"Nad časem zapsaným do jednotlivých políček se den pečlivě, vrstva po vrstvě, usazuje. Ráno hlasová průprava, odpoledne choreografie, večer odpočinek. I nejisté zítřejší dny se rozdělením čárami nenápadně stanou schůdnými."},"ICON-1393":{"nm":"Docházkové razítko","de":"Pevně se otiskne jedna značka na důkaz, že jste přišli i dnes. Čím víc přibývá lehce rozmazaných koleček v jednotlivých políčkách, tím spíš se z poctivosti, jež nevypadala jako nic zvláštního, nenápadně stává cesta. Malý důkaz každého dne."},"ICON-1394":{"nm":"Pochvalná samolepka","de":"Místo slova, že to bylo dobře zvládnuto, se tiše nalepí jedna hvězdička. Je to jen záblesk velký jako nehet, a přece ve chvíli, kdy se usadí v rohu sešitu, se celý den rozjasní. Pochvala je malá, a přesto podivně dlouho svítí."},"ICON-1395":{"nm":"Deníček duše","de":"Stránka, na níž se srdce rozechvělé za jevištěm rozpustilo do slov. I dny, kdy se nic nedařilo, když se do nich upřímně zapíšou, se odněkud stanou o něco lehčími. Srdce sílí přesně tak, jak moc se do něj člověk podívá."},"ICON-1396":{"nm":"Karta představového tréninku","de":"Zavřete oči, sevřete ji v ruce a v hlavě se tiše rozprostře jeviště. Předem si projít celé kolečko po místě, na němž jste ještě nestáli. Trasa nakreslená v představách dorazí o krok dřív než skutečné špičky nohou."},"ICON-1397":{"nm":"Zrcadlo pro nácvik mimiky","de":"Před zrcadlem se usmívá a zase strne, stejný výraz vytvoří přes sto krát. Právě tady se učí, že i radost, i smutek potřebují nácvik. Vždyť výraz tváře je jen přepisování srdce směrem ven."},"ICON-1398":{"nm":"Poznámky k choreografii","de":"Stránka, na níž je cesta, kterou projdou nohy a paže, přepsaná do kresby. Šipky tiše ukazují, kam se má tělo přesunout při každé osmé době. I pohyb, jenž se nijak nechtěl naučit zpaměti, se na téhle stránce pomalu zkrotí."},"ICON-1399":{"nm":"Videočip s choreografií","de":"Do jednoho malého čipu se vejdou stovky pohybů v celé své plnosti. Přehrajete-li si ho ještě jednou před spaním, konečky prstů se samy od sebe rozpohybují po té stejné cestě. Opakování je dalším záznamem, přepisovaným tentokrát do těla."},"ICON-1400":{"nm":"Plán jevištních pozic","de":"Jedna mapa jeviště, viděná shora, z ptačí perspektivy. Kdo se kde setká a kam se rozejde, je předem dohodnuto čarami a body. Aby mnozí společně nakreslili jeden obraz, musí si nejdřív rozdělit cesty."},"ICON-1401":{"nm":"Vstupenka na zkoušku","de":"Hlediště je prázdné a světla ještě spí. Tahle jediná propustka tě vpouští do toho ticha. Jeviště, když se nikdo nedívá – a právě tady začíná chvíle, kdy potkáš svou nejupřímnější podobu."},"ICON-1402":{"nm":"Stylová kniha","de":"S jakou náladou se dnes obléknu? I obyčejná košile má svůj vhodný pocit, šeptá tiše tahle kniha. Čím víc stránek obrátíš, tím víc se u konečků prstů, které kdysi váhaly před zrcadlem, hromadí malý cit pro styl."},"ICON-1403":{"nm":"Lak na vlasy","de":"Jeden střik, a ani vítr už to neroztřepí jen tak. Malá ctižádost udržet těch pár minut na jevišti dokonale na místě. Dokonalý okamžik se vždy dovršuje na téhle drobné umíněnosti."},"ICON-1404":{"nm":"Paleta make-upu","de":"Dvanáct barevných políček je dvanáct různých nálad. Jaký výraz dnes zpívat, o tom nejdřív rozhodnou konečky prstů a srdce je následuje. V každém prázdnějícím políčku tiše ulpívají dny strávené na jevišti."},"ICON-1405":{"nm":"Kostýmní špendlík","de":"V nejzářivější chvíli, na místě, které nikdo nevidí, drží drobný špendlík látku pevně. Aby nesklouzla, aby se nerozhrnula. Lesk na jevišti vždy stojí na něčí pevnosti."},"ICON-1406":{"nm":"Jmenná tabule","de":"Ve chvíli, kdy se prázdná tabule zaplní jménem, jeden mlhavý slib se vyjasní. Kdo bude stát na tomhle místě – rozhodne jediný řádek písma. Jméno je nejkratší a nejpevnější odhodlání."},"ICON-1407":{"nm":"Kartička pro fanoušky","de":"Adresát je jen jeden jediný člověk, a pro toho jednoho je to celý svět. Vtisknout vděčnost za několik nocí do jednoho krátkého pozdravu. Srdce takhle přetéká i na papíře velikosti dlaně."},"ICON-1408":{"nm":"Cvičný list na podpis","de":"Zpočátku i vlastní jméno vypadá při psaní cize. Za svítání, kdy ho stokrát natáhneš a tisíckrát zdokonalíš, dokud ruka nezapamatuje ten tah dřív než srdce. Tak se z jednoho jména konečně stane podpis."},"ICON-1409":{"nm":"List s otázkami k rozhovoru","de":"„Co na tuhle otázku odpovím?“ Konečky prstů svírající papír se lehce chvějí. Nejde o naučení odpovědí, ale o chvíli, kdy si po řadě srovnáš upřímnost – pohovor je totiž stejně jako vyznání nakonec otázkou pořadí v srdci."},"ICON-1410":{"nm":"Slovníček cizích slov","de":"Nejohmatanější roh prozrazuje slovo, na které ses díval nejdéle. O kolik času trvá, než jeden neznámý zvuk přilne k jazyku, o tolik se přibližuje i vzdálenost ke světu, kam jsi nikdy nevkročil."},"ICON-1411":{"nm":"Karta pro nácvik výslovnosti","de":"Kutálející se „ř“, unikající „s“. Jsou svítání strávená obracením karet jednu po druhé a krocením jazyka. Čím zřetelnější je řeč, tím zřetelnější je i tvář toho, koho chceš těmi slovy oslovit."},"ICON-1412":{"nm":"Kontrolní seznam pro živé vystoupení","de":"Mikrofon zapnutý, in-ear ověřen, trasa zkontrolována. S každým vyplněným čtverečkem se o kus vyprázdní i neklid v hrudi. Než vstoupíš na jeviště, důkladnost je ta nejtišší odvaha."},"ICON-1413":{"nm":"Regenerační náplast","de":"Existuje místo, které se hned po nalepení hřejivě rozlije. Přetížené rameno, ztuhlé lýtko – útěcha velikosti dlaně, jež tiše odpovídá na drobné signály těla. I dobře si odpočinout je součástí tréninku."},"ICON-1414":{"nm":"Chladicí polštářek","de":"Přiložíš ho tiše na oteklý kotník. Teprve když chlad pomalu pronikne dovnitř, ukáže se, kolik se toho dnes naběhalo. Zotavení za jevištěm přichází vždy takhle beze zvuku."},"ICON-1415":{"nm":"Lékárnička","de":"Náplasti, léky proti bolesti, kapesní zrcátko. Přijde chvíle, kdy je tenhle malý váček plný nenápadných věcí tím nejspolehlivějším ze všeho. Dobrota připravená předem zazáří nejjasněji před nečekanou krizí."},"ICON-1416":{"nm":"Suflérská karta","de":"Někdo ji zpoza kamery nenápadně zvedne. Věta, na kterou jsi málem zapomněl, je tam úhledně napsaná. Za pořadem, který plyne bez zaškobrtnutí, je vždycky takováhle ruka, co ji kamera nikdy nezachytí."},"ICON-1417":{"nm":"Obálka s úkolem","de":"Nejvíc buší srdce těsně předtím, než obálku roztrhneš. Ať je uvnitř cokoli, ta krátká skulinka vzrušeného nevědění. Kouzlo zábavného pořadu žije celé v tom jediném zapečetěném okamžiku."},"ICON-1418":{"nm":"Jmenovka","de":"Malé jméno připnuté na hrudi zastoupí první pozdrav. Mezi lidmi, kteří se ještě neznají, jedna jmenovka klepne a rozlomí led rozpaků. Od chvíle, kdy se jméno vysloví, začíná vztah."},"ICON-1419":{"nm":"Trestná samolepka","de":"Jeden lísteček plácnutý na čelo poraženého rozpoutá bouři smíchu. Je to na trest až příliš přátelské, takže i prohra se nakonec stane trvalou vzpomínkou. Malé, něžné znamení stvořené k tomu, aby se všichni zasmáli spolu."},"ICON-1420":{"nm":"Karta náhodného trestu","de":"Než se vytáhne, nikdo nic neví. Deset koleček se sloním chobotem, nebo jedna dávka roztomilosti. Ve chvíli, kdy svěříš celý svůj osud jednomu lístku papíru, se první ze všeho uvolní právě smích."},"ICON-1421":{"nm":"Karta s nápovědou","de":"Něco jako ruka tiše nabídnutá do zaseknutého místa. Nedá ti celou odpověď, ale ukáže cestu. Dobrá nápověda není řešení, ale tichý dar odvahy přemýšlet ještě jednou."},"ICON-1422":{"nm":"Karta šance","de":"Jediná příležitost, jak jedním tahem obrátit nakloněnou hrací desku. O výsledku rozhoduje to, kdy tuhle kartu vytáhneš. Štěstí, které jsi šetřil a šetřil, ukáže svou pravou cenu teprve v nejrozhodnější chvíli."},"ICON-1423":{"nm":"Karta na oddechový čas","de":"Že je v pořádku na chvíli zastavit, to za tebe řekne tahle karta. Zvednout ruku odvážně, když potřebuješ popadnout dech – i zastavení je plnohodnotná strategie a dobře si odpočinout je také místo v dovednosti."},"ICON-1424":{"nm":"Tlačítko smíchu","de":"Cvak, a v okamžiku stisknutí se vyvalí bublavý, veselý smích. Opravdu vtipná scéna si žádá, aby jí i takovýhle zvukový efekt nenápadně pomohl. Vřelost místnosti se takhle rozehřeje od jednoho malého žertíku."},"ICON-1425":{"nm":"Ovladač zvukových efektů","de":"Jedno tlačítko na potlesk, druhé na bučení. Kouzelník, který samotnými konečky prstů tvaruje náladu, sedí tiše v režii. Režie, kterou kamera nikdy nezachytí, je to, co té scéně dává dýchat."},"ICON-1426":{"nm":"Klapka","de":"Cvak, a s tím ostrým zvukem začíná záběr. Mezi desítkami špatných klapek a jedním jediným „dobré“, tahle černá deska úhledně odpočítá každý okamžik. Je to první takt, kterým záznam vykročí."},"ICON-1427":{"nm":"Značkovací páska","de":"Ve chvíli, kdy se špička nohy tiše dotkne té čáry, světla klesnou lehce dolů, jako by čekala. Jediné políčko vyryté do paměti až do vytření – jeviště je konečně dokonáno malým barevným pruhem na podlaze."},"ICON-1428":{"nm":"Světelný filtr","de":"Stejná tvář se barvou světla promění celá. V modrém filtru přebývá svítání, v červeném západ slunce. Atmosféra není nikdy daleko – je tiše složená uvnitř jednoho tenkého listu barevného papíru."},"ICON-1429":{"nm":"Baterie do kamery","de":"Jakmile začne blikat červené světýlko, srdce zneklidní jako první. Protože ta nejlepší scéna přichází vždycky na jedno procento nabití. Jedna náhradní v kapse se hned stane úlevou, že si můžeš vydechnout."},"ICON-1430":{"nm":"Paměťová karta","de":"Celodenní smích a kapky potu se natěsnají do čipu velikosti nehtu. Je tak malý, že se snadno ztratí, a o to je vzácnější. Váhu vzpomínek, které v sobě nese, nikdy nelze změřit velikostí."},"ICON-1431":{"nm":"Polaroidní film","de":"Cvak, a pak tiché čekání. Těch pár vteřin, kdy se na bíle prázdné ploše pomalu vynořuje tvář, je zvláštně vzrušujících. I okamžitá fotka v ruce potřebuje přesně jednu lžičku trpělivosti."},"ICON-1432":{"nm":"Film na fotokartičky","de":"Jaký výraz se na tenhle jediný list vytiskne, zůstává tajemstvím až do samotného okamžiku tisku. Právě tady se rodí tvář, která se stane něčím oblíbencem. Jeden malý list papíru v sobě nese tak velké srdce."},"ICON-1433":{"nm":"Sleeve na fotokartu","de":"Fotokartička se nikdy nedotýká holýma rukama. Stačí zmáčknout jeden roh a rozbolí to i úsměv toho dne. Zabalit svého oblíbence pečlivě do jednoho průhledného listu – i v opatrování je tolik oddanosti."},"ICON-1434":{"nm":"Toploader","de":"Vsuneš ji mezi dva tuhé listy a ani čas ji pak nedokáže jen tak pomačkat. Neohýbej se, nepřehýbej se. Chránit něco vzácného si vždy vypůjčuje o jednu vrstvu pevnosti navíc."},"ICON-1435":{"nm":"Balíček samolepek","de":"Odloupneš je jednu po druhé a přilepíš do rohu deníku, na zadní stranu notebooku. Jedním malým obrázkem se jednobarevný den obarví do všech odstínů. Touha zdobit si okolí nemá věkovou hranici."},"ICON-1436":{"nm":"Popisovač","de":"Při zvuku, jak inkoust šustí po papíře, se fronta prodlužuje a prodlužuje. Nad albem podaným roztřesenou rukou zůstane setkání dlouhé jen pár vteřin v paměti nadlouho. Srdce přechází po hrotu pera na druhou stranu."},"ICON-1437":{"nm":"Album s podpisem","de":"Otevřeš obal a jako první tě přivítá důvěrně známý zaoblený podpis. Pouto vzniklé skrze hudbu se na papíře přiblíží o kus dál. Uchovávat znamená tiše zastavit ten okamžik v čase."},"ICON-1438":{"nm":"Baterie do lightsticku","de":"„Rozsviť se, prosím.“ Těsně před vstupem ruce spěchají vyměnit baterie. Aby mezi desítkami tisíc světel nezhaslo právě to moje – malá baterie rozzáří celou tu obrovskou noc."},"ICON-1439":{"nm":"Pouzdro na lightstick","de":"Uloženo úhledně bez jediného škrábance, opatrováno až do křiku dalšího večera. I když rozpálené místo dávno vychladlo, s péčí ho odneseš domů. I nástroj pro povzbuzování má své místo a existuje srdce, které o ně pečuje."},"ICON-1440":{"nm":"Slogan","de":"Věta napsaná na dlouhé látce se rozvine napříč hledištěm. Ve chvíli, kdy se povzbuzení, které se nedalo vyslovit nahlas, doširoka otevře, upřímnost jednoho člověka se stává výkřikem všech. Ta látka se sama stává hlasem."},"ICON-1441":{"nm":"Mini banner","de":"Malé povzbuzení, které se vejde přesně do dlaně. Transparent zavěšený daleko patří všem, ale tenhle vlaje jen na kraji tvého stolu. Tiše se vlnící dokazuje, že malá velikost neznamená malé srdce."},"ICON-1442":{"nm":"Dopis fanouška","de":"Jméno adresáta bylo třikrát přepsáno, první věta sedmkrát smazána. Konečky prstů se chvějí těsně před zalepením obálky, protože srdce je až příliš upřímné. Uvnitř je složena upřímnost těžší než jedna poštovní známka."},"ICON-1443":{"nm":"Dárkový balicí papír","de":"Že ta nejvzrušivější vteřina přichází těsně před rozbalením, to ví balicí papír líp než kdokoli jiný. I když ví, že je jeho osudem být brzy roztržen, obalí se přesto tou nejjemnější strukturou, podobnou srdci toho, kdo dárek podává."},"ICON-1444":{"nm":"Stuha","de":"Uvážeš-li příliš pevně, škrtí, příliš volně, rozváže se, a najít přesně to místo mezi tím je oddanost. Do jednoho uzlu zvoleného konečky prstů se vejde tvar srdce. Poslední řádek dárku vždy místo tebe dopíše stuha."},"ICON-1445":{"nm":"Děkovná kartička","de":"Poděkování vyřčené nahlas se rozptýlí ve větru, ale napsané rukou zůstává dlouho. Je to akt vracení přijaté laskavosti s trochou navíc navrch. Zatímco vtiskáváš písmeno po písmenu, srdce se prohlubuje dvojnásobně."},"ICON-1446":{"nm":"Kupón na oběd","de":"S tímhle jediným lístkem se starost o oběd tiše rozplyne. Čerstvě uvařená rýže se stoupající párou, jídlo s políčky plnými příloh je slíbeno. Malý talisman, který spolehlivě ochrání hladové odpoledne."},"ICON-1447":{"nm":"Kupón na svačinu","de":"Vznikl proto, aby ho bylo možné vytáhnout ve tři odpoledne, když hlad vyšle jemný signál. Kupón, který ví, že jedna malá sladkost zvedne náladu o půl píď. Není to velká odměna, ale přichází tiše přesně ve chvíli, kdy je potřeba."},"ICON-1448":{"nm":"Kupón do kavárny","de":"Jeden teplý šálek a místo u okna, to je vše, co tenhle kupón slibuje. Vypadá to jako maličkost, ale pro někoho se z toho stane malá odměna za to, že přežil den. Něžná pozvánka, jejíž vůně dorazí o krok napřed."},"ICON-1449":{"nm":"Poukaz na úklid bytu","de":"Okna dokořán, přikrývky pořádně vyklepané, den, kdy uteče i poslední zrnko prachu. Kdo by řekl, že nemuset to udělat vlastníma rukama, je taková přepych. Když se pokoj rozzáří, tiše se urovná i srdce."},"ICON-1450":{"nm":"Opravářská sada","de":"Šroubovák, izolepa, pár nejasných součástek. Když se sejdou všechny, zdá se, že není nic, co by se nedalo spravit, ale otevřeš ji a vždycky jeden kousek chybí. Přesto krabička sebedůvěry, ze které se člověk cítí nějak jistější jen tím, že ji drží v ruce."},"ICON-1451":{"nm":"Šťastný lístek","de":"Prázdný lístek bez sedadla a bez čísla. Podstatné je, že na něm není napsáno, co dobrého dnes přijde. Vyplnit tu prázdnotu je totiž úkolem toho, kdo ho nosí v kapse."},"ICON-1452":{"nm":"Kostka","de":"Kamarádka, která nejlíp zná slovo spravedlnost. Nestraní nikomu a miluje všech šest stěn stejně. Jen na ten jeden okamžik, kdy opustí dlaň a kutálí se pryč, i dovednost a známosti na chvíli přenechají místo štěstí."},"ICON-1453":{"nm":"Cestovní lístek","de":"Slib, že odsud až tam stačí jeden krok. Kouzelný lístek papíru, který dlouhou cestu složí namalinko a schová do kapsy. Ve dne, kdy váháš vyrazit, není lepší zábrany proti výmluvám než tahle."},"ICON-1454":{"nm":"Lístek na nový pokus","de":"Místo aby padlému podala ruku, tahle vstupenka ho tiše postrčí do zad se slovy zkus to znovu. Nejtišeji ze všech ti sdělí, že selhání není konec, ale jen krátká čárka. Odvaha na ještě jednou se tady doplňuje."},"ICON-1455":{"nm":"Lístek na rychlé dokončení","de":"Něžný cheat kód, který o kousek přeskočí čekání. Kdo by mohl vyčítat srdci, které nevydrží ani tři minuty? Tady je trochu nefér radost, jako když prstem cvrnkneš písek v přesýpacích hodinách o kus dál."},"ICON-1456":{"nm":"Výrobní booster","de":"Stejné ruce, stejný čas, a přesto dvojnásobný výsledek. Vrní si na pracovním stole a vesele se točí, jako by říkal – na tajemství se neptej. Malé zařízení, které pilně se hýbajícím rukám tiše přidá křídla."},"ICON-1457":{"nm":"Cukrátko blízkosti","de":"I trapnost, kterou je slovy těžké rozmotat, se před něčím sladkým tiše rozpustí. Nad jedním bonbonem rozbaleným společně se pouto přiblíží o kousek víc než včera. Roztomilý objev – že sladkost je rychlostí sbližování."},"ICON-1458":{"nm":"Želé na zlepšení nálady","de":"V rozrušený den funguje něco studeného a měkkého jako kouzlo. Jedno kousnutí, a zamračený výraz se tiše rozvolní. Léčit srdce je od přírody vzácná věc, a to R nad ním nevisí jen tak pro nic za nic."},"ICON-1459":{"nm":"Třpytivý prášek","de":"Lehce ho posypeš na něco obyčejného a najednou je to zvláštní. V jádru je to jen třpytivý prášek, a přece se svět v okamžiku, kdy se snese dolů, zdá o trochu rozjařenější – zvláštní věc. Něco jako koření štěstí, které cvrnkne do všedního dne."},"ICON-1460":{"nm":"Jevištní páska","de":"Když stojíš na jevišti, nesčetná světla tě naráz najdou. To místo tiše vyznačí malé X na podlaze. To, co je nejpřesnější na neviditelném místě, nakonec drží i to největší jeviště."},"ICON-1461":{"nm":"Stahovací páska","de":"Malý hrdina, který jedním tahem uklidí zamotané kabely do pořádku. Že jednou utaženou už nejde vrátit zpět, je jeho slabina i kouzlo zároveň. Nezbytnost, kterou si tiše nachystají ti, kteří to s pořádkem myslí vážně."},"ICON-1462":{"nm":"Náhradní kabel","de":"Věc, která nemá žádnou přítomnost, dokud ji máš, a teprve když chybí, se po ní opravdu zatouží. Spí hluboko v tašce za jevištěm a v rozhodující chvíli se s bleskem probudí. Vlastním tělem dokazuje slovo připravenost."},"ICON-1463":{"nm":"Kontrolní tabulka na zkoušku","de":"Papír nabitý políčko po políčku pohyby, narážkami, dokonce i výměnami kostýmů. Chybí-li tu jediné zaškrtnutí, někomu se sevře srdce. Dokonalé jeviště zvedne oponu teprve poté, co je tahle tabulka celá vyplněná."},"ICON-1464":{"nm":"Cedule na natáčecí scéně","de":"Tady je kavárna, tamhle ulička, jdi za šipkami do úplně jiného světa. Lež namalovaná na překližce, a přece se před kamerou stává skutečnou. Poctivý průvodce, který celý svůj život zasvětil ukazování směru."},"ICON-1465":{"nm":"Mini trofej","de":"Zlatý kousek, po jehož převzetí se člověku nějak zdá, že vyrostl o kus. Třpytí se na stole a říká, že je vážně v pořádku nebýt první, že ví o všem, oč ses dnes snažil. Velká útěcha, kterou nabízí malá odměna."},"ICON-1466":{"nm":"Batoh","de":"Ve chvíli, kdy si ho hodíš na záda, je to, jako by šlo vyrazit kamkoli. Uvnitř toho moc není, ale možností je plný až po okraj. Dobrodružství vždy začíná tím, že se pevně utáhnou tyhle ramenní popruhy."},"ICON-1467":{"nm":"Kompas","de":"Že se nezaleknete, i když zabloudíte, je proto, že hrot střelky vždy ukazuje na sever. Způsob, jakým se dlouho chvěje a nakonec najde své místo, je přesně jako lidské srdce. Že je v pořádku bloudit, ti sděluje svým chvějícím se hrotem."},"ICON-1468":{"nm":"Sešit","de":"První strana je vždy prázdná. Co se na ni napíše, ví jen ten, kdo drží pero. Já prostě čekám, až se dnešní myšlenky stanou písmem a tiše na mě usednou. R hodnocení je vahou možnosti, která se má brzy naplnit."},"ICON-1469":{"nm":"Tužka","de":"Že je v pořádku se splést, je nejněžnější stránkou tohoto nástroje. Dokud je nablízku kamarádka guma, můžeš začít znovu, kolikrát jen chceš. Čím víc ji ořezáváš, tím je kratší, ale ta krátkost je důkazem, jak dlouho byla milovaná."},"ICON-1470":{"nm":"Fotografický film","de":"Ve chvíli, kdy jím projde světlo, se barva toho dne vtiskne beze zbytku. Že jednou minulý záběr už nikdy nelze vrátit, je zároveň napětím i kouzlem. Volba těch, kdo si v uspěchané době záměrně chtějí pamatovat o jeden takt pomaleji."},"ICON-1471":{"nm":"Instantní fotoaparát","de":"Cvak, a pak krátké čekání. Podržíš ho a jemně zatřeseš, a rozmazaný okamžik se pomalu vyjasňuje. Trochu kouzelný přístroj, který tohle přesné místo beze zbytku zachytí na jeden list papíru."},"ICON-1472":{"nm":"Stará fotografie","de":"O kolik vybledla barva, o tolik uplynulo času. Na každém ohmataném rohu se zdrželo něčí doteknutí. Že nejstarší fotografie chová tu nejzřetelnější vzpomínku, je asi právě kvůli těm dotekům."},"ICON-1473":{"nm":"Scrapbook","de":"Útržky příliš drahé na to, aby se vyhodily, se hromadí a hromadí, až se stanou jedním svazkem. Vybledlý kinolístek, sušený okvětní plátek, jeden krátký lístek s poznámkou. Pro cizí oči jen veteš, ale pro toho, kdo ho otevře, znovu ožije celé jedno období."},"ICON-1474":{"nm":"Lodní deník","de":"Dnešní vítr a vlny, a jeden řádek srdce. Zapisovat si to poctivě i v obyčejné dny je pravidlem plavby. Důkaz bezpečného doplutí je vždy zapsán někde v tomto tlustém záznamu."},"ICON-1475":{"nm":"Úlomek mapy","de":"Je to jen jeden roh celku, a přece bez něj nakonec cestu nenajdeš. Ten pocit, když se roztržený okraj přesně zapadne do jiného úlomku. R hodnocení má přítomnost jako poslední kousek puzzle."},"ICON-1476":{"nm":"Vzkaz v láhvi","de":"Aniž by věděl, kdo ho přečte, tiše se svěří vlnám. Neočekává odpověď, jen si přeje, aby tohle srdce někam dorazilo. Nejpomalejší, a přesto nejromantičtější způsob posílání zpráv."},"ICON-1477":{"nm":"Kostka","de":"Šest stěn se kulatě usmívá, jako by říkaly: zase ty? Stejný tvar, a přece s každým hodem jiná odpověď – to je neměnná vrtkavost téhle kamarádky. Ve chvíli, kdy opustí ruku, na chvíli svěříš volbu osudu."},"ICON-1478":{"nm":"Větrník","de":"Skutečně ožije, teprve když se zvedne vítr. Ponechán v klidu je to jen papírové křídlo, ale stačí, aby ho někdo foukl, a vesele se roztočí. Nestydět se za pomoc je moudrostí téhle malé kytičky."},"ICON-1479":{"nm":"Piknikový košík","de":"Otevřeš víko a jako první tě přivítá vůně kimbapu. Zelený trávník, rozprostřená deka a ruce, které si spolu podávají jídlo. Dny, kdy se tenhle košík naplnil, měly zvláštní shodou okolností vždy jasnou oblohu."},"ICON-1480":{"nm":"Váza","de":"Stačí zapíchnout jedinou květinu, a vzduch v místnosti se změní. Když je prázdná, je jejím pravým úkolem mlčky čekat. Nejpokornější jevištní rekvizita pokoje, která tiše snižuje vlastní přítomnost, aby o to víc zazářila květina."},"ICON-1481":{"nm":"Okvětní plátek","de":"Když vítr odnese jeden plátek, jaro je o tolik lehčí. Starý strom na dvoře pronáší každý rok stejný pozdrav – že i padání je jedním záhybem kvetení. Poletování není konec, ale dopis odeslaný předem příštímu jaru."},"ICON-1482":{"nm":"Růže","de":"Že napřed zvedá trny, je slib, že se nemá dotýkat nedbale. Uvnitř se skrývá to nejrudější srdce. Někdo jedno stéblo tiše položil k nohám a odešel, napsal své srdce jen barvou místo jménem."},"ICON-1483":{"nm":"Lilie","de":"Vedle upraveného bílého porcelánu vždy ležela tahle bílá květina. Ať se vůně nese daleko, jen ať se její vzezření nikdy nenaruší. Na tom místě, kde zvolila čistotu namísto okázalosti, lilie mlčky střeží jeden díl důstojnosti."},"ICON-1484":{"nm":"Tulipán","de":"Stojí v řadě s lehce skloněnou hlavou a působí to nějak upraveně. Květina, která má na starosti první řadu jarního záhonu. Ta poctivost, s jakou rozkvétá naráz a naráz i opadá, obarví krátkou sezónu nejsytěji."},"ICON-1485":{"nm":"Hyacint","de":"Na jednom stonku pověsil husto malé zvonečky. Zatřeseš jím a zvuk žádný není, místo něj se místností rozeznívá vůně. Na prahu jara jeden vázový dech, něžný přepych, který jedinou vázou vymění celý vzduch místnosti."},"ICON-1486":{"nm":"Preparát žáby","de":"Malé tělo, ve kterém se zastavil čas, uvnitř skleněné krabičky. Na štítku stojí: „Rýžová pole a nádrže; nejživější den po dešti.“ Teprve po zastavení zůstává v záznamu i teplota vody, u níž tenhle tvor žil."},"ICON-1487":{"nm":"Preparát ještěrky","de":"Ani jako preparát se nesmaže dovednost, s jakou uměla odhodit ocas a utéct. Malý host, který měl rád sluncem prohřáté kamenné zídky. V poznámce vedle úhledně stojí směr slunného místa, na které ráda šplhala."},"ICON-1488":{"nm":"Záznam krtka","de":"Deník toho, kdo se pohybuje pod zemí, je psán do struktury hlíny. Kde kopal a kde se zastavil – mapa neviditelných cest. Čas prožitý zády ke světlu se pro někoho stává tím nejsvědomitějším záznamem."},"ICON-1489":{"nm":"Preparát mušle","de":"Pevný vzor, který vlny tisíckrát obrousily a poslaly na břeh. Lidé z bahnitého pobřeží poznali podle samotné kresby lastury, ze kterého moře pochází. Tvar moře, které kdysi žilo a dýchalo, je celý uchován v preparátu velikosti dlaně."},"ICON-1490":{"nm":"Preparát korálu","de":"V hlubokém moři vyroste sotva o píď za stovky let. Vypadá jako větvičky, ale ve skutečnosti je to dům postavený společně nesčetnými drobnými životy. Že čím pomalejší věc, tím déle zůstává, dokazuje korál mlčením."},"ICON-1491":{"nm":"Stopa Aidong","de":"Úlomek příběhu roztroušený někde na ostrově. Jeden malý kousek papíru tiše ukazuje na další krok. Každé dobrodružství nakonec začíná sbíráním takovýchhle nepatrných stop, říká starý průvodce."},"ICON-1492":{"nm":"Podpisový úlomek","de":"Až se roztroušený vzor vrátí na své místo, teprve tehdy je dokonáno jediné znamení. Úlomek, do kterého je vyryta něčí jedinečná struktura. Dokud není složen, skrývá svůj význam, a v okamžiku, kdy zapadne, se konečně stává jménem."},"ICON-1493":{"nm":"Úlomek jevištní vzpomínky","de":"I když píseň skončí, mezi sedadly zůstává zbytkové teplo. Odloupneš to teplo a necháš ztuhnout, a vznikne takovýhle malý úlomek. Roztroušené střípky potlesku a jásotu, tiše sesbírané, znovu vzkřísí celou tu noc."},"ICON-1494":{"nm":"Debutové razítko","de":"V den, kdy poprvé zaznělo tvé jméno, ta inkoustová stopa vtisknutá na hřbet ruky. I opatrnost, s jakou se sušila, aby se nerozmazala, byla součástí startovní čáry. Jedno malé razítko dělá určitý den navěky nesmazatelným."},"ICON-1495":{"nm":"Medaile Top Idolu","de":"Tíha dovolená jen tomu, kdo vystoupá na nejvyšší místo. Ale tahle medaile není těžká kvůli kovu. Je to proto, že se v jednom bodě beze zbytku shromáždila váha nesčetných rukou, které společně naplnily jeviště."},"ICON-1496":{"nm":"Malý klíček","de":"První klíč od bytu patřil vždy k nejzazšímu pokoji. Místo, kde se dřív než zamykat, učilo odemykat. V den odchodu na studeném kovu ještě dlouho přetrvává teplo, které tam zanechala dlaň."},"ICON-1497":{"nm":"Truhla s pokladem","de":"Dokud se neotevře, nikdo neví, co je uvnitř. Právě to nevědění je skutečným pokladem téhle truhly. V krátkém okamžiku zvedání víka se každý na chvíli vrátí do rozechvění dětských dní."},"ICON-1498":{"nm":"Stavební plán","de":"Na liniích vyrýsovaných políčko po políčku žije budova, která ještě nestojí. Rozevřít výkres znamená projít si zítřek předem, aspoň jednou. Jedna dobře natažená čára podpírá zítřek, který se nezhroutí."},"ICON-1499":{"nm":"Kartička s receptem","de":"Na jedné ohmatané kartičce je babiččina ruka zapsána v množstvích. Neurčitá slova jako „špetka soli“ jsou tím nejpřesnějším tajemstvím. Čím víc písmo bledne, tím zřetelněji se vybaví kuchyně, kde se to jídlo kdysi vařilo."},"ICON-1500":{"nm":"Stavební povolení","de":"Jeden list papíru mění prázdný pozemek v „místo, které lze používat“. Nová budova vždy nejdřív potřebovala razítko vesnice. Povolení je nakonec vřelou pečetí, která říká, že tady je v pořádku něco začít."},"ICON-1501":{"nm":"Přístavní povolení","de":"Než loď mohla spustit kotvu, potřebovala nejdřív tento jediný list papíru. Vybledlá pečeť přístavu je prvním pozdravem těm, kdo přicházejí zdaleka. Mezi odjezdem a příjezdem přístav vždy otevírá své srdce jediným listem papíru."},"ICON-1502":{"nm":"Ostrovní osvědčení o přijetí","de":"Malé osvědčení, že jste se stali jedním z ostrovních. Když se nastěhoval nový soused, stará vesnice přidala jeho jméno na seznam a rozdávala teplé rýžové koláčky. Je to jen kus papíru, ale je na něm napsáno jasné přivítání: „Teď jsi i ty jedním z nás.“"},"ICON-1503":{"nm":"Dveřní jmenovka","de":"S jediným jménem zavěšeným vedle dveří se prázdný pokoj konečně stává něčím domovem. I ve starých hostinských pokojích visela jako první deska vyřezaná se jménem hostitele. Jmenovka je malá, ale je v ní plno tepla slov „tady někdo žije“."},"ICON-1504":{"nm":"Fanouškovská známka","de":"I ta péče, s jakou se známka olízla a pevně přitiskla, byla součástí celého dopisu. Připevnit milovaný pocit na malý kousek papíru a poslat ho daleko. I v digitální době někdo své srdce raději posílá poštou, vlastní rukou."},"ICON-1505":{"nm":"Odznak Třpytivého ostrova","de":"Připni si ho na límec a malé světýlko tě bude následovat na každé cestě. Když na ulici potkáš někoho se stejným odznakem, porozumíte si beze slov. Třpyt není chlubení, ale tichý signál: „Milujeme stejný ostrov.“"},"ICON-1506":{"nm":"Dílenský stůl","de":"Poškrábaná deska svědčí o rukou, které vytvořily nejvíc věcí. Místo, kde se něco opravovalo, spojovalo a zdokonalovalo. Víc než čistý psací stůl toho ve skutečnosti nepořádný pracovní stůl uchovává mnohem víc příběhů."},"ICON-1507":{"nm":"Úložná krabice","de":"Čím vzácnější věc, tím dřív si pro ni najdeme místo. I lidé za starých časů ukládali vzácné listiny zvlášť, do truhliček z pavlovnie. Dobře něco uschovat nakonec znamená úhledně složit dnešek pro někoho v budoucnosti."},"ICON-1508":{"nm":"Zásobovací bedna","de":"Když je toho nadbytek, sbíráme; když se nedostává, sáhneme po zásobě. Je v tom moudrost doby, kdy plná sýpka znamenala klidné srdce. Hromadit zásoby znamená předem podat laskavé jídlo svému budoucímu já."},"ICON-1509":{"nm":"Chladicí bedna","de":"Truhlík naplněný ledem udržel chlad i uprostřed léta. Jako by se stará moudrost ledovny přenesla do velikosti dlaně. Uchovat chlad znamená nechat ten nejčerstvější okamžik zůstat o něco déle."},"ICON-1510":{"nm":"Ruční pumpa na vodu","de":"Zatáhneš za páku nahoru a dolů a hluboko ze země vytryskne voda. Poctivý stroj, který se rozproudil naplno, teprve když do něj člověk nejdřív nalil jeden džbán zaváděcí vody. U studny se odjakživa vědělo, že napřed musíš dát, abys pak mohl dostat."},"ICON-1511":{"nm":"Čistička vody","de":"Malý zázrak, při němž kalná voda po vrstvách zesvětlává. Lidé za starých časů filtrovali vodu vrstvením písku a dřevěného uhlí v hliněných džbánech. Čistota se nezíská zadarmo – je to péče pomalého procezování."},"ICON-1512":{"nm":"Stojan na konev","de":"Ve chvíli, kdy konev na zalévání dostane svoje místo k odpočinku, se den na záhonu zklidní a srovná. Určit místo, kam pověsit nářadí, je zvyk člověka, který svou práci miluje. Jakmile je jedno místo dané, celý dvorek se stane o něco uspořádanějším."},"ICON-1513":{"nm":"Stojan na rybářský prut","de":"Člověk může odejít, než přijde záběr, ale rybářský prut si drží své místo. Trpělivý postoj toho, kdo u řeky vylovil celá léta, je tu pevně zakotven. Stojan je nakonec opěrou, na niž lze na chvíli odložit netrpělivost."},"ICON-1514":{"nm":"Sběrný košík","de":"Hrst horských bylin, jedna polní kytka – matčino ruční břímě, které nosila domů. Škvírami spletenými z bambusových proutků potichu prosakuje vůně hlíny. Podle toho, co do něj vložíš, se z prázdného košíku může stát jaro nebo podzim."},"ICON-1515":{"nm":"Stoupa","de":"Bum, bum – pravidelným rytmem se tlouklo obilí a probouzel se tím den vesnice. Nástroj, jehož zvuk palice na rýžové koláčky za svátků naplňoval uličky. Aby se tvrdé stalo měkkým, je potřeba vytrvalý rytmus pracujících rukou."},"ICON-1516":{"nm":"Prkénko na krájení","de":"Každá stopa po noži vyrývá historii jednoho jídla. Poškrábané dřevěné prkénko je medaile kuchyně za nejpilnější ruce. Krájet něco začíná touhou pohostit to s péčí."},"ICON-1517":{"nm":"Hrnec","de":"Bublavý zvuk vaření je něžnější než jakákoli hudba. V hladovém svítání je těch tři minuty čekání, než se uvaří nudle, tou nejsoukromější útěchou. Po celém kulatém dně se rozehřívá teplo touhy někoho nakrmit."},"ICON-1518":{"nm":"Pánev","de":"Dovednost usmažit něco v mžiku nad ohněm závisí na této jediné pánvi. Čím lépe je povrch vypálený, tím míň se přichytává a tím víc se leskne. Dlouho používaná litinová pánev je sama o sobě důkazem let, která kuchyně prožila."},"ICON-1519":{"nm":"Trouba","de":"Zatímco zavřeš dvířka a čekáš, uvnitř se potichu děje kouzlo. Čas, kdy těsto kyne a barva dozrává. I když to nevidíš, když vyčkáš s důvěrou, teplý výsledek otevře dvířka a vyjde ven."},"ICON-1520":{"nm":"Mixér","de":"I to nejtvrdší se sem vloží a v mžiku se z toho stane hladký nápoj. Malý vír, v němž se různé suroviny promísí a zrodí se nová chuť. Souznění nakonec znamená, že si každý trochu obrousí své hrany."},"ICON-1521":{"nm":"Metla","de":"Jediný pohyb zápěstí uvězní vzduch a to, co bylo řídké, se s rychlostí šlehání pevně zvedá. Zatímco bublinky rostou jako vrcholky, nenapuchá jen samo těsto. Spolu s ním roste i touha dnes někoho nakrmit."},"ICON-1522":{"nm":"Mlýnek na kávu","de":"Otočíš klikou nad hrstí zrnek a vůně se rozláme mezi zoubky jako první. V okamžiku, kdy paži rozbolí, je mletá káva konečně jemná, a první doušek je hluboký přesně tak, jak velká byla ta námaha. Péče vždy začíná v zápěstí."},"ICON-1523":{"nm":"Mlýnek na mouku","de":"Zrno vklouzne mezi kameny a vynoří se jako bílá mouka. Nevadí, když napoprvé není jemná, prostě ji semlete ještě dvakrát. I to, jak udělat z hrubého jemné, má svůj postup, potichu nás učí mlýnek."},"ICON-1524":{"nm":"Pilařský stůl","de":"Když se na stůl položí kmen, pila si nejdřív přečte jeho slój. Sukům se vyhne a řeže jen po rovné cestě, aby se prkno nezkroutilo. Řezat dřevo nakonec znamená úhledně rozprostřít čas, který jeden strom prožil."},"ICON-1525":{"nm":"Šicí stroj","de":"Rrr – zvuk jehly, jak se zakusuje do látky a řítí se vpřed, naplňuje pozdní noc. Jediný šev spojí dva díly v jedno tělo a v každém skrytém stehu uvnitř jevištního kostýmu je pevně všito něčí probdělé hodiny."},"ICON-1526":{"nm":"Barvicí stůl","de":"Ponoříš bílou látku a vytáhneš ji ven: napřed je světle zelená, teprve setkáním se vzduchem konečně zmodrá. Ta barva prý přijde, až se indigo louhuje potřetí. Že čekání samo se stává barvou, jsem se poprvé naučila právě před tímto barvicím stolem."},"ICON-1527":{"nm":"Fotografický stativ","de":"Ve chvíli, kdy tři nohy roztáhne a dotkne se země, se rozechvělý svět zastaví. Záběr, který by se v ruce chvěl, se zpřehlední na slibu těchto tří bodů. Chceš-li se na něco dívat dlouho, musíš nejdřív umět stát v klidu."},"ICON-1528":{"nm":"Světelný stojan","de":"Posadíš světlo na jediný sloupek a kdekoli v místnosti vznikne malé jeviště. Stačí lehce naklonit úhel a stíny se prodlouží, výrazy ožijí. Nemaže tmu, ale laskavě jí i tmě samotné najde místo."},"ICON-1529":{"nm":"Mikrofonní stojan","de":"Ve chvíli, kdy nastavíš výšku, se určí vzdálenost mezi ústy a písní. I když pustíš ruce, hlas zůstane přesně na svém místě. Teprve na jevišti, kde jsou obě ruce volné, začíná píseň zpívaná celým tělem."},"ICON-1530":{"nm":"Notový pult","de":"Když se rozevřený list papíru šikmo opře, noty se seřadí do výšky očí hráče. I když další takt přijde na jediné gesto, opěrka se nezachvěje. Za něčím vystoupením je vždy tiché, mlčenlivé místo."},"ICON-1531":{"nm":"Zahrádka","de":"Zoráš hlínu a vyryješ brázdy a na zemi se objeví tenké linky slibu. Pár dní po zasetí semínek se zdá, že se nic neděje, ale jednoho rána křehké děložní lístky prorazí půdu. Je to výjev, který uvidí jen ten, kdo čekal."},"ICON-1532":{"nm":"Úrodná zahrádka","de":"Stejné semínko, a přece v této zemi mají listy dvojnásobnou velikost. Zapíchneš prst a tmavá, měkká hlína ti zůstane až pod nehty. To, že něco dobře roste, byla nakonec práce, kterou tiše vykonala neviditelná půda pod nohama."},"ICON-1533":{"nm":"Skleník","de":"Pod skleněným stropem plynou roční období o jeden takt pomaleji. I když venku padá jinovatka, uvnitř je vlhko jako uprostřed léta. Pro to, co je citlivé na chlad, tu někdo tiše uvěznil sluneční svit pod střechou."},"ICON-1534":{"nm":"Bylinkový záhon","de":"Přejedeš konečky prstů po listech a vůně tě pozdraví jako první. Bazalka, rozmarýn, máta – při každém jméně ulpí na prstech jiná vůně. Jediný malý záhon dokáže laskavě proměnit celou kuchyni."},"ICON-1535":{"nm":"Sad","de":"Na jaře se větve prohýbají pod stínem květů, na podzim pod tíhou plodů. Vylezeš po žebříku, utrhneš jeden a kousneš – a v ústech ti vybuchne sladkost, kterou celý rok sbíralo slunce. Je to jako odpověď, kterou strom posílá člověku."},"ICON-1536":{"nm":"Houbařská kláda","de":"Do skáceného kmene se navrtají díry a zasadí se myceliem a mrtvý strom znovu něco vypěstuje. O pár dní později, ráno kdy se v hloučcích vynoří klobouky, na místě, které jsme považovali za konec, potichu začíná nový život."},"ICON-1537":{"nm":"Včelí úl","de":"Přiblížíš ucho a zevnitř uslyšíš tichý, pilný bzukot. Tisíce mávnutí křídel se sejde, aby vznikla sotva jedna lžička sladkosti. Denní dřina obletování květin se tu hromadí, lepkavá a zlatavá."},"ICON-1538":{"nm":"Kurník","de":"Ještě než se rozední, ti na bidýlku se ozvou jako první šustěním. Vsuneš ruku do teplé slámy a nahmátneš vejce, které si ještě drží teplo. Místo, jež jako první ohlásí ráno, jako první i prostírá snídani."},"ICON-1539":{"nm":"Pastvina","de":"Rozlehlá pláň, kde se vůně trávy mísí s vůní slunce. Nad hřbety, jež se v ohradě líně přežvykují, přeplouvají stíny mraků. V místě, kde není kam spěchat, plyne pomalu i čas, jako by se pásl."},"ICON-1540":{"nm":"Sýrárna","de":"Čerstvě nadojené mléko postupně tuhne srážením a zráním. Počkáš pár měsíců na polici chladné jako jeskyně a do bílé hmoty se vpije hluboká vůně. Sýr je jméno dané jen mléku, které nespěchalo."},"ICON-1541":{"nm":"Tofuárna","de":"Fazole se namočí, rozemelou a uvaří a syrové sójové mléko získá oříškovou chuť. Jedna kapka nigari spojí rozptýlené v jemné tofu a lehkým přitlačením dostane hranaté obrysy. Je to ruka, která utiší rozptýlené srdce a dá mu tvar."},"ICON-1542":{"nm":"Čangdokte – terasa se sudy","de":"Na slunném koutě dvora se u sebe choulí nízké hliněné sudy a hřejí se na světle. Zvedneš víko a zavane vůně prolouhovaného času. Chuť pasty, kterou babička nakvasila, je ve skutečnosti pojídáním let po jedné lžíci."},"ICON-1543":{"nm":"Mlýn","de":"Když se s rachotem otočí kameny, obilí se rozpustí na mouku. Bílý prach se vznáší ve slunečních paprscích a lidé, kteří chtějí umísit mísu rýžových koláčků, čekají na řadu. Vesnický svátek vždy jako by začínal právě u tohoto prahu."},"ICON-1544":{"nm":"Pekárna","de":"Škvírou dvířek trouby prosakuje vůně másla a cukru. Ve chvíli, kdy nakynuté těsto zezlátne, se kroky kolemjdoucích před obchodem nevědomky zpomalí. V jednom bochníku čerstvě upečeného chleba je něha, které nikdo neodolá."},"ICON-1545":{"nm":"Stánek s pouličním jídlem","de":"Plachta z igelitu vlaje ve větru a omáčka na tteokbokki bublavě zahušťuje. Večer, kdy vypiješ vývar z papírového kelímku k jedné rybí špejli, je místem, kde se naráz roztaje zima i hlad. Malá útěcha usazená na konci uličky."},"ICON-1546":{"nm":"Evropská kuchyně","de":"Pánev se rozehřívá a olivový olej praská. Jediné otočení knoflíku ohně rozhodne, jestli se omáčka zahustí, nebo připálí. V místě, kde se váží i barevná rovnováha na talíři, se z jednoho jídla stává pečlivě nastudované představení."},"ICON-1547":{"nm":"Čínská kuchyně","de":"Nad prudkým plamenem se wok otáčí sem a tam, jako by tančil. V krátkém okamžiku, kdy vyšlehnou plameny, se vůně surovin celá uzavře uvnitř. Rychle a horce – tajemství čínské kuchyně se skrývá v tom jediném dechu, který propásneš, jen když zaváháš."},"ICON-1548":{"nm":"Kavárna","de":"Otevřeš dveře a jako první tě přivítá vůně kávových zrn a tichá hudba. Místo u okna, chladnoucí latte a otevřený sešit. Aby sis v uspěchaném dni mohl na chvíli oddechnout, město tu a tam ukrylo právě takové malé pokojíky."},"ICON-1549":{"nm":"Cukrárna","de":"Ve skleněné vitríně čekají na hosty v řadě pestrobarevné dortíky. Ve chvíli, kdy hrot vidličky rozdělí krém, se koutky úst zvednou jako první. Malý, sladký předpis, po kterém je snesitelný i smutný den – stačí jeden kousek."},"ICON-1550":{"nm":"Řeznictví","de":"Pod červeným světlem leží maso úhledně podle vláken. Na jedinou větu „Dneska je dobrý tohle“ sklouzne nůž na přesně tu správnou tloušťku. Sytost večerní tabule tiše začíná právě u této ruky, která drží stále stejné místo."},"ICON-1551":{"nm":"Rybí zpracovatelský stůl","de":"Pracovní stůl, kde se mísí ranní rybí pach s chladem ledu. Šupiny odlétají a ruce tuhnou zimou, přesto oko, jež vybírá to nejčerstvější, se nezastaví. Věci, které právě vylovili z moře, tu nacházejí cestu na stůl."},"ICON-1552":{"nm":"Solné pole","de":"Zadržíš mořskou vodu a zbytek udělá slunce s větrem. Počkáš pár dní, až voda vyschne, a na dně vyklíčí bílé krystaly jako hvězdy. Hrst slanosti je ve skutečnosti dar, který moře s nebem pomalu společně vytvořily."},"ICON-1553":{"nm":"Sušák na mořské řasy","de":"Na dlouhé šňůře visí bok po boku mořská řasa a kombu a houpají se ve větru. Věci nasáklé mořskou vodou při sušení tmavnou do sytě zelené. Nejskromnější chuť moře, kterou spolu utvořily slunce a mořský vítr, tu visí."},"ICON-1554":{"nm":"Malé molo","de":"Dřevěná prkna napůl ponořená ve vodě se pod nohama lehce houpou. Přesně to pravé místo, kam přivázat jednu malou loďku. Odjezd do dálky i šťastný návrat – oboje začíná i končí právě v tomto jediném úseku."},"ICON-1555":{"nm":"Přístavní sklad","de":"Otevřeš dřevěné dveře prosycené mořským větrem a sítě, sudy a lana jsou navršené až ke stropu. Náklad na dalekou plavbu a náklad, jenž právě dorazil, tu spolu na chvíli přebývají pod jednou střechou. Místo jako přestupní stanice, kde se odjezd a návrat na okamžik míjejí."},"ICON-1556":{"nm":"Maják","de":"Teprve když je noční moře nejtemnější, začíná svou práci. Kroužící světlo protíná mlhu a hlásí: „Tady vede cesta.“ Vysoký strážce, který kvůli něčímu bezpečnému návratu nikdy neusne."},"ICON-1557":{"nm":"Loděnice","de":"Postavíš kýl a připevníš žebra a kostra jedné lodi nabývá tvaru. Na dvoře, kde celý den zní údery kladiv, sní loď, jež ještě nezná chuť vody, o své první plavbě. Místo, kde se člověk nejdřív musí zpevnit, aby mohl odplout."},"ICON-1558":{"nm":"Nahrávací kabina","de":"Jakmile se zavřou dveře, všechny zvuky zvenčí v okamžiku zmizí. Za sluchátky uslyšíš jen vlastní dech a rytmus. V tichu této malé místnosti se konečně rodí hlas, který smí se chvět, jak chce."},"ICON-1559":{"nm":"Hudebna","de":"Harmonie prosakující škvírou dveří naplňují chodbu. Někdo hledá tón, někdo počítá takt. Místo, kde se smí míchat nemotorné zvuky se zkušenými, laskavá učebna, kde každá píseň dělá své první kroky."},"ICON-1560":{"nm":"Klavírní pokoj","de":"Otevřeš víko klaviatury a na bílých klávesách sedí jemná vrstva prachu. Ve chvíli, kdy se jich dotknou prsty, se místností rozlije jasný zvuk. Pokud existují večery, kdy člověk není osamělý ani sám, je to nejspíš díky tomuto jedinému klavíru."},"ICON-1561":{"nm":"Taneční sál","de":"Zatlačíš špičkami a podlaha tě zase odrazí zpět. Zatímco zrcadla na čtyřech stěnách čtyřikrát okopírují stejný pohyb, tělo si zapamatuje choreografii o půl doby dřív než hudbu. Místnost, kde pot a dech setrvávají nejdéle – pohyby tu vypěstované vycházejí na jeviště."},"ICON-1562":{"nm":"Posilovna","de":"Váha nikdy nelže. Lidé mě vyhledávají každé ráno, protože milují právě tu upřímnost – přesně tolik, kolik zvedneš, se ti připíše na ramena. Do zrcadla se pomalu nevyrývají svaly, ale hodiny, které jsi vydržel bez vzdání se."},"ICON-1563":{"nm":"Jógová místnost","de":"Zhluboka se nadechneš a máš pocit, že se dřevěná podlaha nadechne spolu s tebou. Místnost, kde se pomalu skládá den, jenž se sem přihnal ve spěchu; na jediné podložce se každý vrací k rytmu vlastního dechu. I uspěchané srdce se tu na chvíli odloží."},"ICON-1564":{"nm":"Maskérna","de":"Těsně předtím, než vyjdou na jeviště, se lidé tady na chvíli stanou někým jiným. Když žárovky kolem zrcadla rovnoměrně prohřejí tvář, chvění ulpí na konečku pudřenky a tiše se schová za límec. Místo, kde proměna začíná i končí."},"ICON-1565":{"nm":"Kostymérna","de":"Než je jedna scénická souprava hotová, oblečení pověšené tady se desítkykrát obléká a svléká. Figurína otáčející se se zapíchnutými špendlíky, švové linie nakreslené křídou. Za leskem vždy zůstává stopa něčího šití."},"ICON-1566":{"nm":"Televizní kulisa","de":"Že stačí opravdově vyzdobit jen tu jedinou stranu, kterou zabírá kamera, jsem se naučila brzy. Zajdeš za překližku a je tam jen prázdná kostra. Podepřít nádheru přední strany je vždy úkolem neviditelných latí."},"ICON-1567":{"nm":"Fotoateliér","de":"Prvním trikem je vrhnout světlo ze tří stran, aby zmizely stíny. Hlavní světlo vykreslí tvář, dosvětlovací stín, zadní světlo konečky vlasů. Ve zlomku okamžiku, kdy padne závěrka, jedno bílé pozadí zachytí dnešní nejkrásnější úsměv."},"ICON-1568":{"nm":"Koncertní sál","de":"Ve vysokostropé tmě chovám vždy stejný slib: že až se zvedne opona, i prázdná sedadla zadrží dech jako jeden člověk. Kvůli tomu jedinému okamžiku, kdy padne první úder, stojím celý rok tiše prázdný."},"ICON-1569":{"nm":"Kabinka pro fanmeeting","de":"Vzdálenost mezi rukou a rukou je přesně na šířku jednoho stolu. Krátký pozdrav, chvějící se podpis, jedno slovo, které nakonec nepadlo, míjejí v řadě. V této malé kójí se dlouho pěstovaný milovaný pocit poprvé setká tváří v tvář."},"ICON-1570":{"nm":"Postel","de":"Konec dne vždy jako první přijímala právě já. Jakmile se v ní usadí nohy ztěžklé z tréninku i chvění, jež zůstalo za jevištěm, ráno začíná znovu na lehkých špičkách. Popřeju dobrou noc a beze slov tě obejmu."},"ICON-1571":{"nm":"Palanda","de":"Mezi horním a dolním patrem spojuje dva lidi pět příček žebříku. Tiché hlasy sdílené po zhasnutí, na strop nalepené svítící hvězdičky. Stísněné ubytování se stává nejprostornějším díky příběhům, které každou noc stoupají a klesají po žebříku."},"ICON-1572":{"nm":"Polička","de":"Podle toho, co si na ni postavíš, je vidět, kdo jsi. Vedle sebe v řadě stojí přijatý dopis, první trofej, vybledlá vstupenka. Nejsem nábytek na vychloubání, ale místo, které tiše vystavuje vzpomínky, jichž se člověk nemohl vzdát."},"ICON-1573":{"nm":"Psací stůl","de":"S rozevřeným sešitem na texty se přes přeškrtnuté stopy znovu táhne nová linka. Přes noc nastřádané papírové kelímky a sotva vylovená jedna melodická linka. Pomalá práce převádění srdce do slov se vždy tiše odehrává právě na této rovné ploše."},"ICON-1574":{"nm":"Židle","de":"„Sedni si na chvíli“ je nečekaně laskavá věta. Ať už se schůze protahuje nebo trénink táhne do nekonečna, opěradlo mlčky přijímá váhu člověka. Vím, že čím déle někdo stál, tím víc mě uvítá."},"ICON-1575":{"nm":"Pohovka","de":"Aby se pozdní noc v ubytovně proměnila v obývák, stačím já sama. Namačkáte se všichni k sobě a díváte se na zábavný pořad, a než se nadějete, jeden z vás už usnul opřený o loketní opěrku. Prohloubené místo uprostřed dokazuje teplo toho domova."},"ICON-1576":{"nm":"Stůl","de":"Když se posadíte kolem, nikdo už není na čestném místě. Čerstvě uvařený guláš, cinkání lžic, dnešní zážitky se scházejí do středu. Když se rozprostře jedna kulatá plocha, i roztroušený den se znovu posadí k jednomu stolu."},"ICON-1577":{"nm":"Skříň","de":"Kdykoli se mění roční období, zevnitř se vyvalí staré příběhy. Jevištní kostýmy a běžné oblečení stojí rameno na rameni, za zavřenými dveřmi oblečení čeká, až přijde jeho řada. Teprve otevřením dveří se rozhodne, jaký den dnes obléknete."},"ICON-1578":{"nm":"Zrcadlo","de":"Pochvalu i vadu vracím se stejnou upřímností. Místo posledního zkoumání před vykročením na jeviště, před mnou si lidé upravují výraz a napřimují postoj. Nejupřímnější přítel nikdy nepromluví jediné slovo."},"ICON-1579":{"nm":"Toaletní stolek","de":"V každé malé zásuvce spí jiná tvář. Jedna tuba na jeviště, jedna na běžné dny, jedna limitovaná edice odložená stranou. Posadíš se před zrcadlo a pomalu si nejdřív rozhodneš, kým se dnes staneš, než vykročíš ze dveří."},"ICON-1580":{"nm":"Koberec","de":"Dotek, který bosé nohy pocítí jako první, určuje teplotu té místnosti. Stopy posedávání v kruhu, pojídání pochutin a povalování zůstávají jako žmolky. Nábytek, který pracuje z toho nejnižšího místa a chladnou podlahu ohřívá o píď víc."},"ICON-1581":{"nm":"Závěs","de":"Kolik rána vpustit dovnitř, rozhoduji já. Když mě jen trochu odhrneš, slunce vnikne dovnitř dlouhým pruhem; když mě pevně zatáhneš, i pozdní vstávání se stane odpustitelným. Stát mezi oknem a pokojem a tiše regulovat množství světla je úkol, který je vždy svěřen právě mně."},"ICON-1582":{"nm":"Lampa","de":"Stejný pokoj se podle barvy světla stává úplně jinou dobou dne. Žluté světlo protáhne večer donekonečna, bílé světlo ostře probudí svítání. Kouzelník velký jako dlaň, který jediným vypínačem lstivě změní náladu celého dne."},"ICON-1583":{"nm":"Nástěnné hodiny","de":"Zvuk vteřinové ručičky je slyšet jen v tiché místnosti. Čím hlouběji se ponoříš do tréninku, tím víc na mě zapomínáš, a když náhodou vzhlédneš, za oknem je náhle svítání. Bez výčitek vůči uplynulému času jen mlčky ukazuji na další dílek."},"ICON-1584":{"nm":"Váza","de":"I když květiny uvadnou, své místo neponechávám prázdné. Nádoba, jež na chvíli uchová přijatý cit; dokud je tu ruka, která mění vodu, stůl zůstává jasný. I ve chvíli, kdy jsem prázdná, stojím v podobě někoho, kdo čeká."},"ICON-1585":{"nm":"Rámeček na plakát","de":"I zavěsit na zeď oblíbenou tvář vyžaduje péči. Místo, kam sluneční svit nedosáhne přímo, jediný hřebík zavěšený přesně vodorovně. List papíru, uložený opatrně za sklem, mě jako první pozdraví každé ráno, když vstoupím do pokoje."},"ICON-1586":{"nm":"Tabule na fotokartičky","de":"Řadit podle abecedy, nebo podle data vydání – právě to šťastné dilema je začátkem fanouškovství. Jedna prázdná přihrádka je místo pro oblíbence, kterého jsem ještě nepotkala. S každou přidanou kartičkou se tabule stává mou vlastní malou kronikou."},"ICON-1587":{"nm":"Stojan na světelnou hůlku","de":"Baterii vyndat, rukojeť nahoru. I v úhlu, ve kterém ji nakloníš a postavíš, je svůj vlastní trik. Zatímco čeká na příští jásot, hůlka právě tady zhasne světlo a úhledně si lehne. Kdo si dobře odpočine, ten pak zazáří jasněji."},"ICON-1588":{"nm":"Police na trofeje","de":"Do první řady se staví ta nejstarší. Od sošky z malé soutěže po pohár z velkého jeviště se neřadí podle výšky, ale podle pořadí, jaké mají v srdci. Pokaždé, když je leštím, se mi na konečky prstů znovu vrací chvění toho dne na jevišti."},"ICON-1589":{"nm":"Piknikový košík","de":"Otevřeš víko a jako první unikne vůně jarního slunce. Kimbap, termoska a jedna podložka na sezení jsou úhledně poskládané a chystají se vyrazit na louku. Kroky toho, kdo mě nese, jsou vždy nějak o píď lehčí než obvykle."},"ICON-1590":{"nm":"Malý květináč","de":"Píď parapetu mi bohatě stačí. Malý zelený tvor, který velkoryse snese, i když na zalévání často zapomeneš. V koutku stolu zaneprázdněného člověka rozvíjím každý den ještě jeden lísteček a tiše předávám dnešní pozdrav."},"ICON-1591":{"nm":"Velký květináč","de":"Zatímco rostu do výšky, roste spolu se mnou i člověk. Když široké listy, jež zabírají kout obýváku, zachytí slunce a vrhnou stín, do pokoje se nenápadně vkrade i roční období. Odměna, kterou zná jen ten, kdo nezapomíná zalévat."},"ICON-1592":{"nm":"Sada vonných svíček","de":"Ve chvíli, kdy zapálíš knot, vzduch v pokoji o stupeň klesne a zklidní se. Vůně se pomalu šíří a zahřívá i vyprovází včerejší únavu. Jediným malým plamínkem uzavřeš konec rušného dne jako tichý rituál."},"ICON-1593":{"nm":"Minilednička","de":"Otevřeš pozdě v noci dvířka a přivítá mě studená plechovka nápoje. Tiché bzučivé chvění dělá prázdnou ubytovnu o něco méně osamělou. Velkou domácnost neuřídím, ale v tom, postarat se o hladové svítání, mi nikdo nesahá po paty."},"ICON-1594":{"nm":"Čelenka se síťkou na vážky","de":"Ve chvíli, kdy si ji nasadíš na hlavu, ti letní louka vyleze na ramena. Kulatá síťka jemně procedí sluneční svit a s každým krokem se lehce zavlní vůně trávy. Klobouk, který si na sebe navlékne celé roční období, i kdybys nechytil jedinou vážku."},"ICON-1595":{"nm":"Sáček na sběrnou síťku","de":"Zavěšený u pasu se stává společníkem sběru. Lehce stáhnout ústí, aby to, co jsi chytil, znovu neuteklo – to je první trik naučený na louce. Jeden lehký látkový sáček si pevně obejme celodenní úlovek."},"ICON-1596":{"nm":"Sklenice na pozorování hmyzu","de":"Vím, že pro hosta, který se zdrží jen chvíli, jsou dýchací otvory to nejdůležitější. Malá dechová cestička provrtaná ve víčku, jeden lístek trávy položený na dně. Poslat ho zpátky do trávy, jakmile pozorování skončí, patří k tomu jako druhá polovina páru."},"ICON-1597":{"nm":"Krabička na entomologické špendlíky","de":"I v jediném úhlu, pod kterým špendlík šikmo zapíchneš, žije zručnost. Příliš hluboko se zlomí, příliš mělko se rozviklá, takže musíš sílu v konečcích prstů rozdělit s přesností. Krabička, do níž se tiše ukládá péče toho, kdo chce dlouho hledět na malý život."},"ICON-1598":{"nm":"Víko chovné nádoby","de":"Starat se o hranici mezi vnitřkem a vnějškem je moje práce. Zavřu-li příliš pevně, dusí se; nechám-li příliš volně, ztratí se, a tak vždy ponechávám škvíru jako zářez. Chránit je jednoznačně něco jiného než uvěznit."},"ICON-1599":{"nm":"Miska na krmení motýlů","de":"Položíš doprostřed vatu namočenou v cukrové vodě a slétnou se křídla. Trikem je držet ji mělkou a širokou, v hloubce, kde se malé nožky neproboří. Jediná miska tiše svolává do slunné zahrady hosty, kteří se na chvíli zastaví a zas odletí."},"ICON-1600":{"nm":"Lákací lampa na hmyz","de":"Necháš ji ve tmě slabě svítit a malá křídla se slétají za světlem. Jas jemný, místo daleko od lidí. Nadmíru laskavý vábič, který bzučivou letní noc zklidní o poznání víc."},"ICON-1601":{"nm":"Nálepka s hmyzem","de":"Šest nožiček a pár tykadel — v útržku papíru velikosti nehtu spí malý život. Nalep ji jemně na roh sešitu a mezi stránkami se tiše rozprostře kousek louky."},"ICON-1602":{"nm":"Visačka povolení ke sběru","de":"Než dítě zvedne síťku na hmyz, dospělý se nejdřív zeptá: kolik kusů, jak daleko. Tahle jediná malá visačka vede laskavou čáru mezi vzrušenou zvědavostí a slibem, který je třeba dodržet."},"ICON-1603":{"nm":"Dóza na návnadu","de":"Otevřeš víčko a stoupá rybí, chladná vůně svítání. Ryby možná nepřivábí návnada, ale srdce, které umí trpělivě čekat, dokud se splávek nezachvěje."},"ICON-1604":{"nm":"Pouzdro na splávky","de":"Malá skříňka, ve které spí barevné splávky, přihrádka vedle přihrádky. Některé jsou klidným ránem na jezeře, jiné rozbouřeným polednem proudu. Pro každou náladu vody je tu úhledně složen ten pravý partner."},"ICON-1605":{"nm":"Naviják na vlasec","de":"Uvolněný vlasec si neomotávej kolem prstů. Namotej ho úhledně zpět na tenhle kulatý nástroj a i zauzlení se tiše rozplete. Podobá se to doteku, který znovu urovnává ochablý den."},"ICON-1606":{"nm":"Vyprošťovač háčků","de":"Tenhle nástroj pozná jen ten, kdo se už píchl, když holou rukou vytahoval zaseknutý háček. Cesta, která méně bolí — malého tvora i konečky mých prstů. Ohleduplnost vždycky začíná v takových drobnostech."},"ICON-1607":{"nm":"Kryt lopatky na mušle","de":"Jedna vrstva, která obepíná čepel lopatky právě vykopané z bahna. Aby bahno a slaná voda nehlodaly na ostří, tiše se mezi moře a nástroj vsune tenký, měkký odpočinek."},"ICON-1608":{"nm":"Karta přílivových tabulek","de":"Kdy voda přichází a kdy odchází, tiše prozradí kartička velikosti dlaně. Malý kalendář, do kterého člověk opsal starý slib, který si mezi sebou dali měsíc a moře."},"ICON-1609":{"nm":"Kartáček na čištění akvária","de":"Jemně smeť zelené řasy usazené na skleněné stěně a do malého podvodního světa se znovu vplíží světlo. Práce, která rozjasní něčí den, obvykle plyne stejně tiše jako tahle."},"ICON-1610":{"nm":"Teplotní čip do akvária","de":"Jedno číslo bliká, a když se zastaví na správném stupni, rybičky se konečně uklidní. Jeden dílek tepla, ani příliš studeného, ani příliš horkého. Péče dosáhne i tam, kam oko nevidí."},"ICON-1611":{"nm":"Pozorovací nádoba na mořské živočichy","de":"Malý host, který se na chvíli zdrží v průhledné nádobě. Tiše mu spočítáš hřbetní ploutve a pak ho vrátíš zpátky do moře. Pozorovat neznamená vlastnit, ale na chvíli si vypůjčit."},"ICON-1612":{"nm":"Kartáček na fosilie","de":"Vrstvy kamene, které spaly desítky milionů let, nebudí kladivo, ale měkký hrot štětce. Před časem, který by se rozpadl při unáhlení, se opatrnost stává tou nejhlubší úctou."},"ICON-1613":{"nm":"Krytka na vykopávkový štětec","de":"Když hrot štětce úplně vyschne, ani hlína pak nespadá čistě. Malý čepeček chrání dech štětce, aby zůstal vlhký. Ruka, která si váží svých nástrojů, tím dělá první krok vykopávky."},"ICON-1614":{"nm":"Vzorkovnice vrstev","de":"V hrsti hlíny se vrství stovky let, jedna na druhé. Nabereš je tiše na tuhle destičku a dosud neviditelné vzory času se pomalu vynořují a kreslí své linie."},"ICON-1615":{"nm":"Podnos na kosterní úlomky","de":"Ulož roztroušené úlomky do jednotlivých přihrádek, a život, který kdysi rozvál vítr, se pomalu tápavě vrací na svoje místo. Rekonstrukce je práce, při níž se laskavě ptáme na ztracený řád."},"ICON-1616":{"nm":"Restaurátorská páska","de":"Tenký proužek, který spojuje rozbité místo. Jizvu se ani nesnaží skrýt, jen ji něžně obejme a přidrží. Tiše dokazuje, že i to, co se rozbilo, může být zase celé."},"ICON-1617":{"nm":"Kryt výstavní jmenovky","de":"List, který jemně přikrývá cedulku za sklem, aby nevybledla. Ukrývá přání, aby ta krátká věta o tom, kdo a kde žil, byla čitelná zřetelně ještě dlouho v budoucnu."},"ICON-1618":{"nm":"Visačka depozitáře","de":"Hluboká místnost, kde spí poklady, jež nikdy nevstoupily do světla. Na všem uvnitř visí malá jmenovka — aby ani bez místa na výsluní nebyly nikdy zapomenuty."},"ICON-1619":{"nm":"Obálka muzejního daru","de":"Někdo beze slova předává to, co sbíral celý život. V téhle obálce není ukrytá věc, ale dlouho opatrované srdce. Sdílení se stává nejdéle trvající výstavou, která někomu svítí na cestu."},"ICON-1620":{"nm":"Čip s číslem vzorku","de":"Přímo na místě sběru se tiše přidělí malé číslo. Kdy a kde jsme se poprvé setkali. Nezaznamenaný objev se totiž brzy rozplyne jako ranní mlha."},"ICON-1621":{"nm":"Lahvička s úlomkem meteoru","de":"Úlomek, který proletěl nočním nebem, je uvězněný ve skleněné lahvičce. Paprsek světla, jenž zhasl dřív, než sis stihl přát přání, teď znovu tiše zajiskří v tvé dlani."},"ICON-1622":{"nm":"Šňůra s mušličkovou zvonkohrou","de":"Navlékni mušle sesbírané jednu po druhé na pobřeží na provázek a pověs je pod okap. Kdykoli projde vítr, cinkavě zaharaší a moře toho léta si tiše najde cestu až do domu."},"ICON-1623":{"nm":"Duhová kapka rosy","de":"Kapka, která se po dešti chvěje na špičce listu. V tom kulatém tvaru je uzavřená celá obloha a všech sedm barev. Někdy i to nejmenší v sobě dokáže obsáhnout ten nejširší výhled."},"ICON-1624":{"nm":"Lahvička na sběr mlhy","de":"Přinesl jsem domů lahvičku plnou ranní mlhy z úbočí hory. Vezmeš ji do ruky a je chladná, mléčně zakalená. Malá, něžná chtivost udržet na chvíli u sebe to, co se udržet nedá."},"ICON-1625":{"nm":"Miska na sběr rosy","de":"Malý pohárek, který zachytává rosu, co stébla trávy sbírala celou noc, kapku po kapce. Sotva jediný doušek, a přece se v něm v tichosti hromadí ta nejčistší, nejjasnější část rána."},"ICON-1626":{"nm":"Sponka se stužkou vánku","de":"Stužka uvázaná přesně podle vzoru, který za sebou zanechal procházející vítr. Zapíchni si ji do vlasů a s každým krokem tě jemně provází vánek. Lehkost jarního dne, tiše uvázaná v jediné sponce."},"ICON-1627":{"nm":"Kapsle se zvukem vln","de":"Přiložíš si ji jemně k uchu a přivalí se vlny dalekého moře. Jako by někdo pečlivě zapečetil do malé kapsle ten zvuk, který sis kdysi v dětství schovával do lastury."},"ICON-1628":{"nm":"Úlomek hvězdného písku","de":"Sevřeš na nočním pobřeží hrst písku a v ní se zatřpytí drobky hvězd. Jestli spadly z nebe, nebo je jemně obrousily vlny, se nikdo neobtěžuje ptát."},"ICON-1629":{"nm":"Čip s ostrovním počasím","de":"Ostrovní nebe si to za jeden den rozmyslí i několikrát. Zapiš si jasno, mlhu i přeháňku úhledně na malý čip a včerejší nebe si dnes znovu rozevřeš."},"ICON-1630":{"nm":"Sada schodů na útes","de":"Jeden schod, a další, aby se dalo sejít i vystoupat po strmém svahu. Poskládej roztroušené díly a i útes se stane pozvolnou procházkou. Vytvořit cestu znamená předem položit něčí příští krok."},"ICON-1631":{"nm":"Role se vzorem hliněné cesty","de":"Role, která věrně otiskla strukturu měkké hlinité cesty. Rozviň ji jediným pohybem a pod nohama se tiše rozprostře venkovská pěšina, po níž se chce jít bosky."},"ICON-1632":{"nm":"Čip se vzorem dlážděné cesty","de":"Vzor dlažebních kostek, jimiž kdysi byly vydlážděny staré uličky, je celý uchovaný v malém čipu. S každým krokem, ťap ťap, se u špiček tvých nohou znovu probouzejí kroky staré vesnice."},"ICON-1633":{"nm":"Díl plážového plůtku","de":"Jeden úsek nízkého plotu postaveného na písku, aby přes něj vlny nepřepadly. Malý, mlčenlivý strážce hranice, který stojí a laskavě odděluje moře od písku."},"ICON-1634":{"nm":"Záplata na obnovu trávníku","de":"Kousek zeleně jemně položený na místo vyšlapané doholá. Za pár dní si trávy podají ruce a prázdné místo zaplní. Příroda vždycky ví, jak se sama zahojit."},"ICON-1635":{"nm":"Kolík značící vodní cestu","de":"Kolík, který předem ukazuje cestu, kudy poteče voda. Aby dešťová voda nebloudila a nehledala, kam má jít, stojí v zemi zaražený malý ukazatel mlčky i v deštivé dny."},"ICON-1636":{"nm":"Díl malého mostku","de":"Jeden díl droboučkého mostku spojujícího oba břehy potoka. Slib, že se dá kdykoli přejít z jedné strany na druhou, tiše začíná právě u tohohle malého dílu."},"ICON-1637":{"nm":"Krytka zábradlí vyhlídky","de":"Na nejvyšším místě ostrova, jedna dokončovací krytka obepínající konec zábradlí. Tiše podpírá a chrání místo, kterého se nejčastěji dotýkají ruce těch, kdo se sešli, aby se zadívali do dálky."},"ICON-1638":{"nm":"Podstavec ohniště","de":"Než se přiloží dřevo, místo, které drží žhavé uhlíky, aby se nerozprášily. Nad ním hoří dlouho a vřele noci, kdy se hledělo na hvězdy a povídalo si."},"ICON-1639":{"nm":"Vzorník tapet v roli","de":"Nálada pokoje začíná u jedné stěny. Rozvinout malou roličku a vybrat barvu znamená tiše si předem nakreslit, jaké dny si přeješ prožívat."},"ICON-1640":{"nm":"Vzorek podlahové krytiny","de":"Nejdřív konečky prstů odhadneš, jaký bude na dotek povrch podlahy, po níž budou chodit bosé nohy. Teplý, nebo chladný — na tomhle jediném malém čipu tiše závisí útulnost dnů, které tě čekají."},"ICON-1641":{"nm":"Sada stropních háčků","de":"Ve chvíli, kdy zavěsíš na trám jediný háček, se prázdný strop stane místem, které na někoho čeká. Zvonkohru, nebo květináč? Váhu unese tenhle malý kovový hák, ale co na něj pověsit, rozhoduje srdce toho, kdo tu bydlí."},"ICON-1642":{"nm":"Zatemňovací fólie na okno","de":"Poledne svítí příliš upřímně, a tak okno potáhneš jednou tenkou vrstvou fólie. Sluneční svit prochází dál, ale hrany změkčí a všechno v pokoji zjihne do meruňkové barvy. Není to zastínění, ale laskavé rozprostření světla."},"ICON-1643":{"nm":"Kryt zvonku","de":"I tlačítko zvonku, na které mačkají hosté, prý potřebuje kabátek, řekl si někdo a nasadil mu kulatou krytku. Chrání před deštěm, chrání před prachem, a nadevšecko je to malá kulatá ústa, která jako první pronesou pozdrav: „Tady někdo bydlí.“"},"ICON-1644":{"nm":"Stojan na knihu hostů","de":"Stojánek postavený proto, aby si každý příchozí zapsal jméno a šel dál. Než uschne inkoust, z hrotu pera vyteče jeden řádek pozdravu. Jak se navštívené kroky hromadí řádek po řádku, prázdný sešit se z ničeho nic stane nejtlustším albem tohoto domu."},"ICON-1645":{"nm":"Zápich na umístění nábytku","de":"Místo pro stůl, o kterém sis pořád nebyl jistý, jestli ho přesunout, jediný zápich zabodne do podlahy a rozhodne. Malý hřebík, který jemně přidrží nožičky nábytku. Místo, jednou určené, si zamiluješ, přikyvuje tiše dřevěná podlaha."},"ICON-1646":{"nm":"Rámeček na štítek úložiště","de":"Co je kde uloženo, to zásuvka sama nikdy neřekne. Proto se do čtvercového rámečku vloží jmenovka, aby promluvila za ni. Ve chvíli, kdy si štítek najde své místo, si neuspořádané přihrádky znovu najdou svá jména a zklidní se."},"ICON-1647":{"nm":"Tyčinka pokojového difuzéru","de":"Vůně, která smáčí špičku tyčinky, se pomalu šíří vzhůru. Chvíli levandule, chvíli louka po dešti. Když neviditelná niť vůně vymění vzduch v pokoji, z ramen toho, kdo se vrátil domů, se zvolna uvolní celodenní únava."},"ICON-1648":{"nm":"Sponka na sáček se semínky","de":"Semínka koupená na jaře, která se nestihla zasadit, jsou i s pytlíkem pevně sevřená sponkou. Kdyby uniklo byť jedno zrnko, příští sezóna by byla o řádek chudší. V té malé svorce spí celá příští zahrádka."},"ICON-1649":{"nm":"Sazenicová miska","de":"Naplň každou přihrádku zeminou a vznikne první pokojíček mladého klíčku. Jeden život na jednu jamku, prvňáčci, kteří rostou v úhledné řadě vedle sebe. Nakoukneš dovnitř a na podnosu se každé ráno znovu rozjíždí přehlídka zeleně, hlásící se ke jmenovkám."},"ICON-1650":{"nm":"Značka pro zalévání","de":"„Mám žízeň.“ Květináč to neumí říct, tak za něj vysílá signál malá cedulka zapíchnutá v hlíně. Když se barva změní, je čas zalévat. Nejmenší tlumočník mezi rostlinou a člověkem se celý vejde do téhle tyčinky velikosti dlaně."},"ICON-1651":{"nm":"Vázací páska k opěrné tyči","de":"Rostoucí stonek by se mohl pod vlastní vahou zapotácet, a tak ho jemně přivážeš k opěrné tyči měkkou páskou. Příliš pevně a nemůže dýchat, příliš volně a padá, takže vázající ruka potřebuje tu pravou míru něhy. I dospívání potřebuje mít někoho po boku."},"ICON-1652":{"nm":"Ochranná síť proti hmyzu","de":"Jemně tkaná síť tiše zadrží drobná ústa, která si brousí zuby na útlé lístky. Propustí vítr i sluneční světlo a odkloní jen to, co by ublížilo — neviditelný strážce brány. Zahrádka je klidná díky ohleduplnosti ukryté v těchhle hustých okách."},"ICON-1653":{"nm":"Karta na měření slunečního svitu","de":"Kolik sem dopadá slunce? Postavíš do záhonu jednu kartičku a tiše se zeptáš. Čím sytější barva, tím víc světla dnes zachytila. Tenhle malý lístek papíru rozdělí místo pro dítě, které miluje sluníčko, a pro to, kterému je milejší stín."},"ICON-1654":{"nm":"Testovací proužek na pH půdy","de":"Přiložíš testovací proužek k hlíně a od růžové po modrou země barvou vyzná své nitro. Tam, kde není ani příliš kyselá, ani příliš hořká, dýchají kořeny nejsvobodněji. Skryté nitro půdy se tak čte políčko po políčku."},"ICON-1655":{"nm":"Štítek na sběrací košík","de":"Je dnešní úroda hlávkový salát, nebo cherry rajčata? Na každý košík se připne jmenovka. Ve sklizňovém ránu prosyceném vůní hlíny a zeleně se ve chvíli, kdy štítek přilne, stává ten košík prvním ukazatelem na cestě ke stolu."},"ICON-1656":{"nm":"Sklenice na uskladnění semen","de":"Letos sesbíraná semínka uložíš do skleněné sklenice a pošleš je příštímu jaru. Zavřeš víčko a čas se na chvíli zastaví, zatímco drobná zrnka čekají ve tmě na svou řadu. Sklenice jako dopis poslaný přes celé roční období."},"ICON-1657":{"nm":"Roubovací páska","de":"Přiložíš uříznutou větev k nové a omotáš je páskou, a obě pomalu srostou v jedno tělo. Míza znovu proudí přes zlomené místo, rána se pomalu hojí. Spojování je nakonec vždycky o přijetí té druhé struktury."},"ICON-1658":{"nm":"Krytka na zahradnické nůžky","de":"Na ostrý hrot nůžek nasadíš malou čepičku. Zatímco ruka, která prořezávala větve, odpočívá, ostří zůstává ostré a ruka nezraněná. Prý i dokončený nástroj potřebuje pyžamo — zahrádka svoje náčiní pečlivě ukládá ke spánku."},"ICON-1659":{"nm":"Třídič semínek květin","de":"Netýkavka, šrucha, nocenka — semínka odlišná jménem i barvou dostávají každé svůj vlastní pokojíček v samostatné přihrádce. Kdyby se smíchala, na jaře by nebylo poznat, kdo je kdo. Malé přihrádky v krabičce předem kreslí plán zahrady, která ještě nerozkvetla."},"ICON-1660":{"nm":"Podstavec na kolečkách pro květináč","de":"Nasadíš čtyři kolečka a i těžký květináč se vydá za sluncem na procházku. Ráno k východnímu oknu, v poledne do stínu. Zeleň, dřív přikovaná ke svému místu, se koulí a celý den hledá to nejlepší místo za světlem."},"ICON-1661":{"nm":"Úvazek na vedení popínavé rostliny","de":"Úponek tápe prázdným vzduchem, neví kudy, a šňůrka ho tiše navádí na správnou cestu. Nahoru, a ještě výš. Dej mu, čeho se chytit, a rostlina, jak zvláštní, tu ruku uchopí. I růst potřebuje svého průvodce."},"ICON-1662":{"nm":"Držák kartiček s významem květin","de":"Na kartičce zapíchnuté vedle květiny jsou napsána slova, která ta květina vzkazuje. Hortenzie znamená upřímnost, kopretina nevinnost. Aby procházka záhonem byla čtením dopisů, malý držák tiše propůjčí hlas mlčenlivé květině."},"ICON-1663":{"nm":"Krytka na zahradní cedulku","de":"Aby déšť a vítr nerozmyly písmo, nasadíš na zahradní cedulku průhledný klobouček. „Tady rajčata“, „tady bazalka“. Jména, která by mohla vyblednout, zůstávají zřetelná, a tak zahrádka po celý rok nezapomene ani na jednoho ze svých členů."},"ICON-1664":{"nm":"Lžička na hnojivo","de":"Když přidáváš do hlíny živiny, přemíra kořeny jen popálí. Proto jedna lžička, přesně tolik. Malá lžička nabere správné množství a připomene ti — srdce, které dobře pěstuje, vždycky vychází z konečků prstů, jež znají míru."},"ICON-1665":{"nm":"Rozprašovací tryska","de":"Otočíš tryskou a proud vody se rozptýlí jako mlha. Útlý lístek, dřív bičovaný prudkým proudem, pod kapkami podobnými rose jemně zvedne hlavu. Táž voda se stává docela jiným pozdravem podle toho, jak je podávána."},"ICON-1666":{"nm":"Odměrka na krmivo","de":"Jeden odměrek, druhý. Jídlo přítele odměřuješ nikoli odhadem, ale pečlivostí. Příliš mnoho a nechá to, příliš málo a je mu smutno, proto odměříš přesně tolik, kolik je třeba. Láska někdy přichází právě v podobě pečlivého odměřování."},"ICON-1667":{"nm":"Kryt kartáče na línání","de":"V období línání kryt pečlivě obalí měkké chmýří zamotané v kartáči. Nasadíš kartáči po vyčesání čepičku a i další den začne svěže a načechraně. Lesk srsti domácího mazlíčka tiše roste právě z takových drobných úklidů."},"ICON-1668":{"nm":"Krytka na kleštičky na drápky","de":"Na ostrý hrot kleštiček na drápky nasadíš víčko, aby použitý nástroj neškrábal ostatní věci v šuplíku. Uklidit a uložit nástroj ke spánku, když čas péče skončí, patří k jednomu celému kolečku starostlivosti."},"ICON-1669":{"nm":"Přívěsek na obojek","de":"Zavěsíš na obojek jeden třpytivý přívěsek a stejná stará vycházková cesta se stane trošku výjimečnější. Malá ozdůbka, která se ve slunci lehce zatřpytí. Nemusí být okázalá, stačí, že je znamením, že tenhle malý tvor je milovaným členem něčí rodiny."},"ICON-1670":{"nm":"Zdravotní karta mazlíčka","de":"Jedl dnes dobře, nebolí ho něco? Na kartu si zapíšeš každý den jednu větu o dni kamaráda, se kterým žiješ. Když se stav člena rodiny, který neumí mluvit, zapíše písmem, i pečující srdce se stane důkladnějším a jistějším."},"ICON-1671":{"nm":"Povlak na pelíšek","de":"Oblečeš pelíšek do měkkého nového kabátku. Sundáš látku ošoupanou od válení a mazlení a zavane vůně na slunci sušeného chmýří. Udržovat nejčistší místo, kde leží nejčastěji, je každodenní péčí o toho, s kým žiješ."},"ICON-1672":{"nm":"Kolíčky na malý plůtek","de":"Do kraje záhonu zapíchneš drobné kolíčky a vztyčíš nízký plůtek. Ne jako přísný zákaz, ale jako laskavou hranici říkající, že až sem sahá místo pro květiny. Jen tam, kde je čára k dodržení, se dá uvnitř klidně růst."},"ICON-1673":{"nm":"Dóza na pamlsky ke sblížení","de":"I plaché mládě zbystří uši při chrastění téhle dózy. Uvnitř je hrst pamlsků, které otevírají srdce. Sblížit se rychleji než slovy dokáže malý slib, a chrastivý zvuk vykročí kupředu jako první."},"ICON-1674":{"nm":"Visačka se záznamem procházek","de":"Kudy dnes a jak daleko? Na visačku si zaznamenáš dnešek jako uzlík na provázku. Nasbírané stopy se stanou mapou, nasbírané mapy se stanou vzpomínkami. Každý společně ušlý den se úhledně vrství na tomhle malém štítku."},"ICON-1675":{"nm":"Miska na krmení ptáků","de":"Postavíš na parapet misku, nasypeš pár zrnek prosa, a bezejmenní hosté přilétají jeden za druhým. Klepavé zobání, třepot křídel. Malý stolek, u kterého jedna darovaná hrst přiveze každé ráno malý koncert."},"ICON-1676":{"nm":"Pozorovací nádoba na veverky","de":"V průhledné nádobě se setkáš s kulatýma očima veverky. S tvářičkami nacpanými žaludy, jak nakláněla hlavu na stranu — to je pohled. Na slibu, že chvíli pozoruješ a pak zase pustíš, si na okamžik vyměníš pozdrav s kouskem divočiny."},"ICON-1677":{"nm":"Sádrová forma na otisk tlapky","de":"Naliješ měkkou sádru a odlije se v ní malá stopa tlapky. Zatímco čekáš, až ztuhne, i čas na dvorku se na chvíli zastaví. Ten dlaní velký otisk, který s růstem nevyhnutelně zmizí, bílá forma pozvedne jako věčnost a tiše ti ho vloží do dlaní."},"ICON-1678":{"nm":"Krytka objektivu na noční pozorování","de":"Na hrot objektivu, který nahlíží do noci, zavřeš malé víčko. Aby sklo, které vidělo hvězdy i hnízda, čekalo na příští noc bez zrnka prachu. I oči, které jasně vidí ve tmě, potřebují jednu čárku odpočinku přes den."},"ICON-1679":{"nm":"Značka na ochranu hnízda","de":"Když objevíš hnízdo mezi větvemi, místo abys šel blíž, postavíš značku. „Tady žije ptačí rodina, prosím tiše.“ Sledovat, ale nevnikat — právě ten laskavý krok zpět udržuje hnízdo nejbezpečnější."},"ICON-1680":{"nm":"Čip s nahrávkou zvířecích zvuků","de":"Píseň trávy, štěbetání pod okapem, noční hlas hmyzu — do čipu je nezavíráš, jen si je na chvíli půjčuješ. Malá zvuková krabička, která při přehrání oživí i vzduch toho okamžiku. Aby nic z toho, co jsi kdysi slyšel, docela nezmizelo."},"ICON-1681":{"nm":"Kryt pozorovacího dalekohledu","de":"Chvíli předtím, než pták vzlétne, les na okamžik zadrží dech. V tom tichém okamžiku jeden kus látky přehozený přes objektiv střeží onu dálkovou ostrost, nedotčenou byť jedinou skvrnou od prstů."},"ICON-1682":{"nm":"Popruh na fotoaparát pro lesní stezku","de":"Při každém výstupu do prudkého lesního svahu ťuká fotoaparát lehce o hruď. Bušící tep a cvakání závěrky se rozechvívají ve stejném rytmu a tenhle jediný pruh je jistě přidržuje na prsou."},"ICON-1683":{"nm":"Karta s přírodním výkladem","de":"I obyčejný trs trávy má jméno, tiše prozradí kartička. Jakmile to, co jsi dřív míjel bez povšimnutí, dostane jméno, horská stezka se náhle vřele zaplní známými tvářemi."},"ICON-1684":{"nm":"Záplata na opravu plachty","de":"I na plátně, které celým tělem přijímá vítr, zůstávají jizvy. Jednou malou záplatou jemně přiloženou na roztržené místo si plachta znovu vydobude právo obejmout širé moře."},"ICON-1685":{"nm":"Deska na nácvik uzlů","de":"Nahoru, dolů, ještě jednou omotat — postup, který si ruce zapamatovaly, se stává uzlem. V noci, kdy bouře buší do paluby, právě tenhle jediný postup svazuje člověka a loď v jedno."},"ICON-1686":{"nm":"Krytka kotevního řetězu","de":"Nepodceňuj tenhle malý čepeček nasazený na konec kovového řetězu. Rez totiž potají roste zevnitř, a tak jediná krytka, která se postaví zády k mořskému větru, tiše prodlužuje kotvě život."},"ICON-1687":{"nm":"Vlajka na značení kurzu","de":"V den, kdy hustá mlha smaže cestu vpřed, jedna vlaječka promluví za ni. Jeden bod barvy vlající ve větru konečně uvolní ztuhlá ramena zbloudilého kormidelníka."},"ICON-1688":{"nm":"Klíčenka do kajuty","de":"Nad rozhoupaným mořem visí na úzkých dveřích kajuty jeden malý kroužek. Dokud klíč drží své místo, pokoj, do kterého se lze vrátit, pro tebe nikdy nezůstane zamčený."},"ICON-1689":{"nm":"Voděodolné pouzdro na mapu","de":"V dešti papírová mapa nejdřív smaže cestu. Zatímco jeden list zůstává suchý uvnitř průhledného pouzdra, ani promoklá cesta nakonec neztratí směr."},"ICON-1690":{"nm":"Knot do lodní lampy","de":"Olej, který knot pomalu nasává, se nakonec rozkvete plamenem. Jeden bod světla na palubě, a při tom drobném zachvění se nedozírná vzdálenost noční hladiny nenápadně přiblíží."},"ICON-1691":{"nm":"Nouzová signální látka","de":"Na vzdálenost, kam hlas nedosáhne, dojde ruka, mávající vysoko rudou látkou, dál než slova. Tenhle jediný pruh látky prořízne vítr a za tebe vykřičí, že tady někdo žije."},"ICON-1692":{"nm":"Ukazatel směru mořského větru","de":"Kdo ví, odkud vítr vane, ten určuje kurz. K jedinému směru, který tiše ukazuje malá jehla, se nakloní osud celé dnešní plavby."},"ICON-1693":{"nm":"Kryt na skládací lopatku","de":"Sklopíš čepel a přikryješ ji, a i pilná lopatka si na chvíli oddechne. Poslední věc, kterou udělá ruka, jež vyhrabala všechnu tu hlínu, je postarat se, aby zítřejší ostří nezatupělo."},"ICON-1694":{"nm":"Pouzdro na kapesní kompas","de":"Ručička vždycky bez zachvění míří k severu, ale střeží ji pevné pouzdro. Čím víckrát se člověk kdysi ztratil, tím vzácněji si chrání smysl pro směr."},"ICON-1695":{"nm":"Síťka na tábornické nádobí","de":"Umyté nádobí zavěsíš do síťky, aby uschlo na ranním slunci. Den v táboře začíná zvukem osychající vody a tahle drobnost jistotně naplní vnitřek stanu."},"ICON-1696":{"nm":"Karta povolení k táboření","de":"Svolení přenocovat na téhle hoře. Ve chvíli, kdy máš v ruce jediný list papíru, se i cizí les na chvíli postaví na tvoji stranu a tiše přijme tvůj malý stan."},"ICON-1697":{"nm":"Stužka s vlaječkou na stezku","de":"Uvaž vlaječku na každé rozcestí, a cesta zpátky se ve tmě nerozplyne. Jedna drobná značka toho, kdo šel napřed, tiše postrčí do zad kroky toho, kdo jde za ním."},"ICON-1698":{"nm":"Voděodolná dóza na zápalky","de":"Zápalka, jakmile ji smočí jediná kapka, navždy zmlkne. V dóze zapečetěné tak, aby dovnitř nevniklo ani zrnko vody, čeká jiskra suchá a klidná jen pro tu nejchladnější noc."},"ICON-1699":{"nm":"Přenosný vodní filtr","de":"I zakalená voda, u které by ses zaváhal, projde tímhle filtrem a vyjasní se. Malé zařízení, které nechá odložit pochybnost dřív než žízeň — víra, že se dá pít, je sama o sobě douškem klidu."},"ICON-1700":{"nm":"Balíček nouzové deky","de":"Složená se vejde do dlaně, rozložená se stane teplem jednoho člověka. Aby slovo „nouze“ tížilo méně, deka čeká v koutku batohu, vždy připravená se zahřát."},"ICON-1701":{"nm":"Noční značkovací náramek","de":"Na horské stezce zahalené tmou tiše září jedno zápěstí. Ten malý pásek, který oznamuje místo každého z nich, láskyplně spojuje ty, kdo jdou spolu, neviditelnou, něžnou nití."},"ICON-1702":{"nm":"Nálepka na hornickou helmu","de":"Nálepka na helmě je horníkovo druhé jméno. V hluboké štole, kde je vzácné i světlo, poznáš kamaráda s láskou podle toho malého obrázku, který zachytí paprsek lampy."},"ICON-1703":{"nm":"Značkovací špendlík žíly","de":"Tam, kde jsi našel žílu, tiše zapíchneš špendlík. Jediný bod, který sám září ve tmě, laskavě řekne tomu, kdo přijde po tobě, aby začal kopat právě odtud."},"ICON-1704":{"nm":"Měřítko na trhliny","de":"Měřit trhlinu rozevírající se ve zdi je pomalá, vytrvalá trpělivost. Rozšířila se od včerejška o píď? Malé číslo, které pravítko oznámí, odhalí zřícení dřív, než přijde."},"ICON-1705":{"nm":"Papír na otisky reliéfů","de":"Na vzor vytesaný do kamene přiložíš papír a docela jemně poklepáváš tuší. Ve chvíli, kdy se dotek starý tisíc let vynoří v černé kresbě, otisk na okamžik posadí uplynulý čas naproti tobě."},"ICON-1706":{"nm":"Pouzdro na starověkou minci","de":"Tento malý kousek kovu, uložený ke spánku a chráněný před rzí, v sobě chová poslední hlas zaniklé říše. V jediné minci dřímá celá epocha, pomalu stárnoucí v průhledném pouzdře."},"ICON-1707":{"nm":"Podstavec na úlomek křišťálu","de":"I křišťál, který v sobě uzamyká světlo, potřebuje o něco se opřít. Ve chvíli, kdy tiše spočine na malém podstavci, křehká věc konečně naplno rozvine svou zář."},"ICON-1708":{"nm":"Útržek jeskynní mapy","de":"Roztržená mapa lstivě odhaluje jen polovinu svého tajemství. Až do dne, kdy najdeš zbývající kus, tenhle jediný list ukrývá zbytek cesty někde v jeskyni napůl skrytý."},"ICON-1709":{"nm":"Karabina na slaňování","de":"Chceš-li svěřit své tělo skále dolů, musíš nejprve zcela důvěřovat téhle karabině. Zavěsit svou váhu na jediný kus studené oceli - důvěra je svou podstatou právě tak těžká věc."},"ICON-1710":{"nm":"Povolení k vykopávkám","de":"Jediný list papíru, zřetelně orazítkovaný svolením kopat v zemi. Chceš-li probudit to, co je pohřbeno, nejprve si vyžádej svolení - vykopávky tiše učí, že se má začínat zdvořilostí."},"ICON-1711":{"nm":"Větrolam v balení","de":"Rozlož ho zády k větru a uprostřed rozbouřené pláně vznikne kousek ticha. Za touto jedinou vrstvou je chráněn malý plamínek a unavený člověk si na chvíli odpočine."},"ICON-1712":{"nm":"Kryt brýlí proti písečné bouři","de":"Ať písek víří sebedivočeji, výhled se musí uchránit až do konce. Tenký kryt přes brýle se stává odvahou jít dál s otevřenýma očima, i uprostřed bouře."},"ICON-1713":{"nm":"Podnos na deštivou návštěvu","de":"Ze špiček bot příchozího hosta kape dešťová voda. Podnos tiše postavený u vchodu beze slova a vřele přijme promoklé, prokřehlé nohy."},"ICON-1714":{"nm":"Chladicí přívěsek proti vedru","de":"Malý přívěsek, který jemně zchladí polední žár. Visí na tašce a schraňuje svěžest, aby ti pak, právě když se perlí pot, potají podal hrst stínu."},"ICON-1715":{"nm":"Pás s ohřívačem rukou proti mrazu","de":"Jeden teplý pás, který se ovine kolem pasu. Když teplo ohřívače rukou stoupá po zádech vzhůru, i krutá zimní pláň se stane o něco snesitelnější."},"ICON-1716":{"nm":"Sáček pohlcující vlhkost","de":"Vlhkost bezhlučně rozežírá věci. Zatímco malý sáček v krabici mlčky vysává vlhko, milované věci si zachovávají svůj tvar, suché a nedotčené."},"ICON-1717":{"nm":"Návlek na boty proti blátu","de":"Jsou chvíle, kdy i při chůzi bahnem musí boty zůstat čisté. Tenký kryt, který nepustí bláto dál, dělá krok přes práh domů o to lehčí."},"ICON-1718":{"nm":"Kryt lampy proti mořské mlze","de":"Když se mořská mlha snaží pohltit lampu vcelku, tenhle kryt tiše sesbírá rozptýlená vlákna světla. I v šerém úsvitu jedno přístavní světlo do posledního okamžiku odmítá zhasnout."},"ICON-1719":{"nm":"Výstražný špendlík proti blesku","de":"Když se nízko stáhnou temné mraky, jediný špendlík varuje jako první. Slovo, aby ses sehnul dřív, než udeří blesk - pokoru před přírodou je vždy nejlepší naučit se předem."},"ICON-1720":{"nm":"Záložka do kuchařky","de":"Malá záložka vložená mezi stránky otevřené kuchařky. Když u ohně tápavě hledáš řádek, který jsi ztratil, na té stránce se probouzí i matčina chuť."},"ICON-1721":{"nm":"Odměrka na koření","de":"Maminka vždycky říkala jen „jednu špetku“. Odhad okem přece nemůže být přesný, a přesto se její cit nikdy nezmýlil. Když touhle tyčinkou odměřuješ sůl, pochopíš, že tím, co zrálo déle než jakákoli míra, nebyl odhad, ale láska."},"ICON-1722":{"nm":"Kvasná páska na víko","de":"Věděl jsi, že i hrnec dýchá? Když tahle páska pevně obejme víko, vnitřek a vnějšek spolu pomalu začnou hovořit. Teprve po těch nespěchajících dnech si čekání konečně vyslouží jméno chuti."},"ICON-1723":{"nm":"Štítek na zrání","de":"Malý štítek, na který je úhledně zapsán den přípravy. Písmo bledne, zatímco to, co je uvnitř, naopak hloubí. Zapsat si to, jako bys chtěl zapomenout, a jednoho dne to náhle znovu vytáhnout - zrání je slib dodržený právě takhle."},"ICON-1724":{"nm":"Cedník na vývar","de":"Čirý vývar přichází teprve po scezení, a pak ještě jednou. Díváš-li se na síto, jak zadržuje kousky a nechává protékat jen esenci, skrz konečky prstů k tobě dolehne staré kuchyňské rčení - že tam, odkud jsi něco odebral, se usazuje hloubka."},"ICON-1725":{"nm":"Plátno na kynutí těsta","de":"Přes těsto tiše přehodíš jeden kus plátna. Zatímco kvasnice se pod tím šerem pilně nadouvají, poprvé se naučíš něhu věcí, které tiše rostou na místech, jež nikdo nevidí."},"ICON-1726":{"nm":"Přípravný špendlík na suroviny","de":"Malý špendlík, který rozdělí vlákna jarní cibulky a pevně přidrží stroužek česneku. Příprava je jako první pozdrav surovinám, a čím pečlivěji je upravíš, o to jasněji zazáří večerní stůl."},"ICON-1727":{"nm":"Kleštičky na servírování","de":"Kam položit poslední sousto na talíři, o tom nakonec rozhodnou právě tyhle kleštičky. V tom krátkém okamžiku, kdy zkušená ruka zaváhá půl úderu ve vzduchu, se z jídla potichu stane obraz."},"ICON-1728":{"nm":"Termo obal na svačinový box","de":"Krabička s obědem, kterou jsi dostal u školní brány, musela zůstat teplá až do zvonění na oběd. Teplo uzavřené v tomto obalu nechladne, hluboké jako srdce toho, kdo stál od svítání u plotny."},"ICON-1729":{"nm":"Pozvánka na společné jídlo","de":"„Pojď k nám někdy na oběd.“ Existuje snad laskavější slova? Bez velkých slibů, jen si sednout ke stejnému stolu - nejstarší pozvání, jaké korejština umí nabídnout, se vejde na tuhle jedinou kartičku."},"ICON-1730":{"nm":"Rezervační žeton na stůl","de":"Zapíšeš jméno a zajistíš si místo. Zatímco malý žeton na chvíli přivazuje prázdný stůl k někomu konkrétnímu, smluvený čas se blíží pomalu, jako zvuk kroků."},"ICON-1731":{"nm":"Hodnoticí kartička na ochutnávku","de":"Tváře, které kousnou a s naprostou vážností udělí hvězdičky. Upřímný řádek úhledně napsaný na téhle kartičce je to nejvřelejší kárání, jaké existuje, aby bylo příští jídlo ještě chutnější."},"ICON-1732":{"nm":"Děkovná stužka na svačinový box","de":"Kolem dočista vyprázdněné krabičky obtočíš stužku a pošleš ji zpátky. I ten, kdo se nikdy nezmohl na slovo díků, do tohohle uzlu aspoň sváže to, co srdce nedokázalo vyslovit."},"ICON-1733":{"nm":"Alergenový štítek","de":"Tenhle jediný malý štítek tiše střeží něčí stůl. Úhledně vypsat, co se uvnitř skrývá, je jiné jméno pro pohostinnost - péči, která zasahuje i tam, kam oko nedohlédne."},"ICON-1734":{"nm":"Lžíce vzpomínkové chuti","de":"Chuť, která dlouho zůstávala na jazyku, byla ve skutečnosti obrazem toho dne. Když jedna lžička v okamžiku odnese zpátky do dětské kuchyně, zdá se, že vzpomínku nevaří žaludek, ale nabírá a uchovává srdce."},"ICON-1735":{"nm":"Žeton dnešního menu","de":"Co dnes sníst. Před tou nejtěžší otázkou na světě prohráváme pokaždé. Otočíš tenhle žeton, svěříš menu osudu, a srdce se ti překvapivě rozjasní a odlehčí."},"ICON-1736":{"nm":"Zvonek na společný stůl","de":"Jednou zazvoní zvonek a rodina roztroušená po pokojích se sejde na jednom místě. Ten zvuk zvonku nad kulatým stolem je nejmilejší překlad slov „je hotovo, pojďte rychle“."},"ICON-1737":{"nm":"Kartička pořadí dezertu","de":"Sladké přichází vždycky nakonec. Slib, o kterém nikdo neví, kdo ho vymyslel, za nás hlídá tahle kartička. Malý, něžný ceremoniář stolu, který schraňuje vrchol chuti pro jediné sousto dezertu."},"ICON-1738":{"nm":"Vyjednávací žeton","de":"Uprostřed tržiště se srdečně střetávají „slevte mi trochu“ a „vždyť už na tom proděláváme“. Tenhle žeton je stvrzenka starého stálého zákazníka, u nějž smlouvání nakonec vždy skončí smíchem."},"ICON-1739":{"nm":"Kontrolní špendlík na zásoby","de":"Tiše přejíždíš pohledem po regálech skladu, najdeš prázdné místo a zapíchneš špendlík. Vědět, co zbylo a co došlo - velký úkol hospodaření začíná vždy touhle drobnou kontrolou."},"ICON-1740":{"nm":"Kartáč na úklid pultu","de":"Večer po skončení trhu se obchodem tiše rozléhá zvuk kartáče, který zametá prázdný pult. V konečcích prstů, jež předem otírají místo, které se zítra znovu zaplní, je znát pilnost, jež uhlazeně uzavírá den."},"ICON-1741":{"nm":"Kartička dnešního doporučení","de":"„Dneska je tohle dobré.“ Kartička, kterou majitel obchodu potají podá. V tom doporučení, jež jemně postrčí rameno zákazníka, který neví, co si vybrat, je úhledně uložena hrdost celého dne."},"ICON-1742":{"nm":"Držák razítek pro stálé zákazníky","de":"Deset razítek a jedno je zdarma. Tenhle držák, jehož políčka se pomalu plní razítky, je druhou tváří slova „stálý zákazník“, protože chodit často znamená nakonec jen jedno - že to máš rád."},"ICON-1743":{"nm":"Sponka na výměnný sešit","de":"Sponka, která svazuje dohromady záznamy o věcech vyměněných a vrácených. Čím víc se toho vymění, tím tlustší je sešit, a s tou tloušťkou sílí i důvěra vybudovaná se sousedy."},"ICON-1744":{"nm":"Visačka „prodáno“","de":"Ve chvíli, kdy se tahle visačka připne na úplně poslední kus, se srdce podivně naplní. Je to krátké rozloučení, jako „sbohem“, věci, která odchází k něčímu stolu, do koutku něčího pokoje."},"ICON-1745":{"nm":"Košík na rezervované zboží","de":"Košík s tvou jmenovkou drží obsazené jedno místo na polici. Právě to místo, uschované předem, ti při vstupu tiše řekne: „Celou dobu jsem na tebe čekal.“"},"ICON-1746":{"nm":"Podložka na balicí pult","de":"Podložka rozprostřená na balicím pultu je jevištěm rušných rukou. Během té krátké chvíle, kdy se papír skládá a stužka úhledně váže, se obyčejná věc potají promění v něčí dárek."},"ICON-1747":{"nm":"Lísteček s příslibem návštěvy","de":"„Zítra se stavím.“ Lísteček s jedním řádkem, zasunutý potají do škvíry dveří. I když se tváře minou, slib jede na jediném lístku a dorazí dřív než člověk, aby tiše čekal."},"ICON-1748":{"nm":"Dárkový košík pro sousedy","de":"Košík podaný přes plot vždy doprovází výmluva „udělala jsem toho trochu víc“. Korejská vřelost takhle přechází na tuhle stranu, s tváří lhostejnou, pod záminkou nadbytku."},"ICON-1749":{"nm":"Schránka vesnických zpráv","de":"Velké i malé zprávy vesnice se úhledně vrství uvnitř téhle schránky. Kdo se nově přistěhoval a kdo pořádá oslavu - pár listů papíru se sejde a předá tichý tep sousedství."},"ICON-1750":{"nm":"Razítko poděkování za návštěvu","de":"Vděčnost za to, že někdo přišel, pevně otiskneš jediným razítkem. Ta jedna skvrna inkoustu rozlitá na papíře zůstane na místě déle než slova „nezapomenu“."},"ICON-1751":{"nm":"Kartička za laskavost","de":"Kartička, na kterou tiše zapíšeš laskavost, kterou ti dnes někdo prokázal, a pošleš ji zpátky. Ve vesnici, kde si dají tu práci zapsat drobnou něhu slovy, se dobré věci pořád znovu vracejí."},"ICON-1752":{"nm":"Pečeť na omluvný dopis","de":"Jako jablko dozrálé do červena, i slovo „promiň“ lze podat teprve poté, co dostatečně uzraje. Tahle pečeť pevně vtisknutá do obálky je stopou odvahy, jež do konce chránila omluvu, kterou nešlo vyslovit."},"ICON-1753":{"nm":"Rozpisová tabule společné práce","de":"Jeden list rozdělený do políček, kam je zapsáno, kdo co má na starosti. Že i práce, která je sama o sobě příliš těžká, se sdílenými jmény citelně odlehčí - to ví každý, kdo pracoval bok po boku."},"ICON-1754":{"nm":"Stužka sousedské obliby","de":"Barevnými stužkami tiše vyznačíš, co má soused rád. Zapamatovat si něčí vkus je to nejtišší vyznání, že si toho člověka vážíš, aniž bys to kdy musel vyslovit."},"ICON-1755":{"nm":"Kroužek na dveřní štítek s pozváním","de":"Jediný kroužek zavěšený na dveřním štítku oznamuje „dnes přijímáme hosty“. Je to znak velký jako dlaň, a přesto na něm visí dokořán otevřené srdce, hotové přivítat někoho."},"ICON-1756":{"nm":"Vstupní náramek na festival","de":"Vybledlý pásek, který jsi nosil ještě několik dní, protože bylo škoda ho sundat. Teprve ve chvíli, kdy se sepnul kolem zápěstí, začal doopravdy festival. Uvnitř spí uchovaný celý den, který ani po skončení docela neskončil."},"ICON-1757":{"nm":"Pouzdro na vstupenku na ohňostroj","de":"Těsně předtím, než noční nebe vybuchne, lístek v tomhle pouzdru pevně svírá rozechvěné srdce. Je to slib sevřený tak, až se ti potí dlaň, kvůli tomu jedinému okamžiku, kdy vzkvete první rachejtle."},"ICON-1758":{"nm":"Talíř na vítání měsíce","de":"Byly noci, kdy se zdálo, že jsi celý úplněk vyzvedl na mísu. Naaranžuješ na tenhle talíř čerstvé ovoce a songpjon a pokloníš se měsíci - a jedno kulaté srdce dosáhne až na okraj nebe."},"ICON-1759":{"nm":"Špendlík na rukavice pro zimní slavnost","de":"I když ruce v závěji ztuhnou zimou, rukavice pořád sklouzávají ze zápěstí. Teprve když se tenhle špendlík pevně upne na manžetu, můžeš se konečně vrhnout do zimní slavnosti, jak dlouho chceš."},"ICON-1760":{"nm":"Kartička s jarními semínky","de":"Pár semínek dřímajících uvnitř kartičky, každé čeká na své jaro. Zahrabeš je do půdy a bez chybičky vyklíčí, jako slib - vypadá to, že každý začátek vzchází z jednoho malého, pevného bodu."},"ICON-1761":{"nm":"Razítko letní pláže","de":"Vlna pevně vtiskne razítko do písku a znovu se stáhne zpátky. Ač ví, že to bude brzy smazáno, přesto zanechá drobnou stopu, že tu někdo byl. Léto se vždycky takhle jednou zřetelně otiskne a pak odplyne se slaným vánkem."},"ICON-1762":{"nm":"Stužka na podzimní sklizeň","de":"Ruka, která svazovala klasy, na konci úhledně uváže i stužku. Jediný uzel, který pečlivě uzavře celoroční pot. I když se pole vyprazdňují, podzim ještě jednou pozdraví v té nejkrásnější barvě, jako západ slunce."},"ICON-1763":{"nm":"Bublina k pamětní fotce","de":"„Díky, že jsi dorazil až sem.“ Pozdrav, který se nikdy nedostal ven z úst, se na papíře kulatě nadme. Kousek kulatého srdce, který potichu propůjčí hlas tichu zamrzlému na fotografii."},"ICON-1764":{"nm":"Mapový špendlík na slavnost","de":"Značka, kterou někdo přesně zapíchl, abys na širém prostranství nezabloudil. I když nohy vyrazí samy vstříc lidové muzice, tenhle jediný špendlík tiše dovede bloudící tebe na smluvené místo."},"ICON-1765":{"nm":"Hlavní klíč k albu","de":"Uzamčen není nahraný zvukový nosič, ale čas v něm zapečetěný. Chvění prvního nahrávání, úsvit poslední mixáže. Pomalu otočíš klíčem a dveře té místnosti, kterou znají jen tvůrci, vrznou a otevřou se."},"ICON-1766":{"nm":"Kartička se seznamem skladeb","de":"Pořadí písní zapsané na jednom listě je ve skutečnosti pořadím srdce. Kde se sevře v hrdle, kde se zadrží dech - papír to už dávno ví. Vzrušení, které nabíhá dřív, než zazní první tón."},"ICON-1767":{"nm":"Kontrolní visačka nahrávky","de":"Tuhle visačku připne jen ten, kdo přehrál stejný úsek asi stokrát znovu. Ještě jednou, jen ještě jedenkrát poslechnout. Vedle razítka schválení se skrývá noc, kdy někdo do svítání nevěřil vlastním uším."},"ICON-1768":{"nm":"Štítek předobjednávky","de":"Slib čekat na něco, co ještě ani nepřišlo na svět. Ve chvíli, kdy se nalepí štítek, se jedno prázdné místo tiše rezervuje pod něčím jménem. I na vzrušené čekání existuje pořadové číslo."},"ICON-1769":{"nm":"Nálepka pečeti prvního vydání","de":"Připomíná to starý dotek zakrývání hrnce hanji papírem a zapečetění lepidlem. List, který slibuje uchovat věci přesně takové, jaké byly na počátku. Protože víš, že zmizí ve chvíli, kdy ho odloupneš, díváš se na jeho úpravu stále o něco déle."},"ICON-1770":{"nm":"Kalendářový žeton návratu","de":"Přidáš do kalendáře jeden kroužek a noci zbývající do toho dne se zkrátí o jedno políčko. Datum návratu je na malém žetonu v ruce ostré a jasné. Pro toho, kdo čeká, se čas počítá právě takhle, ručně."},"ICON-1771":{"nm":"Obal na fotku konceptu","de":"Než další koncept vytlačí barvu tohoto, průhledný list pečlivě uschová jeho vlákno. Aby se nezapomnělo, i když se změní roční období, jemně uchová odstín uplynulých dnů, i s rohy."},"ICON-1772":{"nm":"Žeton odhalení teaseru","de":"Těsně předtím, než se zvedne závoj, malá mince sevřená v dlani. Ve chvíli, kdy ji podáš, se uzamčená první scéna pootevře o píď směrem ke světu. Odhalení je nakonec věcí toho, kdo první natáhne ruku."},"ICON-1773":{"nm":"Podstavec na vystavení alba","de":"Ve chvíli, kdy nízký podstavec nadzvedne album, se obyčejný disk stane hvězdou výlohy. Něžný vedlejší hráč, který mlčky zezadu podpírá úhel, v němž světlo dopadá nejkrásněji."},"ICON-1774":{"nm":"Vstupenka na debutový showcase","de":"Jediná vstupenka s vyraženými slovy „poprvé vám to představujeme“. Od dlouhé chodby zákulisí až po první potlesk z hlediště tě tahle vstupenka provede rozechvělým prahem debutu."},"ICON-1775":{"nm":"Žeton pozice na první vystoupení","de":"Špičkou nohy tiše nahmatáš žeton přilepený na podlaze. Jedno políčko, které tělo pozná dřív, než se podíváš. Ve chvíli, kdy přesně dopadneš na zapamatované místo, se chvění konečků prstů konečně promění v jasný pohyb."},"ICON-1776":{"nm":"Kartička s poděkovací řečí","de":"I obyčejná věta „je to všechno díky vám“, napsaná roztřeseným rukopisem, přestává být obyčejná. Pár řádků zapsaných předem ze strachu, že se dojetím zapomene. Upřímnost se občas opře o jedinou kartičku."},"ICON-1777":{"nm":"Rozpis fotografování na profilovky","de":"List s úhledně zapsaným datem, kdy se má stanout před objektivem. Rozvrh pro pomalou přípravu té nejlepší tváře. Čím víc se políček zaplní, tím delší jsou noci strávené před zrcadlem."},"ICON-1778":{"nm":"Přihláška do fanklubu","de":"Papír vstupu, na který nesměle vepíšeš na jeden řádek jméno i srdce. Slovo „mám tě rád“ je vždycky těžké, ale tenhle jediný lístek to slovo za tebe úhledně napíše. První podpis pod rozhodnutím být spolu."},"ICON-1779":{"nm":"Kontrolní list debutových dárků","de":"Dotek, který jeden po druhém prohlédne, s myšlenkou na toho, kdo dárek dostane. Nejsou poškozené rohy, nechybí náhodou i kousek srdce? Dárek je milovaný ještě dřív, než je předán, a s tím vyráží na cestu."},"ICON-1780":{"nm":"Značka konce vystoupení","de":"Těsně předtím, než padne opona, značka položená na místě, kde spočine poslední póza. Není to signál konce, spíš malý bod, který konec pečlivě zauzluje. Jen dobře uzavřené vystoupení otevírá to příští."},"ICON-1781":{"nm":"Špendlík čekání na rozhovor","de":"Špendlík, který tiše střeží ticho předtím, než začnou otázky. Během krátkého mlčení, kdy v hlavě vybíráš odpověď, tenhle malý znak místo tebe laskavě řekne: „Ještě ne, ale už brzy.“"},"ICON-1782":{"nm":"Pamětní obálka debutu","de":"Jako starobylý zvyk, kdy se vzácný dopis, i s obálkou, vkládal do rukou toho, kdo se vydával na cestu, jedna vrstva pečlivě uchovává záznam první show. V den, kdy ji v dálné budoucnosti otevřeš, se s ní vyvalí i chvění toho dne."},"ICON-1783":{"nm":"Brčko na dechová cvičení","de":"Cvičení posílat dech dlouze, jedním proudem, tenkým hrdlem trubičky. Zpěv je nakonec dobře ovládaný dech - tohle malé brčko ti to tiše připomíná každé ráno. Nejdřív vítr, teprve pak zvuk."},"ICON-1784":{"nm":"Metronomový cvičný žeton","de":"Cvak, cvak, cvak - nejpoctivější přítel na světě. Když spěcháš, přidrží tě, když zpomaluješ, postrčí tě do zad. Vtisknout rytmus do těla je jako dlouhý rozhovor s tímhle pevným žetonem."},"ICON-1785":{"nm":"Kontrolní stužka taneční linie","de":"Kde se zastaví konečky prstů, kde se otevře rameno - jednou stužkou tiše vysleduješ linii pohybu. Dobře vedená taneční linie zůstává rovná a upravená i tam, kam z hlediště není vidět."},"ICON-1786":{"nm":"Kartička zpětné vazby na mimiku","de":"To rčení, že i úsměvu se je třeba naučit. List, na který se pečlivě zapisuje úhel koutku oka a výška koutku úst. Výraz, který ti zrcadlo nestihlo prozradit, ti místo něj laskavě sdělí tahle kartička."},"ICON-1787":{"nm":"Poznámka k rapovému flow","de":"„Tady se na chvíli zastav, tam to vychrl“ - poznámka, která předem načrtává vodní tok slov. Čím rychlejší úsek, tím zřetelnější musí být dechová cesta. V nedbale nakreslených šipkách žije a dýchá rytmus jedné sloky."},"ICON-1788":{"nm":"Nálepka hlasové teploty","de":"I hlas má své teplé a studené dny. Malá značka, kterou si podle barvy vybereš a nalepíš pro dnešní ladění. Zahřívání a chlazení střídavě, zvuk se každý den probouzí na trochu jiné teplotě."},"ICON-1789":{"nm":"Žeton odpočinkové rutiny","de":"Mince vtisknutá do ruky se slovy, že i dobře odpočívat je dovednost. Podáš ji a můžeš se na chvíli zastavit bez pocitu viny. Pro toho, kdo bez přestání běžel, je zastavit se ta nejodvážnější volba."},"ICON-1790":{"nm":"Špendlík růstového cíle","de":"Malý špendlík zapíchnutý se slovy „zkusme se dostat aspoň sem“. I když se zdá vzdálený, na dosah ruky, každý den o krok k němu rosteš. Cíl je jako něžný slib, který kyne z dálky."},"ICON-1791":{"nm":"Obálka týdenního hodnocení","de":"Pot a slzy celého týdne pečlivě vložíš do jediné obálky a předáš. Uvnitř leží vedle sebe to, co se povedlo, i to, co mrzí. Otevřít ji je malý domácí úkol předaný sobě příštího týdne."},"ICON-1792":{"nm":"Krabička dílů jevištní výzdoby","de":"Za třpytivým jevištěm žijí bezejmenné součástky. Jeden šroubek, jeden kroužek se sejdou a rozsvítí hvězdy na stropě. Otevřeš krabičku a je plná drobné, trpělivé péče, jež mlčky nese celou tu nádheru."},"ICON-1793":{"nm":"Nástěnka kostýmního konceptu","de":"Jeden po druhém připínáš kousky látky a barvy a předem si oblékáš šaty, které na světě ještě nejsou. Jevištní kostým, dokončený nejdřív na nástěnce. Představivost vždycky kráčí o krok před jehlou."},"ICON-1794":{"nm":"Žeton na zkoušku barev","de":"Stejné šaty mají v jiném světle úplně jinou tvář. Která barva se s tím člověkem směje nejjasněji, zjišťuješ tak, že žetony jeden po druhém přikládáš. Souznění je objev na konci dlouhého porovnávání."},"ICON-1795":{"nm":"Vzorník tkaniček","de":"Za pevný krok na jevišti překvapivě odpovídá malá tkanička. Aby se nerozvázala, ale ani netlačila. Ta nejněžnější úvaha, konaná na nejnižším místě, výběr mezi tkaničkami rozloženými podle jejich vzoru."},"ICON-1796":{"nm":"Kontrolní obálka doplňků","de":"Čím víc se něco třpytí, tím výrazněji vynikne jediná vada. Dotek, který drží šperk z obálky proti světlu a pečlivě jej prohlíží. Srdce, jež zkoumá malé věci až do konce, je to, co střeží jeviště."},"ICON-1797":{"nm":"Vzorek barvy na vlasy","de":"Malý vzorek, na kterém si předem „obléknete“ vlasy do nového ročního období. Barva, kterou nasákne jediný pramen, tiše napoví první dojem příštího konceptu. Změna vždycky začíná na místě velkém jako dlaň."},"ICON-1798":{"nm":"Kartička nail art konceptu","de":"List, na kterém je předem rozhodnuto o drobných obrázcích, jež se namalují na deset konečků prstů. Aby koncept jemně prosvítal i v jediném gestu, s láskou oblečeš příběhem i ten nejmenší detail."},"ICON-1799":{"nm":"Poukaz na změnu stylu","de":"„Co kdybych dnes byl trochu jiný než včera?“ - jediný lístek, který tenhle jeden řádek umožní. Ať vlasy, oblečení nebo nálada, tenhle poukaz otevírá vzrušující dveře k nové podobě."},"ICON-1800":{"nm":"Visačka úpravy velikosti","de":"Visačka, na kterou je pečlivě zapsáno, kde ubrat a kde přidat, dokud to nesedí přesně na tělo. Jako starý dotek, který stehem po stehu upravoval dětské šaty, i tahle drobná úprava udělá jeviště o píď pohodlnější."},"ICON-1801":{"nm":"Náčrt náhledové karty","de":"Jeden list, kterého se ještě nedotkla barva. Nad hrubými tužkovými liniemi si potichu odhaduje, kam se příští scéna bude ubírat. Tichá střižna šeptá, že víc než hotové dílo vždy rozechvívá právě tahle nedokončená první linka."},"ICON-1802":{"nm":"Nálepka souhlasu s natáčením","de":"\"Bude v pořádku, když se tu objevím?\" Místo slov si na hruď připevní jeden kulatý symbol. Jediná malá nálepka staví vlídný slib mezi kameru a srdce."},"ICON-1803":{"nm":"Špendlík místa na fotostěně","de":"Drobný špendlík zapíchnutý do rohu zdi. Je to místo, kde předem určíš, kdo bude stát a kde. Kdekoli je špendlík zapíchnutý, tam se zastaví jeden úsměv a promění se ve fotografii."},"ICON-1804":{"nm":"Žeton výběru záběru","de":"Prst, který mezi stovkami záběrů ukáže právě na jeden. Ve chvíli, kdy tento žeton položíš, i všechny odložené výrazy tváře jako by žily jen pro tenhle jediný snímek. Vybírat se vždy podobá tichému loučení."},"ICON-1805":{"nm":"Obálka se scénami zákulisí","de":"Vše, co se odehrálo za kamerou, se ukládá sem. Když přeložíš chlopeň, smích, chybné záběry i ospalá zívnutí usnou pohromadě. Víc než hlavní díl si člověk často oblíbí právě to, co je schované uvnitř."},"ICON-1806":{"nm":"Poznámka s pokyny ke střihu","de":"\"Tady ještě o vteřinu déle, hudbu trochu ztlumit.\" Lístek hustě popsaný červeným písmem. Něčí puntičkářství doladí dech videa o jeden takt. Dokonalost roste právě z těchto drobných doteků."},"ICON-1807":{"nm":"Štítek naplánovaného nahrání","de":"Drobný štítek na videu, které zítra v sedm ráno samo vykročí do světa. I když všichni spí, slib zůstává vzhůru. Čas nastavený předem neumí přijít pozdě."},"ICON-1808":{"nm":"Kryt rámečku náhledu","de":"Kryt, který obepíná nejlépe povedený první záběr. Úhledně sešpendlí rohy tak, aby se ho nedotkly otisky prstů ani prach. Než se ukáže světu, první dojem je takhle jemně střežen."},"ICON-1809":{"nm":"Žeton délky záběru","de":"Malý žeton, který odhaduje, kolik minut se dnes natočilo. Delší neznamená lepší a kratší neznamená lehčí. Vědět, jaká délka je ta pravá, je první knoflík střihu."},"ICON-1810":{"nm":"Korektorský list pokřikových hesel","de":"Papír, na kterém se ještě jednou vše ověří, než se zakřičí z plných plic. Stačí jedno chybné písmeno a tisíce hlasů se rozprchnou. Za jásotem vždy nejdřív projde neviditelná ruka korektora."},"ICON-1811":{"nm":"Obal na uchování fanouškovské kresby","de":"Jeden obrázek, který někdo kreslil celou noc. Nabízí mu průhledný domeček, aby se nepomačkal. Jako by to, co je nakresleno srdcem, muselo být srdcem i chováno, aby to vydrželo - obal ho tiše obejme."},"ICON-1812":{"nm":"Šňůrka na třídění fanouškovských dopisů","de":"Šňůrka, která úhledně svazuje navršené dopisy podle odesílatele. V každém uzlu je uspořádaný jeden den touhy. I když nelze odpovědět na všechny, tady je ruka, která ani jeden dopis nenechá zapadnout."},"ICON-1813":{"nm":"Přihlašovací list na výměnu předmětů","de":"\"Nenašel by se někdo, kdo by si to vyměnil za moje?\" Papír, na který napíšeš své rozechvělé srdce a podáš ho dál. Jen proto, že máte rádi to samé, se na chvíli spřátelí dva úplně cizí lidé."},"ICON-1814":{"nm":"Žeton skupinových fanouškovských míst","de":"Žeton, který přiděluje místa, kde budou lidé ve stejné barvě sedět bok po boku. Když se roztroušená srdce sejdou v jedné sekci, hlediště začne zpívat jako jeden obrovský člověk."},"ICON-1815":{"nm":"Účtenka za narozeninovou reklamu","de":"Jedna účtenka, kterou dostaneš do ruky poté, co necháš lásku zazářit na billboardu. Vedle částky není napsáno to, co bylo sbíráno celou noc - upřímná péče. Tento papír zůstává jako důkaz oslavy určené jen jednomu jedinému člověku."},"ICON-1816":{"nm":"Obal na knihu vzkazů","de":"Obal, který obepíná knihu sestavenou z rukopisů mnoha lidí. Otevřeš ji a různá písma se v jednom srdci vrství na sebe. Navenek je upravený, uvnitř je ale plný vřelého shonu."},"ICON-1817":{"nm":"Odznak fanklubu","de":"Drobný odznak, který se předává jen těm, kdo volají stejné jméno. Ve chvíli, kdy si ho připnou na hruď, se osamělá zalíbenost promění ve slib sdílený mnoha lidmi. Sounáležitost má takhle kulatý tvar."},"ICON-1818":{"nm":"Token online podpory","de":"Bod světla, kterým vzdálené ruce mávají za obrazovkou. Vzdálenost je nedozírná, ale rytmus zůstává stejný. Je to důkaz, že podpora dorazí bez selhání i z neviditelného místa."},"ICON-1819":{"nm":"Úlomek starého klíče","de":"Ukousnutý kus kovu se ztraceným zubem. Nikdo si už nepamatuje, jaké dveře kdysi otvíral. To, co přežije zamčené místo, bývá vždy jen tahle nepotřebná polovina klíče."},"ICON-1820":{"nm":"Mapa tajné chodby","de":"Starý papír s nakreslenou cestou skrytou za břečťanem. Zkratky znají jen ti, kdo je znají. Ve chvíli rozevření obyčejný ostrov potají promění tvář v jeviště dobrodružství."},"ICON-1821":{"nm":"Karta na luštění šifer","de":"Karta, která vrací zpřeházená, rozházená písmena na jejich pravé místo. Když jeden řádek zapadne, přivolá to další tajemství. I uzel, který se zdál nerozlousknutelný, nakonec začíná od prvního písmene."},"ICON-1822":{"nm":"Šňůra zapečetěné bedny","de":"Šňůra pevně svázaná, jako by říkala neotvírej. Co spí uvnitř uzlu, ví jen ten, kdo ho zavázal. Touha rozvázat a touha ochránit jsou v této jediné šňůře svázány bok po boku."},"ICON-1823":{"nm":"Skládačkový úlomek ruin","de":"Malý úlomek uvolněný ze staré kamenné zdi. Když ho vrátíš na místo, pod konečky prstů ožije řemeslné umění někoho, kdo žil před tisíci lety. Sbírat rozptýlené je práce na novém spojení času."},"ICON-1824":{"nm":"Výstřižek ostrovní legendy","de":"Papír, na který byly ručně opsány staré pověsti bloudící po ostrově. Zda jsou pravdivé, na tom příliš nesejde. Příběh putující z úst do úst se sám stává letokruhem ostrova."},"ICON-1825":{"nm":"Kámen se skrytým znamením","de":"Kámen položený u cesty, jako by tam byl náhodou. Jen znalému oku tiše ukáže směr. Čím hlouběji chce být tajemství zakopáno, tím obyčejnější tvář na sobě nosí."},"ICON-1826":{"nm":"Obálka s hádankou","de":"Na vnějším obalu není napsáno vůbec nic. Právě tahle chvíle těsně před rozlepením pečeti je nejvíc rozechvívající. Dokud odpověď nedržíš v ruce, všechny možnosti stále žijí uvnitř obálky."},"ICON-1827":{"nm":"Krytka detektivní lupy","de":"Malá čepička, kterou tiše nasadíš na konec lupy. Když se skrz ni nedívá, nechá čočku v klidu odpočívat. Aby detektiv dobře viděl, musí nejdřív dobře chránit - tohle se učí odjakživa."},"ICON-1828":{"nm":"Jízdenka na okružní ostrovní autobus","de":"Jedna jízdenka na autobus, který objíždí ostrov dokola. Konečná zastávka je zase výchozím bodem. Na cestě, která se stále vrací tam, kde začala, vypadá krajina pokaždé o trochu jinak."},"ICON-1829":{"nm":"Visačka půjčeného kola","de":"Visačka zavěšená na řídítkách vypůjčeného kola. Dokud se kolo nevrátí, je dovolena chvilka svobody. Když skončí čas, kdy jsi projížděl větrem, tato visačka ten slib tiše vezme zpátky."},"ICON-1830":{"nm":"Palubní lístek na malou loď","de":"Palubní lístek na nastoupení do malé loďky. Na kolébající se palubě se ostrovy k sobě přibližují. Přeplouvat vodní cestu vždy přináší trochu vzrušení a trochu mořské nemoci zároveň."},"ICON-1831":{"nm":"Čep kola trakaře","de":"Čep, který pevně drží kolo trakaře na místě. Tenhle jediný drobný kousek kovu udrží těžký náklad v pohybu. Nejméně nápadná součástka bývá právě ta, co mlčky snáší nejvíc váhy."},"ICON-1832":{"nm":"Žeton lanovky","de":"Kulatý žeton, který vhodíš do lanovky prořezávající vzduch. Ve chvíli, kdy nohy opustí zem, se celý ostrov naráz vejde do jednoho pohledu. Čím výš se stoupá, tím velkorysejší je krajina."},"ICON-1833":{"nm":"Nástupní páska na horkovzdušný balon","de":"Páska, kterou si obtočíš kolem zápěstí, než nastoupíš do koše. Jak plamen nabírá na síle a země se vzdaluje, i srdce se stává lehčím. Vznést se znamená na chvíli odložit svou váhu."},"ICON-1834":{"nm":"Žeton na přivolání vodního taxíku","de":"Drobný žeton na přivolání taxíku, který jezdí po vodě. Zvedneš ruku a loď se blíží, proráží si cestu proudem. To, co razí cestu i tam, kde žádná není, je nakonec odvaha toho, kdo zavolá první."},"ICON-1835":{"nm":"Vstupenka na začátek turistické stezky","de":"Vstupenka, kterou dostaneš na první bráně vedoucí do hor. Odsud dál rozhoduje o cestě jen špička boty. Vrchol může být daleko, ale ten výhled je slíben jen tomu, kdo prošel branou."},"ICON-1836":{"nm":"Klíč od přístavní skříňky","de":"Malý klíč, který otevírá skříňku u mola. S rukama odlehčenýma po odložení nákladu se zahledíš na moře. Mít místo, kam si na chvíli odložit věci, znamená vypůjčit si odvahu vydat se daleko."},"ICON-1837":{"nm":"Víčko na nakládanou zeleninu","de":"Víčko sklenice, které uzavírá vše kyselé. Když pevně dotáhneš, letní okurky si zachovají křupavost až do zimy. Tajemství, jak přechytračit čas, se ukáže, začíná dobrým zavřením."},"ICON-1838":{"nm":"Štítek na sušicí síto","de":"Jmenovka připnutá na věci rozprostřené k sušení na sítu. Když si zapíšeš, co a kdy jsi rozložil, čekání se neroztříští. I v čase slunce a větru je zapotřebí pořadí."},"ICON-1839":{"nm":"Sáček s uzeným pilinami","de":"Sáček uchovávající kousky vonného dřeva. Otevřeš hrdlo a vůně jako z táboráku pozdraví tvůj nos jako první. Chuť prohloubená kouřem se pomalu otevírá jen tomu, kdo umí čekat."},"ICON-1840":{"nm":"Nálepka na zavařeninu","de":"Nálepka, kterou nalepíš na zavařovací sklenici s přáním, ať dobře přečká celý rok. Je na ní napsán den nakládání i vložená péče. K jídlu uloženému na dlouho vždy patří drobná poznámka, snažící se zapamatovat si chuť té ruky z toho dne."},"ICON-1841":{"nm":"Štítek kvasicích hodin","de":"Kvašení hodinám nevěří. Čas neměří ručičkou, ale vůní. Ve chvíli, kdy nakyslý pach dosáhne nosu, štítek potichu přikývne: \"Teď už je to hotové.\" I čekání má svou vlastní stupnici."},"ICON-1842":{"nm":"Rozřazovací kolík chladicí přihrádky","de":"Tady stojí malý dopravní policista lednice. Zelenina nahoru, přílohy dolů, včerejší zbytky do první řady. Jeden zapíchnutý kolík stačí a ruka, která se dřív při otvírání dveří ztrácela, brzy zná cestu."},"ICON-1843":{"nm":"Zahřívací páska na krabičku s obědem","de":"Máma obtočila kolem krabičky pásku, aby teplo neuteklo do oběda. Rozvážeš pásku a pod zapařeným víčkem na tebe stále čeká teplá ranní péče."},"ICON-1844":{"nm":"Láhev na zrání omáčky","de":"Dobré koření nikdy nespěchá. Tiše dopřává sójové omáčce a česneku čas, aby do sebe navzájem vsákly. V tmě láhve chuť pomalu houstne a pomalá moudrost hliněné zásobárny se stěhuje do malé lahve."},"ICON-1845":{"nm":"Štítek sezónního džemu","de":"Na jaře jahody, v létě meruňky, na podzim fíky. Jediný štítek úhledně zapíše roční období na sklenici. Otevřeš víčko uprostřed zimy a loňské sluneční paprsky se pomalu rozpouštějí, lžíci po lžíci."},"ICON-1846":{"nm":"Nástěnka odznaků úplnosti sbírky","de":"Nemusíš se namáhat počítat, kolik jsi toho posbíral - nástěnka odznaků se za tebe pochlubí sama. S každým zaplněným prázdným políčkem se ramena o kousek narovnají. Není to číslo, ale stopa vyšlapaná na špičkách."},"ICON-1847":{"nm":"Karta neobjeveného místa","de":"Jedno místo, které jsi ještě nepotkal. Silueta na kartě nabízí slib, jen mlhavě naznačený obrysem. Prázdné znamená brzy zaplněné, a tak na tebe očekávání vždy čeká v podobě otazníku."},"ICON-1848":{"nm":"Razítko dokončeného katalogu","de":"Ten zvuk, jak razítko s žuchnutím dosedne na poslední políčko. Zavřeš katalog, otevřeš dlaň a jedna kapka červeného inkoustu na ní ulpí jako medaile za dokončení. Ta hluboká úleva, kterou zná jen ten, kdo sbíral až do konce."},"ICON-1849":{"nm":"Žeton barvy vzácnosti","de":"I stejný tvar vypráví jiný příběh, když se liší barva. Jediný žeton potichu vede čáru mezi obyčejným a vzácným. Oko sběratele se před tím jemným rozdílem odstínu vždy dlouho zastaví."},"ICON-1850":{"nm":"Poukaz za duplicitní sběr","de":"Zase to samé, znovu. V den, kdy jsi potřetí zvedl něco, co už máš, ti tenhle poukaz potichu podá ruku. Jako útěšné slovo, že i duplicity, když je neodhodíš, ale obejmeš, se jednou vrátí jako něco vzácného."},"ICON-1851":{"nm":"Číselný štítek sbírkové krabice","de":"Očísluj každou krabici a sklad se promění v malou knihovnu. V krabici sedmnáct je jarní úlovek, v krabici dvacet tři to, co jsi sebral u moře. Jsem tichý rejstřík, který srovnává roztroušené vzpomínky řádek po řádku."},"ICON-1852":{"nm":"Průvodce rozmístěním vystavených předmětů","de":"Výstavu z poloviny tvoří umístění. Vysoké dozadu, zářivé doprostřed. Když podle průvodce přesouváš věci rukou, neuspořádaná polička si brzy potichu vydechne jako malá galerie."},"ICON-1853":{"nm":"Oprašovač sbírkových předmětů","de":"Čím vzácnější věc, tím ochotněji se na ni usazuje prach. Jemným koncem štětečku setřeš zlehka i výčitku, že ses na ni dlouho nepodíval. Zatímco utíráš, ospalé vzpomínky se na chvíli znovu rozzáří."},"ICON-1854":{"nm":"Poukaz na rozšíření úložného limitu","de":"Když sbíráš dost dlouho, i nedostatek místa se stane šťastnou starostí. Tichá úleva při pohledu na polici rozšířenou o další patro - to není chamtivost, ale důkaz, jak mnoho toho máš rád."},"ICON-1855":{"nm":"Karta se zvacím kódem pro přátele","de":"Předat tento kód je ta nejvlídnější pozvánka na \"pojď si hrát spolu\". Srdce ukryté v pár číslicích. Teprve když přítel, který kód dostal, poprvé stoupne na ostrov, začne příběh jen pro vás dva."},"ICON-1856":{"nm":"Klíč od společné skladovací komory","de":"Dveře skladu se nikdy neotevřou samy. Zámek se otočí, jen když se spojí dvě ruce, tvoje a moje. Sdílený prostor v sobě vždy nese sdílený slib, zavěšený tam v podobě klíče."},"ICON-1857":{"nm":"Visačka nahlášené ztráty","de":"I ztracená věc je pro někoho vzácná. Napsat jeden řádek \"je tady\" a pověsit ho ven. Visačka je tenká šňůrka, která na chvíli tiše znovu spojí ztracené srdce s jeho majitelem."},"ICON-1858":{"nm":"Vlajka žádosti o pomoc","de":"Poprosit o pomoc není slabost, ale odvaha. Když se vlajka zvedne, odněkud přiběhne někdo. Na tomhle ostrově se nejrychleji nešíří drby, ale ruce natažené jedna k druhé."},"ICON-1859":{"nm":"Náramek s pohotovostním kontaktem","de":"Drobný pocit klidu obtočený kolem zápěstí. Ať se stane cokoli, číslo napsané tady přiběhne dřív než kdokoli jiný. Tichý společník, na kterého ve všedních dnech zapomínáš, ale v chvíli nouze je nejspolehlivější."},"ICON-1860":{"nm":"Žeton rozdělení úkolů","de":"Kdo půjde nakoupit a kdo bude vařit - rozdělte si žetony a nebude se o čem hádat. Prvním krokem k tomu, aby lidé společně něco vytvořili, je vlídně určit podíl každého."},"ICON-1861":{"nm":"Tabule společné tvorby","de":"To, na co by si sám ani netroufl, se najednou stane možným, jakmile se sejde víc lidí, jako kouzlem. Jak se tabule postupně plní jmény, prázdných políček ubývá a smíchu přibývá. Spolupráce potichu roste v prostoru mezi jednotlivými políčky."},"ICON-1862":{"nm":"Karta pravidel slušné návštěvy","de":"Když vstoupíš do cizího domu, opatrnost začíná už od špiček prstů u nohou. Na kartě nejsou napsána žádná velkolepá pravidla, jen drobné, vřelé sliby jako \"boty si srovnej, pozdrav jako první\"."},"ICON-1863":{"nm":"Zvonek na rozloučení party","de":"I radost potřebuje konec, aby se dalo těšit na příště. Když zvonek zacinká, všichni s lítostí ve tváři pomalu sbalí své věci. Party, která umí dobře skončit, zůstává v srdci nejdéle."},"ICON-1864":{"nm":"Páska na rohy matrace","de":"Ať povlečení narovnáš sebehladčeji, rohy se vždycky nadzvednou. Díky pásce, která pevně svírá všechny čtyři rohy, se postel každé ráno probouzí rovná jako v hotelovém pokoji."},"ICON-1865":{"nm":"Knoflíková šňůrka límce přikrývky","de":"Jsem knoflíková šňůrka, která drží límec přikrývky. Ať se přes noc jakkoli převaluješ, pevně svírám, aby límec neutekl. Přikrývka, na které po probuzení není ani jedna vráska - to je odměna za mou celonoční směnu."},"ICON-1866":{"nm":"Klip na uchycení topperu","de":"Topper se snaží při každé příležitosti tiše sklouznout. Vždy, když se o to pokusí, klip pevně skousne roh a udrží místo. Tichý tvrdohlavec, který z neviditelného koutu drží lůžko v pořádku."},"ICON-1867":{"nm":"Vyhlazovač záhybů prostěradla","de":"Jemné záhyby, které se přes noc udělají na prostěradle, se nějak podobají pokrčenému srdci. Jako látka, která zhladkne jedním tahem vyhlazovače, kéž by i rozcuchaný den šel takhle jemně vyžehlit."},"ICON-1868":{"nm":"Prodyšný podstavec pod matraci","de":"I matrace potřebuje trochu prostoru k dýchání. Když podstavec dole otevře cestičku pro vzduch, vlhkost odejde a suchost prosákne dovnitř. Dobrý spánek potichu začíná právě u toho vzduchu, který podpírá tvá záda."},"ICON-1869":{"nm":"Krycí lišta na zip povlečení","de":"Ten půlnoční zmatek, kdy při výměně povlečení stále vylézá výplň. Jednou přikryješ zip lištou a už se ti nestane, že by tě probudilo zachycení nohou. Velký klid, přinesený jednou malou lištou."},"ICON-1870":{"nm":"Podložka proti hrudkování výplně","de":"Výplň polštáře se brzy nahrne na jednu stranu a udělá malý pahorek. Když podložka vytrvale drží mezeru, plochost vydrží až do konce. Díky ní se každou noc bez chybičky vrátí nadýchanost jako u nového polštáře."},"ICON-1871":{"nm":"Elastický háček na prostěradlo","de":"Prostěradlo se vždy pomalu snaží sklouznout na jednu stranu. Zavěsíš háčky na rohy a napneš ho pevně - ani celonoční převalování s ním nehne. Napnutí se takhle tiše stává základem hlubokého spánku."},"ICON-1872":{"nm":"Štítek výměny povlaku na polštář","de":"Když si najednou nejsi jistý, jestli jsi dnes vyprala povlak na polštář, jeden štítek ti jasně odpoví. Rozvrh, na který stále zapomínáš, protože spíš a zase spíš, si za tebe pilně pamatuje tenhle drobný znak."},"ICON-1873":{"nm":"Záložka na snový deník","de":"Sen, který se hned po probuzení rozptýlí mezi prsty, zaznamenává záložka na stránce, kterou si vložila. Otevřeš ji a včerejší noční moře i obloha jsou stále tam - malý most tiše položený mezi spánkem a psaním."},"ICON-1874":{"nm":"Oblázek bílého šumu","de":"Příliš tichá noc dokáže spánek spíš vyplašit. Když oblázek zašumí zvukem podobným jemnému dešti, srdce se pomalu ukládá podél té struktury zvuku. Malý kámen, který tiše konejší ticho."},"ICON-1875":{"nm":"Žeton snímající teplotu ve spánku","de":"Zda je čelo horké, nebo prsty u nohou studené, zatímco spíš, žeton to tiše sleduje po tvém boku. Díky nočnímu strážci, který potichu hledá teplotu přesně padnoucí tělu, spánek plyne bez probuzení až do svítání."},"ICON-1876":{"nm":"Kolík na zatemňovací závěs","de":"Ranní sluneční svit je tak pilný, že se stále protlačuje škvírou mezi závěsy. Skousneš oba konce kolíkem a pokoj zase zčerná jako uprostřed noci. Spolehlivý spolupachatel za jedno další povalování v posteli."},"ICON-1877":{"nm":"Lampa promítající měsíční svit","de":"Zhasneš a nad stropem vyjde měsíc. Jemné světlo, které lampa vrhá vzhůru, promění pokoj v malé noční nebe. Pocit usínání s pohledem vzhůru na měsíc si takhle necháš přímo u postele."},"ICON-1878":{"nm":"Zavěšovák voňavého sáčku na spaní","de":"Sáček s levandulí a vůní trávy se lehce pohupuje u postele. Jak vůně prosakuje k nosu, ramena se pomalu uvolňují a jediný voňavý sáček přivolá spánek dřív než polštář."},"ICON-1879":{"nm":"Kolík hrací skříňky s ukolébavkou","de":"Tiše natočíš pero a rozvine se drobná melodie. Ukolébavka, která se odvíjí z konce kolíku, se velmi podobá rytmu, jakým babička hladila po zádech. Každý tón pomalu ztěžkává víčka."},"ICON-1880":{"nm":"Sklenice na rostlinu do vody","de":"Jsem sklenice, která pěstuje rostlinu v čisté vodě místo hlíny. Když se díváš, jak jemné kořínky poplavávají ve vodě, i vzduch v pokoji je o poznání vlhčí. Malá zelená studánka usazená na stole."},"ICON-1881":{"nm":"Sklenička na sběr úlomků snů","de":"Sen prosakující spánkem nemá tvar, a jakmile se probudíš, uteče ti mezi prsty. Zastavit víčkem sklenice jeden mizející úlomek a podržet ho až do rána - touha si pamatovat začíná právě na takhle malém místě."},"ICON-1882":{"nm":"Podnos na brýle u postele","de":"Ve chvíli, kdy sundáš brýle a odložíš je, s podivem s nimi klesne i celodenní únava. Toto malé místo u postele tu je proto, aby ten jediný pohyb přijalo. Podnos, který před spaním tiše rozmazává svět."},"ICON-1883":{"nm":"Podtácek na noční stolek","de":"Jedna kulatá skvrna, kterou po sobě zanechá sklenice s vodou, se zdá bezvýznamná, ale na dřevěné kresbě nočního stolku zůstává jako vada. Malý kroužek, který ji dodáváš, aby se tomu zabránilo. Opatrující srdce vždy tiše pracuje právě na takových neviditelných místech."},"ICON-1884":{"nm":"Rovnač rohů na skládání přikrývky","de":"I skládání přikrývky do úhledného čtverce má svůj tah. Když podle tohoto nástroje na rovnání rohů srovnáš cípy, i pomačkané srdce se jednou vyhladí. Uspořádané místo je nejslušnějším pozdravem, kterým se otevírá den."},"ICON-1885":{"nm":"Háček na nabíjecí kabel u postele","de":"Háček zavěšený u postele, protože jsem nesnášel, jak nabíjecí kabel přes noc pomalu sklouzává na podlahu. Kabel, který se tiše plní energií, zatímco spíš, čeká ráno plně nabitý na tvé prsty."},"ICON-1886":{"nm":"Košík na svačinu u postele","de":"Košík, ve kterém máš oblíbené svačinky na dosah ruky. Vlídná příprava předem počítající s pozdním nočním hladem. Šustivý zvuk, jak si ve tmě vezmeš jeden kousek a zakousneš se, je bezdůvodně milý."},"ICON-1887":{"nm":"Křídlo podpěry knihy na spaní","de":"Křídlo, které jemně přidržuje rozevřenou stránku, abys neztratil řádek, i když tě přepadá ospalost. Jedna jediná strana, kterou zavřeš těsně před tím, než se ti zavřou oči, na tebe zítra večer bude čekat na stejném místě."},"ICON-1888":{"nm":"Kamenný podstavec pod budík","de":"I budík, který probouzí ráno, potřebuje své pevné místo, které se nezachvěje. Kulatý kamenný podstavec těžce přijímá jeho váhu a drží místo jako slib, který nesklouzne, ani když přijde svítání."},"ICON-1889":{"nm":"Hřebík na zavěšení masky na spaní","de":"Hřebík, na který přes den pověsíš masku na oči, aby po celonočním zakrývání světla mohla dýchat. Dát vydýchat suché místo látce, která splnila svou úlohu - drobná péče se takhle prosákne bez poskvrnky."},"ICON-1890":{"nm":"Kolíček na svítilnu u postele","de":"Kolíček, který udrží drobné světlo potřebné o půlnoci směrem, kam chceš. Skousneš svítilnu na okraj postele a ruka, která tápala tmou, se hned mnohem uvolní. Dotek, který určuje směr světla."},"ICON-1891":{"nm":"Přídržná šňůra dělicího závěsu","de":"Přídržná šňůra, která drží závěs oddělující společný prostor. Je to jen tenký kus látky, ale za ním je něčí soukromá noc. Vlídná hranice, která ve společně obývaném pokoji střeží navzájem spánek toho druhého."},"ICON-1892":{"nm":"Dřevěná deska na rozdělení společné zásuvky","de":"Dřevěná deska vyrobená tak, aby se jedna jediná zásuvka dala rozdělit mezi víc lidí. Rozvádí elektřinu rovnoměrně, aby nikomu noc nezůstala temná. Společné bydlení nakonec začíná právě sdílením takovýchto drobností."},"ICON-1893":{"nm":"Kámen ústupku na jas světla","de":"Když je světlo příliš jasné, místo slov potají podáš dál kámen. \"Mohl bys to trochu ztlumit?\" Tuhle jedinou větu za tebe vyřídí tahle drobnost. Nejjemnější prosba ve společně obývaném pokoji."},"ICON-1894":{"nm":"Token ústupku v čase probuzení","de":"Drobná destička, kterou předáš do dlaně toho, kdo vstane první. Kdo si přidá ranní spánek a kdo se probudí dřív, o tom bez hádky rozhodne tenhle token. Srdce, které pořadí ústupků určuje konečkem prstu."},"ICON-1895":{"nm":"Číslovaný kroužek na sdílený věšák","de":"Číslované kroužky přidělené na věšáky, které používá víc lidí společně. Aby nebylo zmatek, čí místo je čí, jedno drobné číslo tiše zavádí pořádek. Vlídná čára vedená do všedního dne, který se snadno pomíchá."},"ICON-1896":{"nm":"Krytka schůdku patrové postele","de":"Krytka nasazená na schůdek, po kterém se stoupá do horního patra. Aby se bosé chodidlo nedotklo ničeho studeného ani kluzkého, stará se o bezpečí jednoho stupně. Tahle drobná ohleduplnost na konci žebříku pevně podpírá sny nahoře."},"ICON-1897":{"nm":"Rameno na sdílený toaletní papír","de":"Držák ve tvaru ramene na zavěšení toaletního papíru na sdílené toaletě. Je umístěn tak, aby kdokoli mohl jednou rukou snadno utrhnout kus. Zdá se to bezvýznamné, ale je to dotek, který hladce provází ranní chvíle mnoha lidí."},"ICON-1898":{"nm":"Žeton pořadí na osvěžovač vzduchu","de":"Žeton, na kterém je zapsáno, kdo má na řadě doplnit osvěžovač vzduchu. I jemný závan vůně je slibem, že se o zodpovědnost budete střídat. Dobrá vůně nepřichází zadarmo, rozkvétá vždy na něčí řadě."},"ICON-1899":{"nm":"Rukojeť sdílené noční lampičky","de":"Rukojeť noční lampičky, kterou spolu zapíná a zhasíná víc lidí. Ruka, která bděla nejdéle, jako poslední sesbírá světlo. Tichý slib těch, kdo sdílí pokoj a rozdělují si mezi sebou jemnou zář."},"ICON-1900":{"nm":"Prohlubeň na sklenici v opěrce sedačky","de":"Kulaté místo na sklenici vyhloubené v opěrce sedačky. I když na chvíli pustíš sklenici z ruky, nemusíš se bát rozlití. Místo k odpočinku potřebuje mít, kam odložit sklenici, aby si srdce mohlo konečně pohodlně protáhnout."},"ICON-1901":{"nm":"Poutko na zip vložky polštáře","de":"Malé poutko připevněné k zipu, který otevírá a zavírá vnitřní výplň polštáře. Jeden kroužek ušetří starosti s výměnou povlaku. Prsty, které pečují i o neviditelné vnitřnosti věcí – něha domácnosti se vždy skrývá právě tam."},"ICON-1902":{"nm":"Klínový polštář do opěradla pohovky","de":"Polštář, který vyplní mezeru v opěradle a podepře bederní páteř. Vyplňuje prázdné místo, aby vás záda nebolela, i když sedíte dlouho. Pohodlí, které tělo rozpozná jako první, když si s povzdechem řekne „ach, tohle je ono“, ve chvíli, kdy se opřete."},"ICON-1903":{"nm":"Úchytný pásek na roh sedáku","de":"Páska, která uchytí sedák za rohy – ten, co se dřív při každém posazení pokradmu posouval. Upevní ho na jednom místě, aby neklouzal. Úhlednost začíná právě u takového malého, vytrvalého upevnění."},"ICON-1904":{"nm":"Ochranný pásek na švy polštáře","de":"Nejdřív se na polštáři vždy prodře roh se švem. Ochranný pásek ho předem obepne a chrání, aby se nerozpáral. Touha mít věc u sebe dlouho je pevná jako stehy."},"ICON-1905":{"nm":"Kapsa na dálkový ovladač do mezery pohovky","de":"Ovladač, který stále mizel mezi polštáři, má konečně svůj vlastní domov. Malá kapsa zastrčená do skuliny pohovky. Vědomí, že to, co jste považovali za ztracené, je pořád na svém místě, přináší větší úlevu, než byste čekali."},"ICON-1906":{"nm":"Stužka na svinutí deky na klín","de":"Šňůrka, kterou se svine a sváže deka na klín. Teplo, které se rozprostřené rozptyluje, se úhledně uklidí pro příští noc. I teplo si takhle uložené můžete zítra zase vyndat a přehodit přes sebe."},"ICON-1907":{"nm":"Knoflík na potah podnožky","de":"Knoflík, kterým se snadno zapíná potah podnožky – místo, které se od dotyku chodidel opotřebuje nejrychleji. Ten jediný cvak prodlouží látce život. Touha používat věci dlouho je důkladná i v maličkostech."},"ICON-1908":{"nm":"Kluzná krytka na nohu pohovky","de":"Ani těžká pohovka nesmí poškrábat podlahu. Měkká krytka nasazená na konce jejích čtyř nohou opatrně, po špičkách, šetří dřevěnou podlahu. Nábytek pozorný až po chodidla si nějak vysloužívá víc náklonnosti."},"ICON-1909":{"nm":"Stojan na dálkové ovladače","de":"Stojan, který srovná vedle sebe na jedno místo ovladače, jež se dřív váleli a rozlézali se kde kudy. Když se dlouhé i krátké tyčinky srovnají úhledně do řady, samo o sobě to ztiší atmosféru v místnosti o tón klidněji."},"ICON-1910":{"nm":"Nabíjecí háček na herní ovladač","de":"Háček, na který se pověsí a nabije herní ovladač po jednom veselém kole hraní. Zatímco visí a tiše doplňuje síly, i ruce si na chvíli odpočinou. Tahle krátká pauza pevně připraví další zápas."},"ICON-1911":{"nm":"Sáček na figurky do deskové hry","de":"Malý sáček, ve kterém se schovávají pestrobarevné figurky. Kousky čekající v jednom pytlíku na další kolo při zatřesení rachotí. Při tom zvuku se jako první probudí vzrušené „ještě jedno kolo?“"},"ICON-1912":{"nm":"Miska na házení kostkami","de":"Miska určená čistě k házení kostkami. Štěstí, které dřív odskákalo ze stolu a zmizelo, teď udrží uvnitř její okraj. V tom krátkém okamžiku, kdy se kostky kutálejí a zastavují, se všem na chvíli společně zatají dech."},"ICON-1913":{"nm":"Poutko na balíček karet","de":"Páska, která sváže balíček karet, aby se nerozsypal. Dokud se nezamíchají, jejich pořadí samo o sobě je slib. V gestu, kdy se páska sundá a karty se rozprostřou, se teprve začíná příběh dalšího kola."},"ICON-1914":{"nm":"Sponka na uspořádání kabelů u konzole","de":"Sponka, která uchopí a učesá zamotané kabely za konzolí do rovných pramenů. Tiše uklízí nepořádek na místě, které skoro ani není vidět. Úhlednost se takhle vždy dokoná potichu, za zády."},"ICON-1915":{"nm":"Otočný ukazatel skóre","de":"Malý ciferník, kterým se otáčením ukazuje skóre. Cvak, s každým dílkem se číslo zvedne o jednu a hned se ozve jásot. I bez počítání v hlavě si prsty jako první zapamatují výsledek toho dne."},"ICON-1916":{"nm":"Stojánek pro nastavení herní desky","de":"Podstavec, který nakloní herní desku a nastaví úhel tak, aby ji všichni sedící kolem viděli jedním pohledem. Aby nikdo nemusel natahovat krk, tiše rozprostírá spravedlivý výhled pro všechny."},"ICON-1917":{"nm":"Kalíšek na losování pořadí ve hře","de":"Kalíšek, do kterého strčíte ruku a vylosujete pořadí ve hře. Jedna tyčinka, kterou nahmatáte a vytáhnete, rozhodne, kdo je na řadě první. V tom krátkém okamžiku, kdy se trochu spolehnete na štěstí, se všem uvnitř kulatého kalíšku společně rozbuší srdce."},"ICON-1918":{"nm":"Dělená miska na sdílené pochutiny","de":"Dělená miska na podávání pochutin podle druhu. Když jsou oddíly rozdělené, můžete si vybrat oblíbenou svačinku, aniž by se srážely ruce. V každé přihrádce je uložena péče, s jakou se myslelo na ty, kdo se budou dělit."},"ICON-1919":{"nm":"Zahřívací povlak na čajovou konvici","de":"Povlak, který obepne ramena čajové konvice a chrání její teplo. Zahaluje ji, aby čaj nevychladl, zatímco se pomalu louhuje. Je to přání prstů podat teplý šálek teplý až do poslední kapky."},"ICON-1920":{"nm":"Odkládátko na použitý sáček čaje","de":"Odkládátko, kam se vyloví vylouhovaný sáček čaje a nechá si chvíli odpočinout. Zachytí i poslední kapku, aby se nic nerozlilo. Místo, které i listu, jenž splnil svůj úkol, nabídne úhledné zakončení."},"ICON-1921":{"nm":"Rozlišovací kroužek na sdílené hrnky","de":"Šest stejných hrnků na polici v kuchyňce. Místo ptaní se, čí je čí, jsme na ně navlékli barevné kroužky. Jedno malé znamení tiše spojí šest lidí s různou chutí i vkusem u jednoho stolu."},"ICON-1922":{"nm":"Košík na sdílený popcorn","de":"Zatímco putuje z ruky do ruky, jako první vás přivítá voňavá pára. Pokud existuje něco, co se podivně nezmenšuje, i když z toho každý nabere hrst, je to jistě cit sdíleného večera stráveného spolu."},"ICON-1923":{"nm":"Kleštičky na kostky cukru s dózou","de":"Kleštičky ťuknou hranatou kostku cukru a spustí ji do šálku čaje. Sledovat, jak se bílé hrany pomalu rozpouštějí a mizí – nespěchající etiketu sladkosti, kterou jsme se poprvé naučili u babiččina čajového stolku."},"ICON-1924":{"nm":"Protiskluzová podložka na tác","de":"I když se tác nakloní, šálky zůstanou na svém místě. Jako všechno, co nás zdola tiše podpírá, i tahle podložka snese okamžik málem sklouznutí sama a nakonec si to nechá pro sebe."},"ICON-1925":{"nm":"Kelímek na postavení brčka","de":"Postavíte-li brčko rovně, ani nápoj, ani mysl se nerozhodí. Odpoledne, kdy stůl zpřehlední díky jediné maličké vzpřímenosti, kelímek chová v sobě malý sloupek a tiše podpírá líné hodiny."},"ICON-1926":{"nm":"Lapač drobků od sušenek","de":"Křup, ve chvíli, kdy se sušenka rozláme, sem spadnou uletěné drobky. Zachytit i stopu, kterou zanechalo to nejchutnější sousto – tiché zakončení stolování, laskavé i k té úplně poslední drobince."},"ICON-1927":{"nm":"Šňůra na zavěšení fotografií se sponkami","de":"Na šňůru nataženou jako na prádlo se sponkami jedna po druhé připnou polaroidy. Zatímco se dnešní úsměvy ve vánku houpou a suší, kousek zdi se promění v malou, jasnou výstavu vzpomínek."},"ICON-1928":{"nm":"Cívka na klubko vzpomínek","de":"Cívka, na kterou se úhledně namotá rozmotaná zamotaná nit. Věci, které pokračovaly dál, uzlem svázané v každém přetrženém místě. Když se i vzpomínky takhle pomalu odmotávají po kolečku zpátky, cesta, o níž jste si mysleli, že se zkrátila, se znovu prodlouží."},"ICON-1929":{"nm":"Krytka na díru po hřebíku","de":"Malá kulatá krytka, která zakryje stopu po hřebíku. Když jemně přikryjete i drobnou jizvu, jež zůstala po sundání toho, co tam kdysi viselo, stěna se znovu vrátí ke svému hladkému výrazu, jako by se nic nestalo."},"ICON-1930":{"nm":"Vkládací rámeček na skupinovou fotografii","de":"Skupinová fotografie šesti lidí, kteří se na ni namačkali rameny u sebe. Ve chvíli, kdy ji zasunete do rámečku, se spolu s ní zapečetí i smích a teplo toho dne. Rám je ruka, která nejtišeji zastaví plynoucí den."},"ICON-1931":{"nm":"Korková nástěnka na vzkazy","de":"Hnědá deska hustě posetá stopami po napínáčcích. Slib, na který se nesmí zapomenout, něčí povzbudivý lísteček, dnešní úkoly – vše se sem vrství jedno na druhé. Spolehlivá zeď vedle stolu, která si pamatuje místo vaší hlavy."},"ICON-1932":{"nm":"Uzel na zavěšení věnce","de":"I do věnce zavěšeného na dveřích vloží prsty svou dovednost. Uzel se musí utáhnout pevně, aby nespadl ani ve větrné roční době. Srdce, které někoho vítá, sílí vždy nejdřív na neviditelném místě."},"ICON-1933":{"nm":"Krytka kyvadla nástěnných hodin","de":"Látkový povlak, který obepne tikající kyvadlo a chrání ho před prachem. I měření času tak dostává svou péči. Chráníte-li ho jemně před opotřebením, nástěnné hodiny u nás vydrží o něco déle."},"ICON-1934":{"nm":"Sběratelská deska na samolepky","de":"Samolepky, které se dřív povalovaly rozházené po zásuvkách, se teď shromáždí na jedné desce a srovnají do řady. Oblíbená postavička, třpytivá hvězdička, lístek s vlastnoručním písmem. Když se malá radost ze sbírání srovná úhledně do řady, srovná se i mysl."},"ICON-1935":{"nm":"Šňůra na spojení girlandy vlaječek","de":"Šňůra, která spojí barevné vlaječky do jedné řady. Ať jde o narozeniny nebo přivítání, ve chvíli, kdy šňůra protne strop, se obyčejný pokoj promění v dům oslav. Slavit znamená sešívat dohromady srdce, které se přetrhlo."},"ICON-1936":{"nm":"Korková podložka pod rychlovarnou konvici","de":"Jeden plátek korku, na kterém stojí horké dno konvice. Aby se stůl nespálil, přijme tu žhavost celou sám na sebe. Malá pozornost, která ho vytrvale podpírá, aby po ničí vřelosti nezůstala stopa."},"ICON-1937":{"nm":"Zásuvka na drobky z toustovače","de":"Drobky, které upadnou ze zlatova opečeného chleba, se skutálí dolů do zásuvky. Stačí ji vysunout a vyklepat, a je hotovo. Beze slova přijme rušné ráno a znovu se čistě připraví na další jídlo."},"ICON-1938":{"nm":"Otočný kroužek do mikrovlnky","de":"Na roztáčejícím se kroužku talíř pomalu opíše celý kruh. Ta otáčka, roztočená proto, aby se jídlo ohřálo rovnoměrně, oživí včerejší vychladlou rýži zase v jídlo, z něhož stoupá pára."},"ICON-1939":{"nm":"Krytka na mini indukční varnou desku","de":"Ať olej stříká na všechny strany sebevíc, varná deska zůstává vždy čistá. Jedna krytka odděluje prudké horko od vašich rukou. Věci, které neviditelně stojí v cestě, udržují kuchyň místem, kde se nikdo nespálí."},"ICON-1940":{"nm":"Odparovací uzávěr rýžovaru","de":"Čššš – zvuk unikající páry. Díky malému uzávěru, který jemně vypouští nahromaděný tlak, otvírá čerstvě uvařená rýže víko s tou nejjemnější tváří. V čase dopařování není místo na spěch."},"ICON-1941":{"nm":"Stojánek na vařečku","de":"Vařečka, kterou jste míchali polévku, tu stojí zpříma. Malá starost, aby na pracovní desce nezůstala ani jedna skvrna. Úhlednost kuchyně vždy začíná právě u takových nenápadných, drobných míst."},"ICON-1942":{"nm":"Silikonový úchyt na rukojeť hrnce","de":"Nasadíte-li silikon na rozpálenou rukojeť hrnce, ruka se nespálí. Jedna vrstva, která se vloží mezi žár a dlaň. Chrání toho, kdo vaří teplé jídlo, z toho nejbližšího místa."},"ICON-1943":{"nm":"Sítko proti vodnímu kameni do rychlovarné konvice","de":"I ve vodě, kterou vaříte každý den, se hromadí jemné usazeniny. Hustá síťka tiše přefiltruje vodní kámen a nalije jen čistý šálek. Pilná ruka, která z neviditelného místa chrání první doušek čaje."},"ICON-1944":{"nm":"Kuchyňská minutka se sponkovými nožičkami","de":"Ještě tři minuty, říká minutka a pevně kouše okraj stolu svými sponkovými nožičkami. Zatímco se vaří nudle, stojí opřená na svých malých nožičkách a tikáním odpočítává nejočekávanější okamžik dne."},"ICON-1945":{"nm":"Odkapávací kelímek na příbory","de":"Z čerstvě opláchnutých příborů stéká voda, kap, kap. Když odkapávací kelímek tu vlhkost tiše pozbírá, stůl brzy oschne. Úhlednost je laskavá pilnost, která si všímá i jediné kapky vody."},"ICON-1946":{"nm":"Přihrádkový stojan na talíře","de":"Talíře stojí svisle, rozdělené do přihrádek. Nádobí, které se dřív navzájem škrábalo, když leželo naskládané na sobě, teď každé dostane své vlastní místo. Uklidit nakonec znamená dát každému jeho vlastní přihrádku, kde se s nikým nesrazí."},"ICON-1947":{"nm":"Kroužek na spárování hůlek","de":"Osamělou hůlku, která ztratila svůj pár, provlečete kroužkem a znovu ji spojíte s druhou. Jedna osamocená hůlka rychle přijde o smysl, a tak právě tenhle malý kroužek, který je svazuje vedle sebe, udržuje pořádek v zásuvce."},"ICON-1948":{"nm":"Větvený stojan na hrnky","de":"Na stojan, který se větví jako haluze, zavěsíte hrnky jeden po druhém. Zatímco na každé obrácené sklenici osychá vlhkost, kout kuchyně tiše stojí jako malý, úhledný strom."},"ICON-1949":{"nm":"Rukojeť přihrádkového podnosu na příbory","de":"Podnos, na kterém leží vedle sebe v přihrádkách lžíce, hůlky a vidličky. Uchopíte rukojeť, zvednete celý podnos naráz, a prostírání stolu je hned lehčí. I v zásuvce žije, bez výjimky, estetika pořádku."},"ICON-1950":{"nm":"Odkapávací deska na sklenice","de":"Postavíte-li umyté sklenice dnem vzhůru, kapky vody padají, kap, kap. Zatímco pomalu schnou u slunečného okna, sklenice si klidně vrací svou původní průzračnost pro další doušek."},"ICON-1951":{"nm":"Hřebínek na čištění vidličky","de":"Jemné zoubky pečlivě pročistí prostor mezi hroty vidličky, aby v nich neuvízlo jídlo. Díky doteku, který ošetří i tu nejužší škvíru, začíná další jídlo vždy bezvadným, čistým prvním soustem."},"ICON-1952":{"nm":"Plstěná podložka proti sklouznutí misek","de":"Naskládáte-li misky na sebe, porcelán o sebe zazvoní ostrým zvukem. Jeden plátek plsti vložený mezi ně to tření utiší. Tajemství dlouhého společného soužití spočívá v tom, nechat jeden druhého být trochu měkčí."},"ICON-1953":{"nm":"Šňůrka na zavěšení čajové lžičky","de":"Roztomilou čajovou lžičku zavěsíte na poutko a připevníte na zeď. Nikdy nezapadne do zásuvky, ale se třpytí na dosah ruky – malý nástroj, hrdě zaujímající své právoplatné místo. I domácnost má svá pevná místa pro každou věc."},"ICON-1954":{"nm":"Dělený zásobník do lednice","de":"Rozdělíte-li chladicí přihrádku na oddíly, každá potravina dostane svůj malý domeček. Věci, které dřív ležely zpřeházené a zapomenuté, najdou své místo, a při každém otevření dveří jasně na první pohled uvidíte, co je kde."},"ICON-1955":{"nm":"Sponka na postavení mrazicích sáčků","de":"Napůl vyprázdněný mrazicí sáček sevřete sponkou a postavíte ho svisle. Aby se nepřevrátil a nevylil, aby ho bylo příště snadné najít. I v chladném mrazáku přebývá důmyslná moudrost pečlivé hospodyně."},"ICON-1956":{"nm":"Utahovač na uzávěr lahve","de":"Lahev nedovřená pořádně brzy vyprchá. Ten jediný pevný otočný stisk zápěstí, kterým se uzávěr dotáhne, uzamkne vůni i bublinky uvnitř netknuté až do zítřejšího rána. Pečlivost se ukazuje v maličkostech."},"ICON-1957":{"nm":"Protiskluzová vložka na vajíčka","de":"Podložka, která uloží kulatá vajíčka do přihrádek, aby se neodkutálela a nerozbila. Přání zacházet s tím nejkřehčím s nejvíce péčí sedí malé a laskavé v jednom koutě dveří lednice."},"ICON-1958":{"nm":"Rozšiřovací pásek na kapsu dveří lednice","de":"Kapsu ve dveřích lednice mírně natáhnete do strany a vytvoříte tak ještě jedno místo. Vždyť roste-li domácnost, musí s ní růst i její prostor. V dovednosti rozšiřovat těsné místo se odráží srdce šikovné hospodyně."},"ICON-1959":{"nm":"Přítlačné víčko na zbytky jídla","de":"Víčko, které se jemně přitiskne na zbylou přílohu. Tiše ji hlídá, aby nevyschla a nenasákla cizím pachem. Pečující ruka pečlivě uloží i to, co zbylo z jednoho jídla."},"ICON-1960":{"nm":"Usměrňovací lopatka proudu chladného vzduchu","de":"Kterým směrem poteče chladný vzduch? Malá lopatka to tiše rozhodne. Nenápadnou dráhu vánku jemně natočíte konečkem prstu, a chlad tak dosáhne až do nejhlubšího koutku uvnitř."},"ICON-1961":{"nm":"Vlhkost pohlcující podložka do zásuvky na zeleninu","de":"V nejtemnějším koutě zásuvky na zeleninu mlčky pohlcuji vlhkost. Malý zázrak, kdy včera zvadlý list ráno zase zpevní. I když si toho nikdo nevšimne, čerstvost je vždy moje starost."},"ICON-1962":{"nm":"Zarážka proti odkutálení plechovky","de":"Tiše se přichytí k hraně stolu a zachytí nohu plechovky, která se chystala odkutálet pryč. Nápoj, který se skoro rozlil, stůl, který se skoro musel utírat. Klid mysli v domácnosti začíná právě u takové nenápadné, malé zarážky."},"ICON-1963":{"nm":"Otočný ciferník na rozpis služeb","de":"Dnes, kdo myje nádobí, kdo třídí odpad. Jedno otočení šipky a každá hádka se hladce rozplyne. V domě, kde se tísní pět lidí, je střídání se v pořadí tou nejlaskavější formou míru."},"ICON-1964":{"nm":"Silikonový rozlišovací pásek na hrnky","de":"Pět téměř stejných hrnků a ráno plné dohadů, čí je čí. Nasadíte na zápěstí barevný pásek, a ten malý slib „tenhle je můj“ se hned vyjasní, čímž se snídaňový stůl obestře jemným, laskavým řádem."},"ICON-1965":{"nm":"Kroužek s porcovací ryskou do misky","de":"V rušný den se rysky uvnitř misky stanou spolehlivým přítelem. Jedna část na rýži, jedna na přílohu. Ani málo, ani moc – laskavá čárka tiše napoví, kolik jídla si dnes dopřát."},"ICON-1966":{"nm":"Dóza s kleštičkami na sdílené pochutiny","de":"Strčíte-li rovnou celý sáček, zůstane po dotyku ruky trapné místo. Rozdělíte-li svačinu kleštičkami kousek po kousku, teprve pak vyjde podíl každého stejný. Ke sdílení se hodí spíš úhledné ruce než hrst plná chuti."},"ICON-1967":{"nm":"Stojánek na jmenovku u konvice","de":"Vaření vody vždy připadlo těm samým rukám. Od chvíle, kdy jsme na stojánek vedle konvice začali střídavě věšet jmenovky, se stal teplý šálek čaje láskou, kterou se louhuje po řadě."},"ICON-1968":{"nm":"Přívěsek na obraceč s nápisem „nenechávej zbytky“","de":"Malé „nenechávej nic“ visí drobně na konci obraceče. I když to zní jako hubování, není v tom nic nepříjemného – žije v tom totiž duch staré tabule, kde si každého jídla vážili."},"ICON-1969":{"nm":"Háček na osobní pouzdro na příbory","de":"Příbory se už dál neválejí volně v zásuvce. Ve chvíli, kdy se každá sada vloží do vlastního pouzdra a pověsí na zeď, srovnají se místa pěti členů rodiny vedle sebe do řady. Malý pořádek podpírá klid každodenního dne."},"ICON-1970":{"nm":"Korkový terčík na určení místa u stolu","de":"Položíte-li na stůl korkové kousky, hned je jasné, kdo kde sedí. Místo, na které vždy usednete, tvář po boku, kterou vídáte vždy naproti sobě. Pevné místo je tím nejtišším důkazem slov „žijeme spolu“."},"ICON-1971":{"nm":"Háček na svinutou zástěru pro službu","de":"Zástěra, ve které se domylo nádobí, se neodhodí jen tak ledabyle. Svinutá a pověšená na háček bude zítra ráno zas na dosah, čerstvá a suchá. V tomhle malém uzlu žije ohled na toho, kdo přijde po vás."},"ICON-1972":{"nm":"Skládací pytlík na jednorázové pantofle","de":"V den, kdy přicházejí hosté, se rozevřu i s taškou. Úhledně uložené jednorázové pantofle přivítají čerstvě příchozí chodidla svým měkkým polštářováním. Pohostinnost vždy tiše začíná už u vstupních dveří."},"ICON-1973":{"nm":"Kapsička na papírové konce vatových tyčinek","de":"Když se vatové tyčinky spotřebují a zůstanou jen papírové konečky, pečlivě jejich zbytky sesbírám. Dát místo i tomu, co by se jinak vyhodilo. Vím, že tajemství úhledného stolu spočívá právě v takové drobné laskavosti."},"ICON-1974":{"nm":"Svazek cívek do šicí soupravy","de":"Barevné nitě svážete dohromady, aby se cívky nerozmotaly a nezapletly. Utržený knoflík i uvolněný manžetový lem tenhle jediný svazek v mžiku napraví. Ruční šití, které v tichosti zachraňuje večer před důležitým dnem."},"ICON-1975":{"nm":"Jednotlivě balené mýdlo","de":"Kousek mýdla úhledně zabalený zvlášť leží v každém pokoji pro hosty. Tělíčko velké jako dlaň jednou hrstí pěny smyje denní prach. Čistota vždy začíná právě v tak malých místech."},"ICON-1976":{"nm":"Skládací pouzdro na sprchovou čepici","de":"Složíte-li záhyby, vejde se do dlaně; rozevřete-li ji, přesně obepne vlasy. Aby účes upravený před sprchou nezůstal zničený jediným sprchováním. Úhlednost zítřejšího rána chrání právě tahle jediná vrstva."},"ICON-1977":{"nm":"Ochranný nástavec na kartáček","de":"Štětiny jsou citlivější, než by se zdálo. Jeden nástavec překryje jejich konečky, a ani prach v tašce se k nim nedostane. Chránit neviditelná místa – to je skutečná práce hygieny, kterou se učíme na každé cestě."},"ICON-1978":{"nm":"Kleštičky na jednotlivé odebrání kosmetického tamponku","de":"Kosmetický tamponek vyjde čistě, jen když ho vezmete po jednom. Vysypete-li je všechny najednou, víc se jich zbytečně vyplýtvá. „Jeden po druhém, s péčí“ – to je tichý zákon toaletního stolku."},"ICON-1979":{"nm":"Skládací mini lžíce na boty","de":"Složená se vejde do kapsy, rozevřená k patě. Pyšním se tím, že svým drobným tělem zvládám pořádně velký kus práce. I ráno, kdy jste zaspali, jsem to byla vždy já, kdo vám dovolil obout si boty bez pomačkání."},"ICON-1980":{"nm":"Navíječ na jednu nit dentální nitě","de":"Naviníte-li jedno vlákno dentální nitě úhledně, ustřihnete si přesně tolik, kolik potřebujete, až přijde čas. Navíječ ne větší než nehet, přesto se nikdy nechybí v práci na střežení zářivého úsměvu. I úsměv má svou neviditelnou přípravu."},"ICON-1981":{"nm":"Rukojeť víka rychlovarné konvice","de":"Aby se ruka nespálila párou vroucí vody, nasadím se na víko. Píď mezi žárem a dlaní. Ta malá vzdálenost bezpečně zahřeje ráno, jindy tak uspěchané."},"ICON-1982":{"nm":"Silikonová podložka pod žehličku","de":"Nejnebezpečnější je chvíle, kdy na okamžik pustíte žehličku uprostřed žehlení. Postavíte-li ji na silikonovou podložku, neopálí se ani stůl, ani oblečení. Vyžehlení záhybů se dovrší až na téhle podložce."},"ICON-1983":{"nm":"Zabezpečovací hák na ramínko","de":"Aby zavěšené oblečení nesklouzlo jen tak samo, hák pevně zaťatě mlčí. Malý strážce, který hlídá oblíbený kousek v šatníku. Chránit je takhle tichá práce."},"ICON-1984":{"nm":"Sítko na vodní kámen do konvice","de":"Mým úkolem je tiše vyfiltrovat vodní kámen unášený vroucí vodou. Teprve po přecezení i neviditelných usazenin se šálek čaje projasní. Pečlivost vždy uzrává na místech, kam oko nedohlédne."},"ICON-1985":{"nm":"Protiskluzový pásek na ramínko","de":"Ramínko omotané protiskluzovým páskem neupustí ani lehké hedvábí. Kdo jednou viděl oblečení spadnout na zem a pomačkat se, ten zná vděk za tenhle tenoučký proužek."},"ICON-1986":{"nm":"Sponka na uspořádání šňůry žehličky","de":"Rozvinutá šňůra zachytí za nohu a někoho rozhodí. Jedno gesto ruky, které ji úhledně sváže sponkou dohromady. Předcházení nehodám vždy začíná právě u takového malého, nenápadného pořádku."},"ICON-1987":{"nm":"Přesná objímka na patici rychlovarné konvice","de":"Usadím konvici pevně do své objímky, aby se nekymácela. Být na svém místě znamená být klidný. Není náhoda, že se teplá voda každé ráno ohřívá na tom samém místě."},"ICON-1988":{"nm":"Kalhotové ramínko se sponkovými nožičkami","de":"Když sponkové nožičky pevně sevřou lem kalhot, nevytvoří se ani jeden záhyb. S dobře vyžehleným kouskem se zachází s úctou už od chvíle, kdy visí na ramínku. Úhledný střih se dovršuje uvnitř šatníku."},"ICON-1989":{"nm":"Háček na zavěšení fénu","de":"Necháte-li fén ležet jen tak, šňůra se brzy zamotá. Pověsíte-li ho pěkně na háček, umyvadlo se rozšíří a zítřejší ráno zlehčí. Uklizené místo trochu uvolní rušný den."},"ICON-1990":{"nm":"Podtácek pod nápoje z minibaru","de":"Tiše podložený pod sklenici zabrání kapkám rozlévat se po stole. Ohled jednoho podtácku nezanechá kolečkovou stopu. Úhlednost je laskavost, která nezanechává stopy."},"ICON-1991":{"nm":"Cedulka „nerušit“ na kliku","de":"Cedulka zavěšená na klice tiše šeptá „právě odpočívám“. Střeží jeden nádech spánku na konci dlouhého dne. I přestávku musí někdo pečlivě hlídat."},"ICON-1992":{"nm":"Krytka tlačítka na přivolání pokojové služby","de":"Díky krytce obepínající tlačítko ho nezmáčknete náhodně, i když se ho jen zlehka dotkne lem oděvu. Aby zaznělo zřetelně jen ve chvíli skutečné potřeby. Jedna malá krytka udrží rušný pokoj o to úhlednější."},"ICON-1993":{"nm":"Kleštičky na led z minibaru se sponkovými nožičkami","de":"Uchopíte-li led holou rukou, je studený a pořád klouže. Tuhle práci za vás pevně převezmou kleštičkové nožičky. Za začátkem osvěžujícího doušku nápoje se skrývá neviditelná pomocná ruka."},"ICON-1994":{"nm":"Štěrbina na kartu do pokoje","de":"Zasunete-li kartu do štěrbiny, světla v pokoji cvaknou a rozsvítí se. Jsem jen malá škvíra, ale jsem prvním gestem, které otevírá prostor pro odložení denní únavy. Na místě, kam se vracíte, se opět rozsvítí."},"ICON-1995":{"nm":"Zajišťovací kroužek na hrdle lahve","de":"Je-li zajišťovací kroužek na hrdle lahve neporušený, znamená to, že se jí ještě nikdo nedotkl. Malý slib dokazující, že je vše přesně tak, jak bylo na počátku. Důvěra začíná u neporušené pečeti."},"ICON-1996":{"nm":"Stojánek na informační brožuru","de":"Postavíte-li brožuru šikmo, kolemjdoucí pohled se u ní sám od sebe zastaví. Pokorný postoj informace čekající, až se otevře. Pouhé to, že je dobře vidět, někomu značně usnadní cestu."},"ICON-1997":{"nm":"Plochý otvírák na lahve z minibaru","de":"V koutku svého plochého tělíčka skrývá nenápadný zářez na otevírání víček od lahví. I když je malý, svou práci odvede na jedničku. Osvěžující první doušek z lahve se vždy otevře díky téhle drobné destičce."},"ICON-1998":{"nm":"Krytka regulátoru osvětlení","de":"Jemně otočíte knoflíkem obaleným krytkou a jas pokoje se pomalu mění. Jasně, a pak zas tlumeně. Volba světla před spaním je obřad, který den laskavě uzavírá."},"ICON-1999":{"nm":"Klínek na zabrzdění koleček kufru","de":"Zasunete-li ho lehce pod kolečko, kufr se už sám od sebe nerozjede. I na svažitém nástupišti nádraží zavazadlo drží své místo. Klid mysli na cestě za odjezdem sílí právě z tohoto malého klínku."},"ICON-2000":{"nm":"Skládací deska na balení oblečení","de":"Rozložíte a položíte na ni, a košile i kalhoty se srovnají a úhledně poskládají. Aby se obsah tašky nezhroutil, abyste v cílovém městě mohli vystoupit bez pomačkání. Dobře sbalené zavazadlo pomáhá s cestou už dřív, než vyrazíte."},"ICON-2001":{"nm":"Knoflík zámku trezoru","de":"Otočíš knoflíkem a malá závora se tiše zasune dovnitř. Svěřit své cennosti je slib, že si na jednu noc dovolíš mít srdce zcela klidné. Zámek tu není jako úzkost, ale jako jiné jméno pro klid."},"ICON-2002":{"nm":"Návlek na madlo kufru","de":"V každém oťukaném, rukama ohlazeném místě je vryt něčí odjezd. Sevřeš tento návlek, obnošený stejně jako kilometry, které za sebou vláčel, a tiše pochopíš, že odjezd je nakonec slovo, které v sobě nese návrat."},"ICON-2003":{"nm":"Klip na zavěšení cestovní taštičky","de":"Pověsíš taštičku na okraj umyvadla a stísněný pokoj získá o píď víc prostoru. Že řád v tašce začíná jedním malým klipem, to už ruka, která byla daleko, dávno ví."},"ICON-2004":{"nm":"Svorka na kabely nabíječky","de":"Do jedné zásuvky se sejde několik kabelů. V noci, kdy čekáš, až se baterie dobije, je tu malá ruka, která rozptýlené šňůry něžně drží pohromadě na jednom místě."},"ICON-2005":{"nm":"Poutko na jmenovku kufru","de":"Mezi stejnými černými zavazadly ti jediný pramínek poutka pomůže poznat to své. Zavěsit jméno je něžné znamení, že toto zavazadlo má cestu zpátky k někomu."},"ICON-2006":{"nm":"Nástěnný držák nabíjecího kabelu","de":"Malá destička na zdi u čela postele úhledně přidržuje nabíjecí kabel. První noc v cizím pokoji, kdy se rozsvítí jedno známé světýlko, se i to místo na chvíli stane domovem."},"ICON-2007":{"nm":"Skládací nožičky stojanu na zavazadla","de":"Rozložíš složené nožičky a kufr se zvedne o píď nad prašnou podlahu. Nerozbalený kufr, postavený nahoře, v sobě tiše ukrývá nedokončenou cestu a čeká na další ráno."},"ICON-2008":{"nm":"Slot na kartu-klíč","de":"Aby se v pokoji rozsvítilo, musí se do něj zasunout karta. Světlo, které svítí jen po dobu pobytu — den cestovatele hřeje přesně tolik jasu, kolik dovolí tento malý otvor."},"ICON-2009":{"nm":"Poutko na šňůrku ke kartě-klíči","de":"Zavěsíš jedinou kartu na krk a obě ruce se ti uvolní. Přivázat starost o ztrátu k jedné šňůrce je malá vychytralost, kterou si cestovatelé s těžkými zavazadly předávají odedávna."},"ICON-2010":{"nm":"Tlačítko zvonku na recepci","de":"Zmáčkneš ho a někde na recepci se rozezní čirý tón. Aby prosba o pomoc nikdy nebyla trapná, zvonek leží vždy laskavě na dosah ruky."},"ICON-2011":{"nm":"Svorka na pořadové číslo při check-inu","de":"Zvednutý lístek s pořadovým číslem z konce fronty sevřeš a upevníš. I čekání má svůj pořádek — řád vyrůstá z malého slibu tiše šetřit čas toho druhého."},"ICON-2012":{"nm":"Střapec na pokojový klíč","de":"Střapec zavěšený na konci klíče se s každým krokem lehce zavlní. Vkusnou nadsázku k užitečnosti si dovolí přidat jen ten, kdo zná radost špiček prstů."},"ICON-2013":{"nm":"Kryt zvonku recepce","de":"Nasadíš kryt na zvonek a poledního ticha se nic nedotkne. Malá ohleduplnost, jež střeží něčí hluboký spánek — i klid je něco, co někdo pečlivě vytvořil."},"ICON-2014":{"nm":"Cedulka s číslem pokoje","de":"Na klice visí lístek s jasně napsaným číslem pokoje. Pár číslic určuje místo, kam se dnes večer vrátím, a v cizí chodbě se z něj stává malý maják."},"ICON-2015":{"nm":"Magnetický proužek karty-klíče","de":"Přiložíš černý proužek ke škvíře dveří a zámek se tiše otevře. Doba, kdy neviditelný signál otevírá dveře — to, co bývalo kouzlem, se dnes usadilo jako všední věc na dlani."},"ICON-2016":{"nm":"Podložka pod razítko check-inu","de":"Při každém otisku podložka rovnoměrně přijímá inkoust. Aby jeden jasný tah potvrzení zůstal zřetelný, je tu ruka, která tiše podpírá z neviditelného místa."},"ICON-2017":{"nm":"Věšák tyč na vozíku na zavazadla","de":"Jedna tyč na vozíku na zavazadla drží šatní vak bez jediného pomačkání. Věcem, které za nás nesou tíhu dne, se chce občas poděkovat jedním slovem."},"ICON-2018":{"nm":"Visačka na madlo kufru","de":"Na madlo kufru zavěsíš malou visačku. Dokud kolonka na jméno zůstává prázdná, zůstává i chvění z toho, že příští cíl tohoto zavazadla ještě není určen."},"ICON-2019":{"nm":"Zarážka pod kolo vozíku","de":"Podložíš klín pod kolo, aby se vozík na svahu nerozjel. Uhlídat nehybnost je někdy nejspolehlivější jinou tváří bezpečí."},"ICON-2020":{"nm":"Přezka na popruh zavazadla","de":"Utáhneš popruh, aby taška nabobtnalá cestovními věcmi nepraskla. I když cesta skončí, objem vzpomínek se nezmenší, a přezka tu tíhu drží až do konce."},"ICON-2021":{"nm":"Kryt háku vozíku na zavazadla","de":"Kryt navlečený na háku vozíku nenechá na oblečení jedinou stopu. Srdce, které dopředu myslí i na neviditelné škrábance — dobrá pohostinnost se dovršuje právě v takových maličkostech."},"ICON-2022":{"nm":"Kapsička na jmenovku kufru","de":"Malá kapsička na boku zavazadla v sobě chová jmenovku. Napsat, čí to je, je jako předem vtisknout právo znovu se setkat, i kdyby se to ztratilo."},"ICON-2023":{"nm":"Svorka na rukavice na přenášení zavazadel","de":"Při přenášení těžkého nákladu svorka pevně přidrží rukavice, aby nesklouzly. Chránit ruce a dobře odvést práci nakonec pramení z jednoho a téhož srdce."},"ICON-2024":{"nm":"Síťový přehoz na zavazadla","de":"Přehodíš síťku a drobná zavazadla se nerozprchnou na všechny strany. Každé husté očko drží drobnosti pohromadě uprostřed shonu cestování."},"ICON-2025":{"nm":"Držák na vzkazy na vozíku","de":"Ve vzkazu zastrčeném do madla vozíku je napsáno číslo pokoje. Zvyk zapsat si, kam jít — čím zaneprázdněnější ruce, tím tišeji se opírají o jeden řádek písma."},"ICON-2026":{"nm":"Klopa na tác na talíř","de":"Zvedneš stříbrnou klopu a pára vyrazí vzhůru naráz. Srdce, které zakrývá jídlo, aby nevychladlo, je samo o sobě péčí — přáním předat teplo přesně tak, jak je."},"ICON-2027":{"nm":"Cedulka „Nerušit“ na kliku","de":"Zavěsíš tuto cedulku na kliku a i kroky na chodbě zpozorní. Jedna věta „nebuďte mě“ — i odpočinek je celistvý teprve tehdy, když ho někdo hlídá."},"ICON-2028":{"nm":"Kroužek na papírový ubrousek pokojové služby","de":"Papírový ubrousek provlečeš kulatým kroužkem a dáš mu úpravný tvar. Slavnostnost jídla začíná právě u tohoto malého kroužku — péče se nejzřetelněji projeví v maličkostech."},"ICON-2029":{"nm":"Protiskluzová podložka na tác","de":"Položíš podložku na tác a nádobí se nesklouzne. Udržet věci na místě i uprostřed rozechvění — i v tichu stability se skrývá něčí pečlivý návrh."},"ICON-2030":{"nm":"Cedulka objednávky snídaně na kliku","de":"Zavěsíš na kliku cedulku s objednávkou snídaně a zítřejší ráno je předem slíbeno. Zapsat si první jídlo dnešní noci je další tvář laskavého očekávání."},"ICON-2031":{"nm":"Nožky pod tác","de":"Rozložíš nožky tácu a i na posteli z něj vznikne pravý stůl. Ranní hostina přijatá vleže — malý stojánek promění obyčejný pokoj v okázalou scénu."},"ICON-2032":{"nm":"Zahřívací potah na čajovou konvici","de":"Přehodíš potah přes konvici a teplo vody vydrží déle. Stejně jako za dávných nocí u ohniště, touha uchovat teplo nezná dobu."},"ICON-2033":{"nm":"Ocásek s žádostí o úklid na kliku","de":"Zavěsíš na kliku ocásek s žádostí o úklid a zanecháš tichý signál. Prosba předaná bez pohybu rtů — za upraveným pokojem se skrývá slib neviditelné ruky."},"ICON-2034":{"nm":"Držák na dochucovadla na tácu","de":"Držák pevně sevře dózy s kořením, aby se nepřevrhly. Udržet rovnováhu chutí i na kolébajícím se tácu je tichý úkol tohoto jednoho drobného úchytu."},"ICON-2035":{"nm":"Stojánek na vzkazy o rezervacích","de":"Zastrčené vzkazy o rezervacích, postavené vzpřímeně, prozradí pořadí na jeden pohled. Aby se nespletly ani zaneprázdněné ruce, je to malý nástroj řádu, který drží jeden list zřetelně vzpřímený."},"ICON-2036":{"nm":"Mapová nástěnka s připínáčky","de":"Zapichuješ špendlíky do mapy a jedno po druhém označuješ místa, kam chceš jet. Každý špendlík je vzrušení z místa, kde jsi ještě nebyl — cesta začíná už ve chvíli, kdy rozevřeš mapu."},"ICON-2037":{"nm":"Svorka na praporek pro volání taxi","de":"Když voláš taxi, svorka narovná malý praporek do vzpřímené polohy. Signál, který místo zvednuté ruky vykřikuje praporek — i na ulici musí být volání jasné, aby vůbec dorazilo."},"ICON-2038":{"nm":"Rukojeť zvonku concierge","de":"Stiskneš rukojeť a k pultu concierge dolehne čirý tón. Signál pohostinnosti, který říká, že se lze zeptat na cokoliv — v cizím městě to nejjistější jediné zavolání."},"ICON-2039":{"nm":"Klipová deska s číslem rezervace","de":"Lístek s číslem rezervace sevřeš do klipové desky, aby byl zřetelně vidět. Aby se sjednané místo nespletlo, je to malá svědomitost, jež úhledně drží jeden řádek číslic."},"ICON-2040":{"nm":"Stojan na turistické brožury","de":"Vystavíš turistické brožury a ruka cestovatele se sama zastaví. V každém listu, který zvedneš, tiše leží složená krajina cest, na které se ještě nevydal."},"ICON-2041":{"nm":"Podložka pod razítko na mapě","de":"Pro první kroky do vestibulu drží nehybně krabičku razítka na mapě. Když se inkoust nerozmazává, ani cesta nemate. Místo, které tiše nese váhu, aby malý ukazatel stál rovně."},"ICON-2042":{"nm":"Cedulka na úschovu deštníků","de":"Odpoledne, kdy kapky deště ťukaly z okapů, zavěsíš na každý deštník jedno číslo. Když se člověk po dešti vrátí pro svůj vlastní, cedulka mu zřetelně přivolá zpět promoklou vzpomínku."},"ICON-2043":{"nm":"Držák zvonku na informační pult","de":"Cinkne to jednou a odněkud přiběhne někdo s jasným úsměvem. Malý zvonek zavěšený na rohu pultu je ten nejněžnější tlumočník, který za tebe vyřkne i slova, jež jsi sám nedokázal vypravit."},"ICON-2044":{"nm":"Tryska dávkovače šamponu","de":"Otevřeš dlaň, lehce stiskneš a pěna vykvete s tichým puf. Ta jediná dávka, zatímco se koupelnou line vůně. Přesně tady začíná tón, který nejjemněji probouzí ospalé ráno."},"ICON-2045":{"nm":"Odtoková miska pod mýdlo","de":"Miska, která tiše odvádí vodu nastřádanou pod mýdlem. Aby nezvlhlo, aby nezměklo. Malá, něžná pozornost, jež chce to, co se den ode dne obrušuje, udržet o kousek déle po boku."},"ICON-2046":{"nm":"Odměrka na koupelovou sůl","de":"Naberete lžíci prášku a rozpustíte v teplé vodě, barva i vůně se pomalu rozlévají. Zatímco mícháte zápěstím, vana se stává malým jezerem a únava celého dne se v ní tiše ponoří."},"ICON-2047":{"nm":"Síťka na pěnu z mýdla","de":"Uzavřeš kousek mýdla do síťky a otíráš, a dlaně se naplní jemnou pěnou. Tichý alchymista v koutě koupelny, který drsné mění v jemné."},"ICON-2048":{"nm":"Dezinfekční kryt na kartáček","de":"Přání, aby to, co se dotýká úst, bylo vždy čisté. Jeden malý kryt, jenž měkce obepíná štětiny, se stará i o to neviditelné. Čistota vzniká právě z takových nakupených maličkostí."},"ICON-2049":{"nm":"Víčko na dózu s vatovými tyčinkami","de":"Dóza, v níž úhledně leží bílé tyčinky, a víčko, které se kulatě klene nad ní. Otevřeš — cvak, zavřeš — ťuk. Něžná tečka koupelnového pořádku, dovršená tichým zvukem."},"ICON-2050":{"nm":"Kapátková lahvička na koupelový olej","de":"Lehce nakloníš a voňavý olej padá kapku po kapce. Lesk a jemná vůně rozlévající se po vaně. Příliš skromná na luxus, příliš něžná na všednost — jediná kapka."},"ICON-2051":{"nm":"Přihrádka na podnos s toaletními potřebami","de":"Na tácu rozděleném na přihrádky si každá lahvička najde své místo. Věci, které rozházené působí neuklizeně a poskládané úhledně. Jedna přepážka udržuje řád rušného rána."},"ICON-2052":{"nm":"Stojánek na saunové přesýpací hodiny","de":"Je to něžný slib zahřát si záda alespoň po dobu, než se všechen písek přesype. Zatímco hodiny opřené o stojánek tiše odpočítávají čas, člověk si v hustém oparu na chvíli odpočine tím, že není nikým."},"ICON-2053":{"nm":"Ručník s beránčíma ušima do sauny","de":"Konce ručníku stočíš a vztyčíš jako beraní uši, a tvář v zrcadle se tiše rozjasní. Uprostřed horké páry malý rituál sauny, při němž se každý na chvíli vrací do dětství."},"ICON-2054":{"nm":"Naběračka na vodu do sauny","de":"Nabereš naběračkou plnou vodu a poleješ rozžhavené kameny — syč — pára vystřelí až ke stropu. V tu chvíli se celé tělo ponoří do teplé mlhy a stará únava se pomalu uvolňuje v kapkách potu."},"ICON-2055":{"nm":"Teploměrná tyčka do nádoby na koupel nohou","de":"Ponoříš tyčku do vody a rysky ti tiše promluví. Ani příliš horké, ani vychladlé — přesně ta pravá teplota. Než ponoříš špičky nohou, prst, který se jako první zeptá vody, jak se má."},"ICON-2056":{"nm":"Kleště na rozžhavené kameny","de":"Čerstvě rozžhavený kámen se holou rukou uchopit nedá. Když ho kleště jistě sevřou a zvednou, žár se přesune do bezpečné vzdálenosti. I opatrnost je dovednost, tiše říká sauna."},"ICON-2057":{"nm":"Podložka na sezení do sauny","de":"Rozprostřeš na horkou podlahu jednu podložku a místo, kde se dotýkají záda, ihned zjemní. Podložka, jež mlčky přijímá den nasáklý potem. Odpočinek nakonec pramení ze správné vzdálenosti od podlahy."},"ICON-2058":{"nm":"Sáček se solí na koupel nohou","de":"Naberete hrst hrubé soli, rozpustíte ji v teplé vodě a únava se od špiček prstů rozplývá. Zatímco slaná pára obtáčí lýtka, den strávený celý na nohou se konečně zastaví."},"ICON-2059":{"nm":"Miska na vonné kapky na saunové kameny","de":"Ukápneš pár kapek parfému na rozehřátý kámen a zahřátá vůně se pomalu šíří saunou. Zavřeš oči a nevíš, jestli je tohle les, nebo květinová louka. Nejkratší cesta, na kterou se vydáš nosem."},"ICON-2060":{"nm":"Zahřívací obal na termofor","de":"Látka, jež pevně obepne ohřátý termofor a dlouho v sobě podrží teplo. Přesně jako srdce, které ho pevně obejme, aby nevychladl, teplo spočívající na břiše je při tobě celou noc."},"ICON-2061":{"nm":"Tyčinky do aroma difuzéru","de":"Tenké tyčinky nasávají vůni a pomalu ji rozlévají po pokoji. Slabá vůně, jež se s každým nádechem vpíjí dovnitř. Způsob, jakým obývaný prostor postupně začíná připomínat vůni toho, kdo v něm žije."},"ICON-2062":{"nm":"Páka na sklon lehátka","de":"Pomalu otočíš pákou a opěradlo se hladce sklopí. Trochu blíž ke slunci, trochu blíž do stínu. Nahmatat ten nejpohodlnější úhel je výpočet, který patří jenom tobě."},"ICON-2063":{"nm":"Protiskluzový pás okolo bazénu","de":"Protiskluzový pás obtáčí celý okraj vody. Aby drobné nožky, které přiběhnou s šploucháním a smíchem, mohly bezpečně zastavit, je to skrytá cílová páska bezpečí, tiše rozprostřená z dohledu."},"ICON-2064":{"nm":"Poutko na ventilek nafukovacího kruhu","de":"K malé zátce, jež uzavírá vzduch, je pečlivě přivázané poutko. Aby zátka vytažená z kruhu neodplavala po vodě. Moudrost, jež předem zabrání drobné letní ztrátě."},"ICON-2065":{"nm":"Krytka na schody u vstupu do bazénu","de":"Krytka měkce obepíná konec schodu, který vede dolů do vody. Aby se bosé chodidlo nezranilo, měkce zachytí první krok do vody. Protože každý začátek má být vždy opatrný."},"ICON-2066":{"nm":"Poutko na popruh polštáře lehátka","de":"Poutko, k němuž přivážeš popruh, aby polštář nesklouzl. Malý slib udržet si své místo i ve větru. Jeden uzel přišpendlí odpolední lenost přesně na to místo."},"ICON-2067":{"nm":"Deska s úchytem na nápoj u bazénu","de":"Deska, do níž se u okraje bazénu úhledně zasune sklenice s nápojem. Jedno místo, které nezakolísá ani při vydatném cákání. Mít osvěžení na dosah ruky prodlužuje letní odpoledne."},"ICON-2068":{"nm":"Svorka na mokré plavky","de":"Zvedneš odkapávající plavky a tiše je svěříš vánku. Zatímco schnou na slunci, svorka je mlčky drží. Tiché, něžné čekání na další koupání."},"ICON-2069":{"nm":"Zátěž pod stojan slunečníku","de":"Těžká zátěž položená u paty stojanu, aby se slunečník ve větru nekymácel. Že stín zůstává dlouho na jednom místě, je jen díky téhle tíze. Spolehlivost se často skrývá na nejnižším místě."},"ICON-2070":{"nm":"Plovoucí čip s teplotou bazénu","de":"Malý čip, jenž pluje na vodě a tiše hlásí teplotu. Zčervená, když je moc chladno, změkne, když je akorát. Roztomilý věštec, který jednou barvou přečte náladu vody."},"ICON-2071":{"nm":"Střapec na zip stanu","de":"Trhneš za malý střapec zavěšený na konci zipu a vchod stanu se ticho rozevře. Držadlo, které chytnou i tápající prsty na první pokus. Něžně provází příchody a odchody hluboké noci."},"ICON-2072":{"nm":"Motýlková spona na šňůry stanu","de":"Spona, jež sevře šňůru do tvaru motýlka a pevně ji přidrží. Plátno, které se třepetalo ve větru, se konečně utiší. Noc na táboře tiše hlídají právě takové malé, šikovné uzly."},"ICON-2073":{"nm":"Ventilek nafukovací matrace pro glamping","de":"Přiložíš ústa a fouk, fouk foukneš, matrace se pomalu nafoukne. Naplníš ji a pevně uzavřeš ventilek, podlaha změkne a místo k uložení těla pod hvězdami je konečně hotovo."},"ICON-2074":{"nm":"Háček na strop stanu","de":"Háček zavěšený na stropě stanu, na který pověsíš lucernu nebo kapesník. Hospodárná moudrost, jež šetrně využije i malý prostor nad hlavou. Je to, jako bys místo na oblohu pověsil jednu hvězdu na strop."},"ICON-2075":{"nm":"Poutko na svinutý spacák","de":"Poutko, jež omotáš a zapneš, aby se srolovaný spacák znovu nerozvinul. Lůžko, které se ráno zase zmenší. Přichystat se na odjezd znamená úhledně sbalit teplo minulé noci."},"ICON-2076":{"nm":"Podložka na boty u vchodu do stanu","de":"Deska položená u vchodu do stanu, na niž se úhledně postaví boty. Bláto venku, uvnitř čisto. Jeden práh, který něžně odděluje uvnitř od venku — malá zdvořilost kempování."},"ICON-2077":{"nm":"Zahnutý hák na lucernu pro glamping","de":"Zahnutý hák na zavěšení lucerny. Zavěsíš ji sem a světlo se kulatě rozlije po stanu. Místo, kde v temnotě zavěsíš jedno světýlko, se dnes v noci stává naším obývacím pokojem."},"ICON-2078":{"nm":"Svorka na srolované větrací okénko stanu","de":"Svorka, jež srolované větrací okénko přidrží nahoře. Pootevřeš cestičku pro vánek a vzduch ve stanu se výrazně osvěží. Jedna malá škvíra tiše vytváří prostor k dýchání po celou noc."},"ICON-2079":{"nm":"Podlahová podložka do stanu","de":"Podložka rozprostřená na podlaze stanu, jež brání blátu a vlhkosti. Jedna vrstva, díky níž se i na trávě rozprostře suché lůžko. Aby ses zdržoval v přírodě, ale nezmokl v ní, tiše pomáhá po tvém boku."},"ICON-2080":{"nm":"Zámek kotouče na osu činky","de":"Kroužek upevněný na obou koncích osy, aby kotouče nesklouzly. Malý zámek, jenž bezvýhradně věří váze toho, kdo zvedá. Teprve když bezpečí pevně drží, se hranice o kousek posune."},"ICON-2081":{"nm":"Kryt na madlo kettlebellu","de":"Na posledním okruhu, kdy železo hlodalo do dlaně, tenhle malý kryt bolest rozptýlí. Že vydržet do konce je těžší než zvednout váhu, to ruka pozná první, právě v tom závěrečném bodě."},"ICON-2082":{"nm":"Klín pod kotouče","de":"Když se kotouč sebemíň zakolébá, postoj se zboří ještě dřív, než ho zvedneš. Klín, tence zaražený do škvíry, bezhlučně drží těžiště. Pevnost vždy tiše začíná na neviditelném místě."},"ICON-2083":{"nm":"Svorka na osu činky","de":"Prsty zapínající svorku nesmí zaváhat ani na okamžik. Ono tiché cvaknutí zámku nese na sobě celý příští pohyb. Tělo se jako první naučí vkládat důvěru do jedné jediné svorky."},"ICON-2084":{"nm":"Barevný čip s váhou kotouče","de":"Čip odlišený barvou podle váhy pozná ruka dřív, než přečteš číslo. Červená je těžká, modrá lehká — zapamatovat si váhu podle barvy. Tělo, jak se ukazuje, poměřuje sílu překvapivě očima."},"ICON-2085":{"nm":"Podložka pod kettlebell","de":"Díky podložce, jež rozšíří dotykovou plochu s podlahou, se parkety neprodírají. Stopy cvičení mají zůstávat jen v potu a svalech. I tahle malá pozornost, aby zranění nezůstalo pod nohama, je tu uložená."},"ICON-2086":{"nm":"Značka středu osy činky","de":"Znak vyrytý přesně uprostřed tyče je referenční bod pro rovnováhu vlevo a vpravo. Ruka, jež sevře přesně střed, o polovinu sníží kolísání. Ve chvíli, kdy víš, kde je střed, můžeš konečně zvedat bezpečně."},"ICON-2087":{"nm":"Stojan na kotouče","de":"Použitý kotouč se vrací zpátky na své místo. Pohled na kotouče úhledně zavěšené na stojanu podle váhy je tichá ohleduplnost vůči dalšímu, kdo přijde. Uklizený prostor je nejspolehlivější pojistkou bezpečí, věří někdo."},"ICON-2088":{"nm":"Zarážka proti odkutálení kotouče","de":"Nehoda, kdy se kotouč položený na zemi lehce skutálí a přepadne přes nárt, přichází vždy v jednom nestřeženém okamžiku. Zarážka ten okamžik tiše zastaví. Velké neštěstí nepřichází z velkých míst — přikutálí se z malé škvíry."},"ICON-2089":{"nm":"Polštář opěradla lavice","de":"Když je polštář podpírající záda příliš tvrdý, i dech se hned ztenčí. Ono rozhraní vhodně pevného a vhodně měkkého je rovnovážný bod, který nahmatá jen ten, kdo dlouho seděl."},"ICON-2090":{"nm":"Zajišťovací kolík výšky stojanu","de":"Jediný kolík, jenž určí výšku, a tyč padne přesně na ramena každého. Lidé různé výšky se svorně dělí o stejné vybavení — jedna malá seřizovací dírka vytváří tuto něžnou rovnost."},"ICON-2091":{"nm":"Kryt kladky stroje","de":"Uvnitř krytu obepínajícího kladku se lano bezhlučně otáčí a otáčí. Součástka, jež tření skryje uvnitř a ruce nabídne jen hladkost. Dobré zařízení nikdy neprozradí námahu, kterou samo vynaložilo."},"ICON-2092":{"nm":"Protiskluzové nožičky lavice","de":"Protiskluzové nožičky nasazené na koncích čtyř nohou pevně drží lavici na podlaze. Jen když se nehýbe, můžeš do ní s klidnou myslí vložit veškerou sílu. Stabilita nakonec začíná u malého tření pod nohou."},"ICON-2093":{"nm":"Hák stojanu na uložení činky","de":"Hák, na nějž se ukládá tyč, musí být vždy ve výšce na dosah ruky. Místo, kam unavená paže naposledy tiše položí tyč — právě ta poloha na píď bezpečně uzavírá dnešní trénink."},"ICON-2094":{"nm":"Rukojeť kolíku na výběr váhy stroje","de":"Rukojeť, do níž zasunuješ kolík, aby si zvolila váhu, musí být hladká, aby nepoškodila nehty. I v tom prchavém pohybu při změně váhy tušíš, že se v něm tiše skrývá zpracování, jež bralo ohled na lidský konec prstu."},"ICON-2095":{"nm":"Zajišťovací páka úhlu lavice","de":"Je-li páka, jež zajišťuje úhel opěradla, uvolněná, postoj se nenápadně zboří. Jistota chvíle, kdy zapadne s cvaknutím. Provozovatel každé ráno při otevírání dveří nejdřív tiše zkontroluje právě tenhle zvuk."},"ICON-2096":{"nm":"Opěra bezpečnostní tyče stojanu","de":"V nejhorším okamžiku, kdy tyč unikne z rukou, opěra bezpečnostní tyče převezme tu váhu místo tebe. Díky opěře, jež neviditelně a stále čeká dole, se člověk může konečně posunout až na hranici svých sil."},"ICON-2097":{"nm":"Krytka konce lana stroje","de":"Malá krytka, jež sevře konec lana, je posledním uzlem proti rozplétání. Úhledně svázat prameny, aby se nerozešly — důstojnost dokončení vždy spočívá v tom nenápadném konečném bodě."},"ICON-2098":{"nm":"Sáček s magnéziem","de":"Hrst bílého prášku na rukou, jenž smaže sklouznutí. Neviditelný jako líčení za scénou, přesto stabilita každého dnešního pohybu začíná právě z téhle jedné hrsti. Příprava vždy začíná od špiček prstů."},"ICON-2099":{"nm":"Posilovač stisku ruky","de":"Malá svorka, jež mlčky opakuje sevření a uvolnění, posiluje sílu úchopu. Síla stisku roste pomaleji než velké svaly, takže je to i cvičení v tichém odkládání netrpělivosti."},"ICON-2100":{"nm":"Pásek na roztahování prstů","de":"Pásek, jenž vsuneš mezi prsty a pomalu roztahuješ ven. Ruka, jež používala jen svaly ke svírání, znovu nabývá sílu k roztahování. I uvolnit stejně pevně jako sevřít vyžaduje cvik, říká ruka."},"ICON-2101":{"nm":"Víčko tuby na křídu","de":"Stačí, aby víčko prachové tuby bylo jen trochu uvolněné, a celá taška zbělá práškem. Jediné víčko, které dosedá přesně, takové malé neštěstí předem zažehná. O úspěchu utěsnění vždy rozhoduje právě zátka."},"ICON-2102":{"nm":"Bandáž na koleno","de":"Páska omotaná kolem kolene pro oporu se musí zastavit přesně na správném tlaku. Když je moc těsná, uškrtí krev, když je moc volná, je k ničemu, a tak zkušená ruka tu jemnou hranici v tichosti odhaduje po paměti."},"ICON-2103":{"nm":"Odporová smyčka","de":"Pružné lano, které se natáhne a zase stáhne, probudí spící svaly i bez jediného závaží. Odpor přece nemusí být těžký. I před jemným tahem tělo vždy odpovídá upřímně."},"ICON-2104":{"nm":"Zátěžový váček na kotník","de":"Váček s pískem připnutý ke kotníku stahuje každý krok příjemně k zemi. Přidejte trochu váhy a i obyčejná chůze se stane opravdovým tréninkem. Je to malá moudrost, která do všedního dne nenápadně přidá trochu námahy."},"ICON-2105":{"nm":"Posilovací navíječ na zápěstí","de":"Tyč, kterou pomalu navíjíte zápěstím, aby zvedla závaží zavěšené na šňůře. Zápěstí je nejmenší a nejčastěji zapomínaný kloub, a tento jednoduchý nástroj tiše probouzí právě tu zapomenutou sílu."},"ICON-2106":{"nm":"Posilovací gumový míček","de":"Gumový míček, který svíráte a uvolňujete v dlani, potichu pokračuje v tréninku i u stolu. Síla nashromážděná ve volných chvilkách vydrží déle než síla vylitá naráz. Vytrvalost vždy roste z takových drobností."},"ICON-2107":{"nm":"Přezka hrudního pásu","de":"Stačí, aby přezka pásu na hrudi byla jen trochu posunutá, a čísla se rozskáčou. I samotné naslouchání vlastnímu srdci začíná pevným utažením. Každé měření nakonec začíná těsným, bezmezerovým přiléháním."},"ICON-2108":{"nm":"Klip na měření tepu","de":"Klip, který jemně kousne do konečku prstu a v tichosti počítá tep. Nasaďte ho, zklidněte dech, a rytmus srdce se zřetelně objeví na malé obrazovce. Tělo vždy podává pravdivou zprávu o svém stavu."},"ICON-2109":{"nm":"Pouzdro na náramek s tepoměrem","de":"Pouzdro, které ukrývá náramek se snímačem, je malé, ale svého člena rodiny pozná. Čím snáz se malé zařízení ztratí, tím víc potřebuje domov, kam se vrátit. I pečlivé uchovávání je jedna z podob něhy."},"ICON-2110":{"nm":"Vlaječka na tempo","de":"Malá vlaječka, která přesně označí běžcův cíl. Jediný bod určený předem – „jen sem, a dost“ – dovede unavené nohy až do konce. Cílovou pásku v srdci si člověk vždy zapíchne sám."},"ICON-2111":{"nm":"Krytka srdečního světýlka","de":"Malé světýlko, které tiše bliká v rytmu tlukotu srdce. Když se chvíli díváte na ten rytmus rozsvěcení a zhasínání, srdce se znovu dojme myšlenkou, že být naživu může být tak pravidelná věc."},"ICON-2112":{"nm":"Počítadlo kol s korálky","de":"Počítáte opakování korálky, které jedním pohybem posunete o jeden dál. Číslo si nemusíte pamatovat v hlavě – prsty si ho pamatují za vás. Když počítání svěříte rukám, mysl může zůstat celá jen u pohybu."},"ICON-2113":{"nm":"Klip na měření saturace kyslíku","de":"Klip nasazený na konečku prstu tiše čte množství kyslíku v krvi. Když se neviditelná hloubka dechu objeví jako číslo, znovu si uvědomíte, že péče o tělo je nakonec jen o pozorném pohledu."},"ICON-2114":{"nm":"Barevný pásek srdečních zón","de":"Páska, která barvami rozděluje intenzitu cvičení, na první pohled prozradí, jak moc se právě snažíte. Modrá je pohoda, červená je hranice. Barva se tak stává tichým slibem, ve kterém se sama stává laskavým jazykem."},"ICON-2115":{"nm":"Měřicí želé kapsle","de":"Malá želé kapsle, která měří stav těla, v jediném zrnku pečlivě uchovává informace na celý den. Ať už je uvnitř průhledné slupky cokoli, patří tam i přání poznat sám sebe o trochu lépe."},"ICON-2116":{"nm":"Háček na ručník na pot","de":"Malý zvyk věšet ho vždy na svůj vlastní háček místo toho, aby ležel kdekoli, udrží v pořádku celý prostor. Podobně jako tento háček, který ručníku předem vyhradí místo, kam se vrací, i úklid vždy září právě v maličkostech."},"ICON-2117":{"nm":"Poutko na víčko láhve","de":"Krátká šňůrka na víčku láhve zabrání nehodě, kdy víčko odkutálí pryč. Moudrost přivázat k tělu něco, co se snadno ztratí – jediná šňůrka tiše odejme starost na celý den."},"ICON-2118":{"nm":"Lopatka skládacího vějíře","de":"Lopatka vějíře, která rozvíří vzduch, když ji zcela rozevřete. Jako staré vějíře, které kdysi ochlazovaly pot v horké dny, i ten nejjednodušší nástroj dokáže poskytnout nejchladivější útěchu. Jediný závan vždy vzejde z konečků prstů."},"ICON-2119":{"nm":"Sáček na chladicí ručník","de":"Malý sáček, který ukrývá ručník, jenž po namočení zchladne. Kousek látky, který chladí horko, v něm úhledně spí, dokud si sám neusedne na unavený zátylek a v tichosti neodnese poledního horko."},"ICON-2120":{"nm":"Miska na odkapávání","de":"Miska připravená předem na místo, kam skápne kapka. Místo aby stékající kapce vyčítala, nejprve jí připraví místo, kam dopadne. Vlídnost kuchyně vždy zůstává takto potichu, beze zvuku."},"ICON-2121":{"nm":"Směrová lamela ventilátoru","de":"V okamžiku, kdy proud vzduchu mířící přímo vpřed lehce uhne podél malé lamely, dusný vzduch tanečního sálu si konečně vydechne. Změna proudění vždy záležela na takovém drobném úhlu."},"ICON-2122":{"nm":"Čelenka na mytí obličeje","de":"Když se ofina při mytí obličeje namočí, celý den se rozsype. Tato páska, která jemně vyčeše vlasy z čela, dopřeje člověku před zrcadlem pět suchých minut. Teprve když chybí, si toho člověk všimne."},"ICON-2123":{"nm":"Držák na sklenici s klipem","de":"Když se sklenice na okraji stolu nebezpečně kymácí, tento klip ji jemně přidrží z jedné strany. Doušek vody vám připomene, že den, který proběhl bez rozlití, vděčí za to komusi, kdo místo vás držel okraj."},"ICON-2124":{"nm":"Hák na okenní křídlo","de":"Pevně zavřené okno dusí, dokořán otevřené zebe. Tento hák si pamatuje přesně tu správnou mezeru mezi nimi. Větrání je nakonec věcí srdce – nechat věci pootevřené právě tak akorát."},"ICON-2125":{"nm":"Korková krytka na roh kostky","de":"Vždycky bolí právě ostrý roh, do kterého narazíte. Proto se z kousku korku vyřízne krytka na každou hranu. Místo měkce obalené už nikomu neublíží na koleni."},"ICON-2126":{"nm":"Poutko na jógový váleček","de":"Přenášet dlouhý polštář je otravnější, než by se zdálo. Připevníte jedno poutko a vejde se pohodlně do jedné ruky. Tajemství, jak lehce zvednout něco těžkého, spočívá v tom, kam se umístí úchyt."},"ICON-2127":{"nm":"Spona opasku","de":"Jsou dny, kdy si pas utáhnete o dírku víc, i dny, kdy o dírku povolíte. Nejupřímněji dnešní stav zná právě tato malá spona. Kus kovu, který beze slova zaznamenává upřímnost těla."},"ICON-2128":{"nm":"Čtvrtinová podložka pod kostky","de":"Kostka rozřezaná na čtvrtiny pevně podepírá podlahu. Ani příliš vysoko, ani příliš nízko – přesně tak vyváženě. Beze slov ukazuje, že podepírat znamená sklonit se sám, aby se nadneslo to, co je nahoře."},"ICON-2129":{"nm":"Potah na vejcovitý polštář","de":"Polštáři kulatému jako vejce se obleče přesně padnoucí šat. I když se prosákne potem, stačí ho svléknout a vyprat. Domácnost ví, že čím víc se něco denně dotýká pokožky, tím víc potřebuje čerstvý kousek na převlečení."},"ICON-2130":{"nm":"Vyrovnávací klín pod bloky","de":"Když se podlaha byť jen nepatrně nakloní, všechno pečlivě postavené se rozviklá. Vsuňte do mezery jeden tenký klín a svět znovu nabude vodorovnosti. Narovnat věci nevyžaduje nic velkolepého."},"ICON-2131":{"nm":"Zarážkový uzel na popruhu","de":"Pevný uzel na konci popruhu zabrání tomu, aby se rozplétal a třepil. Šňůra s úhledně dokončeným koncem vydrží dlouho. Jediný malý uzel učí, že dokončit je vždy těžší než začít."},"ICON-2132":{"nm":"Skládací podložka pod kolena","de":"Ta bodavá bolest, kdykoli koleno dopadne na tvrdou podlahu. Jediná podložka, kterou lze složit a rozložit, se jemně vsune mezi koleno a zem. Je to něha, která místo někoho jiného podepře jeho kolena."},"ICON-2133":{"nm":"Protiskluzová podložka pod kostky","de":"Sebepevnější kostka je k ničemu, pokud klouže. Jemné drážky vyryté do spodní strany se pevně zakousnou do podlahy. Tajemství toho, co se nechvěje, se vždy skrývá na neviditelné spodní straně."},"ICON-2134":{"nm":"Klip na zarovnání tyčí","de":"Tyče se srovnají do rovné řady a klipem se lehce sepnou. Kdo je zvyklý srovnávat věci do řady, ten to zná – ten podivně malý pocit uspokojení, který se vylévá z toho, když se pokřivené věci narovnají vedle sebe."},"ICON-2135":{"nm":"Poutko na protahovací pás na hamstringy","de":"Když zezadu stehna zabolí tak, že unikne výkřik, tato smyčka místo ruky, která nedosáhne, natáhne se za špičkou nohy. Tam, kam by se sám nedostal, vede jediný pramínek šňůry lávku pro nohu."},"ICON-2136":{"nm":"Podložka na roztažení prstů","de":"I prsty na nohou, zavřené celý den v botách, potřebují chvíli oddechu. Na podložce, která je od sebe roztáhne, se noha konečně protáhne. Večer, který uvolňuje počínaje tím nejvzdálenějším místem."},"ICON-2137":{"nm":"Úhloměr na postoj","de":"O kolik stupňů se moje držení těla vychýlilo, okem prostě nelze odhadnout. Když měřítko tiše sdělí úhel, tělo se teprve pak postaví rovně. Stupnice, která ukáže náklon, jenž nebylo vidět."},"ICON-2138":{"nm":"Klín na vyrovnání pánve","de":"Líné odpoledne, kdy pánev ztuhla nakloněná na jednu stranu. Podložíte jediný klín a pomalu se navrátíte ke středu. Není to násilné napřimování, ale pomoc věcem znovu najít své správné místo."},"ICON-2139":{"nm":"Přezka pásu na otevření ramen","de":"Páska, která jemně narovná schoulená ramena. Utáhnete přezku a shrbená záda se pomalu otevřou. Až se zhluboka nadechnete s doširoka rozevřenými rameny, teprve tehdy se objeví postoj na jevištní úklonu."},"ICON-2140":{"nm":"Klín pod páteř","de":"Lehnete si na záda a páteř nakreslí svou přirozenou křivku. Klín, který tuto křivku tiše podepře, aniž by se jí vzpíral. Umění správně odpočívat začíná uznáním křivky, se kterou se tělo narodilo."},"ICON-2141":{"nm":"Klín na protažení nártu","de":"Protahování nártu vždy někde trochu vázlo. Podepřete správný klín a protáhnete se osvěživě až do hloubky, na kterou jste předtím nedosáhli. Malý svah, který pomůže dosáhnout o kousek dál."},"ICON-2142":{"nm":"Opěrka na zápěstí","de":"Když zápěstí ohnuté před klávesnicí začne brnět, opěrka se tiše podsune pod něj. O ruce, které dlouho pracují, se první postarají právě takové skromné, nízko položené věci."},"ICON-2143":{"nm":"Ochranný pás na zápěstí","de":"Než zvednete něco těžkého, jednou obtočíte pás kolem zápěstí. Jistota, která roste s každým otočením. Zvyk zabalit se dřív, než se člověk zraní, je tichým tajemstvím těch, kdo cvičí dlouhodobě."},"ICON-2144":{"nm":"Pouzdro na telefon na paži","de":"Kam si při běhání odložit telefon, byl vždycky problém. Toto pouzdro připnuté k předloktí ten problém přebírá na sebe. Když běžíte s oblíbenou písní připnutou na paži, cesta se zdá o dost kratší."},"ICON-2145":{"nm":"Krytka pružiny posilovače úchopu","de":"Krytka nasazená na konec pružiny posilovače úchopu, aby nebodala do dlaně. Během všeho toho svírání a uvolňování udržuje tato malá zátka mír mezi rukou a kovem. Ohleduplnost na neviditelném místě."},"ICON-2146":{"nm":"Náprstek na prst rukavice","de":"Babiččiny prsty zručné v šití vždycky nosily náprstek. Tento náprstek nasazený na konec rukavice chrání konec prstu. Přání ušetřit ruce, které dlouho pracovaly, je nápadně stejné i napříč generacemi."},"ICON-2147":{"nm":"Podložka na mozoly na dlani","de":"Mozoly narostlé na dlani jsou otisky prstů zanechané úsilím. Podložka přiložená přes ně umožní další opakování. Znovu obalí ztvrdlé místo, a člověk se znovu zavěsí."},"ICON-2148":{"nm":"Protiskluzová páska na dlaň","de":"Když dlaň pořád klouže, upustíte to, co jste s takovou námahou drželi. Omotáte drsnou pásku a ruka s nástrojem se stanou jedním tělem. Síla nepustit pochází, jak se ukazuje, z tření."},"ICON-2149":{"nm":"Potítko na předloktí","de":"Než pot stékající během cvičení dosáhne zápěstí, tato páska na předloktí ho pohltí jako první. Že se za pot není třeba stydět, beze slov dosvědčuje promáčená látka."},"ICON-2150":{"nm":"Sušák na rukavice","de":"Necháte-li je jen tak ledabyle pohozené, další ráno je muka, ale pověsíte-li je úhledně, vítr je přes noc sám od sebe usuší do měkka. Čistá vůně dobře usušených rukavic otevírá zítřek svěže a čistě."},"ICON-2151":{"nm":"Poutko na zip sportovní bundy","de":"Zpocenou rukou se prostě nedá uchopit maličký zip. Připevníte poutko a jedním čistým tahem je hotovo. Bezvýznamné poutko zachrání celou zoufalou minutu."},"ICON-2152":{"nm":"Prodyšná záplata na pot","de":"Na nejteplejší místo těla umístíte prodyšnou záplatu. Uvězněné horko potichu unikne skrz otvory záplaty. Vytvořit jeden malý průduch přímo uprostřed dusna."},"ICON-2153":{"nm":"Kousek do vložky do boty","de":"Z opotřebené vložky vyříznete jen obnošené místo a vsadíte nový kousek. Ruka, která nevyhodí celou věc, ale vymění jen to, co bolí. Malá oprava pod chodidlem odlehčí každý krok dne."},"ICON-2154":{"nm":"Nažehlovací číslo na dres","de":"Číslo na zádech se žehličkou pevně vtiskne do látky. Zatímco teplo chladne, číslo se na tkanině pevně usadí. Zakládající razítko, kterým se lidé se stejným číslem stávají jedním týmem."},"ICON-2155":{"nm":"Zpevňující krytka špičky boty","de":"Osud boty, jejíž špička neustále do něčeho naráží, tiše zastaví zpevňující krytka na špičce. Místo, které se opotřebí jako první, je uděláno nejpevnější. Čím déle bota vydrží, tím pevnější je hned od špičky."},"ICON-2156":{"nm":"Uzel stahovací šňůry na dresu","de":"V okamžiku, kdy zatáhnete za stahovací šňůru v pase a zavážete ji, volné oblečení se přitiskne k tělu přesně na míru. Tento pevný uzel, který se nerozváže, drží vše na místě po celou dobu i těch nejprudších pohybů."},"ICON-2157":{"nm":"Protiskluzová páska na kotníkové ponožky","de":"Ta trápení, kdy se kotníková ponožka pořád smekala dovnitř boty. Jediná páska tomu smeknutí zabrání. Ponožka tak malá, že jí nikdo nevěnoval pozornost, konečně udrží své místo."},"ICON-2158":{"nm":"Podpažní potítko na dres","de":"Podložka umístěná předem na místo, kde se nejvíc potí. I když se úplně promáčí, na povrchu oblečení se neukáže ani stopa. Věci, které tiše pracují mimo dohled, udržují jeviště čisté."},"ICON-2159":{"nm":"Poutko na patu boty","de":"Poté, co si obujete botu, zatáhnete za poutko na patě a noha hravě zajede dovnitř. Ta krátká pohodlnost, díky které se nemusíte skrčit. V uspěchané ráno takové jediné poutko vykoná dobrou službu."},"ICON-2160":{"nm":"Nástavec masážní pistole","de":"Podle místa, které masírujete, vyměníte nástavec. Každý ztuhlý sval má svůj vlastní tvar, který mu sedí. Večer, kdy si ramena, jež vydržela celý den, vyberou přesně tu správnou intenzitu útěchy."},"ICON-2161":{"nm":"Nabíjecí dok masážní pistole","de":"I ruka, která má celý den uvolňovat tělo, se probudí až po dobití. Dokud se červené světlo nezmění na zelené, můžete si na chvíli odpočinout. Když blikání ustane, tiše se blíží řada na to, aby znovu pohladila ztuhlá ramena."},"ICON-2162":{"nm":"Ovladač intenzity masážní pistole","de":"Slaběji, ještě trochu, tak dost. Otáčením ciferníku konečky prstů tiše smlouvají s vlastním tělem. Dnešní slib – zpevnit se jen tolik, kolik to bolí – je pečlivě zapsán mezi drobnými ryskami."},"ICON-2163":{"nm":"Kroužek na vibrační míček","de":"I dobře se kutálející míček potřebuje místo, kde na chvíli zastavit. Tento kulatý držák tiše obejme srdce, které se chce odkutálet pryč, a udrží mu místo, dokud nepřijde další řada. I odpočinek je součástí cvičení."},"ICON-2164":{"nm":"Krytka na rukojeť tlakové tyčky","de":"Jediná malá čepička nasazená na konec, a bolest v dlani se pomalu rozplyne. Mezi tvrdostí a pokožkou je vždy třeba jedné měkké vrstvy. Něžná píď, která nejprve zaoblí místo, kde dochází k dotyku."},"ICON-2165":{"nm":"Sáček na arašídový váleček","de":"Malý pytlík, ve kterém se ukrývá arašídovitý váleček. Když se vykutálí z rohu tašky, spolu s ním se vynoří i včerejší předsevzetí, že se dnes zase trochu postaráte o tělo. Malý sáček si pamatuje slib."},"ICON-2166":{"nm":"Stojan na masážní váleček na chodidla","de":"Když se zavrtí místo, kterému svěříte chodidlo, zavrtí se i uvolnění. Tento stojan, na kterém stojí váleček, pevně drží zem a připraví místo, kde se unavená chodidla mohou v klidu opřít. Spolehlivost pramení z toho, co se netřese."},"ICON-2167":{"nm":"Zátka do dutiny válečku","de":"Malá zátka, která uzavírá prázdnou dutinu. Neviditelný vnitřek musí být vyplněn, aby se vnějšek nerozpadl. To místo, které nikdo neuvidí, dokud se váleček kutálí, tiše podpírá právě tato tichá součástka."},"ICON-2168":{"nm":"Koncová krytka masážní hůlky","de":"Kulatě zaoblená čepička na konci tyčky. Aby se neopotřebila, aby se nepoškrábala – chránit konec je nakonec cesta, jak si ho udržet po boku dlouho. Přání obalit místo, které dostane ránu jako první, tím nejjemnějším způsobem."},"ICON-2169":{"nm":"Odstřihovač tejpovací pásky","de":"Jedním tahem jednou rukou se páska čistě přestřihne. I v zavazování a dokončování je jistá drobná dovednost, a tato čepel zná cit pro úhledné zakončení. Čisté dokončení odlehčí to, co přijde příště."},"ICON-2170":{"nm":"Lepicí krytka na konec pásky","de":"Krytka, která tiše přitiskne konec, aby se nerozvázal. Začít dokáže každý, ale vydržet přilepený až do konce je vždy těžké. Tato malá ruka, která drží poslední kousek, tiše přebírá zodpovědnost za dnešní dokončení."},"ICON-2171":{"nm":"Kompresní rukáv na zápěstí","de":"Omotáte přetížené zápěstí jednou vrstvou a bolest dorazí o takt později. Jako ruka, která vás tiše drží za ruku, i komprese bývá někdy tou nejněžnější ochranou. Není to svírání, je to opora."},"ICON-2172":{"nm":"Přezka kotníkové ortézy","de":"Krátké cvaknutí zapínající se přezky uklidní mysl. Když pevně obemknete kotník, nenápadně naroste odvaha, se kterou se zdá, že jeden krok navíc bude v pořádku. Jediný malý zvuk se stává pevným začátkem."},"ICON-2173":{"nm":"Stahovací spona na koleno","de":"Čím víc utáhnete popruh, tím jistější koleno je. Aby se nerozvázal, ale zároveň nebolel – někde mezi tím je přesně to správné zúžení. Spona si to místo pokaždé nezapomene, znovu a znovu."},"ICON-2174":{"nm":"Nůžky na prstovou tejpovací pásku","de":"Malé nůžky, které přesně přestřihnou pásku omotanou kolem klubu prstu. Zaoblený hrot, aby neporanily kůži. Čím víc je nástroj určen k péči, tím jemněji je nabroušená jeho čepel – to tiše ukazují právě tyto nůžky."},"ICON-2175":{"nm":"Navíječ na kompresní bandáž","de":"Rám, na který se úhledně znovu navine rozvinutá kompresní bandáž. Ruka, která si pečlivě smotá to, co dopoužila, se nezamotá ani příště, až se bude znovu rozvíjet. V každé úhledně namotané vrstvě je vpitá dnešní upravenost."},"ICON-2176":{"nm":"Popruh chrániče holeně","de":"Popruh, kterým se přiváže chránič holeně. Mysl, která si nejdřív prohlédne místo, kam by mohla dostat ránu, je sama o sobě přípravou. Vstoupíte na hřiště s nohama pevně svázanýma, a strach v srdci se sníží na polovinu."},"ICON-2177":{"nm":"Klip na loketní chránič","de":"Malý klip, který pevně přidrží, aby chránič nesklouzl. Zdánlivě bezvýznamný jako sevření listu papíru, ale povolí-li se právě on, uvolní se úplně všechno. Jediné malé zajištění pevně drží klid na celý den."},"ICON-2178":{"nm":"Rukojeť na protahovací smyčku","de":"Uchopíte smyčku a protáhnete tělo dlouze, a uvidíte konečky prstů natažené o píď dál než včera. S tahem se neprodlužuje jen sval. I ztuhlé srdce se přitom trochu narovná."},"ICON-2179":{"nm":"Rozpěrka mezi prsty","de":"Roztáhnete prsty na nohou, celý den zavřené v botách, a do stísněného místa vnikne vánek. Na světě jsou věci, které se stanou pohodlnými teprve poté, co se na chvíli oddělí. I špičky nohou potřebují prostor k dýchání."},"ICON-2180":{"nm":"Klínová podložka na uvolnění lýtek","de":"Podložíte-li ho klínovitě pod lýtka, nohy se samy pomalu uvolní. Jediný šikmý úhel tiše nechá odtéct tíhu celého dne. Lehce opřený sklon k lehu – to je někdy ta nejpohodlnější poloha ze všech."},"ICON-2181":{"nm":"Opěrka na uvolnění šíje","de":"Položíte na ni krk a na chvíli zavřete oči. Že je v pořádku na okamžik odložit těžkou hlavu, šeptá tato malá opěrka tiše ramenům, pokaždé ze stejného místa. I opírání se vyžaduje odvahu."},"ICON-2182":{"nm":"Koncová krytka protahovací tyče","de":"Jediná krytka pokrývající konec dlouhé tyče. Když je konec měkký, kdekoli se dotkne, je to v pořádku. Ať míří kamkoli, nejdřív zaoblit hrany – ohleduplnost vždy začíná takto potichu."},"ICON-2183":{"nm":"Podložka s masážními hroty","de":"Ulehnete tělem na hrbolaté výstupky, a s každým promáčknutým místem z vás vyprchá kus dne. Na té hranici mezi bolestí a úlevou se ramena ztuhlá celý den pomalu poddávají, jako by se vzdávala."},"ICON-2184":{"nm":"Přesýpací hodiny na dýchání","de":"Tichý slib protahovat dech, dokud nepropadne poslední zrnko písku. Tenký pramínek písku tiše počítá rytmus nádechu a výdechu. I uspěchaná mysl se přitom na chvíli utiší."},"ICON-2185":{"nm":"Podložka s masážním míčkem na chodidlo","de":"Podložíte míček do středu chodidla a jemně zatlačíte. Chodidlům, která celý den nesla celé tělo, tato malá podložka tiše postoupí své místo se slovy, že teď je řada na tom, aby byla ona podepřena. I to, co podpírá, má chvíle na odpočinek."},"ICON-2186":{"nm":"Poutková šňůra na uvolnění ramen","de":"Poutková šňůra, kterou si zavěsíte na rameno a zatáhnete. Natáhnete-li šňůru směrem ke ztuhlému místu, sevřený kloub se uvolní o kousek dál. Ukazuje, že i cesta ke svobodě potřebuje něco, co ji uchopí za ruku."},"ICON-2187":{"nm":"Disk plavecké dráhy","de":"Jediný kulatý článek lanové zábrany, která rozděluje vodní hladinu. Vlídná hranice vytyčená na vodě, aby nedošlo ke srážce se sousedem. Malé přepážky, které střeží cestu každého, vedou všechny bok po boku až do cíle."},"ICON-2188":{"nm":"Napínací háček na dráhové lano","de":"Háček, který napíná dráhové lano a drží ho. Když je moc volné, prohýbá se ve vlnách, když je moc napjaté, praskne. Hledání toho pravého napětí se podobá hledání vnitřního klidu – vždy tápavě hledáte kdesi mezi tím."},"ICON-2189":{"nm":"Barevná krytka dráhy","de":"Malá krytka obarvená pro každou dráhu jinak. Značka natřená tak, aby vlastní cestu bylo možné poznat jediným pohledem i zdálky. Nedopustit, aby se člověk ztratil kvůli jedné barvě – navigace svou podstatou vždy začíná právě takovou drobnou laskavostí."},"ICON-2190":{"nm":"Závěsná deska na dráhová lana","de":"Deska, na kterou se úhledně zavěsí dráhová lana, když se nepoužívají. V ruce, která pečlivě urovná lana pro příští start, se tiše skrývá klidné odhodlání dnešek dobře uzavřít."},"ICON-2191":{"nm":"Navíjecí rukojeť dráhového lana","de":"Rukojetí se otáčí dokola a navíjí se dlouze rozvinuté lano. Sbírat to, co bylo rozptýleno, vždy vyžaduje trpělivost. Jedno otočení, pak další – dokončení se takto skládá pomalu, bez spěchu."},"ICON-2192":{"nm":"Svorka na uzel dráhového lana","de":"Svorka, která pevně sevře, aby se uzel na konci lana nerozvázal. Nepustí ani sebemenší útržek. Jen díky ruce, která hlídá až do konce, si i dlouhé lano uchová svůj úhledný tvar, aniž by se rozplétalo."},"ICON-2193":{"nm":"Plovací korálek dráhového lana","de":"Plovací korálek dráhového lana, který se vznáší na hladině. Aby se nepotopil, nabral si dovnitř plné plíce vzduchu. Že určitá lehkost pramení z prázdnoty pečlivě naplněné úsilím, ukazuje pokaždé znovu vlnící se voda."},"ICON-2194":{"nm":"Vlaječka s číslem dráhy","de":"Malá vlaječka oznamující číslo dráhy. Kousek látky vlající ve větru zřetelně říká: „tady je tvoje místo“. Malý, ale nepřehlédnutelný ukazatel, který vás bez bloudění pošle rovnou na vaši cestu."},"ICON-2195":{"nm":"Spojovací háček dráhových lan","de":"Háček, který spojí jedno dráhové lano s druhým. Jediným hákem, který znovu propojí přetrženou cestu, je vodní dráha konečně dokončena. Spojovat je nakonec práce malého kusu kovu, který nesměle podá ruku mezi tím, co se rozešlo."},"ICON-2196":{"nm":"Nášlapná deska startovního bloku","de":"Nášlapná deska nad startovní čárou přijme na sebe celou váhu prvního skoku. Těch 0,1 sekundy prudkého odrazu – pevnost, o kterou se opřely špičky nohou, odstartuje celý závod. Každý vzlet začíná na místě, kam se dá pevně stoupnout."},"ICON-2197":{"nm":"Startovní madlo","de":"Madlo, které ruka pevně sevře těsně před startovním signálem. Chvějící se srdce je třeba někde ukotvit, jinak se start rozechvěje. Jen díky tomu, že je čeho se zachytit, se další jediný pohyb stane o poznání jasnějším a pevnějším."},"ICON-2198":{"nm":"Vlaječková šňůra pro znak","de":"Vlaječková šňůra, která tomu, kdo pluje s tváří k stropu, oznámí, že se blíží stěna. Vlídnost, která předem upozorní na to, co není vidět. Díky jedinému signálu, který se stará o vaše záda, se poslední záběr stává bezpečným."},"ICON-2199":{"nm":"Podložka na obrátkovou stěnu","de":"Měkká podložka připevněná na stěnu, kde se mění směr. Aby to nebolelo ani při silném nárazu, měkce obalí místo obratu. Na cestě zpět je vždy nejdřív položena něčí tichá ohleduplnost."},"ICON-2200":{"nm":"Cílová dotyková deska","de":"Ve chvíli, kdy se jí dotknou konečky prstů, je všemu konec. Konec dlouhé, zadýchané trati se nakonec smrskne na tento jediný lehký dotek. Deska tiše odpovídá, že dorazit do cíle není nic velkolepého, ale přesně trefit své místo."},"ICON-2201":{"nm":"Startovní pás skluzavky","de":"Každý, kdo stojí na kraji svahu, aspoň jednou zadrží dech. Když ten krátký okamžik strachu překoná a sjede dolů, žbluňk – spolu se sprškou vody vytryskne smích. Start vždycky začíná kousek za malým strachem."},"ICON-2202":{"nm":"Značkovací kužel zatáčky","de":"Když se na rozcestí zaváháš, promluví jako první tenhle malý bod. Tady se otoč, říká, ať nezabloudíš. Někdo díky téhle jediné barvě znovu najde svůj směr a jde dál."},"ICON-2203":{"nm":"Úhlový klín startovního bloku","de":"Těsně před odrazem, v tom půltaktu, kdy se tělo skrčí nejníž. Je tam malý opěrný bod, který podpírá úhel, aby špičky nohou neuklouzly. Každý okamžik vysokého vzletu se rodí právě z tohoto sklonu."},"ICON-2204":{"nm":"Nárazová krytka na roh zdi","de":"Aby to nebolelo, i kdybys se při hraní narazil, roh se vzdal své ostrosti a zaoblil se. Přání, aby ses nezranil, je obroušené znovu a znovu a přilepené ke zdi. Nejněžnější ochrana bývá právě takhle tichá."},"ICON-2205":{"nm":"Háček na záchranný kruh","de":"Za normálních okolností je to jen místo, kde něco visí. Ale ve chvíli, kdy se někdo topí, právě sem se natáhne první ruka. Na světě existuje i taková spolehlivost, která je tím lepší, čím méně se používá."},"ICON-2206":{"nm":"Záchranná tyč s hákem","de":"Dlouhá paže, která jedním pohybem zkrátí nedosažitelnou vzdálenost. Když ruka nestačí, tenhle hák se místo ní stává rukou. Záchrana je nakonec jen podání konečků prstů někomu, kdo je daleko."},"ICON-2207":{"nm":"Sprchová hlavice u bazénu","de":"„Než vlezeš dovnitř, pořádně se opláchni.“ Jako oblíbená hláška plavčíka se ti nad hlavou spustí proud vody. Jedním chladným zásahem denní prach steče pryč."},"ICON-2208":{"nm":"Protiskluzová podlahová dlaždice","de":"Jemně vyvýšený vzor, aby bosé nohy neuklouzly. Z místa, kam nikdo nevidí, tiše přidržuje chodidla. Nejpevnější bezpečí se vždycky skrývá v tom nenápadném."},"ICON-2209":{"nm":"Cedule s hloubkou vody","de":"Než vstoupíš, číslo ti napřed prozradí hloubku. Místo, které by tě mohlo vyděsit, kdybys vešel nevědomky, se po jednom přečtení stane odhadnutelným. Tahle cedule pomáhá jen s malým kouskem přípravy."},"ICON-2210":{"nm":"Bezpečnostní lano s bójkami","de":"Barevná šňůra, která pluje po hladině a odděluje jednotlivé zóny. Bójky si podávají ruce a slibují, že až sem je to bezpečné. Teprve díky hranici se dá plavat s klidnou myslí a naplno."},"ICON-2211":{"nm":"Dezinfekční brodítko na nohy","de":"Malá nádoba, kde se bosé nohy na chvíli zastaví, než vstoupíš do vody. Je v ní ukrytý krátký rituál, při němž se čistota začíná od chodidel. Čistota vždycky začíná právě takovou péčí věnovanou jednomu kroku."},"ICON-2212":{"nm":"Výstražný kužel na mokrou podlahu","de":"Jeden žlutý kužel nenápadně zpomalí tvůj krok. „Tady je mokro, pozor.“ Ohleduplnost vyjádřená barvou místo slov. Toto malé varování tiše chrání den někoho, kdo skoro uklouzl."},"ICON-2213":{"nm":"Nástěnná skříňka první pomoci","de":"Bílá skříňka na zdi se otevírá jen zřídkakdy. Ale v tu chvíli, kdy se otevře, se stává něčí úlevou. Nouze vždycky tiše čeká na tom nejbližším místě."},"ICON-2214":{"nm":"Sítko na hladinu bazénu","de":"Tiše nabírá listí a prach unášené po hladině. Čistota nepřichází sama od sebe, proto musí každý den něčí ruka jednou vylovit, co plave nahoře. Za klidnou vodou stojí pilné sítko."},"ICON-2215":{"nm":"Hadice robotického vysavače bazénu","de":"I v noci, kdy všichni spí, pomalu obchází a osahává dno. Nejsvědomitější dělník v hodinách, kdy se nikdo nedívá. Ranní průzračnost je stopou, kterou tato hadice celou noc kreslila."},"ICON-2216":{"nm":"Dávkovač chlóru","de":"I udržet vodu čistou má svou přesnou míru. Příliš mnoho a je jedovatá, příliš málo a zakalí se – rovnováha někde uprostřed. Neviditelná ruka každý den tiše nastaví tu rysku."},"ICON-2217":{"nm":"Láhev na rozbor vody","de":"Do malé lahvičky se nabere doušek vody a zeptá se, jak se dnes vodě daří. Očima to vypadá pořád stejně, ale čísla nelžou. Klid v duši je něco, co se takhle ověřuje jednou za den."},"ICON-2218":{"nm":"Hrábě na sběr plovoucích předmětů","de":"Dlouhé hrábě, které shrábnou desky a plovoucí odpad unášené po hladině. Ruka, jež shromažďuje rozptýlené věci, se nějak podobá srdci. I nepořádek se jedním zametnutím srovná do klidu."},"ICON-2219":{"nm":"Mřížka na odtok","de":"Hustá mřížka střeží cestu, kudy voda odtéká. Tiše rozlišuje, co pustit dál a co zadržet. I loučení potřebuje filtr, říká beze slov tahle malá mřížka."},"ICON-2220":{"nm":"Plovoucí teploměr","de":"Malý průzkumník, který pluje na hladině a čte teplotu. Ohleduplnost, jež ti prozradí, jestli je voda studená nebo tak akorát, ještě než se jí dotkneš. První jistota před vstupem do vody vždycky začíná u této bójky."},"ICON-2221":{"nm":"Naviják na bazénovou plachtu","de":"Rukojeť, která svine širokou plachtu a uklidí ji stranou. Nástroj, jenž ví, kdy rozprostřít a kdy sbalit, působí nějak spolehlivě. Ve chvíli odpočinku je to, jako by se i voda přikryla peřinou."},"ICON-2222":{"nm":"Koš skimmeru","de":"Koš, kam se nakonec shromáždí veškerý odpad unášený po hladině. Díky tomu, že na neviditelném místě čeká nádoba přijímající nečistoty, je voda navrchu vždycky čirá. Za čistotou se skrývá nahromaděná dřina."},"ICON-2223":{"nm":"Věšák na sušení plavecké čepice","de":"Nasáklou plaveckou čepici pověsíš dnem vzhůru. Zatímco z ní kapka po kapce odkapává voda, čepice si pomalu popadá dech. Uschnutí je nakonec jen jiné jméno pro čekání."},"ICON-2224":{"nm":"Poutko na ramínko plavek","de":"Malé poutko, které přidržuje ramínko, aby nesjelo z ramene. Z místa, které nikdo nevidí, tiše hlídá tvůj upravený vzhled. Úpravnost se vždycky dovršuje na takových drobných oporách."},"ICON-2225":{"nm":"Pytlík na plavecké čepice","de":"Pytlík, v němž si mokré plavecké čepice jedna po druhé nacházejí svoje místo. Malý příbytek, jenž do jediného náručí obejme věci, které se snadno rozptýlí. Uklízení je něžný zvyk snažící se nic neztratit."},"ICON-2226":{"nm":"Vycpávka plavek","de":"Jedna vycpávka tiše usazená na vnitřní straně oblečení. I když zvenčí není vidět, jemně narovná ramena té, která si plavky obléká. Určitá jistota se naplňuje potichu zevnitř, ne zvenčí."},"ICON-2227":{"nm":"Klip na jmenovku plavecké čepice","de":"Malý klip, který zakousne jmenovku na okraj plavecké čepice. Mezi věcmi, jež vypadají úplně stejně, jasně říká: „tohle je moje“. Jedno jediné označení a záměna je hned pryč."},"ICON-2228":{"nm":"Poutko na zip plavek","de":"„Zapneš mi zip na zádech?“ Na to místo, kam sama nedosáhneš, dosáhne místo ruky tenhle malý poutko a vytáhne ho nahoru. Něžná vzdálenost, která pomůže s tím posledním kouskem."},"ICON-2229":{"nm":"Podložka proti kroucení čepice","de":"Plaveckou čepici, která má ve zvyku se svinovat, narovná a podepře. Podložka tiše pomáhá zprohýbané věci znovu najít svůj tvar. Aby se cokoliv znovu narovnalo, musí být ruka, která to narovná."},"ICON-2230":{"nm":"Stahovací šňůrka v pase plavek","de":"Stahovák, který obepne pas přesně tak, aby plavky nesjížděly dolů. Ani příliš pevně, ani příliš volně – právě ta správná míra. Pohodlí vždycky žije někde mezi tím."},"ICON-2231":{"nm":"Kleště na obracení plavecké čepice","de":"Kleště, které chytí naruby obrácenou plaveckou čepici a jedním pohybem ji napraví. Ten pocit, když se převrácená věc otočí zpátky, jak má být, je docela osvěžující. Malé potěšení z pořádku přichází právě z takových drobností."},"ICON-2232":{"nm":"Poutko na plaveckou desku","de":"Šňůrka, která se omotá kolem ruky, abys neupustil plaveckou desku. Když tě unáší proud, mít se čeho přidržet je velká úleva. V téhle šňůrce dodnes zůstává chvění dne, kdy ses poprvé učil kopat nohama."},"ICON-2233":{"nm":"Stahovací popruh plaveckého pásu","de":"Popruh, který pevně přidrží plovák sevřený mezi nohama. Teprve když se nepovolí, můžeš se soustředit jen na techniku. Na dobře drženém základu se ten den trénink prohlubuje kousek po kousku."},"ICON-2234":{"nm":"Nástěnný věšák na ploutve","de":"Když ploutve visí v řadě na zdi, vypadají přesně jako hejno kachen odpočívající u vody. Nohy, které doplavaly, si oklepávají vodu a čekají na zítřek. I ta pauza je nějak kulatá a roztomilá."},"ICON-2235":{"nm":"Krytka rohu plavecké desky","de":"Jedna malá krytka lehce nasazená na roh plavecké desky. Obepíná okraj tak, aby náraz nebolel a opotřebení neškodilo. Tajemství toho, jak si věc udržet dlouho po boku, spočívá v tom, začít šetřit u rohů."},"ICON-2236":{"nm":"Síťka na skladování ploutví","de":"Ploutve, podobné plovacím blánám, se v síťce vyhřívají na slunci. Jako kachny, které právě vylezly z vody a suší si peří, i ony pomalu schnou v síťce. Je to poklidný spánek před dalším plaváním."},"ICON-2237":{"nm":"Jmenovka na plavecký pás","de":"Na každý plovák se přilepí jmenovka, aby bylo jasné, komu patří. Čím víc lidí sdílí jedno místo, tím víc si mysl oddechne, když je jasné, „čí to je“. Jedna malá visačka nastolí pořádek."},"ICON-2238":{"nm":"Odkapávací stojan na plaveckou desku","de":"Místo nakloněné tak, aby voda nastřádaná v desce mohla stékat pryč. Musíš vylít, co jsi v sobě nasál, abys byl lehčí, mlčky ti to sděluje ta opora. Prvním krokem k uschnutí je dobré podepření."},"ICON-2239":{"nm":"Stahovák popruhu ploutve","de":"Malá součástka, která utáhne popruh ploutve přesně na míru nohy. Když je volný, sklouzne, když je moc utažený, bolí – ta jemná hranice mezi tím. Aby ses lehce sunul vpřed jako kachna s plovacími blánami, potřebuješ právě tenhle detail."},"ICON-2240":{"nm":"Rytmický čip na kopání nohama","de":"Malý čip, který při každém kopnutí udává takt. Raz, dva, tři – jakmile si tělo osvojí rytmus, voda se nenápadně promění v píseň. Tento čip jemně učí, že i plavání má svůj rytmus."},"ICON-2241":{"nm":"Pytlík na mokré plavky","de":"V tašce, která opouští bazén, si první místo vždycky zabírám já. Co nadělám, že po mně ostatní věci pokukují – mokré se musí uzavřít zvlášť, aby zůstalo suché všechno ostatní. Karanténa pro vlhkost, to je ta něžná funkce, kterou zastávám."},"ICON-2242":{"nm":"Ždímací deska","de":"Voda má povahu, že když ji stiskneš, tiše uteče. Jednou pořádně, podruhé pořádně – teprve když na ni na desce položíš váhu, se konečně vzdá. Pro toho, kdo neměl kde uplatnit sílu zápěstí, je jen málo lepších jevišť."},"ICON-2243":{"nm":"Přepážka do plavecké tašky","de":"Když se všechno nacpe do jedné tašky, mokré a suché se navzájem umažou. Práce spočívá v tom, nenápadně se vsunout mezi ně a tiše vytyčit hranici. Pokud jedna přihrádka přináší mír, možná je smíření překvapivě jednoduchá věc."},"ICON-2244":{"nm":"Voděodolný pytlík na boty","de":"Spolkne celé boty umazané pískem, a přitom se mu ani nehne ve tváři. Ať se uvnitř děje cokoliv, venek zůstává suchý – tohle je slušnost, kterou dodržuje voděodolnost. Mlčenlivý pytlík je vítán všude."},"ICON-2245":{"nm":"Vypouštěcí zátka plavecké tašky","de":"Otočíš zátkou a den, který se nashromáždil na dně tašky, s bubláním odteče. Úklid po veselém hraní vždycky závisí na téhle jedné malé dírce. I umění pustit něco pryč má svůj promyšlený návrh."},"ICON-2246":{"nm":"Savá rohožka","de":"Tiše leží před vchodem a od každé vcházející nohy přijímá vlhkost. I když si toho nikdo nevšimne, podlaha to ví – že dnes nikdo neuklouzl. V tichém místě přebývá tichá odměna."},"ICON-2247":{"nm":"Miska na mokrou plaveckou čepici","de":"Když si odhozená plavecká čepice nemá kam sednout, podepřu ji já. Ať mi říkají mistička, i když místo jídla nosím kapky vody – když jde o to poskytnout někomu místo, i podložka může chodit hrdě vzpřímená."},"ICON-2248":{"nm":"Kolíček na sušení ručníku","de":"Na šňůře na prádlo pevně sevřu jeden ručník. Mou pýchou je tvrdohlavost, se kterou nepovolím, ať mě vítr dráždí sebevíc. Dokud ručník na slunci úplně neuschne, ruka, která jednou sevřela, se nikdy nepustí první."},"ICON-2249":{"nm":"Věšák na voděodolné pouzdro","de":"Ve chvíli, kdy se pouzdro zavěsí na háček, konečně dostane svou vlastní adresu, po tom, co se dosud jen toulalo. I když si jen vypůjčuje kousek zdi, aby na něm viselo, je snad něco spolehlivějšího než místo, kde se nemusíš bát ztráty?"},"ICON-2250":{"nm":"Vstupní náramek na skluzavku","de":"Vzrušení, které tiše čekalo na svou řadu, je celé svázané v tomhle jednom malém náramku. Teprve když se zapne na zápěstí, začne se fronta na skluzavku vlnit vpřed, takže vstup je možná jen upevnění slibu kolem zápěstí."},"ICON-2251":{"nm":"Kousek podložky vodní skluzavky","de":"Lidé vesele pobíhají, aniž by věděli, že se pod nohama roztrhla. Místo, které bylo položené proti uklouznutí, odhalí svou existenci teprve tehdy, když jeden kousek chybí. Na světě je docela dost věcí, na které si vzpomeneme jen podle prázdného místa."},"ICON-2252":{"nm":"Voděodolný náramek na klíč od skříňky","de":"Chránit klíč od skříňky před vodou je moje celoživotní práce. Ovinu se kolem zápěstí a šplouchám spolu s tebou, ale klíč samotný uhájím naprosto suchý. Když mě ztratíš, ani se nedostaneš ke svému oblečení – tak vážná je má odpovědnost."},"ICON-2253":{"nm":"Signalizační semafor na skluzavce","de":"V tom krátkém okamžiku, kdy se červená mění na zelenou, srdce všech nahoře na skluzavce bije naráz. Pravomoc povolit start – kdo by řekl, že se do téhle malé signalizační destičky vejde tolik vzrušení."},"ICON-2254":{"nm":"Přezka plavecké vesty na líné řece","de":"Přezka, která pevně drží člověka unášeného proudem líné řeky. Teprve po tom cvaknutí se člověk konečně s klidnou myslí svěří proudu vody. Klid v duši někdy začíná právě u tak malého zámku."},"ICON-2255":{"nm":"Vlajka bazénu s umělými vlnami","de":"Předem lidem oznamuje čas, kdy se přiženou vlny. Když se vlajka zvedne, ozve se jásot, když klesne, nastane chvilka na vydechnutí. Kupodivu je to jeden kus látky, kdo udává rytmus u rozvlněného bazénu."},"ICON-2256":{"nm":"Náhrdelník s číslem na skluzavku","de":"Nos si kolem krku, v jaké jsi frontě, a nikdy se nespleteš. Pohled na to, jak jedna číslovka určuje pořadí – řád takhle často začíná u malého náhrdelníku."},"ICON-2257":{"nm":"Nabíjecí žeton na náramek","de":"Lehce se dotkneš náramkem a dobití je hotové. V době, kdy se proplouvá vodou bez hotovosti i karet, tenhle malý žeton zastane celou funkci peněženky. Čím lehčí zápěstí, tím lehčí srdce."},"ICON-2258":{"nm":"Krytka rukojeti vodního děla","de":"Rukojeť vodního děla chutná nejlépe, když ji pevně sevřeš. Když jedna krytka chybí, na míření je konec, jen se to v ruce zbůhdarma protáčí – vítězství v letní vodní bitvě visí na jediném malém dokončovacím díle."},"ICON-2259":{"nm":"Formička na věž hradu z písku","de":"Nabiješ do ní mokrý písek, pevně stiskneš, obrátíš – a vyroste malá věž. Nejlíp ze všech znám to srdce, které staví znovu a znovu, i když ví, že se to zboří. Pro architekta písku je formička rovnou stavebním plánem."},"ICON-2260":{"nm":"Hřeben hrábí na písek","de":"Táhneš ji pískem, jako bys ho česal, a zůstanou po ní pravidelné rýhy. Ačkoliv hřeben ví, že vlna ten vzor brzy smaže, pilně dál kreslí své linie. I ve svědomité tvorbě něčeho, co má zmizet, je svým způsobem půvab."},"ICON-2261":{"nm":"Kotvicí závaží tyče slunečníku","de":"Mlčky drží u paty, aby slunečník neodletěl ve větru. Stín nechrání okázalá látka, nýbrž úkol těžkého, pevně zapuštěného závaží. Neviditelná váha bývá vždycky tou nejspolehlivější."},"ICON-2262":{"nm":"Rukojeť síta na písek","de":"Zatřeseš pískem a přeseješ ho, a v ruce ti zůstanou jen mušle a drobné poklady. Chytneš rukojeť a hop, hop – polovinu hledání pokladu na pláži rozhodne právě tohle jedno síto."},"ICON-2263":{"nm":"Formička na písek ve tvaru mušle","de":"Naplníš ji mokrým pískem, poklepeš – a na pláži jedna za druhou vykvetou mušle velikosti dlaně. Skutečnou mušli sníst nejde, ale tenhle tvar dokáže vytvořit kdokoliv. Skromné letní kouzlo."},"ICON-2264":{"nm":"Nastavovací kolík úhlu slunečníku","de":"Kdykoliv se slunce posune, musí za ním otočit hlavu i slunečník. Vytáhneš kolík a znovu ho zasuneš, a stín se nenápadně přesune. Podstata umění uhýbat před světlem spočívá právě v tomhle malém úhlu."},"ICON-2265":{"nm":"Krytka na hrot lopatky na písek","de":"Nasadíš ji na ostrý hrot lopatky a obsah tašky je v bezpečí. Statečnost, s níž kopala v písku, se na chvíli odloží, a s jednou krytkou se z ní stane mírumilovná hračka. Umět skrýt svou ostrost je taky ohleduplnost."},"ICON-2266":{"nm":"Kolíček na roh plážové podložky","de":"Když se vítr snaží nadzvednout roh podložky, pevně ho skousnu. Udržet jedno místo rozprostřené na písku je nakonec zásluha tvrdohlavosti všech čtyř rohů. Odpoledne bez plandání je dílem malých kolíčků."},"ICON-2267":{"nm":"Věšák na oblečení k tyči slunečníku","de":"Ledabyle ho zavěsíš na tyč slunečníku a mokré oblečení schne ve stínu. Chráněno před sluncem, otevřeno větru – provizorní šňůra na prádlo zřízená jediným háčkem. I na pláži přebývá moudrost domácnosti."},"ICON-2268":{"nm":"Voděodolné pouzdro na telefon na krk","de":"Když v sobě chová telefon a visí na krku, dodá ti odvahu fotit i pod vodou. Chrání voděodolností touhu zachytit ještě jeden snímek navíc. Jako strážce vzpomínek je docela spolehlivý."},"ICON-2269":{"nm":"Voděodolné pouzdro na mokré oblečení","de":"Bez řečí přijme celé mokré oblečení, které jsi svlékl. Jeho hrdostí je, že na ostatní věci v tašce nepustí ani kapku, proto drží pusu pevně zavřenou a hlídá jeden kout tašky. Čisté zakončení začíná u mě."},"ICON-2270":{"nm":"Řemínek přes nárt vodních sandálů","de":"Jemně obepne nárt, aby sandál bosé noze nesklouzl. I když si poskakuješ po písku, s jedním řemínkem máš jistotu. Spolehlivý společník každého kroku, nenápadný, ale vždycky nablízku."},"ICON-2271":{"nm":"Voděodolné pouzdro na kartu na krk","de":"Chová v sobě vstupenku i kartu, visí na krku a pouští se s tebou do vody. Aby ses mohl bez obav šplouchat, kolik chceš, chrání kartu vlastním tělem jako štítem. Postoj spolehlivého osobního strážce."},"ICON-2272":{"nm":"Pouzdro s hadříkem proti zamlžení brýlí","de":"Otřeš zamlženou vnitřní stranu plaveckých brýlí jednou hadříkem, a podvodní svět se znovu vyjasní. Jeden malý pytlík s hadříkem je tak klíčem, který otevírá zamlžený výhled."},"ICON-2273":{"nm":"Kartáč na mokrý písek","de":"Jemně vyčistí písek i mezi prsty na nohou. Poslední ruka, která u dveří domu uklidí stopy po veselém dovádění v moři. Jedním přejetím kartáče se s pískem nastřádaným za celý den konečně rozloučíš."},"ICON-2274":{"nm":"Voděodolný pytlík na mince na zip","de":"Pevně uzamkne pár mincí za zip. I když zmokne, cinkání zůstává stejné, takže nouzové peníze na bufet uhájí až do konce. Malý, ale hospodárně šikovný pytlík."},"ICON-2275":{"nm":"Poutko na svinutý ručník","de":"Svineš ručník, převážeš jedním poutkem, a hned visí na popruhu tašky. Obě ruce volné, ručník na rameni. Tajemství lehkého balení na koupání se skrývá v tomhle malém svazku."},"ICON-2276":{"nm":"Krytka klíčenky voděodolného náramku","de":"Poslední knoflík náramku, který chrání klíč před vodou. Teprve když krytka cvakne a zavře se, můžeš se s klidem vrhnout do bazénu. Malá, ale bezchybná tečka, jež nese odpovědnost za dokonalé zajištění zámku."},"ICON-2277":{"nm":"Náustek šnorchlu","de":"Sevřeš ho v ústech a otevře se ti dýchací cesta, mořská krajina se přiblíží až před nos. Malá zátka, díky níž se dá dýchat i pod vodou. Kdo by řekl, že půjčit si dech může být tak vzrušující."},"ICON-2278":{"nm":"Podložka proti zamlžení potápěčské masky","de":"Když se vnitřek masky zamlží, i podvodní podívaná ztrácí kouzlo. Jedna podložka té mlze zabrání, takže jasný výhled je zásluhou téhle jedné neviditelné vrstvy."},"ICON-2279":{"nm":"Stahovací klip na špičku ploutve","de":"Utáhne špičku ploutve přesně na míru nohy, aby ses mohl odrážet od vody bez volnosti. Aby síla vložená do jednoho kopnutí neunikala, klip u špičky tiše zavazuje pevný uzel."},"ICON-2280":{"nm":"Návlek na řemínek potápěčské masky","de":"Jemně obalí řemínek masky, aby netahal za vlasy. Jedna vrstva ohleduplnosti, která odstraní to štípnutí, jež jsi cítil pokaždé, když sis masku sundával. To, co malý návlek chrání, je překvapivě něha."},"ICON-2281":{"nm":"Krytka odváděcího ventilu šnorchlu","de":"I v úkonu zadržování dechu existuje tiše unikající skulina. Jeden malý ventil nenápadně odvede tu vodní stopu zpátky ven a až do konce uchrání prostor pro nádech. Moře si tuto drobnou ostražitost pamatuje s největší vděčností."},"ICON-2282":{"nm":"Háček na skladování ploutví","de":"Když se ploutve úhledně zavěsí na jeden háček zaražený do zdi, i do rozházené skladovací místnosti se snese pořádek v hlavě. Vrátit věc na její místo je ten nejtišší slib pro příští ponor."},"ICON-2283":{"nm":"Podložka nosního zvonu masky","de":"Jeden kousek podložky jemně přitiskne nos. Díky téhle malé něze, jež brání vodě vniknout dovnitř, si tvář neztrácí svůj výraz ani v chladném moři."},"ICON-2284":{"nm":"Horní chránič šnorchlu","de":"Chránič, kulatě obepínající konec šnorchlu, tiše odsune vodu, kdykoliv se přes něj přelije vlna. Čím neviditelněji součástka pracuje, tím hlouběji podpírá bezpečí jednoho nádechu."},"ICON-2285":{"nm":"Protiskluzový pásek podrážky ploutve","de":"Tenký pásek přilepený na podrážku ploutve. Je to jediná linie tření, které se chytají špičky nohou, aby neuklouzly na mokré palubě. Bezpečí vždycky tiše začíná v takových drobných rýhách."},"ICON-2286":{"nm":"Krytka ventilu potápěčské láhve","de":"Čepička, jež zakrývá ventil láhve plné vzduchu. Aby na ni nesedal prach, aby se dýchací cesta nezašpinila. Zakrýt ji znamená předem pečovat i o první nádech toho, kdo přijde po tobě."},"ICON-2287":{"nm":"Krytka náustku dýchacího přístroje","de":"Místo, kterého se dotýkají ústa, musí být vždycky nejčistší. Tahle jedna krytka nasazená na náustek beze slov chrání bránu dechu před slaným větrem a pískem."},"ICON-2288":{"nm":"Poutko na zip neoprenu","de":"Krátké poutko zavěšené na zipu neoprenu. Je to ohleduplný doplněk, díky němuž ho jedním tahem vytáhneš nahoru i rukama ztuhlýma v chladné vodě. I v zapínání oblečení je zakódované něčí přemýšlení."},"ICON-2289":{"nm":"Ochranná krytka tlakoměru vzduchu","de":"Ochranná krytka, jež obepíná sklíčko přístroje ukazujícího zbývající vzduch. Protože ta čísla se nesmí nikdy rozmazat. Čím víc ta ryska čte samotný život, tím pečlivěji se otírá a zakrývá."},"ICON-2290":{"nm":"Přezka zátěžového pásu","de":"Lidé si ovinou kolem pasu závaží a sestupují do hlubin. V tom okamžiku, kdy se jedna přezka odemkne a zamkne, se volba mezi vynořením a potopením tiše soustředí do konečků prstů."},"ICON-2291":{"nm":"Poutko na zápěstí pro potápěčskou lampu","de":"V naprosté tmě vody jeden pásek uvázaný kolem zápěstí pevně drží lampu. I když pustíš ruku, světlo tě dál následuje. Nezmizet uprostřed tmy jako malý plamínek – to je proto tak uklidňující."},"ICON-2292":{"nm":"Klip na uspořádání dýchací hadice","de":"Malý klip, který spojí rozházené hadice dohromady. Když předem zabráníš zamotání, ruce se nezaseknou ani v naléhavé chvíli. Uklízení je tichá laskavost věnovaná mému budoucímu já."},"ICON-2293":{"nm":"Zpevnění prstů potápěčských rukavic","de":"Zpevňující látka přišitá na každém konci prstu. Místa, která tahají za lano a opírají se o skálu, se opotřebují nejdřív, proto byla přidána ještě jedna vrstva, aby to opotřebení předem obejmula."},"ICON-2294":{"nm":"Patní kroužek potápěčské láhve","de":"Jeden opěrný kroužek, který postaví těžkou láhev rovně. Kulatě obejme váhu, jež by se mohla snadno převrhnout, a dá jí rovnováhu. Podepřít znamená darovat svůj bok, aby něco nespadlo."},"ICON-2295":{"nm":"Krytka ploutve surfového prkna","de":"Krytka obepínající ostrý hrot ploutve pod prknem. Aby ses nezranil ani při chůzi po písku, na chvíli uspí ten čepelovitý hrot, který dosud protínal vlny. Během odpočinku smí každý na chvíli otupět."},"ICON-2296":{"nm":"Ochranná krytka listu pádla","de":"Ochranná krytka, jež chrání hrot listu pádla. Brání tomu, aby škrábance od nárazu do skály narušovaly tok vody. Když si vážíš hrotu, jeden záběr tě donese dál."},"ICON-2297":{"nm":"Rukojeť kajakového pádla","de":"Rukojeť ovinutá v místě, kde se dlaň setkává s pádlem. Jemně podepírá místo, kde se dřív dělaly puchýře, aby ruka pádlo nezačala nenávidět, ani když plaveš proti proudu řeky."},"ICON-2298":{"nm":"Plechovka na surfařský vosk","de":"Malá plechová dóza, v níž se uchovává kus vosku. Kouzlo, které přilepí nohy k prknu, se vždycky vytahuje z téhle krabičky velikosti dlaně. Dnešní příprava začíná u jedné úhledné plechovky."},"ICON-2299":{"nm":"Stahovací poutko kotníkového vodítka","de":"Poutko, jež utáhne vodítko spojující kotník s prknem. Jeden uzel, který slibuje, že tě nepustí, ani kdyby tě strhla velká vlna. Spojení je slib, že tě přidrží, abys neodplaval příliš daleko."},"ICON-2300":{"nm":"Vzduchová zátka paddleboardu","de":"Prkno, které ztvrdne, když se naplní vzduchem, a zátka, jež ten dech uzavírá. Otevřeš ji a prkno se ploše složí, zavřeš ji a ono se postaví na vodu. V jedné malé zátce je uzavřen den, který se nadouvá a zase splaskne."},"ICON-2301":{"nm":"Popruh sedákového polštáře kajaku","de":"Popruh, který přivazuje polštář k sedadlu. Pro záda a bedra, jež dlouho vesluje vsedě, drží měkkost na místě, aby nesklouzla. I pohodlí potřebuje pevný uzel."},"ICON-2302":{"nm":"Nárazník na špici surfového prkna","de":"Nárazník obepínající příď prkna. Je to vycpávka přidaná na špičku, kde jsou srážky nejčastější, aby otupěla jako první. Umístit měkkost na místo, které vede, je slib, že bude sloužit dlouho."},"ICON-2303":{"nm":"Přezka na zapínání nepromokavé tašky","de":"Přezka, kterou přehnete a zapnete dvakrát, třikrát, aby dovnitř nevnikla ani kapka. Udržet vzácné věci suché vždy vyžaduje ještě jeden dotek ruky. To jedno pevné stažení se stává klidem na duši."},"ICON-2304":{"nm":"Kus sítě z futsalové branky","de":"Jediný kus sítě, která kdysi rozechvěla branku. Vlákno po vlákně si pamatuje jásot té chvíle, kdy ji naplnil míč. V každém uzlu žil gól a v každém roztřepeném místě dodnes žije ten zápas."},"ICON-2305":{"nm":"Hubice pumpičky na fotbalový míč","de":"Hubice pumpičky, která vdechuje vzduch do splasklého míče. Kůže, jež se povalovala scvrklá a sklíčená, znovu nadskočí a odrazí se. Naplnit ji znamená znovu postavit na nohy zastavenou hru."},"ICON-2306":{"nm":"Patka rohového praporku","de":"Patka, která rovně vztyčí praporek v rohu hřiště. Je to malé znamení hranice, ale právě díky tomuto jedinému bodu získá hlína konečně tvar stadionu."},"ICON-2307":{"nm":"Popruh chrániče holení","de":"Popruh, který přivazuje chránič holení k lýtku. Pevně drží místo, jež často schytává rány, aby se každý krok neochvěl ani uprostřed drsných soubojů."},"ICON-2308":{"nm":"Čep na výměnu kolíků","de":"Čep na výměnu opotřebovaného kolíku za nový. Drobné zoubky na špičce, které se zakusují do trávníku. Aby člověk neuklouzl, musí občas znovu postavit i to, na čem stojí."},"ICON-2309":{"nm":"Krytka ventilku fotbalového míče","de":"Malá krytka, která uzavírá dýchací otvor míče. Střeží vstup, aby nafouknutý vzduch neunikl. Udržet napětí je podobné tomu, nepolevit v soustředění až do dalšího zápasu."},"ICON-2310":{"nm":"Kužel na vyznačení čar","de":"Kužel, který vyznačuje čáru na zemi a dělí prostor. Až sem naši, odsud dál soupeři. Jediný malý kužel promění neuspořádané prázdné prostranství v hřiště s pravidly."},"ICON-2311":{"nm":"Kartáč na prach z futsalových bot","de":"Kartáč, který vymetá prach a hlínu zachycenou v drážkách futsalových bot. Když zápas skončí, i na botách se nahromadí denní dávka hlíny. Oprašující ruka je tichým poděkováním nohám, které tak dobře běhaly."},"ICON-2312":{"nm":"Věšák na brankářské rukavice","de":"Věšák, na němž brankářské rukavice schnou a odpočívají. Je to místo, kde si potem promočené ruce na chvíli odpočinou, tolikrát, kolikrát zastavily střelu. Pro příští zápas mokré vysychá a ztuhlé srdce se pomalu uvolňuje."},"ICON-2313":{"nm":"Háčky na síťku basketbalového koše","de":"Drobné háčky, na nichž visí síťka na obruči. Díky nim míč při průletu vydá ono jemné svištění. Ten čistý zvuk bodu ve skutečnosti začíná právě u těchto háčků."},"ICON-2314":{"nm":"Nástroj na vypuštění vzduchu z basketbalového míče","de":"Nástroj, který upustí trochu vzduchu z příliš tuhého míče. Přílišné napětí dělá odraz divokým. Ubrat právě tolik, kolik je třeba – míč s dobrým citem se vždy rodí z té správné míry."},"ICON-2315":{"nm":"Senzorová podložka basketbalové desky","de":"Senzorová podložka připevněná za deskou. Jasně, v číslech, zaznamená okamžik, kdy se jí dotkne míč. I chvíli, kterou přehlédlo oko, si tento drobný smysl pamatuje, a rozhodnutí je díky tomu o to spravedlivější."},"ICON-2316":{"nm":"Kužely na driblink","de":"Překážkové kužely seřazené podél driblinkové dráhy. Mezi nimi, při uhýbání sem a tam, roste hbitost nohou. Stát v cestě je také laskavost, jež učí, jak se ještě lépe protáhnout kolem."},"ICON-2317":{"nm":"Kartáček na ventilek basketbalového míče","de":"Drobný kartáček, který čistí ventilový otvor míče. Když jej ucpe prach, jehla nepronikne dovnitř, proto se nejprve vyčistí neviditelný vstup. Než se něco naplní, vždy se to nejdřív vyprázdní a otře."},"ICON-2318":{"nm":"Role tejpu na prsty","de":"Role tejpu, kterou si omotáte prsty. Pevně drží podvrtnutý kloub a dodává odvahu znovu uchopit míč. Obvázat zraněné místo je malé prohlášení, že nepřestanete."},"ICON-2319":{"nm":"Spona na hráčské číslo","de":"Spona, která připíná číslo na dres. Místo tvého jména pak hřištěm probíhá číslo. V tom jediném pevném stisku, aby neodpadlo, je jasně napsáno, kdo dnes hraje."},"ICON-2320":{"nm":"Terčový kroužek na trénink střelby","de":"Terčový kroužek nasazený do obruče, který zužuje cíl. Zmenší místo, kam musí míč vletět, a učí snášet minutí. Kdo dost dlouho míří na tu úzkou bránu, jeho prsty si nakonec samy osvojí přesnost."},"ICON-2321":{"nm":"Stěrka na podrážky basketbalových bot","de":"Než vstoupíte na hřiště, dřepnete si a nejprve otřete podrážky. Protože nechcete na palubovce zanechat ani jediný smyk. Vykročíte-li první krok s čistými špičkami, jste dnes o trochu pevnější než včera."},"ICON-2322":{"nm":"Napínací háček volejbalové sítě","de":"Napětí není vidět. Až ve chvíli, kdy háček natáhne lano na doraz a zastaví se, rozdělí síť hřiště na dvě poloviny oním napětím na šířku dlaně. Rovnováha, kterou drží neviditelná ruka, probouzí hru."},"ICON-2323":{"nm":"Upevňovací klip antény","de":"Anténa, jež se stále chvěla ve větru, se jedním klipem narovná do rovnosti. Malá věc, která zkrotí velké chvění. I ruka, jež v zákulisí potichu upevňuje jediný kabel, se pohybuje s přesně takovým srdcem."},"ICON-2324":{"nm":"Věšák na libero vestu","de":"Jinak barevná vesta hráče specializovaného na obranu visí na zdi a čeká na další zápas. Není okázalá, a přesto nese jméno, které nese celé hřiště: libero. Právě tam, na nejnižším místě, jsou oči, které vidí nejdál."},"ICON-2325":{"nm":"Kapsička na chrániče kolen","de":"Čím víc se člověk valí po zemi, tím častěji jeho kolena narážejí. Tahle malá kapsička, do níž se úhledně uklidí chrániče, to ví: jen ten, kdo se nejdřív naučí dobře padat, nakonec vzlétne nejdál."},"ICON-2326":{"nm":"Tlakoměr na volejbalový míč","de":"Ťuknutím prstu to nepoznáte. Jehla tlakoměru se jemně zachvěje a ukáže na jednu jedinou rysku. Změřit dech jednoho míče je prvním knoflíkem zápasu – z poctivého tlaku se rodí poctivá dráha letu."},"ICON-2327":{"nm":"Páska na vyznačení čáry vybíjené","de":"Jediný kruh nalepený páskou na hlinité zemi hřiště. Jeho vnitřek a vnějšek dělí celý půldenní vesmír honičky. Ruka, jež nakreslila tu čáru, ví: pravidla jsou samotným počátkem hry."},"ICON-2328":{"nm":"Stojánek na rozhodčí píšťalku","de":"Když ostrý zvuk píšťalky utichne, tiše se vrátí na své místo na stojánku. Je to místo, které nejblíž slyší dech rozhodčího. Spravedlnost vždy začíná drobným úkolem, jímž je udržet si své místo."},"ICON-2329":{"nm":"Nástěnný terč na trénink nahrávek","de":"Za svítání, kdy není nikdo, kdo by přihrával, vysíláte prsty tisíckrát k terči na zdi. Zeď je ten nejshovívavější spoluhráč. Míč, který se vrací, znovu postaví na nohy unaveného vás."},"ICON-2330":{"nm":"Měřicí tyč na výšku sítě","de":"I kdyby síť byla nižší jen o šířku prstu, zápas se pokřiví. Ve chvíli, kdy zvednete měřicí tyč, se spravedlnost nestává číslem, ale každodenním zvykem. Neviditelná přesnost střeží hřiště."},"ICON-2331":{"nm":"Kolík na nastavení úhlu startovacích bloků","de":"Úhel, pod nímž se ve dřepu dotýkají špičky bloku, ten jediný stupeň rozhoduje o startu. Jediným kolíkem zafixujete blok a urovnáte dech. Postoj na startu vás tiše doprovází až do cíle."},"ICON-2332":{"nm":"Praporek s číslem dráhy","de":"Malý praporek zapíchnutý v každé dráze zavlaje ve větru svým číslem. Všichni běží stejným směrem, a přece má každý svou vlastní cestu. Dráha v sobě zároveň chová sounáležitost i odlišnost."},"ICON-2333":{"nm":"Krytka konce štafetového kolíku","de":"Pro tu chvíli, kdy se dotkne ruky posledního běžce, krytka zaobluje hrany. Na štafetě není nejcennější rychlost, ale ruka, kterou podáváš dalšímu."},"ICON-2334":{"nm":"Věšák na měřicí pásmo","de":"Pásmo, jímž se zapisovaly výkony, věsíte na zeď, aby se nezamotalo. Je to místo, kde vedle sebe visí včerejší a dnešní vzdálenost. Růst vždy přichází nejdřív jako drobný rozdíl v číslech."},"ICON-2335":{"nm":"Kužel na vyznačení zatáčky dráhy","de":"Malý kužel postavený na vnitřní straně zatáčky vám prozradí záměr trati. Nezařezávej se příliš dovnitř, ale ani se nerozptyluj příliš ven. Ten, kdo dobře projede zatáčku, nakonec vede na čele."},"ICON-2336":{"nm":"Spona na cílovou pásku","de":"Tu pásku, jež se jako první dotkne hrudi, drží spona napnutou a čeká. Šňůra, jež existuje jen proto, aby byla přetržena. Celý den snáší vítr kvůli jediné cizí vteřině."},"ICON-2337":{"nm":"Kryt startovací pistole","de":"Než zazní ono prásknutí signálu, ústí hlavně spí pod krytem. Nádoba zvuku, v níž je uložen start. Čím hlubší ticho, tím dál se nese ozvěna první rány."},"ICON-2338":{"nm":"Kolík na nastavení výšky překážky","de":"Pokaždé, když se zvedne výška o jeden zářez, přesune se s ní i místo kolíku. A strach roste přesně o stejný kus. Přesto nohy pokaždé odhadnou o něco vyšší bod a běží dál."},"ICON-2339":{"nm":"Otočný počítač kol","de":"Když ztratíte přehled o tom, kolik kol zbývá, otočíte číselníkem o jeden dílek. Tiché cvaknutí ubývajícího čísla vlije do nohou novou sílu. Ruka, jež počítá zbývající vzdálenost, hlídá tempo."},"ICON-2340":{"nm":"Stojan na skokanskou tyč","de":"Dlouhá, pružná tyč potřebuje vlastní místo, o které se může opřít. Protože je to nástroj, který se musí ohnout, aby vyskočil, stavíte ji s ještě větší opatrností. Dobře uložená pružnost v sobě chová nejvyšší skok."},"ICON-2341":{"nm":"Hrábě na urovnání doskočiště","de":"Pomalu hráběmi urovnáte i stopy, které zanechal předchozí atlet. Doskočiště se znovu, kolo co kolo, vyrovná jako poprvé. Ruka, jež kvůli něčímu skoku smazává stopy, tam je, tichá a věrná."},"ICON-2342":{"nm":"Pás pro vyznačení rozběhové vzdálenosti","de":"Krok navíc nesmí chybět, ale ani přebývat. Vyznačovací pás na zemi poctivě ukáže místo, kam se má postavit noha. Dobrý rozběh není bezhlavou chtivostí, nýbrž vychází z klidného výpočtu."},"ICON-2343":{"nm":"Grip na diskus","de":"Sklouznou-li prsty, hod je vlastně hozen dřív, než ho vůbec hodíte. Drsná struktura gripu, jenž obepíná disk, drží rotaci na uzdě. Okamžik uvolnění vždy začíná v citu úchopu."},"ICON-2344":{"nm":"Kolébkový kroužek na kouli","de":"Kolébkový kroužek tiše drží těžkou kovovou kouli, aby se neodkutálela. Malé hnízdo, jež uchovává klid těsně před hodem. Čím výbušnější síla, tím pevnější musí být místo jejího odpočinku."},"ICON-2345":{"nm":"Ochranná krytka hrotu oštěpu","de":"Krytka nasazená na ostrý hrot oštěpu jej zahaluje do měkkého mlčení. Když nástroj, jenž má letět daleko, klidně leží, nebezpečí je zkroceno ohleduplností. I v úschově žije bezpečí."},"ICON-2346":{"nm":"Podpěrný háček laťky výškařského skoku","de":"Aby laťka nespadla ani při lehkém doteku, drží ji háček s obdivuhodnou rovnováhou. Je to místo, jež zodpovídá za onu chvějivou hranici mezi přeskočením a pádem. Spravedlnost bydlí v drobných detailech."},"ICON-2347":{"nm":"Kotva na roh doskokové matrace","de":"Nadzvedne-li se roh doskokové matrace, někdo se zraní. Kotva pevně přitiskne všechny čtyři rohy. Aby tělo, které vzlétlo nejvýš, dosedlo nejbezpečněji, podpírá je neviditelně."},"ICON-2348":{"nm":"Páska na vyznačení hraniční kružnice pro hody","de":"Hranice odhodového kruhu je vyznačena jedinou linkou pásky. Zda tu čáru šlápnete, nebo ne, rozhoduje o životě či smrti výkonu. Tenká jediná čára, kde se potkává svoboda s pravidlem, je slib."},"ICON-2349":{"nm":"Gumová patka kladiny","de":"Aby se úzká kladina nekymácela, gumová patka se pevně zakusuje do podlahy. Ona bezchybná rovnováha, jež se na ní odehrává, je ve skutečnosti dílem neviditelné pevnosti dole."},"ICON-2350":{"nm":"Ovinovací páska na hrazdu","de":"Aby dlaň nesklouzla, omotáte kolem madla hrazdy pásku. Tajemství vířivé rotace neleží v okázalosti, ale v pevně sevřené ruce. Pot skanuvší na žíněnku to ví."},"ICON-2351":{"nm":"Výškový úchyt kruhových lan","de":"Odlišují-li se dvě lana ve výšce byť jen o šířku dlaně, sestava se zhroutí. Úchyt tiše drží tuto rovnováhu. Teprve nad přesně vyrovnanou výškou začíná svobodný let."},"ICON-2352":{"nm":"Potah madla gymnastického koně","de":"Potah obepínající madlo chrání dlaň před puchýři. Pod vířícím, otáčivým cvikem je ruka, jež se nesčetněkrát odřela a zase zhojila. Ochrana je vlídný příslib příštího tréninku."},"ICON-2353":{"nm":"Rozpěrný kolík asymetrických bradel","de":"Rozestup mezi dvěma hrazdami přesně nastavíte kolíkem. Ten prázdný prostor, jímž se tělo bude proplétat, se stává jevištěm. Prsty vědí jako první: nad přesnou vzdáleností se rodí ten nejodvážnější skok."},"ICON-2354":{"nm":"Krytka pružiny odrazového můstku","de":"Ve chvíli, kdy odrazíte od můstku, vymrští pružina tělo vzhůru k nebi. Krytka pevně obepíná sílu toho odrazu. Nejkratší rozběh vytváří nejdelší let vzduchem."},"ICON-2355":{"nm":"Sáček na magnézium","de":"Bílý prášek, jímž si potřete ruce, je drobný amulet, který smazává klouzání. Krátký rituál ponoření ruky do sáčku a jejího vytažení zklidní strach. I napětí se nakonec zkrotí na konečcích prstů."},"ICON-2356":{"nm":"Zápěstní páska na gymnastiku","de":"Namotáte-li pásku kolem zápěstí, spolu s ní se utáhnou i struny srdce. Předem tak zpevníte kloub, jenž by se jinak roztřásl. Jedno dobře obvázané zápěstí tiše dovolí odvážnější rotaci."},"ICON-2357":{"nm":"Pojistný kruh na trapéz","de":"Těsně předtím, než vrhnete tělo do vzduchu, se pojistný kruh stane neviditelnou rukou. Teprve když zmizí strach z pádu, můžete doletět nejdál. Důvěra dovršuje let."},"ICON-2358":{"nm":"Víčko na tubu tenisových míčků","de":"Pod víčkem, jež uzavírá ústí tuby, spí nové míčky a v sobě uchovávají tlak. Tiché pop otevírané plechovky probouzí vzrušení ze zápasu. Uzávěr je slibem, který střeží svěžest."},"ICON-2359":{"nm":"Svěrka na napětí výpletu rakety","de":"Svěrka pevně sevře napětí struny a až do konce ji nepustí. Protože napětí jedné struny rozhoduje o odrazu míče. Neviditelný cit pro hru začíná právě u této drobné svěrky."},"ICON-2360":{"nm":"Smeták na vymetání čar tenisového kurtu","de":"Když zápas skončí, pomalu vymetete čáry kurtu. Zbavíte-li je prachu, čáry znovu zbystří. Vydláždit cestu dalšímu zápasu, ta poslední péče oživuje kurt."},"ICON-2361":{"nm":"Ochranná páska hlavy rakety","de":"Jedním obtočením kolem okraje rakety pojme i drsný náraz a otočí ho v oblinu. Vím, že okraj je místem, které se opotřebí jako první. Protože je mým úkolem přebrat opotřebení místo tebe, i dnes stojím na samém kraji."},"ICON-2362":{"nm":"Čip pro měření teploty vzduchu v hale","de":"Studený ranní vítr, jenž se vevalí dovnitř s otevřenými dveřmi, přečte čip velký jako dlaň dřív než jakýkoli člověk. Vycítit ho ještě dřív, než zamrzne nos, to je nejtišší pozdrav, jímž se otevírá den v prázdné hale."},"ICON-2363":{"nm":"Odrazová deska základní čáry","de":"Hráči, který váhá, kam postavit špičku, stačí jediná čára nakreslená na zemi. Čára, kterou se nesmí překročit, se tak sama stává startovní čárou pro nejdelší skok, jak mlčky napovídá odrazová deska."},"ICON-2364":{"nm":"Věšák na koš na tenisové míčky","de":"Pojme desítky míčků do jediného sousta a ani jediný neupustí. Sbírat to, co se rozptýlilo po kurtu, a předat to dalšímu tréninku, ruka tiše zaneprázdněná v koutě, i dnes tu visí."},"ICON-2365":{"nm":"Krytka konce rukojeti rakety","de":"Ve chvíli, kdy ji cvaknete na konec rukojeti, se raketa konečně přitulí k dlani. Jediná malá krytka odděluje klouzání od jistoty. Teprve když je konec pevně uzavřen, zesílí i první úder."},"ICON-2366":{"nm":"Spona na ručník u kurtu","de":"I když prudce fouká vítr, svírá pevně ústa a vydrží na kraji kurtu, aby pečlivě vyždímaný ručník neuletěl. I do ochrany krátké chvíle na popadnutí dechu se otiskly něčí zručné prsty."},"ICON-2367":{"nm":"Kleštičky na narovnání peří badmintonového míčku","de":"Stačí jediné pomačkané peříčko a let se rozkolísá. Opatrně narovnáte pomačkané křídlo a míček je znovu připraven letět rovně. Dolet daleko vždy začíná takovouto drobnou úpravou."},"ICON-2368":{"nm":"Zátka tuby na badmintonové míčky","de":"Aby míčky srovnané uvnitř neztratily pružnost, pevně ucpete konec tuby. Dlouho jste pozorovali, že jediný dotek vlhkosti dokáže sesadit peříčko. Umět dobře uschovat je už samo o sobě součástí zápasu."},"ICON-2369":{"nm":"Odpočívadlo na stolní tenisové míčky","de":"Malý míček, který se sem přikutálel, si na mně na chvíli vydechne. Tiše ho podepřít, aby se neskutálel dál, to je ta nejkulatější podoba pozornosti, kterou nabízí místo vedle stolu."},"ICON-2370":{"nm":"Gumový váleček na pálku na stolní tenis","de":"Přejedete-li válečkem tiše po gumovém povrchu, zvíří se starý prach a lepivost znovu ožije. Aby se míč zatočil, musí žít rotace. Dnešní kondice rakety se probouzí právě touto jedinou vlídnou péčí."},"ICON-2371":{"nm":"Tyčka na měření výšky sítě","de":"I kdyby byla síť vyšší jen o dlaň, ráz hry se změní. Lidé, kteří nakonec odmítnou věřit odhadu okem, si mě přiloží k síti. Spravedlnost, zdá se, přichází teprve z výšky přesně změřené pravítkem."},"ICON-2372":{"nm":"Čip na měření rychlosti badmintonového míčku","de":"Rychlost míčku, jenž prosvištěl vzduchem, tiše odhaduji. Jakmile se dosud neviditelná rychlost usadí do jasného čísla, další slovo trenéra zní o to zřetelněji. Je to práce, jež mění tušení ve fakt."},"ICON-2373":{"nm":"Skladovací pouzdro na stolní tenisové míčky","de":"Uložíte-li kulatý míček jemně do pouzdra, škrábance i prach od něj poodstoupí. S přáním, aby vydržel v pořádku až do dalšího zápasu, je to srdce, které mu věnuje celou malou místnůstku."},"ICON-2374":{"nm":"Věšák na výplet badmintonové rakety","de":"Pověsíte-li povolené struny úhledně, další ruka v pořadí nebude tápat. Uklízení je nakonec jako laskavý lísteček, který si předem píšete pro zítřejší sebe. Dnešek usnadňuje zítřek."},"ICON-2375":{"nm":"Ochranná páska hrany pálky na stolní tenis","de":"Okraj, na němž se guma nejsnáz nadzvedne, tiše obejmu jedinou linkou. Protože rozpadne-li se lem, naruší se i hra míčku. Chránit hranu se nakonec stává ochranou jediného bodu."},"ICON-2376":{"nm":"Sáček na ohřev squashového míčku","de":"Studený míček skoro vůbec neodskočí. Sáček, který jej před zápasem zahřeje a chová jako v teplé dlani. Onen drobný žár předaný do ruky předem určuje dech a rytmus celého kola."},"ICON-2377":{"nm":"Svorka na síťku lakrosové hlavy","de":"Když se očko sítě tiše chystá povolit, beze slova je zakousnu a přidržím. Síť musí být napjatá, aby v ní míč zůstal. Zde je ruka, jež z neviditelného místa drží pohromadě celou hru."},"ICON-2378":{"nm":"Ochranná páska na hlavu squashové rakety","de":"Čím prudčeji švihnete proti zdi, tím dřív se raketa rozpláče od špičky. Jemně obalíte tu plačící špičku a raketa s vámi odehraje ještě jednu sezónu. Ten, kdo umí špičku šetřit, nakonec drží raketu nejdéle."},"ICON-2379":{"nm":"Kryt čepele hokejky","de":"Nasadíte-li kryt na ostrou čepel, konečně se uklidní jak taška, tak vaše prsty. Tiše uspat něco nebezpečného, to je stará zdvořilost, kterou dodržíte hned na začátku, když balíte hokejku."},"ICON-2380":{"nm":"Leštící hadřík na kriketový míček","de":"Otřete-li červený míček hadříkem, jedna strana pojme světlo jako zrcadlo. Nadhazovač citem v konečcích prstů ví, že míč se zatáčí teprve tehdy, když lesk žije. I v pečlivém leštění se skrývá tichá strategie."},"ICON-2381":{"nm":"Víčko na tubu na lakrosové míčky","de":"Aby se tvrdé míčky nekutálely, kam je napadne, pevně ucpete ústí tuby. Konejšivě shromáždit na jedno místo věci náchylné k rozptýlení, základy provozu jsou vždy takto drobné."},"ICON-2382":{"nm":"Terčík na zeď squashového kurtu","de":"Jediný malý terčík zasazený do zdi soustředí kolísavý pohled hráče do jednoho bodu. Ten jediný bod, který určí, kam mířit, i tu širokou zeď před tímto útržkem zúží na jasný cíl."},"ICON-2383":{"nm":"Návlek na madlo hokejky","de":"Přenesete-li madlo, na něž je ruka zvyklá, na neznámou novou hokejku, nástroj se v tu chvíli stane vaším. Drobný návlek, jenž vám dovolí obléknout hokejku do vlastní důvěrnosti, je právě tou zkratkou k přivyknutí."},"ICON-2384":{"nm":"Zavěšovač sítě na branku","de":"Teprve když na branku pověsíte síť, gól se konečně stane gólem tak, jak má být. Vždy to byla síť, jež až do konce udržela ten krátký okamžik, kdy ji naplnil míč. Právě na místě, jež zachytí tvar propuklého jásotu, jsem já."},"ICON-2385":{"nm":"Kryt bruslařské čepele","de":"S obnaženou čepelí si člověk nemůže věřit ani na jediný krok mimo led. Jakmile opustíš led, prosím, nasaď mě na sebe. Tiše uspat ostrost je zdvořilost, kterou brusaři dodržují odedávna."},"ICON-2386":{"nm":"Věšák na tkaničky bruslí","de":"Dlouhé tkaničky sundaných bot pověsíte úhledně, šňůru po šňůře. Rozvázaná tak, aby se nezamotala, tkanička hladce otevře příští cestu na led. Dnešní zakončení se právě tak stává přípravou na zítřek."},"ICON-2387":{"nm":"Utěrka na bruslařské čepele","de":"Na čepeli, jež právě opustila led, se perličkami sráží drobné kapky. Jemně tu vlhkost otřete a rez se jí vyhne. Tiše sesbírat stopy, jež po sobě zanechal chlad, to je moje každodenní práce."},"ICON-2388":{"nm":"Kotníková vložka bruslařské boty","de":"Zakolísá-li kotník byť jen jednou, zhroutí se celá jízda. Vycpávka, jež ho pevně obejme a udrží stabilní stoj. Ona ladná rovnováha na ledě vždy začíná nejdřív na neviditelném místě."},"ICON-2389":{"nm":"Kapsa na chrániče bruslařských čepelí","de":"V koutě tašky je malá kapsa, do níž se pečlivě uloží chrániče čepelí. Zvyk balit vše potřebné a na nic nezapomenout udržuje výstroj naživu na dlouho dlouho. Uspořádaná taška je první scénou dobré jízdy."},"ICON-2390":{"nm":"Svorka na vložku bruslařské boty","de":"Aby se vložka uvnitř boty tiše nevysunula, pevně ji přidrží pod chodidlem. Sklouzne-li místo, na němž stojíte, sklouzne s ním i skok. Ruka, jež drží nejnižší místo, nakonec pomáhá k nejvyššímu vzletu."},"ICON-2391":{"nm":"Poutko krytu bruslařské čepele","de":"Aby kryt tiše nesklouzl, pevně jej zapnete poutkem. Vím, že volná ochrana nakonec žádnou ochranou není. Jedno dobře zapnuté poutko střeží tu čepel až do konce."},"ICON-2392":{"nm":"Utahovací sponka na tkaničky bruslí","de":"Přitáhnete-li tkaničky pevně a zajistíte je sponkou, už se nikdy samy nerozváží. Utáhnout vše zručně a bez skulinky od samé špičky, to je nejspolehlivější uzel, jejž zavážete, než vykročíte poprvé na led."},"ICON-2393":{"nm":"Osušovací hadřík na bruslařskou čepel","de":"Z čepele, jež právě dokončila jízdu, tiše sesbíráte usazenou vlhkost. Víte, že ponechá-li se mokrá, čepel pláče. Jen dosucha vytřená čepel jasně vykreslí na ledě další oblouk."},"ICON-2394":{"nm":"Krytka rukojeti lyžařské hole","de":"Jemně obalíte konec rukojeti hole a sevřená dlaň se hned o něco uvolní. Síla, jež brázdí sněhovou pláň, nakonec vychází právě z toho pevně sevřeného místa. Jediná malá krytka podepře celý dlouhý sjezd až do konce."},"ICON-2395":{"nm":"Kolík vázání snowboardu","de":"Ve chvíli, kdy vypadne drobný kolík spojující prkno s nohou, hora před vámi se zastaví. Kousek, jenž je sotva vidět, a přesto je třeba zkontrolovat jako první, právě toto pevné spojení se stává svobodou na sněhu."},"ICON-2396":{"nm":"Kleštičky na ochranu špičky lyžařské hrany","de":"Aby ostrá hrana neškrábala vnitřek tašky, jemně zakousnete špičku. Konejšivě uspat ostrost, to je vlídné zakončení, jež nabídnete po dobrém sjezdu z hory."},"ICON-2397":{"nm":"Chránič špičky snowboardu","de":"Obalíte-li špičku prkna, i čelní náraz se měkce rozptýlí. Mlčky střežit místo, jež narazí jako první, právě tady začíná odvaha čelit strmému sjezdu."},"ICON-2398":{"nm":"Kryt přezky lyžařské boty","de":"Aby se přezka neponičila nárazy o studený sníh, tiše ji zakryjete. Ještě jeden zámek, jenž střeží zamykací mechanismus – jediný tento drobný kryt nenápadně prodlouží botě jednu sezónu navíc."},"ICON-2399":{"nm":"Poutko pojistného řemínku snowboardu","de":"Aby prkno neuteklo daleko, i když vám vyklouzne z ruky, spojuji kotník s prknem jedinou šňůrou. Aby, i kdybyste je pustili, nakonec neztratili navždy, je to tiché poutko jistoty zavěšené na konci dlouhé šňůry."},"ICON-2400":{"nm":"Hrot škrabky na skluznici lyže","de":"Starý vosk ztuhlý na skluznici hladce seškrábete pryč. Jen důkladným odstraněním starého ožije nové klouzání. Pečlivě ošetřená skluznice otevře příští sněhovou pláň o to rychleji."},"ICON-2401":{"nm":"Nárazník špičky snowboardu","de":"Než deska rozpáře sníh, dotkne se světa jako první špička nosu. Každý náraz jako první přijme tenhle kousek gumy. Místo vpředu, které se obrušuje a nikdy se tím nechlubí – něčí sjezd klouže po této tiché, tvrdošíjné oddanosti."},"ICON-2402":{"nm":"Košík lyžařské hůlky","de":"Ve chvíli, kdy má hůl zapadnout hluboko do sněhu, tenhle kulatý kroužek za ni nahmatá zem. Obvod, který tiše podepře krok, jenž se málem zvrtl. Neviditelný, a přece stojí nablízku jako ruka, co nedovolí uklouznout."},"ICON-2403":{"nm":"Krytka kartáče na voskování hran","de":"Když je ošetření hotové, jemně přikryje štětiny, než prášek zaschne. Zapečetí dnešní hebkost, aby se ani jediné vlákno nerozcuchalo. Aby příště, až ji zase otevřeš, čekala dnešní péče přesně tak, jak jsi ji nechal."},"ICON-2404":{"nm":"Věšák na návleky na uši","de":"Pamatuješ? Návleky na uši, na chvíli zapomenuté vedle tašky, jakmile přišlo jaro. Přesto v noci, kdy se ozve zpráva o prvním sněhu, jsou zavolány jako první. Pro roční období existuje zvláštní místo k zavěšení a tenhle háček na ten slib nikdy nezapomíná."},"ICON-2405":{"nm":"Pouzdro na brousek","de":"Chceš-li nabrousit čepel, musíš nejdřív namočit kámen – posloupnost vžitá jako babiččin dotek. I nástroj, který krotí otupělost, potřebuje místo k odpočinku, a tak tenhle domeček chová brousek a čeká na další ošetření."},"ICON-2406":{"nm":"Váček na vosk","de":"Látka, z níž se rodí zářivý sjezd, sama uvnitř dřímá pevně stmelená. Tíha, jež v sobě chová ztvrdlý kus. Klouzavost se vždy uvolní právě z této tiché váhy a rozlije se po sněhové pláni."},"ICON-2407":{"nm":"Poutko na sáček ohřívače rukou","de":"Na zimní procházce je to místo, které prsty v kapse nahmatají jako první. Malému teplu, jež rozehřívá zmrzlé ruce, dává pevný domov. Čím chladnější den, tím laskavější je tohle malé poutko."},"ICON-2408":{"nm":"Podstavec brusného kamene na hrany","de":"Když se zachvěje, hrana se zkřiví, a tak se sám pevně upevní jako první. Podstavec, který se ani nehne, aby odpovídal za cizí přesnost. Něčí rovná hrana čepele stojí právě na téhle tiché neochvějnosti."},"ICON-2409":{"nm":"Klip na nákrčník","de":"Na cestě do školy za studeného větru se nákrčník sesune, a v tu chvíli – cvak – na límec. I teplo musí držet místo, teprve pak je opravdu teplem. Jediný tichý zvuk udrží ranní teplo na svém místě."},"ICON-2410":{"nm":"Kryt žehličky na voskování","de":"Zatímco rozžhavená plocha pomalu chladne, jediný kus látky ji tiše chrání před prachem. Jeden nástroj pečuje o druhý, který připravil sjezd. Péče takhle tiše pokračuje dál."},"ICON-2411":{"nm":"Víčko fixu na olej na hrany","de":"Jednou otevřeno a zaschlo by to, další čáru bys už nenatáhl. Zavřít proto znamená totéž co otevřít příště – toto malé víčko zapečetí vlhkost na hrotu a předem slíbí zítřejší tah."},"ICON-2412":{"nm":"Hlavička pompomu","de":"Stovky pramínků vycházejí z tohoto jediného bodu a v rytmu se jednohlasně rozlétnou. Nádhera vlnění vždy začíná na pevně uvázaném místě. Pod pódiem první uzel, který rozvlní celé hlediště."},"ICON-2413":{"nm":"Poutko na světelnou tyčku","de":"Po dvou hodinách jásotu, ve chvíli, kdy ti světelná tyčka málem vyklouzne z ruky, tenhle popruh ji vrátí zpátky do dlaně. Přání neztratit ji, i kdyby upadla. Ta něžná starostlivost utvořila na zápěstí smyčku."},"ICON-2414":{"nm":"Skládací spona sedáku na stadion","de":"Desítkrát vyskočit a zase si sednout během fandění. Mezitím tahle drobná sponka pečlivě složí sedák a uhlídá tvé místo. I v rozjásaném hledišti se skrývá dotek, který pamatuje na něčí místo k sezení."},"ICON-2415":{"nm":"Poutko na fanouškovskou bandanu","de":"V den, kdy se stejný vzor rozprostře po celém hledišti, jediný kus látky spojí desetitisíce srdcí do jedné barvy. Prvním bodem, kde ta vlna začíná, je tahle malá smyčka – místo, kde se osamocené fandění stává společným „my“."},"ICON-2416":{"nm":"Polovina tleskací pálky","de":"Zatleská-li se osamoceně, je to jen slabý zvuk; v hledišti se z toho stane vlna. Jedna polovina, jež nejpoctivěji zná pravdu, že zazní teprve tehdy, když se setká s druhou. Ve chvíli, kdy tvůj tlesk potká můj, fandění zesílí."},"ICON-2417":{"nm":"Krytka rohu fanouškovské cedule","de":"Obalí ostrý roh do kulata, aby se soused u tebe neporanil. I do vroucně mávající ruky se vejde ohled na druhé. Fandění je právě v téhle zaoblenosti o kus vřelejší."},"ICON-2418":{"nm":"Držák žerdi fanouškovské stuhy","de":"I ve chvíli, kdy vlání ustane, stojí žerď zpříma a čeká na další jásot. Místo, kde na okamžik tiše spočine, aby se mohla znovu rozvlnit. Mezi jedním jásotem a druhým krátké ticho, v němž stuha popadá dech."},"ICON-2419":{"nm":"Vějíř na zesílení hlasu","de":"Aby jediný výkřik doletěl až na konec pódia, vějířovitý tvar zúží dráhu zvuku. Ústa, jež místo velikosti srdce vždy přemýšlí, jak jej doručit. Tvar zrozený z touhy dosáhnout o kousek dál."},"ICON-2420":{"nm":"Pouzdro na zadní špendlík odznaku","de":"Před připnutím na hruď a po sundání – přesně tady odpočinek odznaku začíná a končí. Malý domeček, který bezpečně uloží ostrý zadní špendlík ke spánku. I zářivý bod potřebuje místo, kde si na chvíli lehne a odpočine."},"ICON-2421":{"nm":"Číselná destička na ukazatel skóre","de":"Nese v sobě péči doby, kdy se po každém gólu ručně vyměňovala. Před digitální érou se výsledek vyrýval po jedné číslici lidskými prsty. Destička, v níž i jediné číslo neslo něčí vzrušení."},"ICON-2422":{"nm":"Magnetka na taktickou tabuli","de":"Podle pokynů trenérova prstu si obrana a útok vymění místa. Každý obraz, který se před zápasem zrodí v hlavě, se nejdřív nakreslí přesouváním těchto drobných puntíků. Výsledek se jednou předem odehraje na tabuli."},"ICON-2423":{"nm":"Stínítko proti záři ukazatele skóre","de":"Aby oslnivá čísla nerozostřila hráčův pohled, stínítko odřízne světlo. I jas musí být občas přiměřeně zastíněn, aby splnil svou úlohu. Na nejjasnějším místě pracuje nejtišší stín."},"ICON-2424":{"nm":"Kroužek na listování skóre","de":"S každým obráceným listem se změní číslo a jásot stoupá za ním. Stopa analogové éry, kdy se výsledek obnovoval doteky ruky. Doba, kdy se se zvukem obraceného skóre obracelo i srdce."},"ICON-2425":{"nm":"Pouzdro na fix na kreslení tras","de":"Každá trasa nakreslená na tabuli v šatně pochází z tohoto fixu. Malá, pevná schránka, jež chová náčrt zápasu. V tichu před rozhodujícím střetnutím místo, které v sobě nese nejvíc slov."},"ICON-2426":{"nm":"Cvakací počítadlo skóre","de":"S každým stiskem přibude jedna čárka, s jasným cvaknutím stoupá počet. Necháš-li čísla na prstech, srdce se může celé obrátit k zápasu. Malý rytmus, jenž snímá tíhu počítání."},"ICON-2427":{"nm":"Kryt kabelů ukazatele skóre","de":"Za oslnivým světlem se vždy skrývá spleť neuspořádaných kabelů. Práce, jež ten nepořádek úhledně zakryje. Teprve když je neviditelné místo v pořádku, může viditelné místo konečně zářit."},"ICON-2428":{"nm":"Stíradlo taktické tabule","de":"Když jedno kolo skončí, plocha se pro další obraz čistě vyprázdní. Nová strategie může vždy vzniknout jen na prázdném místě. Stíradlo je ve skutečnosti prvním tahem příští taktiky."},"ICON-2429":{"nm":"Sponka na skórovací praporek","de":"Pevně sevře praporek, který se chce ve větru utrhnout, a nepustí. Aby vlající látka udržela své místo. I ohlásit výsledek světu potřebuje nejdřív spolehlivou ruku, jež ho pevně přidrží."},"ICON-2430":{"nm":"Sponka na šňůrku píšťalky rozhodčího","de":"Na jediné hvízdnutí se hra zastaví a zase rozproudí. Malý uzel, jenž tuhle autoritu pevně přiváže na krk. Než píšťalka zazní, i uspořádat ticho patří k úkolu téhle sponky."},"ICON-2431":{"nm":"Naviják svinovacího metru","de":"Vytaženou a naměřenou délku zase stáhne zpátky do sebe. Měření je nakonec jen opakované rozvíjení a svíjení. Rukojeť, jež té prosté cestě tam a zpět beze slova pomáhá a otáčí se pokaždé v pozadí přesnosti."},"ICON-2432":{"nm":"Pouzdro na skládací rozhodčí praporek","de":"Praporek, jenž rozhodně dělil vnitřek od vnějšku, se po skončení zápasu úhledně složí a odpočine. I ten jasný signál si na chvíli oddechne pro příště. I za rozhodností se skrývá tichý odpočinek."},"ICON-2433":{"nm":"Poutko na zavěšení stopek","de":"Plynoucí čas zavěsí na jedno místo místo na zápěstí. Nehybný před měřením, a hned jak zazní povel, vyrazí – zastávka pro čas. Malý domov vteřin, jenž zadržuje dech a čeká na startovní signál."},"ICON-2434":{"nm":"Kolečko na značení čar hřiště","de":"Kudy projede, tam zůstane zřetelná bílá stopa. Hranice pravidel se takhle vyrývají do země, otočku po otočce, úhledně. Než zápas začne, kolečko, jež jako první zanechá na hřišti otisk."},"ICON-2435":{"nm":"Kapsička na karty rozhodčího","de":"V okamžiku rozhodnutí tu dřímá karta, kterou vytáhne z náprsní kapsy. Čekárna verdiktu, jenž mlčí až do poslední chvíle, než se ukáže. Kapsička, vždy připravená a čekající, v naději, že nikdy nebude potřeba."},"ICON-2436":{"nm":"Podložka pod závaží váhy","de":"Vážení je poctivé jen na neochvějné ploše. Podložka, jež nese závaží a přitom nabízí vlastní tělo naplocho. První krok přesného měření vždy začíná na tichém místě."},"ICON-2437":{"nm":"Startovní cvakátko","de":"Na jediný zvuk se všechny nohy naráz odrazí od země. Start je sice sotva okamžik, ale ruka, jež ten okamžik tvoří, je klidnější než kdokoli jiný. Ruka, jež jediným cvaknutím uvolní chvění startovní čáry."},"ICON-2438":{"nm":"Základna hřištního kužele","de":"Jméno zní neznámě, práci má ale jasnou – tíživě podpírá střed hřiště jako pódium. Uprostřed, kde všichni září, vždy tiše vydrží jedna neviditelná noha."},"ICON-2439":{"nm":"Přezka pásu na brániční dýchání","de":"Že dobrý zvuk nepřichází z hrdla, ale z hlubokého dechu, ví jako první pas. Přezka, jež nechá dlaň ucítit, jak se břicho zvedá a klesá. Počátek písně vždy leží pod tímto jedním nádechem."},"ICON-2440":{"nm":"Deska s pírkem na cvičení dechu","de":"Když se pírko lehce zachvěje dechem, je to znamení, že dýchání je pravidelné. Neviditelnému dechu jemně propůjčí tvar a učí základ zpěvu. Cvičení, jež se dech před prvním tónem učí očima."},"ICON-2441":{"nm":"Přesýpací hodiny na nádech","de":"Uvnitř skla stéká písek jako dech. Nadechni se, na chvíli se zastav, pomalu vydechni – zrnka za tebe počítají rytmus. Chvíli sleduj tiše padající písek a nepozorovaně se tvůj rozházený dech srovná."},"ICON-2442":{"nm":"Stojánek na cvičení se svíčkou","de":"Zapal knot a hlas se rozechvěje spolu s plamínkem, který se chvěje. Místo, jež někdo pečlivě vyřezal, aby na chvíli podepřelo to nepatrné chvění. V tloušťce ztuhlého vosku, jenž se tu navrstvil, jsou uloženy noci strávené osamělým zpěvem."},"ICON-2443":{"nm":"Popruh polštářku na tlak na břicho","de":"Místo aby ruka spočinula na břiše, tiše to místo přitiskne jediný popruh. Když dech naplní břicho, napne se; když se úplně vyprázdní, tiše povolí. Mlčenlivý malý společník po boku, jenž pomáhá tělu zapamatovat si rytmus jako první."},"ICON-2444":{"nm":"Krytka na balonek pro vytrvalý výdech","de":"Nefoukej balonek najednou celý. Zkus to dlouze, pomalu, až do konce. Zatímco skusuješ krytku a vypouštíš vzduch, dosáhne až do nejhlubšího místa plic. Píseň nakonec doletí právě tak daleko, jak dlouho jsi dokázal zadržet dech."},"ICON-2445":{"nm":"Držadlo na uklidnění dechu","de":"Čím víc se srdce chvěje, tím víc chce ruka něco pevně sevřít. Chytíš toto držadlo a ramena se sama povolí, nádech se prodlouží o kousek dál. Že učit se svírat znamená učit se skládat sama sebe, ví dlaň jako první."},"ICON-2446":{"nm":"Poutko na vibrační pás na břicho","de":"Zavěsíš pás na poutko a jemné chvění se rozlije do středu břicha. Přesně tam, kde se chvěješ, když se od srdce zasměješ, se tiše soustředí síla. Pevný střed vždycky takhle pomalu roste, na místě, které nikdo nevidí."},"ICON-2447":{"nm":"Číselník na počítání nádechů","de":"Raz, dva, tři – s každým cvaknutím ciferníku o dílek dál se vyryje hloubka nadechnutého dechu. Přibude jeden dílek a píseň vydrží o frázi déle. Na tomto malém ciferníku se tiše zapisuje plicní kapacita, kterou jsi dnes vypěstoval."},"ICON-2448":{"nm":"Lžičková destička na cvičení jazyka","de":"Místa, kam má dosednout špička jazyka, jsou na destičce zřetelně vyznačena. Jak se stočit, odrazit a na chvíli zastavit. Za plynule znějící výslovností se skrývá bezpočet svítání, kdy si jazyk takhle zapamatoval svou cestu."},"ICON-2449":{"nm":"Sponka na tvar úst k zrcadlu","de":"Sponka jemně přidrží tvar úst odražený v zrcadle. „Á“ kulaté, „í“ roztažené do stran. Tichá lekce jen mezi tebou a zrcadlem, jež zdokonaluje tvar zvuku, zatímco stojíš tváří v tvář vlastní tváři."},"ICON-2450":{"nm":"Korkový tuleň na výslovnost","de":"Malý tuleň vyřezaný z korku sedí v koutě stolu a poslouchá výslovnost. V noci, kdy „r“ pořád klouže a nálada klesá, kulaté oči tuleně tiše říkají: To nic, zkus to ještě jednou."},"ICON-2451":{"nm":"Špendlík na značení dechu v textu","de":"Kde se v textu nadechnout – to ti prozradí nejdřív tenhle špendlík. Zapíchni ho na konec řádku a to místo se stane laskavou pauzou písně. Chceš-li zpívat volně, i věta potřebuje jednu mezeru na nádech."},"ICON-2452":{"nm":"Opěrka brady na cvičení dikce","de":"I lehké podepření brady stačí, aby se rozptylující se výslovnost vrátila na místo. Zřetelná řeč není práce jen úst, ale společné dílo brady, hrdla a dechu. Tahle malá opěrka tiše pomáhá udržet tu vrtkavou rovnováhu."},"ICON-2453":{"nm":"Stojan tvarů úst pro samohlásky","de":"A, e, i, o, u – rám, jenž věrně zachycuje dráhy, kterými pět samohlásek opouští ústa. Postav ho tiše vedle zrcadla a den co den si tvaruj kostru zvuku. Kostra každé písně nakonec vychází z těchto pěti samohlásek."},"ICON-2454":{"nm":"Kartička s jazykolamem","de":"Jedna kartička, u níž se při čtení jazyk zamotá a nakonec propukne smích. Klidně se splete, opravdu to nevadí – chybovat je přece samotné cvičení. Pokaždé, když tuhle rošťáckou větu zdoláš, se probudí jedna hláska čistě a zřetelně."},"ICON-2455":{"nm":"Zátka na rozcvičení rtů","de":"Rozehřátí, jež zachvěním rtů probudí ztuhlé ústa. Skousni zátku a dlouze vypouštěj vzduch, a spící rty se hebce uvolní. Nejmenší a nejlaskavější rozcvička, jak jemně otevřít první frázi."},"ICON-2456":{"nm":"Gumička na úsek textu","de":"Kolem úseku, kde to pořád vázne, si omotáš gumičku na značku. Kdykoli to místo na zápěstí uvidíš, vybaví se ti hora, kterou dnes musíš zdolat. Čím těžší takt, tím častěji na něj pohlédneš a tím déle si ho neseš v srdci."},"ICON-2457":{"nm":"Poutko na hřejivou šálu na krk","de":"Aby ti v ranním vzduchu přechodného období nechraptěl hlas, pověsíš šálu pevně na poutko. Teprve z hřejivě zabaleného hrdla se uvolní čistý zvuk. Ochrana hlasu vždy začíná tím, že si nejdřív opatruješ hrdlo."},"ICON-2458":{"nm":"Hlavice vibračního válečku na hlasivky","de":"Když hlavice válečku pomalu projede po boku krku, hlasivky, jež celou noc spaly, se tiše probudí. Lehké chvění uvolní ztuhlé napětí a váhavý první tón zjemní. Dotek, jenž zahřeje tělo ještě dřív, než se začne zpívat."},"ICON-2459":{"nm":"Podtácek na hřejivý hrnek k pobrukování","de":"Se sevřenými rty si pobrukuješ a oběma rukama objímáš hrnek, z něhož stoupá pára, a s ním se hřeje i hrdlo. Tiché pobrukování se v kruzích rozlévá po podtácku. Píseň takhle začíná od jediného doušku vlažného tepla."},"ICON-2460":{"nm":"Pouzdro na bonbony na krk","de":"Pro dny, kdy hrdlo drásavě sedá, se v pouzdru tiše shromažďují bonbony. Vlož si jeden do úst těsně před vstupem na pódium a osvěžující máta prodýchá stažené hrdlo. Kousek útěchy pro nouzové chvíle, uložený ve vlastní malé krabičce."},"ICON-2461":{"nm":"Parní obklad na krk","de":"Omotej si kolem krku váček prosycený teplou párou a místa, jež ztuhla dlouhým cvičením, se něžně rozpustí. S útulností čerstvě ohřátého ručníku tiše podává unaveným, sklíčeným hlasivkám chvíli odpočinku."},"ICON-2462":{"nm":"Přesýpací hodiny na odpočinek hlasivek","de":"Slib dnes nemluvit, tiše učiněný, jemná zrnka odpočítávají potichu za tebe. Na chvíli zavřít ústa a šetřit hlas. Ten tichý čas, jenž je zároveň tou nejlepší péčí, tu plyne pomalu."},"ICON-2463":{"nm":"Zátka na rozezpívání vibrací rtů","de":"Vibrace rtů, jež lehce chvěje ústa, zatímco stoupá a klesá po tónech. Lehce skousni zátku a rozháraná chvění se ustálí do rovnoměrného rytmu. Malý nástroj velikosti dlaně, jenž hebce zapne první knoflík hlasového projevu."},"ICON-2464":{"nm":"Rozprašovací krytka na zvlhčení krku","de":"Aby na vysušeném pódiu hrdlo nevyschlo, stiskneš krytku a rozprášíš jemnou mlžinu. Zhluboka nadechneš zvlhčený vzduch a vyprahlý hlas znovu nabere čistý lesk."},"ICON-2465":{"nm":"Vibrační míček na uvolnění hlasu","de":"Podržíš v dlani jemně chvějící se míček a to chvění se hebce vyšplhá po paži až ke krku. Kulatý, laskavý společník na rozcvičku, jenž jemně rozechvěje a probudí hlasové orgány ztuhlé napětím."},"ICON-2466":{"nm":"Značka pozice pro formaci","de":"Jedna malá značka zapíchnutá do jevištní podlahy. Tady je tvé místo, támhle je moje. Když se mnoho lidí sejde a kreslí společně jeden obraz, tiše každého přidrží na místě – neviditelný slib, že se nikdo nerozprchne."},"ICON-2467":{"nm":"Šipkový čip na trasu pohybu","de":"Čip ve tvaru šipky zřetelně ukazuje směr dalšího kroku. Kde se otočit, kde zastavit – podlaha to prozradí jako první, abys neztratil cestu. Trasa je mapa, kterou si špičky nohou zapamatovaly nesčetným šlapáním."},"ICON-2468":{"nm":"Špendlík středu formace","de":"Jediný bod, jenž se tiše stane měřítkem, když se sejde mnoho lidí. Kolem tohoto špendlíku se kulatě vykreslí kruh a formace se doširoka rozevře. I roztroušený pohyb najde svůj řád, stačí jediný středový bod."},"ICON-2469":{"nm":"Klín na křižovatku tras","de":"Tam, kde se dvě rozdvojené cesty setkávají na jednom místě, se pevně zarazí klín. Aby se navzájem nesrazily, aby se nezkřížily a nesplietly. I v tom zadýchaném, prchavém okamžiku míjení nikdo neztratí cestu."},"ICON-2470":{"nm":"Vlaječka směru odchodu","de":"Když dozní ozvěna posledního tónu, tiše se vytratíš směrem, kam ukazuje vlaječka. Odchod nesmí být rozháranější než příchod. I zakončení na pódiu má směr, dohodnutý předem."},"ICON-2471":{"nm":"Sponka svinovacího metru na rozestupy","de":"Sevři konec svinovacího metru pevně sponkou a jedna píď za druhou vyjde vždy neomylně přesně. Dokonce i rozestup mezi lidmi se srovná úhledně, jako by ho měřilo pravítko. Pěkný obraz se vždy rodí z takhle pečlivých prstů."},"ICON-2472":{"nm":"Poutko na vodicí šňůru pro zarovnání","de":"Zavěsíš šňůru na poutko a napneš ji do jedné linie, a ta tenoučká čára se stane měřítkem, podle něhož se všichni srovnají do řady. Že řada vypadá tak úhledně, je zásluhou právě téhle jediné rovné, neviditelné přímky."},"ICON-2473":{"nm":"Tečkovaný dílek trasy pohybu","de":"Dílky, jež tiše nakreslí cestu na podlaze tečkovanou čárou. Jdeš-li podél těchto slabých stop, neztratíš se ani ve tmě. Zatímco se tečka po tečce spojuje, roztříštěné kroky splynou v jediný proud."},"ICON-2474":{"nm":"Podlahový cvoček na pozici","de":"Cvoček zaražený do podlahy, aby ses nezapomněl na své místo. I v naprosté tmě špičky nohou tu drobnou bouli nahmatají a bezpečně najdou. Teprve když se zastavíš přesně v tom jediném bodě, se konečně nad hlavou rozlije světlo reflektoru."},"ICON-2475":{"nm":"Pás na oddělený pohyb krku","de":"Když se brada pohupuje spolu, i hlas se roztřese a rozhází. Aby ses naučil hýbat jen krkem, zatímco hlava zůstává v klidu, omotáš si pás. Za pohybem, jenž vypadal tak nekonečně volně, se skrývá právě tohle tiché cvičení oddělenosti."},"ICON-2476":{"nm":"Sponka fixačního polštářku na rameno","de":"Aby se ramena sama od sebe nešklebila nahoru, sponka tiše přidrží polštářek na místě. Aby tělo jasně rozeznalo, kde se má vlnit a kde zůstat v klidu. Ukázněná linie se vždy rodí z takhle drobného upevňování."},"ICON-2477":{"nm":"Přezka pásu na vnímání žeber","de":"Pás tiše čte jemný vzorec toho, jak se žebra rozevírají a znovu stahují. Zapneš přezku a pohyb dechu se zřetelně přenese až ke špičkám prstů. Hluboký, pevný hlasový projev vychází právě z tohoto neviditelného pohybu kostí."},"ICON-2478":{"nm":"Kyvadlo na houpání boků","de":"Závaží se pomalu houpe ze strany na stranu a tiše prozrazuje rytmus, který kreslí boky. Jak střed těla přenáší váhu, beze slov učí malá závaží velikosti dlaně. Že i houpání má svůj vlastní směr vlákna."},"ICON-2479":{"nm":"Poutko na rotaci zápěstí","de":"Zavěsíš poutko na zápěstí a pomalu otáčíš dovnitř, pak ven, a kloub, ztuhlý celou noc, se hebce uvolní. Aby pohyb dosáhl živě až ke špičkám prstů, musí být zápěstí nejdřív ohebné. Tahle drobná rotace otevírá dveře většímu výrazu."},"ICON-2480":{"nm":"Šňůra s kroužkem na odpor kotníku","de":"Nasadíš kroužek na kotník, přitáhneš šňůru a s každým krokem, který uděláš, se u špiček nohou zachytí jemný odpor. Čím těžší krok, tím tišeji do nohou přibývá síla. Pírkově lehký skok vždy stojí právě na takhle těžkém cvičení."},"ICON-2481":{"nm":"Pytlík s pískem na střed těla","de":"Teprve když si ho omotáš kolem břicha, zjistíš, kde vlastně byl střed tvého těla. Zatímco tíha táhne ramena dolů, vratký střed pomalu najde své místo, a na místě, kde se sundá, zůstane jediné – vzpřímené držení těla."},"ICON-2482":{"nm":"Krytka tyče na zarovnání páteře","de":"Když se malá krytka dotkne zad, jež celý den žila skloněná, je to, jako by ti někdo potají narovnal ramena. Ohnutě se dá žít taky, ale stát vzpřímeně je laskavá dovednost, kterou se musíš pomalu učit znovu."},"ICON-2483":{"nm":"Masážní kulička na uvolnění svalů","de":"Zatlačíš na ztuhlé místo a nejdřív to zabolí, pak se hned uleví. Jako teplo babiččina hřbetu ruky, jenž ti kdysi v dětství mnul záda, uvolnit znamená ještě chvíli víc bolet a přitom zůstat nablízku."},"ICON-2484":{"nm":"Šroub na nastavení úhlu zrcadla","de":"Stačí pootočit jen o dlaň a zrcadlo odráží úplně jinou tvář. Jedna otočka šroubem a svět se nakloní a zase narovná – zdá se, že i postavit se sám sobě tváří v tvář vyžaduje tiché zaměření."},"ICON-2485":{"nm":"Utěrka na zamlžené zrcadlo","de":"Před zrcadlem zamlženým horkou párou člověk na chvíli ztratí vlastní tvář. Jeden tah a tvář se vrátí. Díky tomuto doteku, jenž stírá mlhu, se každé ráno znovu setkávám sám se sebou."},"ICON-2486":{"nm":"Gumička na nožku stativu","de":"Na špičce nohy stativu rozhoduje o osudu záběru jeden kousek gumy velikosti nehtu. Jeho stisk, jenž se pevně zakusuje do podlahy, utiší chvění, a tak neochvějný obraz vždy tiše začíná neviditelným třením."},"ICON-2487":{"nm":"Fólie s mřížkou pro odhad úhlu","de":"Jemné mřížkové linky na fólii jsou jako pomocná kolečka pro oči. Čím víc si kompozice sedá do ruky, tím tišeji linky mizí a zůstává jen cit. Stopy učení se, čím víc dozrávají, tím víc mizí z dohledu."},"ICON-2488":{"nm":"Nožní pedál na spuštění nahrávání","de":"Pro člověka, jenž má obě ruce plné věcí, byl posledním prstem vždycky prst u nohy. Lehce ťukneš a nahrávání začne – zákulisní starost zvládá svůj díl obratně, dokonce až po špičku nohy."},"ICON-2489":{"nm":"Klip na směr osvětlení","de":"Kam dopadne světlo, závisí na prstech tohoto klipu velikosti nehtu. Práce posunout stín o píď a zvýraznit obrys – kvůli tomu nepatrnému rozdílu se někdo dlouho a soustředěně rozmýšlí."},"ICON-2490":{"nm":"Zástěna na porovnání záznamů","de":"Postav včerejšek a dnešek vedle sebe a teprve tehdy promluví změna. Ve chvíli, kdy se zástěna pomalu sveze dolů, se na obrazovce poctivě odhalí vzdálenost času, jenž mezitím uplynul."},"ICON-2491":{"nm":"Poutko na zápěstí k dálkovému ovladači","de":"Omotáš kolem zápěstí jednu šňůrku a obava z upuštění povolí. Malé bezpečnostní opatření naopak ruku osvobodí – laskavý paradox, kdy svázanost uklidní mysl."},"ICON-2492":{"nm":"Krytka objektivu","de":"Zatímco kamera odpočívá, i objektiv tiše zavře oči. Ve světě, kde jediné smítko prachu zanechá na obraze jizvu, znamená jemné zakrytí touhu opatrovat ho co nejdéle."},"ICON-2493":{"nm":"Páska na nadzdvižení koutků úst","de":"Nadzvedneš koutky úst jen trochu a ztuhlý výraz se pomalu uvolní. Úsměv je nakonec taky sval – zprvu si vypůjčíš sílu nástroje, a jednoho rána se rozzáříš úsměvem docela sám."},"ICON-2494":{"nm":"Masážní váleček na svaly tváří","de":"Pomalu rozválíš vnitřek tváře a slova plynou o poznání hladčeji. Tiché rozehřátí, jež jemně probudí tvář ještě před zpěvem. Zahřeješ-li i výraz, stane se ještě vřelejším."},"ICON-2495":{"nm":"Měřítko úhlu úsměvu","de":"Kamera ví, že i úsměv má svůj správný úhel. Měříš gauge sem a tam, až nakonec pochopíš, že nejkrásnější úsměv rozkvétá z upřímnosti, kterou vůbec nelze změřit."},"ICON-2496":{"nm":"Sponka na pohyb obočí","de":"Pohne-li se obočí byť jen o milimetr, celý vnitřní tón se změní. Sponka, jež tiše přidrží nejmenší součástku výrazu – herectví je práce prstů, které krotí právě takovou drobnost."},"ICON-2497":{"nm":"Nálepka na nadzdvižení lícních kostí","de":"Nadzvedneš lícní kost a přilepíš, a na tváři vznikne místo, kde se zdrží světlo. Prostorovost, kterou vytvoří jedna nálepka velikosti nehtu – v jevištním líčení se takhle skrývá neviditelné tajemství."},"ICON-2498":{"nm":"Páska přes oko na nácvik mrknutí","de":"Zakryješ jedno oko a srdce se celé soustředí do toho, jež zůstalo. Nacvičovat mrknutí znamená nakonec naučit se ladně skrýt polovinu. Jsou výrazy, které se právě tím zakrytím vyjasní."},"ICON-2499":{"nm":"Sponka šablony tvaru úst","de":"Ga, gja, gŏ… přiložíš tvar úst k šabloně a rozmazaná výslovnost se vyjasní. Že každá samohláska je vlastně postoj tváře, si pomalu vrýváš do těla před zrcadlem."},"ICON-2500":{"nm":"Zahřívací váček na rozcvičení výrazu","de":"Těsně před vstupem na pódium hřejivý váček jemně zahřeje tvář. Jako ztuhnou zkřehlé ruce při hře, ztuhne i výraz. Malá pravda ze zákulisí: i úsměv potřebuje předehřátí."},"ICON-2501":{"nm":"Pásek na vyhlazení čela","de":"Když si čelo obtočíte páskem, hluboko vryté vrásky se tiše vyhladí. Předmět, který na chvíli nechá odpočinout vrásky vyryté starostmi. Pod vyhlazeným čelem člověk vypadá o něco mladší."},"ICON-2502":{"nm":"Náprstek na listování scénářem","de":"Malý náprstek, který si nasadíte na konec prstu při listování stránkami. Rytmus otáčení tlustého scénáře list po listu se nenápadně stává rytmem příběhu. I ve čtení dřímá něžný zvyk ruky."},"ICON-2503":{"nm":"Vlaječka na vybarvení pocitů","de":"Radost je žlutá, smutek modrý. Když obarvíte své srdce a vztyčíte vlaječku, neviditelný cit nabere tvar a zavlaje ve větru. I pocity lze takto nakreslit vlastní rukou."},"ICON-2504":{"nm":"Svorka na důraz v replice","de":"„Polož důraz na tohle slovo,“ tiše napovídá svorka. I stejná replika změní celý smysl jediným přízvukem, a tak je to malá značka, která drží těžiště řeči."},"ICON-2505":{"nm":"Kostka pro čtenářskou pauzu","de":"Kostka položená se vzkazem: „tady si na chvíli odpočiň.“ Čárka v replice není zastavením, ale nádechem pro další slova. Ten, kdo si umí dobře odpočinout, nakonec i dobře mluví."},"ICON-2506":{"nm":"Páska se sponou na značení dechu","de":"Páska podél spony stoupá a klesá a kreslí před očima délku nádechu. Sledovat a napodobovat rytmus vdechu a výdechu — úvod písně vždy začíná zvládnutím dechu."},"ICON-2507":{"nm":"Váček s kostkou pocitů","de":"Z váčku se vykutálí kostka a rozhodne o dnešním pocitu. Padne-li radost, zkus být radostný, padne-li hněv, zkus se rozzlobit. Herecký nácvik se stává hrou, kdy srdce svěříte náhodě."},"ICON-2508":{"nm":"Šikmý stojan na scénář","de":"Položíte-li scénář na nakloněný stojan, nemusíte sklánět hlavu. Tento malý sklon, který udržuje váš pohled ve výšce očí, tiše pečuje o šíji ztuhlou z dlouhého nácviku."},"ICON-2509":{"nm":"Zástěna pro šepot","de":"Značka, že odtud se má šeptat. Ztlumíte-li hlas za zástěnou, hlediště naopak zatají dech a nakloní se blíž, aby naslouchalo. Je to něžný paradox jeviště: čím tišeji mluvíte, tím dál to doletí."},"ICON-2510":{"nm":"Krabička žetonů na výměnu rolí","de":"Stačí žeton lehce otočit a role se změní. Dnes hlavní hrdina, zítra přítel po boku. Na ostrově, kde všichni rostou společně, přijde jednou na řadu každý, kdo si stoupne doprostřed jeviště."},"ICON-2511":{"nm":"Nálepka bodu pro upřený pohled","de":"Klidně spočiňte očima na malé tečce vedle kamery. V okamžiku, kdy se těkavý pohled ustálí na jednom místě, oči na obrazovce znovu ožijí jasným leskem. Upřený pohled nakonec začíná tím, že se zastavíte."},"ICON-2512":{"nm":"Trojúhelníkové pravítko na odhad úhlu","de":"Když se roh obrazu zdá kdovíproč nakřivo, stačí přiložit trojúhelníkové pravítko a odpověď se ukáže. Práce narovnávání toho, co je křivé. Než uvěříte vlastním očím, na chvíli zkuste věřit pravítku."},"ICON-2513":{"nm":"Podstavec na výšku objektivu","de":"Nastavíte-li objektiv do výšky lidských očí, obraz méně lže. Ne shora, ne zdola — teprve když se díváte stejnýma očima, zachytí se nenalíčený, opravdový výraz."},"ICON-2514":{"nm":"Křidélko šipky vedoucí pohled","de":"Pohled se pomalu sune tam, kam ukazuje křidélko. Malá šipka, která nenápadně vede oči diváka. Dobrý záběr laskavě naznačuje, kam se má člověk dívat."},"ICON-2515":{"nm":"Podlahový čip pohybové trasy","de":"Stačí došlápnout na bod trasy, kterou znáte nazpaměť do omrzení, a další místo máte hned na dosah. Kroky křižující jeviště jsou neviditelnou cestou spletenou z takových drobných značek vtisknutých do podlahy."},"ICON-2516":{"nm":"Pásmo na vzdálenost kamery","de":"Páskou se odměří vzdálenost mezi objektem a kamerou. Ve světě, kde jedna píď rozhoduje mezi blízkým a vzdáleným, se z pásma stává tichý strážce hlídající hranici mezi rozostřením a ostrostí."},"ICON-2517":{"nm":"Vodítko na náklon hlavy","de":"O kolik naklonit hlavu, aby to vypadalo nejněžněji? Sledujte vodítko a nenápadně pochopíte — úhel náklonu se nakonec velmi podobá tomu, nakolik otevřete své srdce."},"ICON-2518":{"nm":"Svorka se zrcátkem na oční kontakt","de":"Připevníte-li svorkou zrcátko vedle kamery, díváte se do vlastních očí, a přitom se setkáváte s tvýma. Drobný nástroj, který nenápadně staví most pohledu mezi mnou v zrcadle a tebou na obrazovce."},"ICON-2519":{"nm":"Signální světlo natáčení","de":"Rozsvítí-li se světlo, je to signál, že se právě natáčí. Jedna malá lampička soustředí napětí rozjívleného place do jednoho bodu. Od okamžiku, kdy se rozsvítí, se dech všech srovná do jednoho rytmu."},"ICON-2520":{"nm":"Tlačítko se zvonečkem na reakci","de":"Stiskněte tlačítko a rozezní se čistý, jasný zvonek. Jako potlesk, který se rozpoutá po dobré scéně, i v tomto malém zvonku je uschováno něčí vřelé slůvko „výborně.“"},"ICON-2521":{"nm":"Tuba na rychlé losování","de":"Zatřeste s ní a dřevěné tyčinky zaklapou, jako první rozproudí náladu. Kdo otevře scénu, se rozhodne jediným pohybem zápěstí — vylosovaný se rozpačitě usměje, ostatní si oddychnou. I dělení štěstí má svá laskavá pravidla."},"ICON-2522":{"nm":"Rolnička na zvukový efekt","de":"Lehce máchnete zápěstím a cinknutím se ozve dovtipná vsuvka. Tato drobná rolnička jako první vyplní mezeru, než ticho stihne ztrapně zhoustnout. V počítání rytmu smíchu je tahle vždycky o krok napřed."},"ICON-2523":{"nm":"Víko krabice s překvapením","de":"Dokud se neotevře, nikdo netuší, co je uvnitř. To je jediný úkol, který toto víčko plní. Aby v okamžiku pootevření vytryskl výkřik i smích zároveň, zavěšuje na jediný pant celé vzrušené očekávání."},"ICON-2524":{"nm":"Skládací vějíř na reakce","de":"Praskavý zvuk rozevření se sám stává odpovědí. Žebra vějíře odvějí obdiv, který se nestihl vyslovit slovy. Mezi gesty skládání a rozevírání proudí nadšení sem a tam a s vánkem se zachvěje i kousek srdce."},"ICON-2525":{"nm":"Ruleta na trestný úkol","de":"Nikdo předem netuší, na kterém políčku se jehla zastaví. Čím pomaleji se kolo točí, tím rychleji naopak buší srdce — cvak, a na místě, kde se zastaví, je zapsán dnešní legrační osud. Pár vteřin, kdy je zábavné i to chvění."},"ICON-2526":{"nm":"Tabulka s bublinou úžasu","de":"Zvednete-li ji vysoko nad hlavu, „wow“ se vznese jako písmena. Jediný list papíru předběhne srdce a vykřikne to, co ústa nestihla. Protože i reakce potřebuje trochu jevištní režie."},"ICON-2527":{"nm":"Ruční vlaječka na zastavení","de":"V okamžiku, kdy se vlaječka zvedne, všichni strnou přesně tam, kde stojí. Signál, který uzamkne do nehybného obrazu i zvuk dechu. Když znovu klesne, zamrzlý smích se naráz vyvalí ven."},"ICON-2528":{"nm":"Kbelík na svorky s bláznivými odpověďmi","de":"Čím potrhlejší odpověď, tím pevněji ji sepnou a zavěsí. Když se nesprávné odpovědi rozvěšené na šňůře houpou ve větru, stává se z toho jeviště, kde jsou omyly milovány víc než správné odpovědi. Obrázek dne, kdy je v pořádku se splést."},"ICON-2529":{"nm":"Klín na opravu držení zad","de":"V okamžiku, kdy se opřete zády, prohnutá páteř si nenápadně nahmatá vlastní cestu. Jeden malý klín, který podpírá beze slova. Správné držení těla, tiše napovídá zezadu, je pohodlné teprve tehdy, když ho někdo podepře."},"ICON-2530":{"nm":"Podložka na vyrovnání pánve","de":"Drobná pevnost podložená pod chodidla, když se zakolísá těžiště. Rovnováha těla se nakonec pomalu zvedá od podlahy. Bezejmenný vedlejší herec, který podpírá držení těla z místa, které nikdo nevidí."},"ICON-2531":{"nm":"Balanční míč na stažení břicha","de":"Vložíte-li ho na břicho a jemně stáhnete, rozptýlené těžiště se sesbírá do jednoho bodu. Čím hlouběji ustálíte dech, tím pevnější míč je, a tělo si po jednom nádechu znovu nachází osu, na kterou zapomnělo."},"ICON-2532":{"nm":"Pravítko na kontrolu křivky páteře","de":"Přiložíte-li pravítko podél zad, neviditelná křivka se ukáže na stupnici. Stát rovně neznamená vymazat křivku — znamená s láskou přečíst i tu drobnou odchylku."},"ICON-2533":{"nm":"Elastická smyčka na narovnání ramen","de":"Zavěsíte-li ji na ramena a pomalu zatáhnete, schoulená hruď se dokořán otevře. Pružnost stále šeptá: vrať se na své místo, a záda shrbená za celý den se při tomto něžném volání kousek po kousku narovnávají."},"ICON-2534":{"nm":"Pytlík s pískem na zapojení jádra","de":"Obtočíte-li ho kolem pasu, těžká zrnka písku probudí spící střed těla. I lehký pohyb se před touto váhou v okamžiku stane opravdovým. Čím víc vydržíš, tím jsi pevnější — každé zrnko to tiše napovídá."},"ICON-2535":{"nm":"Visačka polštářku pod kostrč","de":"Polštářek, který jemně podepře pod kostrčí, a na jeho konci zavěšená malá visačka. Nástroj podobný něžnému lístečku, napsanému a přilepenému pro den unavený dlouhým sezením: „Tady se na chvíli můžeš opřít.“"},"ICON-2536":{"nm":"Trojnožka na úhel opory beder","de":"Opřená o tři nohy tiše drží úhel, o který se má opřít bederní páteř. Podpěra, která se nenápadně vloudí do postoje, jenž se chystá zhroutit. Aby se udrželo to, co se kymácí, stačí překvapivě tři body."},"ICON-2537":{"nm":"Svorka na zatažení brady","de":"Lehce zatáhnete a podepřete bradu a rozladěná linie krku najde své místo. Domlouvání svorky velké jako prst je nějak něžné. Jak správně zvednout hlavu, učí tento drobný nástroj."},"ICON-2538":{"nm":"Žebříkový pás na krokovou práci","de":"Páska rozprostřená na podlaze postupně kreslí políčka, na která má chodidlo šlápnout. Když poctivě šlapete políčko za políčkem, kroky se dřív, než se nadějete, vryjí do těla. Cesta je vždy jasnější, čím víc se po ní šlape."},"ICON-2539":{"nm":"Kuželový čip na změnu směru","de":"Postavíte-li ho, je to malá značka, která napoví „tady zahni.“ Darem nabídne roh chodidlům, jež dosud jen běhala rovně. I v cestě zatáčky se skrývá vlastní rytmus."},"ICON-2540":{"nm":"Balanční deska na stoj na jedné noze","de":"V okamžiku, kdy vystoupíte na jednu nohu, se deska nenápadně nakloní. Těch pár vteřin usilovného zápasu s kymácením je tou nejupřímnější lekcí rovnováhy. Špičky prstů, které se snaží nespadnout, vypovídají o všem."},"ICON-2541":{"nm":"Blikací světlo na rychlost reakce","de":"V okamžiku, kdy se rozsvítí signál, závodí ruka s okem o to, kdo bude první. Blikající světlo nedává prostor váhat. Rychlá ruka se vždy pohne o půl úderu napřed před myšlenkou."},"ICON-2542":{"nm":"Značky na cikcak krokování","de":"Drobné tečky nalepené šikmo na podlaze, které vedou nohy tančit v cikcaku. Těžší než přímka je vždycky vzájemné střídání stran. Bloudíte-li podle teček, hbité krůčky se zdatně vypěstují."},"ICON-2543":{"nm":"Plochá tyč na balancování jako na laně","de":"Postavíte-li nohy na útlou tyč, svět se zúží na jediné lano. Jako provazochodec kráčející vzduchem soustředíte celé tělo na šířku jedné dlaně. Rovnováha je čím užší, tím jasnější."},"ICON-2544":{"nm":"Náramek s odrazovým míčkem na hbitost","de":"Nasadíte-li si ho na zápěstí, malý míček se s odrazem pružně vrátí zpět. V okamžiku hodu a chytání se rychlost reakce vryje do konečků prstů. Rychlost nakonec znamená nepromeškat to, co se vrací."},"ICON-2545":{"nm":"Hula kruh na obratnost nohy","de":"Nasadíte-li ho na nohu a roztočíte, hula kruh neustále pobízí lýtko k pohybu. V okamžiku, kdy se zastaví, spadne, a tak se noha bez odpočinku pohupuje. Zatímco se pohybujete jakoby na hraní, práce nohou se hbitě a rychle zdokonaluje."},"ICON-2546":{"nm":"Dřevěná káča rovnováhy","de":"Káča točící se na dlani se v okamžiku ztráty středu rovnou zastaví. Jako v dětských dnech, kdy se šlehala káča na dvorku, rovnováha je něčím, co může stát pouze tehdy, když se bez konce točí."},"ICON-2547":{"nm":"Stahovací šňůrka na ochranu kotníku","de":"Obtočíte-li a utáhnete kotník, vratký krok se stane o poznání jistějším. Čím zranitelnější místo, tím něžněji je třeba je držet. Jediný pramínek šňůry se stává jistotou jednoho kroku."},"ICON-2548":{"nm":"Zahřívací páska na koleno","de":"Obtočíte-li ji kolem studeného kolene, teplo prostoupí mezi klouby. Ztuhlý kloub změkne teprve tehdy, když se zahřeje. Nejteplejší ranní pozdrav, který svému tělu předáte, než se pohnete."},"ICON-2549":{"nm":"Akupresurní kulička na uvolnění svalů","de":"Pevně zatlačíte na ztuhlé místo a zrnka jemně pohladí uzel. Podivná útěcha, že se uvolní přesně tolik, kolik to bolí. I ztuhlost, na kterou ruka nedosáhla, tato malá kulička místo ní hladí."},"ICON-2550":{"nm":"Kolo pořadí rozcvičky","de":"Tělo se probouzí od políčka, na kterém se kolo zastaví. Krk, ramena, kotníky — pořadí ponecháte na štěstí a srdce necháte lehké. Když se do rozcvičky vplíží hra, ztuhlé tělo se usměje jako první."},"ICON-2551":{"nm":"Termo obklad na zahřátí kloubů","de":"Položíte-li horký obklad na kloub, rozlije se úleva podobná teplé zimní podlaze. Je to čas, kdy se ztuhlé klouby rozvolní do ospalého uvolnění. Teprve zahřáté tělo se pomalu chystá k pohybu."},"ICON-2552":{"nm":"Poutko s úchytem na protahování","de":"Uchopíte-li poutko a zatáhnete, ztuhlý sval se dlouze protáhne. Mezi vzpírající se rukou a rozvíjejícím se tělem probíhá napjatý rozhovor. O co víc se protáhne, o to lehčí bude zítřejší pohyb."},"ICON-2553":{"nm":"Deska s bodlinkami na chodidla","de":"Postavíte-li se bosí na bodlinky, spící chodidla se s trhnutím probudí. Jako pichlavý pocit chůze bosky po štěrkové cestě, pocit dotyku se zemí stoupá od špiček prstů výš."},"ICON-2554":{"nm":"Magnetický špendlík se vzkazem o zranění","de":"Napíšete „nepřehánět to“ a připevníte na plechovou desku. Bolestivé vzpomínky se snadno zapomínají, a tak si to zavěsíte magnetem před oči. I péče o vlastní tělo nakonec začíná jediným řádkem poznámky."},"ICON-2555":{"nm":"Hrbolatý váleček na uvolnění fascií","de":"Pomalu koulíte hrbolatou tyčí a přilnutá fascie se uvolňuje kousek po kousku. Doteky, které jemně vytlačují uzly pryč. I zauzlený den, takto vyhlazený uzel po uzlu, je o poznání lehčí."},"ICON-2556":{"nm":"Podlahová páska na chůzový směr","de":"Rozprostřená rovně na podlaze dává nohám jednu linku, kterou mohou následovat. I roztěkaná chůze, postavená na tuto čáru, se nenápadně narovná. Nakreslíte-li cestu, nohy už nebloudí."},"ICON-2557":{"nm":"Tyč na vodorovnost ramen","de":"Položená napříč na ramena tiše odhalí rovnováhu nakloněnou na jednu stranu. Vodorovnost vždy znamená spustit jednu stranu a zvednout druhou. Jediná tyč tiše ukáže na křivý zlozvyk."},"ICON-2558":{"nm":"Vyrovnávací závaží na temeno","de":"Aby závaží na temeni nespadlo, celé tělo se musí narovnat do jediné přímky. Jako kdysi obraz chůze se džbánem vody na hlavě, střed se ustavuje shora od nejvyššího bodu dolů."},"ICON-2559":{"nm":"Opěrka na úhel brady","de":"Jemně podepřete bradu a hlava, která pořád klesala, znovu nabere svůj správný úhel. Krátký odpočinek opřený o jedinou podpěru. Rovná linie je dokonalá teprve tehdy, když ji někdo zespodu podrží."},"ICON-2560":{"nm":"Kolík na rozestup kroků","de":"Kolík zapíchnutý do podlahy předem odměří rozestup, na který má chodidlo dopadnout. Jeden krok, ani příliš široký, ani příliš úzký — ta poctivá vzdálenost. Rovnováha chůze tiše začíná u tohoto malého znamení."},"ICON-2561":{"nm":"Klín na směr špičky nohy","de":"Váhavý první krok — špička nohy zaváhá jako první, kam se má vydat. Když tento malý klín určí směr, srdce se nenápadně nakloní tím směrem také. Volba cesty není žádné velkolepé rozhodnutí, ale jen ta píď, kam ukazuje špička nohy."},"ICON-2562":{"nm":"Pásek na narovnání zad","de":"Ten hlas, co pořád opakoval „narovnej se, narovnej se,“ jako by žil dál uvnitř tohoto pásku. Tiše narovnáte shrbený den a váha, která ležela na ramenou, se podivně o kousek odlehčí. Jedno správné držení těla dokáže napřímit i srdce."},"ICON-2563":{"nm":"Šlapátko na rozložení váhy","de":"Sedm na levou nohu, tři na pravou. Rovnováha se rozhoduje podle toho, kam vložíte více váhy. Šlapátko se tiše ptá — na kterou stranu se teď nakláníš víc? Stát rovně je ve skutečnosti nekonečné dolaďování."},"ICON-2564":{"nm":"Terčová tyč na výšku pohledu","de":"Oči neustále padají ke špičkám nohou. V takové chvíli jediná tyč postavená v dálce pomalu pozvedne pohled. Nácvik dívání se do dálky je nácvikem chůze do dálky, a tak se v okamžiku, kdy zvednete hlavu, přiblíží i místo, které se zdálo nedosažitelné."},"ICON-2565":{"nm":"Kartová svorka na úhel úklony","de":"Patnáct stupňů, třicet stupňů, čtyřicet pět stupňů. Srdce se sklání stejně hluboko, jako se ohýbá pás. Úhel zapsaný na kartě není jen číslo, ale drobná stupnice, která měří upřímnost věnovanou druhému."},"ICON-2566":{"nm":"Poutko na složení rukou při pozdravu","de":"Sepnete-li obě ruce úhledně dohromady, i rozjitřené srdce se klidně usadí na jednom místě. Toto malé poutko něžně zachytí rozechvělé, bezradné konečky prstů a tiše nastaví první postoj pozdravu."},"ICON-2567":{"nm":"Magnetka se šipkou trasy","de":"To, co ztracená noha hledá jako první, rozhlížejíc se kolem, je šipka. Jediný směr přichycený magnetem přetne váhání a jemně přitáhne krok tam, kam je třeba jít. I bloudící srdce si konečně najde jeden směr."},"ICON-2568":{"nm":"Značkovací špendlík směru odchodu","de":"Cesta ven bývá vždy těžší než cesta dovnitř. I ve tmě po zhasnutí světel tento jasně zářící špendlík tiše naznačuje poslední trasu. Že i dobrý odchod patří k jevišti, se člověk dozví teprve na konci."},"ICON-2569":{"nm":"Páska s kartami pořadí formální úklony","de":"Bývaly doby, kdy bylo jasné, kdo se klaní první a kdo později. Skloníte-li se v pořadí zapsaném na pásce, i zdvořilost získá svůj vlastní vzor a slušnost svůj tok. Je to zachovávání pořadí srdce."},"ICON-2570":{"nm":"Magnetický čip na sladění kroku","de":"Vybočí-li jeden člověk, zakolísá celá řada. Jako čip, který cvakne a přilne, jakmile se srovnají špičky nohou, znamená stát společně jemně přenechat svůj krok sousedovi vedle sebe. Nejjistější jsou kroky dopadající ve stejném rytmu."},"ICON-2571":{"nm":"Podkova pozice pro úklonu na jevišti","de":"I jediná úklona na jevišti má své místo, kde stát. Postavíte-li nohy na stopy rozprostřené do kruhu jako podkova, první pozdrav, který se pořád z nervozity kazil, konečně nabere svůj tvar. Když znáte své místo, i chvění se trochu utiší."},"ICON-2572":{"nm":"Karta gest poděkování","de":"Vděčnost, kterou slova nestihla plně obsáhnout, vyteče konečky prstů. Nakreslit srdce, položit ruku na hruď — každé gesto zapsané na kartě se stává překladem srdce zaznamenaným v pohybu. Upřímnost, která touží dosáhnout k druhému, má vždy nějaký tvar."},"ICON-2573":{"nm":"Kartový kolík na rozestup ve frontě","de":"I stání ve frontě má svou laskavou zdvořilost. Jako kolík, který udržuje přesně jednu píď vzdálenosti od člověka vpředu, čekání začíná drobným ohledem, aby se lidé navzájem netlačili. I stát trochu opodál znamená myslet na druhého."},"ICON-2574":{"nm":"Kroužek na listování kartami s narážkami","de":"Když další replika stále krouží kolem rtů, prst tiše obrátí další list. Drobné papíry navlečené na kroužku klidně tlumí bušící srdce a nenechavě otevírají políčko pro to, co říct dál. I když se chvěješ, tok se nepřeruší."},"ICON-2575":{"nm":"Přesýpací hodiny pořadí programu","de":"Sledujete-li klidně přesýpající se zrnka písku, další pořadí se klidně srovná v mysli. Než spadne poslední zrnko, tyto malé hodiny učí, jak číst čas očima, beze spěchu."},"ICON-2576":{"nm":"Cvičná tyč na držení mikrofonu","de":"Než si na to ruka zvykne, i prázdná tyč váží jako tisíc kilo. Úhel úchopu, vzdálenost od úst, síla v zápěstí — nácvik, sevřený a povolený nesčetněkrát, jednoho dne náhle rozkvete v jediný přirozený pohyb."},"ICON-2577":{"nm":"Jazyková hůlka na zřetelnou výslovnost","de":"Ga, na, da, ra. Přidržíte hůlku v ústech a zkoušíte hlásky, dokud se špička jazyka nevyjasní. Slovo, které se protáhne zřetelně a jasně, je jako květina, jež tiše rozkvete nad stovkami hodin drmolení a mlžení."},"ICON-2578":{"nm":"Ruční vlaječka s pokynem","de":"Start, stop, počkej jeden takt. Jediná beze slova mávající vlaječka řídí dech jeviště. Z místa, které hlediště nevidí, tiše mávající ruka drží bez mezery každý takt."},"ICON-2579":{"nm":"Zvoneček na přechod scén","de":"Zacinká to jasně a scéna se změní. Jako zvuk zvonku, který se šířil tržištěm za soumraku, tento drobný zvuk lehce přenese váhavé srdce do dalšího úseku. Přechod vždy začíná zvukem."},"ICON-2580":{"nm":"Kyvadlo na dechový rytmus řeči","de":"Nadechnete se — jedna, dva — a pomalu vydechnete. Vyrovnáte-li dech podle kyvadla houpajícího se ze strany na stranu, i slova, která se hnala příliš rychle, brzy znovu naleznou svůj rytmus. Rychlost řeči byla nakonec vždy rychlostí dechu."},"ICON-2581":{"nm":"Skládací deska na scénář programu","de":"V jediném pohybu skládání a rozevírání je celé pořadí dnešního dne uchováno beze zbytku. V okamžiku, kdy rozevřete desku prosáklou stopami rukou, mysl zmatená tím, co vytáhnout nejdřív, se klidně srovná do řady. Jediné rozevření uspořádá celý den."},"ICON-2582":{"nm":"Přesýpací hodiny dechového rytmu","de":"Nádech tři, zádrž čtyři, výdech šest. Zatímco teče písek, tiše s ním plyne i můj dech. Počítat dech jeden po druhém je nejstarší a nejněžnější způsob, jak pomalu pečovat o uspěchaného sebe."},"ICON-2583":{"nm":"Střapec na meditační polštář","de":"Střapec zavěšený na okraji polštáře se jemně pohupuje, i když nefouká žádný vítr. Usednete-li do tureckého sedu, ticho starého člověka, jenž kdysi utišoval srdce sedě na dřevěné verandě, tiše přijde vedle vás, na chvíli zůstane a odejde."},"ICON-2584":{"nm":"Ruční zvonkohra na uklidnění dechu","de":"Když přejde jediný závan větru, tiše zazní čistý zvuk. Zavěšený jako zvonkohra pod okapem, kápne jednu chladivou, osvěžující kapku na srdce vroucí ve zmatku. I zvuk má moc ochladit."},"ICON-2585":{"nm":"Miska na dým z vonných tyčinek","de":"Dým zbylý po dohořelé vonné tyčince se pomalu snáší na misku. Jako ta vůně, jež kdysi stoupala před sváteční ranní tabulí, jeden pramínek dýmu tiše uklidní neklidný vzduch a naplní pokoj tichem."},"ICON-2586":{"nm":"Kyvné závaží na nádech a výdech","de":"Můj dech se nese na jediném závaží, jež pomalu stoupá a znovu klesá. Vznáší se při nádechu, klesá při výdechu — v den, kdy tělo zapomene, jak dýchat, tyto malé hodiny to znovu učí od úplného začátku."},"ICON-2587":{"nm":"Palička na meditační zvon","de":"Udeříte-li jednou tiše na zvon, ozvěna se dlouze rozprostře. Jako zvuk zvonkohry doznívající v horském chrámu, pouhé naslouchání v tichu, dokud tento zvuk zcela nezmizí ve vzduchu, čistě vypláchne jeden kout srdce."},"ICON-2588":{"nm":"Pírko na vedení dechové stezky","de":"Podržíte-li pírko klidně před nosem, neviditelná dechová stezka se konečně stane viditelnou. Jemné zachvění znamená, že dýcháte dobře, nehybnost znamená, že jste ho zadrželi příliš dlouho. Nejlehčí věc bývá občas nejupřímnějším průvodcem."},"ICON-2589":{"nm":"Oblázek na uklidnění mysli","de":"Oblázek sevřený v dlani je chladný a hladký. Jako kámen, který se dlouho valil při břehu řeky, až odevzdal všechny své hrany, budete-li si s ním pořád pohrávat konečky prstů, i ostré kousky vroucí mysli se pomalu obrousí do kulata."},"ICON-2590":{"nm":"Svorka na teplotu nosního dechu","de":"Teplota u špičky nosu tiše napovídá hloubku dechu. Svorka tiše zaznamená vzduch, který vchází chladný a vychází teplý, a jasně vám před očima ukáže dech, který běžně ani nevnímáte. I dech má svůj výraz."},"ICON-2591":{"nm":"Tabulka nálady jako počasí","de":"Je dnes mé srdce jasné, nebo zamračené? V okamžiku, kdy vyberete malou nálepku a přilepíte ji na tabulku, i nálada těžko vyjádřitelná slovy se stane jakýmsi počasím a nabere jasný tvar. I srdce potřebuje předpověď počasí."},"ICON-2592":{"nm":"Ruční razítko barvy citů","de":"Radost je žlutá, smutek modrý. Vyberete-li barvu a pevně ji otisknete na papír, barva srdce zůstane jako stopa. I cit, kterému bylo těžké dát jméno, barva přijde první a tiše ho rozpozná."},"ICON-2593":{"nm":"Okvětní čip dnešního srdce","de":"Na jediný okvětní lístek si jemně položíte srdce celého dnešního dne. Jako azalky poletující jarním dnem, jeden lehký a křehký čip se na konci pohasínajícího dne tiše zeptá, jak se ti dnes vedlo."},"ICON-2594":{"nm":"Magnetka s bublinou povzbuzení","de":"Slova, která chcete říct, se pořád jen honí kolem rtů. V okamžiku, kdy přilepíte magnetku s bublinou řeči, slůvko povzbuzení, které jste se neodvážili vyslovit nahlas, tiše dosáhne na něčí unavený den. Takto se srdce předává dál."},"ICON-2595":{"nm":"Pečeť na obálku s vnitřním srdcem","de":"Slova, která se nestihla vyslovit, se úhledně vloží do obálky a zapečetí. Jako starý člověk, jenž kdysi lepidlem na konečcích prstů zavíral dopis, jediná pečeť bezpečně chrání to, co je uvnitř srdce. Tiše čeká na den, kdy je bude možné vytáhnout a rozevřít."},"ICON-2596":{"nm":"Poupě teploty citů","de":"Sevřené poupě, dotčené teplem, se opatrně rozevírá vrstvu po vrstvě. Rozkvétá s tím, jak stoupá teplota srdce — jak moc jsem se dnes zahřál, ví tato květina dřív než slova. I do srdce přichází jaro."},"ICON-2597":{"nm":"Řemínek zrcátka na sebechválu","de":"Zvednete zrcátko a tiše se setkáte se svýma vlastníma očima v něm. To, co ukazuje malá tvář zavěšená na řemínku, není obličej, ale včerejší já, které si zaslouží slovo za to, že to dobře vydrželo. Útěcha nikdy nebyla daleko."},"ICON-2598":{"nm":"Sada razítek s výrazy nálady","de":"Zářivý úsměv, oči plné slz, nadutě zamračená ústa. Pevně otisknete razítka výrazů a píšete tak deník srdce. V den, kdy je toho příliš na to, napsat to slovy, jedna malá tvář místo mě tiše vysloví náladu toho dne."},"ICON-2599":{"nm":"Poutko na rozmotání klubka citů","de":"Ať je klubko sebevíc zamotané, rozmotáte-li ho trpělivě vlákno po vláknu, nakonec se vrátí zpět v jedinou nit. Zavěsíte-li na poutko jedno po druhém zmatené, tíživé city, i srdce, kterému jste vůbec nerozuměli, najde tenoučkou nit vodítka."},"ICON-2600":{"nm":"Šňůrka voňavého váčku na spaní","de":"Z voňavého váčku zavěšeného u čela postele se tiše šíří jemná bylinná vůně. Jako ta vůně, kterou babička kdysi ukládala hluboko do skříně, zatímco si pohráváte se šňůrkou, napětí napjaté celý den se pomalu ukládá ke spánku."},"ICON-2601":{"nm":"Otočná spánková deska","de":"Noc, kdy ses převaloval a usnul až za svítání. Když tiše obrátíš polohu vleže, včerejší neklid se pozvolna promění v dnešní ranní svěžest. I odpočinek je třeba trénovat, říká tahle malá deska beze slov."},"ICON-2602":{"nm":"Věšáček měsíčního svitu na polštář","de":"Kousek světla, který proniklo škvírou v záclonách, pověsíš u polštáře. Nad spící tváří se rozlije jemná řeka, a i noci učednice, která se bála tmy, se konečně zjemnily. Byla to první malá útěcha, kterou kdy poznala."},"ICON-2603":{"nm":"Čip kondice ve tvaru poupěte","de":"Dnešní kondice je zavřená jako poupě. Stačí ťuknout na čip a pomalu se rozevře — tělo vždycky ví jako první, jestli ses vyspal dobře, nebo ne. I to váhání předtím, než rozkvete naplno, je tiše milé."},"ICON-2604":{"nm":"Krytka knotu noční lampičky","de":"„Prosím, nezhasínejte.“ Kvůli nejmladší, která se bála tmy, někdo jemně nasadil krytku na knot. Ne příliš jasně, ne příliš tmavě — je to malý a něžný slib bdít nablízku jen do chvíle, než přijde spánek."},"ICON-2605":{"nm":"Slunečnicová spona na probuzení","de":"Zapíchneš ji u postele a ona jemně otočí hlavičku, jako slunečnice, k prvnímu paprsku slunce. I ve dny, kdy se ti nechce vstávat, má světlo svůj důvod, proč volá, a odnese ráno jedním směrem."},"ICON-2606":{"nm":"Bylinný kartáček na polštář","de":"Naneseš na štětinky levanduli a heřmánek a jednou přejedeš přes polštář. Zatímco vůně vsakuje do povlaku, denní napětí se pomalu uvolňuje z ramen. Dobrý spánek začíná touhle malou vůní."},"ICON-2607":{"nm":"Sponka na roh přikrývky","de":"K ránu ti prsty na nohou pořád unikají zpod deky. Když roh pevně sevřeš sponkou, teplo přes noc neuteče. Je to malé zajištění, které nahradí slova „dobrou noc“."},"ICON-2608":{"nm":"Košík na oblázky dobrého dne","de":"Jedna dobrá věc za den, jeden oblázek velký jako dlaň. Čím těžší jsou kamínky nashromážděné v košíku, tím jistěji se cítí i srdce. Sbírat obyčejné chvíle do dlaně — takhle se štěstí odjakživa počítá."},"ICON-2609":{"nm":"Džbán hvězd odhodlání","de":"Každou noc vytvaruješ dnešní odhodlání do podoby hvězdy a spustíš ji do džbánu. Když se naplní až po okraj, stane se z něj malé noční nebe. Kdysi prázdné hrdlo ví, že sliby zazáří jen tehdy, když je shromáždíš."},"ICON-2610":{"nm":"Věšáček na sladkou odměnu","de":"Jeden bonbon, který si po náročném dni podáš sám sobě. Ve chvíli, kdy jeden vezmeš z věšáku a vložíš si ho do úst, je v pořádku, i když si toho nikdo nevšiml. Malá odměna je totiž ta nejupřímnější pochvala."},"ICON-2611":{"nm":"Razítko „dnes zvládnuto“","de":"Namočíš do inkoustu a pevně otiskneš do sešitu. „Dnes zvládnuto.“ Den, který se povedl, i den, který jsi jen vydržel, vyplní políčko stejně. Každý den nemusí být dokonalý, jen nesmíš přestat razítkovat."},"ICON-2612":{"nm":"Podstavec na vlaječku povzbuzení","de":"Zapíchneš ji pevně do země a čím silněji fouká vítr, tím mohutněji vlajka vlaje. I to, co se chvěje, potřebuje ruku, která ho podepře. Srdce, které někoho povzbuzuje, se právě takhle drží zespodu."},"ICON-2613":{"nm":"Květináč se semínkem cíle","de":"Cíl se neodříkává slovy, ale zahrabává do hlíny. Zatímco zasadíš semínko, zaléváš ho a čekáš, netrpělivost se pomalu mění v kořeny. V květináči neroste jen výhonek."},"ICON-2614":{"nm":"Tabule na samolepky za pochvalu","de":"Za každý dobrý skutek jedna samolepka. Čím pestřejší je tabule, tím víc ožívají barvou dny, které jsme bezmyšlenkovitě nechali proplout. My jako děti jsme to věděli — pochvala je zřetelnější, čím víc jí nalepíš."},"ICON-2615":{"nm":"Poutko na stužku odhodlání","de":"Ruka provlékne stužku poutkem a zaváže uzel. Pevně, aby se nerozvázal, ale ne příliš pevně. Odhodlání je přesně jako tenhle uzel — utáhneš ho moc, praskne, necháš ho volný, tiše se rozpustí."},"ICON-2616":{"nm":"Mušlový čip malého úspěchu","de":"Na mušli sebranou na pláži si zapíšeš malý úspěch. Jako úlomek, který sem doputoval, obroušený a hlazený vlnami, i tvůj den se dlouho valil a teď se leskne hladce. Vše, co vydrží čas, nakonec zazáří."},"ICON-2617":{"nm":"Háček na zavěšení medaile","de":"Vydřenou medaili nevěšíš do zásuvky, ale do výše očí. Váha na háčku ti každé ráno narovná ramena. Odměna se neschovává, ale zavěsí se tam, aby na ni bylo vidět."},"ICON-2618":{"nm":"Kalíšek na odkapávání deštníku","de":"Monzunový déšť stéká po hrotu deštníku a kape dál. Podložíš kalíšek a předsíň zůstane suchá. Nemůžeš zastavit to, co se lije, ale můžeš určit, kam to dopadne."},"ICON-2619":{"nm":"Chladicí sáček proti horku","de":"V hlubokém létě za jevištěm si přiložíš na šíji studený sáček. Rozpálené horko na okamžik ustoupí. „Vydechni si.“ Ruka, která se o mě postará dřív než horko, je opora, na kterou se dá spolehnout."},"ICON-2620":{"nm":"Sponka na lopatky ventilátoru","de":"I zuřivě se točící lopatky se jednou sponkou tiše zastaví. Čím prudší vítr, tím víc potřebuješ něco, co ho pevně přidrží. Rychle se točící věci jsou nakonec v bezpečí podle toho, kdo je udrží."},"ICON-2621":{"nm":"Sušicí tyčka do mokrých bot","de":"Deštěm promoklé boty do rána prosáknou vlhkem až do srdce. Zasuneš dovnitř tyčku a ráno jsou zas dost suché na to, abys je obul. To, co je mokré, se nemá vyhodit, ale pečlivě usušit."},"ICON-2622":{"nm":"Škrabka na bláto z holínek","de":"Holínky obalené blátem z rýžového políčka. Až po pořádném otření o škrabku vstoupíš na podlahu. Nechat venkovní bahno u dveří dřív, než vejdeš dovnitř — je to stará zdvořilost, jež udržuje domov čistý."},"ICON-2623":{"nm":"Chladivá dlaždička na léto","de":"Bosé nohy poznají první. Přitiskneš chodidlo na dlaždičku položenou na letní podlaze a polední žár tiše ustoupí hrsti chladu. I jedna malá chladná chvilka dokáže ulehčit celé dlouhé roční období."},"ICON-2624":{"nm":"Páska proti dešti na práh","de":"Stačí kolem prahu ovinout jednu pásku a dešťová voda už se dovnitř nepřelije. Tenká čára, která odděluje vnitřek od venku. Místo, které stojí za ochranu, sluší spíš úzká, pevná hranice než okázalá zeď."},"ICON-2625":{"nm":"Podstavec na spirálu proti komárům","de":"V letní noci položíš spirálu proti komárům na podstavec a stoupá štiplavý, ale důvěrně známý kouř. Jako se kroužek vonné spirály zmenšuje, i noc pomalu houstne. Je to vůně dob, kdy jsme leželi na dřevěné lavici a počítali hvězdy."},"ICON-2626":{"nm":"Poutko na chladivý rukávník","de":"Předloktí spálené sluncem zakryješ rukávníkem. Připevníš ho poutkem pevně k rukávu a i práce v poledním žáru se stane snesitelnou. Chlad je vlastně malá laskavost, která zastíní místo, kam se dotýká."},"ICON-2627":{"nm":"Ruční koštátko na listí","de":"Listí, jež se snesou na celou zahradu, smeteš ručním koštátkem na hromádku. Pod nohama zašustí celé roční období. Uklízet něco znamená také s citem vyprovodit to, co má odejít."},"ICON-2628":{"nm":"Vzpěrná tyčka na větrání okna","de":"Do dusné místnosti vsuneš tyčku a necháš okno pootevřené. Podzimní vánek se tiše vplíží dovnitř a odnese zatuchlý vzduch. Větrání je maličký průduch, který jemně vymění to, co se uvnitř nahromadilo, za venkovní vzduch."},"ICON-2629":{"nm":"Zátka na pytlík žaludů","de":"Jako veverka naplníš pytlík žaludy až po okraj a ústí zajistíš zátkou. Pevně, aby žádný nevykutálel ven. Touha chránit nashromážděné je odvěký pud drobných tvorů, kteří přečkávají zimu."},"ICON-2630":{"nm":"Vyklepávač na podzimní přikrývky","de":"Přikrývku, kterou jsi přikrýval celé léto, pověsíš na zahradě a rázně ji vyklepeš tímto vyklepávačem. Prachem se line vůně slunce. Zápěstí si první vzpomene, že staré roční období musíš vyklepat, než se přikryješ novým."},"ICON-2631":{"nm":"Těsnicí šňůrka na okenní škvíru","de":"Studený průvan, který se plíží okenní škvírou, pevně zastavíš jedinou šňůrkou. Tenká čára uchová teplo pokoje až do konce. Velký mráz vždycky začíná v malé škvíře — příprava na zimu to ví."},"ICON-2632":{"nm":"Krytka síťky na listí do okapu","de":"Síťka položená na okapu. Listí čistě zachytí a propustí jen vodu. Aby proudění nic nebrzdilo, musíš rozhodnout, co propustit a co zadržet — říká podzimní okap."},"ICON-2633":{"nm":"Sponka na svazek suché trávy","de":"Svazek vyprahlé trávy pevně sevřeš sponkou. Ruka, která svazuje dohromady to, co se chce rozpadnout. I na místě, odkud vyprchala všechna letní zeleň, si sesbírané zachová svou plnou užitečnost."},"ICON-2634":{"nm":"Ukazatel podzimního vánku","de":"Když zavane vítr, zavěšený ukazatel se rozhoupe. Podle šíře jeho pohupování odhaduješ, jak hluboko dnes podzim pokročil. Teplota není číslo — nejdřív se tvé ruky dotkne jako něco, co se jemně komíhá."},"ICON-2635":{"nm":"Pouzdro na ohřívač rukou do kapsy","de":"„Zebou tě ruce.“ Pouzdro na ohřívač rukou zastrčené v kapse kabátu jemně zahřeje prokřehlé prsty. Srdce, které se nejdřív stará o něčí zimu, sedí vždycky tiše v kapse."},"ICON-2636":{"nm":"Odkapávací lišta na zamlžené okno","de":"Lišta tiše zachytí slzy, které zimní okno ronilo celou noc. Malý vodní potůček vzniklý rozdílem teplot mezi vnitřkem a venkem. Kde je rozdíl největší, tam proudí nejvíc — svítající okno to ukazuje každý den."},"ICON-2637":{"nm":"Ochranná mřížka před kamna","de":"Před planoucí kamna postavíš ochrannou mřížku. Teplo nablízku, nebezpečí jen na píď dál. Udržet oheň poblíž, aniž by někdo přišel k úrazu, je ta nejzákladnější vzdálenost péče o druhého."},"ICON-2638":{"nm":"Přítlačná sponka na zimní přikrývku","de":"Když tlustá zimní deka pořád sklouzává, sponka ji přitiskne a tiše udrží na místě. Těžké teplo je třeba pevně přidržet, aby si zasloužilo svou cenu. Útulnost zimní noci se takhle pečlivě střeží."},"ICON-2639":{"nm":"Škrabka na námrazu","de":"Bíle rozkvetlou námrazu na ranním okně auta seškrábeš stěrkou. Zamlžený výhled se čára po čáře pročišťuje. I to, co zmrzlo, se dá nakonec seškrábat, radí ti hroty prstů zimního rána."},"ICON-2640":{"nm":"Termoobal na láhev s horkou vodou","de":"Na láhev naplněnou horkou vodou navlékneš zateplovací obal. Aby přes noc nevychladla, obalíš teplo ještě jednou vrstvou navíc. Způsob, jak si teplo podržet dlouho, je nakonec vždycky někoho pečlivě obejmout."},"ICON-2641":{"nm":"Přítlačná tyčka na papírové těsnění dveří","de":"Ledový vítr, který se prodíral dveřní škvírou, se v okamžiku, kdy narazí na tebe, zarazí. Jediná tyčka pevně přitiskne okraj papírové výplně. Teplo pokoje konečně chrání své vlastní — zima je díky téhle malé tvrdohlavosti teplá."},"ICON-2642":{"nm":"Podložka pod nožní ohřívač","de":"Kulatá podložka pod nožním ohřívačem. Sama na sebe přijme veškeré horko a na podlaze nezanechá ani stopu ohořeliny. Když se něčí prsty u nohou zahřejí do ospalého tepla, můj podíl na dnešním dni tiše skončí."},"ICON-2643":{"nm":"Poutko na hadřík na kondenzaci","de":"Aby hadřík, který setřel kapky na ranním okně, neztratil své místo, čeká na zdi zavěšené poutko. Víc než nasáknout do sytosti je pravou podstatou vsakování čekat suchý na zítřejší ráno."},"ICON-2644":{"nm":"Sušák na zimní rukavice","de":"Rukavice po koulovačce roztáhnou prsty dokořán vedle radiátoru. Pohled na ně, jak visí na sušáku a jemně se z nich kouří. Na konci odpoledne s červeným nosem přichází to nejklidnější zimní prádlo."},"ICON-2645":{"nm":"Náhradní peří na oprašovač","de":"Když se peří opotřebuje, vyměníš ho za nové. Chvíle, kdy hrot, co honil prach, znovu zpuchří. I úklidové nástroje mají svá střídání ročních období — tenhle malý náhradní díl to jemně prozradí ve tvé dlani."},"ICON-2646":{"nm":"Rukojeť na vyždímání hadru","de":"Rukojeť je připevněná, aby ušetřila sílu zápěstí. Jedno otočení a hadr sám od sebe vyplivne vodu. Sbohem časům dřiny nad valchou. V domácnosti se hrst šikovnosti stává vlastně laskavostí."},"ICON-2647":{"nm":"Náhradní hlavice na podlahový kartáč","de":"Když se podlahový kartáč opotřebí, vymění se pouze hlavice. Násada zůstává, i váha, na kterou si ruka zvykla, zůstává stejná. Ve věcech, které se používají dlouho, přebývá malá, pevná něha, jež nechce vyhazovat celek."},"ICON-2648":{"nm":"Náhradní jádro do lepicího válečku","de":"Když utrhneš poslední list válečku na prach, je ti nějak prázdno. Tehdy nasadíš nové jádro. Je to vytrvalý a laskavý slib náhradního dílu, že se postará i o jediné žmolky ulpělé na svetru."},"ICON-2649":{"nm":"Škrabka na prach v koutech","de":"I do koutu, kam koště nedosáhne, si prach tiše zařídí domácnost. Tenkým hrotem koutek pěkně vyškrábeš dočista. Srdce, které pečuje i o to, co není vidět, je samou pýchou domácího hospodaření."},"ICON-2650":{"nm":"Hřeben na čištění koštěte","de":"I koště, které zametá, potřebuje chvilku odpočinku. Vlasy zamotané mezi štětinami tímto hřebenem prořízneš, a koště, po skončené práci, se konečně připraví na další zametání."},"ICON-2651":{"nm":"Voskovací podložka na dřevěnou podlahu","de":"Naneseš vrstvu vosku po vláknech dřeva a dřevo si pomalu vzpomene na lesk, na který dávno zapomnělo. Chodidlo, jako by se klouzalo, a jako by ne — odpoledne, kdy se celý dům lesklý a spokojený usmívá."},"ICON-2652":{"nm":"Zametáček prachu z dveřní škvíry","de":"Loví prach, který žije ve škvíře dveří. Vše, co se tam pokaždé při otevření a zavření nenápadně nahromadí, seberu svým tenkým tělem. Čím užší a hlubší škvíra, tím jistěji na mě přijde řada."},"ICON-2653":{"nm":"Síťová krytka rohožky proti prachu","de":"Aby prach, který pohltila vstupní rohožka, znovu neunikl ven, stojí síťová krytka jako poslední strážce brány. Prach, který zablácené boty přinesly z vnějšího světa, se pustí dovnitř jen přesně sem — a ani o krok dál."},"ICON-2654":{"nm":"Kartáček na vodní kámen na kohoutku","de":"Malý kartáček krouží kolem a stírá vodní kámen, jenž se tiše usadil na hrdle kohoutku. Čím víc se místa denně dotýkají ruce, tím víc musí zářit. To je koupelnová zdvořilost, kterou tenhle drobný kartáček střeží."},"ICON-2655":{"nm":"Síťová krytka na vlasy do odtoku","de":"Vlasy unášené k odtoku tiše zachytím. Zažehnat malou pohromu ucpání jedinou krytkou. Den kulatého, spolehlivého hrdiny plyne potichu, vždycky přímo pod nohama."},"ICON-2656":{"nm":"Škrabka na spáry mezi dlaždicemi","de":"Spáru mezi bílými dlaždicemi zčernalou dlouhými léty jemně seškrábeš hrotem, až zmizí. Když se úzké mezery pročistí, celá koupelna si lehce vydechne, jako by byla nová."},"ICON-2657":{"nm":"Čisticí jehla na sprchovou hlavici","de":"Ucpané otvory sprchové hlavice protáhneš hrotem jehly a voda, která dlouho jen slabě crčela, znovu vytryskne osvěživě proudem. Vítězný zvuk ranní vody, jak se uvolní jedno malé ucpání."},"ICON-2658":{"nm":"Kelímek na uložení WC kartáče","de":"I kartáč na záchod je hygienický teprve tehdy, když odpočívá na suchém místě. Úhledně zasunutý do kelímku, který zachytává kapky vody, čeká na svou další chvíli. Důstojnost nástroje se neprojevuje v jeho použití, ale v tom, jak je uložen."},"ICON-2659":{"nm":"Houbička na otírání plísně","de":"Plíseň, jež se černě rozšířila v koutě dlaždic, tomuto vytrvalému hostu houbička zdvořile navrhne odchod. Po jednom otření se koupelna znovu jasně vrátí ke své původní bílé barvě."},"ICON-2660":{"nm":"Stěrka na zamlžené zrcadlo","de":"Před zrcadlem zamlženým po sprše stěrka jedním tahem odhalí tvou zřetelnou tvář. Chvíle, kdy se znovu setkáš s dnešním výrazem, který se na okamžik schoval za párou."},"ICON-2661":{"nm":"Věšák na koupelnové pantofle","de":"Pověsíš mokré pantofle vzhůru nohama, voda skape a vnitřek zůstane útulně suchý. Aby dalšímu člověku nebyly nohy zima. Péče malého věšáku vždycky vyráží o krok napřed ti naproti."},"ICON-2662":{"nm":"Pouzdro na kartáček na nehty","de":"I malý kartáček, který stírá nečistoty pod nehty, má svůj domeček. Útulně zasunutý do pouzdra osychá bez vlhkosti a čeká na další umyvadlo. Čistota vždycky tiše začíná úklidem."},"ICON-2663":{"nm":"Víčko na sterilizační kelímek zubního kartáčku","de":"I zubní kartáček, který se dvakrát denně setkává s tvými ústy, potřebuje malé útočiště. Ve chvíli, kdy víčko sterilizačního kelímku tiše zaklapne, se jedna míra čistoty ochrání před vlhkem, jenž se vznáší koupelnou."},"ICON-2664":{"nm":"Cestovní pouzdro na vatové tyčinky","de":"Aby se vatové tyčinky v cestovní tašce nezlámaly ani nerozsypaly, jedna kapsle je útulně obejme. Čím menší věc, tím dřív ji musíš sbalit — abys pak na neznámé cestě nezůstal zaskočen."},"ICON-2665":{"nm":"Mini destička na kontrolu dechu","de":"Fouknuteš „ha“ do dlaně a přiložíš ji k mini destičce, a tvůj dech se jí dotkne a zamží ji do bělava. Nejroztomilejší důkaz, že v mrazivém dni pořád žiju, tahle malá destička beze slov zaznamená."},"ICON-2666":{"nm":"Domeček na uložení ušního čistítka","de":"Když se ušní čistítko vydá na cestu v tašce, hrot se snadno otupí. Proto mu vznikl malý domeček. Uvnitř, kde se hrot nezraní ani při nošení, jemný nástroj spí klidným spánkem."},"ICON-2667":{"nm":"Sponka na složený kapesník","de":"Sponka jemně sevře kapesník úhledně složený do čtyř rohů a nedovolí mu v tašce se rozházet. Jeden úhledně poskládaný kus propůjčí tichou důstojnost, ať ho vytáhneš v jakoukoli chvíli."},"ICON-2668":{"nm":"Pouzdro na náplasti","de":"V den, kdy si odřeš koleno, otevřeš pouzdro a v řadě na tebe čekají náplasti všeho druhu. Něha, která umí nadělat starosti i z malého škrábnutí. Lékárničku je třeba mít vždycky po ruce."},"ICON-2669":{"nm":"Stěrka otisků prstů do dlaně","de":"Setřeš otisky prstů na skle a stopy váhavé ruky zmizí. Malé kouzlo velikosti dlaně, kdy se svět za oknem, na každém dotyku rozmazaný, znovu projasní."},"ICON-2670":{"nm":"Přepážka na tříděný odpad","de":"Papír sem, plechovky tam. Jediná přepážka rozdělí osud, který se málem smíchal. Třídění odpadu je nakonec srdce, jež pečlivě rozlišuje, a tuhle první čáru pevně a jasně vede právě tahle úhledná přihrádka."},"ICON-2671":{"nm":"Škrabka na odlepení samolepek","de":"I lepkavě přilnutá samolepka se přede mnou tiše vzdá. Zasuneš plochý hrot lopatky jemně pod roh a ona se odloupne čistě, beze stopy — vítězné rozloučení."},"ICON-2672":{"nm":"Zoubky na odstřižení maskovací pásky","de":"Nemusíš pátrat po nůžkách, jen abys použil maskovací pásku. Přiložíš ji k zoubkům, zatáhneš a ona se rovně utrhne podle vlákna. Malý, hbitý nejlepší přítel, kterého si dekorativní prsty cení nejvíc."},"ICON-2673":{"nm":"Rohová spona na lepení okrajů","de":"Malá kovová spona, jež zevnitř pevně přidrží odchlipující se roh. Z místa, které není vidět, mlčky střeží pravý úhel. Za tím, co je navenek rovné, se obvykle skrývá právě taková neviditelná opora."},"ICON-2674":{"nm":"Ochranný tubus na sešity nálepek","de":"Aby se vzácné listy nálepek nezmačkaly ani nezvlhly, spí v tubusu bok po boku s ochrannou fólií. Vedle radosti ze sbírání vždycky kráčí i péče, jež se ji snaží něžně ochránit."},"ICON-2675":{"nm":"Čisticí kartáček na razítka","de":"Kartáček jemně smete podél rýh razítko nasáklé inkoustem a strhne starou barvu. Malý, pilný dotek, který uklízí předem, aby byl další otisk zřetelný."},"ICON-2676":{"nm":"Křidélko na listy do pořadače","de":"Aby průhledné listy v pořadači nesklouzly ven, křidélka je pevně sevřou z obou stran. Díky tomu, že každý list zůstává na svém místě, se prst listující stránkami nikdy nezmate."},"ICON-2677":{"nm":"Lopatka na sbírání dekoračních kousků","de":"Drobné, rozházené dekorační kousky jedním pohybem nabereš do malé lopatky. Když zmizí ta otrava sbírat je jeden po druhém prsty, čas strávený pečlivým tvořením se stane ještě radostnějším."},"ICON-2678":{"nm":"Spona na střapec záložky","de":"Aby se střapec na konci záložky neuvolnil, spona ho pevně sváže. I průvodce zpátky k nedočtené stránce potřebuje mít vlastní úpravu v pořádku, aby si člověk mohl oddechnout."},"ICON-2679":{"nm":"Sponka na víčko dekorativního fixu","de":"Sponka pevně přidrží víčko, aby hrot dekorativního fixu nevyschl. Zabrání nehodě, kdy fix zapomenutý otevřený ztuhne, a barva tak vždycky vytéká vlhká jako poprvé."},"ICON-2680":{"nm":"Výměnný hrot pro šroubovák","de":"Rukojeť šroubováku necháš tak, jak je, a jen vyměníš hrot na konci. Křížový nebo plochý, vždycky po ruce. Chytrost zvládnout mnoho úkolů jedním nástrojem je pevně sbalená do tohohle malého hrotu."},"ICON-2681":{"nm":"Návin brusného papíru na roh","de":"Obtočíš drsnou plochu kolem a dlaň se stane nástrojem. Švih, švih — s každým tahem po vláknu se drsný roh zaobluje, a poslední hladkost vždycky pozná lidský konec prstů."},"ICON-2682":{"nm":"Trychtýř na třídění šroubků","de":"Rozházené šroubky projdou úzkým hrdlem a s cinkotem se shromáždí na jednom místě. Zvuk drobností, jež se povalovaly po stole a nacházejí své místo — jako by se do pořádku srovnala i rozházená mysl."},"ICON-2683":{"nm":"Háček na konci pásmové míry","de":"Háček na konci pásma je druhou rukou toho, kdo pracuje sám. Zavěsíš ho na roh a pásmo se nezachvěje, a ruka i srdce zpoctivějí přesně o tolik, kolik jsi naměřil."},"ICON-2684":{"nm":"Potah na rukojeť francouzského klíče","de":"Vrstva navlečená na studenou kovovou rukojeť. Ve chvíli, kdy ji sevřeš, se místo chladu dotkne ruky měkké teplo. Nástroj zůstává po boku déle, když nejdřív myslí na toho, kdo ho drží."},"ICON-2685":{"nm":"Ochranný klobouček na hrot šídla","de":"Na každý ostrý hrot se nasadí malý klobouček. Klid, s jakým prohrabáváš zásuvku, aniž by ses píchl — čím ostřejší věc, tím pečlivěji ji zabalíš, a nikomu se nic nestane."},"ICON-2686":{"nm":"Čepel na odizolování drátu","de":"Sloupneš jen tenkou izolaci a vnitřní vodič zůstane nedotčen. Ve chvíli, kdy jemně rozvineš jednu vrstvu a zablýskne se měděné vlákno, dobrá čepel přesně ví, kde má přestat."},"ICON-2687":{"nm":"Stěrka na okénko vodováhy","de":"Teprve když bublinka zůstane přesně uprostřed, je to skutečná vodorovnost. Utírat čisté malé okénko připomíná tiché soustředění, kdy si nejdřív urovnáš dech, než potáhneš čáru."},"ICON-2688":{"nm":"Ochranný návlek na prst při zatloukání hřebíků","de":"Malý návlek, který těsně obejme prst svírající hřebík. Klidně udeř bez obav, i kdyby kladivo minulo — je pevně připraven přijmout ránu místo tvého prstu."},"ICON-2689":{"nm":"Protiskluzová podložka pod misku na krmení","de":"Vrstva gumy, jež podepře misku, aby nesklouzávala po podlaze. Bez toho, aby miska při hodování utekla, začíná klid jídla na místě, které se nezachvěje."},"ICON-2690":{"nm":"Věšák na naběračku krmiva","de":"Naběračku na krmivo pověsíš na zeď, ať se lehce usuší. Malý řád, který při každém jídle vítá ruku na stejném místě — mít o koho pečovat je právě takhle něžná věc."},"ICON-2691":{"nm":"Podnos na přetečenou vodu z misky","de":"Tiše zachytí doušek, který přeteče přes okraj misky s vodou. Díky širokému talíři, jenž ho pojme dřív, než by zvlhla podlaha, zůstává pod nohama vždycky útulné sucho."},"ICON-2692":{"nm":"Kleštičky na podávání pamlsků","de":"Kleštičky, které přesně uchopí jeden kousek pamlsku a podají ho. I před malými ústy čekajícími s vystrčeným čumáčkem má sdílení svůj něžný, nikdy nezakolísaný konec prstů."},"ICON-2693":{"nm":"Sponka na zavinutí sáčku s krmivem","de":"Malá svorka, jež srolovaný okraj otevřeného sáčku s krmivem pevně sevře. Jedním cvaknutím se zabrání vlhkosti a zítřejší chrupavá hrst zůstane úplně zachovaná."},"ICON-2694":{"nm":"Zátka na hubičku napáječky","de":"Zátka, jež přesně dosedne na hubičku napáječky. Kap — kapající voda se zastaví a okraj oschne. To, co je dobře uzavřené, neteče a zůstává čisté a klidné dlouhý čas."},"ICON-2695":{"nm":"Odměrka na dávku krmiva","de":"Podle rysky přesně odměříš jeden pohárek. Ani moc, ani málo — do ruky, jež spravedlivě odhaduje dnešní porci, se vejde den malého člena rodiny přesně tak, jak má být."},"ICON-2696":{"nm":"Okraj podložky proti rozsypanému krmivu","de":"Okraj, jenž brání rozlitému krmivu přejít mimo podložku. Jediný lehce zvednutý lem pevně shromáždí drobky, které se málem rozsypaly."},"ICON-2697":{"nm":"Rozdělovací kroužek na složené misky","de":"Malý kroužek, jenž jemně oddělí dvě do sebe zaklíněné misky. Ruka, jež se s nimi dřela slepenými k sobě, se náhle uleví. I dobře oddělit něco od sebe je, jak se ukazuje, něžná péče."},"ICON-2698":{"nm":"Trychtýř na kutálení míčků ze zahrady","de":"Trychtýř, jenž shromáždí na jedno místo míčky, které se rozkutálely po zahradě. Po večeru plném dovádění se sama od sebe vybaví ruka, jež sbírá dohromady to, co se rozprchlo sem a tam."},"ICON-2699":{"nm":"Čepička na kůl plotu","de":"Na každý kůl plotu nasadíš kulatou čepičku. Aby se hroty nerozštípaly ve větru a dešti, srdce, jež pečuje a přikrývá i tu nejmenší věc, prosákne celou zahradou."},"ICON-2700":{"nm":"Háček na složení herního tunelu","de":"Háček, na nějž úhledně složíš vydováděný herní tunel a zavěsíš ho. Když den zamazaný od hlíny pěkně uklidíš a pověsíš, dobře uklizená hra bezpečně slibuje zítřek."},"ICON-2701":{"nm":"Polstrování na madlo tahacího lana","de":"Polštářek, který měkce obepíná madlo tahacího lana. Ať zatáhneš sebesilněji, dlaň se nikdy neodře. Že ruka vydrží déle v pohodlí, je zásluhou něčí drobné pozornosti."},"ICON-2702":{"nm":"Spona na stínicí plachtu na dvorku","de":"Spona, která pevně přidržuje stínicí plachtu nataženou přes dvorek. I poledního chládku je třeba se přidržet, aby zůstal. Pod stínem, který spona udrží napjatý, se rozvalené odpoledne dlouze protahuje."},"ICON-2703":{"nm":"Kryt na čepel rycí lopaty","de":"Kryt, který se jemně nasouvá na čepel rycí lopaty. Necháš-li ji po náročném dni odpočinout, zůstane neotupená a znovu se setká s hlínou dalšího jara."},"ICON-2704":{"nm":"Rampa na koulení míčku","de":"Jediná rampa, po níž se míček vesele skutálí dolů. Po mírně skloněném svahu se míček s radostí řítí. Jeden malý sklon dokáže vytvořit celodenní radost."},"ICON-2705":{"nm":"Zajišťovací kroužek na plotová vrátka","de":"Zajišťovací kroužek, kterým se zamykají plotová vrátka. Tiché cvaknutí zámku uklidní srdce. Jedna pevně zavřená branka střeží malý dvorek jako celý svůj vlastní svět."},"ICON-2706":{"nm":"Šňůrka s hracím zvonečkem","de":"Lehce zatřeseš šňůrkou se zavěšeným zvonečkem a rozlije se čistý zvuk. Cink, cink – dosud tichý pokoj se probouzí a při jediném drobném zazvonění celé srdce nastraží uši."},"ICON-2707":{"nm":"Miska pod květináč","de":"Miska, která tiše zachycuje vodu prosakující zpod květináče. Zadržuje přebytečnou vodu, aby okenní parapet zůstal suchý. I když péče přeteče, potřebuje místo, kde se dá zachytit."},"ICON-2708":{"nm":"Sázecí lopatka na přesazování sazenic","de":"Malá lopatka na přesazování útlých sazenic do hlíny a jejich jemné zasazení. Pod prsty, které opatrně usazují každý výhonek na jeho místo, pozvedá zelené jaro hlavu i na zahrádce velké jako dlaň."},"ICON-2709":{"nm":"Značkovací kolíček do záhonu","de":"Značkovací kolíček, na který si napíšeš, co jsi zasadil do jednotlivých řádků. Na hlíně, kde ještě nevzešel žádný výhonek, jedna malá jmenovka tiše pamatuje, co z ní vyroste."},"ICON-2710":{"nm":"Sítko na hubici konve","de":"Jemné sítko nasazené na hubici konve. Voda, která by jinak vytékala v jediném proudu, se rozprostře do mnoha pramínků jako jemný déšť. Jen měkký proud dokáže nezranit křehké listy."},"ICON-2711":{"nm":"Klips na uchycení k opoře","de":"Klips, který jemně přidrží kolébající se stonek k opěrné tyčce. Jen vypůjčená opora, dokud se ještě křehká rostlina nepostaví zpříma – k růstu je taková podpora třeba."},"ICON-2712":{"nm":"Sponka na zavírání sáčku semínek","de":"Sponka, která pevně sevře a uzavře zbylý sáček semínek. Jednou cvaknuta, nepustí ven ani jedno zrnko. Malý slib příštímu jaru se skrývá v tomto jediném stisku."},"ICON-2713":{"nm":"Odměrná lopatka na hlínu a hnojivo","de":"Malá lopatka na nabírání přesného množství hlíny a hnojiva. Ani moc, ani málo – jedna odměřená lžíce. Teprve na přesně vyváženém množství hlína konečně odvede svou práci."},"ICON-2714":{"nm":"Závěsný háček na květináč","de":"Závěsný háček, který lehce zavěsí květináč do vzduchu. Zvednutá zeleň se o píď přiblíží slunci a vánku. U okna se vznáší malá zahrádka."},"ICON-2715":{"nm":"Ochranná síťka na výhonky","de":"Ochranná síťka, jež jemně zakrývá čerstvě vyrašené výhonky. Dokud ještě křehké lístky nezvládnou první chlad a palčivé slunce, nejzranitelnější věc je vždy první, komu se dostane péče."},"ICON-2716":{"nm":"Věšák na hřeben na srst","de":"Místo, kam se z hřebene vyklepou uvolněné chlupy a kam se úhledně pověsí. Vyčištěný, vyprázdněný hřeben čeká na další jemný dotek. Úpravnost vždy začíná drobným zvykem pečovat o své nástroje."},"ICON-2717":{"nm":"Protiskluzový kroužek pod umývací nádobu","de":"Kroužek, který podepírá nádobu na mytí tlapek, aby neklouzala. Když nádoba pod cákajícími malými tlapkami stojí pevně, nechvěje se ani myjící ruka, ani myjící srdce."},"ICON-2718":{"nm":"Háček na venčicí vodítko","de":"Jediný háček, na který se u dveří pověsí vodítko na procházku. Na svém místě vedle dveří vždy čeká připravenost vyrazit ven. V okamžiku, kdy vodítko sundáš, se k tobě přidá i jeden roztřesený krok radostného očekávání."},"ICON-2719":{"nm":"Ochranná krytka na stříhání drápků","de":"Ochranná krytka, která při stříhání drápků chrání citlivou živou tkáň. Jen s bezpečnou hranicí vyznačenou přesně sem až potud zůstane i ruka svírající nůžky klidná a nechvěje se."},"ICON-2720":{"nm":"Teploměrný proužek do koupele","de":"Proužek, který se vznáší na vodě v koupeli a ukazuje její teplotu. Starý zvyk namočit hřbet ruky, aby se odhadlo to pravé teplo, se teď plaví na hladině jasně přeložen do jediného barevného pásku."},"ICON-2721":{"nm":"Lepicí váleček na chlupy","de":"Jeden bílý chloupek na černém oblečení vypadá těsně před vystoupením největší ze všech. Za zvuku kutálení se denní dávka smítek jedno po druhém přesouvá na lepicí papír. Úpravnost se takto dokončuje po proužcích, přesně tak, kolik se jich odloupne."},"ICON-2722":{"nm":"Kleštičky na sáček po venčení","de":"Na konci procházky přichází něžná chvíle sehnutí. Sevřeš sáček do kleštiček a ruce zůstanou čisté, srdce lehké. Ve společné procházce je ukryta i drobná zdvořilost postarat se, co zůstane za vámi – a tyto kleštičky to vědí jako první."},"ICON-2723":{"nm":"Lem rohožky u dveří","de":"Lem rohožky přede dveřmi je první přivítání, kterého se dotkne tlapka. Zastaví-li se tu vlhká špička nohy jen jednou, podlaha uvnitř zůstane suchá. Nejníže položené místo ze všech, které beze slova otírá a vítá každého, kdo vchází dovnitř."},"ICON-2724":{"nm":"Šňůrka s uzlem na zvoneček k úpravě srsti","de":"I na připevnění jediného zvonečku existuje svůj postup. Dvakrát obtočíš šňůrku a jednou ji provlékneš, a s každým krokem se rozezní čistý zvuk. Úprava zevnějšku je nakonec srdce, které nikdy nevynechá tento drobný závěrečný krok."},"ICON-2725":{"nm":"Kapsička na kapající skládací deštník","de":"V hale po dešti odkapávají ze složeného deštníku kapky a tečkují podlahu. Jedna kapsička je tiše zachytí a ničí nohy se pak nepodkluzují. Laskavost obvykle takto tiše stojí nablízku, beze zvuku."},"ICON-2726":{"nm":"Klips na tašku přes opěradlo","de":"Taška zavěšená na židli neustále pomalu klouže dolů. Jednou ji sevřeš do klipsu a obě ruce jsou volné od starosti, že spadne. Volnost odchodu z domova začíná ve chvíli, kdy smíš na chvíli zapomenout na svá zavazadla."},"ICON-2727":{"nm":"Látkový sáček na ohřívač rukou","de":"V uličce s chladným větrem tiše přenáší látkový váček v kapse teplo do dlaně. Měkká vrstva, jež obalí horkou věc a zahřeje ji tak akorát. Zimní laskavost se vždy předává skrze jediný kus látky."},"ICON-2728":{"nm":"Skládací stojánek na kapesní zrcátko","de":"Rozevřeš ho a malé zrcátko se nakloní do svého úhlu. Abys mohl vidět svou tvář, aniž bys ho musel držet, stojánek stojí místo tebe. I v té krátké chvilce upravování zevnějšku je nablízku jeden spolehlivý pomocník."},"ICON-2729":{"nm":"Víčko na cestovní vlhčené ubrousky","de":"První ubrousek z balení vždy postupně vysychal. Cvakneš víčkem a vlhkost vydrží až do posledního kousku. Udržet ho použitelným až do konce – tajemství dlouho vydržející domácnosti se skrývá právě v takových drobnostech."},"ICON-2730":{"nm":"Přihrádka na mince do peněženky","de":"Když se mince rozsypou mezi bankovky, u pokladny vždy nastane shon. Jedna přihrádka shromáždí ty kulaté věci na jednu stranu a prsty už dál netápou. Uklízet znamená dávat každé věci její místo a jméno."},"ICON-2731":{"nm":"Skládací pouzdro na roušku","de":"Složená rouška se v tašce ani nezmačká. Pouzdro, které čistě uchová kousek, jenž jste si na chvíli sundali. Skrývá se v něm jeden laskavý zvyk uschovat věc úhledně pro příští použití."},"ICON-2732":{"nm":"Kryt na zoubky cestovního hřebenu","de":"Zoubky hřebenu v tašce často škrábaly ostatní věci. Nasadíš kryt na zoubky a hřeben je v bezpečí, stejně jako věci uložené vedle něj. Že jedna tenká vrstva ochrany chrání obě strany, ví každý, kdo se o své věci staral."},"ICON-2733":{"nm":"Přepážkový klips do zásuvky","de":"Kdykoli se zásuvka otevřela, promíchaný obsah se z ní vysypal jako povzdech. Rozdělíš ji jedním klipsem na přihrádky a drobnosti konečně najdou svůj vlastní kout. Uklizená zásuvka tiše mění náladu každého rána."},"ICON-2734":{"nm":"Stojánek na vystavení mince","de":"Postavíš starou minci na stojánek a sama o sobě se stane malou výstavou. Stojánek ji nakloní tak, aby jasně ukázal vzor na líci. Pozvednout ohmataný čas na úroveň očí – právě tady se prohlubuje radost ze sbírání."},"ICON-2735":{"nm":"Navíječ na kabel sluchátek","de":"Byla rána, kdy se polovina jich ztratila v rozmotávání zamotaných šňůrek sluchátek. Naviješ je úhledně kolem navíječe a příště je vytáhneš hladké. Malé uklízení se stává tichým darem, který si potají posíláš zítřejšímu já."},"ICON-2736":{"nm":"Nástěnný háček na nabíjecí kabel","de":"Nabíjecí kabel volně ležící na zemi se stále pletl pod nohy. Připevníš na zeď jeden háček a stůl se rázem zdá prostornější. Zkrotit nepořádek nevyžaduje nic velkolepého – stačí místo velké jako jeden hřebík."},"ICON-2737":{"nm":"Stojánek na dálkový ovladač","de":"Dálkový ovladač, který stále mizel ve škvíře gauče, konečně dostal domov, kam se může vracet. Postavíš ho do stojánku a už ho nemusíš hledat ani si na něj sedat. Mít své vlastní místo je i pro věc malým odpočinkem."},"ICON-2738":{"nm":"Klips na zavěšení brýlových stranic","de":"Odložené brýle vždy někam potichu sklouzly. Zavěsíš stranici jemně na klips a čočky se už nedotknou podlahy. V tomto malém věšáčku se skrývá přání, aby dočkaly zítřka bez jediného škrábance."},"ICON-2739":{"nm":"Třídicí klips na svazek klíčů","de":"Čím těžší je svazek klíčů, tím víc se stírá, který klíč patří ke kterým dveřím. Svážeš je třídicím klipsem a samotné prsty poznají ten správný pár. Tichý průvodce, který denně otvíraným a zavíraným dveřím potichu vnáší řád."},"ICON-2740":{"nm":"Klips na vzpřímenou poznámku","de":"Zapsaný lísteček se na stole často převrátil. Když ho klips přidrží vzpřímeně, písmena se ti podívají přímo do očí. Způsob, jak nechat ten jeden řádek, na který se nesmí zapomenout, žít na místě, kde je stále na očích."},"ICON-2741":{"nm":"Stojánek na hrot pera","de":"Kolikrát ses ohnul, abys zvedl pero, které se skutálelo pryč? Zapíchneš špičku do stojánku a vzdálenost k dalšímu řádku se zkrátí o dlaň. Malá čekárna, stále bdělá po boku toho, kdo píše."},"ICON-2742":{"nm":"Podstavec na převracení přesýpacích hodin","de":"Když přesýpací hodiny doběhnou, musí je někdo obrátit, aby znovu ožily. Podstavec zachytí okamžik posledního zrnka a hladce je postaví zpátky vzhůru nohama. Dotek, který vrací čas na začátek, spočívá zde, na kousku dřeva."},"ICON-2743":{"nm":"Pečený brambor s máslem","de":"Máslo se pomalu rozpouští na bramboru pečeném ve slupce. Jak žlutá stružka prosakuje spolu s párou, kyprý vnitřek tiše přijímá její vůni. Přesně tento okamžik je, kdy kořenová zelenina provoněná hlínou dosáhne nejtěsnějšího tepla."},"ICON-2744":{"nm":"Grilovaná kukuřice s máslem","de":"Žlutá zrna, poskládaná zrnko vedle zrnka, na grilu tiše praskají. Kousek másla po nich sklouzne a prudce se zvedne sladká vůně. Sladkost letního pole se tak celá přenese do jednoho soustu."},"ICON-2745":{"nm":"Vafle","de":"V každém čtverečku mřížky trpělivě čeká sirup, až se v něm nahromadí. Zvenku křupavé, uvnitř nadýchané – jedno kousnutí a unikne teplá pára. Čtvercová políčka jsou jako miska, která rozdává drobné kousky štěstí."},"ICON-2746":{"nm":"Americké lívance","de":"Pamatuji si tu vůni těsta, jak se na pánvi dozlatova nadýmalo. Přes kulaté placky navrstvené jedna na druhou se máslo pomalu sesouvá a rozplývá. Měkký talíř, který si člověk potichu dovolí jen v poklidném ránu."},"ICON-2747":{"nm":"Čokoláda","de":"Vložíš kousek do úst a teplem těla se pomalu rozpouští. Sladkost, jež se rozlévá na konci hořkosti, jemně uvolní napětí v srdci. V únavném dni malá útěcha hnědé barvy, vytažená z kapsy."},"ICON-2748":{"nm":"Jahodový dort","de":"Červené jahody usedají na bílý šlehačkový krém a jako první ohlašují jaro. Když vidlička rozdělí měkký řez, jemně se rozvoní nakyslá vůně. V den, kdy je co oslavovat, něžný hlavní hrdina uprostřed stolu."},"ICON-2749":{"nm":"Cheesecake","de":"Jeden těžký kousek se sytě rozplyne na jazyku. Slaný dozvuk vezme sladkost za ruku a stále volá po dalším soustu. Dezert, který si tiše vychutnávají milovníci husté, hutné plnosti."},"ICON-2750":{"nm":"Banánové sušenky","de":"Vůně rozmačkaného banánu v troubě dozrává do zlatavé barvy. Kousneš a měkká sladkost se rozlije po celých ústech. Teplý okamžik, kdy se pěkně zralé ovoce znovu narodí jako sušenka."},"ICON-2751":{"nm":"Čokoládové sušenky","de":"Kousky čokolády v těstě se při pečení rozpouštějí do husté, tažené hmoty. Rozlomíš je ještě teplé a sytá hněď zůstane na prstech. Kousek, díky němuž je odpoledne o něco vlídnější, když k němu patří sklenice mléka."},"ICON-2752":{"nm":"Sušenky s kakaovými boby","de":"Nadrobno drcené kousky kakaa mezi těstem tiše křupou pod zuby. Nesladká, hluboká hořkost tiše konejší dospělé chutě. Trochu vážná sušenka, jež v sobě uchovává původní vůni tak, jak byla ještě před zpracováním."},"ICON-2753":{"nm":"Toast se sýrem","de":"Sýr se táhne dlouze jako niť přes do zlatova opečený chléb. Křupavost zvenčí a lahodnost zevnitř se spojí v jednom soustu. Nejjednodušší a přitom nejněžnější jídlo, které vydatně naplní pozdní dopoledne."},"ICON-2754":{"nm":"Sendvič","de":"Mezi dvěma plátky chleba se vrstva po vrstvě ukládá péče celého dne. Kousneš a navrstvené chutě tě všechny najednou pozdraví. Malý jídelní stůl na dlani, který můžeš vzít s sebou kamkoli."},"ICON-2755":{"nm":"Francouzský toast","de":"Chléb důkladně namočený ve vajíčku dozlatova zapéká na pánvi. Okraje, nadmuté vůní másla, zkřupavějí jako první ze všeho. Stačí jedna čárka sirupu a i obyčejný chléb se promění ve sváteční hýření."},"ICON-2756":{"nm":"Houbové ramen","de":"Nad vroucím vývarem se s párou vznáší hluboká vůně hub. Vyloviš kousek pružného klobouku a ústy se rozlije zemitá sladkost. Trochu zvláštní miska, která nasytí nejprve vůní a teprve pak nudlemi."},"ICON-2757":{"nm":"Smažené ramen","de":"Nudle bez vývaru, promíchané s pikantním kořením, se lesknou hladkým leskem. Zvedneš je hůlkami a mezi párou se rozestře lahodná vůně opečeného. Když se zachce rychlého a sytého jídla, nejspolehlivější přítel."},"ICON-2758":{"nm":"Sýrové ramen","de":"Položíš plátek sýra na horké nudle a pomalu se sesune a rozplyne. Pálivý vývar se potká s měkkou lahodností a hrany se zaoblí. Miska jako stvořená pro noc, kdy chceš trochu zmírnit ostrost."},"ICON-2759":{"nm":"Kari ramen","de":"Sytá vůně kari obtáčí nudle a vzhůru stoupá žlutá pára. Jeden hlučný doušek a teplá pálivost tě zahřeje zevnitř. Nudle radostné obměny, jež do známého vývaru přidávají trochu neznámou vůni."},"ICON-2760":{"nm":"Mořské ramen","de":"Nad vývarem plným moře se vznášejí baculaté krevety a mušle. Osvěžující, a přesto hluboká chuť umami prosakuje mezi nudlemi. Malé kouzlo, které přináší vůni pobřeží do jedné misky, aniž bys musel kamkoli cestovat."},"ICON-2761":{"nm":"Kimbap s nakládanou ředkví","de":"Kolem žluté nakládané ředkve se v kruhu usadí rýžová zrnka a jediný list nori je všechny vřele sváže v jeden svitek. Za svítání v den výletu se na prkénku rodí to nejpoctivější jídlo ze všech."},"ICON-2762":{"nm":"Tuňákový kimbap","de":"V okamžiku, kdy se lžíce tuňáka smíchaného s majonézou vsákne mezi rýži, i pod pozdní nocí ve světle večerky se jídlo dostatečně zahřeje. Útěcha, po níž nejčastěji sahají zaneprázdněné ruce."},"ICON-2763":{"nm":"Ovocný salát","de":"Barvy nasbírané v jejich sezóně se poprvé setkávají v jedné misce. Jak se červená, zelená a žlutá dokážou snést, aniž by se hádaly, ukáže ovoce teprve tehdy, když je nakrájené a spojené dohromady."},"ICON-2764":{"nm":"Kuřecí salát","de":"Lehce grilovaná kuřecí prsa úhledně poležou na zeleném listovém salátu. Na stole toho, kdo se připravuje na zítřejší pódium, vždy stojí takto upravený talíř."},"ICON-2765":{"nm":"Rajčatovo-okurkový salát","de":"Uzrálá rajčata a křupavé okurky jsou lehce nakysle promíchány. V poledni hustém cikádovým zpěvem stačí jedna hůlka do úst a léto se v ní na okamžik osvěživě ochladí."},"ICON-2766":{"nm":"Salát z hlávkového salátu","de":"Opláchneš studenou vodou listy právě natrhané ze záhonu a prsty se svěže probudí chladem. Chvíle, kdy nejobyčejnější zelenina zaujme na stole to nejzelenější a nejsvěžejší místo."},"ICON-2767":{"nm":"Kukuřičný salát","de":"Při každém prasknutí sladkého zrnka se před očima rozprostře slunné letní pole. I v misce salátu žlutá kukuřice nikdy docela nezapomene na své vlastní slunce."},"ICON-2768":{"nm":"Coleslaw","de":"Když jemně nakrájené zelí nasákne sladkokyselou omáčkou, jeho křupavost se o něco jemněji zmírní. Ctnost přílohy, jež se vedle jakéhokoli hlavního chodu nesnaží soupeřit o pozornost a prostě dělá svůj díl."},"ICON-2769":{"nm":"Salát s krevetami a limetkou","de":"Vymáčkneš trochu limetky a sladkost krevet se probudí zřetelněji. Jedna kyselá kapka vdechne život celému talíři – malý, ale rozhodující poslední dotek."},"ICON-2770":{"nm":"Hamburský steak","de":"Tlustě tvarovaná masová placka se dozlatova propéká na rozpáleném plechu. Šťáva, jež vytryskne ve chvíli, kdy se jí dotkne ostří nože – jídlo, které je nejdéle milované na pomezí domácí a evropské kuchyně."},"ICON-2771":{"nm":"Pizza","de":"To jedno sousto, kde se sýr dlouze táhne, si mnozí sedící kolem podávají z ruky do ruky. Teprve když se kulatý koláč společně rozdělí na kousky, stane se ze sešlosti opravdová sešlost."},"ICON-2772":{"nm":"Krémové těstoviny s houbami","de":"Hluboká zemitá vůně hub a jemnost smetany obejmou nudli po nudli. Ve večeru s tichým šumem deště se sytá vůně pomalu rozlévá až na dno talíře."},"ICON-2773":{"nm":"Krevetové těstoviny","de":"Baculaté krevety se lehce orestují na olivovém oleji a promíchají s nudlemi dohromady. Když se slanost moře potká s prostou chutí nudlí, obyčejný večer se stane o něco výjimečnějším."},"ICON-2774":{"nm":"Olejové těstoviny s česnekem","de":"Česnek, olej a nudle, jen tyto tři věci. Existuje chuť, která se čím víc odebírá, tím zřetelnější je, a tyto těstoviny to potichu dokazují beze zbytečností."},"ICON-2775":{"nm":"Těstoviny s mušlemi","de":"Vývar, který mušle uvolní, když otevřou ulity, hluboko prosákne do každé nudle. Vůně doušku bílého vína na talíři dlouho nemizí, jako jarní den, který nechce pominout."},"ICON-2776":{"nm":"Krémové těstoviny","de":"Když hustá smetana tiše obejme nudle, kout srdce se zahřeje už od prvního sousta. Útěcha, kterou nabízí měkkost, se ještě prohlubuje v den, kdy vane vítr."},"ICON-2777":{"nm":"Rajčatové těstoviny","de":"Dlouho vařená rajčatová omáčka se červeně rozlévá po nudlích. Když se sladkost a kyselost pomalu zredukují a konečně najdou rovnováhu, nejzákladnější talíř je nejspolehlivější."},"ICON-2778":{"nm":"Omurice","de":"Jemné vejce jako přikrývka měkce přikryje teplou rýži. Napíšeš-li na něj kečupem alespoň jedno jméno, stane se ten den stůl malým dopisem, který ti někdo podal."},"ICON-2779":{"nm":"Grilovaný losos","de":"Pomalu se peče před plamenem, dokud kůže nezkřupaví. Proužek páry stoupající ve chvíli, kdy se růžové maso rozpadá po vláknech – trpělivost bývá lososem vždy poctivě odměněna."},"ICON-2780":{"nm":"Bruschetta","de":"Na křupavě opečený chléb se vydatně navrší nasekaná rajčata a bazalka. Ta lehkost, s jakou ji vezmeš do prstů a zakousneš se, vřele zahájí první pozdrav sešlosti."},"ICON-2781":{"nm":"Mangové smoothie","de":"Jemně rozmixuješ zralé mango a osvěživě smícháš s ledem. Když se na žlutém poháru orosí kapičky, ospalé letní odpoledne stoupá až ke špičce brčka."},"ICON-2782":{"nm":"Limonáda","de":"Přidáš čerstvě vymačkaný citron, cukr a studenou vodu a protřepeš to celé v poháru. Jak žlutá kyselost svěže sklouzne hrdlem dolů, i rozpoutané vedro na chvíli kapituluje."},"ICON-2783":{"nm":"Jahodové mléko","de":"Rozmícháš rozmačkanou jahodu do mléka a růžový obláček se v poháru pomalu usazuje. Dětské vzrušení z prstů otevírajících dveře lednice se vejde celé do jednoho poháru."},"ICON-2784":{"nm":"Banánové mléko","de":"Nápoj, který je už jen tvarem svého kulatého lahvičkovitého tvaru celou jednou érou vzpomínek. Žlutá vzpomínka na zapíchnuté brčko na lavičce u lázní se s každým douškem vřele probouzí k životu."},"ICON-2785":{"nm":"Borůvkové mléko","de":"Vpustíš dovnitř fialová zrníčka a rozmačkáš je a bílé mléko se zabarví do jemné nebeské modři. Ta jedna hrst drobného ovoce promění celý pohár v úplně novou barvu."},"ICON-2786":{"nm":"Ovocný džus","de":"Vymačkáš dohromady několik druhů ovoce a vznikne chuť, kterou už nejde pojmenovat jediným jménem. Malý sbor sladkostí, který se prolíná a bujaří o to bohatěji."},"ICON-2787":{"nm":"Kakao","de":"U zasněženého okna tiše obejmeš oběma rukama teplý hrnek. Jeden hnědý šálek, z něhož se line pára, tě pomalu zahřeje od konečků prstů až po srdce."},"ICON-2788":{"nm":"Káva","de":"Světlo v ranní zkušebně vždy rozsvítí právě tento jeden šálek. Jak hořkosladká vůně tiše odsune ospalost, další den na pódiu tak potichu začíná znovu."},"ICON-2789":{"nm":"Lososové sushi","de":"Sevřeš rýži v dlani a vycítíš tu jemnou hranici mezi pevností a měkkostí. V okamžiku, kdy se na ni jemně položí tenký plátek lososa, stane se jedno sousto dovršením malé oddanosti."},"ICON-2790":{"nm":"Dýňová kaše","de":"Žlutou dýni důkladně provaříš a jemně rozmixuješ. S každou lžičkou se v ústech teple rozpouští podzimní slunce. Kaše, která se vybaví jako první, když je někomu špatně."},"ICON-2791":{"nm":"Rybí kari","de":"Rybí maso lehce podušené v koření se v kari měkce rozpadá. Přidáš-li do známé misky nádech moře, obyčejný večer se vydá o kousek dál na cestu."},"ICON-2792":{"nm":"Smažené krevety","de":"Ten krátký okamžik, kdy uchopíš ocásek, obalíš v těstíčku a vhodíš do vroucího oleje, rozhoduje o všem. Kreveta oděná do zlatavého kabátku září nejjasněji, sníš-li ji dřív, než křupavost stihne vychladnout."},"ICON-2793":{"nm":"Smažené kroužky kalamárů","de":"Kulaté kroužky se v horkém oleji baculatě nadmou. To sousto, kde křupavost obepíná pružnost, sluší nejlépe žlutým světlům stánku s pouličním jídlem."},"ICON-2794":{"nm":"Grilované kuře","de":"Potřeš marinádou a pomalu griluješ před plamenem, až se kůže rozzáří leskem. Jídlo, jehož chuť se láme na jediném seřízení ohně – nejjednodušší, a právě proto nejpoctivější."},"ICON-2795":{"nm":"Vepřové maso s kimchi na pánvi","de":"Orestuješ dobře uzrálé kimchi společně s vepřovým masem a kyselost dozraje do sladkosti. Chod, po němž se samo od sebe zachce mísy bílé rýže – nejspolehlivější dvojice na korejském stole."},"ICON-2796":{"nm":"Vepřové maso na pánvi","de":"Rychle orestuješ na prudkém ohni tak, aby povrch pěkně zkřupavěl. Když kuchyň naplní lahodná vůně oleje, dnešní večerní menu je bez dalších slov rozhodnuto."},"ICON-2797":{"nm":"Hovězí maso s houbami na pánvi","de":"Orestuješ voňavé houby společně s hovězím a chuť obou se ještě prohloubí. Upravené podzimní jídlo, v němž se hlína a pole na jednom talíři tiše chytí za ruce."},"ICON-2798":{"nm":"Dak-galbi se sýrem","de":"Na pikantní dak-galbi necháš vydatně rozpustit sýr a dlouze ho vytáhneš. Když se mnozí sesednou kolem horkého plechu uprostřed, i pálivá štiplavost se rozpustí ve smíchu."},"ICON-2799":{"nm":"Kimči čige","de":"Čím starší kimchi, tím hlubší a sytější vývar dá. Posadíš se tváří v tvář nad bublajícím hliněným hrncem a slovo »rodina« se znovu vřele prohřeje."},"ICON-2800":{"nm":"Doenjang čige","de":"Rozpustíš vonnou sójovou pastu, přidáš tofu a cuketu a necháš to zvolna probublávat. Ten zvuk bublání, který v hliněném hrnci vydrží až do posledního doušku, je nejjistější známkou, že jsi doma."},"ICON-2801":{"nm":"Hovězí polévka s ředkví","de":"Půl dne stráveného tichým čekáním u mírného plamene, dokud ředkev nezprůhlední. Když se lžíce čiré polévky dotkne rtů, vybaví se stůl oněch nenápadných dob. Prostota vydrží nejdéle."},"ICON-2802":{"nm":"Polévka z mušlí","de":"V okamžiku, kdy se mušle otevřou, v hrnci se prohlubuje jaro. Když s párou stoupá hrst mořské vůně, vybaví se kuchyně přímořské vesnice za úsvitu. V každé pootevřené škvíře se drží slané moře."},"ICON-2803":{"nm":"Karamelizované batáty","de":"Cestou ze školy, žluté kousky v papírovém kelímku, svírané v dlani jako ohřívač rukou. Když prokoušete zlatavý povrch, zevnitř vyrazí pára. Sladce karamelizovaný povrch a horký vnitřek – chuť zimy v její nejněžnější podobě."},"ICON-2804":{"nm":"Restovaný lilek","de":"Okamžik, kdy se fialová barva setká s olejem a pomalu se rozplyne. Zelenina, které se vyčítala měkkost, ve skutečnosti vstřebává koření lépe než kterákoli jiná. Při prvním soustu vás nejdřív zasáhne jemně vpitá chuť ruky, jež ji připravila."},"ICON-2805":{"nm":"Brambory dušené na sójové omáčce","de":"Večer, kdy se sójová omáčka zavařovala a kuchyní se šířila sladká vůně. Ruka, která do přihrádky obědové krabičky ukládala jeden lesklý hnědý kousek. V každém z těch malých kousků je vepsaná péče, kterou žádný recept nezachytí."},"ICON-2806":{"nm":"Nakládané perilové listy","de":"Naložit celou vůni léta a donést ji až na zimní stůl. Odloupnete-li jeden list a položíte ho na rýži, minulé roční období znovu rozkvete v ústech. Mezi listy naskládanými vrstva na vrstvu spí sluneční svit toho roku."},"ICON-2807":{"nm":"Čerstvé kimči z pekingského zelí","de":"Ruce, které nevydržely čekat na zimní kimčchi, ho ještě týž den promnou s kořením. Svěžest, kterou lze vychutnat jen v okamžiku, kdy koření teprve začíná pronikat do křupavých listů. Nedozrálá čerstvost před kvašením je přepychem jen pro dnešek."},"ICON-2808":{"nm":"Restované houby","de":"Věci, které tiše vyrostly ve stínu lesa po dešti. Zatímco se smaží na perilovém oleji, vůně hlíny se mění v lahodnost. Čím tišeji něco roste ve tmě, tím hlubší a sytější je jeho vůně."},"ICON-2809":{"nm":"Ochucený špenát","de":"Listová zelenina, která se spařením smrskne na pouhou hrst, se promne mezi prsty. Tato skromná velikost je ctností jarních bylin. Jeden zelený talíř přinese na stůl o kousek víc jarního slunce."},"ICON-2810":{"nm":"Ochucené mořské řasy","de":"Kluzké pramínky, právě vylovené z moře, se snoubí s kyselou pálivou omáčkou. Při každém soustu praskne na jazyku slaná chuť. Talíř, který přenáší přímo do misky texturu vlnícího se moře."},"ICON-2811":{"nm":"Restovaná cuketa","de":"Existuje zelenina, jejíž sladkost roste s tím, jak stárne. Nakrájená na tenké plátky a orestovaná se solenými krevetami, i nenápadná cuketa nesměle odhalí svou sladkost. Žluť, která se v ústech až do konce jemně rozplývá."},"ICON-2812":{"nm":"Smažená rýže s kimči","de":"Když staré kimči dozraje do plné hloubky, setká se ve stejné pánvi se studenou rýží. Miska, která se stane nejvydatnější právě spojením toho, co zbylo, s tím, co zbylo. Nejněžnější spása pozdní noci pod světlem svobodného pokojíku."},"ICON-2813":{"nm":"Kuřecí kari","de":"Když žlutá omáčka zalije bílou rýži, stůl se rozzáří. V dobách, kdy bylo koření ještě cizí, byla toto první chuť vnějšího světa, se kterou jsme se spřátelili. Nedělní oběd, kdy se kuřecí maso rozplývalo měkce a nadýchaně."},"ICON-2814":{"nm":"Smažená rýže","de":"Zbytky, které přežily v koutě lednice, se na jedné pánvi svorně spojí. Velkorysost, jež vlídně přijme cokoli. Shromáždit roztroušené na jedno místo – tím začíná vedení domácnosti."},"ICON-2815":{"nm":"Miska rýže s bulgogi","de":"Maso naložené ve sladké marinádě se pomalu sesune na horkou, pářící se rýži. Když se hlavní chod hostiny promění ve všední misku, výjimečnost se stává o to něžnější."},"ICON-2816":{"nm":"Bibimbap","de":"Nad kypící rýží se do kruhu usadí zelenina pěti barev. V prstech, které pečlivě sladily barvy, proudí starý smysl pro krásu. Chuť souladu, jenž se dovrší teprve promícháním všeho dohromady."},"ICON-2817":{"nm":"Smažená rýže s krevetami","de":"Baculaté krevety vystupují růžově mezi zrnky rýže. Přidáte-li hrst moře do pánve, i obyčejné jídlo se začne podobat hostině. Sladká chuť, která se rozlije v okamžiku křupnutí, je vždy vítaná."},"ICON-2818":{"nm":"Miska rýže s pikantním vepřovým","de":"Vepřové maso důkladně provoněné pálivým kořením se setkává s pářící se rýží. Miska, jejíž dno bylo o polední přestávce vidět jako první. Útěcha jednoho jídla, které konejšivě poplácá po zádech uspěchaný den."},"ICON-2819":{"nm":"Rýže s tuňákem a majonézou","de":"Jedna konzerva, proužek majonézy a mísa teplé rýže. Přísady jsou skromné, ale útěcha je vydatná. Chuť té noci, kdy se rýže tajně míchala na lavici třídy po skončení večerního studia."},"ICON-2820":{"nm":"Kari s rýží","de":"Hustá zlatá barva zaplní celý talíř. Péče dlouhého míchání, dokud brambory a mrkev úplně nezměknou. Vybaví se sourodost onoho večera, kdy celá rodina nahlížela do stejného hrnce."},"ICON-2821":{"nm":"Bibimbap s mořskými řasami","de":"Pramínky vonící mořem se setkávají s pálivou pastou gochujang a čile se promíchávají. Když kluzká, kyselá textura obalí zrnka rýže, v jedné misce se rozprostře moře, které potápěčka vylovila se zadrženým dechem."},"ICON-2822":{"nm":"Grilovaná makrela","de":"Stříbrný hřbet se na grilu pomalu propéká do zlatava. Ruka, která vybírala kosti a kladla maso na rýži. V jednom kousku modrohřbeté ryby je vepsaná tichá láska, jež takto krmila a vychovávala."},"ICON-2823":{"nm":"Bramborové placky","de":"Věc, kterou za deštivých dní strouhaly a smažily v horské kuchyni provincie Kangwon. Přilnavý okraj a křupavý cíp žijí vedle sebe na jedné placce. Těsto, které se nejlépe hodí ke zvuku deště bubnujícího na okno."},"ICON-2824":{"nm":"Kimči placka","de":"V okamžiku, kdy se kysané kimči dotkne rozehřáté pánve, celý dům se naplní syčivým zvukem. Zlatavý kruh, který sám od sebe volá po misce makkolli. Stálice jídelníčku, jež tvoří pár se zvukem deště pod okapem."},"ICON-2825":{"nm":"Placka s jarní cibulkou","de":"Jarní cibulku srovnáme vedle sebe, zalijeme těstem a pomalu upečeme. Placka, která se pohybuje mezi křupavostí a měkkostí. Přesně ten milý obraz stánku na tržní den, z něhož stoupala pára."},"ICON-2826":{"nm":"Cuketová placka","de":"Tence nakrájenou cuketu obalíme v těstíčku a osmažíme dozlatova. Světle zelený kroužek, který úhledně střežil svůj kout na obětním stole předků. Pečlivá obřadnost, jež se naplní teprve po mnoha hodinách práce rukou."},"ICON-2827":{"nm":"Restovaná oliheň","de":"Chapadla obalená v červeném koření se lesknou a třpytí. I když se na čele perlí kapky potu z pálivosti, hůlky se nedokážou zastavit. Ten jeden talíř, v němž se propletl pot s potěšením."},"ICON-2828":{"nm":"Tteokbokki","de":"Rýžové knedlíčky a rybí koláčky se topí v zavařené červené omáčce gochujang. Je v tom uzavřené celé odpoledne bufetu, kde se dvojice dělila o jídlo za našetřené drobné. Chuť vzpomínky, při jejímž pouhém vyslovení se sbíhají sliny."},"ICON-2829":{"nm":"Polévka s rybími koláčky","de":"Pouliční stánek, kde se v horkém vývaru vlní rybí koláčky, pára zamlžuje sklo do běla. Chytíte-li jeden špíz a nalijete si vývar do papírového kelímku, abyste ho srkli, mrazivá zimní noc hned zas o něco zteplá."},"ICON-2830":{"nm":"Tofu s kimči","de":"Vedle jemného tofu se usadí pálivě orestované kimči. Chlad a žár, jemnost a síla se snoubí na jednom talíři. Dvojice, která odedávna doprovázela noci dospělých."},"ICON-2831":{"nm":"Restovaná klobása se zeleninou","de":"Červené párky a zelenina se syčivě spojují v barvě kečupu. Přihrádka, která se po otevření víka svačinového boxu na sportovní den vyprázdnila jako první. Barva onoho dne zůstává živá bez ohledu na plynoucí čas."},"ICON-2832":{"nm":"Batátové latte","de":"Jemně rozmačkaný batát se měkce rozpouští v teplém mléce. Domácí sladkost, napsaná na jídelním lístku korejským písmem. Ve dnech, kdy vás zebou konečky prstů, sevřete šálek oběma dlaněmi a teplo se v něm pomalu rozlévá."},"ICON-2833":{"nm":"Majonéza","de":"Omáčka, která ještě nedorazila do kuchyně Třpytivého ostrova. Brzy bude vykreslena jako krémová ikonka. (připravuje se)"}};